class C:
    RED="\033[91m"; GREEN="\033[92m"; YELLOW="\033[93m"; CYAN="\033[96m"
    MAGENTA="\033[95m"; BLUE="\033[94m"; BOLD="\033[1m"; DIM="\033[2m"; RESET="\033[0m"

def c(code): return "" if NO_COLOR else code

def log(level, msg, indent=4):
    icons = {
        "INFO"  : f"{c(C.CYAN)}[*]{c(C.RESET)}",
        "OK"    : f"{c(C.GREEN)}[✓]{c(C.RESET)}",
        "WARN"  : f"{c(C.YELLOW)}[!]{c(C.RESET)}",
        "VULN"  : f"{c(C.RED)}[✗]{c(C.RESET)}",
        "SKIP"  : f"{c(C.DIM)}[─]{c(C.RESET)}",
        "SCAN"  : f"{c(C.BLUE)}[⚡]{c(C.RESET)}",
        "FUZZ"  : f"{c(C.MAGENTA)}[≈]{c(C.RESET)}",
        "BL"    : f"{c(C.MAGENTA)}[BL]{c(C.RESET)}",
        "TMPL"  : f"{c(C.CYAN)}[T]{c(C.RESET)}",
        "CONF"  : f"{c(C.GREEN)}[✔✔]{c(C.RESET)}",
        "SQLI"  : f"{c(C.RED)}[SQLi]{c(C.RESET)}",
        "XSS"   : f"{c(C.YELLOW)}[XSS]{c(C.RESET)}",
        "NUCLEI": f"{c(C.CYAN)}[N]{c(C.RESET)}",
        "SSTI"  : f"{c(C.MAGENTA)}[SSTI]{c(C.RESET)}",
        "XXE"   : f"{c(C.RED)}[XXE]{c(C.RESET)}",
        "OREDIR": f"{c(C.YELLOW)}[ORedir]{c(C.RESET)}",
        "CRLF"  : f"{c(C.CYAN)}[CRLF]{c(C.RESET)}",
        "CACHE" : f"{c(C.GREEN)}[Cache]{c(C.RESET)}",
        "NOSQL" : f"{c(C.MAGENTA)}[NoSQL]{c(C.RESET)}",
        "JWT"   : f"{c(C.CYAN)}[JWT]{c(C.RESET)}",
        "SMUG"  : f"{c(C.RED)}[Smug]{c(C.RESET)}",
        "UPLOAD": f"{c(C.YELLOW)}[Upload]{c(C.RESET)}",
        "HIDDEN": f"{c(C.GREEN)}[Hidden]{c(C.RESET)}",
        "BURP"  : f"{c(C.CYAN)}[Burp]{c(C.RESET)}",
        "PDF"   : f"{c(C.MAGENTA)}[PDF]{c(C.RESET)}",
        "ALERT" : f"{c(C.RED)}[Alert]{c(C.RESET)}",
        "SWAG"  : f"{c(C.GREEN)}[Swagger]{c(C.RESET)}",
        "WORK"  : f"{c(C.BLUE)}[Workflow]{c(C.RESET)}",
        "DNSRB" : f"{c(C.CYAN)}[DNSRB]{c(C.RESET)}",
        "AI"    : f"{c(C.MAGENTA)}[AI]{c(C.RESET)}",
        "CORS"  : f"{c(C.YELLOW)}[CORS]{c(C.RESET)}",
        "LOG4J" : f"{c(C.RED)}[Log4J]{c(C.RESET)}",
        "TIME"  : f"{c(C.CYAN)}[Time]{c(C.RESET)}",
        "LDAP"  : f"{c(C.MAGENTA)}[LDAP]{c(C.RESET)}",
        "SMTP"  : f"{c(C.YELLOW)}[SMTP]{c(C.RESET)}",
        "FTP"   : f"{c(C.GREEN)}[FTP]{c(C.RESET)}",
        "JS"    : f"{c(C.CYAN)}[JS]{c(C.RESET)}",
        "MULTI" : f"{c(C.MAGENTA)}[Multi]{c(C.RESET)}",
        "PASS"  : f"{c(C.BLUE)}[Passive]{c(C.RESET)}",
        "VM"    : f"{c(C.GREEN)}[VM]{c(C.RESET)}",
        "INT"   : f"{c(C.MAGENTA)}[INT]{c(C.RESET)}",
        "ENH"   : f"{c(C.CYAN)}[ENH]{c(C.RESET)}",
    }
    print(f"{' '*indent}{icons.get(level,'[?]')} {msg}")

def _type_text(text, delay=0.001):
    """Typing animation — prints text char by char."""
    for ch in text:
        sys.stdout.write(ch)
        sys.stdout.flush()
        time.sleep(delay)
    print()

def _glitch(text):
    """Glitch effect — flickers between colors then settles on red."""
    glitch_colors = [C.MAGENTA, C.CYAN, C.MAGENTA, C.CYAN]
    for col in glitch_colors:
        sys.stdout.write(f"\r{c(col)}{c(C.BOLD)}{text}{c(C.RESET)}")
        sys.stdout.flush()
        time.sleep(0.06)
        sys.stdout.write("\r" + " " * (len(text) + 4) + "\r")
        sys.stdout.flush()
    print(f"{c(C.RED)}{c(C.BOLD)}{text}{c(C.RESET)}")

def _matrix_rain(lines=12):
    """Matrix rain — random ASCII chars in green."""
    chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789@#$%^&*()"
    for _ in range(lines):
        row = "".join(random.choices(chars, k=60))
        print(f"{c(C.GREEN)}{c(C.DIM)}{row}{c(C.RESET)}")
        time.sleep(0.045)

def _loading(label="Loading", steps=5):
    """Animated loading bar."""
    sys.stdout.write(f"{c(C.CYAN)}{label} ")
    sys.stdout.flush()
    for _ in range(steps):
        sys.stdout.write(".")
        sys.stdout.flush()
        time.sleep(0.25)
    print(f" {c(C.GREEN)}[OK]{c(C.RESET)}")

def _fake_login():
    """Hacker-style fake auth screen."""
    print(f"\n{c(C.GREEN)}{c(C.BOLD)}")
    try:
        user = input("  Username: ")
        import getpass
        getpass.getpass("  Password: ")
    except (EOFError, KeyboardInterrupt):
        user = "root"
    time.sleep(0.8)
    print(f"\n{c(C.CYAN)}{c(C.BOLD)}  ✔  Access Granted — Welcome, {user}{c(C.RESET)}\n")
    time.sleep(0.7)

