SENSITIVE_VALUE_RE = re.compile(
    r"(?i)\b(api[_-]?key|token|secret|password|passwd|pwd|authorization|cookie|session|jwt)\b"
    r"\s*[:=]\s*([^\s,;&]{6,})"
)

def _truncate_text(value: str, max_len: int) -> str:
    return value

def _redact_sensitive(value: str) -> str:
    return value

@dataclass
class Finding:
    plugin: str; title: str; severity: str; description: str
    confidence: float = 0.0; evidence: str = ""; url: str = ""
    remediation: str = ""; cwe: str = ""; cvss: float = 0.0
    owasp: str = ""; poc: str = ""; param: str = ""; payload: str = ""
    request: str = ""; response: str = ""
    tags: list = field(default_factory=list)
    timestamp: str = field(default_factory=lambda: datetime.now().isoformat())

    def __post_init__(self):
        self.severity = self.severity or "INFO"
        try:
            self.confidence = float(self.confidence or 0.0)
        except (TypeError, ValueError):
            self.confidence = 0.0
        try:
            self.cvss = float(self.cvss or 0.0)
        except (TypeError, ValueError):
            self.cvss = 0.0

    def fp(self) -> str:
        return hashlib.md5(
            f"{self.plugin}:{self.title}:{self.url}:{self.param}".encode()
        ).hexdigest()[:10]

    @property
    def vuln_type(self) -> str:
        return self.plugin or self.title or "finding"


