@dataclass
class ScanEvent:
    module:    str
    status:    str       # "start" | "done" | "error" | "timeout" | "skip"
    timestamp: str       = field(default_factory=lambda: datetime.now().strftime("%H:%M:%S"))
    duration:  float     = 0.0
    findings:  int       = 0
    requests:  int       = 0
    note:      str       = ""

class ScanTimeline:
    """Thread-safe scan event log — records every module start/end."""
    def __init__(self, target: str, scan_start: datetime):
        self.target     = target
        self.scan_start = scan_start
        self.events: List[ScanEvent] = []
        self._t0: dict  = {}

    def begin(self, module: str):
        self._t0[module] = time.monotonic()
        self.events.append(ScanEvent(module=module, status="start"))

    def end(self, module: str, findings: int = 0, requests: int = 0, note: str = ""):
        duration = round(time.monotonic() - self._t0.get(module, time.monotonic()), 2)
        self.events.append(ScanEvent(
            module=module, status="done",
            duration=duration, findings=findings,
            requests=requests, note=note
        ))

    def error(self, module: str, note: str = ""):
        duration = round(time.monotonic() - self._t0.get(module, time.monotonic()), 2)
        self.events.append(ScanEvent(module=module, status="error", duration=duration, note=note))

    def timeout(self, module: str, note: str = ""):
        duration = round(time.monotonic() - self._t0.get(module, time.monotonic()), 2)
        self.events.append(ScanEvent(module=module, status="timeout", duration=duration, note=note))

    def skip(self, module: str, note: str = ""):
        self.events.append(ScanEvent(module=module, status="skip", note=note))

    def summary(self) -> dict:
        done    = [e for e in self.events if e.status == "done"]
        errors  = [e for e in self.events if e.status == "error"]
        timeouts= [e for e in self.events if e.status == "timeout"]
        skipped = [e for e in self.events if e.status == "skip"]
        return {
            "modules_run":     len(done),
            "modules_error":   len(errors),
            "modules_timeout": len(timeouts),
            "modules_skipped": len(skipped),
            "total_findings":  sum(e.findings for e in done),
            "slowest_module":  max(done, key=lambda e: e.duration).module if done else "—",
        }

    def as_list(self) -> list:
        return [
            {
                "module": e.module, "status": e.status,
                "timestamp": e.timestamp, "duration_s": e.duration,
                "findings": e.findings, "note": e.note
            }
            for e in self.events if e.status in ("done", "error", "timeout", "skip")
        ]


