class ScopeEnforcer:
    """
    Restrict scanning to allowed hosts/paths.
    Raises ValueError if a URL is out of scope.
    """
    def __init__(self, allowed_hosts: List[str] = None,
                 excluded_paths: List[str] = None,
                 allowed_schemes: List[str] = None):
        self.allowed_hosts   = [h.lower().lstrip("*.") for h in (allowed_hosts or [])]
        self.excluded_paths  = [p.lower() for p in (excluded_paths or [])]
        self.allowed_schemes = allowed_schemes or ["http", "https"]

    def is_in_scope(self, url: str) -> bool:
        try:
            p = urlparse(url)
            if p.scheme not in self.allowed_schemes:
                return False
            host = (p.hostname or "").lower()
            if self.allowed_hosts:
                if not any(host == ah or host.endswith("." + ah)
                           for ah in self.allowed_hosts):
                    return False
            path = (p.path or "").lower()
            if any(path.startswith(ep) for ep in self.excluded_paths):
                return False
            return True
        except Exception:
            return False

    def filter(self, urls: List[str]) -> List[str]:
        return [u for u in urls if self.is_in_scope(u)]

def _host_is_private_or_reserved(host: str) -> bool:
    try:
        ip = ipaddress.ip_address(host)
        return any([
            ip.is_private, ip.is_loopback, ip.is_link_local, ip.is_multicast,
            ip.is_reserved, ip.is_unspecified,
        ])
    except ValueError:
        pass
    try:
        infos = socket.getaddrinfo(host, None, type=socket.SOCK_STREAM)
    except socket.gaierror:
        return False
    for info in infos:
        addr = info[4][0]
        try:
            ip = ipaddress.ip_address(addr)
            if any([ip.is_private, ip.is_loopback, ip.is_link_local, ip.is_multicast, ip.is_reserved, ip.is_unspecified]):
                return True
        except ValueError:
            continue
    return False

def _validate_target_or_raise(target: str, cfg: ScanConfig) -> None:
    parsed = urlparse(target)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("Target URL must use http:// or https://")
    if not parsed.hostname:
        raise ValueError("Target URL must include a valid host")
    if _host_is_private_or_reserved(parsed.hostname) and not cfg.allow_private_targets:
        raise ValueError(
            "Private, loopback, link-local, multicast, or reserved targets are blocked by default. "
            "Use --allow-private-targets only for systems you own or are explicitly authorized to test."
        )

class ProgressBar:
    """Thread-safe CLI progress bar — shows 1-100%, elapsed, ETA, modules done/remaining."""

    def __init__(self, total: int, label: str = "", width: int = 35):
        self.total    = max(total, 1)
        self.current  = 0
        self.label    = label
        self.width    = width
        self.t0       = time.monotonic()
        self._lock    = asyncio.Lock()
        self._module  = ""

    async def step(self, n: int = 1, suffix: str = "", module: str = ""):
        async with self._lock:
            self.current = min(self.current + n, self.total)
            if module:
                self._module = module
            self._draw(suffix)

    def set_module(self, module: str):
        self._module = module

    def finish(self, suffix: str = "done"):
        self.current = self.total
        self._draw(suffix)
        print()

    def _draw(self, suffix: str = ""):
        if NO_COLOR:
            return
        pct      = self.current / self.total
        done_b   = int(self.width * pct)
        bar      = "█" * done_b + "░" * (self.width - done_b)
        ela      = time.monotonic() - self.t0
        done_m   = self.current
        remain_m = self.total - self.current

        if done_m > 0 and pct > 0:
            eta = (ela / pct) * (1 - pct)
            eta_str = f"ETA {eta:4.0f}s" if eta < 9999 else "ETA --"
        else:
            eta_str = "ETA --"

        mod_label = (self._module[:28] + "…") if len(self._module) > 28 else self._module
        line = (
            f"\r  \033[96m[{bar}]\033[0m "
            f"\033[1;93m{pct*100:5.1f}%\033[0m  "
            f"\033[92m✓{done_m}\033[0m/\033[91m◌{remain_m}\033[0m  "
            f"\033[96m{ela:5.1f}s\033[0m \033[2m{eta_str}\033[0m  "
            f"\033[95m{mod_label}\033[0m"
            f"\033[K"
        )
        print(line, end="", flush=True)


