#  MODULE 1 — Multi-Port & Service Scanner
# ════════════════════════════════════════════════════════════════════════

class PortServiceScanner:
    def __init__(self, client: WebScoutClient, cfg: ScanConfig):
        self.client = client; self.cfg = cfg

    async def scan(self, host: str, ports: list = None, timeout: int = 2) -> list:
        ports = ports or [p for p, *_ in PORTS_DB]
        findings = []; loop = asyncio.get_event_loop()
        log("SCAN", f"Scanning {len(ports)} ports on {host}")

        async def probe(port, service, sev, note, cwe):
            try:
                await asyncio.wait_for(
                    loop.run_in_executor(None, self._tcp, host, port, timeout),
                    timeout=timeout + 1)
                return (port, service, sev, note, cwe, True)
            except Exception:
                return (port, service, sev, note, cwe, False)

        tasks = [probe(*row) for row in PORTS_DB if row[0] in ports]
        results = await asyncio.gather(*tasks, return_exceptions=True)

        for item in results:
            if isinstance(item, Exception): continue
            port, service, sev, note, cwe, is_open = item
            if not is_open: continue
            banner = await loop.run_in_executor(None, self._banner, host, port, timeout)
            auth_note = await self._auth_probe(host, port, loop, timeout)
            if auth_note: sev = "CRITICAL"
            evidence = f"Port {port}/tcp OPEN | {service}"
            if banner: evidence += f" | Banner: {banner[:80]}"
            if auth_note: evidence += f" | {auth_note}"
            findings.append(Finding(
                plugin="port_scanner",
                title=f"Open Port: {port}/{service}" + (f" — {auth_note}" if auth_note else ""),
                severity=sev, description=f"{note}. Port {port} accessible.",
                evidence=evidence, url=f"tcp://{host}:{port}",
                remediation=f"Firewall port {port}. Use VPN for admin. Enforce auth on {service}.",
                cwe=cwe, owasp="A05",
                tags=["port-scan", "infrastructure", service.lower()],
            ))
            log("WARN" if sev in ("CRITICAL", "HIGH") else "INFO",
                f"Port {port}/{service} OPEN{' — ' + auth_note if auth_note else ''}")

        log("OK", f"Port scan done — {len(findings)} open port(s)")
        return findings

    def _tcp(self, host, port, timeout):
        s = socket.socket(); s.settimeout(timeout); s.connect((host, port)); s.close()

    def _banner(self, host, port, timeout) -> str:
        s = socket.socket()
        try:
            s.settimeout(timeout)
            s.connect((host, port))
            s.sendall(b"\r\n")
            d = s.recv(256)
            return d.decode(errors="replace").strip()[:100]
        except Exception:
            return ""
        finally:
            try: s.close()
            except Exception:
                pass

    async def _auth_probe(self, host, port, loop, timeout) -> str:
        if port not in AUTH_PROBE: return ""
        service, probe_bytes, expected = AUTH_PROBE[port]
        def _do():
            try:
                s = socket.socket(); s.settimeout(timeout)
                s.connect((host, port))
                if probe_bytes: s.sendall(probe_bytes)
                d = s.recv(512); s.close()
                if expected in d: return f"UNAUTHENTICATED {service}"
            except (OSError, socket.error, Exception) as _se:
                log("DEBUG", f"Socket probe {service}:{port} failed: {_se}") if False else None
            return ""
        return await loop.run_in_executor(None, _do)


