class SSRFScanner:
    """Detects Server-Side Request Forgery using localhost and collaborator."""
    SSRF_PAYLOADS = [
        "http://127.0.0.1:80",
        "http://169.254.169.254/latest/meta-data/",
        "http://localhost:8080",
        "http://[::1]:80",
        "http://0.0.0.0:80",
        "http://internal.service",
        "http://metadata.google.internal/",
    ]

    async def scan(self, client, url, collaborator=None):
        findings = []
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        url_params = [p for p in params if any(k in p.lower() for k in ["url", "uri", "path", "redirect", "next", "return", "dest", "webhook", "callback"])]
        if not url_params:
            url_params = list(params.keys())[:5]
        for param in url_params:
            # Fetch baseline to detect keywords already present in normal responses
            baseline_r = await client.get(url)
            baseline_text = baseline_r["text"].lower() if baseline_r else ""
            for payload in self.SSRF_PAYLOADS:
                np = {**params, param: [payload]}
                test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await client.get(test_url)
                if not r:
                    continue
                body_lower = r["text"].lower()
                # STRICT SSRF criteria:
                # 1. Response must contain internal service evidence
                # 2. That evidence must NOT already exist in the baseline (avoid false positives
                #    from pages that legitimately mention "localhost" or "metadata")
                # 3. Response must contain content that only an internal fetch would return
                INTERNAL_EVIDENCE = [
                    "ami-id", "instance-id", "iam/security-credentials",
                    "computeMetadata", "gce/", "latest/meta-data",
                    "root:x:0:0", "/etc/passwd", "window station",
                ]
                unique_evidence = [ev for ev in INTERNAL_EVIDENCE
                                   if ev.lower() in body_lower
                                   and ev.lower() not in baseline_text]
                if unique_evidence:
                    findings.append(Finding(
                        plugin="ssrf_scanner",
                        title=f"SSRF Confirmed via param '{param}'",
                        severity="CRITICAL",
                        confidence=92.0,
                        description=(f"Server fetched internal resource. Parameter '{param}' "
                                     f"with payload '{payload}' returned internal service content."),
                        evidence=f"Payload: {payload} | Internal content found: {unique_evidence[0][:60]}",
                        url=test_url, param=param, payload=payload,
                        remediation="Validate and whitelist allowed URLs. Block requests to internal IP ranges (RFC1918). Use a URL allowlist.",
                        cwe="CWE-918", cvss=9.8, owasp="A01",
                        poc=f"curl -sk '{test_url}'",
                        tags=["ssrf", "injection", "confirmed"],
                    ))
                    break
            if collaborator and "http" in collaborator:
                np = {**params, param: [collaborator]}
                test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await client.get(test_url)
                if r and r["status"] in (200, 302):
                    findings.append(Finding(
                        plugin="ssrf_scanner",
                        title="SSRF Potential with Collaborator",
                        severity="CRITICAL",
                        confidence=50.0,
                        description=f"Parameter '{param}' accepted collaborator URL, check for out-of-band interaction.",
                        evidence=f"URL: {test_url} | HTTP {r['status']}",
                        url=test_url, param=param, payload=collaborator,
                        remediation="Validate and whitelist allowed URLs.",
                        cwe="CWE-918", cvss=8.6, owasp="A01",
                        tags=["ssrf", "oob"],
                    ))
        return findings

class CommandInjectionScanner:
    """Detects OS command injection using time‑based and output‑based payloads."""
    PAYLOADS = [
        ("; sleep 5", 5, "Unix time-based (;)"),
        ("| sleep 5", 5, "Unix time-based (|)"),
        ("& ping -c 5 127.0.0.1", 5, "Unix time-based (&)"),
        ("&& sleep 5", 5, "Unix time-based (&&)"),
        ("|| sleep 5", 5, "Unix time-based (||)"),
        ("%3B sleep 5", 5, "Unix time-based (URL encoded ;)"),
        ("; ping -n 5 127.0.0.1", 5, "Windows time-based"),
        ("| ping -n 5 127.0.0.1", 5, "Windows time-based"),
        ("& ping -n 5 127.0.0.1", 5, "Windows time-based"),
        ("&& ping -n 5 127.0.0.1", 5, "Windows time-based"),
        ("|| ping -n 5 127.0.0.1", 5, "Windows time-based"),
        ("; echo vulnerable", 0, "Unix output"),
        ("| echo vulnerable", 0, "Unix output"),
        ("& echo vulnerable", 0, "Unix output"),
        ("&& echo vulnerable", 0, "Unix output"),
        ("|| echo vulnerable", 0, "Unix output"),
    ]

    async def scan(self, client, url):
        findings = []
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        cmd_params = [p for p in params if any(k in p.lower() for k in [
            "cmd", "exec", "ping", "traceroute", "command", "system", "shell", "run", "execute"])]
        if not cmd_params:
            cmd_params = list(params.keys())[:5]

        # Baseline RTT — three samples, take worst-case to avoid flagging slow servers
        _rtt_samples_cmd = []
        for _ in range(3):
            _t = time.perf_counter()
            await client.get(urlunparse(parsed))
            _rtt_samples_cmd.append(time.perf_counter() - _t)
        _baseline_rtt_cmd = max(_rtt_samples_cmd)

        for param in cmd_params:
            for payload, delay, desc in self.PAYLOADS:
                np = {**params, param: [payload]}
                test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))

                if delay > 0:
                    # TIME-BASED: requires two consecutive delays + fast control
                    required = delay - 1.0 + _baseline_rtt_cmd

                    t0 = time.perf_counter()
                    r1 = await client.get(test_url)
                    elapsed1 = time.perf_counter() - t0
                    if not r1 or elapsed1 < required:
                        continue

                    t1 = time.perf_counter()
                    r2 = await client.get(test_url)
                    elapsed2 = time.perf_counter() - t1
                    if not r2 or elapsed2 < required:
                        continue

                    # Control: safe value must respond fast
                    np_safe = {**params, param: ["1"]}
                    safe_url = urlunparse(parsed._replace(query=urlencode(np_safe, doseq=True)))
                    t_s = time.perf_counter()
                    r_safe = await client.get(safe_url)
                    elapsed_safe = time.perf_counter() - t_s
                    if r_safe and elapsed_safe >= (delay - 1.0):
                        continue  # Server is slow regardless — not injection

                    findings.append(Finding(
                        plugin="cmd_injection",
                        title=f"OS Command Injection Confirmed (Time-Based) via '{param}'",
                        severity="CRITICAL", confidence=94.0,
                        description=(f"Two consecutive delays of {elapsed1:.2f}s and {elapsed2:.2f}s "
                                     f"confirmed for payload '{payload}'. Control responded in {elapsed_safe:.2f}s."),
                        evidence=(f"Payload: {payload} | Delay1: {elapsed1:.2f}s | "
                                  f"Delay2: {elapsed2:.2f}s | Baseline: {_baseline_rtt_cmd:.2f}s | "
                                  f"Control: {elapsed_safe:.2f}s"),
                        url=test_url, param=param, payload=payload,
                        remediation=("Never pass user input to shell commands. "
                                     "Use subprocess with argument arrays (no shell=True). "
                                     "Apply strict input allowlists."),
                        cwe="CWE-78", cvss=9.8, owasp="A03",
                        poc=f"curl -sk '{test_url}'",
                        tags=["cmd-injection", "rce", "time-based", "confirmed"],
                    ))
                    break

                else:
                    # OUTPUT-BASED: check for command output signatures, not just the word "vulnerable"
                    r = await client.get(test_url)
                    if not r:
                        continue
                    body = r["text"]
                    # Genuine command output signatures
                    cmd_output_sigs = [
                        r"root:.*:0:0",           # /etc/passwd content
                        r"uid=\d+\(.*\) gid=",   # id command output
                        r"Linux.*#\d+",            # uname output
                        r"\d+\.\d+\.\d+\.\d+.*TTL",  # ping output
                        r"PING.*bytes of data",   # ping output
                        r"vulnerable",             # explicit marker (last resort)
                    ]
                    baseline_r = await client.get(url)
                    baseline_body = baseline_r["text"] if baseline_r else ""
                    matched_sig = next((re.search(sig, body, re.I) for sig in cmd_output_sigs
                                       if re.search(sig, body, re.I)
                                       and not re.search(sig, baseline_body, re.I)), None)
                    if matched_sig:
                        findings.append(Finding(
                            plugin="cmd_injection",
                            title=f"OS Command Injection Confirmed (Output-Based) via '{param}'",
                            severity="CRITICAL", confidence=96.0,
                            description=(f"Command output signature found in response for payload '{payload}'. "
                                         f"Server is executing OS commands."),
                            evidence=f"Payload: {payload} | Output signature: '{matched_sig.group()[:60]}'",
                            url=test_url, param=param, payload=payload,
                            remediation=("Never pass user input to shell commands. "
                                         "Use parameterized subprocess calls with no shell expansion."),
                            cwe="CWE-78", cvss=9.8, owasp="A03",
                            poc=f"curl -sk '{test_url}'",
                            tags=["cmd-injection", "rce", "output-based", "confirmed"],
                        ))
                        break
        return findings

class LDAPInjectionScanner:
    """Detects LDAP injection vulnerabilities."""
    PAYLOADS = [
        ("*", "Wildcard"),
        ("*)(&", "Wildcard with parenthesis"),
        ("admin*", "User enumeration"),
        ("*)(uid=*", "Authentication bypass"),
        ("*)(|(uid=*", "Authentication bypass variant"),
        ("*)(|(password=*)", "Password bypass"),
        ("*)(objectClass=*)", "ObjectClass extraction"),
    ]
    ERROR_PATTERNS = [
        r"javax.naming.NameNotFoundException",
        r"javax.naming.directory.InvalidSearchFilterException",
        r"LDAPException",
        r"LDAP: error code",
        r"Bad search filter",
        r"Unbalanced parentheses",
    ]

    async def scan(self, client, url):
        findings = []
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        ldap_params = [p for p in params if any(k in p.lower() for k in ["user", "username", "login", "uid", "cn", "mail", "filter"])]
        if not ldap_params:
            ldap_params = list(params.keys())[:5]
        for param in ldap_params:
            for payload, desc in self.PAYLOADS:
                np = {**params, param: [payload]}
                test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await client.get(test_url)
                if not r:
                    continue
                body_lower = r["text"].lower()
                if any(re.search(pat, body_lower, re.I) for pat in self.ERROR_PATTERNS):
                    findings.append(Finding(
                        plugin="ldap_injection",
                        title=f"LDAP Injection via {param}",
                        severity="HIGH",
                        confidence=75.0,
                        description=f"LDAP injection detected with payload: {desc}",
                        evidence=f"Payload: {payload} | Error pattern matched",
                        url=test_url, param=param, payload=payload,
                        remediation="Use parameterized LDAP queries. Validate and escape user input.",
                        cwe="CWE-90", cvss=8.5, owasp="A03",
                        tags=["ldap", "injection"],
                    ))
                    break
        return findings

class AdvancedRequestSmugglingScanner:
    """Detects HTTP request smuggling using CL.TE, TE.CL, and GET-based techniques."""
    async def scan(self, client, url):
        findings = []
        # HTTP Request Smuggling is inherently hard to confirm automatically without
        # direct HTTP/1.1 socket control. The key indicator is NOT a 400/500 response
        # (servers correctly return 400 for malformed requests — that is NOT smuggling).
        # True smuggling requires a follow-up request to be "poisoned" by the first.
        # We use a differential timing approach: measure baseline latency vs malformed.

        # CL.TE test — the server must ACCEPT the ambiguous body (200 OK), not reject it (400)
        # A 400 means the server correctly detected the malformed request — NOT vulnerable.
        headers_cl_te = {"Content-Length": "4", "Transfer-Encoding": "chunked"}
        body_cl_te = "3\r\nabc\r\n0\r\n\r\nX"
        try:
            r = await client.post(url, data=body_cl_te, headers=headers_cl_te)
            # Only flag if server accepted the malformed body (200/201/302) — rejection (400) is safe
            if r and r["status"] in (200, 201, 302):
                # Also verify normal POST to same endpoint returns different behaviour
                normal_r = await client.post(url, data="test=1")
                if normal_r and normal_r["status"] != r["status"]:
                    findings.append(Finding(
                        plugin="request_smuggling",
                        # Severity is MEDIUM (not HIGH) because confidence is 70% and
                        # manual confirmation is always required for request smuggling.
                        # Flagging as HIGH misleads users into believing exploitation is confirmed.
                        title="HTTP Request Smuggling (CL.TE) — Server Accepted Ambiguous Body [Indicative]",
                        severity="MEDIUM",
                        confidence=70.0,
                        description=(
                            "Server accepted a CL.TE ambiguous POST body with HTTP 200. "
                            "This is an indicator ONLY — not a confirmed exploit. "
                            "Manual confirmation with dedicated tools (smuggler.py, h2csmuggler) is required."
                        ),
                        evidence=f"Ambiguous body accepted: HTTP {r['status']} | Normal POST: {normal_r['status'] if normal_r else 'N/A'}",
                        url=url,
                        remediation="Normalise all Transfer-Encoding and Content-Length headers at the proxy layer. Reject ambiguous bodies.",
                        cwe="CWE-444", cvss=6.5, owasp="A01",
                        poc="python3 smuggler.py -u " + url,
                        tags=["smuggling", "http", "requires-manual-confirmation", "indicative"],
                    ))
        except Exception as _smug_e:
            log("DEBUG", f"Request smuggling CL.TE probe failed: {_smug_e}")

        # TE.CL test — same logic: only flag if server accepts (not rejects) the ambiguous request
        headers_te_cl = {"Content-Length": "20", "Transfer-Encoding": "chunked"}
        body_te_cl = "0\r\n\r\nX"
        try:
            r = await client.post(url, data=body_te_cl, headers=headers_te_cl)
            if r and r["status"] in (200, 201, 302):
                normal_r2 = await client.post(url, data="test=1")
                if normal_r2 and normal_r2["status"] != r["status"]:
                    findings.append(Finding(
                        plugin="request_smuggling",
                        title="HTTP Request Smuggling (TE.CL) — Server Accepted Ambiguous Body [Indicative]",
                        severity="MEDIUM",
                        confidence=65.0,
                        description=(
                            "Server accepted a TE.CL ambiguous POST body. "
                            "This is an indicator ONLY — not a confirmed exploit. "
                            "Verify manually with dedicated smuggling tools."
                        ),
                        evidence=f"Ambiguous body accepted: HTTP {r['status']}",
                        url=url,
                        remediation="Ensure proxy and origin agree on Transfer-Encoding handling. Reject conflicting headers.",
                        cwe="CWE-444", cvss=6.5, owasp="A01",
                        poc="python3 smuggler.py -u " + url,
                        tags=["smuggling", "http", "requires-manual-confirmation", "indicative"],
                    ))
        except Exception as _smug_e2:
            log("DEBUG", f"Request smuggling TE.CL probe failed: {_smug_e2}")

        return findings


