#  MODULE v41-5 — HTTP/2 and h2c Scanner
# ════════════════════════════════════════════════════════════════════════

class HTTP2Scanner:
    """
    Tests HTTP/2 and h2c (HTTP/2 cleartext) specific issues:
    - h2c upgrade on cleartext connections
    - HTTP/2 Rapid Reset (CVE-2023-44487) vulnerability indicators
    - HTTP/2 header injection
    - Downgrade attack detection
    """

    async def _check_h2c_upgrade(self, url: str, timeout: int = 10) -> Optional[dict]:
        """Try h2c upgrade via HTTP/1.1 Upgrade header."""
        parsed = urlparse(url)
        if parsed.scheme != "http":
            return None
        try:
            import socket as _sock
            host = parsed.hostname
            port = parsed.port or 80
            path = parsed.path or "/"

            raw = (
                f"GET {path} HTTP/1.1\r\n"
                f"Host: {host}\r\n"
                "Connection: Upgrade, HTTP2-Settings\r\n"
                "Upgrade: h2c\r\n"
                "HTTP2-Settings: AAMAAABkAAQAAP__\r\n"
                "\r\n"
            ).encode()

            s = _sock.create_connection((host, port), timeout=timeout)
            s.sendall(raw)
            resp = s.recv(4096).decode(errors="replace")
            s.close()

            if "101" in resp and "h2c" in resp.lower():
                return {"upgraded": True, "response": resp[:200]}
            elif "200" in resp.split("\r\n")[0]:
                return {"upgraded": False, "response": resp[:200]}
        except Exception as _h2c_e:
            log("DEBUG", f"[HTTP2] H2C upgrade probe failed: {_h2c_e}")
        return None

    async def _check_rapid_reset_indicator(self, client: "WebScoutClient", url: str) -> bool:
        """
        Check for indicators that suggest HTTP/2 Rapid Reset might work.
        (Full exploitation requires a low-level HTTP/2 client; here we detect indicators.)
        """
        r = await client.get(url)
        if not r:
            return False
        server = r["headers"].get("Server", r["headers"].get("server", ""))
        x_powered = r["headers"].get("X-Powered-By", "")
        alt_svc = r["headers"].get("Alt-Svc", "")

        vulnerable_versions = [
            ("nginx", r"nginx/1\.([0-9]|1[0-8])\b"),
            ("apache", r"Apache/2\.[0-3]"),
            ("h2",    r"h2"),
        ]
        for name, pattern in vulnerable_versions:
            if re.search(pattern, server + alt_svc, re.I):
                return True
        return False

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        log("SCAN", "Running HTTP/2 and h2c scanner…")
        parsed = urlparse(url)

        r = await client.get(url)
        if r:
            alt_svc        = r["headers"].get("Alt-Svc", "")
            upgrade_hdr    = r["headers"].get("Upgrade", "")
            server_hdr     = r["headers"].get("Server", r["headers"].get("server", ""))
            via_hdr        = r["headers"].get("Via", "")
            x_proto        = r["headers"].get("X-Firefox-Spdy", "")
            # HTTP/2 indicators: Alt-Svc "h2", Via "2.0", x-firefox-spdy, or server-side h2 strings
            h2_detected = (
                "h2" in alt_svc
                or "2.0" in via_hdr
                or x_proto == "h2"
                or re.search(r"\bh2\b", server_hdr, re.I) is not None
                or upgrade_hdr.lower() == "h2c"
            )
            if h2_detected:
                h2_evidence = (
                    f"Alt-Svc: {alt_svc or '(none)'} | "
                    f"Via: {via_hdr or '(none)'} | "
                    f"X-Firefox-Spdy: {x_proto or '(none)'} | "
                    f"Server: {server_hdr or '(none)'}"
                )
                findings.append(Finding(
                    plugin="http2_scanner",
                    title="HTTP/2 Supported (Multiple Indicators Detected)",
                    severity="INFO", confidence=100.0,
                    description=(
                        "Server supports HTTP/2 based on one or more response indicators "
                        f"(Alt-Svc, Via, X-Firefox-Spdy, Server header). {h2_evidence}"
                    ),
                    evidence=h2_evidence,
                    url=url,
                    remediation="Ensure HTTP/2 implementation is up to date (CVE-2023-44487 — Rapid Reset).",
                    tags=["http2", "info"],
                ))

        if parsed.scheme == "http":
            h2c_result = await asyncio.get_event_loop().run_in_executor(
                None, lambda: None
            )
            try:
                loop = asyncio.get_event_loop()
                h2c_result = await loop.run_in_executor(None, lambda: (
                    __import__("socket").create_connection(
                        (parsed.hostname, parsed.port or 80), timeout=5
                    ) and None
                ))
            except Exception:
                h2c_result = None

            if h2c_result is None:
                raw_h2c = (
                    f"GET {parsed.path or '/'} HTTP/1.1\r\n"
                    f"Host: {parsed.netloc}\r\n"
                    "Connection: Upgrade, HTTP2-Settings\r\n"
                    "Upgrade: h2c\r\n"
                    "HTTP2-Settings: AAMAAABkAAQAAP__\r\n"
                    "\r\n"
                )
                try:
                    import socket as _sock
                    s = _sock.create_connection((parsed.hostname, parsed.port or 80), timeout=8)
                    s.sendall(raw_h2c.encode())
                    resp_raw = s.recv(2048).decode(errors="replace")
                    s.close()
                    if "101 Switching" in resp_raw and "h2c" in resp_raw.lower():
                        findings.append(Finding(
                            plugin="http2_scanner",
                            title="h2c Upgrade Accepted (HTTP/2 Cleartext)",
                            severity="MEDIUM", confidence=88.0,
                            description=(
                                "Server accepts HTTP/2 cleartext (h2c) upgrade via HTTP/1.1 Upgrade header. "
                                "h2c on public endpoints may allow request smuggling via HTTP/2 downgrade."
                            ),
                            evidence=f"HTTP 101 Switching Protocols received | Response: {resp_raw[:150]}",
                            url=url,
                            remediation=(
                                "Disable h2c on public-facing servers. Use HTTPS with HTTP/2 only. "
                                "Ensure CDN/proxy strips h2c upgrade headers."
                            ),
                            cwe="CWE-444", cvss=6.5, owasp="A04",
                            tags=["http2", "h2c", "smuggling", "downgrade"],
                        ))
                except Exception as _h2c_smug_e:
                    log("DEBUG", f"[HTTP2] H2C smuggling finding build failed: {_h2c_smug_e}")

        rapid_reset = await self._check_rapid_reset_indicator(client, url)
        if rapid_reset:
            findings.append(Finding(
                plugin="http2_scanner",
                title="HTTP/2 Rapid Reset Vulnerability Indicator (CVE-2023-44487)",
                severity="HIGH", confidence=70.0,
                description=(
                    "Server fingerprint suggests an HTTP/2 implementation version potentially "
                    "affected by CVE-2023-44487 (Rapid Reset DoS). Verify and patch."
                ),
                evidence="Server version or Alt-Svc header indicates potentially vulnerable HTTP/2 stack",
                url=url,
                remediation=(
                    "Update nginx to >=1.25.3, Apache httpd to >=2.4.58, Go to >=1.21.3. "
                    "Enable HTTP/2 stream limits. Monitor for abnormal RST_STREAM floods."
                ),
                cwe="CWE-400", cvss=7.5, owasp="A04",
                tags=["http2", "rapid-reset", "dos", "cve-2023-44487"],
            ))

        r_http2_hdr = await client.get(url, headers={
            ":path": "/admin",
            ":method": "GET",
        })
        if r_http2_hdr and r_http2_hdr["status"] == 200 and "admin" not in url:
            findings.append(Finding(
                plugin="http2_scanner",
                title="HTTP/2 Pseudo-Header Injection — :path Override",
                severity="MEDIUM", confidence=70.0,
                description="Server may process HTTP/2 pseudo-headers sent via HTTP/1.1 — potential path override.",
                evidence=f":path: /admin returned HTTP 200",
                url=url,
                remediation="Strip and validate HTTP/2 pseudo-headers at proxy/gateway layer.",
                cwe="CWE-113", cvss=6.5, owasp="A04",
                tags=["http2", "header-injection"],
            ))

        log("OK", f"HTTP/2 scan done — {len(findings)} issue(s)")
        return findings


