#  MODULE v41-6 — Dynamic CSP & Security Header Analyzer
# ════════════════════════════════════════════════════════════════════════

class DynamicCSPAnalyzer:
    """
    Deep Content Security Policy analysis:
    - Detects unsafe-inline, unsafe-eval, wildcard sources
    - Missing nonce or hash directives
    - Overly permissive script-src
    - Missing directives (default-src, frame-ancestors, object-src)
    - Report-only mode (no enforcement)
    - Strict-Transport-Security max-age check
    - Feature-Policy / Permissions-Policy analysis
    """

    DANGEROUS_CSP_VALUES = [
        ("unsafe-inline", "HIGH",   "Allows inline scripts — XSS protection bypassed"),
        ("unsafe-eval",   "HIGH",   "Allows eval() — DOM XSS escalation possible"),
        ("*",             "HIGH",   "Wildcard source — any origin can serve scripts"),
        ("data:",         "MEDIUM", "data: URIs allowed — XSS bypass vector"),
        ("http:",         "MEDIUM", "HTTP (insecure) sources allowed in CSP"),
    ]

    REQUIRED_DIRECTIVES = [
        "default-src", "script-src", "object-src",
        "frame-ancestors", "base-uri", "form-action",
    ]

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        log("SCAN", "Running dynamic CSP & security header analyzer…")
        r = await client.get(url)
        if not r:
            return findings

        hdrs = {k.lower(): v for k, v in r["headers"].items()}
        csp = hdrs.get("content-security-policy", "")
        csp_ro = hdrs.get("content-security-policy-report-only", "")
        sts = hdrs.get("strict-transport-security", "")
        perms = hdrs.get("permissions-policy", hdrs.get("feature-policy", ""))
        referrer = hdrs.get("referrer-policy", "")

        if csp_ro and not csp:
            findings.append(Finding(
                plugin="csp_analyzer",
                title="CSP in Report-Only Mode (Not Enforced)",
                severity="MEDIUM", confidence=100.0,
                description="CSP is in report-only mode — no active protection against XSS or data injection.",
                evidence=f"Content-Security-Policy-Report-Only: {csp_ro[:200]}",
                url=url,
                remediation="Switch to Content-Security-Policy header for active enforcement.",
                cwe="CWE-693", cvss=5.3, owasp="A05",
                tags=["csp", "report-only", "misconfiguration"],
            ))

        if not csp and not csp_ro:
            findings.append(Finding(
                plugin="csp_analyzer",
                title="Content-Security-Policy Header Completely Absent",
                severity="MEDIUM", confidence=100.0,
                description="No CSP header set — XSS attacks have no policy-level mitigation.",
                evidence="Neither CSP nor CSP-Report-Only header present",
                url=url,
                remediation="Implement a strict CSP with nonces or hashes for inline scripts.",
                cwe="CWE-693", cvss=5.4, owasp="A05",
                tags=["csp", "missing"],
            ))
        else:
            active_csp = csp or csp_ro
            for val, sev, desc in self.DANGEROUS_CSP_VALUES:
                if val in active_csp.lower():
                    findings.append(Finding(
                        plugin="csp_analyzer",
                        title=f"CSP Weakness: '{val}' Detected",
                        severity=sev, confidence=100.0,
                        description=f"CSP contains '{val}' — {desc}.",
                        evidence=f"CSP fragment containing '{val}': {active_csp[:300]}",
                        url=url,
                        remediation=(
                            f"Remove '{val}' from CSP. Use nonces or hashes for inline scripts. "
                            "Avoid eval() usage."
                        ),
                        cwe="CWE-693", cvss=6.5, owasp="A05",
                        tags=["csp", val.replace("-", ""), "misconfiguration"],
                    ))

            directives_present = [d.strip().split()[0] for d in active_csp.split(";") if d.strip()]
            for required in self.REQUIRED_DIRECTIVES:
                if not any(required == d.lower() for d in directives_present):
                    sev = "HIGH" if required in ("object-src", "script-src") else "LOW"
                    findings.append(Finding(
                        plugin="csp_analyzer",
                        title=f"CSP Missing Directive: '{required}'",
                        severity=sev, confidence=95.0,
                        description=f"CSP lacks '{required}' directive — fallback to default-src may be overly permissive.",
                        evidence=f"Present directives: {directives_present}",
                        url=url,
                        remediation=f"Add '{required}: none' or a specific allowlist to your CSP.",
                        cwe="CWE-693", cvss=4.3, owasp="A05",
                        tags=["csp", "missing-directive"],
                    ))

        if sts:
            ma_match = re.search(r"max-age=(\d+)", sts, re.I)
            if ma_match:
                max_age = int(ma_match.group(1))
                if max_age < 15552000:
                    findings.append(Finding(
                        plugin="csp_analyzer",
                        title=f"HSTS max-age Too Short: {max_age}s (< 180 days)",
                        severity="LOW", confidence=100.0,
                        description=f"HSTS max-age={max_age}s is below the recommended 180 days (15552000s).",
                        evidence=f"Strict-Transport-Security: {sts}",
                        url=url,
                        remediation="Set max-age to at least 31536000 (1 year). Add includeSubDomains; preload.",
                        cwe="CWE-319", cvss=3.7, owasp="A05",
                        tags=["hsts", "misconfiguration"],
                    ))
            if "includesubdomains" not in sts.lower():
                findings.append(Finding(
                    plugin="csp_analyzer",
                    title="HSTS Missing 'includeSubDomains'",
                    severity="LOW", confidence=100.0,
                    description="HSTS does not include subdomains — subdomain downgrade attacks possible.",
                    evidence=f"Strict-Transport-Security: {sts}",
                    url=url,
                    remediation="Add 'includeSubDomains' to HSTS header.",
                    cwe="CWE-319", cvss=3.1, owasp="A05",
                    tags=["hsts", "misconfiguration"],
                ))

        if not referrer:
            findings.append(Finding(
                plugin="csp_analyzer",
                title="Referrer-Policy Header Missing",
                severity="LOW", confidence=100.0,
                description="No Referrer-Policy — sensitive URL parameters may leak via Referer header to third parties.",
                evidence="Referrer-Policy header absent",
                url=url,
                remediation="Set Referrer-Policy: strict-origin-when-cross-origin or no-referrer.",
                cwe="CWE-200", cvss=3.1, owasp="A05",
                tags=["referrer-policy", "information-disclosure"],
            ))

        dangerous_features = ["camera", "microphone", "geolocation", "payment", "usb"]
        if not perms:
            findings.append(Finding(
                plugin="csp_analyzer",
                title="Permissions-Policy Header Missing",
                severity="LOW", confidence=100.0,
                description="No Permissions-Policy — browser features (camera, mic, geolocation) not restricted.",
                evidence="Permissions-Policy header absent",
                url=url,
                remediation="Add Permissions-Policy: camera=(), microphone=(), geolocation=(), payment=().",
                cwe="CWE-693", cvss=2.0, owasp="A05",
                tags=["permissions-policy"],
            ))
        else:
            for feat in dangerous_features:
                if feat not in perms.lower():
                    findings.append(Finding(
                        plugin="csp_analyzer",
                        title=f"Permissions-Policy Missing Restriction: '{feat}'",
                        severity="LOW", confidence=90.0,
                        description=f"Feature '{feat}' not restricted in Permissions-Policy.",
                        evidence=f"Permissions-Policy: {perms[:200]}",
                        url=url,
                        remediation=f"Add '{feat}=()' to Permissions-Policy.",
                        cwe="CWE-693", cvss=1.5, owasp="A05",
                        tags=["permissions-policy", feat],
                    ))

        log("OK", f"CSP analyzer done — {len(findings)} issue(s)")
        return findings


