#  MODULE v41-7 — Advanced Race Condition Scanner
# ════════════════════════════════════════════════════════════════════════

class AdvancedRaceConditionScanner:
    """
    Multi-scenario race condition testing:
    - Coupon code reuse via parallel requests (≤15ms window)
    - Double-spend on purchase/payment endpoints
    - User registration with duplicate email
    - File upload race (multiple simultaneous uploads)
    - Rate limit bypass via concurrent burst
    """

    async def _parallel_burst(self, client: "WebScoutClient", method: str,
                               url: str, count: int = 20,
                               data=None, json_body=None) -> list:
        """Fire `count` requests simultaneously."""
        tasks = [
            client.request(method, url, data=data, json_body=json_body)
            for _ in range(count)
        ]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        exc_count = sum(1 for r in results if isinstance(r, Exception))
        if exc_count:
            log("WARN", f"Race burst to {url}: {exc_count}/{count} request(s) raised exceptions "
                        f"(e.g. {next(r for r in results if isinstance(r, Exception))})")
        return results

    async def test_coupon_race(self, client: "WebScoutClient", url: str,
                                coupon: str = "SAVE10") -> list:
        findings = []
        parsed = urlparse(url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        coupon_endpoints = [
            f"{base}/api/coupon/apply",
            f"{base}/api/cart/coupon",
            f"{base}/coupon",
            f"{base}/discount/apply",
        ]
        for ep in coupon_endpoints:
            results = await self._parallel_burst(
                client, "POST", ep,
                json_body={"coupon": coupon, "code": coupon},
                count=15
            )
            success_count = sum(
                1 for r in results
                if isinstance(r, dict) and r and r.get("status") in (200, 201) and
                any(s in (r.get("text") or "").lower() for s in ["success", "applied", "discount", "saved"])
            )
            if success_count >= 2:
                findings.append(Finding(
                    plugin="race_condition",
                    title=f"Race Condition: Coupon '{coupon}' Applied {success_count}x Simultaneously",
                    severity="HIGH", confidence=88.0,
                    description=(
                        f"Sending {15} parallel coupon apply requests resulted in {success_count} successes — "
                        "race window allows multiple applications of the same coupon."
                    ),
                    evidence=f"Success count: {success_count}/15 | Endpoint: {ep}",
                    url=ep, payload=coupon,
                    remediation="Use atomic DB operations or distributed locks. Implement idempotency keys.",
                    cwe="CWE-362", cvss=7.5, owasp="A04",
                    tags=["race-condition", "coupon", "business-logic"],
                ))
                log("VULN", f"Race: coupon {coupon} applied {success_count}x at {ep}")
        return findings

    async def test_registration_race(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        parsed = urlparse(url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        reg_email = f"race_{secrets.token_hex(4)}@ws41test.invalid"
        reg_endpoints = [
            f"{base}/api/register", f"{base}/api/auth/register",
            f"{base}/register", f"{base}/signup",
            f"{base}/api/users", f"{base}/api/v1/users",
        ]
        for ep in reg_endpoints:
            payload = {
                "email": reg_email, "username": f"ws41_{secrets.token_hex(4)}",
                "password": "Ws41Test!Pass#" + secrets.token_hex(4),
            }
            results = await self._parallel_burst(client, "POST", ep,
                                                  json_body=payload, count=10)
            success_count = sum(
                1 for r in results
                if isinstance(r, dict) and r and r.get("status") in (200, 201)
            )
            if success_count >= 2:
                findings.append(Finding(
                    plugin="race_condition",
                    title=f"Race Condition: Duplicate User Registration ({success_count}x)",
                    severity="HIGH", confidence=82.0,
                    description=(
                        f"Parallel registration with same email produced {success_count} successes — "
                        "duplicate account creation possible, uniqueness constraint not atomic."
                    ),
                    evidence=f"Email: {reg_email} | {success_count}/10 requests succeeded | Endpoint: {ep}",
                    url=ep, payload=reg_email,
                    remediation="Use DB unique constraints with proper transaction isolation. Check email uniqueness atomically.",
                    cwe="CWE-362", cvss=6.5, owasp="A04",
                    tags=["race-condition", "registration", "duplicate"],
                ))
        return findings

    async def test_rate_limit_race(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        parsed = urlparse(url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        auth_paths = ["/api/login", "/login", "/api/auth/token",
                      "/api/auth", "/api/v1/auth/login"]
        for path in auth_paths:
            ep = base + path
            results = await self._parallel_burst(
                client, "POST", ep,
                json_body={"username": "admin", "password": "wrong_password_ws41"},
                count=25
            )
            non_429 = sum(
                1 for r in results
                if isinstance(r, dict) and r and r.get("status") not in (429, 403, 423)
            )
            if non_429 >= 20:
                findings.append(Finding(
                    plugin="race_condition",
                    title=f"Rate Limit Bypass via Race Condition — {path}",
                    severity="MEDIUM", confidence=80.0,
                    description=(
                        f"{non_429}/25 simultaneous login attempts reached the server without rate limiting — "
                        "brute-force rate limits can be bypassed via parallel requests."
                    ),
                    evidence=f"Non-429 responses: {non_429}/25 | Endpoint: {ep}",
                    url=ep,
                    remediation="Use global rate limiting with atomic counters (Redis INCR). Apply per-IP and per-account limits.",
                    cwe="CWE-307", cvss=6.5, owasp="A07",
                    tags=["race-condition", "rate-limit-bypass", "brute-force"],
                ))
        return findings

    async def scan(self, client: "WebScoutClient", url: str,
                   coupon_codes: list = None) -> list:
        log("SCAN", "Running advanced race condition scanner…")
        findings = []
        for coupon in (coupon_codes or ["SAVE10", "DISCOUNT20", "FREE", "TEST"]):
            findings += await self.test_coupon_race(client, url, coupon)
        findings += await self.test_registration_race(client, url)
        findings += await self.test_rate_limit_race(client, url)
        log("OK", f"Race condition scan done — {len(findings)} issue(s)")
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE v41-8 — SPA (Single-Page Application) Scanner
# ════════════════════════════════════════════════════════════════════════

class SPAScanner:
    """
    Detects and analyzes Single-Page Applications:
    - Framework identification (React, Vue, Angular, Next.js, Nuxt, Svelte)
    - Route extraction from JS bundles
    - API endpoint harvesting from JS source
    - Auth bypass via direct route navigation
    - Exposed Redux/Vuex store contents
    """

    SPA_SIGNATURES = {
        "React":     [r"__reactFiber", r"React\.createElement", r"createRoot"],
        "Vue.js":    [r"__vue__", r"Vue\.component", r"createApp"],
        "Angular":   [r"ng-version", r"NgModule", r"platformBrowser"],
        "Next.js":   [r"__NEXT_DATA__", r"_next/static/", r"getServerSideProps"],
        "Nuxt.js":   [r"__NUXT__", r"_nuxt/", r"nuxtApp"],
        "Svelte":    [r"__svelte", r"SvelteComponent"],
        "Ember.js":  [r"Ember\.Application", r"ember-source"],
        "Backbone":  [r"Backbone\.Model", r"Backbone\.View"],
    }

    ROUTE_PATTERNS = [
        r'path\s*:\s*["\']([/a-zA-Z0-9:_-]+)["\']',
        r'route\s*\(["\']([/a-zA-Z0-9:_-]+)["\']',
        r'"/([a-zA-Z0-9_/-]+)":\s*\{',
        r"from\s+['\"]\.\.?/([a-zA-Z0-9_/-]+)['\"]",
    ]

    API_PATTERNS = [
        r'(?:fetch|axios|http|api)\s*[\.\(]["\']?(/api/[a-zA-Z0-9/_-]+)',
        r'baseURL\s*:\s*["\']([^"\']+)["\']',
        r'["\']/(api|v[0-9]+)/([a-zA-Z0-9/_-]+)["\']',
        r'endpoint[sS]?\s*=\s*\{([^}]+)\}',
    ]

    async def _fetch_js_bundles(self, client: "WebScoutClient", url: str) -> list:
        """Fetch main page and download linked JS bundles."""
        r = await client.get(url)
        if not r:
            return []
        sources = [r["text"]]
        parsed = urlparse(url)
        for m in re.finditer(r'src=["\']([^"\']+\.js[^"\']*)["\']', r["text"], re.I):
            js_url = urljoin(url, m.group(1))
            if urlparse(js_url).netloc == parsed.netloc:
                jr = await client.get(js_url)
                if jr:
                    sources.append(jr["text"])
        return sources

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        log("SCAN", "Running SPA scanner…")
        sources = await self._fetch_js_bundles(client, url)
        if not sources:
            return findings

        combined = "\n".join(sources)

        detected_frameworks = [
            fw for fw, pats in self.SPA_SIGNATURES.items()
            if any(re.search(p, combined) for p in pats)
        ]

        if detected_frameworks:
            findings.append(Finding(
                plugin="spa_scanner",
                title=f"SPA Framework Detected: {', '.join(detected_frameworks)}",
                severity="INFO", confidence=90.0,
                description=f"Single-Page Application using {', '.join(detected_frameworks)} detected.",
                evidence=f"Frameworks: {detected_frameworks}",
                url=url,
                remediation="Ensure all API routes enforce server-side authorization — client-side routing is not a security control.",
                tags=["spa", "framework"] + [f.lower() for f in detected_frameworks],
            ))

        routes = set()
        for pat in self.ROUTE_PATTERNS:
            for m in re.finditer(pat, combined):
                route = m.group(1)
                if len(route) > 1 and "." not in route.split("/")[-1]:
                    routes.add(route if route.startswith("/") else "/" + route)

        sensitive_routes = [r for r in routes if any(
            kw in r.lower() for kw in
            ["admin", "internal", "debug", "config", "secret", "manage",
             "dashboard", "panel", "sys", "superuser", "root"]
        )]

        if sensitive_routes:
            parsed = urlparse(url)
            base = f"{parsed.scheme}://{parsed.netloc}"
            for route in sensitive_routes[:10]:
                r2 = await client.get(base + route, allow_redirects=False)
                if r2 and r2["status"] == 200:
                    findings.append(Finding(
                        plugin="spa_scanner",
                        title=f"SPA Sensitive Route Accessible: {route}",
                        severity="HIGH", confidence=82.0,
                        description=(
                            f"Sensitive route '{route}' extracted from JS bundle is directly accessible "
                            "(HTTP 200) — server-side auth may be missing."
                        ),
                        evidence=f"Route: {route} | HTTP {r2['status']} | Size: {r2['length']}B",
                        url=base + route,
                        remediation="Implement server-side authentication/authorization on all API routes behind SPA.",
                        cwe="CWE-285", cvss=8.1, owasp="A01",
                        tags=["spa", "route", "unauthorized-access"],
                    ))

        if not sensitive_routes and routes:
            findings.append(Finding(
                plugin="spa_scanner",
                title=f"SPA Routes Extracted from JS Bundle — {len(routes)} route(s)",
                severity="INFO", confidence=85.0,
                description=f"Extracted {len(routes)} route(s) from JS bundles — verify server-side authorization on each.",
                evidence=f"Routes: {list(routes)[:10]}",
                url=url,
                remediation="Audit all extracted routes for proper server-side authorization controls.",
                tags=["spa", "route-disclosure"],
            ))

        api_endpoints = set()
        for pat in self.API_PATTERNS:
            for m in re.finditer(pat, combined, re.I):
                ep = m.group(1) if m.lastindex >= 1 else ""
                if ep and ep.startswith("/"):
                    api_endpoints.add(ep)

        if api_endpoints:
            findings.append(Finding(
                plugin="spa_scanner",
                title=f"API Endpoints Extracted from SPA JS — {len(api_endpoints)} endpoint(s)",
                severity="INFO", confidence=80.0,
                description="API endpoints discovered in JS bundles — test each for authentication and authorization.",
                evidence=f"Endpoints: {list(api_endpoints)[:10]}",
                url=url,
                remediation="Ensure all extracted API endpoints enforce authentication and input validation.",
                tags=["spa", "api-disclosure"],
            ))

        redux_pattern = re.search(r'window\.__REDUX_STATE__\s*=\s*(\{[^;]+\})', combined)
        if redux_pattern:
            state_snippet = redux_pattern.group(1)[:200]
            findings.append(Finding(
                plugin="spa_scanner",
                title="Redux/Vuex State Exposed in Page Source",
                severity="MEDIUM", confidence=88.0,
                description="Application state object (Redux/Vuex) exposed in page source — may contain sensitive user data or auth tokens.",
                evidence=f"State: {state_snippet}…",
                url=url,
                remediation="Never serialize sensitive auth tokens or PII into initial Redux/Vuex store for SSR.",
                cwe="CWE-312", cvss=5.3, owasp="A02",
                tags=["spa", "state-disclosure", "redux"],
            ))

        log("OK", f"SPA scan done — {len(findings)} issue(s)")
        return findings


