#  MODULE v41-9 — Smart Credential Guesser
# ════════════════════════════════════════════════════════════════════════

class SmartCredentialGuesser:
    """
    Intelligent credential guessing with:
    - Domain-derived passwords (company name + year/symbol)
    - Common username/password combos
    - Progressive lockout detection
    - Spray mode (one password across many usernames)
    """

    COMMON_USERS = [
        "admin", "administrator", "root", "superuser", "user",
        "test", "demo", "guest", "support", "helpdesk",
        "info", "webmaster", "sysadmin", "operator",
    ]

    COMMON_PASSWORDS = [
        "password", "Password1", "password123", "P@ssw0rd", "admin",
        "admin123", "letmein", "welcome", "qwerty", "12345678",
        "changeme", "secret", "test", "test123", "abc123",
        "111111", "dragon", "iloveyou", "monkey", "login",
        "pass", "master", "hello", "sunshine", "shadow",
    ]

    async def _find_login_endpoint(self, client: "WebScoutClient", url: str) -> Optional[dict]:
        """Locate login form or API endpoint."""
        parsed = urlparse(url)
        base = f"{parsed.scheme}://{parsed.netloc}"
        login_paths = [
            "/login", "/api/login", "/api/auth/login", "/auth/login",
            "/api/auth", "/api/v1/auth/login", "/api/v1/login",
            "/admin/login", "/wp-login.php", "/user/login",
            "/signin", "/api/signin", "/account/login",
        ]
        for path in login_paths:
            r = await client.get(base + path)
            if r and r["status"] in (200, 401, 405):
                is_json = "application/json" in r["headers"].get("content-type", "")
                form_action = re.search(r'<form[^>]+action=["\']([^"\']*)["\']', r["text"], re.I)
                return {
                    "url": base + path, "is_json": is_json,
                    "form_action": form_action.group(1) if form_action else path,
                }
        return None

    def _derive_domain_passwords(self, url: str) -> list:
        """Generate passwords derived from the target domain."""
        parsed = urlparse(url)
        host = parsed.hostname or ""
        domain_parts = host.split(".")
        base_name = domain_parts[0] if domain_parts else "company"

        import datetime as _dt
        year = str(_dt.datetime.now().year)
        prev_year = str(_dt.datetime.now().year - 1)

        derived = [
            base_name, base_name.capitalize(),
            f"{base_name.capitalize()}{year}",
            f"{base_name.capitalize()}{year}!",
            f"{base_name.capitalize()}@{year}",
            f"{base_name}{year}",
            f"{base_name.capitalize()}1",
            f"{base_name.capitalize()}123",
            f"{base_name.capitalize()}!1",
            f"{base_name.upper()}{year}",
            f"Welcome{year}!",
            f"Welcome{prev_year}!",
        ]
        return derived

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        log("PASS", "Running smart credential guesser…")

        endpoint = await self._find_login_endpoint(client, url)
        if not endpoint:
            log("SKIP", "No login endpoint found for credential guessing")
            return findings

        ep_url = endpoint["url"]
        is_json = endpoint["is_json"]
        domain_passwords = self._derive_domain_passwords(url)

        test_passwords = self.COMMON_PASSWORDS[:15] + domain_passwords[:10]
        lockout_detected = False
        found_creds = []

        # Pre-fetch login page to extract CSRF token / nonce if the form requires one
        _CSRF_RE = re.compile(
            r'<input[^>]+name=["\']'
            r'(?:csrf_token|_token|csrfmiddlewaretoken|authenticity_token|_csrf|nonce)["\']'
            r'[^>]+value=["\']([^"\']+)["\']',
            re.I,
        )
        _CSRF_META_RE = re.compile(
            r'<meta[^>]+name=["\']csrf-token["\'][^>]+content=["\']([^"\']+)["\']', re.I
        )

        # Regex to extract XSRF-TOKEN cookie value (Angular / axios double-submit pattern)
        _XSRF_COOKIE_RE = re.compile(
            r'(?:^|;\s*)XSRF-TOKEN=([^;]+)', re.I
        )

        async def _get_csrf_token() -> tuple:
            """
            Return (token_value, field_name, cookie_header) from the login page.

            Covers three CSRF patterns:
              1. Synchronizer token in a hidden <input> field.
              2. Token in a <meta name="csrf-token"> tag (Rails/Laravel style).
              3. Double-submit cookie: XSRF-TOKEN set in Set-Cookie, expected back
                 as X-XSRF-TOKEN header (Angular / axios default behaviour).
            """
            r_page = await client.get(ep_url)
            if not r_page:
                return "", "", ""
            page_text = r_page["text"]
            raw_cookie = r_page.get("headers", {}).get("set-cookie", "")

            # Pattern 1 & 2: form input or <meta>
            m = _CSRF_RE.search(page_text) or _CSRF_META_RE.search(page_text)
            if m:
                token_val = m.group(1)
                fname_m = re.search(r'name=["\']([^"\']+)["\']', m.group(0), re.I)
                fname = fname_m.group(1) if fname_m else "csrf_token"
                return token_val, fname, raw_cookie

            # Pattern 3: XSRF-TOKEN cookie (used even by pure JSON APIs)
            xsrf_m = _XSRF_COOKIE_RE.search(raw_cookie)
            if xsrf_m:
                return xsrf_m.group(1).strip(), "X-XSRF-TOKEN", raw_cookie

            return "", "", ""

        _csrf_val, _csrf_field, _csrf_cookie = await _get_csrf_token()

        for username in self.COMMON_USERS[:8]:
            if lockout_detected:
                break
            for password in test_passwords:
                # Refresh CSRF token per-request for SYNCHRONIZER_TOKEN pattern apps
                if not is_json and _csrf_field:
                    _csrf_val, _csrf_field, _csrf_cookie = await _get_csrf_token()

                if is_json:
                    payload_json = {"username": username, "password": password,
                                    "email": username, "login": username}
                    # Many SPAs protect JSON endpoints via CSRF headers
                    # (X-CSRF-Token, X-CSRFToken, X-XSRF-TOKEN).
                    # Refresh and inject if the login page returned a token.
                    if _csrf_field:
                        _csrf_val, _csrf_field, _csrf_cookie = await _get_csrf_token()
                    json_hdrs: dict = {}
                    if _csrf_val:
                        json_hdrs["X-CSRF-Token"]  = _csrf_val
                        json_hdrs["X-CSRFToken"]    = _csrf_val
                        json_hdrs["X-XSRF-TOKEN"]  = _csrf_val
                    if _csrf_cookie:
                        json_hdrs["Cookie"] = _csrf_cookie
                    r = await client.post(ep_url, json_body=payload_json,
                                          headers=json_hdrs if json_hdrs else None)
                else:
                    form_data = (
                        f"username={quote(username)}&password={quote(password)}"
                        f"&email={quote(username)}"
                    )
                    if _csrf_field and _csrf_val:
                        form_data += f"&{quote(_csrf_field)}={quote(_csrf_val)}"
                    extra_hdrs = {"Content-Type": "application/x-www-form-urlencoded"}
                    if _csrf_cookie:
                        extra_hdrs["Cookie"] = _csrf_cookie
                    r = await client.post(ep_url, data=form_data, headers=extra_hdrs)

                if not r:
                    continue

                if r["status"] == 429 or "too many" in r["text"].lower() or "locked" in r["text"].lower():
                    lockout_detected = True
                    findings.append(Finding(
                        plugin="credential_guesser",
                        title="Account Lockout / Rate Limit Activated During Credential Test",
                        severity="INFO", confidence=95.0,
                        description="Login endpoint activated lockout or rate limiting after credential spray — lockout is working.",
                        evidence=f"HTTP {r['status']} | Triggered after: {username}:{password}",
                        url=ep_url,
                        remediation="Lockout is working correctly. Ensure lockout notification is sent to account owner.",
                        tags=["credential-guessing", "lockout", "rate-limit"],
                    ))
                    break

                success_indicators = [
                    "logout", "dashboard", "welcome", "profile", "token",
                    "access_token", "session", "authenticated", "success",
                ]
                fail_indicators = [
                    "invalid", "incorrect", "wrong", "failed", "error",
                    "bad credentials", "unauthorized",
                ]

                if r["status"] in (200, 302) and any(s in r["text"].lower() for s in success_indicators):
                    if not any(f in r["text"].lower() for f in fail_indicators):
                        found_creds.append((username, password))
                        findings.append(Finding(
                            plugin="credential_guesser",
                            title=f"Weak Credential Found: {username} / {password}",
                            severity="CRITICAL", confidence=90.0,
                            description=(
                                f"Login succeeded with common credential '{username}:{password}'. "
                                "Account is using a weak/default password."
                            ),
                            evidence=f"HTTP {r['status']} | Success indicators in response",
                            url=ep_url, param="username", payload=f"{username}:{password}",
                            remediation=(
                                "Enforce strong password policy. Require MFA. "
                                "Disable default credentials. Alert on login from new IP."
                            ),
                            cwe="CWE-521", cvss=9.8, owasp="A07",
                            tags=["credential-guessing", "weak-password", "default-credentials"],
                        ))
                        log("VULN", f"Credential found: {username}:{password}")

                await asyncio.sleep(0.1)

        if not lockout_detected and not found_creds:
            findings.append(Finding(
                plugin="credential_guesser",
                title="No Lockout Detected During Credential Spray",
                severity="MEDIUM", confidence=80.0,
                description=(
                    f"Tested {len(self.COMMON_USERS[:8]) * len(test_passwords)} credential combinations "
                    "without triggering account lockout or rate limiting."
                ),
                evidence=f"No 429/lockout response after {len(test_passwords)} attempts per user",
                url=ep_url,
                remediation="Implement account lockout after 5-10 failed attempts. Add IP-based rate limiting.",
                cwe="CWE-307", cvss=7.5, owasp="A07",
                tags=["credential-guessing", "no-lockout"],
            ))

        log("OK", f"Credential guesser done — {len(found_creds)} credential(s) found")
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE v41-10 — NVD Version Analyzer (CVE Lookup)
# ════════════════════════════════════════════════════════════════════════

class NVDVersionAnalyzer:
    """
    Queries the NIST NVD API to look up CVEs for detected software versions.
    Now also enriches each CVE with EPSS (Exploit Prediction Scoring System)
    probability via the FIRST.org API (Feature 4: CVE Live Feed).

    EPSS score = probability (0.0–1.0) that the CVE will be exploited in the
    next 30 days, derived from threat intel signals. A score ≥ 0.1 (10%)
    indicates active exploitation risk.
    """

    NVD_API_BASE  = "https://services.nvd.nist.gov/rest/json/cves/2.0"
    EPSS_API_BASE = "https://api.first.org/data/v1/epss"

    # In-memory response cache keyed by (keyword, version).
    # Without caching, a scan with 10 detected components makes 10 sequential NVD API
    # calls which quickly triggers the 5 req/30 s rate limit for unauthenticated users.
    # The cache is process-scoped (not cross-run) so data is never stale across restarts.
    _nvd_cache:  dict = {}  # {(keyword, version): [cve_dict, ...]}
    _epss_cache: dict = {}  # {cve_id: {"epss": float, "percentile": float}}

    VERSION_PATTERNS = {
        "Apache": r"Apache[/ ](\d+\.\d+(?:\.\d+)?)",
        "nginx": r"nginx[/ ](\d+\.\d+(?:\.\d+)?)",
        "PHP": r"PHP[/ ](\d+\.\d+(?:\.\d+)?)",
        "OpenSSL": r"OpenSSL[/ ](\d+\.\d+(?:\.\d+)?[a-z]?)",
        "WordPress": r"WordPress (\d+\.\d+(?:\.\d+)?)",
        "jQuery": r"jquery[/ @](\d+\.\d+(?:\.\d+)?)",
        "Bootstrap": r"Bootstrap[/ ](\d+\.\d+(?:\.\d+)?)",
        "Django": r"Django[/ ](\d+\.\d+(?:\.\d+)?)",
        "Laravel": r"Laravel[/ ](\d+\.\d+(?:\.\d+)?)",
        "Node.js": r"Node\.js[/ ](\d+\.\d+(?:\.\d+)?)",
        "Express": r"Express[/ ](\d+\.\d+(?:\.\d+)?)",
        "Spring": r"Spring[/ ](\d+\.\d+(?:\.\d+)?)",
        "Struts": r"Struts[/ ](\d+\.\d+(?:\.\d+)?)",
        "Tomcat": r"Apache Tomcat[/ ](\d+\.\d+(?:\.\d+)?)",
    }

    async def _query_epss(self, client: "WebScoutClient",
                           cve_ids: list) -> dict:
        """
        Query FIRST.org EPSS API for exploit probability of a list of CVE IDs.
        Returns dict: {cve_id: {"epss": float, "percentile": float}}

        EPSS (Exploit Prediction Scoring System) scores reflect the probability
        (0.0–1.0) of active exploitation within the next 30 days.
        Scores ≥ 0.10 indicate significant active exploitation risk.
        """
        if not cve_ids:
            return {}
        result = {}
        try:
            # Check cache first
            uncached = [c for c in cve_ids if c not in NVDVersionAnalyzer._epss_cache]
            if uncached:
                # EPSS API accepts comma-separated CVE IDs
                _batch = ",".join(uncached[:20])
                r = await client.get(
                    self.EPSS_API_BASE,
                    params={"cve": _batch, "limit": 20},
                    headers={"Accept": "application/json"},
                )
                if r and r.get("status") == 200:
                    try:
                        data = json.loads(r["text"])
                        for item in data.get("data", []):
                            cid = item.get("cve", "")
                            if cid:
                                NVDVersionAnalyzer._epss_cache[cid] = {
                                    "epss":       float(item.get("epss", 0.0)),
                                    "percentile": float(item.get("percentile", 0.0)),
                                }
                    except Exception:
                        pass
        except Exception as _epss_e:
            log("DEBUG", f"[NVD] EPSS query failed (non-fatal): {_epss_e}")

        for cid in cve_ids:
            result[cid] = NVDVersionAnalyzer._epss_cache.get(
                cid, {"epss": 0.0, "percentile": 0.0})
        return result

    async def _query_nvd(self, client: "WebScoutClient", keyword: str,
                          version: str, nvd_api_key: str = "") -> list:
        """
        Query NVD API (live) for CVEs matching software+version.
        Enriches each CVE with EPSS exploit-probability from FIRST.org.

        Results are cached in NVDVersionAnalyzer._nvd_cache so that repeated
        lookups for the same (keyword, version) pair within a single scan session
        never trigger additional API requests (avoids rate-limit HTTP 429).
        """
        _cache_key = (keyword.lower(), version)
        if _cache_key in NVDVersionAnalyzer._nvd_cache:
            log("DEBUG", f"NVD cache hit for {keyword} {version}")
            return NVDVersionAnalyzer._nvd_cache[_cache_key]
        try:
            params = {
                "keywordSearch": f"{keyword} {version}",
                "resultsPerPage": 15,
                # Pull only CVEs from the NVD live feed (no static DB)
            }
            headers = {}
            if nvd_api_key:
                headers["apiKey"] = nvd_api_key

            r = None
            _max_retries = 3
            _backoff = 10
            for _attempt in range(_max_retries):
                r = await client.get(self.NVD_API_BASE, params=params, headers=headers)
                if r and r["status"] == 429:
                    log("WARN", (
                        f"NVD API rate-limited (HTTP 429) — retry {_attempt + 1}/{_max_retries} "
                        f"after {_backoff}s. Without an API key, NIST enforces 5 req/30 s. "
                        "Use --nvd-api-key for 50 req/30 s. "
                        "Free key: https://nvd.nist.gov/developers/request-an-api-key"
                    ))
                    await asyncio.sleep(_backoff)
                    _backoff = min(_backoff * 2, 60)
                    continue
                break

            if not r or r["status"] != 200:
                NVDVersionAnalyzer._nvd_cache[_cache_key] = []
                return []

            data = json.loads(r["text"])
            cves = []
            for item in data.get("vulnerabilities", []):
                cve        = item.get("cve", {})
                cve_id     = cve.get("id", "")
                metrics    = cve.get("metrics", {})
                cvss_score = 0.0
                severity   = "UNKNOWN"
                for key in ["cvssMetricV31", "cvssMetricV30", "cvssMetricV2"]:
                    if key in metrics and metrics[key]:
                        data_v     = metrics[key][0].get("cvssData", {})
                        cvss_score = data_v.get("baseScore", 0.0)
                        severity   = data_v.get("baseSeverity", "UNKNOWN")
                        break
                desc_list = cve.get("descriptions", [])
                desc      = next(
                    (d["value"] for d in desc_list if d.get("lang") == "en"), "")
                published = cve.get("published", "")[:10]   # YYYY-MM-DD
                cves.append({
                    "id": cve_id, "score": cvss_score,
                    "severity": severity, "description": desc[:200],
                    "published": published,
                    "epss": 0.0, "epss_percentile": 0.0,
                })

            # ── Enrich with EPSS scores ───────────────────────────────────
            if cves:
                epss_map = await self._query_epss(client, [c["id"] for c in cves])
                for c in cves:
                    e = epss_map.get(c["id"], {})
                    c["epss"]            = e.get("epss", 0.0)
                    c["epss_percentile"] = e.get("percentile", 0.0)

            # Sort: EPSS score first (active exploitation priority), then CVSS
            result = sorted(cves, key=lambda x: (-(x["epss"]), -(x["score"])))
            NVDVersionAnalyzer._nvd_cache[_cache_key] = result
            return result
        except Exception as e:
            log("WARN", f"NVD API query failed for {keyword} {version}: {e}")
            NVDVersionAnalyzer._nvd_cache[_cache_key] = []
            return []

    async def scan(self, client: "WebScoutClient", url: str,
                   nvd_api_key: str = "") -> list:
        """
        Live CVE Feed scan (Feature 4): queries NVD API in real-time and
        enriches each result with EPSS exploit-probability.
        """
        findings = []
        log("SCAN", "Running NVD live CVE feed analyzer…")

        r = await client.get(url)
        if not r:
            return findings

        combined = r["text"] + " ".join(f"{k}:{v}" for k, v in r["headers"].items())

        detected_versions = {}
        for software, pattern in self.VERSION_PATTERNS.items():
            m = re.search(pattern, combined, re.I)
            if m:
                detected_versions[software] = m.group(1)
                log("SCAN", f"NVD: detected {software} {m.group(1)}")

        if not detected_versions:
            log("OK", "NVD: No software versions detected in responses")
            return findings

        for software, version in detected_versions.items():
            cves         = await self._query_nvd(client, software, version, nvd_api_key)
            critical_high = [c for c in cves if c["score"] >= 7.0]
            actively_exploited = [c for c in cves if c.get("epss", 0.0) >= 0.10]

            if critical_high or actively_exploited:
                worst = (actively_exploited or critical_high)[0]
                epss_str = (
                    f"EPSS: {worst['epss']:.1%} exploitation probability "
                    f"(top {(1 - worst.get('epss_percentile', 0)) * 100:.0f}th percentile)"
                    if worst.get("epss", 0.0) > 0 else ""
                )
                sev = "CRITICAL" if worst["score"] >= 9.0 or worst.get("epss", 0) >= 0.30 else "HIGH"
                findings.append(Finding(
                    plugin="nvd_analyzer",
                    title=(
                        f"{'[ACTIVELY EXPLOITED] ' if worst.get('epss',0)>=0.10 else ''}"
                        f"CVE Match: {software} {version} — "
                        f"{worst['id']} (CVSS {worst['score']})"
                    ),
                    severity=sev,
                    confidence=90.0,
                    description=(
                        f"{software} version {version} matches "
                        f"{len(critical_high)} CVE(s) with CVSS ≥7.0 "
                        f"and {len(actively_exploited)} with EPSS ≥10%. "
                        f"Worst: {worst['id']} (CVSS {worst['score']}) — "
                        f"{worst['description']}. "
                        f"{epss_str}"
                    ),
                    evidence=(
                        f"Software: {software} {version} | "
                        f"Published: {worst.get('published','?')} | "
                        f"CVEs (CVSS≥7): {[c['id'] for c in critical_high[:3]]} | "
                        f"EPSS≥10%: {[c['id'] for c in actively_exploited[:3]]} | "
                        f"Highest CVSS: {worst['score']} | "
                        f"{epss_str}"
                    ),
                    url=url,
                    remediation=(
                        f"Update {software} to the latest stable version immediately. "
                        f"Review: https://nvd.nist.gov/vuln/search/results?query="
                        f"{software}+{version} | "
                        f"EPSS: https://api.first.org/data/v1/epss?cve={worst['id']}"
                    ),
                    cwe="CWE-1104", cvss=worst["score"], owasp="A06",
                    tags=(["nvd", "cve", "outdated-component", software.lower()] +
                          (["epss-high", "actively-exploited"]
                           if worst.get("epss", 0) >= 0.10 else [])),
                ))
                log("WARN",
                    f"NVD: {software} {version} → {len(critical_high)} high CVE(s), "
                    f"{len(actively_exploited)} actively exploited (EPSS≥10%)")
            elif cves:
                best_epss = max(c.get("epss", 0.0) for c in cves)
                findings.append(Finding(
                    plugin="nvd_analyzer",
                    title=f"Known Version Detected: {software} {version} ({len(cves)} CVE match(es))",
                    severity="LOW", confidence=75.0,
                    description=(
                        f"{software} {version} has {len(cves)} known CVE(s), "
                        f"none above CVSS 7.0. Highest EPSS: {best_epss:.1%}"
                    ),
                    evidence=(
                        f"CVEs: {[c['id'] for c in cves[:3]]} | "
                        f"Max EPSS: {best_epss:.3f}"
                    ),
                    url=url,
                    remediation=f"Keep {software} updated. Monitor NVD for new CVEs.",
                    cwe="CWE-1104", cvss=cves[0]["score"] if cves else 0.0,
                    owasp="A06", tags=["nvd", "cve", software.lower()],
                ))
            else:
                log("OK", f"NVD: {software} {version} — no matching CVEs found")

        log("OK", f"NVD live CVE feed done — {len(findings)} finding(s)")
        return findings


