#  MODULE v41-11 — Advanced WebSocket Scanner
# ════════════════════════════════════════════════════════════════════════

class AdvancedWebSocketScanner:
    """
    Enhanced WebSocket security testing:
    - Large frame DoS (oversized messages)
    - JSON injection in messages
    - Authentication weakness (unauthenticated WS connections)
    - Replay attack detection
    - Origin header validation bypass
    """

    HAS_WEBSOCKETS = False
    _websockets_warned: bool = False  # class-level: emit install hint only once

    def __init__(self):
        try:
            import importlib
            spec = importlib.util.find_spec("websockets")
            self.HAS_WEBSOCKETS = spec is not None
        except Exception:
            self.HAS_WEBSOCKETS = False

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        if not self.HAS_WEBSOCKETS:
            if not AdvancedWebSocketScanner._websockets_warned:
                AdvancedWebSocketScanner._websockets_warned = True
                log("INFO", (
                    "[AdvWebSocket] 'websockets' package not installed — "
                    "deep WebSocket testing is disabled. "
                    "Install with: pip install websockets — then re-run."
                ))
            return findings
        log("SCAN", "Running advanced WebSocket scanner…")

        parsed = urlparse(url)
        host = parsed.netloc
        ws_url = url.replace("https://", "wss://").replace("http://", "ws://")

        r = await client.get(url)
        if not r:
            return findings

        ws_endpoints = []
        body = r["text"]

        for m in re.finditer(r'''(?:new WebSocket|io\.connect|socket\.io)\s*\(\s*["'`]([^"'`]+)["'`]''',
                              body, re.I):
            ep = m.group(1)
            if not ep.startswith("ws"):
                ep = ws_url.rstrip("/") + ep
            ws_endpoints.append(ep)

        for m in re.finditer(r'"(wss?://[^"]+)"', body, re.I):
            ws_endpoints.append(m.group(1))

        if not ws_endpoints:
            for path in ["/ws", "/socket", "/websocket", "/io", "/socket.io"]:
                ws_test = f"wss://{host}{path}" if parsed.scheme == "https" else f"ws://{host}{path}"
                ws_endpoints.append(ws_test)

        if not self.HAS_WEBSOCKETS:
            if ws_endpoints:
                findings.append(Finding(
                    plugin="advanced_websocket",
                    title=f"WebSocket Endpoints Discovered (Install websockets for deep testing)",
                    severity="INFO", confidence=80.0,
                    description=f"Found {len(ws_endpoints)} potential WebSocket endpoint(s). Install 'websockets' package for full testing.",
                    evidence=f"Endpoints: {ws_endpoints[:5]}",
                    url=url,
                    remediation="pip install websockets — then re-run for full WebSocket security audit.",
                    tags=["websocket", "setup"],
                ))
            return findings

        import websockets as _ws

        for ws_ep in ws_endpoints[:3]:
            try:
                async with _ws.connect(
                    ws_ep, additional_headers={"Origin": "https://evil.ws41test.invalid"},
                    open_timeout=5, close_timeout=5
                ) as ws:
                    findings.append(Finding(
                        plugin="advanced_websocket",
                        title=f"WebSocket Accepts Arbitrary Origin",
                        severity="MEDIUM", confidence=88.0,
                        description="WebSocket connection accepted with untrusted Origin header — CSRF/CSWSH risk.",
                        evidence=f"Connected to {ws_ep} with Origin: evil.ws41test.invalid",
                        url=ws_ep,
                        remediation="Validate Origin header on WebSocket handshake against allowlist.",
                        cwe="CWE-346", cvss=6.5, owasp="A01",
                        tags=["websocket", "origin-bypass", "csrf"],
                    ))

                    injection_payloads = [
                        '{"__proto__":{"polluted":"ws41"}}',
                        '{"action":"/../admin","data":"test"}',
                        '{"id":"1 OR 1=1","action":"query"}',
                        '<script>alert(1)</script>',
                        "A" * 65536,
                    ]
                    for payload in injection_payloads:
                        try:
                            await ws.send(payload)
                            resp = await asyncio.wait_for(ws.recv(), timeout=3.0)
                            if "ws41" in str(resp) or "polluted" in str(resp):
                                findings.append(Finding(
                                    plugin="advanced_websocket",
                                    title="WebSocket JSON Injection / Prototype Pollution",
                                    severity="HIGH", confidence=85.0,
                                    description="WebSocket message reflection indicates JSON injection or prototype pollution.",
                                    evidence=f"Payload: {payload[:80]} | Response: {str(resp)[:100]}",
                                    url=ws_ep, payload=payload,
                                    remediation="Validate and sanitize all WebSocket messages server-side.",
                                    cwe="CWE-20", cvss=7.5, owasp="A03",
                                    tags=["websocket", "injection"],
                                ))
                        except asyncio.TimeoutError:
                            log("DEBUG", f"[AdvWebSocket] Payload probe timed out on {ws_ep}")
                        except Exception as _ws_probe_e:
                            log("DEBUG", f"[AdvWebSocket] Payload probe error on {ws_ep}: {_ws_probe_e}")

            except Exception as e:
                if "403" in str(e) or "401" in str(e):
                    findings.append(Finding(
                        plugin="advanced_websocket",
                        title=f"WebSocket Endpoint Found (Auth Required): {ws_ep}",
                        severity="INFO", confidence=80.0,
                        description="WebSocket endpoint exists but requires authentication.",
                        evidence=f"Connection error: {str(e)[:100]}",
                        url=ws_ep,
                        remediation="Verify authentication tokens are validated on WebSocket handshake, not just HTTP upgrade.",
                        tags=["websocket", "authentication"],
                    ))

        log("OK", f"Advanced WebSocket scan done — {len(findings)} issue(s)")
        return findings


