#  MODULE v41-12 — Advanced GraphQL Scanner
# ════════════════════════════════════════════════════════════════════════

class AdvancedGraphQLScanner:
    """
    Deep GraphQL security testing:
    - Merge query attack (query batching abuse)
    - Schema extraction with introspection disabled (field suggestion)
    - Field duplication DoS
    - Circular fragment detection
    - Directive injection
    - Authorization bypass via query aliasing
    """

    async def _find_graphql_endpoint(self, client: "WebScoutClient", url: str) -> Optional[str]:
        parsed = urlparse(url)
        base = f"{parsed.scheme}://{parsed.netloc}"
        for path in ["/graphql", "/api/graphql", "/graphql/v1", "/query", "/gql"]:
            r = await client.post(
                base + path,
                json_body={"query": "{__typename}"},
                headers={"Content-Type": "application/json"},
            )
            if r and r["status"] == 200 and "__typename" in r.get("text", ""):
                return base + path
        return None

    async def test_field_suggestion_extraction(self, client: "WebScoutClient",
                                                 ep: str) -> list:
        """Extract schema types via field suggestion errors even when introspection is disabled."""
        findings = []
        probe_q = '{"query": "{__typ {nam}}"}'
        r = await client.post(ep, data=probe_q,
                               headers={"Content-Type": "application/json"})
        if not r:
            return findings
        body = r["text"]
        if "Did you mean" in body or "suggestion" in body.lower():
            suggestions = re.findall(r'"([a-zA-Z_][a-zA-Z0-9_]*)"', body)
            if suggestions:
                findings.append(Finding(
                    plugin="graphql_advanced",
                    title="GraphQL Schema Leakage via Field Suggestion (Introspection Disabled)",
                    severity="MEDIUM", confidence=88.0,
                    description=(
                        "GraphQL error messages reveal type/field names via 'Did you mean?' suggestions — "
                        "schema can be reconstructed even with introspection disabled."
                    ),
                    evidence=f"Suggestions found: {suggestions[:10]}",
                    url=ep,
                    remediation="Disable field suggestions in production. Use generic error messages.",
                    cwe="CWE-209", cvss=5.3, owasp="A05",
                    tags=["graphql", "schema-leak", "suggestion"],
                ))
        return findings

    async def test_batching_abuse(self, client: "WebScoutClient", ep: str) -> list:
        """Test query batching for amplification and brute-force bypass."""
        findings = []
        batch_query = [
            {"query": f'{{user_{i}: __typename}}'}
            for i in range(100)
        ]
        r = await client.post(ep, json_body=batch_query,
                               headers={"Content-Type": "application/json"})
        if r and r["status"] == 200 and r["text"].count("__typename") >= 50:
            findings.append(Finding(
                plugin="graphql_advanced",
                title="GraphQL Query Batching Accepted (100 queries in single request)",
                severity="HIGH", confidence=90.0,
                description=(
                    "Server processed a batch of 100 GraphQL queries in a single HTTP request — "
                    "enables brute-force rate limit bypass and amplification DoS."
                ),
                evidence=f"100 batched queries → {r['text'].count('__typename')} results",
                url=ep,
                remediation="Disable or limit query batching. Add per-batch rate limiting.",
                cwe="CWE-400", cvss=7.5, owasp="A04",
                tags=["graphql", "batching", "rate-limit-bypass", "dos"],
            ))
        return findings

    async def test_directive_injection(self, client: "WebScoutClient", ep: str) -> list:
        """Test for directive injection that could bypass field-level authorization."""
        findings = []
        payloads = [
            '{"query": "{__schema @include(if: true) { types { name } } }"}',
            '{"query": "{viewer { sensitiveField @skip(if: false) } }"}',
        ]
        for payload in payloads:
            r = await client.post(ep, data=payload,
                                   headers={"Content-Type": "application/json"})
            if r and r["status"] == 200 and "types" in r.get("text", ""):
                findings.append(Finding(
                    plugin="graphql_advanced",
                    title="GraphQL Directive Injection — Introspection via @include",
                    severity="MEDIUM", confidence=80.0,
                    description="GraphQL directive injection (@include/@skip) bypasses schema restrictions.",
                    evidence=f"Payload: {payload[:100]} | Response contained schema data",
                    url=ep, payload=payload,
                    remediation="Validate and sanitize GraphQL directives server-side. Apply field-level authorization.",
                    cwe="CWE-285", cvss=5.3, owasp="A01",
                    tags=["graphql", "directive", "injection"],
                ))
                break
        return findings

    async def test_circular_fragment(self, client: "WebScoutClient", ep: str) -> list:
        """Test for circular fragment DoS (stack overflow via recursive fragments)."""
        findings = []
        q = """
        fragment A on __Schema { types { ...B } }
        fragment B on __Type { fields { type { ...A } } }
        query { __schema { ...A } }
        """
        r = await client.post(ep, json_body={"query": q},
                               headers={"Content-Type": "application/json"})
        if r:
            elapsed = r.get("time_ms", 0)
            if r["status"] == 500 or elapsed > 5000:
                findings.append(Finding(
                    plugin="graphql_advanced",
                    title="GraphQL Circular Fragment DoS",
                    severity="HIGH", confidence=80.0,
                    description="Circular fragment query caused server error or extreme delay — DoS via recursive fragments.",
                    evidence=f"HTTP {r['status']} | Response time: {elapsed}ms",
                    url=ep,
                    remediation="Implement query depth limiting and fragment cycle detection.",
                    cwe="CWE-400", cvss=6.5, owasp="A04",
                    tags=["graphql", "dos", "circular-fragment"],
                ))
        return findings

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        findings = []
        log("SCAN", "Running advanced GraphQL scanner…")
        ep = await self._find_graphql_endpoint(client, url)
        if not ep:
            log("SKIP", "No GraphQL endpoint found")
            return findings
        log("OK", f"GraphQL endpoint: {ep}")
        findings += await self.test_field_suggestion_extraction(client, ep)
        findings += await self.test_batching_abuse(client, ep)
        findings += await self.test_directive_injection(client, ep)
        findings += await self.test_circular_fragment(client, ep)
        log("OK", f"Advanced GraphQL scan done — {len(findings)} issue(s)")
        return findings


