#  MODULE v41-13 — ML Anomaly Detector (Isolation Forest)
# ════════════════════════════════════════════════════════════════════════

class MLAnomalyDetector:
    """
    Machine-learning based anomaly detection using Isolation Forest algorithm
    (implemented from scratch to avoid sklearn dependency).
    Detects unusual HTTP response patterns that may indicate unknown vulnerabilities
    or undocumented behavior.
    """

    # 50+ probe paths to provide a statistically more meaningful training set
    # for the Isolation Forest.  More samples reduce false positives significantly
    # because normal cluster tightens and anomalies stand out more clearly.
    PROBE_PATHS = [
        "/", "/index.html", "/login", "/logout", "/register",
        "/api", "/api/v1/health", "/api/v2", "/api/v3",
        "/admin", "/admin/login", "/administrator", "/wp-admin",
        "/api/users", "/api/user", "/api/profile", "/api/me",
        "/config", "/debug", "/status", "/health", "/ping",
        "/search?q=test", "/api/v1/users?limit=10", "/404_xyz_nonexistent",
        "/metrics", "/actuator", "/actuator/health", "/actuator/env",
        "/env", "/api/v1/admin", "/api/v1/config", "/.git/config",
        "/swagger.json", "/.env", "/api/v1/auth/token",
        "/phpinfo.php", "/info.php", "/.well-known/security.txt",
        "/robots.txt", "/sitemap.xml", "/crossdomain.xml",
        "/api/v1/orders", "/api/v1/products", "/api/v1/payments",
        "/api/v1/settings", "/api/v1/logs", "/api/v1/stats",
        "/backup.sql", "/db_backup.sql", "/web.config",
        "/server-status", "/server-info",
        "/api/graphql", "/graphql", "/gql",
        "/api/v1/tokens", "/api/v1/keys", "/api/v1/secrets",
    ]

    def _fit_isolation_forest(self, data: list, n_trees: int = 50,
                               sample_size: int = 16) -> list:
        """Minimal Isolation Forest: returns anomaly score per sample (higher = more anomalous)."""
        if len(data) < 4:
            return [0.0] * len(data)

        import random as _rand
        _rand.seed(42)  # Fixed seed for reproducible anomaly scores across runs

        def _isolation_tree(X: list, max_depth: int) -> dict:
            if len(X) <= 1 or max_depth <= 0:
                return {"type": "leaf", "size": len(X)}
            feature = _rand.randint(0, len(X[0]) - 1)
            vals = [x[feature] for x in X]
            mn, mx = min(vals), max(vals)
            if mn == mx:
                return {"type": "leaf", "size": len(X)}
            split = _rand.uniform(mn, mx)
            left = [x for x in X if x[feature] < split]
            right = [x for x in X if x[feature] >= split]
            return {
                "type": "node", "feature": feature, "split": split,
                "left": _isolation_tree(left, max_depth - 1),
                "right": _isolation_tree(right, max_depth - 1),
            }

        def _path_length(node: dict, x: list, depth: int = 0) -> float:
            if node["type"] == "leaf":
                n = node["size"]
                if n <= 1:
                    return depth
                h = 2 * (sum(1/i for i in range(1, n)) - (n-1)/n)
                return depth + h
            if x[node["feature"]] < node["split"]:
                return _path_length(node["left"], x, depth + 1)
            return _path_length(node["right"], x, depth + 1)

        import math as _math
        max_depth = int(_math.ceil(_math.log2(max(sample_size, 2))))
        scores = []
        for xi in data:
            avg_path = 0.0
            for _ in range(n_trees):
                sample = _rand.sample(data, min(sample_size, len(data)))
                tree = _isolation_tree(sample, max_depth)
                avg_path += _path_length(tree, xi)
            avg_path /= n_trees
            n = sample_size
            c_n = 2 * (sum(1/i for i in range(1, n)) - (n-1)/n) if n > 1 else 1.0
            score = 2 ** (-avg_path / c_n)
            scores.append(score)
        return scores

    async def scan(self, client: "WebScoutClient", base_url: str) -> list:
        findings = []
        log("AI", "Running ML anomaly detector (Isolation Forest)…")
        parsed = urlparse(base_url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        feature_vectors = []
        probe_results = []

        for path in self.PROBE_PATHS:
            t0 = time.perf_counter()
            r = await client.get(base + path)
            elapsed = time.perf_counter() - t0
            if not r:
                continue

            body = r["text"]
            from math import log2 as _log2
            freq = {}
            for ch in body[:2000]:
                freq[ch] = freq.get(ch, 0) + 1
            ln = len(body[:2000]) or 1
            entropy = -sum((c/ln)*_log2(c/ln) for c in freq.values() if c > 0)

            json_keys = 0
            try:
                if "application/json" in r["headers"].get("content-type", ""):
                    obj = json.loads(body)
                    json_keys = len(obj) if isinstance(obj, dict) else 0
            except Exception as _ml_json_e:
                log("DEBUG", f"ML: JSON parse error for {path}: {_ml_json_e}")

            vec = [
                float(r["status"]) / 1000.0,
                min(len(body), 100000) / 100000.0,
                min(elapsed, 10.0) / 10.0,
                len(r["headers"]) / 50.0,
                entropy / 8.0,
                float(json_keys) / 100.0,
            ]
            feature_vectors.append(vec)
            probe_results.append({"path": path, "status": r["status"],
                                   "size": len(body), "time": elapsed,
                                   "entropy": entropy, "url": base + path})

        if len(feature_vectors) < 4:
            log("WARN", "ML: insufficient probe data for anomaly detection")
            return findings

        scores = self._fit_isolation_forest(feature_vectors)

        THRESHOLD = 0.65
        anomalies = sorted(
            [(scores[i], probe_results[i]) for i in range(len(scores)) if scores[i] > THRESHOLD],
            key=lambda x: -x[0]
        )

        # Note on statistical reliability: this Isolation Forest is trained on
        # ~16-22 probe responses only, which is a very small sample.  Scores are
        # directionally useful but NOT statistically reliable — both false positives
        # (normal endpoints that look unusual among few peers) and false negatives
        # (vulnerabilities that blend with other anomalous responses) are common.
        # All ML findings MUST be treated as "Indicative — manual verification required."
        # Confidence is capped at 65% regardless of score to reflect this limitation.
        _ML_MAX_CONFIDENCE = 65.0
        _sample_count = len(feature_vectors)

        for score, meta in anomalies[:5]:
            # Downgrade severity by one level vs raw score to account for low sample reliability
            sev = "MEDIUM" if score > 0.80 else "LOW"
            findings.append(Finding(
                plugin="ml_anomaly",
                title=f"ML Anomaly Detected [Indicative] — {meta['path']} (score={score:.3f})",
                severity=sev,
                confidence=min(_ML_MAX_CONFIDENCE, score * 80),
                description=(
                    f"Isolation Forest flagged '{meta['path']}' as anomalous (score={score:.3f}). "
                    f"HTTP {meta['status']} | Size: {meta['size']}B | "
                    f"Time: {meta['time']:.2f}s | Entropy: {meta['entropy']:.2f}. "
                    "IMPORTANT: model trained on only "
                    f"{_sample_count} probe responses — results are indicative only. "
                    "Manual verification is required before treating this as a confirmed vulnerability."
                ),
                evidence=(
                    f"Anomaly score: {score:.3f} (threshold={THRESHOLD}) | "
                    f"Training samples: {_sample_count} | "
                    f"Path: {meta['path']} | Status: {meta['status']} | "
                    f"Size: {meta['size']} | Entropy: {meta['entropy']:.2f}"
                ),
                url=meta["url"],
                remediation=(
                    "Investigate this path manually. Verify expected behavior and access controls. "
                    "Do not treat this as a confirmed vulnerability without manual analysis."
                ),
                cwe="CWE-200", cvss=3.0, owasp="A05",
                poc=f"curl -s -o /dev/null -w '%{{http_code}} %{{size_download}} %{{time_total}}' {meta['url']}",
                tags=["ml", "anomaly", "isolation-forest", "indicative"],
            ))
            log("AI", f"ML anomaly [indicative]: {meta['path']} score={score:.3f}")

        log("OK", f"ML anomaly detection done — {len(findings)} anomaly/ies found")
        return findings


