#  MODULE v41-14 — Performance Monitor & Analytics
# ════════════════════════════════════════════════════════════════════════

class PerformanceMonitor:
    """
    Analyzes scan performance metrics and response timing:
    - Identifies slow endpoints (potential DoS vectors or bottlenecks)
    - Detects false-positive-prone paths
    - Measures scan coverage efficiency
    - Identifies rate-limit induced delays
    - Generates performance summary report
    """

    async def scan(self, client: "WebScoutClient", url: str,
                   existing_findings: list = None) -> list:
        findings = []
        log("SCAN", "Running performance monitor & analytics…")
        parsed = urlparse(url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        probe_paths = ["/", "/api", "/login", "/api/v1/health", "/nonexistent_ws41"]
        timing_data = []

        for path in probe_paths:
            times = []
            # 7 samples provide a statistically meaningful average and variance estimate
            # (3 samples are insufficient — single outlier dominates the mean).
            for _ in range(7):
                t0 = time.perf_counter()
                r = await client.get(base + path)
                times.append(time.perf_counter() - t0)
            avg_time = sum(times) / len(times)
            variance = sum((t - avg_time)**2 for t in times) / len(times)
            timing_data.append({
                "path": path, "avg": avg_time,
                "min": min(times), "max": max(times),
                "variance": variance,
            })

        slow_paths = [d for d in timing_data if d["avg"] > 2.0]
        for slow in slow_paths:
            findings.append(Finding(
                plugin="performance_monitor",
                title=f"Slow Response Detected — {slow['path']} (avg={slow['avg']:.2f}s)",
                severity="MEDIUM", confidence=85.0,
                description=(
                    f"Path '{slow['path']}' averages {slow['avg']:.2f}s response time "
                    f"(min={slow['min']:.2f}s, max={slow['max']:.2f}s). "
                    "Slow endpoints are potential DoS amplification vectors and indicate performance issues."
                ),
                evidence=f"Avg: {slow['avg']:.2f}s | Min: {slow['min']:.2f}s | Max: {slow['max']:.2f}s | Variance: {slow['variance']:.4f}",
                url=base + slow["path"],
                remediation="Profile server-side code. Add caching. Investigate database query performance.",
                cwe="CWE-400", cvss=3.0, owasp="A05",
                tags=["performance", "slow-response", "dos-potential"],
            ))

        high_variance = [d for d in timing_data if d["variance"] > 1.0 and d["avg"] > 0.5]
        for hv in high_variance:
            findings.append(Finding(
                plugin="performance_monitor",
                title=f"High Response Time Variance — {hv['path']} (σ²={hv['variance']:.2f})",
                severity="LOW", confidence=75.0,
                description=(
                    f"Path '{hv['path']}' shows high timing variance (σ²={hv['variance']:.2f}) — "
                    "suggests inconsistent server load, connection pooling issues, or time-based injection sensitivity."
                ),
                evidence=f"Variance: {hv['variance']:.4f} | Times: {[round(hv['min'],2), round(hv['avg'],2), round(hv['max'],2)]}",
                url=base + hv["path"],
                remediation="Investigate server-side performance inconsistency. Consider connection pooling and caching.",
                cwe="CWE-400", cvss=2.0, owasp="A05",
                tags=["performance", "variance", "timing"],
            ))

        stats = client.stats
        total_requests = stats.get("requests", 0)
        timeouts = stats.get("timeouts", 0)
        errors = stats.get("errors", 0)
        rate_limited = stats.get("rate_limited", 0)

        perf_summary = {
            "total_requests": total_requests,
            "timeouts": timeouts,
            "errors": errors,
            "rate_limited": rate_limited,
            "timeout_rate": f"{(timeouts/max(total_requests,1))*100:.1f}%",
            "error_rate": f"{(errors/max(total_requests,1))*100:.1f}%",
        }

        if rate_limited > 0:
            findings.append(Finding(
                plugin="performance_monitor",
                title=f"Rate Limiting Encountered During Scan ({rate_limited} requests throttled)",
                severity="INFO", confidence=100.0,
                description=(
                    f"Scanner was rate-limited {rate_limited} time(s) — target has active rate limiting. "
                    "Consider increasing --delay and reducing --concurrency for better coverage."
                ),
                evidence=f"Rate-limited requests: {rate_limited} | Total: {total_requests}",
                url=url,
                remediation="Rate limiting is a security control — ensure it is consistent across all endpoints.",
                tags=["performance", "rate-limiting", "scan-quality"],
            ))

        if timeouts > total_requests * 0.1 and total_requests > 10:
            findings.append(Finding(
                plugin="performance_monitor",
                title=f"High Timeout Rate During Scan ({perf_summary['timeout_rate']})",
                severity="LOW", confidence=80.0,
                description=(
                    f"{timeouts} timeout(s) out of {total_requests} requests ({perf_summary['timeout_rate']}) — "
                    "high timeout rate may indicate scan coverage gaps or server instability."
                ),
                evidence=f"Timeouts: {timeouts} | Errors: {errors} | Total: {total_requests}",
                url=url,
                remediation="Increase --timeout value. Check server stability. Reduce --concurrency.",
                tags=["performance", "timeouts", "scan-quality"],
            ))

        findings.append(Finding(
            plugin="performance_monitor",
            title="Scan Performance Summary",
            severity="INFO", confidence=100.0,
            description=(
                f"Scan statistics: {total_requests} total requests | "
                f"{timeouts} timeouts ({perf_summary['timeout_rate']}) | "
                f"{errors} errors ({perf_summary['error_rate']}) | "
                f"{rate_limited} rate-limited | "
                f"Avg response time across probes: {sum(d['avg'] for d in timing_data)/len(timing_data):.2f}s"
            ),
            evidence=json.dumps(perf_summary),
            url=url,
            remediation="Review scan parameters for optimal speed/accuracy tradeoff.",
            tags=["performance", "summary", "analytics"],
        ))

        log("OK", f"Performance monitor done — {len(findings)} finding(s)")
        return findings


