#  MODULE v41-15 — Advanced SameSite & CSRF Scanner
# ════════════════════════════════════════════════════════════════════════

class AdvancedSameSiteCSRFScanner:
    """
    Advanced CSRF testing with SameSite bypass scenarios:
    - SameSite=Lax bypass via GET requests with state-changing effects
    - SameSite=Lax bypass via top-level navigation in iframes
    - SameSite=None without Secure flag
    - Token predictability attacks (sequential or low-entropy tokens)
    - Double-submit cookie bypass
    - Content-type based CSRF (JSON with text/plain)
    """

    async def test_samesite_lax_get_bypass(self, client: "WebScoutClient",
                                             url: str) -> list:
        """Test if state-changing operations are possible via GET (SameSite=Lax bypass)."""
        findings = []
        r = await client.get(url)
        if not r:
            return findings

        # Tightened patterns: require action keywords in both the tag AND a meaningful path segment
        # (not just any link that contains these words in anchor text or outer content)
        state_change_patterns = [
            r'<a[^>]+href=["\'][^"\']*[/?](delete|remove|logout|cancel|purchase|transfer|confirm)[^"\']*["\']',
            r'<form[^>]+method=["\']get["\'][^>]*action=["\'][^"\']*[/?](delete|buy|confirm|transfer|update)[^"\']*["\']',
        ]

        # Success indicators: body should signal that a state change happened, not just a 200
        success_indicators = [
            "success", "deleted", "removed", "confirmed", "cancelled",
            "logged out", "transferred", "updated", "purchased",
        ]
        # Error indicators: if present the endpoint rejected the request → not a real bypass
        error_indicators = [
            "csrf", "token", "invalid", "forbidden", "not allowed",
            "access denied", "unauthorized", "error", "bad request",
        ]

        for pat in state_change_patterns:
            matches = re.findall(pat, r["text"], re.I)
            for match in matches[:3]:
                href = re.search(r'href=["\']([^"\']+)["\']', match, re.I)
                action = re.search(r'action=["\']([^"\']+)["\']', match, re.I)
                target = href.group(1) if href else (action.group(1) if action else "")
                if not target:
                    continue
                full_url = urljoin(url, target)
                test_r = await client.get(full_url)
                if not test_r or test_r["status"] not in (200, 302):
                    continue
                body_lower = test_r["text"].lower()
                # Only flag if response body confirms success AND has no CSRF/error rejection
                has_success = any(s in body_lower for s in success_indicators)
                has_error   = any(e in body_lower for e in error_indicators)
                if has_success and not has_error:
                    findings.append(Finding(
                        plugin="advanced_csrf",
                        title="SameSite=Lax Bypass: State-Changing GET Request",
                        severity="HIGH", confidence=82.0,
                        description=(
                            f"State-changing operation via GET found at '{full_url}'. "
                            "SameSite=Lax cookies are sent on top-level GET navigations — "
                            "attacker can trigger this action from another site via link or redirect."
                        ),
                        evidence=(
                            f"GET {full_url} → HTTP {test_r['status']} | "
                            f"Success indicator found in body | Pattern: {match[:100]}"
                        ),
                        url=full_url,
                        remediation=(
                            "State-changing operations must use POST, PUT, or DELETE. "
                            "Add CSRF token validation. Use SameSite=Strict for sensitive cookies."
                        ),
                        cwe="CWE-352", cvss=8.1, owasp="A01",
                        tags=["csrf", "samesite-lax-bypass", "get-based-csrf"],
                    ))
        return findings

    async def test_samesite_none_insecure(self, client: "WebScoutClient",
                                           url: str) -> list:
        """Detect SameSite=None cookies without Secure flag."""
        findings = []
        r = await client.get(url)
        if not r:
            return findings
        cookies = r["headers"].get("Set-Cookie", "")
        if not cookies:
            return findings
        cookie_list = cookies.split(",") if "," in cookies else [cookies]
        for ck in cookie_list:
            ck_lower = ck.lower()
            has_samesite_none = "samesite=none" in ck_lower
            has_secure = "secure" in ck_lower
            if has_samesite_none and not has_secure:
                findings.append(Finding(
                    plugin="advanced_csrf",
                    title="Cookie SameSite=None Without Secure Flag",
                    severity="HIGH", confidence=100.0,
                    description=(
                        "Cookie has SameSite=None but is missing the Secure flag. "
                        "Modern browsers reject SameSite=None without Secure, but this may expose "
                        "the cookie on HTTP connections and indicates a misconfiguration."
                    ),
                    evidence=f"Set-Cookie: {ck[:150]}",
                    url=url,
                    remediation="Add Secure flag to all cookies with SameSite=None. Use HTTPS exclusively.",
                    cwe="CWE-614", cvss=7.5, owasp="A07",
                    tags=["csrf", "samesite", "cookie", "misconfiguration"],
                ))
        return findings

    async def test_content_type_csrf(self, client: "WebScoutClient",
                                      url: str) -> list:
        """Test JSON endpoints accessible via text/plain Content-Type (CSRF via form)."""
        findings = []
        parsed = urlparse(url)
        params = parse_qs(parsed.query)

        r = await client.get(url)
        if not r:
            return findings

        forms = re.findall(r'<form[^>]+action=["\']([^"\']*)["\'][^>]*>.*?</form>',
                           r["text"], re.DOTALL | re.I)
        for form_action in forms[:5]:
            ep = urljoin(url, form_action)
            json_payload = '{"test":"ws41csrf","action":"update"}'
            r2 = await client.post(
                ep, data=json_payload,
                headers={"Content-Type": "text/plain"}
            )
            if r2 and r2["status"] in (200, 201):
                body = r2["text"].lower()
                if not any(e in body for e in ["invalid", "error", "bad request", "wrong content-type"]):
                    findings.append(Finding(
                        plugin="advanced_csrf",
                        title=f"CSRF via Content-Type Confusion (text/plain for JSON)",
                        severity="HIGH", confidence=80.0,
                        description=(
                            f"Endpoint '{ep}' accepts JSON payload with Content-Type: text/plain — "
                            "enables CSRF attacks via HTML form since browsers send form data as text/plain."
                        ),
                        evidence=f"POST {ep} with Content-Type: text/plain → HTTP {r2['status']}",
                        url=ep,
                        remediation="Strictly validate Content-Type header. Reject non-JSON content-types on JSON APIs.",
                        cwe="CWE-352", cvss=8.0, owasp="A01",
                        tags=["csrf", "content-type-confusion"],
                    ))
        return findings

    async def test_token_predictability(self, client: "WebScoutClient",
                                         url: str) -> list:
        """Collect multiple CSRF tokens and check for patterns or low entropy."""
        findings = []
        tokens = []
        for _ in range(5):
            r = await client.get(url)
            if not r:
                continue
            tok = SessionCSRFManager._extract_csrf(r["text"])
            if tok and len(tok) >= 4:
                tokens.append(tok)
            await asyncio.sleep(0.2)

        if len(tokens) < 3:
            return findings

        if len(set(tokens)) == 1:
            findings.append(Finding(
                plugin="advanced_csrf",
                title="CSRF Token is Static (Same Value Across All Requests)",
                severity="CRITICAL", confidence=98.0,
                description="CSRF token is identical across multiple requests — completely predictable and bypassable.",
                evidence=f"Token: {tokens[0]} | All {len(tokens)} tokens identical",
                url=url,
                remediation="Generate a unique, cryptographically random CSRF token per session AND per request.",
                cwe="CWE-330", cvss=9.1, owasp="A01",
                tags=["csrf", "static-token", "predictable"],
            ))
            return findings

        entropies = []
        for tok in tokens:
            if not tok:
                continue
            freq = {}
            for ch in tok:
                freq[ch] = freq.get(ch, 0) + 1
            ln = len(tok)
            ent = -sum((c/ln)*log2(c/ln) for c in freq.values() if c > 0)
            entropies.append(ent)

        avg_entropy = sum(entropies) / len(entropies) if entropies else 0
        if avg_entropy < 3.0:
            findings.append(Finding(
                plugin="advanced_csrf",
                title=f"CSRF Token Low Entropy (avg={avg_entropy:.2f} bits/char)",
                severity="HIGH", confidence=85.0,
                description=(
                    f"CSRF tokens have average entropy of {avg_entropy:.2f} bits/char — "
                    "below the recommended minimum of 3.0 bits/char. Tokens may be predictable."
                ),
                evidence=f"Tokens: {tokens[:3]} | Entropies: {[round(e,2) for e in entropies]}",
                url=url,
                remediation="Use cryptographically random 256-bit tokens. Avoid timestamp or sequential-based tokens.",
                cwe="CWE-330", cvss=7.5, owasp="A01",
                tags=["csrf", "low-entropy", "predictable"],
            ))
        return findings

    async def scan(self, client: "WebScoutClient", url: str) -> list:
        log("SCAN", "Running advanced SameSite & CSRF scanner…")
        findings = []
        findings += await self.test_samesite_lax_get_bypass(client, url)
        findings += await self.test_samesite_none_insecure(client, url)
        findings += await self.test_content_type_csrf(client, url)
        try:
            findings += await self.test_token_predictability(client, url)
        except Exception as _csrf_pred_e:
            log("DEBUG", f"[AdvCSRF] token_predictability probe failed: {_csrf_pred_e}")
        log("OK", f"Advanced CSRF/SameSite scan done — {len(findings)} issue(s)")
        return findings


