async def self_test(target: str = ""):
    """Run a quick self-test against a known vulnerable target to verify functionality.

    Args:
        target: URL to test against.  Falls back to the public demo lab
                http://testphp.vulnweb.com when not provided.
    """
    if not target:
        target = "http://testphp.vulnweb.com"
    print(f"{c(C.YELLOW)}[!] Starting self-test against {target} ...{c(C.RESET)}")
    cfg = ScanConfig(
        timeout=10,
        concurrency=5,
        verbose=True,
        # Minimal config
    )
    client = WebScoutClient(cfg)
    findings = []

    # Test SQLi scanner
    sqli = EnhancedSQLiScanner()
    findings += await sqli.scan(client, target, second_order=False)

    # Test XSS scanner
    xss = EnhancedXSSScanner()
    findings += await xss.scan(client, target)

    # Test Nuclei templates (built-in)
    nuclei = NucleiTemplateEngine(client)
    findings += await nuclei.run(target, tags=["sqli", "xss"])

    await client.close()

    # Summary
    print(f"{c(C.GREEN)}[✓] Self-test completed. Found {len(findings)} potential issues.{c(C.RESET)}")
    for f in findings[:5]:  # show first 5
        print(f"    - {f.title} ({f.severity})")
    if len(findings) > 5:
        print(f"    ... and {len(findings)-5} more.")

    print(f"{c(C.CYAN)}[*] If you see SQLi and XSS detections above, the tool is working as expected.{c(C.RESET)}")


