#  MODULE v40 — Sensitive File Exposure Scanner
# ════════════════════════════════════════════════════════════════════════

class SensitiveFileScanner:
    """
    Detects exposed sensitive files using content-signature verification.
    Every finding requires matching file-specific content patterns — HTTP 200
    alone is never sufficient (avoids false positives from custom 200-error pages).
    """

    TARGETS = [
        # (path, [content_signatures], description, severity, cvss)
        (".env",               [r"^[A-Z_]{2,}=\S", r"DB_HOST|DB_PASS|SECRET|API_KEY|PASSWORD"],
         "Environment secrets file",            "CRITICAL", 9.5),
        (".env.local",         [r"^[A-Z_]{2,}=\S"],
         "Local environment file",              "CRITICAL", 9.5),
        (".env.backup",        [r"^[A-Z_]{2,}=\S"],
         "Backup environment file",             "CRITICAL", 9.0),
        (".env.production",    [r"^[A-Z_]{2,}=\S"],
         "Production environment file",         "CRITICAL", 9.5),
        (".git/config",        [r"\[core\]", r"repositoryformatversion"],
         ".git repository config exposed",      "CRITICAL", 9.0),
        (".git/HEAD",          [r"ref: refs/heads/"],
         "Git HEAD file exposed",               "HIGH",     7.5),
        (".git/COMMIT_EDITMSG",[r".+"],
         "Git commit message exposed",          "MEDIUM",   5.0),
        ("wp-config.php",      [r"DB_NAME|DB_PASSWORD|table_prefix|AUTH_KEY"],
         "WordPress config exposed",            "CRITICAL", 9.5),
        ("config.php",         [r"\$db|mysql_connect|PDO|define.*PASSWORD"],
         "PHP database config exposed",         "CRITICAL", 9.5),
        ("settings.py",        [r"SECRET_KEY\s*=|DATABASES\s*=|ALLOWED_HOSTS"],
         "Django settings exposed",             "CRITICAL", 9.0),
        ("application.yml",    [r"datasource:|spring:|password:"],
         "Spring Boot config exposed",          "CRITICAL", 9.0),
        ("database.yml",       [r"adapter:|database:|password:"],
         "Rails database config exposed",       "CRITICAL", 9.0),
        (".htpasswd",          [r"[a-zA-Z0-9_.-]+:\$apr1\$|:[a-zA-Z0-9/+]{13}$"],
         "Apache password file exposed",        "CRITICAL", 9.0),
        ("backup.sql",         [r"INSERT INTO|CREATE TABLE|DROP TABLE"],
         "SQL database backup exposed",         "CRITICAL", 9.0),
        ("dump.sql",           [r"INSERT INTO|CREATE TABLE"],
         "SQL dump exposed",                    "CRITICAL", 9.0),
        ("db.sql",             [r"INSERT INTO|CREATE TABLE"],
         "SQL dump exposed",                    "CRITICAL", 9.0),
        ("database.sql",       [r"INSERT INTO|CREATE TABLE"],
         "SQL dump exposed",                    "CRITICAL", 9.0),
        ("phpinfo.php",        [r"PHP Version|php\.ini Path|Configure Command"],
         "phpinfo() page exposed",              "HIGH",     7.5),
        ("info.php",           [r"PHP Version|php\.ini"],
         "phpinfo() page exposed",              "HIGH",     7.5),
        ("server-status",      [r"Apache Server Status|Total Accesses|BytesPerSec"],
         "Apache mod_status exposed",           "HIGH",     7.5),
        ("server-info",        [r"Apache Server Information|Module Name"],
         "Apache mod_info exposed",             "MEDIUM",   5.5),
        (".aws/credentials",   [r"\[default\]|aws_access_key_id|aws_secret"],
         "AWS credentials exposed",             "CRITICAL", 10.0),
        (".ssh/id_rsa",        [r"-----BEGIN.*PRIVATE KEY-----"],
         "SSH private key exposed",             "CRITICAL", 10.0),
        ("id_rsa",             [r"-----BEGIN.*PRIVATE KEY-----"],
         "SSH private key exposed",             "CRITICAL", 10.0),
        ("private.key",        [r"-----BEGIN.*PRIVATE KEY-----"],
         "Private key exposed",                 "CRITICAL", 10.0),
        ("docker-compose.yml", [r"services:|image:|environment:"],
         "Docker Compose config exposed",       "MEDIUM",   5.5),
        ("Dockerfile",         [r"^FROM |^RUN |^EXPOSE "],
         "Dockerfile exposed",                  "LOW",      4.0),
        ("swagger.json",       [r'"swagger"|"openapi"|"paths"'],
         "API documentation (Swagger) exposed", "MEDIUM",   5.0),
        ("swagger.yaml",       [r"swagger:|openapi:|paths:"],
         "API documentation (Swagger) exposed", "MEDIUM",   5.0),
        ("api-docs.json",      [r'"swagger"|"openapi"'],
         "API documentation exposed",           "MEDIUM",   5.0),
        ("openapi.json",       [r'"openapi"'],
         "OpenAPI spec exposed",                "MEDIUM",   5.0),
        ("crossdomain.xml",    [r"allow-access-from|<cross-domain-policy"],
         "Flash crossdomain policy exposed",    "MEDIUM",   5.0),
        (".DS_Store",          [r"\x00\x00\x00\x01Bud1"],
         "macOS .DS_Store exposed",             "LOW",      3.0),
        ("composer.json",      [r'"require"|"name"|"autoload"'],
         "Composer dependencies exposed",       "LOW",      3.0),
        ("package.json",       [r'"dependencies"|"scripts"|"name"'],
         "NPM package.json exposed",            "LOW",      3.0),
        # Informational (no content signatures required)
        ("robots.txt",         [],
         "robots.txt present",                  "INFO",     0.0),
        (".well-known/security.txt", [],
         "security.txt present",                "INFO",     0.0),
    ]

    async def scan(self, client, url: str) -> list:
        findings = []
        parsed = urlparse(url)
        base = f"{parsed.scheme}://{parsed.netloc}"
        pb = ProgressBar(len(self.TARGETS), "Sensitive Files")

        for path, signatures, desc, severity, cvss in self.TARGETS:
            target_url = f"{base}/{path.lstrip('/')}"
            await pb.step(suffix=f" {path}")
            r = await client.get(target_url, allow_redirects=False)
            if not r or r["status"] not in (200, 206):
                continue
            body = r["text"]

            # Informational entries: just report presence (no content check needed)
            if not signatures:
                findings.append(Finding(
                    plugin="sensitive_files",
                    title=f"File Present: {path}",
                    severity="INFO", confidence=90.0,
                    description=f"{desc} is publicly accessible.",
                    evidence=f"URL: {target_url} | HTTP {r['status']} | Size: {r['length']}B",
                    url=target_url,
                    remediation="Review the file contents and restrict access if necessary.",
                    cwe="CWE-200", cvss=0.0, owasp="A05",
                    tags=["sensitive-files", "disclosure"],
                ))
                continue

            # Content-based confirmation: at least one signature must match
            matched = [sig for sig in signatures if re.search(sig, body, re.M | re.I)]
            if not matched:
                continue  # 200 but content doesn't match — likely a custom error page

            # Confidence grows with number of matched signatures
            confidence = min(97.0, 75.0 + len(matched) * 8.0)
            findings.append(Finding(
                plugin="sensitive_files",
                title=f"Sensitive File Exposed: {path}",
                severity=severity, confidence=confidence,
                description=(f"{desc} is publicly accessible with {len(matched)} "
                             f"content signature(s) confirmed."),
                evidence=(f"URL: {target_url} | HTTP {r['status']} | "
                          f"Signatures matched: {matched[:2]} | Size: {r['length']}B"),
                url=target_url,
                remediation=(
                    "Block access via web server config (deny all for sensitive paths). "
                    "Move config files above the web root. "
                    "Rotate any credentials found immediately."
                ),
                cwe="CWE-200", cvss=cvss, owasp="A05",
                poc=f"curl -sk '{target_url}'",
                tags=["sensitive-files", "disclosure", "confirmed"],
            ))
            log("VULN", f"Sensitive file confirmed: {path} ({len(matched)} signatures)")

        pb.finish()
        log("OK", f"Sensitive file scan done — {len(findings)} exposed")
        return findings


