#  MODULE v38-2 — Subdomain Takeover Scanner
# ════════════════════════════════════════════════════════════════════════

class SubdomainTakeoverScanner:
    """Detect dangling DNS CNAMEs that can be claimed (subdomain takeover)."""

    TAKEOVER_FINGERPRINTS = {
        "GitHub Pages":        ["There isn't a GitHub Pages site here", "github.io"],
        "Heroku":              ["No such app", "herokuapp.com"],
        "Netlify":             ["Not Found", "netlify.app"],
        "Vercel":              ["The deployment could not be found", "vercel.app"],
        "Shopify":             ["Sorry, this shop is currently unavailable", "myshopify.com"],
        "AWS S3":              ["NoSuchBucket", "s3.amazonaws.com", "s3-website"],
        "Azure":               ["404 Web Site not found", "azurewebsites.net", "blob.core.windows.net"],
        "Fastly":              ["Fastly error: unknown domain"],
        "Ghost":               ["The thing you were looking for is no longer here", "ghost.io"],
        "Tumblr":              ["There's nothing here", "tumblr.com"],
        "Surge.sh":            ["project not found", "surge.sh"],
        "Pantheon":            ["404 error unknown site", "pantheonsite.io"],
        "LaunchRock":          ["It looks like you may have taken a wrong turn", "launchrock.com"],
        "WP Engine":           ["The site you were looking for couldn't be found", "wpengine.com"],
        "HubSpot":             ["Domain not found", "hs-sites.com", "hubspot.com"],
        "Zendesk":             ["Help Center Closed", "zendesk.com"],
        "ReadTheDocs":         ["unknown to Read the Docs", "readthedocs.io"],
        "Cargo":               ["404 Not Found", "cargocollective.com"],
        "Tilda":               ["Domain not found", "tilda.ws"],
        "Smartling":           ["Domain is not configured"],
        "Bigcartel":           ["Oops! We could not find your store", "bigcartel.com"],
        "Statuspage.io":       ["You are being redirected", "statuspage.io"],
        "UptimeRobot":         ["page not found", "uptimerobot.com"],
    }

    COMMON_SUBDOMAINS = [
        "www", "mail", "remote", "blog", "webmail", "server", "ns1", "ns2",
        "smtp", "secure", "vpn", "m", "shop", "ftp", "mail2", "test",
        "portal", "ns", "ww1", "host", "support", "dev", "web", "bbs",
        "mx", "email", "cloud", "1", "mail1", "2", "forum", "owa", "www2",
        "gw", "admin", "store", "mobile", "static", "cdn", "api", "app",
        "staging", "beta", "demo", "old", "new", "v2", "docs", "help",
        "status", "assets", "media", "img", "images", "video", "download",
    ]

    async def scan(self, client: WebScoutClient, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        domain = parsed.hostname or ""
        root_domain = ".".join(domain.split(".")[-2:]) if domain.count(".") >= 1 else domain

        log("SCAN", f"Checking subdomain takeover for {root_domain} ({len(self.COMMON_SUBDOMAINS)} subdomains)")
        loop = asyncio.get_event_loop()

        async def check_sub(sub):
            fqdn = f"{sub}.{root_domain}"
            # DNS resolution
            try:
                cname = await loop.run_in_executor(None, self._get_cname, fqdn)
            except Exception:
                cname = ""

            target_url = f"{parsed.scheme}://{fqdn}"
            r = await client.get(target_url)
            if not r:
                return

            body = r["text"]
            for provider, fingerprints in self.TAKEOVER_FINGERPRINTS.items():
                for fp in fingerprints:
                    if fp.lower() in body.lower() or (cname and fp.lower() in cname.lower()):
                        findings.append(Finding(
                            plugin="subdomain_takeover",
                            title=f"Subdomain Takeover — {fqdn} ({provider})",
                            severity="CRITICAL", confidence=88.0,
                            description=f"Subdomain {fqdn} resolves via CNAME to unclaimed {provider} resource.",
                            evidence=f"CNAME: {cname or 'N/A'} | Fingerprint: {fp} | HTTP {r['status']}",
                            url=target_url,
                            remediation=f"Remove dangling DNS record for {fqdn} or claim the {provider} resource.",
                            cwe="CWE-350", cvss=8.8, owasp="A05",
                            poc=f"Claim {provider} resource pointing to {fqdn}",
                            tags=["subdomain-takeover", "dns", provider.lower().replace(" ", "-")],
                        ))
                        log("VULN", f"Subdomain takeover: {fqdn} → {provider}")
                        return

        tasks = [check_sub(sub) for sub in self.COMMON_SUBDOMAINS]
        await asyncio.gather(*tasks, return_exceptions=True)

        log("OK", f"Subdomain takeover scan done — {len(findings)} finding(s)")
        return findings

    def _get_cname(self, fqdn: str) -> str:
        """Return the CNAME target for fqdn.

        Resolution order (first success wins):
          1. dnspython ``dns.resolver`` — most reliable cross-platform.
             RECOMMENDED: pip install dnspython
             Without dnspython, CNAME resolution falls back to system CLI tools
             which may not be available on all platforms.
          2. ``dig +short CNAME <fqdn>`` — available on most Unix/macOS systems.
          3. ``nslookup`` — platform-aware fallback for Windows and minimal Unix.

        Note: For best results, install dnspython:
            pip install dnspython
        """
        # 1. dnspython (optional install: pip install dnspython)
        try:
            import dns.resolver  # type: ignore
            answers = dns.resolver.resolve(fqdn, "CNAME")
            return str(answers[0].target).rstrip(".")
        except Exception:
            pass

        # 2. dig — simpler and more consistent output than nslookup across platforms
        if shutil.which("dig"):
            try:
                result = subprocess.run(
                    ["dig", "+short", "CNAME", fqdn],
                    capture_output=True, text=True, timeout=5, shell=False
                )
                cname = result.stdout.strip().rstrip(".")
                if cname:
                    return cname
            except Exception:
                pass

        # 3. nslookup — Windows uses /type=CNAME, Unix uses -type=CNAME
        if shutil.which("nslookup"):
            try:
                flag = "/type=CNAME" if sys.platform.startswith("win") else "-type=CNAME"
                result = subprocess.run(
                    ["nslookup", flag, fqdn],
                    capture_output=True, text=True, timeout=5, shell=False
                )
                for line in result.stdout.splitlines():
                    line_l = line.lower()
                    # Unix output: "fqdn  canonical name = target."
                    # Windows output: "Aliases: target"
                    if "canonical name" in line_l or "alias" in line_l:
                        parts = line.split("=") if "=" in line else line.split()
                        cname = parts[-1].strip().rstrip(".")
                        if cname:
                            return cname
            except Exception:
                pass

        return ""


# ════════════════════════════════════════════════════════════════════════
#  MODULE v38-3 — OAuth 2.0 / OIDC Security Scanner
# ════════════════════════════════════════════════════════════════════════

class OAuth2Scanner:
    """Detect OAuth 2.0 and OpenID Connect security misconfigurations."""

    OAUTH_PATHS = [
        "/.well-known/openid-configuration",
        "/.well-known/oauth-authorization-server",
        "/oauth/authorize",
        "/oauth/token",
        "/oauth2/authorize",
        "/oauth2/token",
        "/auth/authorize",
        "/connect/authorize",
        "/api/oauth/token",
        "/v1/oauth/token",
    ]

    async def scan(self, client: WebScoutClient, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        # Discover OAuth endpoints
        oauth_eps = []
        for path in self.OAUTH_PATHS:
            r = await client.get(base + path, allow_redirects=False)
            if r and r["status"] in (200, 302, 400):
                oauth_eps.append((base + path, r))
                log("OK", f"OAuth endpoint: {base + path}")

        # Check OIDC discovery doc
        oidc_url = base + "/.well-known/openid-configuration"
        r = await client.get(oidc_url)
        if r and r["status"] == 200:
            try:
                doc = json.loads(r["text"])
                # Check for implicit flow enabled
                response_types = doc.get("response_types_supported", [])
                if "token" in response_types:
                    findings.append(Finding(
                        plugin="oauth2",
                        title="OAuth2: Implicit Flow Enabled",
                        severity="HIGH", confidence=95.0,
                        description="Implicit flow (response_type=token) is deprecated and insecure. Tokens appear in URL fragments.",
                        evidence=f"response_types_supported: {response_types}",
                        url=oidc_url,
                        remediation="Disable implicit flow. Use authorization_code with PKCE.",
                        cwe="CWE-346", cvss=7.4, owasp="A07",
                        tags=["oauth2", "implicit-flow"],
                    ))

                # Check for missing PKCE requirement
                code_challenge_methods = doc.get("code_challenge_methods_supported", [])
                if not code_challenge_methods:
                    findings.append(Finding(
                        plugin="oauth2",
                        title="OAuth2: PKCE Not Supported",
                        severity="MEDIUM", confidence=90.0,
                        description="Server does not advertise PKCE support — authorization code interception risk.",
                        evidence="code_challenge_methods_supported missing from discovery doc",
                        url=oidc_url,
                        remediation="Implement and require PKCE (S256) for all public clients.",
                        cwe="CWE-306", cvss=6.5, owasp="A07",
                        tags=["oauth2", "pkce"],
                    ))

                # Exposed jwks_uri
                jwks_uri = doc.get("jwks_uri", "")
                if jwks_uri:
                    rj = await client.get(jwks_uri)
                    if rj and rj["status"] == 200 and "keys" in rj["text"]:
                        findings.append(Finding(
                            plugin="oauth2",
                            title="OAuth2: JWKS Publicly Accessible",
                            severity="INFO", confidence=100.0,
                            description="JWKS endpoint is publicly accessible — expected but verify key rotation.",
                            evidence=f"JWKS URI: {jwks_uri}",
                            url=jwks_uri,
                            remediation="Ensure regular key rotation and monitor for key exposure.",
                            owasp="A07", tags=["oauth2", "jwks"],
                        ))

                # Token endpoint auth methods
                token_auth_methods = doc.get("token_endpoint_auth_methods_supported", [])
                if "none" in token_auth_methods:
                    findings.append(Finding(
                        plugin="oauth2",
                        title="OAuth2: Token Endpoint Allows 'none' Auth",
                        severity="HIGH", confidence=90.0,
                        description="Token endpoint accepts 'none' auth method — unauthenticated token requests possible.",
                        evidence=f"token_endpoint_auth_methods_supported: {token_auth_methods}",
                        url=oidc_url,
                        remediation="Remove 'none' from supported auth methods. Require client_secret_basic or private_key_jwt.",
                        cwe="CWE-306", cvss=8.1, owasp="A07",
                        tags=["oauth2", "token-endpoint"],
                    ))
            except Exception as _oauth2_e:
                log("DEBUG", f"[OAuth2] Token endpoint check failed: {_oauth2_e}")

        # Test for open redirect in OAuth callback
        for ep, _ in oauth_eps:
            if "authorize" in ep.lower():
                evil_redirect = "https://evil.example.com/steal"
                test_url = ep + f"?client_id=test&redirect_uri={quote(evil_redirect)}&response_type=code&scope=openid"
                r = await client.get(test_url, allow_redirects=False)
                if r and (
                    r["status"] in (302, 301) and
                    "evil.example.com" in r["headers"].get("Location", "")
                ):
                    findings.append(Finding(
                        plugin="oauth2",
                        title="OAuth2: Open Redirect via redirect_uri",
                        severity="CRITICAL", confidence=92.0,
                        description="OAuth authorization endpoint redirects to arbitrary redirect_uri without validation.",
                        evidence=f"Location: {r['headers'].get('Location', '')}",
                        url=test_url, payload=evil_redirect,
                        remediation="Whitelist redirect_uri values. Exact match only.",
                        cwe="CWE-601", cvss=9.1, owasp="A07",
                        poc=f"curl -Lv '{test_url}'",
                        tags=["oauth2", "open-redirect"],
                    ))

            # Test token endpoint for brute-force protection
            if "token" in ep.lower():
                for _ in range(3):
                    r = await client.post(ep, data={
                        "grant_type": "password",
                        "username": "admin",
                        "password": "wrongpass123",
                        "client_id": "test",
                    })
                if r and r["status"] not in (429, 400, 401):
                    pass  # could indicate no rate limiting

        # Check state parameter in auth URLs found in page
        page = await client.get(base_url)
        if page:
            oauth_links = re.findall(r'href=["\']([^"\']*(?:oauth|authorize|auth)[^"\']*)["\']',
                                      page["text"], re.I)
            for link in oauth_links[:5]:
                full = urljoin(base_url, link)
                parsed_link = urlparse(full)
                qs = parse_qs(parsed_link.query)
                if not qs.get("state"):
                    findings.append(Finding(
                        plugin="oauth2",
                        title="OAuth2: Missing 'state' Parameter (CSRF Risk)",
                        severity="HIGH", confidence=80.0,
                        description="OAuth authorization URL missing 'state' parameter — CSRF in OAuth flow possible.",
                        evidence=f"URL: {full}",
                        url=full,
                        remediation="Add cryptographically random 'state' parameter to all OAuth requests.",
                        cwe="CWE-352", cvss=8.1, owasp="A07",
                        tags=["oauth2", "csrf", "state"],
                    ))

        log("OK", f"OAuth2/OIDC scan done — {len(findings)} finding(s)")
        return findings


