#  MODULE v38-5 — Email Security Scanner (SPF / DKIM / DMARC)
# ════════════════════════════════════════════════════════════════════════

class EmailSecurityScanner:
    """Check DNS-based email security: SPF, DKIM, DMARC."""

    async def scan(self, client: WebScoutClient, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        domain = parsed.hostname or ""
        loop = asyncio.get_event_loop()

        # SPF
        spf = await loop.run_in_executor(None, self._txt_record, domain)
        spf_records = [r for r in spf if r.startswith("v=spf1")]
        if not spf_records:
            findings.append(Finding(
                plugin="email_security",
                title=f"Missing SPF Record — {domain}",
                severity="HIGH", confidence=100.0,
                description="No SPF TXT record found. Domain can be used for email spoofing.",
                evidence=f"Domain: {domain} | SPF records found: 0",
                url=base_url,
                remediation='Add SPF record: "v=spf1 include:yourmailprovider.com -all"',
                cwe="CWE-290", cvss=7.5, owasp="A07",
                tags=["email", "spf", "spoofing"],
            ))
        else:
            spf_val = spf_records[0]
            if "+all" in spf_val:
                findings.append(Finding(
                    plugin="email_security",
                    title=f"SPF Record Uses +all (Permissive) — {domain}",
                    severity="CRITICAL", confidence=100.0,
                    description="SPF record with '+all' allows any server to send email as this domain.",
                    evidence=f"SPF: {spf_val}",
                    url=base_url,
                    remediation='Change +all to -all or ~all in SPF record.',
                    cwe="CWE-290", cvss=9.1, owasp="A07",
                    tags=["email", "spf", "spoofing"],
                ))
            elif "~all" in spf_val:
                findings.append(Finding(
                    plugin="email_security",
                    title=f"SPF Record Uses ~all (SoftFail) — {domain}",
                    severity="MEDIUM", confidence=100.0,
                    description="SPF SoftFail (~all) still allows spoofed email to pass some filters.",
                    evidence=f"SPF: {spf_val}",
                    url=base_url,
                    remediation='Use -all (HardFail) to fully reject unauthorized senders.',
                    cwe="CWE-290", cvss=5.3, owasp="A07",
                    tags=["email", "spf"],
                ))

        # DMARC
        dmarc = await loop.run_in_executor(None, self._txt_record, f"_dmarc.{domain}")
        dmarc_records = [r for r in dmarc if r.startswith("v=DMARC1")]
        if not dmarc_records:
            findings.append(Finding(
                plugin="email_security",
                title=f"Missing DMARC Record — {domain}",
                severity="HIGH", confidence=100.0,
                description="No DMARC policy found. Domain vulnerable to email spoofing and phishing.",
                evidence=f"Domain: _dmarc.{domain} | No DMARC found",
                url=base_url,
                remediation='Add DMARC: "v=DMARC1; p=reject; rua=mailto:dmarc@yourdomain.com"',
                cwe="CWE-290", cvss=7.5, owasp="A07",
                tags=["email", "dmarc", "spoofing"],
            ))
        else:
            dmarc_val = dmarc_records[0]
            if "p=none" in dmarc_val:
                findings.append(Finding(
                    plugin="email_security",
                    title=f"DMARC Policy is 'none' — {domain}",
                    severity="MEDIUM", confidence=100.0,
                    description="DMARC policy p=none takes no action on failures — monitoring only.",
                    evidence=f"DMARC: {dmarc_val}",
                    url=base_url,
                    remediation='Change DMARC policy to p=quarantine or p=reject.',
                    cwe="CWE-290", cvss=5.3, owasp="A07",
                    tags=["email", "dmarc"],
                ))

        # DKIM (common selectors)
        dkim_found = False
        for selector in ["default", "google", "mail", "email", "k1", "s1", "s2", "dkim"]:
            dkim_domain = f"{selector}._domainkey.{domain}"
            recs = await loop.run_in_executor(None, self._txt_record, dkim_domain)
            if any("v=DKIM1" in r or "p=" in r for r in recs):
                dkim_found = True
                break
        if not dkim_found:
            findings.append(Finding(
                plugin="email_security",
                title=f"No DKIM Record Found — {domain}",
                severity="MEDIUM", confidence=70.0,
                description="No DKIM TXT record detected at common selectors. Email integrity unverified.",
                evidence=f"Checked selectors: default, google, mail, email, k1, s1, s2, dkim",
                url=base_url,
                remediation="Configure DKIM signing for outbound email and publish DKIM public key in DNS.",
                cwe="CWE-290", cvss=5.3, owasp="A07",
                tags=["email", "dkim"],
            ))

        log("OK", f"Email security scan done — {len(findings)} finding(s)")
        return findings

    def _txt_record(self, domain: str) -> list:
        """Return TXT records for domain using dnspython (preferred) or nslookup fallback.

        Note: For best SPF/DMARC resolution results, install dnspython:
            pip install dnspython
        Without it, nslookup is used as a fallback which may fail on minimal systems.
        """
        try:
            import dns.resolver  # type: ignore
            answers = dns.resolver.resolve(domain, "TXT")
            return [b.decode() for rdata in answers for b in rdata.strings]
        except Exception:
            pass
        try:
            import sys as _sys
            flag = "/type=TXT" if _sys.platform.startswith("win") else "-type=TXT"
            result = subprocess.run(
                ["nslookup", flag, domain],
                capture_output=True, text=True, timeout=5
            )
            records = []
            for line in result.stdout.splitlines():
                if "text =" in line.lower() or '"' in line:
                    val = line.split("=", 1)[-1].strip().strip('"')
                    if val:
                        records.append(val)
            return records
        except FileNotFoundError:
            return []
        except Exception:
            return []


