class AttackTemplateEngine:
    """
    Feature 4: Execute v43 attack templates with live exploit confirmation.
    Extends the built-in NucleiTemplateEngine with offensive confirmation.
    """

    def __init__(self, client: "WebScoutClient", cfg: "ScanConfig"):
        self.client = client
        self.cfg = cfg
        self.exploit_engine = ExploitAsEvidenceEngine()

    async def run_v43_templates(self, base_url: str) -> list:
        findings = []
        parsed = urlparse(base_url)
        base = f"{parsed.scheme}://{parsed.netloc}"

        for tmpl in V43_ATTACK_TEMPLATES:
            log("TMPL", f"Attack template: [{tmpl['id']}] {tmpl['name']}")
            for req in tmpl["requests"]:
                method  = req["method"]
                path    = req["path"]
                body    = req.get("body")

                # Replace RAND placeholders
                rand_str = secrets.token_hex(4)
                if body:
                    body = json.loads(
                        json.dumps(body).replace("RAND", rand_str)
                    )

                full_url = base + path
                r = await self.client.request(
                    method, full_url,
                    json_body=body if method in ("POST", "PUT", "PATCH") else None,
                )
                if not r:
                    continue

                matched = self._check_matchers(r, tmpl["matchers"])
                if not matched:
                    continue

                # --- Attempt live exploit confirmation ---
                confirmed_finding = None
                confirm_type = tmpl.get("confirm_with")

                if confirm_type == "mass_assignment":
                    confirmed_finding = await self.exploit_engine.confirm_mass_assignment(
                        self.client, base_url,
                        register_endpoint="/api/register",
                        login_endpoint="/api/login",
                    )
                elif confirm_type == "sqli_extraction":
                    # Try each GET param
                    pqs = parse_qs(urlparse(path).query)
                    for param in list(pqs.keys())[:3] or ["q", "id", "search"]:
                        confirmed_finding = await self.exploit_engine.confirm_sqli_extraction(
                            self.client, full_url, param
                        )
                        if confirmed_finding:
                            break
                elif confirm_type == "path_traversal":
                    pqs = parse_qs(urlparse(path).query)
                    for param in list(pqs.keys())[:3] or ["file", "page", "path"]:
                        confirmed_finding = await self.exploit_engine.confirm_path_traversal(
                            self.client, full_url, param
                        )
                        if confirmed_finding:
                            break

                if confirmed_finding:
                    findings.append(confirmed_finding)
                    log("CONF", f"CONFIRMED via exploit: {confirmed_finding.title[:60]}")
                else:
                    # Report as Potential
                    findings.append(Finding(
                        plugin=f"attack-template[{tmpl['id']}]",
                        title=f"[Potential] {tmpl['name']}",
                        severity=tmpl["severity"],
                        confidence=60.0,
                        description=(
                            f"Attack template '{tmpl['id']}' matched response criteria but exploit "
                            "confirmation was not conclusive. Manual verification recommended."
                        ),
                        evidence=f"URL: {full_url} | HTTP {r['status']} | snippet: {r['text'][:200]}",
                        url=full_url,
                        remediation=tmpl["remediation"],
                        cwe=tmpl["cwe"],
                        cvss=tmpl["cvss"],
                        owasp=tmpl["owasp"],
                        tags=tmpl["tags"] + ["potential"],
                    ))
                    log("WARN", f"Potential match (not confirmed): {tmpl['name'][:60]}")
                break  # one match per template is enough

        log("OK", f"Attack templates done — {len(findings)} finding(s)")
        return findings

    @staticmethod
    def _check_matchers(response: dict, matchers: list) -> bool:
        for matcher in matchers:
            mtype = matcher.get("type")
            if mtype == "status":
                if response["status"] in matcher.get("status", []):
                    return True
            elif mtype == "word":
                text = (response["text"] + str(response["headers"])).lower()
                words = [w.lower() for w in matcher.get("words", [])]
                cond  = matcher.get("condition", "or")
                if cond == "or":
                    if any(w in text for w in words):
                        return True
                else:
                    if all(w in text for w in words):
                        return True
            elif mtype == "regex":
                pattern = matcher.get("pattern", "")
                text = response["text"] + str(response["headers"])
                if re.search(pattern, text, re.I):
                    return True
            elif mtype == "header":
                header_val = response["headers"].get(
                    matcher.get("header", ""), ""
                )
                if any(w in header_val for w in matcher.get("words", [])):
                    return True
        return False


