import heapq, threading, sqlite3, difflib, functools, traceback, textwrap
from typing import Callable, Coroutine
from contextlib import asynccontextmanager
from enum import IntEnum

# ── Priority levels for the task queue ───────────────────────────────
class TaskPriority(IntEnum):
    CRITICAL = 0
    HIGH     = 1
    NORMAL   = 2
    LOW      = 3


@dataclass(order=True)
class _QueueItem:
    priority: int
    seq:      int                         # tie-breaker
    coro_fn:  Any = field(compare=False)  # callable → coroutine
    args:     tuple = field(compare=False, default_factory=tuple)
    kwargs:   dict  = field(compare=False, default_factory=dict)


class PriorityTaskQueue:
    """
    Async priority task queue.
    Tasks are executed in priority order (0 = highest).
    Supports concurrency limit, graceful shutdown, and per-task timeout.

    Usage
    -----
    queue = PriorityTaskQueue(workers=10, default_timeout=30)
    await queue.start()
    await queue.submit(my_coro, priority=TaskPriority.HIGH, timeout=10)
    await queue.join()
    await queue.stop()
    """

    def __init__(self, workers: int = 8, default_timeout: float = 30.0):
        self._heap:    list        = []
        self._seq:     int         = 0
        self._lock:    asyncio.Lock | None = None
        self._event:   asyncio.Event | None = None
        self._workers: int         = workers
        self._default_timeout = default_timeout
        self._tasks:   list        = []
        self._running: bool        = False
        self._done_count: int      = 0
        self._fail_count: int      = 0
        self._pending:    int      = 0

    async def start(self) -> None:
        self._lock  = asyncio.Lock()
        self._event = asyncio.Event()
        self._running = True
        self._tasks = [
            asyncio.create_task(self._worker(i))
            for i in range(self._workers)
        ]

    async def submit(
        self,
        coro_fn: Callable[..., Coroutine],
        *args,
        priority: int = TaskPriority.NORMAL,
        timeout: float | None = None,
        **kwargs,
    ) -> None:
        async with self._lock:
            self._seq += 1
            item = _QueueItem(
                priority=priority,
                seq=self._seq,
                coro_fn=coro_fn,
                args=args,
                kwargs={**kwargs, "__timeout__": timeout or self._default_timeout},
            )
            heapq.heappush(self._heap, item)
            self._pending += 1
        self._event.set()

    async def _worker(self, _wid: int) -> None:
        while self._running or self._heap:
            await self._event.wait()
            item = None
            async with self._lock:
                if self._heap:
                    item = heapq.heappop(self._heap)
                else:
                    self._event.clear()
            if item is None:
                continue
            timeout = item.kwargs.pop("__timeout__", self._default_timeout)
            try:
                await asyncio.wait_for(
                    item.coro_fn(*item.args, **item.kwargs),
                    timeout=timeout,
                )
                self._done_count += 1
            except asyncio.TimeoutError:
                log("WARN", f"[Queue] Task timed out after {timeout}s")
                self._fail_count += 1
            except Exception as exc:
                log("WARN", f"[Queue] Task failed: {exc}")
                self._fail_count += 1
            finally:
                async with self._lock:
                    self._pending -= 1
                if not self._heap:
                    self._event.clear()

    async def join(self) -> None:
        """Wait until all submitted tasks are done."""
        while True:
            async with self._lock:
                if self._pending == 0:
                    break
            await asyncio.sleep(0.05)

    async def stop(self) -> None:
        self._running = False
        self._event.set()
        await asyncio.gather(*self._tasks, return_exceptions=True)

    def stats(self) -> dict:
        return {
            "done": self._done_count,
            "failed": self._fail_count,
            "pending": self._pending,
        }


# ── Retry / Exponential-Backoff ───────────────────────────────────────

def retry_async(
    max_attempts: int = 3,
    base_delay:   float = 1.0,
    max_delay:    float = 30.0,
    exceptions:   tuple = (Exception,),
):
    """
    Decorator: retry an async function with exponential backoff.

    @retry_async(max_attempts=4, base_delay=0.5, exceptions=(aiohttp.ClientError,))
    async def fetch(url): ...
    """
    def decorator(fn):
        @functools.wraps(fn)
        async def wrapper(*args, **kwargs):
            delay = base_delay
            for attempt in range(1, max_attempts + 1):
                try:
                    return await fn(*args, **kwargs)
                except exceptions as exc:
                    if attempt == max_attempts:
                        raise
                    jitter = random.uniform(0, delay * 0.2)
                    sleep_time = min(delay + jitter, max_delay)
                    log("WARN",
                        f"[Retry] {fn.__name__} attempt {attempt}/{max_attempts} "
                        f"failed ({exc}). Retrying in {sleep_time:.1f}s…")
                    await asyncio.sleep(sleep_time)
                    delay = min(delay * 2, max_delay)
        return wrapper
    return decorator


def retry_sync(
    max_attempts: int = 3,
    base_delay:   float = 1.0,
    exceptions:   tuple = (Exception,),
):
    """Sync version of retry_async."""
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            delay = base_delay
            for attempt in range(1, max_attempts + 1):
                try:
                    return fn(*args, **kwargs)
                except exceptions as exc:
                    if attempt == max_attempts:
                        raise
                    time.sleep(min(delay * (2 ** (attempt - 1)), 30))
        return wrapper
    return decorator


class RetryManager:
    """
    Centralized retry policy manager.
    Wraps retry_async / retry_sync into a configurable object
    so retry policies can be shared, named, and adjusted at runtime.

    Usage
    -----
    rm = RetryManager(max_attempts=4, base_delay=0.5)

    # As async decorator
    @rm.async_decorator(exceptions=(aiohttp.ClientError,))
    async def fetch(url): ...

    # Direct call
    result = await rm.run_async(fetch, "https://example.com")
    result = rm.run_sync(my_sync_fn, arg1, arg2)
    """

    def __init__(
        self,
        max_attempts: int   = 3,
        base_delay:   float = 1.0,
        max_delay:    float = 30.0,
        exceptions:   tuple = (Exception,),
    ):
        self.max_attempts = max_attempts
        self.base_delay   = base_delay
        self.max_delay    = max_delay
        self.exceptions   = exceptions
        self._attempts_log: list[dict] = []

    def async_decorator(self, exceptions: tuple | None = None):
        """Return an async retry decorator using this policy."""
        return retry_async(
            max_attempts=self.max_attempts,
            base_delay=self.base_delay,
            max_delay=self.max_delay,
            exceptions=exceptions or self.exceptions,
        )

    def sync_decorator(self, exceptions: tuple | None = None):
        """Return a sync retry decorator using this policy."""
        return retry_sync(
            max_attempts=self.max_attempts,
            base_delay=self.base_delay,
            exceptions=exceptions or self.exceptions,
        )

    async def run_async(self, fn: Callable, *args, **kwargs):
        """Run an async callable with this manager's retry policy."""
        decorated = retry_async(
            max_attempts=self.max_attempts,
            base_delay=self.base_delay,
            max_delay=self.max_delay,
            exceptions=self.exceptions,
        )(fn)
        return await decorated(*args, **kwargs)

    def run_sync(self, fn: Callable, *args, **kwargs):
        """Run a sync callable with this manager's retry policy."""
        decorated = retry_sync(
            max_attempts=self.max_attempts,
            base_delay=self.base_delay,
            exceptions=self.exceptions,
        )(fn)
        return decorated(*args, **kwargs)

    def stats(self) -> dict:
        return {
            "policy": {
                "max_attempts": self.max_attempts,
                "base_delay":   self.base_delay,
                "max_delay":    self.max_delay,
            },
            "attempts_logged": len(self._attempts_log),
        }


# ── Session Pool ──────────────────────────────────────────────────────

class SessionPool:
    """
    Managed pool of aiohttp.ClientSession objects.
    Rotates sessions to avoid per-session rate limiting.
    Automatically recreates dead sessions.

    Usage
    -----
    pool = SessionPool(size=5, headers={"User-Agent": "..."})
    await pool.start()
    async with pool.acquire() as session:
        resp = await session.get(url)
    await pool.close()
    """

    def __init__(
        self,
        size:    int  = 5,
        headers: dict | None = None,
        timeout: float = 30.0,
        proxy:   str | None = None,
    ):
        self._size    = size
        self._headers = headers or {}
        self._timeout = aiohttp.ClientTimeout(total=timeout)
        self._proxy   = proxy
        self._sessions: list[aiohttp.ClientSession] = []
        self._idx     = 0
        self._lock    = None

    async def start(self) -> None:
        self._lock = asyncio.Lock()
        for _ in range(self._size):
            self._sessions.append(self._make_session())

    def _make_session(self) -> aiohttp.ClientSession:
        connector = aiohttp.TCPConnector(ssl=False, limit=50)
        return aiohttp.ClientSession(
            headers=self._headers,
            timeout=self._timeout,
            connector=connector,
        )

    @asynccontextmanager
    async def acquire(self):
        async with self._lock:
            sess = self._sessions[self._idx % self._size]
            self._idx += 1
            if sess.closed:
                self._sessions[self._idx % self._size] = self._make_session()
                sess = self._sessions[self._idx % self._size]
        try:
            yield sess
        except aiohttp.ClientError:
            pass

    async def close(self) -> None:
        for s in self._sessions:
            if not s.closed:
                await s.close()


# ── Crash Guard ───────────────────────────────────────────────────────

class CrashGuard:
    """
    Global exception guard for async scan runs.
    Records crashes to a crash log file and optionally resumes.

    Usage
    -----
    guard = CrashGuard(log_path="crashes.log")
    async with guard.protect("SQLiScanner"):
        await scanner.run()
    print(guard.summary())
    """

    def __init__(self, log_path: str = "webscout_crashes.log"):
        self._log_path  = log_path
        self._crashes:  list[dict] = []
        self._lock      = threading.Lock()

    @asynccontextmanager
    async def protect(self, module: str):
        try:
            yield
        except asyncio.CancelledError:
            raise
        except Exception as exc:
            tb = traceback.format_exc()
            record = {
                "module":    module,
                "error":     str(exc),
                "traceback": tb,
                "time":      datetime.now().isoformat(),
            }
            with self._lock:
                self._crashes.append(record)
            try:
                with open(self._log_path, "a") as f:
                    f.write(json.dumps(record) + "\n")
            except OSError:
                pass
            log("WARN", f"[CrashGuard] {module} crashed: {exc} (logged, continuing)")

    def summary(self) -> str:
        if not self._crashes:
            return "CrashGuard: No crashes recorded."
        lines = [f"CrashGuard: {len(self._crashes)} crash(es) recorded:"]
        for c in self._crashes:
            lines.append(f"  [{c['time']}] {c['module']}: {c['error']}")
        return "\n".join(lines)

    @property
    def crashes(self) -> list:
        return list(self._crashes)


