class ResponseDiffer:
    """
    Compares two HTTP responses and produces a structured diff report.
    Used to detect anomalies between a baseline and a fuzzed response —
    the core of blind injection / timing / differential analysis.

    Usage
    -----
    differ = ResponseDiffer()
    baseline = await differ.capture(session, "GET", url)
    differ.set_baseline(baseline)
    fuzzed   = await differ.capture(session, "GET", url + "' OR 1=1--")
    report   = differ.compare(baseline, fuzzed)
    if report["is_anomalous"]:
        ...
    """

    NOISE_HEADERS = {"date", "x-request-id", "x-correlation-id", "set-cookie",
                     "age", "expires", "last-modified", "etag"}

    def __init__(
        self,
        length_threshold:  float = 0.05,   # 5% body-size change
        timing_threshold:  float = 2.0,    # 2 s latency delta
        status_weight:     float = 1.0,
        header_weight:     float = 0.5,
        body_weight:       float = 1.0,
        timing_weight:     float = 0.8,
    ):
        self._lt = length_threshold
        self._tt = timing_threshold
        self._sw = status_weight
        self._hw = header_weight
        self._bw = body_weight
        self._tw = timing_weight
        self._baseline: dict | None = None

    def set_baseline(self, snapshot: dict) -> None:
        self._baseline = snapshot

    async def capture(
        self,
        session,
        method: str,
        url: str,
        **req_kwargs,
    ) -> dict:
        t0 = time.monotonic()
        try:
            async with session.request(method, url, **req_kwargs) as resp:
                body  = await resp.read()
                elapsed = time.monotonic() - t0
                return {
                    "status":  resp.status,
                    "headers": {k.lower(): v for k, v in resp.headers.items()
                                if k.lower() not in self.NOISE_HEADERS},
                    "body":    body,
                    "body_len": len(body),
                    "elapsed": elapsed,
                    "url":     str(resp.url),
                }
        except Exception as exc:
            return {
                "status": -1, "headers": {}, "body": b"",
                "body_len": 0, "elapsed": time.monotonic() - t0,
                "url": url, "error": str(exc),
            }

    def compare(self, base: dict, fuzz: dict) -> dict:
        score = 0.0
        signals: list[str] = []

        # Status code change
        if base["status"] != fuzz["status"]:
            score += self._sw
            signals.append(
                f"status_change:{base['status']}->{fuzz['status']}"
            )

        # Body length delta
        if base["body_len"] > 0:
            ratio = abs(fuzz["body_len"] - base["body_len"]) / base["body_len"]
            if ratio > self._lt:
                score += self._bw * min(ratio, 3.0)
                signals.append(f"body_delta:{ratio:.1%}")

        # Timing delta
        t_delta = fuzz["elapsed"] - base["elapsed"]
        if t_delta > self._tt:
            score += self._tw * min(t_delta / self._tt, 3.0)
            signals.append(f"timing_delta:{t_delta:.2f}s")

        # Header changes (ignoring noise)
        added   = set(fuzz["headers"]) - set(base["headers"])
        removed = set(base["headers"]) - set(fuzz["headers"])
        if added or removed:
            score += self._hw
            if added:
                signals.append(f"headers_added:{','.join(sorted(added))}")
            if removed:
                signals.append(f"headers_removed:{','.join(sorted(removed))}")

        # Body content diff (first 8 KB only for speed)
        base_text = base["body"][:8192].decode("utf-8", errors="replace")
        fuzz_text = fuzz["body"][:8192].decode("utf-8", errors="replace")
        ratio = difflib.SequenceMatcher(None, base_text, fuzz_text).ratio()
        similarity = ratio
        if ratio < 0.85:
            score += self._bw * (1.0 - ratio)
            signals.append(f"content_similarity:{ratio:.2f}")

        return {
            "score":        round(score, 3),
            "is_anomalous": score > 1.0,
            "signals":      signals,
            "similarity":   round(similarity, 3),
            "timing_delta": round(t_delta if 't_delta' in dir() else 0, 3),
            "status_base":  base["status"],
            "status_fuzz":  fuzz["status"],
        }

    def diff_text(self, base: dict, fuzz: dict, context: int = 3) -> str:
        """Return a unified text diff of the two response bodies."""
        a = base["body"][:16384].decode("utf-8", errors="replace").splitlines()
        b = fuzz["body"][:16384].decode("utf-8", errors="replace").splitlines()
        diff = list(difflib.unified_diff(
            a, b, fromfile="baseline", tofile="fuzzed", n=context,
        ))
        return "\n".join(diff[:200])  # cap at 200 lines


class PayloadMutator:
    """
    Automatically mutates payloads based on observed responses.
    Learns which mutations are effective and promotes them.

    Usage
    -----
    mutator = PayloadMutator()
    for payload in mutator.mutate(base_payload, response_diff):
        ...
    mutator.record_hit(payload)           # call when a payload triggers a vuln
    top = mutator.top_payloads(n=10)      # get the most effective payloads
    """

    WRAPPERS = [
        ("", ""),
        ("'", ""),
        ('"', ""),
        ("' ", "--"),
        ('" ', "--"),
        ("/*", "*/"),
        ("%27", ""),
        ("%22", ""),
        ("`;", "//"),
        (" AND 1=1", ""),
        (" OR 1=1", ""),
        ("<script>", "</script>"),
        ("{{", "}}"),
        ("${", "}"),
        ("<!--", "-->"),
        ("../", ""),
        ("..%2F", ""),
        ("%0a", ""),
        ("%0d%0a", ""),
    ]

    CASE_VARIANTS = [
        lambda p: p,
        lambda p: p.upper(),
        lambda p: p.lower(),
        str.title,
        lambda p: "".join(c.upper() if i % 2 else c for i, c in enumerate(p)),
    ]

    ENCODING_VARIANTS = [
        lambda p: p,
        lambda p: quote(p, safe=""),
        lambda p: quote(quote(p, safe=""), safe=""),
        lambda p: base64.b64encode(p.encode()).decode(),
        lambda p: p.replace(" ", "/**/"),
        lambda p: p.replace(" ", "%20"),
        lambda p: p.replace("'", "%27"),
        lambda p: p.replace("<", "&lt;").replace(">", "&gt;"),
    ]

    def __init__(self):
        self._scores:  dict[str, float]  = {}
        self._history: list[tuple]       = []   # (payload, result)

    def mutate(
        self,
        base_payload: str,
        diff:         dict | None = None,
        max_variants: int = 30,
    ) -> list[str]:
        """
        Return a list of mutated variants of base_payload.
        If diff is provided, bias mutation toward signals that match the diff.
        """
        variants: list[str] = []

        # Always include the original
        variants.append(base_payload)

        # Wrapper mutations
        for prefix, suffix in self.WRAPPERS:
            variants.append(f"{prefix}{base_payload}{suffix}")

        # Case variants
        for fn in self.CASE_VARIANTS:
            try:
                variants.append(fn(base_payload))
            except Exception:
                pass

        # Encoding variants
        for fn in self.ENCODING_VARIANTS:
            try:
                variants.append(fn(base_payload))
            except Exception:
                pass

        # If diff shows timing anomaly → add sleep payloads
        if diff and any("timing" in s for s in diff.get("signals", [])):
            variants += [
                f"{base_payload}' AND SLEEP(5)--",
                f"{base_payload}\" AND SLEEP(5)--",
                f"{base_payload}; WAITFOR DELAY '0:0:5'--",
                f"{base_payload}`sleep 5`",
            ]

        # If diff shows content difference → add reflection payloads
        if diff and any("content" in s for s in diff.get("signals", [])):
            tag = f"<zz{secrets.token_hex(3)}>test</zz>"
            variants += [
                f"{base_payload}{tag}",
                f"{tag}{base_payload}",
            ]

        # Deduplicate, cap size, and sort by known score (best first)
        seen: set[str] = set()
        unique: list[str] = []
        for v in variants:
            if v not in seen:
                seen.add(v)
                unique.append(v)

        unique.sort(key=lambda p: self._scores.get(p, 0.0), reverse=True)
        return unique[:max_variants]

    def record_hit(self, payload: str, score: float = 1.0) -> None:
        """Record that a payload triggered a finding."""
        prev = self._scores.get(payload, 0.0)
        self._scores[payload] = prev + score
        self._history.append((payload, score))

    def record_miss(self, payload: str) -> None:
        """Record that a payload did NOT trigger a finding."""
        if payload in self._scores:
            self._scores[payload] = max(0.0, self._scores[payload] - 0.1)

    def top_payloads(self, n: int = 20) -> list[tuple[str, float]]:
        """Return the top-n most effective payloads with their scores."""
        return sorted(self._scores.items(), key=lambda x: x[1], reverse=True)[:n]


class PatternDetector:
    """
    Detects recurring patterns across multiple scan findings.
    Used to surface systemic vulnerabilities and reduce noise.

    Patterns detected:
    - Parameter patterns (same param name vulnerable across endpoints)
    - Technology patterns (version-specific vulns)
    - Severity clustering (multiple HIGH/CRIT on same host)
    - Attack surface hotspots (endpoints with many findings)

    Usage
    -----
    detector = PatternDetector()
    for finding in findings:
        detector.ingest(finding)
    patterns = detector.analyze()
    """

    def __init__(self):
        self._findings:   list[Finding] = []
        self._param_freq: dict = defaultdict(list)
        self._path_freq:  dict = defaultdict(list)
        self._type_freq:  dict = defaultdict(list)
        self._sev_freq:   dict = defaultdict(int)

    def ingest(self, finding: "Finding") -> None:
        self._findings.append(finding)
        self._sev_freq[finding.severity] += 1
        self._type_freq[finding.vuln_type].append(finding)

        # Extract param from URL
        try:
            qs = parse_qs(urlparse(finding.url).query)
            for param in qs:
                self._param_freq[param].append(finding)
        except Exception:
            pass

        # Extract path
        try:
            path = urlparse(finding.url).path
            self._path_freq[path].append(finding)
        except Exception:
            pass

    def analyze(self) -> list[dict]:
        patterns: list[dict] = []

        # Pattern 1: Repeated vulnerable parameter
        for param, findings in self._param_freq.items():
            if len(findings) >= 3:
                types = list({f.vuln_type for f in findings})
                patterns.append({
                    "type":        "REPEATED_PARAM",
                    "description": f"Parameter '{param}' is vulnerable across "
                                   f"{len(findings)} endpoints: {', '.join(types[:5])}",
                    "count":       len(findings),
                    "severity":    "HIGH" if len(findings) >= 5 else "MEDIUM",
                    "affected":    [f.url for f in findings[:10]],
                })

        # Pattern 2: Hot endpoint (many findings on same path)
        for path, findings in self._path_freq.items():
            if len(findings) >= 4:
                patterns.append({
                    "type":        "HOT_ENDPOINT",
                    "description": f"Path '{path}' has {len(findings)} findings "
                                   f"— likely an attack surface hotspot.",
                    "count":       len(findings),
                    "severity":    "HIGH",
                    "affected":    [path],
                })

        # Pattern 3: Dominant vuln type
        for vtype, findings in self._type_freq.items():
            if len(findings) >= 5:
                urls = list({urlparse(f.url).path for f in findings})
                patterns.append({
                    "type":        "SYSTEMIC_VULN",
                    "description": f"'{vtype}' appears {len(findings)} times across "
                                   f"{len(urls)} distinct paths — systemic issue.",
                    "count":       len(findings),
                    "severity":    "CRITICAL" if len(findings) >= 10 else "HIGH",
                    "affected":    urls[:10],
                })

        # Pattern 4: Severity distribution alert
        critical = self._sev_freq.get("CRITICAL", 0)
        high     = self._sev_freq.get("HIGH", 0)
        if critical + high >= 10:
            patterns.append({
                "type":        "HIGH_RISK_CLUSTER",
                "description": f"Target has {critical} CRITICAL and {high} HIGH "
                               f"findings — potential for full compromise.",
                "count":       critical + high,
                "severity":    "CRITICAL",
                "affected":    [],
            })

        return sorted(patterns, key=lambda p: p["count"], reverse=True)

    def summary_table(self) -> str:
        lines = [
            "  ┌─────────────────┬────────┐",
            "  │ Severity        │  Count │",
            "  ├─────────────────┼────────┤",
        ]
        for sev in SEV_ORDER:
            cnt = self._sev_freq.get(sev, 0)
            lines.append(f"  │ {sev:<15} │ {cnt:>6} │")
        lines.append("  └─────────────────┴────────┘")
        return "\n".join(lines)


