try:
    from rich.console import Console as _RichConsole
    from rich.table   import Table  as _RichTable
    from rich.layout  import Layout as _RichLayout
    from rich.panel   import Panel  as _RichPanel
    from rich.live    import Live   as _RichLive
    from rich.text    import Text   as _RichText
    from rich.syntax  import Syntax as _RichSyntax
    from rich.progress import (
        Progress, SpinnerColumn, BarColumn,
        TextColumn, TimeElapsedColumn, TaskID,
    )
    HAS_RICH = True
except ImportError:
    HAS_RICH = False
    import warnings as _w
    _w.warn(
        "rich not installed — Live Dashboard disabled. "
        "Install with: pip install rich",
        ImportWarning, stacklevel=1,
    )


class LiveDashboard:
    """
    Real-time terminal dashboard for scan progress.
    Shows:
    - Live scan progress bar per scanner module
    - Running findings count by severity
    - Last 10 findings (live-updating)
    - Scan statistics (requests/sec, elapsed, target)
    - Pattern alerts

    Requires: pip install rich

    Usage
    -----
    async with LiveDashboard(target="https://example.com") as dash:
        dash.update_progress("SQLi", 45, 100)
        dash.add_finding(finding)
        dash.set_stat("req/s", 23.5)
    """

    SEV_STYLE = {
        "CRITICAL": "bold red",
        "HIGH":     "bold orange1",
        "MEDIUM":   "bold yellow",
        "LOW":      "bold blue",
        "INFO":     "dim",
    }

    def __init__(
        self,
        target:       str,
        refresh_rate: float = 0.25,
    ):
        self._target       = target
        self._refresh_rate = refresh_rate
        self._findings:    list[Finding]       = []
        self._stats:       dict[str, Any]      = {
            "target": target,
            "started": datetime.now().strftime("%H:%M:%S"),
            "requests": 0,
            "req/s": 0.0,
            "elapsed": "0s",
        }
        self._modules:     dict[str, tuple[int, int]] = {}  # name → (done, total)
        self._live:        Any = None
        self._console:     Any = None
        self._lock         = threading.Lock()
        self._sev_counts   = defaultdict(int)
        self._start_time   = time.monotonic()

    async def __aenter__(self):
        if not HAS_RICH:
            return self
        self._console = _RichConsole()
        self._live = _RichLive(
            self._render(),
            console=self._console,
            refresh_per_second=int(1 / self._refresh_rate),
        )
        self._live.start()
        return self

    async def __aexit__(self, *_):
        if self._live:
            self._live.stop()

    def update_progress(self, module: str, done: int, total: int) -> None:
        with self._lock:
            self._modules[module] = (done, total)
        self._refresh()

    def add_finding(self, finding: Finding) -> None:
        with self._lock:
            self._findings.append(finding)
            self._sev_counts[finding.severity] += 1
        self._refresh()

    def set_stat(self, key: str, value: Any) -> None:
        with self._lock:
            self._stats[key] = value
        self._refresh()

    def increment_requests(self, n: int = 1) -> None:
        with self._lock:
            self._stats["requests"] = self._stats.get("requests", 0) + n
            elapsed = max(time.monotonic() - self._start_time, 0.01)
            self._stats["req/s"]   = round(self._stats["requests"] / elapsed, 1)
            self._stats["elapsed"] = f"{int(elapsed)}s"
        self._refresh()

    def _refresh(self) -> None:
        if self._live and HAS_RICH:
            self._live.update(self._render())

    def _render(self):
        if not HAS_RICH:
            return ""

        # ── Header ──────────────────────────────────────────────────
        title = _RichText(f"⚡ WebScout Ultimate — {self._target}", style="bold cyan")

        # ── Stats row ───────────────────────────────────────────────
        stats_table = _RichTable(show_header=False, box=None, padding=(0, 2))
        stats_table.add_column(style="dim")
        stats_table.add_column(style="bold")
        for k, v in self._stats.items():
            stats_table.add_row(k, str(v))

        # ── Severity counts ─────────────────────────────────────────
        sev_table = _RichTable(
            title="Findings", show_header=True, box=None,
            title_style="bold white",
        )
        sev_table.add_column("Severity", style="bold", min_width=10)
        sev_table.add_column("Count",    justify="right", min_width=6)
        for sev in SEV_ORDER:
            cnt = self._sev_counts.get(sev, 0)
            sev_table.add_row(
                f"[{self.SEV_STYLE[sev]}]{sev}[/]",
                f"[{self.SEV_STYLE[sev]}]{cnt}[/]",
            )

        # ── Module progress ─────────────────────────────────────────
        prog_table = _RichTable(title="Scanners", show_header=True, box=None)
        prog_table.add_column("Module", min_width=25)
        prog_table.add_column("Progress", min_width=20)
        prog_table.add_column("%", justify="right")
        with self._lock:
            for mod, (done, total) in self._modules.items():
                pct = int(done / total * 100) if total else 0
                bar = "█" * (pct // 5) + "░" * (20 - pct // 5)
                prog_table.add_row(
                    mod,
                    f"[green]{bar}[/]",
                    f"{pct}%",
                )

        # ── Recent findings ─────────────────────────────────────────
        findings_table = _RichTable(
            title="Recent Findings", show_header=True, box=None,
        )
        findings_table.add_column("Sev", min_width=8)
        findings_table.add_column("Type",   min_width=30)
        findings_table.add_column("URL",    min_width=40)
        with self._lock:
            recent = self._findings[-10:]
        for f in reversed(recent):
            style = self.SEV_STYLE.get(f.severity, "")
            findings_table.add_row(
                f"[{style}]{f.severity}[/]",
                f.vuln_type[:30],
                f.url[:60],
            )

        from rich.columns import Columns
        layout = _RichPanel(
            Columns([stats_table, sev_table, prog_table]),
            title=title,
            border_style="cyan",
        )
        from rich import box as _rbox
        outer = _RichTable(show_header=False, box=_rbox.MINIMAL)
        outer.add_row(layout)
        outer.add_row(_RichPanel(findings_table, border_style="dim"))
        return outer


class RequestResponseViewer:
    """
    Interactive request/response viewer for scan findings.
    Displays formatted HTTP exchanges from findings.

    Usage
    -----
    viewer = RequestResponseViewer()
    viewer.show(finding)               # print one finding
    viewer.show_all(findings, top=20)  # print top-N findings
    viewer.export_har(findings, "scan.har")  # export as HAR
    """

    def __init__(self):
        self._console = _RichConsole() if HAS_RICH else None

    def show(self, finding: Finding) -> None:
        if HAS_RICH and self._console:
            self._show_rich(finding)
        else:
            self._show_plain(finding)

    def _show_rich(self, finding: Finding) -> None:
        sev_style = LiveDashboard.SEV_STYLE.get(finding.severity, "white")
        header = (
            f"[{sev_style}]● {finding.severity}[/]  "
            f"[bold]{finding.vuln_type}[/]  "
            f"[dim]{finding.url}[/]"
        )
        lines = [header, ""]

        if finding.evidence:
            lines.append("[bold]Evidence:[/]")
            lines.append(f"  [dim]{finding.evidence[:400]}[/]")
            lines.append("")

        if finding.poc:
            lines.append("[bold]PoC:[/]")
            lines.append(f"  [yellow]{finding.poc[:400]}[/]")
            lines.append("")

        lines.append(
            f"[dim]CVSS: {finding.cvss or 'N/A'}  "
            f"CWE: {finding.cwe or 'N/A'}  "
            f"OWASP: {finding.owasp or 'N/A'}[/]"
        )

        self._console.print(
            _RichPanel(
                "\n".join(lines),
                border_style=sev_style,
                padding=(0, 1),
            )
        )

    def _show_plain(self, finding: Finding) -> None:
        print(f"\n[{finding.severity}] {finding.vuln_type}")
        print(f"  URL:  {finding.url}")
        if finding.evidence:
            print(f"  Evidence: {finding.evidence[:200]}")
        if finding.poc:
            print(f"  PoC: {finding.poc[:200]}")
        print(f"  CVSS: {finding.cvss}  CWE: {finding.cwe}")

    def show_all(
        self,
        findings: list[Finding],
        top: int = 30,
        min_severity: str = "LOW",
    ) -> None:
        min_score = SEV_SCORES.get(min_severity, 0)
        filtered = [
            f for f in findings
            if SEV_SCORES.get(f.severity, 0) >= min_score
        ]
        filtered.sort(key=lambda f: SEV_SCORES.get(f.severity, 0), reverse=True)
        for f in filtered[:top]:
            self.show(f)

    def export_har(self, findings: list[Finding], output_path: str) -> str:
        """Export findings as a HAR (HTTP Archive) file."""
        entries = []
        for f in findings:
            parsed = urlparse(f.url)
            entry = {
                "startedDateTime": datetime.now().isoformat() + "Z",
                "time": 0,
                "request": {
                    "method": "GET",
                    "url": f.url,
                    "httpVersion": "HTTP/1.1",
                    "headers": [],
                    "queryString": [
                        {"name": k, "value": v[0]}
                        for k, v in parse_qs(parsed.query).items()
                    ],
                    "cookies": [],
                    "headersSize": -1,
                    "bodySize": -1,
                },
                "response": {
                    "status": 200,
                    "statusText": "OK",
                    "httpVersion": "HTTP/1.1",
                    "headers": [],
                    "cookies": [],
                    "content": {
                        "size": len(f.evidence or ""),
                        "mimeType": "text/html",
                        "text": f.evidence or "",
                    },
                    "redirectURL": "",
                    "headersSize": -1,
                    "bodySize": -1,
                },
                "_webscout": {
                    "vuln_type": f.vuln_type,
                    "severity":  f.severity,
                    "cvss":      f.cvss,
                    "cwe":       f.cwe,
                    "owasp":     f.owasp,
                    "poc":       f.poc,
                    "tags":      f.tags,
                },
            }
            entries.append(entry)

        har = {
            "log": {
                "version": "1.2",
                "creator": {"name": "WebScout Ultimate", "version": "V10"},
                "entries": entries,
            }
        }
        path = Path(output_path)
        path.write_text(json.dumps(har, indent=2, default=str))
        return str(path.resolve())


