# ════════════════════════════════════════════════════════════════════════
#  MODULE 1 — UNIFIED DETECTION ENGINE
#  Cross-module correlation · Pattern recognition · Smart deduplication
# ════════════════════════════════════════════════════════════════════════

class UnifiedDetectionEngine:
    CORRELATION_RULES = [
        {"name": "SQLi Chain", "requires": ["SQLi", "Error-Based"], "severity_boost": "CRITICAL",
         "desc": "SQL injection confirmed via error-based detection + payload confirmation"},
        {"name": "XSS+Cookie Theft", "requires": ["XSS", "Cookie"], "severity_boost": "HIGH",
         "desc": "XSS combined with cookie access enables session hijacking"},
        {"name": "SSRF+Cloud", "requires": ["SSRF", "Cloud"], "severity_boost": "CRITICAL",
         "desc": "SSRF with cloud metadata access enables credential theft"},
        {"name": "Auth Bypass Chain", "requires": ["IDOR", "Auth"], "severity_boost": "CRITICAL",
         "desc": "IDOR combined with authentication weakness enables full account takeover"},
        {"name": "RCE Chain", "requires": ["Command", "Upload"], "severity_boost": "CRITICAL",
         "desc": "File upload combined with command injection enables remote code execution"},
        {"name": "Priv Escalation", "requires": ["Mass Assignment", "Role"], "severity_boost": "CRITICAL",
         "desc": "Mass assignment with role parameter enables privilege escalation"},
        {"name": "Data Exfil", "requires": ["SQLi", "CORS"], "severity_boost": "CRITICAL",
         "desc": "SQL injection with CORS misconfiguration enables cross-origin data exfiltration"},
        {"name": "Full Takeover", "requires": ["JWT", "Weak"], "severity_boost": "CRITICAL",
         "desc": "JWT weakness enables token forgery and complete authentication bypass"},
    ]

    DETECTION_SIGNATURES = {
        "sql_error": [
            r"(?i)SQL\s*syntax.*MySQL", r"(?i)ORA-\d{4,5}",
            r"(?i)microsoft.*ODBC.*SQL\s*Server", r"(?i)PostgreSQL.*ERROR",
            r"(?i)sqlite3\.OperationalError", r"(?i)Unclosed\s+quotation\s+mark",
            r"(?i)quoted\s+string\s+not\s+properly\s+terminated",
        ],
        "xss_reflection": [
            r"<script[^>]*>.*?</script>", r"javascript\s*:",
            r"on\w+\s*=\s*[\"']", r"<img[^>]+onerror",
        ],
        "path_traversal": [
            r"root:.*:0:0:", r"\[boot\s+loader\]",
            r"(?i)\[extensions\]", r"/etc/passwd",
        ],
        "command_injection": [
            r"uid=\d+\(", r"(?i)volume\s+serial\s+number",
            r"Linux\s+\S+\s+\d+\.\d+", r"(?i)windows\s+ip\s+configuration",
        ],
        "information_disclosure": [
            r"(?i)stack\s*trace", r"(?i)debug\s*mode",
            r"(?i)internal\s+server\s+error.*at\s+/",
            r"(?i)(DB_PASSWORD|SECRET_KEY|API_KEY)\s*[=:]",
        ],
    }

    def __init__(self, client):
        self._client = client
        self._response_cache = {}

    async def scan(self, target: str, existing_findings: list) -> list:
        results = []
        results.extend(self._correlate_findings(existing_findings, target))
        results.extend(await self._deep_detection(target))
        results.extend(self._pattern_analysis(existing_findings, target))
        return results

    def _correlate_findings(self, findings: list, target: str) -> list:
        results = []
        finding_text = " ".join(
            f"{f.title} {f.description} {f.plugin} {' '.join(f.tags)}"
            for f in findings
        ).lower()
        for rule in self.CORRELATION_RULES:
            matches = sum(1 for kw in rule["requires"] if kw.lower() in finding_text)
            if matches >= len(rule["requires"]):
                results.append(Finding(
                    plugin="UnifiedDetectionEngine",
                    title=f"Correlated: {rule['name']}",
                    severity=rule["severity_boost"],
                    description=rule["desc"],
                    confidence=85.0 + (matches * 5),
                    url=target,
                    tags=["correlation", "detection-engine"],
                ))
        return results

    async def _deep_detection(self, target: str) -> list:
        results = []
        probe_paths = ["/", "/api", "/admin", "/login", "/search", "/user", "/debug"]
        for path in probe_paths:
            url = urljoin(target, path)
            try:
                resp = await self._client.request("GET", url)
                if resp and hasattr(resp, "text"):
                    body = resp.text if hasattr(resp, "text") else str(resp)
                    for sig_type, patterns in self.DETECTION_SIGNATURES.items():
                        for pat in patterns:
                            if re.search(pat, body):
                                sev = "HIGH" if sig_type in ("sql_error", "command_injection") else "MEDIUM"
                                results.append(Finding(
                                    plugin="UnifiedDetectionEngine",
                                    title=f"Signature Match: {sig_type.replace('_', ' ').title()}",
                                    severity=sev,
                                    description=f"Detected {sig_type} signature at {url}",
                                    confidence=80.0,
                                    url=url,
                                    evidence=pat,
                                    tags=["detection-engine", sig_type],
                                ))
                                break
            except Exception:
                continue
        return results

    def _pattern_analysis(self, findings: list, target: str) -> list:
        results = []
        sev_counts = defaultdict(int)
        plugin_counts = defaultdict(int)
        for f in findings:
            sev_counts[f.severity] += 1
            plugin_counts[f.plugin] += 1
        if sev_counts.get("CRITICAL", 0) >= 3:
            results.append(Finding(
                plugin="UnifiedDetectionEngine",
                title="High-Risk Target: Multiple Critical Vulnerabilities",
                severity="CRITICAL",
                description=f"Target has {sev_counts['CRITICAL']} critical vulnerabilities indicating systemic security failures",
                confidence=95.0, url=target,
                tags=["detection-engine", "pattern-analysis"],
            ))
        param_findings = [f for f in findings if f.param]
        param_counts = defaultdict(int)
        for f in param_findings:
            param_counts[f.param] += 1
        for param, count in param_counts.items():
            if count >= 3:
                results.append(Finding(
                    plugin="UnifiedDetectionEngine",
                    title=f"Multi-Vulnerability Parameter: {param}",
                    severity="HIGH",
                    description=f"Parameter '{param}' is vulnerable to {count} different attack types",
                    confidence=90.0, url=target, param=param,
                    tags=["detection-engine", "parameter-analysis"],
                ))
        return results


# ════════════════════════════════════════════════════════════════════════
#  MODULE 2 — ADVANCED FALSE POSITIVE REDUCER
#  Multi-strategy validation · Statistical analysis · Re-confirmation
# ════════════════════════════════════════════════════════════════════════

class AdvancedFPReducer:
    STRATEGIES = [
        "baseline_comparison",
        "payload_re_verification",
        "response_entropy_analysis",
        "timing_confirmation",
        "status_code_validation",
    ]

    def __init__(self, client):
        self._client = client
        self._baseline_cache = {}

    async def reduce(self, findings: list, target: str) -> list:
        if not findings:
            return findings
        await self._build_baseline(target)
        validated = []
        for f in findings:
            score = await self._validate_finding(f)
            if score >= 0.6:
                f.confidence = min(100.0, f.confidence + (score * 20))
                if score >= 0.8:
                    f.tags = list(set(f.tags + ["validated"]))
                validated.append(f)
            else:
                if f.severity in ("CRITICAL", "HIGH"):
                    retry_score = await self._deep_retest(f)
                    if retry_score >= 0.5:
                        f.confidence = max(f.confidence, 76.0)
                        f.tags = list(set(f.tags + ["retested"]))
                        validated.append(f)
        removed = len(findings) - len(validated)
        if removed > 0:
            log("INFO", f"[FP Reducer] Removed {removed} false positive(s)")
        return validated

    async def _build_baseline(self, target: str):
        test_paths = ["/", "/nonexistent_" + secrets.token_hex(4)]
        for path in test_paths:
            url = urljoin(target, path)
            try:
                resp = await self._client.request("GET", url)
                if resp:
                    body = resp.text if hasattr(resp, "text") else str(resp)
                    self._baseline_cache[path] = {
                        "status": resp.status if hasattr(resp, "status") else 0,
                        "length": len(body),
                        "entropy": self._calc_entropy(body),
                        "headers": dict(resp.headers) if hasattr(resp, "headers") else {},
                    }
            except Exception:
                pass

    async def _validate_finding(self, finding: Finding) -> float:
        scores = []
        if finding.evidence:
            scores.append(0.8)
        if finding.confidence >= 90:
            scores.append(0.9)
        elif finding.confidence >= 75:
            scores.append(0.7)
        else:
            scores.append(0.4)
        if finding.poc:
            scores.append(0.85)
        if finding.cwe:
            scores.append(0.7)
        if finding.url and finding.payload:
            try:
                resp = await self._client.request("GET", finding.url)
                if resp:
                    body = resp.text if hasattr(resp, "text") else str(resp)
                    baseline = self._baseline_cache.get("/", {})
                    baseline_len = baseline.get("length", 0)
                    if abs(len(body) - baseline_len) > 50:
                        scores.append(0.75)
                    else:
                        scores.append(0.3)
            except Exception:
                scores.append(0.5)
        return sum(scores) / max(len(scores), 1)

    async def _deep_retest(self, finding: Finding) -> float:
        if not finding.url:
            return 0.3
        try:
            results = []
            for _ in range(3):
                resp = await self._client.request("GET", finding.url)
                if resp:
                    body = resp.text if hasattr(resp, "text") else str(resp)
                    status = resp.status if hasattr(resp, "status") else 0
                    results.append({"status": status, "length": len(body)})
                await asyncio.sleep(0.5)
            if len(results) >= 2:
                statuses = [r["status"] for r in results]
                lengths = [r["length"] for r in results]
                if len(set(statuses)) == 1 and max(lengths) - min(lengths) < 100:
                    return 0.7
                return 0.4
        except Exception:
            pass
        return 0.3

    @staticmethod
    def _calc_entropy(data: str) -> float:
        if not data:
            return 0.0
        freq = defaultdict(int)
        for ch in data:
            freq[ch] += 1
        total = len(data)
        return -sum((c / total) * log2(c / total) for c in freq.values() if c > 0)


# ════════════════════════════════════════════════════════════════════════
#  MODULE 3 — PERFORMANCE ENGINE
#  Adaptive concurrency · Response caching · Efficiency metrics
# ════════════════════════════════════════════════════════════════════════

class PerformanceEngine:
    def __init__(self):
        self._start_time = time.monotonic()
        self._request_times = []
        self._module_times = {}
        self._cache_hits = 0
        self._cache_misses = 0
        self._total_requests = 0
        self._total_findings = 0
        self._errors = 0
        self._bytes_transferred = 0

    def record_request(self, duration: float, size: int = 0, error: bool = False):
        self._request_times.append(duration)
        self._total_requests += 1
        self._bytes_transferred += size
        if error:
            self._errors += 1

    def record_module(self, name: str, duration: float, findings: int):
        self._module_times[name] = {"duration": duration, "findings": findings}

    def record_scan_stats(self, client_stats: dict, total_findings: int):
        self._total_requests = client_stats.get("requests", 0)
        self._total_findings = total_findings
        self._errors = client_stats.get("errors", 0)

    def generate_report(self) -> dict:
        elapsed = time.monotonic() - self._start_time
        avg_req_time = (sum(self._request_times) / len(self._request_times)) if self._request_times else 0
        rps = self._total_requests / max(elapsed, 0.001)
        error_rate = (self._errors / max(self._total_requests, 1)) * 100
        efficiency = max(0, min(100, int(100 - error_rate - (avg_req_time * 10))))
        slowest_modules = sorted(
            self._module_times.items(), key=lambda x: -x[1]["duration"]
        )[:5]
        report = {
            "elapsed_seconds": round(elapsed, 2),
            "total_requests": self._total_requests,
            "total_findings": self._total_findings,
            "requests_per_second": round(rps, 2),
            "avg_request_time_ms": round(avg_req_time * 1000, 2),
            "error_rate_percent": round(error_rate, 2),
            "efficiency_score": efficiency,
            "bytes_transferred": self._bytes_transferred,
            "cache_hit_rate": round(
                (self._cache_hits / max(self._cache_hits + self._cache_misses, 1)) * 100, 2
            ),
            "slowest_modules": [
                {"name": name, "duration_s": round(info["duration"], 2), "findings": info["findings"]}
                for name, info in slowest_modules
            ],
            "recommendations": self._generate_recommendations(rps, error_rate, avg_req_time),
        }
        return report

    def _generate_recommendations(self, rps: float, error_rate: float, avg_time: float) -> list:
        recs = []
        if rps < 5:
            recs.append("Increase concurrency (-c flag) for better throughput")
        if error_rate > 20:
            recs.append("High error rate — target may have rate limiting or WAF. Use --stealth")
        if avg_time > 2.0:
            recs.append("Slow response times — consider reducing timeout or using proxy")
        if not recs:
            recs.append("Performance is within optimal parameters")
        return recs


