#  MODULE 7 — ENHANCED BUSINESS LOGIC ENGINE
#  Extended workflow analysis · Privilege escalation · Rate abuse
# ════════════════════════════════════════════════════════════════════════

class EnhancedBusinessLogicEngine:
    WORKFLOW_ENDPOINTS = [
        "/checkout", "/payment", "/order", "/subscribe", "/register",
        "/reset-password", "/transfer", "/approve", "/submit", "/confirm",
    ]
    PRIV_FIELDS = [
        "role", "is_admin", "admin", "privilege", "access_level",
        "is_superuser", "is_staff", "account_type", "tier", "plan",
    ]

    def __init__(self, client, config):
        self._client = client
        self._cfg = config

    async def scan(self, target: str) -> list:
        results = []
        results.extend(await self._test_privilege_escalation(target))
        results.extend(await self._test_rate_abuse(target))
        results.extend(await self._test_workflow_skip(target))
        results.extend(await self._test_negative_currency(target))
        results.extend(await self._test_replay_attacks(target))
        results.extend(await self._test_parameter_pollution_logic(target))
        return results

    async def _test_privilege_escalation(self, target: str) -> list:
        results = []
        test_endpoints = ["/api/user", "/api/profile", "/api/account", "/user/settings", "/api/me"]
        for ep in test_endpoints:
            url = urljoin(target, ep)
            for field in self.PRIV_FIELDS:
                for val in ["true", "1", "admin", "superuser"]:
                    try:
                        body = json.dumps({field: val})
                        resp = await self._client.request(
                            "PUT", url,
                            headers={"Content-Type": "application/json"},
                            data=body
                        )
                        if resp:
                            status = resp.status if hasattr(resp, "status") else 0
                            rbody = resp.text if hasattr(resp, "text") else ""
                            if status in (200, 201) and any(
                                ind.lower() in rbody.lower() for ind in ["success", "updated", "true", val]
                            ):
                                results.append(Finding(
                                    plugin="EnhancedBusinessLogic",
                                    title=f"Privilege Escalation: {field}={val}",
                                    severity="CRITICAL",
                                    description=f"Server accepted privilege escalation via {field}={val} at {ep}",
                                    confidence=85.0, url=url, param=field, payload=body,
                                    cwe="CWE-269", tags=["business-logic", "privilege-escalation"],
                                ))
                                break
                    except Exception:
                        continue
        return results

    async def _test_rate_abuse(self, target: str) -> list:
        results = []
        rate_endpoints = ["/api/login", "/api/register", "/api/reset-password", "/api/otp", "/api/verify"]
        for ep in rate_endpoints:
            url = urljoin(target, ep)
            success_count = 0
            for i in range(20):
                try:
                    resp = await self._client.request("POST", url,
                        headers={"Content-Type": "application/json"},
                        data=json.dumps({"email": f"test{i}@test.com", "password": "Test123!"}))
                    if resp:
                        status = resp.status if hasattr(resp, "status") else 0
                        if status not in (429, 503):
                            success_count += 1
                except Exception:
                    break
            if success_count >= 18:
                results.append(Finding(
                    plugin="EnhancedBusinessLogic",
                    title=f"Missing Rate Limiting: {ep}",
                    severity="MEDIUM",
                    description=f"No rate limiting on {ep} — {success_count}/20 requests succeeded",
                    confidence=80.0, url=url,
                    cwe="CWE-770", tags=["business-logic", "rate-limiting"],
                ))
        return results

    async def _test_workflow_skip(self, target: str) -> list:
        results = []
        for i, ep in enumerate(self.WORKFLOW_ENDPOINTS):
            url = urljoin(target, ep)
            try:
                resp = await self._client.request("POST", url,
                    headers={"Content-Type": "application/json"},
                    data=json.dumps({"step": "final", "skip": True}))
                if resp:
                    status = resp.status if hasattr(resp, "status") else 0
                    body = resp.text if hasattr(resp, "text") else ""
                    if status in (200, 201) and any(
                        s in body.lower() for s in SUCCESS_IND
                    ):
                        results.append(Finding(
                            plugin="EnhancedBusinessLogic",
                            title=f"Workflow Skip: {ep}",
                            severity="HIGH",
                            description=f"Workflow step bypass allowed at {ep} — direct final step accepted",
                            confidence=80.0, url=url,
                            cwe="CWE-841", tags=["business-logic", "workflow-bypass"],
                        ))
            except Exception:
                continue
        return results

    async def _test_negative_currency(self, target: str) -> list:
        results = []
        money_endpoints = ["/api/transfer", "/api/payment", "/api/withdraw", "/api/charge"]
        for ep in money_endpoints:
            url = urljoin(target, ep)
            for amount in [-1, -100, -0.01, 0]:
                try:
                    resp = await self._client.request("POST", url,
                        headers={"Content-Type": "application/json"},
                        data=json.dumps({"amount": amount, "to": "attacker"}))
                    if resp:
                        status = resp.status if hasattr(resp, "status") else 0
                        body = resp.text if hasattr(resp, "text") else ""
                        if status in (200, 201) and any(s in body.lower() for s in SUCCESS_IND):
                            results.append(Finding(
                                plugin="EnhancedBusinessLogic",
                                title=f"Negative Amount Accepted: {ep} (amount={amount})",
                                severity="CRITICAL",
                                description=f"Negative monetary value {amount} accepted at {ep}",
                                confidence=90.0, url=url, param="amount", payload=str(amount),
                                cwe="CWE-20", tags=["business-logic", "currency-manipulation"],
                            ))
                            break
                except Exception:
                    continue
        return results

    async def _test_replay_attacks(self, target: str) -> list:
        results = []
        replay_endpoints = ["/api/payment/confirm", "/api/transfer/execute", "/api/order/place"]
        for ep in replay_endpoints:
            url = urljoin(target, ep)
            nonce = secrets.token_hex(16)
            body = json.dumps({"nonce": nonce, "action": "confirm", "amount": 1})
            responses = []
            for _ in range(3):
                try:
                    resp = await self._client.request("POST", url,
                        headers={"Content-Type": "application/json"}, data=body)
                    if resp:
                        status = resp.status if hasattr(resp, "status") else 0
                        responses.append(status)
                except Exception:
                    break
            success_replays = sum(1 for s in responses if s in (200, 201))
            if success_replays >= 3:
                results.append(Finding(
                    plugin="EnhancedBusinessLogic",
                    title=f"Replay Attack: {ep}",
                    severity="HIGH",
                    description=f"Request replay accepted {success_replays} times at {ep} — no nonce validation",
                    confidence=80.0, url=url,
                    cwe="CWE-294", tags=["business-logic", "replay-attack"],
                ))
        return results

    async def _test_parameter_pollution_logic(self, target: str) -> list:
        results = []
        test_urls = ["/api/user?role=user&role=admin", "/api/order?price=100&price=0"]
        for path in test_urls:
            url = urljoin(target, path)
            try:
                resp = await self._client.request("GET", url)
                if resp:
                    status = resp.status if hasattr(resp, "status") else 0
                    body = resp.text if hasattr(resp, "text") else ""
                    if status == 200 and ("admin" in body.lower() or "0" in body):
                        results.append(Finding(
                            plugin="EnhancedBusinessLogic",
                            title=f"Business Logic HPP: {path}",
                            severity="HIGH",
                            description=f"HTTP parameter pollution exploitable for business logic at {path}",
                            confidence=75.0, url=url,
                            cwe="CWE-235", tags=["business-logic", "hpp"],
                        ))
            except Exception:
                continue
        return results


# ════════════════════════════════════════════════════════════════════════
#  MODULE 8 — PLUGIN SYSTEM
#  Dynamic loading · Sandboxed execution · Custom scanner plugins
# ════════════════════════════════════════════════════════════════════════

class PluginSystem:
    PLUGIN_INTERFACE = {
        "name": str, "version": str, "description": str,
        "author": str, "scan": "async callable(client, target, config) -> list[Finding]",
    }

    def __init__(self, plugin_dir: str = "plugins"):
        self._plugin_dir = Path(plugin_dir)
        self._plugins = {}
        self._loaded = False

    def discover(self):
        if not self._plugin_dir.exists():
            self._plugin_dir.mkdir(parents=True, exist_ok=True)
            self._create_example_plugin()
            log("INFO", f"[Plugin System] Created plugin directory: {self._plugin_dir}")
            return
        plugin_files = list(self._plugin_dir.glob("*.py"))
        for pf in plugin_files:
            if pf.name.startswith("_"):
                continue
            try:
                self._load_plugin(pf)
            except Exception as e:
                log("WARN", f"[Plugin System] Failed to load {pf.name}: {e}")
        log("INFO", f"[Plugin System] Discovered {len(self._plugins)} plugin(s)")
        self._loaded = True

    def _load_plugin(self, path: Path):
        import importlib.util
        spec = importlib.util.spec_from_file_location(path.stem, str(path))
        if not spec or not spec.loader:
            return
        module = importlib.util.module_from_spec(spec)
        try:
            spec.loader.exec_module(module)
        except Exception as e:
            raise RuntimeError(f"Plugin execution error: {e}")
        plugin_class = getattr(module, "Plugin", None)
        if not plugin_class:
            for attr_name in dir(module):
                attr = getattr(module, attr_name)
                if isinstance(attr, type) and hasattr(attr, "scan") and hasattr(attr, "name"):
                    plugin_class = attr
                    break
        if plugin_class:
            instance = plugin_class()
            name = getattr(instance, "name", path.stem)
            self._plugins[name] = instance
            log("OK", f"[Plugin System] Loaded: {name}")

    def _create_example_plugin(self):
        example = '''"""
Example WebScout Plugin — Custom Header Checker

To create a plugin:
1. Create a .py file in the plugins/ directory
2. Define a class with 'name', 'version', 'description' attributes
3. Implement async def scan(self, client, target, config) -> list method
4. Return a list of Finding objects
"""


class Plugin:
    name = "example_header_checker"
    version = "1.0.0"
    description = "Checks for custom security headers"
    author = "WebScout"

    async def scan(self, client, target, config):
        findings = []
        try:
            resp = await client.request("GET", target)
            if resp and hasattr(resp, "headers"):
                headers = {k.lower(): v for k, v in resp.headers.items()}
                if "x-content-type-options" not in headers:
                    from dataclasses import dataclass, field
                    from datetime import datetime
                    findings.append(type("Finding", (), {
                        "plugin": self.name,
                        "title": "Missing X-Content-Type-Options",
                        "severity": "LOW",
                        "description": "X-Content-Type-Options header not set",
                        "confidence": 90.0,
                        "evidence": "",
                        "url": target,
                        "remediation": "Add X-Content-Type-Options: nosniff",
                        "cwe": "CWE-16",
                        "cvss": 3.0,
                        "owasp": "A05",
                        "poc": "",
                        "param": "",
                        "payload": "",
                        "request": "",
                        "response": "",
                        "tags": ["plugin", "headers"],
                        "timestamp": datetime.now().isoformat(),
                        "fp": lambda self: "plugin_example",
                    })())
        except Exception:
            pass
        return findings
'''
        example_path = self._plugin_dir / "_example_plugin.py"
        example_path.write_text(example)

    async def run_all(self, client, target: str, config) -> list:
        all_findings = []
        for name, plugin in self._plugins.items():
            try:
                scan_func = getattr(plugin, "scan", None)
                if scan_func and callable(scan_func):
                    result = await scan_func(client, target, config)
                    if result and isinstance(result, list):
                        all_findings.extend(result)
                        log("OK", f"[Plugin: {name}] {len(result)} finding(s)")
            except Exception as e:
                log("WARN", f"[Plugin: {name}] Error: {e}")
        return all_findings

    def count(self) -> int:
        return len(self._plugins)

    def list_plugins(self) -> list:
        return [
            {"name": name, "version": getattr(p, "version", "?"), "description": getattr(p, "description", "")}
            for name, p in self._plugins.items()
        ]


