    def _gen_json_report(self, findings: list, target: str, stats: dict,
                        path: str, timeline=None) -> str:
        report = {
            "meta": {
                "tool": "WebScout Ultimate v45",
                "target": target,
                "scan_date": datetime.now().isoformat(),
                "total_findings": len(findings),
                "author": "JOKER 313 YEMEN",
            },
            "summary": {
                sev: sum(1 for f in findings if f.severity == sev)
                for sev in SEV_ORDER
            },
            "findings": [asdict(f) for f in findings],
            "stats": stats,
        }
        Path(path).write_text(json.dumps(report, indent=2, default=str), encoding="utf-8")
        return path

    def _gen_csv_report(self, findings: list, path: str) -> str:
        with open(path, "w", newline="", encoding="utf-8") as f:
            writer = csv.writer(f)
            writer.writerow(["#", "Severity", "Title", "Plugin", "Confidence", "URL", "Param", "CWE", "Description"])
            for i, finding in enumerate(findings, 1):
                writer.writerow([
                    i, finding.severity, finding.title, finding.plugin,
                    f"{finding.confidence:.0f}%", finding.url[:100], finding.param,
                    finding.cwe, finding.description[:200],
                ])
        return path


