#  MODULE 10 — ENHANCED VULNERABILITY DATABASE
#  SQLite persistence · CVE correlation · Historical tracking · Trends
# ════════════════════════════════════════════════════════════════════════

class EnhancedVulnDB:
    CVE_PATTERNS = {
        "CVE-2021-44228": {"name": "Log4Shell", "keywords": ["log4j", "jndi", "log4shell"], "severity": "CRITICAL"},
        "CVE-2023-44487": {"name": "HTTP/2 Rapid Reset", "keywords": ["http/2", "rapid reset", "h2"], "severity": "HIGH"},
        "CVE-2021-41773": {"name": "Apache Path Traversal", "keywords": ["apache", "path traversal", "2.4.49"], "severity": "CRITICAL"},
        "CVE-2023-22515": {"name": "Atlassian Confluence RCE", "keywords": ["confluence", "atlassian"], "severity": "CRITICAL"},
        "CVE-2024-3400":  {"name": "PAN-OS Command Injection", "keywords": ["palo alto", "pan-os", "globalprotect"], "severity": "CRITICAL"},
        "CVE-2023-34362": {"name": "MOVEit Transfer SQLi", "keywords": ["moveit", "progress"], "severity": "CRITICAL"},
        "CVE-2021-26855": {"name": "ProxyLogon", "keywords": ["exchange", "proxylogon", "owa"], "severity": "CRITICAL"},
        "CVE-2023-46747": {"name": "F5 BIG-IP Auth Bypass", "keywords": ["f5", "big-ip", "bigip"], "severity": "CRITICAL"},
        "CVE-2024-21887": {"name": "Ivanti Connect Secure", "keywords": ["ivanti", "pulse", "connect secure"], "severity": "CRITICAL"},
        "CVE-2023-27997": {"name": "FortiOS Heap Overflow", "keywords": ["fortinet", "fortios", "fortigate", "ssl vpn"], "severity": "CRITICAL"},
        "CVE-2022-1388":  {"name": "F5 BIG-IP iControl REST", "keywords": ["f5", "icontrol", "big-ip"], "severity": "CRITICAL"},
        "CVE-2021-34473": {"name": "ProxyShell", "keywords": ["exchange", "proxyshell", "autodiscover"], "severity": "CRITICAL"},
        "CVE-2023-23397": {"name": "Outlook Privilege Escalation", "keywords": ["outlook", "ntlm"], "severity": "CRITICAL"},
        "CVE-2022-22965": {"name": "Spring4Shell", "keywords": ["spring", "spring4shell", "classloader"], "severity": "CRITICAL"},
        "CVE-2021-21972": {"name": "VMware vCenter RCE", "keywords": ["vcenter", "vmware", "vsphere"], "severity": "CRITICAL"},
    }

    def __init__(self, db_path: str = "webscout_vulns.db"):
        self._db_path = db_path
        self._conn = None

    def init(self):
        self._conn = sqlite3.connect(self._db_path)
        self._conn.execute("PRAGMA journal_mode=WAL")
        self._conn.execute("""CREATE TABLE IF NOT EXISTS scans (
            id TEXT PRIMARY KEY, target TEXT, scan_date TEXT,
            total_findings INTEGER, critical INTEGER, high INTEGER,
            medium INTEGER, low INTEGER, info INTEGER, stats TEXT)""")
        self._conn.execute("""CREATE TABLE IF NOT EXISTS findings (
            id INTEGER PRIMARY KEY AUTOINCREMENT, scan_id TEXT,
            plugin TEXT, title TEXT, severity TEXT, confidence REAL,
            url TEXT, param TEXT, cwe TEXT, cvss REAL, description TEXT,
            payload TEXT, evidence TEXT, tags TEXT, timestamp TEXT,
            cve_match TEXT DEFAULT '',
            FOREIGN KEY (scan_id) REFERENCES scans(id))""")
        self._conn.execute("""CREATE TABLE IF NOT EXISTS cve_correlations (
            id INTEGER PRIMARY KEY AUTOINCREMENT, scan_id TEXT,
            cve_id TEXT, cve_name TEXT, finding_title TEXT, confidence REAL,
            FOREIGN KEY (scan_id) REFERENCES scans(id))""")
        self._conn.commit()

    def save_scan(self, findings: list, target: str, stats: dict) -> str:
        scan_id = f"scan_{secrets.token_hex(8)}_{int(time.time())}"
        sev_counts = defaultdict(int)
        for f in findings:
            sev_counts[f.severity] += 1
        self._conn.execute(
            "INSERT INTO scans VALUES (?,?,?,?,?,?,?,?,?)",
            (scan_id, target, datetime.now().isoformat(), len(findings),
             sev_counts["CRITICAL"], sev_counts["HIGH"], sev_counts["MEDIUM"],
             sev_counts["LOW"], sev_counts["INFO"], json.dumps(stats, default=str))
        )
        for f in findings:
            self._conn.execute(
                "INSERT INTO findings (scan_id,plugin,title,severity,confidence,url,param,cwe,cvss,"
                "description,payload,evidence,tags,timestamp) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)",
                (scan_id, f.plugin, f.title, f.severity, f.confidence, f.url, f.param,
                 f.cwe, f.cvss, f.description, f.payload, f.evidence,
                 json.dumps(f.tags), f.timestamp)
            )
        self._conn.commit()
        return scan_id

    def correlate_cves(self, findings: list) -> list:
        correlations = []
        for f in findings:
            text = f"{f.title} {f.description} {f.plugin} {' '.join(f.tags)}".lower()
            for cve_id, info in self.CVE_PATTERNS.items():
                matches = sum(1 for kw in info["keywords"] if kw in text)
                if matches >= 2:
                    conf = min(95.0, 60.0 + matches * 15)
                    correlations.append({
                        "cve_id": cve_id, "cve_name": info["name"],
                        "finding_title": f.title, "confidence": conf,
                        "severity": info["severity"],
                    })
                    f.tags = list(set(f.tags + [cve_id]))
                    f.cwe = f.cwe or cve_id
        return correlations

    def get_scan_history(self, target: str = None, limit: int = 20) -> list:
        if target:
            rows = self._conn.execute(
                "SELECT * FROM scans WHERE target=? ORDER BY scan_date DESC LIMIT ?",
                (target, limit)
            ).fetchall()
        else:
            rows = self._conn.execute(
                "SELECT * FROM scans ORDER BY scan_date DESC LIMIT ?", (limit,)
            ).fetchall()
        return [{"id": r[0], "target": r[1], "date": r[2], "total": r[3],
                 "critical": r[4], "high": r[5]} for r in rows]

    def get_trends(self, target: str) -> dict:
        rows = self._conn.execute(
            "SELECT scan_date, total_findings, critical, high FROM scans "
            "WHERE target=? ORDER BY scan_date", (target,)
        ).fetchall()
        return {
            "scans": len(rows),
            "trend": "improving" if len(rows) >= 2 and rows[-1][1] < rows[-2][1] else
                     "worsening" if len(rows) >= 2 and rows[-1][1] > rows[-2][1] else "stable",
            "history": [{"date": r[0], "total": r[1], "critical": r[2], "high": r[3]} for r in rows],
        }

    def close(self):
        if self._conn:
            self._conn.close()


