    def build_graph(self, findings: list, target: str) -> dict:
        graph = {
            "target": target,
            "nodes": [],
            "edges": [],
            "clusters": defaultdict(list),
        }
        for i, f in enumerate(findings):
            node = {
                "id": i, "title": f.title, "severity": f.severity,
                "plugin": f.plugin, "url": f.url, "confidence": f.confidence,
                "tags": f.tags,
            }
            graph["nodes"].append(node)
            for tag in f.tags:
                graph["clusters"][tag].append(i)
        for i, f1 in enumerate(findings):
            for j, f2 in enumerate(findings):
                if i >= j:
                    continue
                relationship = self._find_relationship(f1, f2)
                if relationship:
                    graph["edges"].append({
                        "from": i, "to": j,
                        "type": relationship["type"],
                        "strength": relationship["strength"],
                    })
        return graph

    def _find_relationship(self, f1, f2) -> dict:
        if f1.url and f2.url and urlparse(f1.url).path == urlparse(f2.url).path:
            return {"type": "same_endpoint", "strength": 0.9}
        if f1.param and f1.param == f2.param:
            return {"type": "same_parameter", "strength": 0.8}
        shared_tags = set(f1.tags) & set(f2.tags)
        if len(shared_tags) >= 2:
            return {"type": "related_category", "strength": 0.6}
        chaining_pairs = [
            (["sqli", "injection"], ["rce", "command", "execute"]),
            (["xss", "script"], ["session", "cookie", "auth"]),
            (["ssrf"], ["cloud", "metadata", "internal"]),
            (["idor", "access"], ["data", "leak", "disclosure"]),
            (["upload", "file"], ["rce", "command", "shell"]),
        ]
        t1 = " ".join(f1.tags + [f1.title.lower()])
        t2 = " ".join(f2.tags + [f2.title.lower()])
        for group_a, group_b in chaining_pairs:
            if any(k in t1 for k in group_a) and any(k in t2 for k in group_b):
                return {"type": "chaining_potential", "strength": 0.7}
            if any(k in t2 for k in group_a) and any(k in t1 for k in group_b):
                return {"type": "chaining_potential", "strength": 0.7}
        return None

    def find_attack_chains(self, graph: dict) -> list:
        chains = []
        all_text = " ".join(
            f"{n['title']} {' '.join(n.get('tags', []))}".lower()
            for n in graph["nodes"]
        )
        for rule in self.CHAIN_RULES:
            stage_matches = []
            for stage_idx, keywords in enumerate(rule["keywords_per_stage"]):
                matches = sum(1 for kw in keywords if kw in all_text)
                stage_matches.append(matches > 0)
            matched_stages = sum(stage_matches)
            if matched_stages >= 2:
                chains.append({
                    "name": rule["name"],
                    "stages_matched": matched_stages,
                    "total_stages": len(rule["stages"]),
                    "stages": rule["stages"],
                    "severity": rule["final_severity"],
                    "impact": rule["impact"],
                    "completeness": round(matched_stages / len(rule["stages"]) * 100),
                })
        return sorted(chains, key=lambda x: -x["completeness"])

    def print_chains(self, chains: list):
        for ch in chains:
            icon = "🔴" if ch["severity"] == "CRITICAL" else "🟠"
            log("VULN", f"{icon} Attack Chain: {ch['name']} "
                f"({ch['stages_matched']}/{ch['total_stages']} stages, "
                f"{ch['completeness']}% complete)")
            for i, stage in enumerate(ch["stages"]):
                status = "✓" if i < ch["stages_matched"] else "○"
                log("INFO", f"  Stage {i+1}: [{status}] {stage}")

    def export_graph(self, graph: dict, out_dir: str, target: str) -> str:
        safe = re.sub(r"[^a-z0-9_-]", "_", target.lower())[:40]
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        path = str(Path(out_dir) / f"attack_graph_{safe}_{ts}.json")
        export_data = {
            "meta": {"tool": "WebScout Ultimate v45", "target": target,
                     "generated": datetime.now().isoformat()},
            "graph": {
                "nodes": graph["nodes"],
                "edges": graph["edges"],
                "clusters": dict(graph["clusters"]),
                "stats": {
                    "total_nodes": len(graph["nodes"]),
                    "total_edges": len(graph["edges"]),
                    "clusters": len(graph["clusters"]),
                },
            },
        }
        Path(path).write_text(json.dumps(export_data, indent=2, default=str), encoding="utf-8")
        return path


