#  MODULE 13 — ADVANCED COVERAGE ENGINE
#  Coverage tracking · Gap analysis · Endpoint enumeration · Completeness
# ════════════════════════════════════════════════════════════════════════

class AdvancedCoverageEngine:
    COMMON_ENDPOINTS = [
        "/", "/login", "/register", "/admin", "/api", "/api/v1", "/api/v2",
        "/graphql", "/health", "/status", "/search", "/upload", "/download",
        "/profile", "/settings", "/dashboard", "/logout", "/forgot-password",
        "/reset-password", "/verify", "/confirm", "/checkout", "/cart",
        "/payment", "/webhook", "/callback", "/oauth", "/token", "/refresh",
        "/.env", "/.git/config", "/robots.txt", "/sitemap.xml",
        "/wp-admin", "/wp-login.php", "/administrator",
        "/swagger-ui.html", "/api-docs", "/openapi.json",
        "/debug", "/phpinfo.php", "/server-status", "/server-info",
    ]

    ATTACK_CATEGORIES = [
        "SQLi", "XSS", "SSRF", "CSRF", "SSTI", "XXE", "RCE",
        "Path Traversal", "IDOR", "Authentication", "Authorization",
        "Business Logic", "Information Disclosure", "Cryptographic",
        "Configuration", "Input Validation", "Session Management",
    ]

    def __init__(self, client):
        self._client = client

    async def scan(self, target: str, existing_findings: list) -> list:
        results = []
        discovered = await self._enumerate_endpoints(target)
        tested_urls = set(f.url for f in existing_findings if f.url)
        tested_params = set(f.param for f in existing_findings if f.param)
        tested_categories = set()
        for f in existing_findings:
            text = f"{f.title} {f.plugin} {' '.join(f.tags)}".lower()
            for cat in self.ATTACK_CATEGORIES:
                if cat.lower() in text:
                    tested_categories.add(cat)
        untested_endpoints = [ep for ep in discovered if ep not in tested_urls]
        untested_categories = [cat for cat in self.ATTACK_CATEGORIES if cat not in tested_categories]
        total_endpoints = len(discovered) or 1
        coverage_pct = round((len(tested_urls) / max(total_endpoints, 1)) * 100, 1)
        cat_coverage = round((len(tested_categories) / len(self.ATTACK_CATEGORIES)) * 100, 1)
        results.append(Finding(
            plugin="AdvancedCoverageEngine",
            title=f"Scan Coverage: {coverage_pct}% endpoints, {cat_coverage}% attack categories",
            severity="INFO",
            description=(
                f"Endpoint coverage: {len(tested_urls)}/{total_endpoints} ({coverage_pct}%) | "
                f"Category coverage: {len(tested_categories)}/{len(self.ATTACK_CATEGORIES)} ({cat_coverage}%) | "
                f"Parameters tested: {len(tested_params)} | "
                f"Total findings: {len(existing_findings)}"
            ),
            confidence=100.0, url=target,
            tags=["coverage", "analysis"],
        ))
        if untested_endpoints:
            results.append(Finding(
                plugin="AdvancedCoverageEngine",
                title=f"Coverage Gap: {len(untested_endpoints)} untested endpoint(s)",
                severity="INFO",
                description=f"Untested endpoints: {', '.join(untested_endpoints[:20])}",
                confidence=100.0, url=target,
                tags=["coverage", "gap"],
            ))
        if untested_categories:
            results.append(Finding(
                plugin="AdvancedCoverageEngine",
                title=f"Coverage Gap: {len(untested_categories)} untested attack category(ies)",
                severity="LOW",
                description=f"Untested categories: {', '.join(untested_categories)}",
                confidence=100.0, url=target,
                remediation="Run with --deep-scan to cover all attack categories",
                tags=["coverage", "gap", "recommendation"],
            ))
        return results

    async def _enumerate_endpoints(self, target: str) -> list:
        discovered = []
        for ep in self.COMMON_ENDPOINTS:
            url = urljoin(target, ep)
            try:
                resp = await self._client.request("GET", url)
                if resp:
                    status = resp.status if hasattr(resp, "status") else 0
                    if status not in (404, 0):
                        discovered.append(url)
            except Exception:
                continue
        return discovered


