#  MODULE 14 — INFRASTRUCTURE DEEP SCAN
# ════════════════════════════════════════════════════════════════════════

class InfrastructureDeepScanner:
    SERVICE_PORTS = {
        21: ("FTP", "MEDIUM"), 22: ("SSH", "LOW"), 25: ("SMTP", "LOW"),
        53: ("DNS", "LOW"), 80: ("HTTP", "INFO"), 110: ("POP3", "LOW"),
        143: ("IMAP", "LOW"), 389: ("LDAP", "MEDIUM"), 443: ("HTTPS", "INFO"),
        445: ("SMB", "HIGH"), 587: ("SMTP Submission", "LOW"),
        993: ("IMAPS", "LOW"), 995: ("POP3S", "LOW"), 1433: ("MSSQL", "HIGH"),
        1521: ("Oracle DB", "HIGH"), 2049: ("NFS", "HIGH"),
        2375: ("Docker API", "CRITICAL"), 3306: ("MySQL", "HIGH"),
        3389: ("RDP", "MEDIUM"), 5432: ("PostgreSQL", "HIGH"),
        5601: ("Kibana", "MEDIUM"), 5900: ("VNC", "HIGH"),
        5984: ("CouchDB", "HIGH"), 6379: ("Redis", "HIGH"),
        8000: ("HTTP Alt", "LOW"), 8080: ("HTTP Proxy/Admin", "MEDIUM"),
        8443: ("HTTPS Admin", "MEDIUM"), 9000: ("Admin/Dev Service", "MEDIUM"),
        9200: ("Elasticsearch", "HIGH"), 9300: ("Elasticsearch Transport", "HIGH"),
        11211: ("Memcached", "HIGH"), 15672: ("RabbitMQ Admin", "MEDIUM"),
        27017: ("MongoDB", "HIGH"),
    }

    SUBDOMAIN_WORDS = [
        "www", "api", "admin", "portal", "dev", "staging", "test", "beta",
        "mail", "smtp", "vpn", "db", "mysql", "postgres", "redis", "mongo",
        "kibana", "grafana", "jenkins", "git", "ci", "status", "monitor",
        "backup", "files", "cdn", "assets", "old", "legacy",
    ]

    HTTP_PORTS = {80, 443, 8000, 8080, 8443, 9000, 5601, 9200, 5984, 15672}

    def __init__(self, client: "WebScoutClient", cfg: "ScanConfig" = None):
        self.client = client
        self.cfg = cfg
        self.timeout = 2.5

    async def scan(self, target: str) -> list[Finding]:
        findings: list[Finding] = []
        host = urlparse(target).hostname or target
        hosts = await self._discover_scoped_hosts(host)
        findings.extend(self._host_inventory_findings(target, hosts))
        tasks = [self._scan_host_services(h) for h in hosts[:30]]
        for result in await asyncio.gather(*tasks, return_exceptions=True):
            if isinstance(result, list):
                findings.extend(result)
        return findings

    async def _discover_scoped_hosts(self, host: str) -> list[str]:
        discovered = {host}
        base = self._base_domain(host)
        candidates = [f"{word}.{base}" for word in self.SUBDOMAIN_WORDS if base and host != f"{word}.{base}"]
        sem = asyncio.Semaphore(25)

        async def resolve(candidate: str):
            async with sem:
                try:
                    infos = await asyncio.to_thread(socket.getaddrinfo, candidate, None)
                    if infos:
                        discovered.add(candidate)
                except Exception:
                    pass

        await asyncio.gather(*(resolve(c) for c in candidates), return_exceptions=True)
        return sorted(discovered)

    def _base_domain(self, host: str) -> str:
        parts = host.split(".")
        if len(parts) <= 2:
            return host
        return ".".join(parts[-2:])

    def _host_inventory_findings(self, target: str, hosts: list[str]) -> list[Finding]:
        if len(hosts) <= 1:
            return []
        return [Finding(
            plugin="infrastructure-deep-scan",
            title=f"Scoped infrastructure inventory discovered {len(hosts)} host(s)",
            severity="INFO",
            description="The scanner safely resolved related in-scope hostnames for broader authorized coverage.",
            confidence=0.80,
            evidence=", ".join(hosts[:25]),
            url=target,
            remediation="Review all discovered hosts and ensure each one is intentionally exposed and included in the security program.",
            tags=["infra", "inventory", "scoped-discovery"],
        )]

    async def _scan_host_services(self, host: str) -> list[Finding]:
        findings: list[Finding] = []
        tasks = [self._check_port(host, port) for port in self.SERVICE_PORTS]
        for result in await asyncio.gather(*tasks, return_exceptions=True):
            if not result:
                continue
            port, service, severity = result
            finding = Finding(
                plugin="infrastructure-deep-scan",
                title=f"Exposed {service} service on {host}:{port}",
                severity=severity,
                description=f"A TCP connection was established to {service} on {host}:{port}. This is a safe exposure check only; no credentials or destructive actions were attempted.",
                confidence=0.86,
                evidence=f"TCP connect succeeded: {host}:{port}",
                url=f"{host}:{port}",
                remediation="Restrict access to trusted networks, require strong authentication, and verify the service is intentionally internet-accessible.",
                tags=["infra", "open-port", service.lower().replace(" ", "-")],
            )
            findings.append(finding)
            if port in self.HTTP_PORTS:
                findings.extend(await self._fingerprint_http_service(host, port, service))
        return findings

    async def _check_port(self, host: str, port: int):
        try:
            conn = asyncio.open_connection(host, port, ssl=False)
            reader, writer = await asyncio.wait_for(conn, timeout=self.timeout)
            writer.close()
            try:
                await writer.wait_closed()
            except Exception:
                pass
            service, severity = self.SERVICE_PORTS[port]
            return port, service, severity
        except Exception:
            return None

    async def _fingerprint_http_service(self, host: str, port: int, service: str) -> list[Finding]:
        scheme = "https" if port in (443, 8443) else "http"
        url = f"{scheme}://{host}" if port in (80, 443) else f"{scheme}://{host}:{port}"
        resp = await self.client.get(url, allow_redirects=False)
        if not resp:
            return []
        headers = resp.get("headers", {})
        evidence = "; ".join(f"{k}: {v}" for k, v in headers.items() if k.lower() in {"server", "x-powered-by", "www-authenticate"})[:500]
        if not evidence:
            evidence = f"HTTP status {resp.get('status')}, length {resp.get('length')}"
        return [Finding(
            plugin="infrastructure-deep-scan",
            title=f"HTTP service fingerprinted on {host}:{port}",
            severity="INFO",
            description=f"The exposed {service} endpoint returned a reachable HTTP response.",
            confidence=0.78,
            evidence=evidence,
            url=url,
            remediation="Confirm the service is intended to be public and remove unnecessary version banners.",
            tags=["infra", "http-fingerprint"],
        )]


