class DatabaseExposureScanner:
    DB_PORTS = {
        1433: "Microsoft SQL Server", 1521: "Oracle Database", 3306: "MySQL/MariaDB",
        5432: "PostgreSQL", 5984: "CouchDB", 6379: "Redis", 7000: "Cassandra",
        9042: "Cassandra", 9200: "Elasticsearch", 11211: "Memcached",
        27017: "MongoDB", 27018: "MongoDB", 28017: "MongoDB HTTP",
    }

    ADMIN_PATHS = {
        "/phpmyadmin/": ("phpMyAdmin panel exposed", "HIGH", ["phpMyAdmin", "pma_username"]),
        "/adminer.php": ("Adminer database panel exposed", "HIGH", ["Adminer", "Login"]),
        "/pgadmin/": ("pgAdmin panel exposed", "HIGH", ["pgAdmin", "PostgreSQL"]),
        "/mongo-express/": ("Mongo Express panel exposed", "HIGH", ["Mongo Express", "Database"]),
        "/redis-commander/": ("Redis Commander panel exposed", "HIGH", ["Redis Commander", "redis"]),
        "/_cluster/health": ("Elasticsearch cluster health exposed", "CRITICAL", ["cluster_name", "status", "number_of_nodes"]),
        "/_cat/indices?v": ("Elasticsearch indices exposed", "CRITICAL", ["health", "index", "docs.count"]),
        "/solr/admin/": ("Solr admin panel exposed", "HIGH", ["Solr Admin", "Dashboard"]),
        "/couchdb/_utils/": ("CouchDB Futon/Fauxton exposed", "HIGH", ["CouchDB", "Fauxton"]),
    }

    def __init__(self, client: "WebScoutClient"):
        self.client = client
        self.timeout = 2.5

    async def scan(self, target: str) -> list[Finding]:
        findings: list[Finding] = []
        host = urlparse(target).hostname or target
        port_results = await asyncio.gather(
            *(self._check_db_port(host, port, name) for port, name in self.DB_PORTS.items()),
            return_exceptions=True,
        )
        for result in port_results:
            if isinstance(result, Finding):
                findings.append(result)
        panel_results = await asyncio.gather(
            *(self._check_admin_path(target, path, spec) for path, spec in self.ADMIN_PATHS.items()),
            return_exceptions=True,
        )
        for result in panel_results:
            if isinstance(result, Finding):
                findings.append(result)
        return findings

    async def _check_db_port(self, host: str, port: int, name: str) -> Optional[Finding]:
        try:
            conn = asyncio.open_connection(host, port, ssl=False)
            reader, writer = await asyncio.wait_for(conn, timeout=self.timeout)
            banner = ""
            try:
                banner_bytes = await asyncio.wait_for(reader.read(80), timeout=0.5)
                banner = banner_bytes.decode("utf-8", "replace").strip()
            except Exception:
                pass
            writer.close()
            try:
                await writer.wait_closed()
            except Exception:
                pass
            return Finding(
                plugin="database-exposure-audit",
                title=f"Database service exposed: {name} on {host}:{port}",
                severity="HIGH",
                description="A database-related TCP service is reachable from the scan origin. This check is non-authenticated and non-destructive.",
                confidence=0.88,
                evidence=(banner or f"TCP connect succeeded to {host}:{port}")[:500],
                url=f"{host}:{port}",
                remediation="Bind databases to private interfaces, require VPN/private network access, enforce TLS and strong authentication, and block public ingress.",
                tags=["database", "open-port", name.lower().replace(" ", "-")],
            )
        except Exception:
            return None

    async def _check_admin_path(self, target: str, path: str, spec: tuple) -> Optional[Finding]:
        title, severity, indicators = spec
        url = urljoin(target.rstrip("/") + "/", path.lstrip("/"))
        resp = await self.client.get(url, allow_redirects=True)
        if not resp:
            return None
        status = resp.get("status", 0)
        text = resp.get("text", "")[:15000]
        headers = resp.get("headers", {})
        hits = [i for i in indicators if i.lower() in text.lower()]
        if status == 200 and hits:
            confidence = 0.91
            evidence = ", ".join(hits)
        elif status in (401, 403):
            confidence = 0.67
            severity = "MEDIUM"
            evidence = f"Protected database/admin endpoint returned HTTP {status}"
        elif status == 200 and any(h.lower() in json.dumps(headers).lower() for h in indicators):
            confidence = 0.74
            evidence = "Database/admin fingerprint found in headers"
        else:
            return None
        return Finding(
            plugin="database-exposure-audit",
            title=title,
            severity=severity,
            description="A database administration or database API surface appears reachable from the target web origin.",
            confidence=confidence,
            evidence=evidence[:500],
            url=url,
            remediation="Remove public exposure, enforce SSO/MFA, IP allowlisting, and least-privilege database access.",
            tags=["database", "admin-panel", "exposure"],
        )


