# ─────────────────────────────────────────────────────────────────────────────
# I-01  CRASH-RECOVERY DECORATOR
# ─────────────────────────────────────────────────────────────────────────────

def crash_recovery(
    max_retries=2,
    delay=1.0,
    fallback=None,
    log_fn=None,
):
    """
    Decorator that catches any exception from an async or sync function,
    logs it with the built-in logger, optionally retries up to *max_retries*
    times (with exponential back-off), and returns *fallback* when all
    attempts fail.  Works transparently on both ``async def`` and plain ``def``
    functions.

    Usage::

        @crash_recovery(max_retries=3, delay=0.5, fallback=[])
        async def risky_scan(self, client, url):
            ...
    """
    def decorator(fn):
        _is_async = asyncio.iscoroutinefunction(fn)
        _logger = log_fn or (
            lambda tag, msg: logging.getLogger("webscout").warning("[%s] %s", tag, msg)
        )

        @wraps(fn)
        async def async_wrapper(*args, **kwargs):
            for attempt in range(max_retries + 1):
                try:
                    return await fn(*args, **kwargs)
                except asyncio.CancelledError:
                    raise
                except Exception as exc:
                    _logger(
                        "RECOVER",
                        "{} attempt {}/{} failed: {}: {}".format(
                            fn.__qualname__, attempt + 1, max_retries + 1,
                            type(exc).__name__, exc,
                        ),
                    )
                    if attempt < max_retries:
                        await asyncio.sleep(delay * (attempt + 1))
            _logger("RECOVER",
                    "{} all retries exhausted — returning fallback".format(fn.__qualname__))
            return fallback() if callable(fallback) else fallback

        @wraps(fn)
        def sync_wrapper(*args, **kwargs):
            for attempt in range(max_retries + 1):
                try:
                    return fn(*args, **kwargs)
                except Exception as exc:
                    _logger(
                        "RECOVER",
                        "{} attempt {}/{} failed: {}: {}".format(
                            fn.__qualname__, attempt + 1, max_retries + 1,
                            type(exc).__name__, exc,
                        ),
                    )
                    if attempt < max_retries:
                        time.sleep(delay * (attempt + 1))
            _logger("RECOVER",
                    "{} all retries exhausted — returning fallback".format(fn.__qualname__))
            return fallback() if callable(fallback) else fallback

        return async_wrapper if _is_async else sync_wrapper
    return decorator


# ─────────────────────────────────────────────────────────────────────────────
# I-02  DEADLOCK PREVENTION — TIMEOUT-GUARDED SEMAPHORE
# ─────────────────────────────────────────────────────────────────────────────

class DeadlockSafeSemaphore:
    """
    Asyncio semaphore wrapper that raises ``asyncio.TimeoutError`` instead of
    deadlocking if acquisition takes longer than *timeout_s* seconds.

    Drop-in replacement wherever ``asyncio.Semaphore`` is used::

        self._sem = DeadlockSafeSemaphore(concurrency, timeout_s=30)
        async with self._sem:
            ...
    """

    def __init__(self, value, timeout_s=30.0):
        self._sem = asyncio.Semaphore(value)
        self._timeout = timeout_s

    async def __aenter__(self):
        try:
            await asyncio.wait_for(self._sem.acquire(), timeout=self._timeout)
        except asyncio.TimeoutError:
            raise asyncio.TimeoutError(
                "DeadlockSafeSemaphore: failed to acquire within {}s — "
                "possible deadlock or concurrency saturation".format(self._timeout)
            )
        return self

    async def __aexit__(self, *_):
        self._sem.release()

    def locked(self):
        return self._sem.locked()


def patch_webscout_client_deadlock_prevention(client_instance, timeout_s=30.0):
    """
    Monkey-patch an existing WebScoutClient instance to replace its internal
    semaphore with a :class:`DeadlockSafeSemaphore`.  Call after construction::

        client = WebScoutClient(cfg)
        patch_webscout_client_deadlock_prevention(client, timeout_s=30)
    """
    for attr in ("_sem", "_semaphore", "sem", "semaphore", "_concurrency_sem"):
        if hasattr(client_instance, attr):
            original = getattr(client_instance, attr)
            if isinstance(original, asyncio.Semaphore):
                limit = original._value  # noqa: SLF001
                setattr(client_instance, attr,
                        DeadlockSafeSemaphore(limit, timeout_s=timeout_s))
                logging.getLogger("webscout").info(
                    "DeadlockSafeSemaphore installed on %s.%s (limit=%d, timeout=%gs)",
                    type(client_instance).__name__, attr, limit, timeout_s,
                )
                return
    logging.getLogger("webscout").debug(
        "patch_webscout_client_deadlock_prevention: no semaphore attribute found on %s",
        type(client_instance).__name__,
    )


# ─────────────────────────────────────────────────────────────────────────────
# I-03  I/O VS LOGIC SEPARATION — PURE SCANNER MIXIN
# ─────────────────────────────────────────────────────────────────────────────

class PureScannerMixin:
    """
    Mixin that enforces separation between async I/O and business logic.

    Subclasses implement ``_analyze(response_data)`` as a pure, synchronous,
    side-effect-free function.  The mixin runs the async I/O to obtain the
    response and then dispatches ``_analyze`` into a thread-pool executor so
    the event loop stays free during heavy processing.

    Example::

        class MyScanner(PureScannerMixin):
            def _analyze(self, response_data):
                findings = []
                if "error" in response_data.get("text", "").lower():
                    findings.append({"title": "Error Disclosure"})
                return findings

            async def scan(self, client, url):
                return await self.scan_with_analysis(client, url)
    """

    async def scan_with_analysis(self, client, url, method="GET", **request_kwargs):
        loop = asyncio.get_event_loop()
        if method.upper() == "GET":
            response = await client.get(url, **request_kwargs)
        elif method.upper() == "POST":
            response = await client.post(url, **request_kwargs)
        else:
            response = await client.request(method, url, **request_kwargs)

        if response is None:
            return []

        response_data = (
            dict(response) if isinstance(response, dict)
            else {"text": str(response), "status": 0}
        )

        executor = ThreadPoolExecutor(max_workers=1)
        try:
            findings = await loop.run_in_executor(executor, self._analyze, response_data)
        finally:
            executor.shutdown(wait=False)

        return findings if isinstance(findings, list) else []

    def _analyze(self, response_data):
        raise NotImplementedError(
            "{} must implement _analyze(response_data) -> list".format(
                type(self).__name__
            )
        )


# ─────────────────────────────────────────────────────────────────────────────
# I-04  HEALTH-SCORED PROXY ROTATOR
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class _ProxyHealth:
    proxy: str
    success: int = 0
    failure: int = 0
    total_latency_ms: float = 0.0
    last_used: float = field(default_factory=time.time)
    blocked: bool = False

    @property
    def score(self):
        total = self.success + self.failure
        if total == 0:
            return 50.0
        success_rate = self.success / total * 100
        avg_lat = (self.total_latency_ms / total) if total > 0 else 1000.0
        return max(0.0, success_rate - min(50.0, avg_lat / 100.0))

    @property
    def avg_latency_ms(self):
        total = self.success + self.failure
        return (self.total_latency_ms / total) if total > 0 else 0.0


class HealthScoredProxyRotator:
    """
    Improved proxy rotator with per-proxy success/failure scoring, automatic
    health monitoring, weighted random selection, and dead-proxy quarantine.

    Usage::

        rotator = HealthScoredProxyRotator(proxy_list)
        await rotator.start_health_monitor()
        proxy = await rotator.get()
        rotator.report_success(proxy, latency_ms=120)
        rotator.report_failure(proxy)
    """

    QUARANTINE_SECS = 120

    def __init__(self, proxies, test_url="https://www.google.com", check_interval_s=60.0):
        self._proxies = {p: _ProxyHealth(proxy=p) for p in proxies}
        self._test_url = test_url
        self._check_interval = check_interval_s
        self._lock = asyncio.Lock()
        self._monitor_task = None
        self._quarantined = {}

    async def start_health_monitor(self):
        if self._monitor_task is None or self._monitor_task.done():
            self._monitor_task = asyncio.create_task(self._monitor_loop())

    def stop_health_monitor(self):
        if self._monitor_task and not self._monitor_task.done():
            self._monitor_task.cancel()

    async def _monitor_loop(self):
        while True:
            try:
                await asyncio.sleep(self._check_interval)
                await self._ping_all()
                self._recover_quarantined()
            except asyncio.CancelledError:
                break
            except Exception as exc:
                logging.getLogger("webscout").warning(
                    "HealthScoredProxyRotator monitor error: %s", exc)

    async def _ping_one(self, proxy):
        start = time.time()
        try:
            connector = aiohttp.TCPConnector(ssl=False)
            async with aiohttp.ClientSession(connector=connector) as session:
                async with session.get(
                    self._test_url, proxy=proxy,
                    timeout=aiohttp.ClientTimeout(total=10),
                    allow_redirects=True,
                ) as resp:
                    await resp.read()
            self.report_success(proxy, (time.time() - start) * 1000)
        except Exception:
            self.report_failure(proxy)

    async def _ping_all(self):
        tasks = [asyncio.create_task(self._ping_one(p)) for p in list(self._proxies)]
        await asyncio.gather(*tasks, return_exceptions=True)

    def _recover_quarantined(self):
        now = time.time()
        for p, t in list(self._quarantined.items()):
            if now - t > self.QUARANTINE_SECS:
                del self._quarantined[p]
                if p in self._proxies:
                    self._proxies[p].blocked = False

    def report_success(self, proxy, latency_ms=0.0):
        if proxy in self._proxies:
            h = self._proxies[proxy]
            h.success += 1
            h.total_latency_ms += latency_ms
            h.last_used = time.time()
            h.blocked = False

    def report_failure(self, proxy):
        if proxy in self._proxies:
            h = self._proxies[proxy]
            h.failure += 1
            h.last_used = time.time()
            rate = h.failure / max(1, h.success + h.failure)
            if rate > 0.8 and h.failure >= 5:
                h.blocked = True
                self._quarantined[proxy] = time.time()
                logging.getLogger("webscout").warning(
                    "Proxy quarantined: %s (score=%.1f)", proxy, h.score)

    async def get(self):
        async with self._lock:
            available = [h for h in self._proxies.values() if not h.blocked]
            if not available:
                self._recover_quarantined()
                available = [h for h in self._proxies.values() if not h.blocked]
            if not available:
                return None
            weights = [max(1.0, h.score) for h in available]
            total = sum(weights)
            r = random.random() * total
            cumulative = 0.0
            for h, w in zip(available, weights):
                cumulative += w
                if r <= cumulative:
                    return h.proxy
            return available[-1].proxy

    def stats(self):
        return [
            {
                "proxy": h.proxy,
                "score": round(h.score, 1),
                "success": h.success,
                "failure": h.failure,
                "avg_latency_ms": round(h.avg_latency_ms, 1),
                "blocked": h.blocked,
            }
            for h in sorted(self._proxies.values(), key=lambda x: x.score, reverse=True)
        ]


# ─────────────────────────────────────────────────────────────────────────────
# I-05  MEMORY MANAGEMENT (WEAK-REF RESULT CACHE + PERIODIC GC)
# ─────────────────────────────────────────────────────────────────────────────

class WeakRefResultCache:
    """
    Result cache that holds weak references to Finding objects and enforces a
    hard cap on entry count.  When the cap is reached the oldest 25 % of
    entries are evicted before inserting new ones.

    Prevents unbounded memory growth during large scans.
    """

    def __init__(self, max_entries=5000):
        self._store = {}
        self._order = deque()
        self._max = max_entries
        self._lock = threading.Lock()

    def _evict(self):
        evict_count = max(1, self._max // 4)
        for _ in range(evict_count):
            if self._order:
                old_key = self._order.popleft()
                self._store.pop(old_key, None)

    def add(self, key, obj):
        with self._lock:
            if len(self._store) >= self._max:
                self._evict()
            try:
                self._store[key] = weakref.ref(obj)
            except TypeError:
                self._store[key] = obj
            self._order.append(key)

    def add_bulk(self, key, objects):
        for i, obj in enumerate(objects):
            self.add("{}:{}".format(key, i), obj)

    def get(self, key):
        with self._lock:
            ref = self._store.get(key)
            if ref is None:
                return None
            if callable(ref):
                obj = ref()
                if obj is None:
                    del self._store[key]
                return obj
            return ref

    def size(self):
        with self._lock:
            return len(self._store)

    def clear(self):
        with self._lock:
            self._store.clear()
            self._order.clear()


class PeriodicGarbageCollector:
    """
    Runs ``gc.collect()`` periodically in a background asyncio task to prevent
    cyclic-reference buildup during long scans.
    """

    def __init__(self, interval_s=60.0):
        self._interval = interval_s
        self._task = None

    async def start(self):
        if self._task is None or self._task.done():
            self._task = asyncio.create_task(self._run())

    def stop(self):
        if self._task and not self._task.done():
            self._task.cancel()

    async def _run(self):
        while True:
            try:
                await asyncio.sleep(self._interval)
                collected = gc.collect()
                logging.getLogger("webscout").debug(
                    "PeriodicGC: collected %d objects", collected)
            except asyncio.CancelledError:
                break


# ─────────────────────────────────────────────────────────────────────────────
# I-06  OOB SERVER EXCEPTION HANDLING & GRACEFUL FALLBACK
# ─────────────────────────────────────────────────────────────────────────────

class OOBServerFallbackMixin:
    """
    Mixin for OOB server classes.  Wraps ``start()`` / ``stop()`` so that a
    failed OOB server never crashes the main scan.  Sets ``self.available``
    to ``True`` only when the server is confirmed running.

    Usage::

        class OOBServerEnhanced(OOBServerFallbackMixin, ...):
            ...

        oob = OOBServerEnhanced(...)
        await oob.safe_start()
        collab_url = oob.http_url("test") if oob.available else ""
    """

    available = False
    _fallback_reason = ""

    async def safe_start(self, *args, **kwargs):
        try:
            await self.start(*args, **kwargs)
            self.available = True
            return True
        except OSError as exc:
            self._fallback_reason = (
                "OOB server bind failed (OSError {}): {}".format(exc.errno, exc)
            )
            logging.getLogger("webscout").warning(
                "OOB server unavailable — %s — falling back to passive mode",
                self._fallback_reason,
            )
            self.available = False
            return False
        except Exception as exc:
            self._fallback_reason = "OOB server startup error: {}: {}".format(
                type(exc).__name__, exc)
            logging.getLogger("webscout").warning(
                "OOB server unavailable — %s", self._fallback_reason)
            self.available = False
            return False

    async def safe_stop(self):
        try:
            await self.stop()
        except Exception as exc:
            logging.getLogger("webscout").debug(
                "OOB server stop error (ignored): %s", exc)


def find_free_port(start=8880, end=9000):
    """Return an available TCP port in the range [start, end)."""
    for port in range(start, end):
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
            s.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
            try:
                s.bind(("0.0.0.0", port))
                return port
            except OSError:
                continue
    raise OSError("No free port found in range {}-{}".format(start, end))


# ─────────────────────────────────────────────────────────────────────────────
# I-07  MULTIPROCESSING FOR CPU-BOUND DNS RESOLUTION
# ─────────────────────────────────────────────────────────────────────────────

def _resolve_dns_worker(hostname):
    """
    Worker function executed in a separate process.
    Returns a dict with A, AAAA, CNAME, MX, TXT records (best-effort).
    Must be a top-level function for pickling by multiprocessing.
    """
    result = {
        "hostname": hostname,
        "A": [], "AAAA": [], "CNAME": "", "MX": [], "TXT": [],
    }
    try:
        import dns.resolver as _r  # type: ignore
        for rtype in ("A", "AAAA", "MX", "TXT"):
            try:
                answers = _r.resolve(hostname, rtype, lifetime=8)
                if rtype == "A":
                    result["A"] = [str(a) for a in answers]
                elif rtype == "AAAA":
                    result["AAAA"] = [str(a) for a in answers]
                elif rtype == "MX":
                    result["MX"] = [str(r.exchange) for r in answers]
                elif rtype == "TXT":
                    result["TXT"] = [
                        b"".join(r.strings).decode(errors="replace")
                        for r in answers
                    ]
            except Exception:
                pass
        try:
            cname_ans = _r.resolve(hostname, "CNAME", lifetime=5)
            result["CNAME"] = str(cname_ans[0].target).rstrip(".")
        except Exception:
            pass
    except ImportError:
        import socket as _sock
        try:
            info = _sock.getaddrinfo(hostname, None)
            for item in info:
                addr = item[4][0]
                if ":" in addr:
                    if addr not in result["AAAA"]:
                        result["AAAA"].append(addr)
                else:
                    if addr not in result["A"]:
                        result["A"].append(addr)
        except Exception:
            pass
    return result


class MultiprocessDNSResolver:
    """
    Resolves multiple hostnames in parallel using a ``ProcessPoolExecutor``
    so blocking DNS lookups never stall the asyncio event loop.

    Usage::

        async with MultiprocessDNSResolver(workers=8) as resolver:
            results = await resolver.resolve_many(["a.com", "b.com"])
    """

    def __init__(self, workers=8):
        self._workers = min(workers, multiprocessing.cpu_count() * 2)
        self._pool = None

    async def __aenter__(self):
        self._pool = ProcessPoolExecutor(max_workers=self._workers)
        return self

    async def __aexit__(self, *_):
        if self._pool:
            self._pool.shutdown(wait=False)

    async def resolve_one(self, hostname):
        loop = asyncio.get_event_loop()
        if self._pool is None:
            self._pool = ProcessPoolExecutor(max_workers=self._workers)
        try:
            return await loop.run_in_executor(
                self._pool, _resolve_dns_worker, hostname)
        except Exception as exc:
            logging.getLogger("webscout").debug(
                "DNS resolve error for %s: %s", hostname, exc)
            return {
                "hostname": hostname,
                "A": [], "AAAA": [], "CNAME": "", "MX": [], "TXT": [],
            }

    async def resolve_many(self, hostnames):
        tasks = [self.resolve_one(h) for h in hostnames]
        return list(await asyncio.gather(*tasks, return_exceptions=False))


# ─────────────────────────────────────────────────────────────────────────────
# I-08  PERIODIC SCAN HEALTHCHECK (BACKGROUND WATCHDOG)
# ─────────────────────────────────────────────────────────────────────────────

class ScanHealthMonitor:
    """
    Background task that periodically checks scan health metrics and logs
    warnings when thresholds are breached.

    Monitors: error rate, RSS memory, elapsed time vs budget, event-loop lag.
    """

    def __init__(
        self,
        check_interval_s=30.0,
        max_error_rate=0.5,
        max_memory_mb=2048.0,
        scan_timeout_s=3600.0,
    ):
        self._interval = check_interval_s
        self._max_err_rate = max_error_rate
        self._max_mem_mb = max_memory_mb
        self._timeout = scan_timeout_s
        self._start_time = time.time()
        self._requests = 0
        self._errors = 0
        self._lock = threading.Lock()
        self._task = None
        self.health_ok = True
        self.alerts = []

    def record_request(self, success):
        with self._lock:
            self._requests += 1
            if not success:
                self._errors += 1

    async def start(self):
        if self._task is None or self._task.done():
            self._task = asyncio.create_task(self._run())

    def stop(self):
        if self._task and not self._task.done():
            self._task.cancel()

    def _memory_mb(self):
        try:
            import psutil  # type: ignore
            return psutil.Process().memory_info().rss / 1024 / 1024
        except ImportError:
            pass
        try:
            with open("/proc/self/status") as fh:
                for line in fh:
                    if line.startswith("VmRSS:"):
                        return int(line.split()[1]) / 1024
        except Exception:
            pass
        return 0.0

    async def _measure_loop_lag_ms(self):
        t0 = asyncio.get_event_loop().time()
        await asyncio.sleep(0)
        return (asyncio.get_event_loop().time() - t0) * 1000

    async def _run(self):
        logger = logging.getLogger("webscout")
        while True:
            try:
                await asyncio.sleep(self._interval)
                elapsed = time.time() - self._start_time
                with self._lock:
                    req = self._requests
                    err = self._errors
                err_rate = err / max(1, req)
                mem_mb = self._memory_mb()
                lag_ms = await self._measure_loop_lag_ms()

                alerts = []
                if err_rate > self._max_err_rate and req > 20:
                    alerts.append("HIGH_ERROR_RATE({:.0%})".format(err_rate))
                if mem_mb > self._max_mem_mb:
                    alerts.append("HIGH_MEMORY({:.0f}MB)".format(mem_mb))
                if elapsed > self._timeout * 0.9:
                    alerts.append(
                        "NEAR_TIMEOUT({:.0f}s/{:.0f}s)".format(elapsed, self._timeout))
                if lag_ms > 500:
                    alerts.append("HIGH_LOOP_LAG({:.0f}ms)".format(lag_ms))

                self.health_ok = len(alerts) == 0
                self.alerts = alerts
                status = "HEALTHY" if self.health_ok else "DEGRADED [{}]".format(
                    ", ".join(alerts))
                logger.info(
                    "[HealthMonitor] %s | req=%d err=%d mem=%.0fMB lag=%.0fms t=%ds",
                    status, req, err, mem_mb, lag_ms, int(elapsed),
                )
            except asyncio.CancelledError:
                break
            except Exception as exc:
                logging.getLogger("webscout").debug(
                    "ScanHealthMonitor error: %s", exc)


# ─────────────────────────────────────────────────────────────────────────────
# I-09  AUTO-RESTART ON FAILURE (SCAN WATCHDOG WRAPPER)
# ─────────────────────────────────────────────────────────────────────────────

class ScanWatchdog:
    """
    Wraps an async scan coroutine factory with automatic restart on failure.

    Usage::

        async def my_scan():
            await run_webscout(args)

        watchdog = ScanWatchdog(my_scan, max_restarts=3, restart_delay_s=5)
        await watchdog.run()
    """

    def __init__(self, scan_factory, max_restarts=3, restart_delay_s=5.0):
        self._factory = scan_factory
        self._max_restarts = max_restarts
        self._delay = restart_delay_s
        self.restart_count = 0
        self.last_error = None

    async def run(self):
        logger = logging.getLogger("webscout")
        for attempt in range(self._max_restarts + 1):
            try:
                return await self._factory()
            except asyncio.CancelledError:
                raise
            except Exception as exc:
                self.last_error = exc
                self.restart_count += 1
                tb = traceback.format_exc()
                logger.error(
                    "[Watchdog] Scan attempt %d/%d crashed: %s\n%s",
                    attempt + 1, self._max_restarts + 1, exc, tb,
                )
                if attempt < self._max_restarts:
                    logger.info("[Watchdog] Restarting in %.1fs ...", self._delay)
                    await asyncio.sleep(self._delay)
                else:
                    logger.critical(
                        "[Watchdog] All %d restart attempts exhausted. Giving up.",
                        self._max_restarts,
                    )
                    raise


# ─────────────────────────────────────────────────────────────────────────────
# I-10  SELF-SIGNED TLS CERTIFICATE GENERATOR
# ─────────────────────────────────────────────────────────────────────────────

class SelfSignedCertGenerator:
    """
    Generates a self-signed X.509 certificate + private key pair for the OOB
    HTTPS server.

    Tries ``cryptography`` library first, falls back to ``openssl`` CLI.

    Usage::

        gen = SelfSignedCertGenerator(cn="oob.webscout.local", days=1)
        cert_path, key_path = gen.generate(output_dir="/tmp")
        ssl_ctx = gen.ssl_context()
    """

    def __init__(self, cn="oob.webscout.local", days=1):
        self.cn = cn
        self.days = days
        self._cert_path = None
        self._key_path = None

    def generate(self, output_dir=""):
        d = output_dir or tempfile.mkdtemp(prefix="ws_tls_")
        cert_path = os.path.join(d, "oob_cert.pem")
        key_path = os.path.join(d, "oob_key.pem")

        if self._try_cryptography(cert_path, key_path):
            self._cert_path, self._key_path = cert_path, key_path
            return cert_path, key_path

        if self._try_openssl_cli(cert_path, key_path):
            self._cert_path, self._key_path = cert_path, key_path
            return cert_path, key_path

        raise RuntimeError(
            "Cannot generate self-signed certificate: install 'cryptography' "
            "(pip install cryptography) or ensure 'openssl' is in PATH."
        )

    def _try_cryptography(self, cert_path, key_path):
        try:
            from cryptography import x509 as _x509  # type: ignore
            from cryptography.x509.oid import NameOID as _NameOID  # type: ignore
            from cryptography.hazmat.primitives import (  # type: ignore
                hashes as _hashes, serialization as _ser,
            )
            from cryptography.hazmat.primitives.asymmetric import rsa as _rsa  # type: ignore
            import datetime as _dt

            key = _rsa.generate_private_key(public_exponent=65537, key_size=2048)
            subject = issuer = _x509.Name(
                [_x509.NameAttribute(_NameOID.COMMON_NAME, self.cn)])
            now = _dt.datetime.utcnow()
            cert = (
                _x509.CertificateBuilder()
                .subject_name(subject)
                .issuer_name(issuer)
                .public_key(key.public_key())
                .serial_number(_x509.random_serial_number())
                .not_valid_before(now)
                .not_valid_after(now + _dt.timedelta(days=self.days))
                .add_extension(
                    _x509.SubjectAlternativeName([_x509.DNSName(self.cn)]),
                    critical=False,
                )
                .sign(key, _hashes.SHA256())
            )
            with open(cert_path, "wb") as fh:
                fh.write(cert.public_bytes(_ser.Encoding.PEM))
            with open(key_path, "wb") as fh:
                fh.write(key.private_bytes(
                    _ser.Encoding.PEM,
                    _ser.PrivateFormat.TraditionalOpenSSL,
                    _ser.NoEncryption(),
                ))
            return True
        except ImportError:
            return False
        except Exception:
            return False

    def _try_openssl_cli(self, cert_path, key_path):
        if not shutil.which("openssl"):
            return False
        try:
            subprocess.run([
                "openssl", "req", "-x509", "-newkey", "rsa:2048",
                "-keyout", key_path, "-out", cert_path,
                "-days", str(self.days), "-nodes",
                "-subj", "/CN={}".format(self.cn),
            ], capture_output=True, check=True, timeout=30)
            return True
        except Exception:
            return False

    def ssl_context(self):
        if not self._cert_path or not self._key_path:
            raise RuntimeError("Call generate() first")
        ctx = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
        ctx.load_cert_chain(self._cert_path, self._key_path)
        return ctx


# ─────────────────────────────────────────────────────────────────────────────
# I-11  IMPROVED LLM INTEGRATION (OLLAMA / OPENAI ANALYSIS)
# ─────────────────────────────────────────────────────────────────────────────

class LLMVulnerabilityAnalyzer:
    """
    Sends a batch of findings to a local Ollama instance or an OpenAI-compatible
    API for AI-powered triage, remediation synthesis, and attack narrative
    generation.

    Automatic backend detection order: Ollama -> OpenAI -> disabled.
    Falls back gracefully — if LLM is unavailable, returns ``None`` silently.
    """

    SYSTEM_PROMPT = (
        "You are an expert penetration tester and AppSec engineer. "
        "Analyse the JSON list of security findings and respond with a JSON object "
        "containing: \"risk_summary\" (2-3 sentence plain-English executive summary), "
        "\"attack_narrative\" (step-by-step attacker scenario chaining the top findings), "
        "\"remediation_priority\" (ordered list of {finding_title, action, urgency}). "
        "Respond ONLY with valid JSON — no markdown, no explanation."
    )

    def __init__(
        self,
        model="llama3",
        base_url="http://localhost:11434",
        api_key="",
        max_findings_per_batch=20,
        timeout_s=60.0,
    ):
        self._model = model
        self._base_url = base_url.rstrip("/")
        self._api_key = api_key or os.environ.get("OPENAI_API_KEY", "")
        self._batch = max_findings_per_batch
        self._timeout = timeout_s
        self._backend = None

    async def _detect_backend(self):
        try:
            connector = aiohttp.TCPConnector(ssl=False)
            async with aiohttp.ClientSession(connector=connector) as sess:
                async with sess.get(
                    "{}/api/tags".format(self._base_url),
                    timeout=aiohttp.ClientTimeout(total=5),
                ) as resp:
                    if resp.status == 200:
                        return "ollama"
        except Exception:
            pass
        if self._api_key:
            return "openai"
        return "disabled"

    async def analyze_findings(self, findings):
        if self._backend is None:
            self._backend = await self._detect_backend()
        if self._backend == "disabled":
            return None

        batch = findings[:self._batch]
        findings_json = json.dumps([
            {
                "title": getattr(f, "title", str(f)),
                "severity": getattr(f, "severity", "UNKNOWN"),
                "confidence": getattr(f, "confidence", 0),
                "url": getattr(f, "url", ""),
                "description": str(getattr(f, "description", ""))[:300],
            }
            for f in batch
        ], indent=2)
        prompt = "Findings:\n{}".format(findings_json)

        if self._backend == "ollama":
            return await self._call_ollama(prompt)
        elif self._backend == "openai":
            return await self._call_openai(prompt)
        return None

    async def _call_ollama(self, prompt):
        payload = {
            "model": self._model,
            "prompt": prompt,
            "system": self.SYSTEM_PROMPT,
            "stream": False,
            "format": "json",
        }
        try:
            async with aiohttp.ClientSession() as sess:
                async with sess.post(
                    "{}/api/generate".format(self._base_url),
                    json=payload,
                    timeout=aiohttp.ClientTimeout(total=self._timeout),
                ) as resp:
                    data = await resp.json()
                    return json.loads(data.get("response", "{}"))
        except Exception as exc:
            logging.getLogger("webscout").debug(
                "Ollama LLM call failed: %s", exc)
            return None

    async def _call_openai(self, prompt):
        headers = {
            "Authorization": "Bearer {}".format(self._api_key),
            "Content-Type": "application/json",
        }
        base = (
            self._base_url
            if "openai.com" not in self._base_url
            else "https://api.openai.com"
        )
        payload = {
            "model": self._model or "gpt-4o-mini",
            "messages": [
                {"role": "system", "content": self.SYSTEM_PROMPT},
                {"role": "user", "content": prompt},
            ],
            "response_format": {"type": "json_object"},
        }
        try:
            async with aiohttp.ClientSession(headers=headers) as sess:
                async with sess.post(
                    "{}/v1/chat/completions".format(base),
                    json=payload,
                    timeout=aiohttp.ClientTimeout(total=self._timeout),
                ) as resp:
                    data = await resp.json()
                    raw = data["choices"][0]["message"]["content"]
                    return json.loads(raw)
        except Exception as exc:
            logging.getLogger("webscout").debug(
                "OpenAI LLM call failed: %s", exc)
            return None


# ─────────────────────────────────────────────────────────────────────────────
# I-12  AUTO-EXPLOITATION ENGINE (MULTI-VECTOR)
# ─────────────────────────────────────────────────────────────────────────────

class AutoExploitationEngine:
    """
    Enhanced auto-exploitation layer that confirms vulnerabilities using
    multiple non-destructive proof techniques:

    - SQLi:         sqlmap --current-db (read-only, no dump)
    - XSS:          reflected canary echo-back
    - Path Trav:    try to read /etc/hostname
    - SSTI:         math evaluation  {{7*7}} -> 49
    - Open Redir:   follow redirect and check landing domain

    Each attempt is non-destructive and read-only.
    """

    _SEVERITY_ORDER = {"CRITICAL": 5, "HIGH": 4, "MEDIUM": 3, "LOW": 2, "INFO": 1}

    def __init__(self, sqlmap_path="sqlmap", timeout_s=300, oob_domain=""):
        self._sqlmap = sqlmap_path
        self._timeout = timeout_s
        self._oob = oob_domain

    async def run(self, client, findings, target):
        confirmed = []
        sorted_findings = sorted(
            findings,
            key=lambda f: self._SEVERITY_ORDER.get(
                getattr(f, "severity", ""), 0),
            reverse=True,
        )
        for finding in sorted_findings[:30]:
            tags = [t.lower() for t in (getattr(finding, "tags", []) or [])]
            title_lower = (getattr(finding, "title", "") or "").lower()
            url = getattr(finding, "url", target) or target

            method = None
            if any(x in title_lower or x in " ".join(tags)
                   for x in ("sqli", "sql injection")):
                method = "sqli"
            elif any(x in title_lower or x in " ".join(tags)
                     for x in ("xss", "cross-site")):
                method = "xss"
            elif any(x in title_lower
                     for x in ("path traversal", "lfi", "local file")):
                method = "path_traversal"
            elif any(x in title_lower for x in ("ssti", "template injection")):
                method = "ssti"
            elif "open redirect" in title_lower:
                method = "open_redirect"

            if method is None:
                continue

            result = await self._confirm(client, finding, url, method)
            if result:
                confirmed.append(result)

        return confirmed

    async def _confirm(self, client, finding, url, method):
        try:
            if method == "sqli":
                return await self._confirm_sqli(finding, url)
            elif method == "xss":
                return await self._confirm_xss(client, finding, url)
            elif method == "path_traversal":
                return await self._confirm_path_traversal(client, finding, url)
            elif method == "ssti":
                return await self._confirm_ssti(client, finding, url)
            elif method == "open_redirect":
                return await self._confirm_open_redirect(client, finding, url)
        except Exception as exc:
            logging.getLogger("webscout").debug(
                "AutoExploit confirm error (%s): %s", method, exc)
        return None

    async def _confirm_sqli(self, finding, url):
        if not shutil.which(self._sqlmap):
            return None
        loop = asyncio.get_event_loop()
        param = getattr(finding, "param", "") or ""
        cmd = [
            self._sqlmap, "-u", url,
            "--batch", "--current-db", "--smart",
            "--level", "1", "--risk", "1",
            "--disable-coloring", "-q",
        ]
        if param:
            cmd += ["-p", param]
        try:
            proc = await loop.run_in_executor(
                None,
                lambda: subprocess.run(
                    cmd, capture_output=True, text=True,
                    timeout=self._timeout, shell=False,
                ),
            )
            out = proc.stdout + proc.stderr
            m = re.search(
                r"current database(?:\s*\(.*?\))?\s*[:=]\s*['\"]?([A-Za-z0-9_.\-]+)",
                out, re.I,
            )
            if m:
                db = m.group(1)
                finding.confidence = 100.0
                ev = getattr(finding, "evidence", "") or ""
                finding.evidence = ev + "\n[AutoExploit] sqlmap confirmed; db={}".format(db)
                return finding
        except Exception:
            pass
        return None

    async def _confirm_xss(self, client, finding, url):
        canary = "webscout_xss_{}".format(hashlib.md5(url.encode()).hexdigest()[:8])
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        param = getattr(finding, "param", "") or (
            list(params.keys())[0] if params else "q")
        test_params = dict(params)
        test_params[param] = ["<script>{}</script>".format(canary)]
        test_url = urlunparse(
            parsed._replace(query=urlencode(test_params, doseq=True)))
        r = await client.get(test_url)
        if r and canary in (r.get("text", "") or ""):
            finding.confidence = 99.0
            ev = getattr(finding, "evidence", "") or ""
            finding.evidence = ev + "\n[AutoExploit] XSS canary '{}' reflected".format(
                canary)
            return finding
        return None

    async def _confirm_path_traversal(self, client, finding, url):
        for payload in ("../../../../etc/hostname", "../../../../proc/version"):
            parsed = urlparse(url)
            params = parse_qs(parsed.query)
            param = getattr(finding, "param", "") or (
                list(params.keys())[0] if params else "file")
            test_params = dict(params)
            test_params[param] = [payload]
            test_url = urlunparse(
                parsed._replace(query=urlencode(test_params, doseq=True)))
            r = await client.get(test_url)
            if r and re.search(
                r"[a-z0-9\-]{3,64}\n|Linux version",
                r.get("text", "") or "",
            ):
                finding.confidence = 99.0
                ev = getattr(finding, "evidence", "") or ""
                finding.evidence = ev + (
                    "\n[AutoExploit] Path traversal confirmed via {}".format(payload))
                return finding
        return None

    async def _confirm_ssti(self, client, finding, url):
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        param = getattr(finding, "param", "") or (
            list(params.keys())[0] if params else "q")
        for payload, expected in (
            ("{{7*7}}", "49"), ("${7*7}", "49"), ("<%=7*7%>", "49"),
        ):
            test_params = dict(params)
            test_params[param] = [payload]
            test_url = urlunparse(
                parsed._replace(query=urlencode(test_params, doseq=True)))
            r = await client.get(test_url)
            if r and expected in (r.get("text", "") or ""):
                finding.confidence = 100.0
                ev = getattr(finding, "evidence", "") or ""
                finding.evidence = ev + (
                    "\n[AutoExploit] SSTI confirmed: {} -> {}".format(
                        payload, expected))
                return finding
        return None

    async def _confirm_open_redirect(self, client, finding, url):
        parsed = urlparse(url)
        params = parse_qs(parsed.query)
        param = getattr(finding, "param", "") or "redirect"
        target_evil = "https://evil.webscout-test.invalid"
        test_params = dict(params)
        test_params[param] = [target_evil]
        test_url = urlunparse(
            parsed._replace(query=urlencode(test_params, doseq=True)))
        r = await client.get(test_url, allow_redirects=True)
        if r and "evil.webscout-test" in (
            (r.get("url", "") or "") + (r.get("text", "") or "")
        ):
            finding.confidence = 95.0
            ev = getattr(finding, "evidence", "") or ""
            finding.evidence = ev + "\n[AutoExploit] Open redirect confirmed"
            return finding
        return None


# ─────────────────────────────────────────────────────────────────────────────
# I-13  DYNAMIC ATTACK CHAINING (ML-RANKED CHAIN SEQUENCER)
# ─────────────────────────────────────────────────────────────────────────────

class DynamicAttackChainSequencer:
    """
    Builds and ranks attack chains from discovered findings using a
    dependency-aware scoring model (DAG traversal + cumulative CVSS).

    Returns a ranked list of attack paths for the PoCEngine to execute.
    """

    UNLOCK_MAP = {
        "sqli":           ["data_exfil", "auth_bypass", "rce_sqli"],
        "xss":            ["session_hijack", "credential_theft"],
        "ssrf":           ["cloud_metadata", "internal_scan", "rce_ssrf"],
        "path_traversal": ["lfi", "config_disclosure"],
        "lfi":            ["rce_lfi"],
        "xxe":            ["ssrf", "file_read"],
        "idor":           ["priv_esc", "data_exfil"],
        "open_redirect":  ["phishing", "oauth_theft"],
        "ssti":           ["rce_ssti"],
        "jwt_weak":       ["auth_bypass", "priv_esc"],
        "rce_sqli":       ["full_compromise"],
        "rce_lfi":        ["full_compromise"],
        "rce_ssti":       ["full_compromise"],
        "full_compromise": [],
    }

    CVSS_WEIGHT = {
        "sqli": 9.8, "xss": 7.5, "ssrf": 9.1, "path_traversal": 7.5,
        "lfi": 8.1, "xxe": 8.2, "idor": 8.6, "open_redirect": 6.1,
        "ssti": 9.8, "jwt_weak": 8.8, "data_exfil": 9.0, "auth_bypass": 9.5,
        "rce_sqli": 10.0, "cloud_metadata": 9.8, "internal_scan": 7.5,
        "rce_ssrf": 10.0, "config_disclosure": 7.0, "rce_lfi": 10.0,
        "session_hijack": 8.0, "credential_theft": 9.0, "priv_esc": 9.5,
        "phishing": 6.0, "oauth_theft": 8.5, "rce_ssti": 10.0,
        "file_read": 7.5, "full_compromise": 10.0,
    }

    def _classify(self, finding):
        text = " ".join([
            str(getattr(finding, "title", "")),
            " ".join(str(t) for t in (getattr(finding, "tags", []) or [])),
        ]).lower()
        for key in self.UNLOCK_MAP:
            if key.replace("_", " ") in text or key in text:
                return key
        return None

    def build_chains(self, findings):
        found_types = {}
        for f in findings:
            vtype = self._classify(f)
            if vtype and vtype not in found_types:
                found_types[vtype] = f

        chains = []

        def dfs(current, path, score, depth):
            if depth > 6:
                return
            unlocks = self.UNLOCK_MAP.get(current, [])
            if not unlocks:
                chains.append({
                    "path": list(path),
                    "score": round(score, 2),
                    "starts_with_confirmed": path[0] in found_types,
                    "ends_with": current,
                })
                return
            for nxt in unlocks:
                new_score = score + self.CVSS_WEIGHT.get(nxt, 5.0) * (0.9 ** depth)
                dfs(nxt, path + [nxt], new_score, depth + 1)

        for vtype in list(found_types.keys()):
            dfs(vtype, [vtype], self.CVSS_WEIGHT.get(vtype, 5.0), 0)

        seen = set()
        unique = []
        for c in sorted(chains, key=lambda x: x["score"], reverse=True):
            key = ">".join(c["path"])
            if key not in seen:
                seen.add(key)
                unique.append(c)
        return unique[:20]


# ─────────────────────────────────────────────────────────────────────────────
# I-14  SHODAN / CENSYS PASSIVE RECON INTEGRATION
# ─────────────────────────────────────────────────────────────────────────────

class PassiveReconEngine:
    """
    Passive reconnaissance via Shodan and Censys APIs.

    Environment variables (set before running):
        SHODAN_API_KEY
        CENSYS_API_ID
        CENSYS_API_SECRET
    """

    def __init__(
        self,
        shodan_api_key="",
        censys_api_id="",
        censys_api_secret="",
        timeout_s=15.0,
    ):
        self._shodan_key = shodan_api_key or os.environ.get("SHODAN_API_KEY", "")
        self._censys_id = censys_api_id or os.environ.get("CENSYS_API_ID", "")
        self._censys_secret = (
            censys_api_secret or os.environ.get("CENSYS_API_SECRET", ""))
        self._timeout = timeout_s

    async def lookup(self, ip):
        results = {"ip": ip, "shodan": {}, "censys": {}}
        tasks = []
        if self._shodan_key:
            tasks.append(("shodan", self._shodan_lookup(ip)))
        if self._censys_id and self._censys_secret:
            tasks.append(("censys", self._censys_lookup(ip)))
        for name, coro in tasks:
            try:
                results[name] = await coro
            except Exception as exc:
                logging.getLogger("webscout").debug(
                    "Passive recon %s error: %s", name, exc)
        return results

    async def _shodan_lookup(self, ip):
        url = "https://api.shodan.io/shodan/host/{}?key={}".format(
            ip, self._shodan_key)
        async with aiohttp.ClientSession() as sess:
            async with sess.get(
                url, timeout=aiohttp.ClientTimeout(total=self._timeout)
            ) as resp:
                if resp.status != 200:
                    return {"error": "HTTP {}".format(resp.status)}
                data = await resp.json()
                return {
                    "ports": data.get("ports", []),
                    "vulns": list(data.get("vulns", {}).keys()),
                    "org": data.get("org", ""),
                    "isp": data.get("isp", ""),
                    "country": data.get("country_name", ""),
                    "os": data.get("os", ""),
                    "hostnames": data.get("hostnames", []),
                    "tags": data.get("tags", []),
                }

    async def _censys_lookup(self, ip):
        creds = base64.b64encode(
            "{}:{}".format(self._censys_id, self._censys_secret).encode()
        ).decode()
        headers = {"Authorization": "Basic {}".format(creds)}
        url = "https://search.censys.io/api/v2/hosts/{}".format(ip)
        async with aiohttp.ClientSession(headers=headers) as sess:
            async with sess.get(
                url, timeout=aiohttp.ClientTimeout(total=self._timeout)
            ) as resp:
                if resp.status != 200:
                    return {"error": "HTTP {}".format(resp.status)}
                data = (await resp.json()).get("result", {})
                services = data.get("services", [])
                return {
                    "ports": [s.get("port") for s in services],
                    "services": [
                        {
                            "port": s.get("port"),
                            "name": s.get("service_name"),
                            "transport": s.get("transport_protocol"),
                        }
                        for s in services
                    ],
                    "autonomous_system": data.get("autonomous_system", {}),
                    "location": data.get("location", {}),
                }

    async def to_findings(self, ip, recon_data):
        findings = []
        for cve in recon_data.get("shodan", {}).get("vulns", []):
            findings.append({
                "plugin": "passive_recon[shodan]",
                "title": "Shodan: Known Vulnerability {} on {}".format(cve, ip),
                "severity": "HIGH", "confidence": 75.0,
                "description": "Shodan reports {} on host {}.".format(cve, ip),
                "evidence": "Shodan vuln: {}".format(cve),
                "url": "https://nvd.nist.gov/vuln/detail/{}".format(cve),
                "tags": ["passive-recon", "shodan", cve.lower()],
            })
        for svc in recon_data.get("censys", {}).get("services", []):
            port = svc.get("port", 0)
            name = svc.get("name", "unknown")
            if port in (21, 23, 3389, 5900):
                findings.append({
                    "plugin": "passive_recon[censys]",
                    "title": "Risky Service Exposed: {} on port {}".format(name, port),
                    "severity": "MEDIUM", "confidence": 85.0,
                    "description": "Censys identifies {} (port {}) on {}.".format(
                        name, port, ip),
                    "evidence": str(svc),
                    "url": "tcp://{}:{}".format(ip, port),
                    "tags": ["passive-recon", "censys", name.lower()],
                })
        return findings


# ─────────────────────────────────────────────────────────────────────────────
# I-15  SWAGGER / OPENAPI SPEC SCANNER
# ─────────────────────────────────────────────────────────────────────────────

class OpenAPISpecScanner:
    """
    Discovers, parses, and fuzzes OpenAPI/Swagger specs.

    Steps:
    1. Probe common spec URLs
    2. Parse spec (OpenAPI 2/3) — extract endpoints, parameters, auth schemes
    3. Fuzz each parameter with basic injection payloads
    4. Report: unauthenticated endpoints, missing auth, sensitive params, injections
    """

    SPEC_PATHS = [
        "/swagger.json", "/swagger.yaml", "/openapi.json", "/openapi.yaml",
        "/api-docs", "/api-docs.json", "/api/swagger.json", "/api/openapi.json",
        "/v1/swagger.json", "/v2/swagger.json", "/v3/openapi.json",
        "/.well-known/openapi.json", "/docs/swagger.json",
    ]

    SENSITIVE_PARAM_NAMES = {
        "password", "passwd", "secret", "token", "api_key", "apikey", "key",
        "auth", "credential", "private_key", "access_token", "refresh_token",
    }

    INJECTION_PAYLOADS = [
        ("sqli", "' OR '1'='1"),
        ("xss",  "<script>alert(1)</script>"),
        ("ssti", "{{7*7}}"),
    ]

    async def scan(self, client, base_url):
        findings = []
        parsed = urlparse(base_url)
        base = "{}://{}".format(parsed.scheme, parsed.netloc)

        spec = await self._discover_spec(client, base)
        if spec is None:
            return findings

        spec_url, spec_data = spec
        findings.append({
            "plugin": "openapi_scanner",
            "title": "OpenAPI/Swagger Spec Publicly Accessible",
            "severity": "MEDIUM", "confidence": 90.0,
            "description": "API spec is publicly accessible — exposes endpoint inventory.",
            "evidence": "Spec URL: {}".format(spec_url),
            "url": spec_url,
            "remediation": "Restrict spec access to authenticated users.",
            "tags": ["api", "openapi", "disclosure"],
        })

        endpoints = self._extract_endpoints(spec_data, base)
        auth_schemes = self._extract_auth(spec_data)

        for ep_url, method, params, requires_auth in endpoints:
            if not requires_auth and auth_schemes:
                findings.append({
                    "plugin": "openapi_scanner",
                    "title": "Unauthenticated API Endpoint: {} {}".format(
                        method, ep_url),
                    "severity": "HIGH", "confidence": 80.0,
                    "description": "Endpoint has no auth requirement in spec.",
                    "evidence": "Schemes defined: {}".format(auth_schemes),
                    "url": ep_url,
                    "tags": ["api", "openapi", "unauthenticated"],
                })

            for param in params:
                pname = (param.get("name") or "").lower()
                if pname in self.SENSITIVE_PARAM_NAMES:
                    findings.append({
                        "plugin": "openapi_scanner",
                        "title": "Sensitive Parameter in Spec: {} @ {}".format(
                            param.get("name"), ep_url),
                        "severity": "MEDIUM", "confidence": 75.0,
                        "description": "Spec documents sensitive parameter '{}'.".format(
                            param.get("name")),
                        "evidence": "Endpoint: {} {} | Param: {}".format(
                            method, ep_url, param),
                        "url": ep_url,
                        "tags": ["api", "openapi", "sensitive-param"],
                    })

            fuzz_results = await self._fuzz_endpoint(client, ep_url, params)
            findings.extend(fuzz_results)

        return findings

    async def _discover_spec(self, client, base):
        for path in self.SPEC_PATHS:
            url = base + path
            r = await client.get(url)
            if not r or r["status"] != 200:
                continue
            try:
                data = json.loads(r["text"])
                if "paths" in data or "swagger" in data or "openapi" in data:
                    return url, data
            except Exception:
                pass
            try:
                import yaml as _yaml  # type: ignore
                data = _yaml.safe_load(r["text"])
                if isinstance(data, dict) and "paths" in data:
                    return url, data
            except Exception:
                pass
        return None

    def _extract_endpoints(self, spec, base):
        endpoints = []
        paths = spec.get("paths", {})
        global_security = bool(spec.get("security"))
        base_path = spec.get("basePath", "")
        servers = spec.get("servers", [])
        server_base = servers[0].get("url", "") if servers else base_path

        for path, path_item in paths.items():
            for method, op in path_item.items():
                if method.upper() not in (
                    "GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"
                ):
                    continue
                params = (
                    list(op.get("parameters", []))
                    + list(path_item.get("parameters", []))
                )
                has_security = bool(op.get("security")) or global_security
                full_url = "{}{}{}".format(base, server_base, path)
                endpoints.append(
                    (full_url, method.upper(), params, has_security))
        return endpoints

    def _extract_auth(self, spec):
        sec_defs = (
            spec.get("securityDefinitions")
            or spec.get("components", {}).get("securitySchemes", {})
            or {}
        )
        return list(sec_defs.keys())

    async def _fuzz_endpoint(self, client, url, params):
        findings = []
        query_params = {
            p["name"]: "test"
            for p in params if p.get("in") == "query"
        }
        if not query_params:
            return findings
        for vuln_type, payload in self.INJECTION_PAYLOADS:
            for pname in list(query_params.keys())[:3]:
                test_params = dict(query_params)
                test_params[pname] = payload
                test_url = url + "?" + urlencode(test_params)
                r = await client.get(test_url)
                if not r:
                    continue
                body = r["text"] or ""
                if vuln_type == "sqli" and re.search(
                    r"sql|mysql|sqlite|syntax error|ORA-", body, re.I
                ):
                    findings.append({
                        "plugin": "openapi_scanner",
                        "title": "OpenAPI Endpoint SQLi Indicator: {}".format(url),
                        "severity": "HIGH", "confidence": 70.0,
                        "description": "SQL error in response for param '{}'.".format(
                            pname),
                        "evidence": body[:300],
                        "url": test_url,
                        "tags": ["api", "openapi", "sqli"],
                    })
                elif vuln_type == "xss" and payload in body:
                    findings.append({
                        "plugin": "openapi_scanner",
                        "title": "OpenAPI Endpoint XSS Reflection: {}".format(url),
                        "severity": "HIGH", "confidence": 80.0,
                        "description": "XSS payload reflected for param '{}'.".format(
                            pname),
                        "evidence": body[:300],
                        "url": test_url,
                        "tags": ["api", "openapi", "xss"],
                    })
                elif vuln_type == "ssti" and "49" in body:
                    findings.append({
                        "plugin": "openapi_scanner",
                        "title": "OpenAPI Endpoint SSTI Indicator: {}".format(url),
                        "severity": "CRITICAL", "confidence": 85.0,
                        "description": "{{7*7}} evaluated to 49 for param '{}'.".format(
                            pname),
                        "evidence": body[:300],
                        "url": test_url,
                        "tags": ["api", "openapi", "ssti"],
                    })
        return findings


# ─────────────────────────────────────────────────────────────────────────────
# I-16  UVLOOP PERFORMANCE DROP-IN
# ─────────────────────────────────────────────────────────────────────────────

def install_uvloop():
    """
    Install uvloop as the asyncio event loop policy if available.
    uvloop is 2-4x faster than the default asyncio loop for I/O-heavy workloads.

    Returns True if installed, False if falling back to default.
    Call before ``asyncio.run()`` in ``main()``::

        install_uvloop()
        asyncio.run(run_webscout(args))
    """
    try:
        import uvloop as _uvloop  # type: ignore
        _uvloop.install()
        logging.getLogger("webscout").info(
            "uvloop installed as asyncio event loop policy")
        return True
    except ImportError:
        logging.getLogger("webscout").debug(
            "uvloop not available (pip install uvloop) "
            "-- using default asyncio event loop")
        return False


# ─────────────────────────────────────────────────────────────────────────────
# I-17  DNS CACHING (IN-PROCESS LRU + OPTIONAL AIODNS)
# ─────────────────────────────────────────────────────────────────────────────

class CachingDNSResolver:
    """
    Async DNS resolver with in-process LRU caching and configurable TTL.

    Uses aiodns if available (async, non-blocking, c-ares backend).
    Falls back to ``asyncio.loop.getaddrinfo()``.
    Thread-safe via asyncio.Lock.
    """

    def __init__(self, cache_size=512, ttl_s=300.0):
        self._cache = {}          # hostname -> ([addrs], timestamp)
        self._cache_size = cache_size
        self._ttl = ttl_s
        self._lock = asyncio.Lock()
        self._aiodns_resolver = None
        self._aiodns_checked = False

    async def _get_aiodns(self):
        if not self._aiodns_checked:
            self._aiodns_checked = True
            try:
                import aiodns as _aiodns  # type: ignore
                self._aiodns_resolver = _aiodns.DNSResolver()
            except ImportError:
                self._aiodns_resolver = None
        return self._aiodns_resolver

    async def resolve(self, hostname):
        now = time.time()
        async with self._lock:
            cached = self._cache.get(hostname)
            if cached and (now - cached[1]) < self._ttl:
                return cached[0]

        addrs = await self._do_resolve(hostname)

        async with self._lock:
            if len(self._cache) >= self._cache_size:
                oldest = min(self._cache.items(), key=lambda x: x[1][1])
                del self._cache[oldest[0]]
            self._cache[hostname] = (addrs, now)

        return addrs

    async def _do_resolve(self, hostname):
        resolver = await self._get_aiodns()
        if resolver is not None:
            try:
                result = await resolver.query(hostname, "A")
                return [r.host for r in result]
            except Exception:
                pass
        loop = asyncio.get_event_loop()
        try:
            info = await loop.getaddrinfo(
                hostname, None, type=socket.SOCK_STREAM)
            return list({item[4][0] for item in info})
        except Exception:
            return []

    def cache_stats(self):
        return {
            "size": len(self._cache),
            "max_size": self._cache_size,
            "ttl_s": self._ttl,
        }


# ─────────────────────────────────────────────────────────────────────────────
# I-18  DYNAMIC RETEST ENGINE (REDUCE FPs BY RETESTING ALL FINDINGS)
# ─────────────────────────────────────────────────────────────────────────────

class DynamicRetestEngine:
    """
    Re-tests every finding with fresh HTTP requests to confirm reproducibility
    and reduce false positives.

    - Replays the exact URL from each finding
    - Checks that the vulnerability indicator is still present
    - Downgrads confidence by 30 if retest fails; removes if below threshold
    """

    def __init__(self, max_retests=2, min_confidence=40.0):
        self._max_retests = max_retests
        self._min_confidence = min_confidence

    async def retest(self, client, findings):
        validated = []
        for finding in findings:
            url = getattr(finding, "url", "") or ""
            if not url.startswith(("http://", "https://")):
                validated.append(finding)
                continue
            confirmed = await self._retest_finding(client, finding)
            if confirmed:
                validated.append(finding)
            else:
                conf = getattr(finding, "confidence", 50.0)
                new_conf = conf - 30.0
                if new_conf >= self._min_confidence:
                    try:
                        finding.confidence = new_conf
                        old_tags = list(getattr(finding, "tags", []) or [])
                        finding.tags = list(
                            set(old_tags + ["retest-uncertain"]))
                    except Exception:
                        pass
                    validated.append(finding)
                else:
                    logging.getLogger("webscout").info(
                        "DynamicRetest: removed low-confidence finding: %s",
                        getattr(finding, "title", str(finding)),
                    )
        return validated

    async def _retest_finding(self, client, finding):
        url = getattr(finding, "url", "")
        evidence = str(getattr(finding, "evidence", "") or "")
        payload = getattr(finding, "payload", "") or ""

        for attempt in range(self._max_retests):
            r = await client.get(url)
            if not r:
                await asyncio.sleep(1.0)
                continue
            body = r.get("text", "") or ""
            status = r.get("status", 0)
            if payload and len(payload) > 3 and payload in body:
                return True
            if status in (500, 503) and "500" in evidence:
                return True
            if status == 200 and len(body) > 100:
                return True
            if attempt < self._max_retests - 1:
                await asyncio.sleep(0.5)
        return False


# ─────────────────────────────────────────────────────────────────────────────
# I-19  BASELINE COMPARISON ENGINE
# ─────────────────────────────────────────────────────────────────────────────

class BaselineComparisonEngine:
    """
    Suppresses findings that appeared in a previous baseline scan, keeping
    only *new* vulnerabilities since the last known-good state.

    Baseline files are JSON arrays of {title, url, severity, fingerprint}.

    Usage::

        engine = BaselineComparisonEngine("baseline_2024_01_01.json")
        new_findings = engine.filter_new(current_findings)
        engine.save_baseline(current_findings, "baseline_2024_06_01.json")
    """

    def __init__(self, baseline_path=""):
        self._baseline = set()
        if baseline_path and Path(baseline_path).exists():
            self._load(baseline_path)

    def _fingerprint(self, f):
        if isinstance(f, dict):
            title = (f.get("title") or "").lower()[:60]
            url = f.get("url") or ""
        else:
            title = (getattr(f, "title", None) or "").lower()[:60]
            url = getattr(f, "url", None) or ""
        path = urlparse(url).path
        return hashlib.sha1(
            "{}:{}".format(title, path).encode()
        ).hexdigest()

    def _load(self, path):
        try:
            with open(path) as fh:
                data = json.load(fh)
            if isinstance(data, list):
                for item in data:
                    self._baseline.add(
                        item.get("fingerprint") or self._fingerprint(item))
            logging.getLogger("webscout").info(
                "Baseline loaded: %d entries from %s",
                len(self._baseline), path,
            )
        except Exception as exc:
            logging.getLogger("webscout").warning(
                "Baseline load error: %s", exc)

    def filter_new(self, findings):
        if not self._baseline:
            return list(findings)
        new = []
        suppressed = 0
        for f in findings:
            fp = self._fingerprint(f)
            if fp in self._baseline:
                suppressed += 1
            else:
                new.append(f)
        logging.getLogger("webscout").info(
            "Baseline: %d total, %d new, %d suppressed",
            len(findings), len(new), suppressed,
        )
        return new

    def save_baseline(self, findings, output_path):
        data = [
            {
                "title": getattr(f, "title", str(f)),
                "url": getattr(f, "url", ""),
                "severity": getattr(f, "severity", ""),
                "fingerprint": self._fingerprint(f),
            }
            for f in findings
        ]
        with open(output_path, "w") as fh:
            json.dump(data, fh, indent=2)
        logging.getLogger("webscout").info(
            "Baseline saved: %d entries -> %s", len(data), output_path)


# ─────────────────────────────────────────────────────────────────────────────
# I-20  CONTENT-TYPE VERIFICATION (POLYGLOT / MISMATCH DETECTION)
# ─────────────────────────────────────────────────────────────────────────────

class ContentTypeMismatchScanner:
    """
    Detects Content-Type mismatches that indicate polyglot files, missing
    MIME-type headers, dangerous Content-Types on upload endpoints, and
    missing X-Content-Type-Options: nosniff.
    """

    EXPECTED_SIGNATURES = {
        "image/jpeg": [b"\xff\xd8\xff"],
        "image/png":  [b"\x89PNG\r\n\x1a\n"],
        "image/gif":  [b"GIF87a", b"GIF89a"],
        "image/webp": [b"RIFF"],
        "application/pdf":  [b"%PDF"],
        "application/zip":  [b"PK\x03\x04"],
        "application/gzip": [b"\x1f\x8b"],
    }

    DANGEROUS_CT = {
        "text/html", "application/xhtml+xml", "text/javascript",
        "application/javascript", "image/svg+xml",
    }

    async def scan(self, client, base_url):
        findings = []
        parsed = urlparse(base_url)
        base = "{}://{}".format(parsed.scheme, parsed.netloc)

        upload_endpoints = [
            "/upload", "/api/upload", "/files/upload",
            "/profile/avatar", "/api/files",
        ]
        for ep in upload_endpoints:
            url = base + ep
            r = await client.get(url)
            if not r or r["status"] not in (200, 405):
                continue
            hdrs = r.get("headers", {}) or {}
            ct = hdrs.get(
                "content-type",
                hdrs.get("Content-Type", ""),
            ).lower().split(";")[0].strip()
            nosniff = hdrs.get(
                "x-content-type-options",
                hdrs.get("X-Content-Type-Options", ""),
            ).lower()

            if ct in self.DANGEROUS_CT:
                findings.append({
                    "plugin": "content_type_mismatch",
                    "title": "Dangerous Content-Type on Upload Endpoint: {}".format(ct),
                    "severity": "HIGH", "confidence": 80.0,
                    "description": (
                        "Upload endpoint returns Content-Type: {} "
                        "which allows script execution.".format(ct)
                    ),
                    "evidence": "URL: {} | Content-Type: {}".format(url, ct),
                    "url": url,
                    "remediation": (
                        "Set Content-Type: application/octet-stream "
                        "for uploaded files."),
                    "tags": ["content-type", "upload", "xss"],
                })

            if nosniff != "nosniff":
                findings.append({
                    "plugin": "content_type_mismatch",
                    "title": "Missing X-Content-Type-Options: {}".format(url),
                    "severity": "LOW", "confidence": 95.0,
                    "description": (
                        "X-Content-Type-Options: nosniff is absent — "
                        "browser may MIME-sniff the response."
                    ),
                    "evidence": (
                        "URL: {} | CT: {} | X-CTO: {}".format(
                            url, ct, nosniff or "absent")
                    ),
                    "url": url,
                    "remediation": (
                        "Add 'X-Content-Type-Options: nosniff' to all responses."),
                    "tags": ["content-type", "mime-sniffing", "header"],
                })

        r = await client.get(base_url)
        if r:
            hdrs = r.get("headers", {}) or {}
            ct = hdrs.get(
                "content-type",
                hdrs.get("Content-Type", ""),
            ).lower()
            body_bytes = (r.get("text", "") or "").encode(errors="replace")[:16]
            for declared_ct, sigs in self.EXPECTED_SIGNATURES.items():
                if declared_ct in ct:
                    if not any(body_bytes.startswith(sig) for sig in sigs):
                        findings.append({
                            "plugin": "content_type_mismatch",
                            "title": "Content-Type Mismatch / Polyglot Indicator",
                            "severity": "MEDIUM", "confidence": 70.0,
                            "description": (
                                "Response declares '{}' but file magic bytes "
                                "do not match — possible polyglot.".format(declared_ct)
                            ),
                            "evidence": (
                                "URL: {} | CT: {} | Magic: {}".format(
                                    base_url, declared_ct, body_bytes.hex()[:12])
                            ),
                            "url": base_url,
                            "tags": ["content-type", "polyglot", "mismatch"],
                        })
                    break

        return findings


# ─────────────────────────────────────────────────────────────────────────────
# I-21  CODE-QUALITY: STRUCTURED LOGGER + CONFIG FACTORY
# ─────────────────────────────────────────────────────────────────────────────

class _V20JsonFormatter(logging.Formatter):
    """JSON log formatter — machine-readable structured output."""

    def format(self, record):
        return json.dumps({
            "ts": self.formatTime(record, "%Y-%m-%dT%H:%M:%S"),
            "level": record.levelname,
            "logger": record.name,
            "msg": record.getMessage(),
        }, ensure_ascii=False)


class WebScoutLogger:
    """
    Structured logger that replaces the global ``log()`` function with a
    proper ``logging.Logger`` hierarchy.

    Supports:
    - JSON-structured output (machine-readable, ``json_output=True``)
    - Plain-text output (human-readable, default)
    - File output with rotation

    Usage::

        ws_log = WebScoutLogger(name="webscout", level="INFO")
        ws_log.info("SCAN", "Starting scan for %s", url)
        ws_log.warning("WAF", "WAF detected: %s", waf_name)
    """

    def __init__(
        self,
        name="webscout",
        level="INFO",
        json_output=False,
        log_file="",
        max_bytes=10 * 1024 * 1024,
        backup_count=3,
    ):
        self._logger = logging.getLogger(name)
        self._logger.setLevel(
            getattr(logging, level.upper(), logging.INFO))

        if not self._logger.handlers:
            if log_file:
                from logging.handlers import RotatingFileHandler as _RFH
                handler = _RFH(
                    log_file, maxBytes=max_bytes, backupCount=backup_count)
            else:
                handler = logging.StreamHandler(sys.stderr)

            handler.setFormatter(
                _V20JsonFormatter()
                if json_output
                else logging.Formatter(
                    fmt="%(asctime)s [%(levelname)-8s] %(message)s",
                    datefmt="%H:%M:%S",
                )
            )
            self._logger.addHandler(handler)

    def _emit(self, level_int, tag, msg, *args):
        full_msg = "[{}] {}".format(tag, msg % args if args else msg)
        self._logger.log(level_int, full_msg)

    def debug(self, tag, msg, *args):
        self._emit(logging.DEBUG, tag, msg, *args)

    def info(self, tag, msg, *args):
        self._emit(logging.INFO, tag, msg, *args)

    def warning(self, tag, msg, *args):
        self._emit(logging.WARNING, tag, msg, *args)

    def error(self, tag, msg, *args):
        self._emit(logging.ERROR, tag, msg, *args)

    def critical(self, tag, msg, *args):
        self._emit(logging.CRITICAL, tag, msg, *args)


def build_v20_config(
    target,
    concurrency=20,
    proxy_list=None,
    enable_llm=False,
    llm_model="llama3",
    baseline_file="",
    output_dir=".",
    json_log=False,
    log_level="INFO",
):
    """
    Factory that returns a unified configuration dict for the v20 layer.
    All v20 components can be initialised from this dict.
    """
    return {
        "target": target,
        "logger": {"name": "webscout", "level": log_level, "json_output": json_log},
        "retest": {"max_retests": 2, "min_confidence": 40.0},
        "baseline": {"baseline_path": baseline_file},
        "llm": {
            "enabled": enable_llm,
            "model": llm_model,
            "base_url": "http://localhost:11434",
        },
        "proxy_rotator": {
            "proxies": proxy_list or [],
            "check_interval_s": 60.0,
        },
        "health_monitor": {
            "check_interval_s": 30.0,
            "max_error_rate": 0.5,
            "max_memory_mb": 2048.0,
            "scan_timeout_s": 3600.0,
        },
        "dns_cache": {"cache_size": 512, "ttl_s": 300.0},
        "output_dir": output_dir,
    }


# ─────────────────────────────────────────────────────────────────────────────
# V20 MAIN INTEGRATION ENTRY POINT
# ─────────────────────────────────────────────────────────────────────────────

async def run_v20_improvements(
    target,
    findings,
    client,
    enable_retest=True,
    enable_baseline=False,
    baseline_path="",
    enable_llm=False,
    llm_model="llama3",
    enable_openapi=True,
    enable_content_type=True,
    enable_passive_recon=False,
    shodan_key="",
    censys_id="",
    censys_secret="",
    save_new_baseline="",
):
    """
    Run all v20 improvement modules on completed scan results.

    Designed to be called after ``run_webscout()`` returns its findings::

        v20 = await run_v20_improvements(
            target="https://example.com",
            findings=scan_findings,
            client=webscout_client,
            enable_retest=True,
        )
        final_findings = v20["findings"]
        attack_chains  = v20["attack_chains"]
        llm_analysis   = v20["llm_analysis"]
    """
    logger = logging.getLogger("webscout")
    report = {
        "findings": list(findings),
        "attack_chains": [],
        "llm_analysis": None,
        "passive_recon": {},
        "openapi_findings": [],
        "content_type_findings": [],
        "baseline_suppressed": 0,
    }

    logger.info("[V20] Starting v20 pass over %d findings", len(findings))

    if enable_baseline and baseline_path:
        bce = BaselineComparisonEngine(baseline_path)
        before = len(report["findings"])
        report["findings"] = bce.filter_new(report["findings"])
        report["baseline_suppressed"] = before - len(report["findings"])
        if save_new_baseline:
            bce.save_baseline(report["findings"], save_new_baseline)

    if enable_retest:
        logger.info("[V20] Retesting %d findings ...", len(report["findings"]))
        rte = DynamicRetestEngine(max_retests=2, min_confidence=40.0)
        report["findings"] = await rte.retest(client, report["findings"])
        logger.info("[V20] After retest: %d confirmed", len(report["findings"]))

    if enable_openapi:
        oa = OpenAPISpecScanner()
        oa_findings = await oa.scan(client, target)
        report["openapi_findings"] = oa_findings
        report["findings"].extend(oa_findings)
        logger.info("[V20] OpenAPI: %d additional findings", len(oa_findings))

    if enable_content_type:
        ct = ContentTypeMismatchScanner()
        ct_findings = await ct.scan(client, target)
        report["content_type_findings"] = ct_findings
        report["findings"].extend(ct_findings)
        logger.info("[V20] Content-Type: %d findings", len(ct_findings))

    if enable_passive_recon and (shodan_key or (censys_id and censys_secret)):
        parsed = urlparse(target)
        host = parsed.hostname or ""
        loop = asyncio.get_event_loop()
        try:
            info = await loop.getaddrinfo(host, None)
            ip = info[0][4][0]
            recon = PassiveReconEngine(
                shodan_api_key=shodan_key,
                censys_api_id=censys_id,
                censys_api_secret=censys_secret,
            )
            recon_data = await recon.lookup(ip)
            report["passive_recon"] = recon_data
            recon_findings = await recon.to_findings(ip, recon_data)
            report["findings"].extend(recon_findings)
            logger.info("[V20] Passive recon: %d findings", len(recon_findings))
        except Exception as exc:
            logger.warning("[V20] Passive recon error: %s", exc)

    sequencer = DynamicAttackChainSequencer()
    report["attack_chains"] = sequencer.build_chains(report["findings"])
    logger.info("[V20] Attack chains: %d built", len(report["attack_chains"]))

    if enable_llm and report["findings"]:
        llm = LLMVulnerabilityAnalyzer(model=llm_model)
        report["llm_analysis"] = await llm.analyze_findings(report["findings"])
        if report["llm_analysis"]:
            logger.info("[V20] LLM analysis complete")
        else:
            logger.info("[V20] LLM unavailable -- skipped")

    logger.info(
        "[V20] Complete: %d final findings, %d chains",
        len(report["findings"]),
        len(report["attack_chains"]),
    )
    return report


def add_v20_argparse_flags(parser):
    """
    Adds v20 flags to an existing argparse.ArgumentParser.

    Call after building the base parser::

        add_v20_argparse_flags(parser)
        args = parser.parse_args()
    """
    g = parser.add_argument_group("WebScout v20 Improvements")
    g.add_argument(
        "--v20-retest", action="store_true", default=True,
        help="[I-18] Retest all findings to reduce false positives (default: on)")
    g.add_argument(
        "--no-v20-retest", dest="v20_retest", action="store_false",
        help="Disable the finding retest pass")
    g.add_argument(
        "--v20-baseline", metavar="FILE", default="",
        help="[I-19] Path to baseline JSON — suppress known findings")
    g.add_argument(
        "--v20-save-baseline", metavar="FILE", default="",
        help="[I-19] Save current findings as new baseline JSON")
    g.add_argument(
        "--v20-llm", action="store_true", default=False,
        help="[I-11] Enable LLM analysis via Ollama or OpenAI")
    g.add_argument(
        "--v20-llm-model", metavar="MODEL", default="llama3",
        help="[I-11] LLM model name (default: llama3)")
    g.add_argument(
        "--v20-openapi", action="store_true", default=True,
        help="[I-15] Enable OpenAPI/Swagger spec scanner (default: on)")
    g.add_argument(
        "--no-v20-openapi", dest="v20_openapi", action="store_false",
        help="Disable OpenAPI scanner")
    g.add_argument(
        "--v20-content-type", action="store_true", default=True,
        help="[I-20] Enable Content-Type mismatch scanner (default: on)")
    g.add_argument(
        "--no-v20-content-type", dest="v20_content_type", action="store_false",
        help="Disable Content-Type mismatch scanner")
    g.add_argument(
        "--v20-shodan-key", metavar="KEY", default="",
        help="[I-14] Shodan API key for passive recon")
    g.add_argument(
        "--v20-censys-id", metavar="ID", default="",
        help="[I-14] Censys API ID for passive recon")
    g.add_argument(
        "--v20-censys-secret", metavar="SECRET", default="",
        help="[I-14] Censys API secret for passive recon")
    g.add_argument(
        "--v20-uvloop", action="store_true", default=False,
        help="[I-16] Install uvloop (pip install uvloop) for faster async I/O")
    g.add_argument(
        "--v20-json-log", action="store_true", default=False,
        help="[I-21] Output structured JSON logs instead of plain text")


