# ════════════════════════════════════════════════════════════════════════
#  FEATURE 1 — RAW HTTP REQUEST EXPORTER (.http format)
# ════════════════════════════════════════════════════════════════════════

class RawHttpExporter:
    """
    Exports findings as raw HTTP requests in the JetBrains/VS Code .http format.
    Each vulnerability gets its own .http file in an output directory.

    Usage::

        exporter = RawHttpExporter(output_dir="http_exports")
        exporter.export_findings(findings, target="https://example.com")
        # Writes:  http_exports/01_sqli_GET_login.http
        #          http_exports/02_xss_GET_search.http  …
    """

    COMMENT_WIDTH = 70

    def __init__(self, output_dir: str = "http_exports"):
        self.output_dir = Path(output_dir)
        self.output_dir.mkdir(parents=True, exist_ok=True)

    # ── helpers ─────────────────────────────────────────────────────────

    @staticmethod
    def _slug(text: str, maxlen: int = 30) -> str:
        """Convert title to filesystem-safe slug."""
        slug = re.sub(r"[^a-zA-Z0-9_\-]", "_", text.lower())
        slug = re.sub(r"_+", "_", slug).strip("_")
        return slug[:maxlen]

    @staticmethod
    def _parse_request_line(raw: str) -> tuple:
        """
        Parse a stored request string like:
            GET /path HTTP/1.1\\nHost: example.com\\n\\nBODY
        Returns (method, path, headers_dict, body).
        """
        lines = raw.splitlines() if raw else []
        if not lines:
            return "GET", "/", {}, ""
        try:
            parts = lines[0].split()
            method = parts[0] if parts else "GET"
            path   = parts[1] if len(parts) > 1 else "/"
        except (IndexError, AttributeError):
            method, path = "GET", "/"

        headers: dict = {}
        body_lines: list = []
        in_body = False
        for line in lines[1:]:
            if not in_body and line == "":
                in_body = True
                continue
            if in_body:
                body_lines.append(line)
            else:
                if ":" in line:
                    k, _, v = line.partition(":")
                    headers[k.strip()] = v.strip()
        body = "\n".join(body_lines)
        return method, path, headers, body

    def _build_http_block(
        self,
        idx: int,
        finding: "Finding",
        target: str,
    ) -> str:
        """Build a single .http file content block for one finding."""
        sep = "#" * self.COMMENT_WIDTH

        # ── header comment ──
        sev   = getattr(finding, "severity",    "INFO")
        cwe   = getattr(finding, "cwe",         "")
        cvss  = getattr(finding, "cvss",        0.0)
        owasp = getattr(finding, "owasp",       "")
        title = getattr(finding, "title",       "Finding")
        desc  = getattr(finding, "description", "")
        rem   = getattr(finding, "remediation", "")
        param = getattr(finding, "param",       "")
        payload_val = getattr(finding, "payload", "")
        raw_req = getattr(finding, "request",   "")

        lines = [
            f"### {sep}",
            f"### [{idx:02d}] {title}",
            f"### Severity   : {sev}",
        ]
        if cwe:
            lines.append(f"### CWE        : {cwe}")
        if cvss:
            lines.append(f"### CVSS       : {cvss}")
        if owasp:
            lines.append(f"### OWASP      : {owasp}")
        if param:
            lines.append(f"### Parameter  : {param}")
        if payload_val:
            lines.append(f"### Payload    : {payload_val}")
        if desc:
            for dl in textwrap.wrap(desc, 66):
                lines.append(f"### Desc       : {dl}")
        if rem:
            for rl in textwrap.wrap(rem, 66):
                lines.append(f"### Fix        : {rl}")
        lines.append(f"### {sep}")
        lines.append("")

        # ── reconstruct request ──
        url = getattr(finding, "url", "") or target

        if raw_req:
            method, path, req_headers, body = self._parse_request_line(raw_req)
            # Prefer stored URL over reconstructed path
            if url and url.startswith("http"):
                request_url = url
            else:
                parsed_t = urlparse(target)
                request_url = urlunparse((
                    parsed_t.scheme, parsed_t.netloc,
                    path, "", "", ""
                ))
        else:
            method  = "GET"
            request_url = url if url.startswith("http") else target
            req_headers = {}
            body    = ""
            # If payload is a JSON body, switch to POST
            if payload_val and payload_val.strip().startswith("{"):
                method = "POST"
                body   = payload_val

        lines.append(f"{method} {request_url}")

        # Standard headers
        parsed_url = urlparse(request_url)
        lines.append(f"Host: {parsed_url.netloc or urlparse(target).netloc}")
        lines.append("User-Agent: WebScout-Ultimate/21.0")
        lines.append("Accept: */*")
        if method in ("POST", "PUT", "PATCH"):
            lines.append("Content-Type: application/json")
        for k, v in req_headers.items():
            if k.lower() not in ("host", "user-agent", "accept", "content-type"):
                lines.append(f"{k}: {v}")

        lines.append("")

        if body:
            lines.append(body)

        lines.append("")
        lines.append("")
        return "\n".join(lines)

    # ── public API ───────────────────────────────────────────────────────

    def export_findings(
        self,
        findings: list,
        target: str = "",
        bundle: bool = True,
    ) -> list:
        """
        Write .http files for each finding.

        Args:
            findings: list of Finding objects.
            target:   base target URL (fallback when finding.url is empty).
            bundle:   if True, also write one combined findings.http file.

        Returns:
            list of written file paths (str).
        """
        written = []
        combined_blocks = []

        for idx, f in enumerate(findings, start=1):
            block = self._build_http_block(idx, f, target)
            combined_blocks.append(block)

            slug     = self._slug(getattr(f, "title", "finding"))
            fname    = f"{idx:03d}_{slug}.http"
            fpath    = self.output_dir / fname
            fpath.write_text(block, encoding="utf-8")
            written.append(str(fpath))

        if bundle and combined_blocks:
            bundle_path = self.output_dir / "all_findings.http"
            bundle_path.write_text(
                "\n".join(combined_blocks), encoding="utf-8"
            )
            written.append(str(bundle_path))
            log("OK", f"[HTTP Export] {len(findings)} .http file(s) → {self.output_dir}/")

        return written

    def export_single(self, finding: "Finding", target: str = "") -> str:
        """Export a single finding and return the file path."""
        block = self._build_http_block(1, finding, target)
        slug  = self._slug(getattr(finding, "title", "finding"))
        fpath = self.output_dir / f"001_{slug}.http"
        fpath.write_text(block, encoding="utf-8")
        return str(fpath)


# ════════════════════════════════════════════════════════════════════════
#  FEATURE 2 — VISUAL RESPONSE DIFF VIEWER (terminal)
# ════════════════════════════════════════════════════════════════════════

class ResponseDiffViewer:
    """
    Side-by-side / unified diff between two HTTP responses.

    Supports:
      • Unified diff (default) with ANSI color highlighting.
      • Side-by-side diff (``mode="side"``) for narrow terminals.
      • HTML diff export (``export_html``).
      • Status-code / header-only diff (``diff_headers``).

    Usage::

        viewer = ResponseDiffViewer()
        viewer.compare(resp_a, resp_b, label_a="Baseline", label_b="Modified")
        viewer.export_html(resp_a, resp_b, path="diff.html")
    """

    # ANSI color codes
    _ADD  = "\033[92m"   # green
    _DEL  = "\033[91m"   # red
    _HDR  = "\033[94m"   # blue
    _SYM  = "\033[93m"   # yellow
    _RST  = "\033[0m"

    def __init__(self, context_lines: int = 3, no_color: bool = False):
        self.context_lines = context_lines
        self.no_color      = no_color

    def _c(self, code: str) -> str:
        return "" if self.no_color else code

    @staticmethod
    def _response_lines(resp) -> list:
        """
        Accept a string, bytes, dict, or aiohttp-like response object and
        return a list of text lines.
        """
        if resp is None:
            return ["<empty response>"]
        if isinstance(resp, (bytes, bytearray)):
            text = resp.decode("utf-8", errors="replace")
        elif isinstance(resp, str):
            text = resp
        elif isinstance(resp, dict):
            text = json.dumps(resp, indent=2, ensure_ascii=False)
        else:
            # Try to coerce using str()
            text = str(resp)
        return text.splitlines(keepends=True)

    def compare(
        self,
        resp_a,
        resp_b,
        label_a: str = "Response A",
        label_b: str = "Response B",
        mode: str = "unified",
    ) -> str:
        """
        Print and return a colored diff between two responses.

        Args:
            resp_a / resp_b:  response bodies (str / bytes / dict).
            label_a / label_b: labels shown in the diff header.
            mode: ``"unified"`` (default) or ``"side"``.

        Returns:
            The plain-text diff string (no ANSI codes).
        """
        lines_a = self._response_lines(resp_a)
        lines_b = self._response_lines(resp_b)

        if mode == "side":
            return self._side_by_side(lines_a, lines_b, label_a, label_b)
        return self._unified(lines_a, lines_b, label_a, label_b)

    def _unified(self, lines_a, lines_b, label_a, label_b) -> str:
        diff = list(difflib.unified_diff(
            lines_a, lines_b,
            fromfile=label_a, tofile=label_b,
            n=self.context_lines,
        ))
        plain_parts = []
        for line in diff:
            stripped = line.rstrip("\n")
            if stripped.startswith("+++") or stripped.startswith("---"):
                print(f"{self._c(self._HDR)}{stripped}{self._c(self._RST)}")
            elif stripped.startswith("@@"):
                print(f"{self._c(self._SYM)}{stripped}{self._c(self._RST)}")
            elif stripped.startswith("+"):
                print(f"{self._c(self._ADD)}{stripped}{self._c(self._RST)}")
            elif stripped.startswith("-"):
                print(f"{self._c(self._DEL)}{stripped}{self._c(self._RST)}")
            else:
                print(stripped)
            plain_parts.append(stripped)
        if not diff:
            print(f"{self._c(self._ADD)}[Diff] Responses are identical.{self._c(self._RST)}")
        return "\n".join(plain_parts)

    def _side_by_side(self, lines_a, lines_b, label_a, label_b, width: int = 80) -> str:
        half = max(10, (width - 3) // 2)
        header = f"{label_a:<{half}} | {label_b}"
        sep    = "-" * width
        print(f"{self._c(self._HDR)}{header}{self._c(self._RST)}")
        print(sep)

        result_lines = [header, sep]
        max_len = max(len(lines_a), len(lines_b))
        for i in range(max_len):
            la = lines_a[i].rstrip("\n") if i < len(lines_a) else ""
            lb = lines_b[i].rstrip("\n") if i < len(lines_b) else ""
            left  = la[:half].ljust(half)
            right = lb[:half]
            if la != lb:
                row = f"{self._c(self._DEL)}{left}{self._c(self._RST)} | {self._c(self._ADD)}{right}{self._c(self._RST)}"
            else:
                row = f"{left} | {right}"
            print(row)
            result_lines.append(f"{left} | {right}")
        return "\n".join(result_lines)

    def diff_headers(
        self,
        headers_a: dict,
        headers_b: dict,
        label_a: str = "Baseline",
        label_b: str = "Modified",
    ) -> None:
        """Print a diff of two header dictionaries."""
        def hdr_lines(d):
            return [f"{k}: {v}\n" for k, v in sorted(d.items())]

        self._unified(hdr_lines(headers_a), hdr_lines(headers_b), label_a, label_b)

    def export_html(
        self,
        resp_a,
        resp_b,
        label_a: str = "Baseline",
        label_b: str = "Modified",
        path: str = "diff.html",
    ) -> str:
        """Write an HTML side-by-side diff and return the file path."""
        lines_a = self._response_lines(resp_a)
        lines_b = self._response_lines(resp_b)
        differ  = difflib.HtmlDiff(wrapcolumn=100)
        html    = differ.make_file(
            lines_a, lines_b,
            fromdesc=label_a, todesc=label_b,
            context=True, numlines=self.context_lines,
        )
        Path(path).write_text(html, encoding="utf-8")
        log("OK", f"[Diff] HTML diff saved → {path}")
        return path

    def compare_findings(
        self,
        finding_a: "Finding",
        finding_b: "Finding",
    ) -> None:
        """Diff the response bodies of two Finding objects."""
        ra = getattr(finding_a, "response", "") or ""
        rb = getattr(finding_b, "response", "") or ""
        ta = getattr(finding_a, "title", "Finding A")
        tb = getattr(finding_b, "title", "Finding B")
        print(f"\n{'═'*60}")
        print(f"  DIFF: {ta}  ↔  {tb}")
        print(f"{'═'*60}")
        self.compare(ra, rb, label_a=ta, label_b=tb)
        print()


# ════════════════════════════════════════════════════════════════════════
#  FEATURE 3 — INTERACTIVE COMMAND SHELL DURING SCAN
# ════════════════════════════════════════════════════════════════════════

class InteractiveScanShell:
    """
    A non-blocking interactive command shell that runs in a background
    thread and lets the operator issue commands while the scan is running.

    Supported commands::

        status          — show live finding counts
        pause           — pause new scans
        resume          — resume scanning
        findings        — list current findings
        export          — dump findings to JSON now
        skip <module>   — mark a module as skipped
        stop            — graceful stop (finish current, exit)
        help            — this help
        quit / exit     — alias for stop

    Usage::

        shell = InteractiveScanShell()
        shell.start()
        # … scanning …
        shell.stop()
        findings = shell.get_findings()
    """

    _COMMANDS = [
        "status", "pause", "resume", "findings", "export",
        "skip", "stop", "help", "quit", "exit",
    ]

    def __init__(self):
        self._findings: list       = []
        self._lock                 = threading.Lock()
        self._paused               = threading.Event()
        self._stopped              = threading.Event()
        self._skipped_modules: set = set()
        self._cmd_queue: "queue.Queue[str]" = queue.Queue()
        self._thread: Optional[threading.Thread] = None
        self._paused.clear()   # not paused initially

    # ── public control API ───────────────────────────────────────────────

    def start(self):
        """Start the interactive shell thread."""
        self._thread = threading.Thread(
            target=self._shell_loop, name="ws-interactive", daemon=True
        )
        self._thread.start()
        log("INFO", "[Shell] Interactive command shell started (type 'help' for commands)")

    def stop(self):
        """Signal the shell to stop."""
        self._stopped.set()
        if self._thread and self._thread.is_alive():
            self._thread.join(timeout=2)

    def add_finding(self, f: "Finding"):
        """Called by scan modules to register a new finding."""
        with self._lock:
            self._findings.append(f)

    def add_findings(self, fs: list):
        with self._lock:
            self._findings.extend(fs)

    def is_paused(self) -> bool:
        return self._paused.is_set()

    def is_stopped(self) -> bool:
        return self._stopped.is_set()

    def is_skipped(self, module: str) -> bool:
        return module.lower() in self._skipped_modules

    def get_findings(self) -> list:
        with self._lock:
            return list(self._findings)

    # ── internal shell loop ───────────────────────────────────────────────

    def _setup_readline(self):
        try:
            readline.set_completer(rlcompleter.Completer(
                {cmd: None for cmd in self._COMMANDS}
            ).complete)
            readline.parse_and_bind("tab: complete")
        except Exception:
            pass

    def _shell_loop(self):
        self._setup_readline()
        while not self._stopped.is_set():
            try:
                # Non-blocking check for input availability (Unix)
                r, _, _ = select.select([sys.stdin], [], [], 0.3)
                if not r:
                    continue
                try:
                    line = sys.stdin.readline()
                except EOFError:
                    break
                if not line:
                    break
                cmd = line.strip()
                if cmd:
                    self._dispatch(cmd)
            except KeyboardInterrupt:
                print("\n[Shell] KeyboardInterrupt — type 'stop' to exit gracefully.")
            except Exception:
                pass

    def _dispatch(self, raw: str):
        parts = raw.split(None, 1)
        cmd   = parts[0].lower() if parts else ""
        arg   = parts[1].strip() if len(parts) > 1 else ""

        if cmd == "status":
            with self._lock:
                cnt = len(self._findings)
            paused = "PAUSED" if self._paused.is_set() else "RUNNING"
            print(f"  [Shell] Status: {paused} | Findings so far: {cnt}")

        elif cmd == "pause":
            self._paused.set()
            print("  [Shell] Scan PAUSED — type 'resume' to continue")

        elif cmd == "resume":
            self._paused.clear()
            print("  [Shell] Scan RESUMED")

        elif cmd == "findings":
            with self._lock:
                fs = list(self._findings)
            if not fs:
                print("  [Shell] No findings yet.")
            else:
                for i, f in enumerate(fs, 1):
                    sev = getattr(f, "severity", "?")
                    ttl = getattr(f, "title",    "?")
                    url = getattr(f, "url",      "?")
                    print(f"  [{i:03d}] [{sev:<8}] {ttl} — {url}")

        elif cmd == "export":
            with self._lock:
                fs = list(self._findings)
            ts   = datetime.now().strftime("%Y%m%d_%H%M%S")
            path = Path(f"live_export_{ts}.json")
            try:
                data = []
                for f in fs:
                    try:
                        data.append(asdict(f))
                    except Exception:
                        data.append({"title": str(getattr(f, "title", "?"))})
                path.write_text(json.dumps(data, indent=2, default=str), encoding="utf-8")
                print(f"  [Shell] Exported {len(fs)} finding(s) → {path}")
            except Exception as exc:
                print(f"  [Shell] Export error: {exc}")

        elif cmd == "skip":
            if arg:
                self._skipped_modules.add(arg.lower())
                print(f"  [Shell] Module '{arg}' marked as SKIPPED")
            else:
                print("  [Shell] Usage: skip <module_name>")

        elif cmd in ("stop", "quit", "exit"):
            print("  [Shell] Stopping scan...")
            self._stopped.set()

        elif cmd == "help":
            print(textwrap.dedent("""
              Interactive Scan Shell Commands:
                status           — show live status and finding count
                pause            — pause scan (finish current request)
                resume           — resume paused scan
                findings         — list all findings found so far
                export           — save current findings to JSON
                skip <module>    — skip a specific module by name
                stop / quit      — graceful stop
                help             — show this help
            """))
        else:
            print(f"  [Shell] Unknown command: '{cmd}' (type 'help')")


# ════════════════════════════════════════════════════════════════════════
#  FEATURE 4 — EXTERNAL PROXY ROUTING ENGINE
# ════════════════════════════════════════════════════════════════════════

class ExternalProxyRouter:
    """
    Routes ALL tool traffic through a configurable external proxy.

    Supports:
      • Single proxy (``--proxy http://127.0.0.1:8080``)
      • Proxy rotation from a list with health checks
      • Per-protocol override (HTTP proxy vs HTTPS CONNECT)
      • Environment variable injection for subprocess tools

    Usage::

        router = ExternalProxyRouter(proxy="http://127.0.0.1:8080")
        session_kwargs = router.aiohttp_kwargs()
        env = router.subprocess_env()
    """

    def __init__(
        self,
        proxy: str = "",
        proxy_list: Optional[List[str]] = None,
        rotate: bool = False,
        verify_ssl: bool = True,
    ):
        self.proxy       = proxy.strip() if proxy else ""
        self.proxy_list  = [p.strip() for p in (proxy_list or []) if p.strip()]
        self.rotate      = rotate
        self.verify_ssl  = verify_ssl
        self._idx        = 0
        self._lock       = threading.Lock()
        self._banned: set = set()

    # ── proxy selection ──────────────────────────────────────────────────

    def current_proxy(self) -> str:
        """Return the current proxy URL, rotating if enabled."""
        if self.rotate and self.proxy_list:
            active = [p for p in self.proxy_list if p not in self._banned]
            if not active:
                log("WARN", "[ProxyRouter] All proxies banned — no proxy in use")
                return ""
            with self._lock:
                proxy = active[self._idx % len(active)]
                self._idx += 1
            return proxy
        if self.proxy:
            return self.proxy
        if self.proxy_list:
            return self.proxy_list[0]
        return ""

    def ban_proxy(self, proxy_url: str):
        """Mark a proxy as failed so it is skipped in rotation."""
        self._banned.add(proxy_url)
        log("WARN", f"[ProxyRouter] Proxy banned: {proxy_url}")

    def proxy_ok(self, proxy_url: str) -> bool:
        """Quick TCP reachability check for a proxy."""
        try:
            parsed = urlparse(proxy_url)
            host   = parsed.hostname or "127.0.0.1"
            port   = parsed.port    or 8080
            with socket.create_connection((host, port), timeout=4):
                return True
        except OSError:
            return False

    # ── integration helpers ──────────────────────────────────────────────

    def aiohttp_kwargs(self) -> dict:
        """
        Return keyword arguments for aiohttp.ClientSession or
        curl_cffi AsyncSession that route through the proxy.
        """
        proxy = self.current_proxy()
        kw: dict = {}
        if proxy:
            kw["proxy"] = proxy
        if not self.verify_ssl:
            kw["ssl"] = False
        return kw

    def requests_proxies(self) -> dict:
        """Return a proxies dict for the ``requests`` library."""
        proxy = self.current_proxy()
        if proxy:
            return {"http": proxy, "https": proxy}
        return {}

    def subprocess_env(self) -> dict:
        """
        Return an environment dict with HTTP_PROXY / HTTPS_PROXY set
        (for subprocess tools like curl, sqlmap, nmap-scripts).
        """
        env   = dict(os.environ)
        proxy = self.current_proxy()
        if proxy:
            env["http_proxy"]  = proxy
            env["https_proxy"] = proxy
            env["HTTP_PROXY"]  = proxy
            env["HTTPS_PROXY"] = proxy
            env["ALL_PROXY"]   = proxy
        return env

    def inject_into_config(self, cfg: "ScanConfig"):
        """
        Inject proxy settings into a ScanConfig object so all
        WebScout HTTP calls use the configured proxy.
        """
        proxy = self.current_proxy()
        if proxy:
            cfg.proxy = proxy
            log("INFO", f"[ProxyRouter] All traffic → {proxy}")

    def health_check_all(self) -> dict:
        """
        Check reachability of every proxy in the list.
        Returns {proxy_url: True/False}.
        """
        results: dict = {}
        for p in self.proxy_list:
            ok = self.proxy_ok(p)
            results[p] = ok
            if not ok:
                self._banned.add(p)
        alive = sum(1 for v in results.values() if v)
        log("INFO", f"[ProxyRouter] Health check: {alive}/{len(results)} proxies alive")
        return results

    def __repr__(self) -> str:
        return (
            f"ExternalProxyRouter(proxy={self.proxy!r}, "
            f"rotate={self.rotate}, "
            f"active_list={len(self.proxy_list)}, "
            f"banned={len(self._banned)})"
        )


# ════════════════════════════════════════════════════════════════════════
#  FEATURE 5 — TERMINAL REPEATER INTERFACE
# ════════════════════════════════════════════════════════════════════════

class TerminalRepeater:
    """
    Interactive terminal-based HTTP request repeater — similar to
    Burp Suite's Repeater tab but for the CLI.

    Allows the operator to:
      • Load a Finding or raw request
      • Modify method / URL / headers / body inline
      • Replay the request repeatedly
      • Diff successive responses
      • Save modified request back as a .http file

    Usage::

        repeater = TerminalRepeater(proxy="http://127.0.0.1:8080")
        await repeater.run()          # interactive loop
        await repeater.load_finding(finding)
        await repeater.send()
    """

    _HELP = textwrap.dedent("""
        ┌─────────────────────────────────────────────────────────────┐
        │                WebScout Terminal Repeater                   │
        ├─────────────────────────────────────────────────────────────┤
        │  load <url>          — load URL (GET by default)            │
        │  method <METHOD>     — change HTTP method                   │
        │  header <K> <V>      — set request header                   │
        │  del-header <K>      — remove header                        │
        │  body <json-or-text> — set request body                     │
        │  param <K>=<V>       — add/update query parameter           │
        │  send / s            — send the request                     │
        │  diff                — diff last two responses              │
        │  show                — print current request                │
        │  save [file.http]    — save request as .http file           │
        │  history             — show response history                │
        │  clear               — reset to blank request               │
        │  quit / exit         — leave repeater                       │
        │  help                — this help                            │
        └─────────────────────────────────────────────────────────────┘
    """)

    def __init__(
        self,
        proxy: str = "",
        timeout: int = 30,
        verify_ssl: bool = True,
        no_color: bool = False,
    ):
        self.proxy      = proxy
        self.timeout    = timeout
        self.verify_ssl = verify_ssl
        self.diff_viewer = ResponseDiffViewer(no_color=no_color)

        # Current request state
        self._url      = ""
        self._method   = "GET"
        self._headers: dict = {
            "User-Agent": "WebScout-Repeater/21.0",
            "Accept":     "*/*",
        }
        self._body     = ""
        self._params: dict = {}

        # History
        self._history: list = []   # list of (request_repr, status, body)

    # ── request building ─────────────────────────────────────────────────

    def _build_url(self) -> str:
        if not self._params:
            return self._url
        sep = "&" if "?" in self._url else "?"
        return self._url + sep + urlencode(self._params)

    def _show_request(self):
        url = self._build_url()
        print(f"\n  {c(C.CYAN)}{'─'*55}{c(C.RESET)}")
        print(f"  {c(C.BOLD)}{self._method} {url}{c(C.RESET)}")
        for k, v in self._headers.items():
            print(f"  {c(C.DIM)}{k}: {v}{c(C.RESET)}")
        if self._body:
            print(f"\n  {c(C.YELLOW)}{self._body[:200]}{c(C.RESET)}")
        print(f"  {c(C.CYAN)}{'─'*55}{c(C.RESET)}\n")

    # ── HTTP send ────────────────────────────────────────────────────────

    async def send(self) -> Optional[tuple]:
        """Send the current request. Returns (status, headers, body) or None."""
        if not self._url:
            print("  [Repeater] No URL loaded — use 'load <url>'")
            return None

        url = self._build_url()
        req_repr = f"{self._method} {url}"
        print(f"  {c(C.BLUE)}→ Sending: {req_repr}{c(C.RESET)}")

        proxy_arg = {"proxy": self.proxy} if self.proxy else {}

        try:
            async with aiohttp.ClientSession() as session:
                body_kw: dict = {}
                if self._body:
                    body_kw["data"] = self._body.encode("utf-8")
                resp = await session.request(
                    self._method, url,
                    headers=self._headers,
                    ssl=False if not self.verify_ssl else None,
                    timeout=aiohttp.ClientTimeout(total=self.timeout),
                    **proxy_arg,
                    **body_kw,
                )
                resp_body = await resp.text(errors="replace")
                status    = resp.status
                resp_hdrs = dict(resp.headers)

            # Print response summary
            color = c(C.GREEN) if status < 400 else c(C.RED)
            print(f"  {color}← {status} ({len(resp_body)} bytes){c(C.RESET)}")
            print(f"  {c(C.DIM)}{resp_body[:500]}{c(C.RESET)}\n")

            # Store in history
            self._history.append((req_repr, status, resp_body, resp_hdrs))

            return status, resp_hdrs, resp_body

        except Exception as exc:
            print(f"  {c(C.RED)}[Repeater] Error: {exc}{c(C.RESET)}")
            return None

    def load_finding(self, finding: "Finding"):
        """Pre-load a Finding into the repeater."""
        url = getattr(finding, "url", "")
        if url:
            self._url    = url
            self._method = "GET"
        raw_req = getattr(finding, "request", "")
        if raw_req:
            exporter = RawHttpExporter.__new__(RawHttpExporter)
            m, p, h, b = exporter._parse_request_line(raw_req)
            self._method  = m
            self._headers.update(h)
            self._body    = b
        log("INFO", f"[Repeater] Loaded: {self._method} {self._url}")

    # ── interactive loop ─────────────────────────────────────────────────

    async def run(self):
        """Start the interactive repeater REPL."""
        print(self._HELP)
        loop = asyncio.get_event_loop()

        while True:
            try:
                raw = await loop.run_in_executor(
                    None,
                    lambda: input(f"{c(C.MAGENTA)}repeater> {c(C.RESET)}")
                )
            except (EOFError, KeyboardInterrupt):
                print("\n  [Repeater] Exiting.")
                break

            parts = raw.strip().split(None, 2)
            if not parts:
                continue
            cmd = parts[0].lower()

            if cmd in ("quit", "exit"):
                break

            elif cmd == "help":
                print(self._HELP)

            elif cmd == "load" and len(parts) >= 2:
                self._url = parts[1]
                self._method = "GET"
                print(f"  [Repeater] Loaded: {self._url}")

            elif cmd == "method" and len(parts) >= 2:
                self._method = parts[1].upper()
                print(f"  [Repeater] Method: {self._method}")

            elif cmd == "header" and len(parts) >= 3:
                self._headers[parts[1]] = parts[2]
                print(f"  [Repeater] Header set: {parts[1]}: {parts[2]}")

            elif cmd == "del-header" and len(parts) >= 2:
                removed = self._headers.pop(parts[1], None)
                if removed is not None:
                    print(f"  [Repeater] Header removed: {parts[1]}")
                else:
                    print(f"  [Repeater] Header not found: {parts[1]}")

            elif cmd == "body" and len(parts) >= 2:
                self._body = raw.split(None, 1)[1] if len(parts) > 1 else ""
                print(f"  [Repeater] Body set ({len(self._body)} chars)")

            elif cmd == "param" and len(parts) >= 2:
                kv = parts[1]
                if "=" in kv:
                    k, _, v = kv.partition("=")
                    self._params[k] = v
                    print(f"  [Repeater] Param set: {k}={v}")
                else:
                    print("  [Repeater] Format: param key=value")

            elif cmd in ("send", "s"):
                await self.send()

            elif cmd == "diff":
                if len(self._history) < 2:
                    print("  [Repeater] Need at least 2 responses in history.")
                else:
                    _, _, body_prev, _ = self._history[-2]
                    _, _, body_last, _ = self._history[-1]
                    self.diff_viewer.compare(
                        body_prev, body_last,
                        label_a=f"Response #{len(self._history)-1}",
                        label_b=f"Response #{len(self._history)}",
                    )

            elif cmd == "show":
                self._show_request()

            elif cmd == "save":
                fname = parts[1] if len(parts) >= 2 else "repeater_request.http"
                # Build a minimal Finding to reuse exporter
                fake = Finding(
                    plugin="repeater", title="Repeater Request",
                    severity="INFO", description="Saved from Terminal Repeater",
                    url=self._url, request=f"{self._method} {self._url} HTTP/1.1\n" +
                    "\n".join(f"{k}: {v}" for k, v in self._headers.items()) +
                    "\n\n" + self._body,
                )
                exporter = RawHttpExporter(output_dir=str(Path(fname).parent or "."))
                exporter.export_single(fake, target=self._url)
                print(f"  [Repeater] Saved → {fname}")

            elif cmd == "history":
                if not self._history:
                    print("  [Repeater] No history yet.")
                else:
                    for i, (req, status, body, _) in enumerate(self._history, 1):
                        print(f"  [{i}] {status} — {req} ({len(body)}B)")

            elif cmd == "clear":
                self._url    = ""
                self._method = "GET"
                self._headers = {
                    "User-Agent": "WebScout-Repeater/21.0",
                    "Accept":     "*/*",
                }
                self._body   = ""
                self._params = {}
                print("  [Repeater] Reset.")

            else:
                print(f"  [Repeater] Unknown: '{cmd}' — type 'help'")


# ════════════════════════════════════════════════════════════════════════
#  FEATURE 6 — INTERCEPTING PROXY MODE (mitmproxy-style)
# ════════════════════════════════════════════════════════════════════════

class InterceptingProxy:
    """
    A lightweight HTTP/HTTPS CONNECT intercepting proxy.

    Listens on ``127.0.0.1:<port>`` and:
      • Logs all request/response pairs.
      • Stores them as Finding objects for the scanner.
      • Optionally modifies requests on-the-fly via a hook function.
      • Supports HTTPS via CONNECT tunneling.
      • Forwards intercepted requests to an upstream proxy if configured.

    Usage::

        proxy = InterceptingProxy(port=8888, upstream_proxy="")
        proxy.start()
        # … configure browser to use 127.0.0.1:8888 …
        findings = proxy.get_captured_findings()
        proxy.stop()
    """

    class _Handler(http.server.BaseHTTPRequestHandler):
        """Inner handler — one per connection."""

        def log_message(self, fmt, *args):
            pass  # Suppress default access log; we do our own

        def _send_error_response(self, code: int, msg: str):
            try:
                self.send_response(code)
                self.end_headers()
                self.wfile.write(msg.encode())
            except Exception:
                pass

        def do_CONNECT(self):
            """Handle HTTPS CONNECT tunneling."""
            try:
                host_port = self.path
                host, _, port_str = host_port.rpartition(":")
                port = int(port_str) if port_str.isdigit() else 443

                # Open tunnel to target
                try:
                    remote = socket.create_connection((host, port), timeout=10)
                except OSError as e:
                    self._send_error_response(502, f"Cannot connect: {e}")
                    return

                # Tell client tunnel is established
                self.send_response(200, "Connection Established")
                self.end_headers()

                # Relay bytes bidirectionally
                self.server._proxy_instance._tunnel(
                    self.connection, remote, host, port
                )
            except Exception as exc:
                logger_v21.debug("CONNECT error: %s", exc)

        def do_GET(self): self._handle_method()
        def do_POST(self): self._handle_method()
        def do_PUT(self): self._handle_method()
        def do_DELETE(self): self._handle_method()
        def do_PATCH(self): self._handle_method()
        def do_HEAD(self): self._handle_method()
        def do_OPTIONS(self): self._handle_method()

        def _handle_method(self):
            proxy_inst = self.server._proxy_instance
            method  = self.command
            url     = self.path
            headers = dict(self.headers)
            length  = int(headers.get("Content-Length", 0) or 0)
            body    = self.rfile.read(length) if length else b""

            # Hook: allow modification
            if proxy_inst.request_hook:
                try:
                    method, url, headers, body = proxy_inst.request_hook(
                        method, url, headers, body
                    )
                except Exception:
                    pass

            # Log + capture
            req_repr = f"{method} {url} HTTP/1.1\n"
            req_repr += "\n".join(f"{k}: {v}" for k, v in headers.items())
            req_repr += f"\n\n{body.decode('utf-8', errors='replace')}"

            proxy_inst._log_request(method, url, headers, body, req_repr)

            # Forward
            try:
                parsed  = urlparse(url)
                scheme  = parsed.scheme or "http"
                host    = parsed.netloc
                path    = parsed.path or "/"
                if parsed.query:
                    path += "?" + parsed.query

                import http.client as _http_client
                conn_cls = (
                    _http_client.HTTPSConnection
                    if scheme == "https"
                    else _http_client.HTTPConnection
                )
                conn = conn_cls(host, timeout=15)
                conn.request(method, path, body=body, headers=headers)
                resp = conn.getresponse()
                resp_body = resp.read()

                # Record finding
                proxy_inst._capture_finding(
                    method, url, headers, body,
                    resp.status, dict(resp.getheaders()), resp_body
                )

                self.send_response(resp.status)
                for k, v in resp.getheaders():
                    if k.lower() not in ("transfer-encoding",):
                        self.send_header(k, v)
                self.end_headers()
                self.wfile.write(resp_body)
                conn.close()

            except Exception as exc:
                self._send_error_response(502, f"Proxy error: {exc}")

    def __init__(
        self,
        host: str = "127.0.0.1",
        port: int = 8888,
        upstream_proxy: str = "",
        request_hook=None,
    ):
        self.host           = host
        self.port           = port
        self.upstream_proxy = upstream_proxy
        self.request_hook   = request_hook  # callable(method, url, hdrs, body) → (m,u,h,b)

        self._captured_requests: list  = []
        self._captured_findings: list  = []
        self._lock                     = threading.Lock()
        self._server: Optional[socketserver.TCPServer] = None
        self._thread: Optional[threading.Thread]       = None

    # ── internal helpers ─────────────────────────────────────────────────

    @staticmethod
    def _tunnel(client_sock, remote_sock, host: str, port: int):
        """Relay bytes between client and remote until one side closes."""
        socks = [client_sock, remote_sock]
        try:
            while True:
                readable, _, errored = select.select(socks, [], socks, 5)
                if errored:
                    break
                for s in readable:
                    data = s.recv(65536)
                    if not data:
                        return
                    other = remote_sock if s is client_sock else client_sock
                    try:
                        other.sendall(data)
                    except OSError:
                        return
        except Exception:
            pass
        finally:
            for s in (client_sock, remote_sock):
                try:
                    s.close()
                except Exception:
                    pass

    def _log_request(self, method, url, headers, body, raw):
        entry = {
            "method":    method,
            "url":       url,
            "headers":   headers,
            "body":      body.decode("utf-8", errors="replace"),
            "timestamp": datetime.now().isoformat(),
            "raw":       raw,
        }
        with self._lock:
            self._captured_requests.append(entry)
        log("INFO", f"[Proxy] {method} {url}")

    def _capture_finding(self, method, url, req_hdrs, req_body,
                         status, resp_hdrs, resp_body):
        # Create a Finding for each intercepted request
        severity = "INFO"
        if status >= 500:
            severity = "HIGH"
        elif status in (401, 403):
            severity = "MEDIUM"

        f = Finding(
            plugin="intercepting-proxy",
            title=f"[Proxy] {method} {url} → {status}",
            severity=severity,
            description=f"Intercepted via mitmproxy-mode. Status: {status}",
            evidence=f"Request: {method} {url} | Response: {status} ({len(resp_body)}B)",
            url=url,
            request=(
                f"{method} {url} HTTP/1.1\n"
                + "\n".join(f"{k}: {v}" for k, v in req_hdrs.items())
                + f"\n\n{req_body.decode('utf-8', errors='replace')}"
            ),
            response=resp_body.decode("utf-8", errors="replace")[:2000],
            tags=["proxy", "intercepted", method.lower()],
        )
        with self._lock:
            self._captured_findings.append(f)

    # ── public API ───────────────────────────────────────────────────────

    def start(self):
        """Start the proxy in a background thread."""
        class _Server(socketserver.ThreadingTCPServer):
            allow_reuse_address = True
            daemon_threads      = True

        server = _Server((self.host, self.port), self._Handler)
        server._proxy_instance = self
        self._server = server

        self._thread = threading.Thread(
            target=server.serve_forever, name="ws-proxy", daemon=True
        )
        self._thread.start()
        log("OK", f"[Proxy] Intercepting proxy listening on {self.host}:{self.port}")
        print(f"  Configure your browser/tool to use proxy: {self.host}:{self.port}")

    def stop(self):
        """Stop the proxy server."""
        if self._server:
            self._server.shutdown()
            self._server = None
        log("INFO", "[Proxy] Intercepting proxy stopped")

    def get_captured_requests(self) -> list:
        with self._lock:
            return list(self._captured_requests)

    def get_captured_findings(self) -> list:
        with self._lock:
            return list(self._captured_findings)

    def save_traffic(self, path: str = "intercepted_traffic.json"):
        with self._lock:
            data = list(self._captured_requests)
        Path(path).write_text(
            json.dumps(data, indent=2, default=str), encoding="utf-8"
        )
        log("OK", f"[Proxy] Traffic saved → {path} ({len(data)} requests)")

    def export_http_files(self, output_dir: str = "proxy_exports") -> list:
        """Export all intercepted requests as .http files."""
        findings = self.get_captured_findings()
        exporter = RawHttpExporter(output_dir=output_dir)
        return exporter.export_findings(findings)

    def __repr__(self) -> str:
        n = len(self._captured_requests)
        return f"InterceptingProxy({self.host}:{self.port}, captured={n})"


# ════════════════════════════════════════════════════════════════════════
#  FEATURE 7 — LIVE BROWSER SCANNER (Playwright / Headless)
# ════════════════════════════════════════════════════════════════════════

class LiveBrowserScanner:
    """
    Headless Chromium scanner using Playwright.

    Capabilities:
      • Render JavaScript-heavy pages and extract DOM content.
      • Capture all network requests/responses during page load.
      • Detect client-side XSS sinks (innerHTML, document.write, eval …).
      • Screenshot each scan step.
      • Detect CORS misconfigurations via fetch() calls in browser.
      • Crawl same-domain links up to a configurable depth.
      • Detect DOM-based open redirects.

    Usage::

        scanner = LiveBrowserScanner(proxy="http://127.0.0.1:8080")
        findings = await scanner.scan("https://example.com", depth=2)
    """

    XSS_SINKS = [
        "innerHTML", "outerHTML", "document.write", "document.writeln",
        "eval(", "setTimeout(", "setInterval(", "Function(",
        "insertAdjacentHTML", "location.href", "location.replace",
        "location.assign",
    ]

    OPEN_REDIRECT_PARAMS = [
        "redirect", "redirect_uri", "redirectUri", "next", "return",
        "returnTo", "return_url", "returnUrl", "url", "goto", "continue",
        "forward", "dest", "destination", "target",
    ]

    def __init__(
        self,
        proxy: str = "",
        headless: bool = True,
        timeout: int = 30_000,
        screenshot_dir: str = "screenshots",
        user_agent: str = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
    ):
        self.proxy          = proxy
        self.headless       = headless
        self.timeout        = timeout
        self.screenshot_dir = Path(screenshot_dir)
        self.user_agent     = user_agent
        self._findings: list = []

        if not HAS_PLAYWRIGHT:
            log("WARN", "[Browser] Playwright unavailable — browser scanning disabled")

    # ── internal helpers ─────────────────────────────────────────────────

    def _screenshot_path(self, slug: str) -> str:
        self.screenshot_dir.mkdir(parents=True, exist_ok=True)
        ts = datetime.now().strftime("%H%M%S")
        return str(self.screenshot_dir / f"{ts}_{slug[:40]}.png")

    def _add_finding(
        self, title: str, severity: str, url: str,
        description: str = "", evidence: str = "",
        cwe: str = "", tags: Optional[List[str]] = None,
    ):
        f = Finding(
            plugin="browser-scanner",
            title=title, severity=severity,
            description=description, evidence=evidence,
            url=url, cwe=cwe or "CWE-79",
            tags=(tags or []) + ["browser", "playwright"],
        )
        self._findings.append(f)
        log("VULN", f"[Browser] {severity} — {title}")

    # ── JS sink detection ────────────────────────────────────────────────

    async def _detect_xss_sinks(self, page, url: str):
        """Scan JS in the page for dangerous DOM sinks."""
        try:
            scripts = await page.evaluate("""
                () => {
                    return Array.from(document.querySelectorAll('script'))
                               .map(s => s.innerText || s.textContent || '')
                               .join('\\n');
                }
            """)
            found_sinks = []
            for sink in self.XSS_SINKS:
                if sink in scripts:
                    found_sinks.append(sink)
            if found_sinks:
                self._add_finding(
                    title=f"DOM XSS Sink(s) Detected: {', '.join(found_sinks[:3])}",
                    severity="HIGH",
                    url=url,
                    description=(
                        "Dangerous JavaScript sinks found in inline scripts. "
                        "May allow DOM-based XSS if attacker-controlled input reaches them."
                    ),
                    evidence=f"Sinks: {', '.join(found_sinks)}",
                    cwe="CWE-79",
                    tags=["xss", "dom", "client-side"],
                )
        except Exception as exc:
            logger_v21.debug("XSS sink detection error: %s", exc)

    # ── network capture ──────────────────────────────────────────────────

    def _build_network_listener(self, captured_requests: list):
        def on_request(request):
            captured_requests.append({
                "url":     request.url,
                "method":  request.method,
                "headers": dict(request.headers),
                "post":    request.post_data or "",
            })
        return on_request

    def _build_response_listener(self, captured_responses: list):
        async def on_response(response):
            try:
                hdrs = dict(response.headers)
                captured_responses.append({
                    "url":     response.url,
                    "status":  response.status,
                    "headers": hdrs,
                })
            except Exception:
                pass
        return on_response

    # ── CORS check via browser ────────────────────────────────────────────

    async def _check_cors(self, page, target: str):
        try:
            result = await page.evaluate(f"""
                async () => {{
                    try {{
                        const r = await fetch("{target}", {{
                            method: "GET",
                            mode: "cors",
                            headers: {{"Origin": "https://evil-cors-test.example.com"}}
                        }});
                        const acao = r.headers.get("access-control-allow-origin");
                        return acao || "";
                    }} catch (e) {{
                        return "";
                    }}
                }}
            """)
            if result in ("*", "https://evil-cors-test.example.com"):
                self._add_finding(
                    title="CORS Wildcard via Browser Validation",
                    severity="MEDIUM",
                    url=target,
                    description="The server reflects any Origin in ACAO header.",
                    evidence=f"Access-Control-Allow-Origin: {result}",
                    cwe="CWE-942",
                    tags=["cors", "misconfiguration"],
                )
        except Exception as exc:
            logger_v21.debug("CORS browser check error: %s", exc)

    # ── open redirect ────────────────────────────────────────────────────

    async def _check_open_redirect(self, page, target: str):
        parsed = urlparse(target)
        for param in self.OPEN_REDIRECT_PARAMS:
            test_url = (
                f"{parsed.scheme}://{parsed.netloc}{parsed.path}"
                f"?{param}=https://evil-redirect.example.com"
            )
            try:
                await page.goto(test_url, timeout=5000, wait_until="domcontentloaded")
                final_url = page.url
                if "evil-redirect.example.com" in final_url:
                    self._add_finding(
                        title=f"Open Redirect via '{param}' Parameter",
                        severity="MEDIUM",
                        url=target,
                        description=f"Parameter '{param}' redirects to attacker-controlled URL.",
                        evidence=f"Payload: {test_url} → Final: {final_url}",
                        cwe="CWE-601",
                        tags=["open-redirect", "client-side"],
                    )
                    break
            except Exception:
                pass

    # ── crawler ──────────────────────────────────────────────────────────

    async def _crawl_links(self, page, base_url: str, depth: int) -> list:
        if depth <= 0:
            return []
        base_netloc = urlparse(base_url).netloc
        try:
            hrefs = await page.evaluate("""
                () => Array.from(document.querySelectorAll('a[href]'))
                           .map(a => a.href)
            """)
        except Exception:
            hrefs = []

        same_domain = []
        for href in hrefs:
            try:
                if href.startswith(("http://", "https://")):
                    if urlparse(href).netloc == base_netloc:
                        same_domain.append(href)
                elif href.startswith("/"):
                    p = urlparse(base_url)
                    same_domain.append(f"{p.scheme}://{p.netloc}{href}")
            except Exception:
                pass
        return list(dict.fromkeys(same_domain))[:20]   # dedupe, cap 20

    # ── main scan ────────────────────────────────────────────────────────

    async def scan(
        self,
        target: str,
        depth: int = 1,
        take_screenshot: bool = True,
        check_cors: bool = True,
        check_redirect: bool = True,
        check_xss_sinks: bool = True,
    ) -> list:
        """
        Full headless browser scan of ``target``.

        Args:
            target:           The URL to scan.
            depth:            How many link-levels deep to crawl (0 = single page).
            take_screenshot:  Save a screenshot after each page load.
            check_cors:       Run browser-based CORS check.
            check_redirect:   Test common redirect parameters.
            check_xss_sinks:  Scan inline scripts for DOM XSS sinks.

        Returns:
            list of Finding objects.
        """
        if not HAS_PLAYWRIGHT:
            log("WARN", "[Browser] Playwright not available — skipping browser scan")
            return []

        self._findings = []
        visited: set   = set()

        try:
            from playwright.async_api import async_playwright
        except ImportError:
            log("WARN", "[Browser] Cannot import playwright.async_api")
            return []

        async with async_playwright() as pw:
            launch_opts: dict = {"headless": self.headless}
            if self.proxy:
                launch_opts["proxy"] = {"server": self.proxy}

            browser = await pw.chromium.launch(**launch_opts)
            context = await browser.new_context(
                user_agent=self.user_agent,
                ignore_https_errors=True,
            )

            async def _scan_page(url: str, current_depth: int):
                if url in visited or current_depth < 0:
                    return
                visited.add(url)
                log("INFO", f"[Browser] Scanning: {url} (depth={current_depth})")

                captured_requests: list  = []
                captured_responses: list = []

                page = await context.new_page()
                page.on("request",  self._build_network_listener(captured_requests))
                page.on("response", self._build_response_listener(captured_responses))

                try:
                    await page.goto(url, timeout=self.timeout, wait_until="networkidle")
                except Exception as exc:
                    log("WARN", f"[Browser] Page load error at {url}: {exc}")
                    await page.close()
                    return

                # ── screenshot ─────────────────────────────────────────
                if take_screenshot:
                    try:
                        slug = re.sub(r"[^a-zA-Z0-9]", "_", url)
                        spath = self._screenshot_path(slug)
                        await page.screenshot(path=spath, full_page=True)
                        log("INFO", f"[Browser] Screenshot → {spath}")
                    except Exception:
                        pass

                # ── security header check (from captured responses) ────
                for resp_info in captured_responses:
                    hdrs = resp_info.get("headers", {})
                    resp_url = resp_info.get("url", url)

                    missing_headers = []
                    for h in ("x-frame-options", "x-content-type-options",
                              "content-security-policy", "strict-transport-security"):
                        if h not in {k.lower() for k in hdrs}:
                            missing_headers.append(h)
                    if missing_headers and resp_url == url:
                        self._add_finding(
                            title=f"Missing Security Headers: {', '.join(missing_headers[:2])}",
                            severity="LOW",
                            url=resp_url,
                            description="One or more security response headers are missing.",
                            evidence=f"Missing: {', '.join(missing_headers)}",
                            cwe="CWE-693",
                            tags=["headers", "misconfiguration"],
                        )
                        break  # one finding per page

                # ── DOM XSS sinks ──────────────────────────────────────
                if check_xss_sinks:
                    await self._detect_xss_sinks(page, url)

                # ── CORS via browser ───────────────────────────────────
                if check_cors and current_depth == depth:
                    await self._check_cors(page, url)

                # ── Open redirect ──────────────────────────────────────
                if check_redirect and current_depth == depth:
                    await self._check_open_redirect(page, url)

                # ── crawl deeper ───────────────────────────────────────
                if current_depth > 0:
                    links = await self._crawl_links(page, url, current_depth)
                    await page.close()
                    for link in links:
                        if link not in visited:
                            await _scan_page(link, current_depth - 1)
                else:
                    await page.close()

            await _scan_page(target, depth)
            await browser.close()

        log("OK", f"[Browser] Scan complete: {len(self._findings)} finding(s) from {len(visited)} page(s)")
        return self._findings

    async def scan_with_auth(
        self,
        target: str,
        username: str,
        password: str,
        login_url: str = "",
        username_selector: str = "input[type='text'], input[name='username'], input[name='email']",
        password_selector: str = "input[type='password']",
        submit_selector: str   = "button[type='submit'], input[type='submit']",
        **kwargs,
    ) -> list:
        """
        Authenticated browser scan — fills login form then scans.

        Args:
            target:            URL to scan post-login.
            username/password: Credentials.
            login_url:         Login page URL (defaults to target).
            *_selector:        CSS selectors for login form elements.
            **kwargs:          Passed to ``scan()``.
        """
        if not HAS_PLAYWRIGHT:
            log("WARN", "[Browser] Playwright not available")
            return []

        try:
            from playwright.async_api import async_playwright
        except ImportError:
            return []

        async with async_playwright() as pw:
            launch_opts: dict = {"headless": self.headless}
            if self.proxy:
                launch_opts["proxy"] = {"server": self.proxy}

            browser = await pw.chromium.launch(**launch_opts)
            context = await browser.new_context(
                user_agent=self.user_agent,
                ignore_https_errors=True,
            )
            page = await context.new_page()

            try:
                await page.goto(login_url or target, timeout=self.timeout)
                await page.fill(username_selector, username)
                await page.fill(password_selector, password)
                await page.click(submit_selector)
                await page.wait_for_load_state("networkidle", timeout=self.timeout)
                log("OK", f"[Browser] Logged in as {username!r}")

                # Store auth cookies for subsequent pages
                cookies = await context.cookies()
                log("INFO", f"[Browser] Captured {len(cookies)} auth cookie(s)")
            except Exception as exc:
                log("WARN", f"[Browser] Login failed: {exc}")
            finally:
                await page.close()
                await browser.close()

        # Run main scan (will reuse cookies via separate context — simplified flow)
        return await self.scan(target, **kwargs)


# ════════════════════════════════════════════════════════════════════════
#  V21 INTEGRATION HELPER — Wire all 7 features into one call
# ════════════════════════════════════════════════════════════════════════

async def run_v21_enhancements(
    target: str,
    findings: list,
    client=None,
    # Feature 1
    export_http: bool = False,
    http_export_dir: str = "http_exports",
    # Feature 2
    diff_responses: bool = False,
    diff_resp_a=None,
    diff_resp_b=None,
    diff_html_path: str = "",
    # Feature 3
    interactive_shell: bool = False,
    # Feature 4
    proxy: str = "",
    proxy_list: Optional[List[str]] = None,
    rotate_proxy: bool = False,
    # Feature 5
    repeater_mode: bool = False,
    # Feature 6
    intercept_proxy: bool = False,
    intercept_port: int = 8888,
    # Feature 7
    browser_scan: bool = False,
    browser_depth: int = 1,
    browser_headless: bool = True,
    browser_screenshot: bool = True,
) -> dict:
    """
    Run all v21 enhancement modules on completed or live scan results.

    Returns a dict with keys matching each activated module.
    """
    report: dict = {
        "findings": list(findings),
        "http_exports": [],
        "diff_result": "",
        "browser_findings": [],
        "proxy_findings": [],
        "shell": None,
        "proxy_router": None,
    }

    # ── Feature 4 — Proxy Router ──────────────────────────────────────────
    proxy_router = ExternalProxyRouter(
        proxy=proxy,
        proxy_list=proxy_list or [],
        rotate=rotate_proxy,
    )
    report["proxy_router"] = proxy_router
    if (proxy or proxy_list) and client is not None:
        if hasattr(client, "cfg"):
            proxy_router.inject_into_config(client.cfg)

    # ── Feature 3 — Interactive Shell ────────────────────────────────────
    shell: Optional[InteractiveScanShell] = None
    if interactive_shell:
        shell = InteractiveScanShell()
        shell.add_findings(findings)
        shell.start()
        report["shell"] = shell

    # ── Feature 1 — HTTP Export ───────────────────────────────────────────
    if export_http and findings:
        exporter = RawHttpExporter(output_dir=http_export_dir)
        written  = exporter.export_findings(findings, target=target)
        report["http_exports"] = written
        log("OK", f"[v21] HTTP exports: {len(written)} file(s) → {http_export_dir}/")

    # ── Feature 2 — Diff Viewer ──────────────────────────────────────────
    if diff_responses and diff_resp_a is not None and diff_resp_b is not None:
        viewer = ResponseDiffViewer()
        diff   = viewer.compare(
            diff_resp_a, diff_resp_b,
            label_a="Baseline Response",
            label_b="Modified Response",
        )
        report["diff_result"] = diff
        if diff_html_path:
            viewer.export_html(
                diff_resp_a, diff_resp_b,
                path=diff_html_path,
            )

    # ── Feature 7 — Browser Scanner ──────────────────────────────────────
    if browser_scan:
        bs = LiveBrowserScanner(
            proxy=proxy,
            headless=browser_headless,
        )
        browser_findings = await bs.scan(
            target,
            depth=browser_depth,
            take_screenshot=browser_screenshot,
        )
        report["browser_findings"] = browser_findings
        report["findings"].extend(browser_findings)

    # ── Feature 6 — Intercepting Proxy ───────────────────────────────────
    if intercept_proxy:
        iproxy = InterceptingProxy(port=intercept_port)
        iproxy.start()
        report["intercepting_proxy"] = iproxy
        log("INFO", f"[v21] Intercepting proxy on ::{intercept_port} — press Ctrl+C to stop and collect")

    # ── Feature 5 — Repeater (interactive, blocks) ───────────────────────
    if repeater_mode:
        rep = TerminalRepeater(proxy=proxy)
        if findings:
            rep.load_finding(findings[0])
        await rep.run()   # blocking REPL

    return report


def add_v21_argparse_flags(parser):
    """
    Adds v21 flags to an existing argparse.ArgumentParser.

    Call after building the base parser::

        add_v21_argparse_flags(parser)
        args = parser.parse_args()
    """
    g = parser.add_argument_group("WebScout v21 — New Features")

    # Feature 1
    g.add_argument(
        "--export-http", action="store_true", default=False,
        help="[F1] Export each finding as a .http request file")
    g.add_argument(
        "--http-export-dir", metavar="DIR", default="http_exports",
        help="[F1] Directory for .http exports (default: http_exports)")

    # Feature 2
    g.add_argument(
        "--diff-html", metavar="FILE", default="",
        help="[F2] Generate HTML diff of two responses and save to FILE")

    # Feature 3
    g.add_argument(
        "--interactive", action="store_true", default=False,
        help="[F3] Enable interactive command shell during scan")

    # Feature 4
    g.add_argument(
        "--route-proxy", metavar="PROXY", default="",
        help="[F4] Route all traffic through this external proxy (e.g. http://127.0.0.1:8080)")
    g.add_argument(
        "--rotate-proxies", action="store_true", default=False,
        help="[F4] Rotate through --proxy-list proxies")

    # Feature 5
    g.add_argument(
        "--repeater", action="store_true", default=False,
        help="[F5] Launch terminal Repeater after scan")

    # Feature 6
    g.add_argument(
        "--intercept", action="store_true", default=False,
        help="[F6] Start intercepting proxy (mitmproxy mode)")
    g.add_argument(
        "--intercept-port", type=int, default=8888,
        help="[F6] Port for intercepting proxy (default: 8888)")

    # Feature 7
    g.add_argument(
        "--browser", action="store_true", default=False,
        help="[F7] Enable headless Playwright browser scan")
    g.add_argument(
        "--browser-depth", type=int, default=1,
        help="[F7] Browser crawl depth (default: 1)")
    g.add_argument(
        "--browser-visible", action="store_true", default=False,
        help="[F7] Show browser window (non-headless mode)")
    g.add_argument(
        "--browser-screenshot", action="store_true", default=True,
        help="[F7] Save screenshots during browser scan (default: on)")
    g.add_argument(
        "--no-browser-screenshot", dest="browser_screenshot",
        action="store_false",
        help="[F7] Disable browser screenshots")


